INSERT INTO safety_incidents VALUES ('c78290723c1f1596ca07a60df253b728c3b309ce', 'EU Safety Gate', '2025-03-07', 2025, '2025-03', 'EU / EEA', 'Ireland', 'United States', 'Cosmetics & Personal Care', 'Brow lamination kit, including brow affix, style solution, neutraliser, treatment oil, plastic film, a spoolie, and clear mini combs. The product is sold online on several websites. The batch numbers mentioned are those which were tested, however all batches are concerned by the measure.', 'Other', 'Other', 'Not Specified', '', 'Not Reported', 0, 0, '', 'SR/00841/25');
