INSERT INTO safety_incidents VALUES ('148af903bb5990c02e0f587946deadba3c22c02f', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', '32 Degrees Heated Socks', 'Burns', 'Explosion', 'Burns', '14 heat-related incidents have been reported, with 13 involving first- or second-degree burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the heated socks and return them to Costco for a full refund.', '26435');
INSERT INTO safety_incidents VALUES ('ca808789a4c468b7071b90e041a88c9bd7227f9a', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Autobrush Sonic Pro Kids Toothbrush Boxes', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the boxes for the toothbrushes immediately, take them away from children and contact Autobrush for a $5 refund in the form of store credit. Consumers will be asked to write "Recalled" with permanent marker on the box and send a photo of the marked box to recall-support@autobrush.com. Consumers should then dispose of the box. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26434');
INSERT INTO safety_incidents VALUES ('c50f4dd07a37bf1b65ed3322bf2b254206456aba', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'AMZCMJ DGD Children''s Tower Stools', 'Injury', 'Entrapment', 'Entrapment', 'The firm is aware of seven incidents of children falling from the stool or becoming entrapped, resulting in four injuries such as contusions, splinters and scrapes.', 'Fatal', 1, 0, 'Consumers should stop using the recalled tower stools immediately and contact AMZCMJ DGD for a full refund. Consumers will be asked to destroy the stool by writing "recalled" in permanent marker on all sides, disassembling it and sending a photo of the destroyed stool to dgdtoddlertowerrecall@dchskj.cn. Consumers should then dispose of the destroyed product.', '26433');
INSERT INTO safety_incidents VALUES ('6b57326a03148427d7f9277e9654ac73d6fbc916', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'TOETOL Tower Stools', 'Injury', 'Entrapment', 'Entrapment', 'The firm has received 18 reports of the stools collapsing, resulting in eleven injuries including contusions, cuts and scrapes.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled tower stools and contact TOETOL HOME for a full refund. Consumers will be asked to destroy the stool by disassembling it and send a photo of the destroyed stool to TOETOLHOMEStepStoolsrecall@outlook.com. Consumers should then dispose of the destroyed product.', '26432');
INSERT INTO safety_incidents VALUES ('47af1bcc327dfa7471a1cf430547e34b765e3075', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Cpzzkq Baby Loungers', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the baby loungers immediately and contact CetoPMax for a refund. Consumers will be asked to remove the foam and pad from the baby lounger''s cover and cut the cover, foam and pad in half. Consumers will then email photos of the destroyed pieces to?CetoPMaxRecall@outlook.com?to receive a refund.', '26438');
INSERT INTO safety_incidents VALUES ('69621b74452212a6db74c680167bc5a0c3564375', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Sweetie Baby and Style Life Eleven Baby Loungers', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the baby loungers immediately and contact HappyGira for a full refund. Consumers will be asked to destroy the loungers by removing the sleeping pad and bumpers covers, cutting the bumpers, sleeping pad and the covers in half, and send a photo of the destroyed pieces to?support@happygira.com. Consumers should then dispose of the destroyed product.', '26437');
INSERT INTO safety_incidents VALUES ('c63bac3709bb708ea3a32931a8aaf01ccab333b0', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'KMUYSL Big Red Barn Farm Animal Playsets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled toys immediately, take them away from children and contact MISSJUNE for a full refund. Consumers will be asked to remove and properly dispose of the fence handles into the trash and send a photo of the disposed product to kmuyslfarmanimalrecall@gmail.com to receive a full refund.', '26440');
INSERT INTO safety_incidents VALUES ('d14195b9caa271e7e51a37821cb6373fafbebe68', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'BlissfulDestiny Magnetic Stick Figure Sets', 'The Magnetic Stick Figures Violate The Mandatory Standard For Toys Because They Contain Loose Magnets Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic stick figures immediately and take them away from children. Contact BlissfulDestiny for information on how to receive a full refund. Consumers will be asked to throw the recalled magnetic stick figures away and email a photo of the disposed product to Blissful_Destiny@outlook.com.', '26436');
INSERT INTO safety_incidents VALUES ('57a36f8571fc4fa5c667e438bec0782feb98ddde', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'mGanna Sodium Hydroxide (lye) Pellet Bags', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should stop using and secure the recalled sodium hydroxide product out of sight and reach of children immediately and contact Archie Xpress for a full refund. Consumers will be asked to write "RECALLED" on the back of the zip-top pouch and send a photo of the marked pouch to support@archieenterprise.in. Consumers should then dispose of the pellets in accordance with local and state regulations. Note: Consumers should follow local household hazardous waste (HHW) guidance for corrosive solids. Contact your city, county, or state HHW program for instructions, as requirements may differ by location. Recommend safe approach: Keep the product in its package, clearly label it "DO NOT USE" and bring it to a local HHW drop-off facility.', '26429');
INSERT INTO safety_incidents VALUES ('8dad907a8054e309db8da01319a0548acbb9e842', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'FitRx SmartBell Quick-Select 5-52.5lbs Adjustable Dumbbells', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'There have been more than 115 reports of weight plates dislodging during use, with at least six injuries, including broken toes, bruises, contusions and lacerations.', 'Serious', 1, 0, 'Consumers should immediately stop using the adjustable dumbbell and contact Tzumi Electronics for a free replacement of the dumbbell and tray. Consumers should write the word "Recalled" across the dumbbell tray using permanent spray paint or marker, register at https://myfitrx.com/recall-52-lbs/ and dispose of the product after registration is confirmed.', '26431');
INSERT INTO safety_incidents VALUES ('cf96abc9a8685887c8fcef1c3e0a2c6017f19893', 'CPSC', '2026-04-23', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Wiifo Children''s Tower Stools', 'Injury', 'Entrapment', 'Entrapment', 'The firm is aware of 22 incidents of stools collapsing, resulting in six injuries such as contusions and scrapes.', 'Fatal', 1, 0, 'Consumers should stop using the recalled tower stools immediately and contact Wiifo for a full refund. Consumers will be asked to destroy the stool by disassembling it and send a photo of the destroyed stool to support@wiifo.net. Consumers should then dispose of the destroyed product.', '26430');
INSERT INTO safety_incidents VALUES ('336a30125df564aff5bb935d95c052371e9d3445', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'ZOLIQUEX Adult Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled adult portable bed rails immediately and contact ZOLIQUEX for a full refund. Consumers should cut the black safety strap in half and write "RECALLED" on the upper and lower bed rails with a permanent marker, take a photo of the marked bed rail with the buyer''s name on a piece of paper and email the photo to ZEXnaturemedical@outlook.com.', '26425');
INSERT INTO safety_incidents VALUES ('91e1cdc4e3f5b96ccaf5d61abc439b17cdabbb5c', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Agiiman Electric Pressure Washers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled pressure washers immediately and contact Agiiman for a full refund. Consumers will be asked to cut the power cord in half to destroy the pressure washer and send a photo of the destroyed pressure washer to agiimanservice@163.com. Consumers should then dispose of the destroyed recalled product.', '26420');
INSERT INTO safety_incidents VALUES ('7fb515f30728d8cde0f06bf09c017151b93b4786', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Manik and Apex-branded ATX Computer Power Supplies (PSU)', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled computer power supplies immediately and contact Apex Gaming PCs Inc. for a free repair in the form of one permanent, UL-recognized, heat-resistant adhesive safety label containing an ANSI-compliant "Danger/Warning" shock hazard and "No User-Serviceable Parts" label sticker to be mailed to the consumer via U.S. Mail. Consumers who are uncomfortable adding the UL-recognized safety label can request a free replacement unit. Replacement units will be sent free of charge, and the original unit must be returned using the same box and provided shipping label that is sent with the replacement unit. Consumers should not, under any circumstances, attempt to open, disassemble, or service the power supply unit.', '26426');
INSERT INTO safety_incidents VALUES ('2e572df0f015383b646c3e1acf1a8764532a9658', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'ATOYUS Children''s Activity Cubes', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled toys, take them away from children and contact Melofaver US for a full refund. Consumers will be asked to destroy the toy by writing "recalled" on all sides of the multi-sided wooden cube and cutting the playmat in half and email a photo of the destroyed toy to ATOYUSActivityCubeRecall@outlook.com. Consumers should then dispose of the recalled product.', '26411');
INSERT INTO safety_incidents VALUES ('451879e44028a3e0a7bf3fd132415f35ef213764', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Fengrong Tool Electric Pressure Washers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled pressure washers immediately and contact Fengrong Tool for a full refund. Consumers will be asked to destroy the pressure washer by cutting the unplugged power cord and send a photo of the destroyed power washer to fengrongservice@163.com. Consumers should then dispose of the destroyed recalled product.', '26421');
INSERT INTO safety_incidents VALUES ('f858c59ad041d0b01d59c317c2ed03f23b8cf132', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Fisher & Paykel Gas Ranges', 'Burns', 'Flammability / Overheating', 'Burns', 'The firm has received 18 reports of gas ranges with delayed ignition and one report of a minor burn injury.', 'Minor', 1, 0, 'Consumers should stop using the ovens in the recalled gas ranges immediately and contact Fisher & Paykel for a free inspection and repair. Fisher & Paykel will provide professional in-home repair of the oven''s ignitor. Consumers can continue to use the cooktop burners on the range.', '26419');
INSERT INTO safety_incidents VALUES ('bcded8998554395a83b588e6b02cf5e9c9f65493', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Multi-Point Swing Frames', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm received 10 reports of the swing frame cracking or breaking and children falling, resulting in two children sustaining contusions.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled multi-point suspension swing frame and contact Fun and Function for a full refund. Consumers should register at https://funandfunction.com/pages/swing-recall and disassemble and dispose of the product, according to the directions provided on the registration page.', '26413');
INSERT INTO safety_incidents VALUES ('0b1ba0f41e6df064d34a9fb2036734cc96b56c8c', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Generac Portable Generators', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 114 reports of generator fuel leaks. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Generac portable generator and go to https://www.generac.com/about/recalls/GP-Carburetor to check to see if your model and serial number are included in this recall. If your unit is included in the recall and has either not yet been filled with fuel or exhibited leakage after fueling as described above, please contact your dealer to arrange for free repair at the dealer''s location.', '26407');
INSERT INTO safety_incidents VALUES ('f1905806333bdaf773ed2d1b00b31fcef0370c58', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Lil'' Buddies Pet Laser Toy', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled pet toys, place them in an area that children cannot access and properly dispose of the batteries. Contact JC Sales for a full refund. Customers will be asked to email a photograph of the disposed items to Recall@jcsales.net. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26428');
INSERT INTO safety_incidents VALUES ('65616a957027ca94d531259275c3f18e150c7856', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Le Hao Tool Electric Pressure Washers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled pressure washers immediately and contact Le Hao Tool for a full refund. Consumers will be asked to destroy the pressure washer by cutting the unplugged power cord in half and send a photo of the destroyed power washer to LeHaoService2026@outlook.com. Consumers should then dispose of the destroyed recalled product.', '26422');
INSERT INTO safety_incidents VALUES ('8dfd2fe5a2e1ce04687eda47e73663b15a9b9a34', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Arch Studio Tea Kettle', 'Burns', 'Mechanical Failure', 'Burns', 'The firm has received three reports of the handle detaching. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should stop using the recalled tea kettles immediately and contact Macy''s for a full refund in the form of a check for the purchase price. Consumers will be asked to complete a recall form at https://www.recallrtr.com/teakettle for a prepaid shipping label to return the product. No purchase receipt will be required.', '26412');
INSERT INTO safety_incidents VALUES ('862030bb529a8c3f376dbf03f5b710c4b9c476a0', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'SEGMART 55" Indoor/Outdoor Mini Round Toddler Trampolines with Enclosure Nets and Accessory Kits', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received one report of an incident in which a child''s neck became entangled in the hammock straps, resulting in a rope burn injury around the child''s neck.', 'Fatal', 1, 0, 'Consumers should remove the hammock, punching bag, hand ring and basketball board accessories immediately before continuing to use the trampoline. SEGMART will provide a $30 refund to consumers who remove and destroy the hammock, punching bag, hand ring and basketball board accessories. Consumers will be asked to cut the straps on the accessories and submit photos of the cut accessories to the firm. Instructions can be found at www.segmart.com.', '26414');
INSERT INTO safety_incidents VALUES ('f913d30711a286980607015490c32ea65610248e', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'SpringFlower 5-in-1 Montessori Toy Set', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the Montessori toy sets immediately and take them away from children and contact SpringFlower for a free replacement part or a refund. Consumers will be asked to cut off all the tentacles from the airplane shaped teething toy, write the date and customer''s initials in permanent marker on its base, and submit photos of the destroyed and marked airplane shaped toy to springflower.com.cn/product-recall. Consumers can then dispose of the airplane shaped toy.', '26427');
INSERT INTO safety_incidents VALUES ('f7826f82e217ecdba7e184b36469ab8eb11bd255', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'nvyue Magic Pocket Staffs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'CPSC has received 163 reports of incidents involving injuries to the eyes, face and hands. Reported injuries include corneal lacerations, temporary vision loss and injuries requiring stitches, many involving children as young as nine years old.', 'Moderate', 1, 0, 'Consumers should stop using the Magic Pocket Staff immediately and contact Xingwenfeng for a full refund. Consumers will be asked to write their initials and the current date with permanent marker on the Magic Pocket Staff and send a photo of the marked Magic Pocket Staff to nvyue_recall@163.com. Consumers will be instructed to safely expand the Magic Pocket Staff before disposal. Consumers should then dispose of the recalled product.  Do not sell or give away these hazardous products.', '26409');
INSERT INTO safety_incidents VALUES ('ec40fa0330d82239e56c8c2cacb9bd9286c798a6', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'BAYOTAK USA Electric Pressure Washers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled pressure washers and contact BATOYAK USA for a free replacement pressure washer of at least equal value to the recalled pressure washer, including shipping. Consumers will be asked to destroy the pressure washer by unplugging it and cutting the power cord in half and send a photo of the destroyed power washer to bayotakservice@163.com. Consumers should then dispose of the destroyed recalled product.', '26406');
INSERT INTO safety_incidents VALUES ('67e74f0cfcc5d6d8f10fb7b6c7a0d6a6ed0ac60f', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Patoolio Direct Electric Pressure Washers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled pressure washers immediately and contact Patoolio Direct for a full refund. Consumers will be asked to destroy the pressure washer by cutting the power cord in half and send a photo of the destroyed power washer to PatoolioPressureWasherrecall@outlook.com. Consumers should then dispose of the destroyed recalled product.', '26417');
INSERT INTO safety_incidents VALUES ('c8616e9609d62e678994d490f3ddb4913633e7f9', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Sanlebi Pet Vet Playsets', 'The Pet Vet Playset Violates The Mandatory Standard For Toys Because The Button Cell Batteries In The Nail Grinder And Otoscope Can Be Easily Accessed By Children.', 'Other', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should take away the nail grinder and otoscope from children immediately, stop using them and remove and properly dispose of the batteries. Consumers will be asked to throw the nail grinder and otoscope components away and send a photo of the disposed components to letorecall@outlook.com to receive a $5 refund or replacement nail grinder and otoscope. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26408');
INSERT INTO safety_incidents VALUES ('d67af3cd926b04ea7541436baf4e02edd13f402d', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Sweetcrispy Electric Pressure Washers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled pressure washers immediately and contact Sweetcrispy for a full refund. Consumers will be asked to destroy the pressure washer by cutting the unplugged power cord and send a photo of the destroyed power washer to LR023784@outlook.com. Consumers should then dispose of the destroyed recalled product.', '26423');
INSERT INTO safety_incidents VALUES ('52633d168b36679834e49bd04cac9ce1c02a6be1', 'CPSC', '2026-04-16', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'LED Finger Beam Lights', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should take the LED Finger Beam Lights away from children, stop using them immediately and contact ZMC Group for full refund or a replacement product. Consumers should remove the batteries, break each component in half and submit a photo of the destroyed pieces to recallzmctoy@gmail.com. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26424');
INSERT INTO safety_incidents VALUES ('8acbcd302fc029f1288ca7e356b909d79ea0eb78', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Steam Shot OmniReach and Steam Shot Omni Steam Cleaners with attachments', 'Burns', 'Mechanical Failure', 'Burns', 'BISSELL has received 206 reports of hot water or steam unexpectedly escaping from the steam cleaners'' attachments, including 161 reports of burn injuries with a report of one second degree burn.', 'Moderate', 1, 0, 'Consumers should stop using the recalled steam cleaner attachments immediately and contact BISSELL to receive free new attachments. Consumers should visit www.steamshot2026.com to register for the recall and for instructions on how to participate in the recall, including how to upload a photo showing the original attachment accessories have been disposed of in the trash.', '26385');
INSERT INTO safety_incidents VALUES ('c73aab55c51a4276ebfacd42a2f8b3fa0bc3a6ba', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Easymake Adult Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled bed rails immediately and contact ZFZG-US for a full refund. Consumers should destroy the bed rail by cutting the storage bag off the upper rail and the safety strap in half, write "Recalled" in permanent marker on the main frame and upload a photo of the marked bed rails to https://easymake-us.myshopify.com/recall. Consumers should then dispose of the recalled product in accordance with state and local waste disposal procedures.', '26387');
INSERT INTO safety_incidents VALUES ('ff5557388407348f10518bb3aa9dc40b23c7da8e', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Besslly Halloween Pumpkin Carving Kits', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled carving kits immediately and contact Besslly Store for a full refund. Consumers will be asked to email a photograph of disposal to tingjmng@outlook.com to receive the refund. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26396');
INSERT INTO safety_incidents VALUES ('b49d843abcb6f45fbf4d9a083ca7b69f8094d466', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Head Ski Boots', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Serious', 1, 0, 'Consumers should stop using the recalled ski boots immediately and contact Head USA or a Head authorized retailer. For recalled boots with fluorescent boot shell materials, Head will provide free replacement boots in a newer equivalent model upon return of the recalled boots. For recalled boots with yellow sole inserts, Head will provide free replacement sole inserts, which can be installed by the consumer or by a ski shop.', '26395');
INSERT INTO safety_incidents VALUES ('5f2a1422e0a5b02c13b79dcce9f70ac45d8232b9', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Happiness Light LED Lights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled LED lights immediately and place them in an area where children cannot access them. Consumers will be asked to disassemble the lights and submerge all of the components in water. To receive a full refund, email a photo showing the submerged product to usa@happinesslight.com. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26403');
INSERT INTO safety_incidents VALUES ('27e3197220cb5a3e2abac2683e94edd0c212ab5b', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Maitys Drinkware Charms', 'The Recalled Magnetic Drinkware Charms Violate The Mandatory Standard For Magnets Because They Contain Loose Magnets Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled drinkware charms immediately, take them away from children and contact Maitys for a full refund. Consumers will be asked to dispose of the charms and send a photo of the disposed product to maituus@outlook.com.', '26392');
INSERT INTO safety_incidents VALUES ('f8e65d899a308e929e9edbfb1115c2466b63478c', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Muscccm Pool Drain Covers', 'Drowning', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners, pool operators and consumers should immediately stop using pools with the recalled pool drain covers. To receive a refund, consumers should remove the drain cover from the pool, take a photo of the removed cover, and send it to SZ Hengxun by email at MuscccmRecall@126.com. Ensure all pools and spas have VGBA-compliant drain covers and teach children to stay away from drains.', '26405');
INSERT INTO safety_incidents VALUES ('b32131e6fa392e8bcc8c0483b1764f57d90cb439', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Supernova and Typhoon Lighters', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled lighters immediately and contact Prestige Import Group for a full refund or store credit. Consumers will be asked to write "Recalled" in permanent marker and send a photo of the marked lighter to salesdept2@prestigeimportgroup.com. Consumers should then dispose of the recalled product in accordance with state and local waste disposal procedures.', '26404');
INSERT INTO safety_incidents VALUES ('d9f4939a54dc1dcc371898c45c6ed3407e5ab8b6', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'SCUBAPRO Monorail Weight Pockets for BCDs', 'Injury', 'Drowning Risk', 'Drowning', 'The firm has received two reports of the D-ring handle detaching. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Monorail Weight Pocket and register online at https://scubapro.johnsonoutdoors.com/us/recalls for a free repair of the D-ring handle at a local authorized dealer or to obtain a prepaid shipping label to return the recalled weight pocket to SCUBAPRO for a free repair and free return shipping.', '26393');
INSERT INTO safety_incidents VALUES ('c98d6b082eb2bcd730907306f3df90f8f3d42f4f', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Members Mark 7'' Pre-Lit Twinkling Buck', 'Burns', 'Flammability / Overheating', 'Burns', 'The firm has received five reports of smoke and a burning smell. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the Members Mark 7'' Pre-Lit Twinkling Buck immediately and contact Seasonal Specialties to request either a full refund or a repair kit. The repair kit includes new instructions on how to connect the wires, color-coded wire labels and a cord tag warning sticker.', '26394');
INSERT INTO safety_incidents VALUES ('ef30414c4b36e311facba94de49aa11c74961adc', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'VEEKTOMX Portable Charger Mini Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'Shenzhen Baihang has received three reports of fires resulting in minor property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled power banks and contact Shenzhen Baihang to verify power bank is part of the recall and receive a free replacement power bank.', '26399');
INSERT INTO safety_incidents VALUES ('05546a5aca261e21ae0fae25622fe02523333614', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Male-to-Male Extension Cords', 'Fire', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled extension cords immediately, taking care not to touch the live end of the cord when unplugging, and contact Shenzhen Shijingjie Network Technology for a full refund.', '26401');
INSERT INTO safety_incidents VALUES ('2fe5d3ee721ebeed2422411cf264b3e640bd1022', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'ShymeryDirect LED Lights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled LED lights and place them in an area where children cannot access them. Consumers will be asked to disassemble and submerge all components in water. To receive a full refund, email a photo showing the submerged product to Shymeryrecall0402@outlook.com. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26398');
INSERT INTO safety_incidents VALUES ('a6a84e2fcebc35b133e8741932c49e6536e97e88', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Children''s Loungewear Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled loungewear, take it away from children and contact Silks for a full refund or store credit. Consumers should destroy the garments by cutting the top and bottom in half and send a photo of the destroyed garments to silkssupport@silksdesign.com. Consumers should then dispose of the loungewear.', '26389');
INSERT INTO safety_incidents VALUES ('4dd9ec6005df1893226bd521cad49e0593b780bb', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Breez 2-in-1 Smart Bedroom Fan and White Noise Machine', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm reported six cases of the fans overheating and smoking with one report of fire. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled fan immediately and go to the firm''s website to register for a replacement fan. Breez 2nd Generation sound machines are not affected by this recall. To determine whether a product is affected, consumers should locate the serial number on the underside of the fan''s wooden base. Serial numbers beginning with BZ10 or BZ02 are included in this recall. Consumers will be asked to cut the power cord and upload a photo of the cut power cord and a photo of the adapter showing the model number and all printed information.', '26388');
INSERT INTO safety_incidents VALUES ('96c89cacf680cc6ac7c37eb1a7b1785868be8dc2', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Various Brands of Iron-Containing Dietary Supplements', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately store the supplements out of sight and reach of children and contact Vitaquest International for information on how to obtain a free child-resistant replacement cap or storage pouch. Brand / Product Name Remedy Arey Not Today, Grey (60ct and 180ct) Cap Bari Life Complete Bariatric Vitamin - Watermelon (60ct) Storage pouch Bird&Be The Prenatal Essentials for Females (30 pkts) Storage pouch Bird&Be The Power Prenatal for Females (30 pkts) Storage pouch Bird&Be The Power Prenatal for Females + CoQ10 Boost (30pkts) Storage pouch Bird&Be Female Fertility Power Prenatal Pack (30 pkts) Storage pouch Bird&Be Complete Prenatal Pack (30 pkts) Storage pouch Bird&Be Female Fertility Power Prenatal + CoQ10 Pack (30 pkts) Storage pouch Biote Nutraceutical Iron+ (30ct) Cap Dr. Fuhrman Gentle Prenatal Multivitamin + D3 (120ct) Cap Dr. Fuhrman Pixie Vites Children''s Multivitamin (120ct) Cap NuLife Advanced Bariatrics Multivitamin Chewable Tablets (60ct) Cap HMR Multi Daily Vitamin and Mineral Supplement (60ct) Cap Bariatric Pal Ultra Multi Bariatric Multivitamin (90ct) Cap Noevir Inner Care Premium BioEssentials (120ct) Cap Zenbean Kids Café Instant Coffee + Nutrition Latte, Original, Caramel, Chocolate, and Vanilla (30srv) Storage pouch Sakara The Foundation (30pkts) Storage pouch Sakara The Foundation: Prenatal (30pkts) Storage pouch', '26386');
INSERT INTO safety_incidents VALUES ('8ccb2a86c52a8e531eeaf2c5bf48326428d63959', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Osprey 700 Max and S1 robotic pool vacuums', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received ten reports of the pool vacuums overheating or catching fire while charging and not charging, resulting in nine incidents of property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled robotic pool vacuums immediately and contact Wybotics to receive a free replacement WYBOT C2 robotic pool vacuum. Wybotics will provide a free return label for consumers to send the recalled product back to Wybotics. Within 15 days of receiving the recalled pool vacuums, Wybotics will ship the replacement product. Wybotics is contacting all known purchasers directly.', '26372');
INSERT INTO safety_incidents VALUES ('1b679e6365fa35428c9ee6cbe37ed7e431874d9e', 'CPSC', '2026-04-09', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Yeeluzan Pool Drain Covers', 'Drowning', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners, pool operators and consumers should immediately stop using pools with the recalled pool drain covers. To receive a full refund to their original payment method, consumers should destroy the removed drain cover, take a clear photograph/video of the destroyed product as proof of destruction, and send the proof to the recalling firm by email at yeeluzanrecall@163.com. Ensure all pools and spas are fitted with VGBA-compliant drain covers and teach children to stay away from drains.', '26397');
INSERT INTO safety_incidents VALUES ('f92e935cd742a96edbf30efd4b43af5667f7681a', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Beestech Children''s Spiral Tower Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should take the toys away from children immediately and contact Beestech for a full refund. Consumers will be asked to write "Recalled" with permanent marker on the toy and send a photo of the marked toy to beestechballtowerrecall@hotmail.com. Consumers should then dispose of the recalled product.', '26365');
INSERT INTO safety_incidents VALUES ('85f6f93cea2f97eb6dc42802cc55643336415a01', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Coluans Christmas Light-Up Rings Party Favors', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should take the recalled light-up rings away from children, stop using them immediately and remove and properly dispose of the batteries. Consumers will be asked to throw away the light-up rings and send a photo of the disposed product to BUDIrecall@outlook.com for a full refund. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26369');
INSERT INTO safety_incidents VALUES ('2ce2590f8da82a651514b11e176a88ef3fdffe79', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Granitestone Diamond Pro Blue Sauté Pans', 'Burns', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'E Mishan is aware of at least 98 incidents where the metal cap detached and ejected from the pan, including one report where a consumer received bruising and burn injuries.', 'Moderate', 1, 0, 'Consumers should stop using the recalled sauté pans immediately and contact E Mishan for a full refund. Consumers will be asked to return the recalled sauté pan.', '26377');
INSERT INTO safety_incidents VALUES ('a65e4e1b0231e96b0d3a29dee68ef41559ff968f', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'ELENKER Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled bed rails immediately and contact Fuzhou Shiahaha Cultural Industry Development for a full refund. Consumers will be asked to write "RECALL" with permanent marker on the bed rails and then dispose of the recalled product in accordance with the state and local waste disposal procedure.', '26374');
INSERT INTO safety_incidents VALUES ('18b58f31ac7c5878e7dfa512d348b352221086ad', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Gavoyeat Halloween Light-Up Rings Party Favors', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should take the recalled light-up rings from children, stop using the recalled toys immediately and remove and properly dispose of the batteries. Consumers will be asked to throw away the light-up rings and send a photo of the disposed product to recalledgavoyeat@yeah.net. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26368');
INSERT INTO safety_incidents VALUES ('9dd6c88e38d4c58746c42b04724b50dc803344fd', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'HTRC and Haisito battery chargers', 'Fire', 'Explosion', 'Respiratory', 'Huizhou Haitan Technology has received 33 reports of fires and explosions, including three reports of burn and smoke inhalation injuries and 12 reports of property damage totaling $224,000.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled chargers and contact Huizhou Haitan Technology for instructions on how to return the chargers for a full refund. Consumers will be instructed to contact the firm to request a prelabeled and prepaid return package to be sent to them so they can return the chargers to the firm for disposal.', '26379');
INSERT INTO safety_incidents VALUES ('60b1feaad8b972f8811e56e61e8194c7149977fb', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Ocun Condor HMS Triple Locking Carabiners', 'Injury', 'Mechanical Failure', 'Fall Injury', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled carabiner immediately and contact OCUN NA for a free replacement. Consumers will be asked to fill out the recall form and email it to recall@ocun.com and follow the instructions to receive a prepaid return shipping label and return the recalled product.', '26373');
INSERT INTO safety_incidents VALUES ('483711c7b298ddb8b84a5fe2d12733d5a434a4e7', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Member''s Mark Children''s Valentine SS Notch Collar Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pajama sets, take them away from children and contact Sam''s Club for information on how to receive a full refund. Consumers will be asked to return the product to their local store or to destroy the pajamas by cutting them in half and send a photo of the destroyed pajamas to Supersam@Samsclub.com then dispose of the product.', '26380');
INSERT INTO safety_incidents VALUES ('c84be3f620801dd276d308c4a909a18ac188cea1', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Universal Broadmoore brand Bellevue and Oaklynn model canopy bed frames', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received five reports of the bed canopy collapsing, including five reports of consumers being struck by the canopy beam and four resulting in shoulder and head contusion injuries.', 'Moderate', 1, 0, 'Consumers should not move the recalled bed frames and contact Samson International immediately for a free repair and installation kit consisting of four metal brackets and mounting hardware.', '26382');
INSERT INTO safety_incidents VALUES ('a14b179d29427a730f0cd957e08679e4b3001cd9', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Sangohe Adult Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled adult portable bed rails and contact Sangohe for a full refund. Consumers should destroy the bed rails by cutting the handrails'' foam padding and writing "RECALLED" on the upper and lower rails with permanent marker, take a photo of the destroyed rails and email the photo to SGHproductrecall@163.com.', '26378');
INSERT INTO safety_incidents VALUES ('1239c84f69459a16ef74708582e39f05c6f46c11', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'TecFlox Hair and Beard Growth Serum Bottles', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled serum bottles out of sight and reach of children and contact TecFlox to receive free replacement serum bottles, including shipping. Only bottles with serum remaining will be replaced. Consumers will be asked to dispose of the bottles'' contents and email a photo of the bottles in the trash, showing the manufacture date to TecFloxrecall@outlook.com', '26375');
INSERT INTO safety_incidents VALUES ('a9270e4883069c54cd48ec0809fedde5f75a3070', 'CPSC', '2026-04-02', 2026, '2026-04', 'USA', 'United States', '', 'Other', 'Tuymec Minoxidil Hair Growth Kits, 5% Minoxidil with Biotin Spray', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should secure the recalled serum bottles out of sight and reach of children immediately and contact DrHealBeauty for a free empty replacement bottle with a child-resistant closure into which consumers should transfer the recalled bottle''s contents.', '26381');
INSERT INTO safety_incidents VALUES ('cd8d172cf8ead54378e9a869ccbecefda794c16c', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', '4our Kiddies Plastic Tip Restraint Kits', 'The Recalled Plastic Tip Restraint Kits (Also Referred To As Furniture Straps) Can Break Or Degrade, Posing Tip-Over And Entrapment Hazards That Can Result In Serious Injuries Or Death To Children Or Elderly Consumers Interacting With Furniture That Is Secured To The Wall With The Defective Plastic Tip Restraints. This Is A Hidden Defect Because Consumers Who Purchase And Install This Product May Be Under A False Sense Of Security That Their Furniture Is Safe From A Tip-Over Incident.', 'Entrapment', 'Entrapment', 'CPSC is aware of at least 150 incidents where consumers reported that the defective plastic tip restraint kits broke, including three reported tip-over incidents.', 'Fatal', 1, 0, 'Consumers should stop using 4our Kiddies plastic tip restraints immediately and contact 4our Kiddies for a free replacement tip restraint kit made of stainless steel. Consumers should keep children away from the unit while waiting for a replacement tip restraint kit and should dispose of the recalled tip restraint in their household trash once they have installed the replacement tip restraint.', '26340');
INSERT INTO safety_incidents VALUES ('26f842cb40b6c220cabcf45af87e2e49589acd5a', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'AirClub Convertible Bassinets', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled AirClub convertible bassinets immediately and contact AirClub for a replacement attachment mechanism. Consumers will be asked to cut off the two original L-shape straps, throw them away and follow the instructions provided to install the new four straps with T-shaped buckle.', '26342');
INSERT INTO safety_incidents VALUES ('8b790e6a501f9d7c453bd3a91a0bd378edfc1165', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'CCCEI Power Strips', 'Fire', 'Electrical Fault', 'Respiratory', 'Middle Way Electronics has received two reports of the power strips sparking and melting. No fires or injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the CCCEI power strips and contact Middle Way Electronics to receive a full refund.', '26346');
INSERT INTO safety_incidents VALUES ('06470c47c11b35dda19b10c25de6ad45c408e989', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'DIY Sauna Heater Kits', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 12 reports of units overheating. No fires or injuries have been reported.', 'Fatal', 1, 0, 'Consumers should stop using the recalled Sauna Heater Kit immediately and register at www.diycoldplunge.com/pages/recall for a full refund. Consumers will be asked to submit written and photo proof that the product has been destroyed/disposed of or request a prepaid shipping label to return the product.', '26349');
INSERT INTO safety_incidents VALUES ('a5e5a82d0ae4c8df374c4e0187e80771ca783e71', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'DuraTrac stainless steel gas connectors', 'Fire', 'Mechanical Failure', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled DuraTrac stainless steel gas connectors immediately and contact DuraTrac for a full refund.', '26343');
INSERT INTO safety_incidents VALUES ('f0f966ce7874c261d72762c3b522bb0301494028', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'FUNTOK 24V 2-Seater Ride-On Trucks', 'Fire', 'Flammability / Overheating', 'Burns', 'Shenzhen Luobei Trading Co. has received 11 reports of the ride-on trucks catching fire, sparking, burning, melting, overheating and smoking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled ride-on truck immediately, unplug the truck if it is charging, and contact Shenzhen Luobei Trading Co. for instructions to receive a full refund. To obtain a refund, consumers will need to disable the ride-on truck by cutting the wires to the battery and submitting a photo of the cut wires with "VOID," the consumer''s name and the date written on the hood of the truck in permanent marker. Consumers should dispose of the disabled ride-on truck once they receive their refund. Directions on how to disassemble and disable the ride-on truck can be found on https://funtok.net/pages/voluntary-product-safety-recall. Note: Do not throw the truck battery in the trash, or in the general recycling stream (e.g., street-level or curbside recycling bins). Lead-acid batteries must be disposed of differently than other batteries. Your municipal household hazardous waste (HHW) collection center or battery recycling boxes found at various retail and home improvement stores may accept this lead-acid battery for disposal. Before taking your battery to a HHW collection center, contact that office ahead of time and ask whether it accepts lead-acid batteries. If it does not, contact your municipality for further guidance.', '26348');
INSERT INTO safety_incidents VALUES ('2a79bec0d4cdc976c21638e2a91cf525b26b2928', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'GLMZZ Fidget Magnet Ball Toys', 'The Magnet Ball Toys Violate The Mandatory Standard For Toys Because They Are High-Powered Magnets, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, They Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnet ball toys immediately, take them away from children, and contact GLMZZ to receive a full refund. Consumers will be asked to throw the magnet ball toys away and email photo of the disposal to GLMZZrecall@outlook.com.', '26345');
INSERT INTO safety_incidents VALUES ('d6f7a00d1fe13d9099822efd6896d7ae6a80c50c', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'MPINOI Adult Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled adult portable bed rails immediately and contact Bioenrrty for a full refund. Consumers will be asked to destroy the bed rails by cutting the black safety strap in half and writing "RECALLED" on the upper and lower rails with permanent marker, take a photo of the destroyed rails and email the photo to MPINOIproductrecall@outlook.com.', '26350');
INSERT INTO safety_incidents VALUES ('2b609221ddcc6d570d3e72a0f07ec6da0a5efcea', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Metal Wire Bristle Grill Brushes', 'Small Metal Wire Bristles Can Detach From The Brushes And Stick To The Grill Or Food, Posing An Ingestion Hazard And Risk Of Serious Internal Injuries That Could Require Surgery.', 'Mechanical Failure', 'Poisoning / Ingestion', 'Nexgrill is aware of at least 68 reports and reviews where small wire bristles detached from the grill brushes, including five reports of consumers who swallowed metal bristles and sought medical treatment to remove the bristles from their digestive tract or throat.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled grill brushes and contact Nexgrill for a full refund to be issued as a gift card. Consumers will be provided with a registration code as part of the recall process and will be directed to upload a photograph of their grill brush with that code and their initials to the recall website to register for the recall. After receiving a confirmation email that their registration has been successfully processed, consumers will then receive directions on how to discard of the recalled grill brush.', '26339');
INSERT INTO safety_incidents VALUES ('38ce0e2a907fdfc39d418ba6287699dbb7f74362', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Nomic and Ergonomic Ice Climbing Axes', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 26 reports of the ice axe shafts breaking at the handle. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled ice axes and contact Petzl America for a free repair kit. Consumers should register at https://www.petzl.com/US/en/Sport/Contact?request=product-recall to request a pre-paid shipping label to return the shaft. Petzl America will send a repair kit with a new shaft, hardware for the grip rest and assembly instructions.', '26347');
INSERT INTO safety_incidents VALUES ('697e2c966977876ae8b75ef37ea7bcf7158c8c2f', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Sunnyyes LED Mini Lights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled LED lights immediately and place them in an area where children cannot access them. Consumers will be asked to disassemble and submerge all components in water. To receive a full refund, consumers will be asked to email a photo of the submerged product to usa@sunnyyes.com. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26344');
INSERT INTO safety_incidents VALUES ('994a865a4ac8c82565cb44979f1f0b9db65f0db3', 'CPSC', '2026-03-26', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Vive Health Bed Rails', 'When The Recalled Bed Rails Are Attached To A Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Bed Rail And The Side Of The Mattress. This Poses A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'Vive Health has received two reports of entrapment deaths associated with one model of the recalled bed rails. The deaths occurred in September 2024 and involved a 97-year-old man at an assisted living facility in Texas and a 93-year-old man at his home in Florida.', 'Fatal', 1, 0, 'Consumers should stop using the recalled Vive Health Bed Rails immediately and contact Vive Health for a full refund. Consumers should write "RECALLED" on the upper and lower portions of the bed rails with permanent marker and take a photo of the marked bed rail with the buyer''s name on a piece of paper and email to recalls@vivehealth.com. Consumers should then dispose of the recalled product in accordance with the state and local waste disposal procedure.', '26341');
INSERT INTO safety_incidents VALUES ('172b298c2fbc18a3339e81d303aab46ba3100226', 'CPSC', '2026-03-19', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Aisstxoer Adult Bike Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled adult helmets immediately and contact YXTDZ Store for a full refund. Consumers will be asked to destroy the recalled helmet by cutting the straps and email a photo of the destroyed helmet to yxtdzamz@126.com.', '26335');
INSERT INTO safety_incidents VALUES ('655bb771b8fab70116375eb575fd01a378bb05db', 'CPSC', '2026-03-19', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Amazon Basics Camping Folding Pocket Knives', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Amazon received one report of the blade not remaining properly secured in the closed position. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled knife and register for the recall at https://amazonfoldingkniferecall.expertinquiry.com/. Consumers will be provided with a prepaid return kit and instructions to safely return the recalled knife to Amazon. Upon receipt, consumers will be issued a full refund to the original payment method or in the form of an Amazon gift card.', '26334');
INSERT INTO safety_incidents VALUES ('614e79dd8952412959baf2dbdb28a3fe891dedf3', 'CPSC', '2026-03-19', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Frigidaire Gas Ranges', 'Burns', 'Flammability / Overheating', 'Burns', 'Electrolux Group and the CPSC are aware of 62 reports of the oven''s bake burner delayed ignition, including 30 reports of burn injuries.', 'Minor', 1, 0, 'Consumers should stop using ovens in the recalled ranges immediately and contact Electrolux Group for a free repair. Electrolux Group will provide professional in-home installation of a new bake burner at no cost to consumers. Consumers can continue to use the cooktop burners on the range.', '26333');
INSERT INTO safety_incidents VALUES ('c4d7a20f223a3b6df7d12c2e070c7649ea1b9573', 'CPSC', '2026-03-19', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Goregent Infant Walkers', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled infant walkers and contact Goregent Official Store for a full refund. Consumers will be asked to disassemble the walker, remove the fabric seat, write "Recalled" on the top of the tray in permanent marker and send a photo of the recalled infant walker to GoregentInfantWalkersRecall@outlook.com.', '26332');
INSERT INTO safety_incidents VALUES ('82b2a78ad67f3918c56bf63d793bc746e80c1f86', 'CPSC', '2026-03-19', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'BUILT LUUM Tumblers', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'Lifetime Brands has received one report of a child gaining access to the tumbler''s button cell battery and putting it in the mouth. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should stop using the recalled tumblers immediately, place them in an area that children cannot access and properly dispose of the battery. Contact Lifetime Brands for a full refund. Consumers will be asked to throw the piece with the LED light away and upload a photo of the product in the trash when completing a Product Recall Refund Form at https://www.builtny.com/pages/recall. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedure.', '26331');
INSERT INTO safety_incidents VALUES ('199876ee941e4269131bcb880a0e72514a74501c', 'CPSC', '2026-03-19', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Specialized Turbo Como SL 4.0 & 5.0 Bicycle Forks', 'Falls', 'Chemical / Toxic Substance', 'Fall Injury', 'The firm has received one report of an incident involving a steerer tube failing and breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using their Specialized Turbo Como SL bicycles immediately and contact their Authorized Specialized Retailer to schedule an appointment to bring their bike in for a free replacement of the fork at an authorized dealer location. Replacement parts are expected to be available in Spring 2026.', '26330');
INSERT INTO safety_incidents VALUES ('0f3b52fa1c65085f8bed6d7724f506031d62b718', 'CPSC', '2026-03-19', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Swivel Office Chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled chairs immediately and visit https://www.tainoki.com/recall for instructions on how to participate in the recall. Consumers will be asked to submit photos of the recalled chairs, the model number and proof of destruction for a full refund.', '26329');
INSERT INTO safety_incidents VALUES ('b90cea70fd97088026a7c5f79a0d2cf25e640dd3', 'CPSC', '2026-03-19', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Wagner 900 Series Power Steamers', 'Burns', 'Drowning Risk', 'Burns', 'Wagner has received at least 156 incidents involving the hose getting too hot or the nozzle/gun expelling hot water. This includes over 50 reported burn injuries to consumers'' arms, hands, feet, and face, many of which resulted in first- or second-degree burns.', 'Moderate', 1, 0, 'Consumers should stop using the recalled steamers immediately and contact Wagner for a free repair kit, consisting of a hose sleeve, nozzle cover and funnel.', '26328');
INSERT INTO safety_incidents VALUES ('df05d1e0894c1a59907fde7a1505e911551899aa', 'CPSC', '2026-03-12', 2026, '2026-03', 'USA', 'United States', '', 'Other', '17 Stories Furniture 14-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Risks Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to the wall and place them in an area that children cannot access. Contact Hong Kong Baojia International for instructions on how to identify affected units and dispose of the dressers to receive a full refund. Consumers will be asked to submit a photo to Baojia_recall@outlook.com demonstrating disposal of the product.', '26323');
INSERT INTO safety_incidents VALUES ('4716955eeea97ef280bdff56c3a8a4ebd2d60cd7', 'CPSC', '2026-03-12', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Playground Swing Set Seats', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm received one report of a swing breaking and a child falling, resulting in a minor injury.', 'Minor', 1, 0, 'Consumers should stop using the recalled playground swings immediately and contact LFTE USA for a free replacement swing seat. Little Tikes Commercial and Miracle Recreation Equipment have contacted all known purchasers directly.', '26324');
INSERT INTO safety_incidents VALUES ('a45c942c8d46c353c97da4edcf723935a73eeffb', 'CPSC', '2026-03-12', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'LIVEHOM 11-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Risks Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Safety Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to the wall and place them in an area that children cannot access. Contact Simplehome for a full refund. Consumers will be asked to write "RECALL" with permanent marker on the dressers and send a photo of the marked dressers to livehomerecall@163.com. Consumers should then dispose of the recalled product.', '26321');
INSERT INTO safety_incidents VALUES ('e1076a0e36047578c8a0812e4d4e8ff01e3c6d54', 'CPSC', '2026-03-12', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'ProRider Bicycle Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact ProRider for a full refund. Consumers should destroy the helmet by cutting the straps and sending a photo of the destroyed helmet to org@prorider.com to obtain a refund.', '26320');
INSERT INTO safety_incidents VALUES ('a5ab78875a230919669db9fd7baf619f6909edbe', 'CPSC', '2026-03-12', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Kluster Fun Tabletop Magnet Chess Games', 'The Recalled Magnet Games Violate The Mandatory Standard For Toys Because They Contain Loose High-Powered Magnets That Fit Within Cpsc''S Small Parts Cylinder, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled magnet games, take them away from children and contact Stoney Games for instructions on how to dispose of the recalled magnets and receive replacement magnets that are not small parts.', '26319');
INSERT INTO safety_incidents VALUES ('4d761228144fbd5729a93ba7784c80cc38451626', 'CPSC', '2026-03-05', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Cubimana Island Storm 3 In 1 Building Sets with LED Lights', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should take the Island Storm 3 In 1 Building Sets away from children immediately, stop using the recalled toys and remove and properly dispose of the batteries. Consumers will be asked to throw the product away and send a photo of the disposed product to productrecall@cubimanatoys.com to receive a full refund. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26317');
INSERT INTO safety_incidents VALUES ('0044ed1dc94d770b9c19e2037502a8247b55b3fd', 'CPSC', '2026-03-05', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'HALO Magic Sleepsuits', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received 15 reports of the zipper head detaching from the garment. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled HALO Magic Sleepsuit immediately and go to the firm''s website at http://www.sleepsuitrecall.com to participate in the recall. After registering, consumers will receive a coupon code that can be applied towards a replacement sleepsuit or a $50 store credit to purchase another item on the firm''s website. Do not discard the recalled garment until you have received the coupon code.', '26315');
INSERT INTO safety_incidents VALUES ('216759c7cb188d53736ffc531a3da357e9688d5d', 'CPSC', '2026-03-05', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Tomum Hair Regrowth Treatment with Minoxidil for Men and Women Spray Bottles', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should secure the recalled serum bottles out of sight and reach of children immediately and contact Belleka for a free replacement product, including two child-resistant bottles of serum (60 mL per unit). Consumers will be asked to dispose of the recalled product bottle and send a photo of the bottle in the trash to Belleka at tomumcs@gmail.com.', '26312');
INSERT INTO safety_incidents VALUES ('28db76c2c8cdc1fa7e0495e2179a8877bdf7c8c4', 'CPSC', '2026-03-05', 2026, '2026-03', 'USA', 'United States', '', 'Other', 'Forever 21 Kids Disney Mickey Mouse Pajama Pants', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled pajama pants immediately and contact Unique Brands Com for a full refund. Consumers will be provided with a prepaid shipping label to return the recalled kids pajama pants.', '26309');
INSERT INTO safety_incidents VALUES ('e83e37a80159beb41573c2d87903c98f06c542f1', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Window opening control devices sold as kits or installed on 100 Series casement windows', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received eight reports of the devices breaking, detaching or malfunctioning. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should leave the recalled windows with the opening control devices in the closed and locked position and immediately contact Andersen Windows to schedule a free in-home repair by an authorized technician. Consumers should submit a request for the repair to: www.andersenwindows.com/100seriescasementwocdrecall.', '26306');
INSERT INTO safety_incidents VALUES ('5d8b9903cd6512687b3aef47043626bc9949058c', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Babysense Max View Baby Monitors', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Hisense has received 11 reports of incidents involving the display unit for the Babysense Max View Baby Monitors. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the display unit of the Max View baby monitors immediately and contact Hisense for a free replacement display unit that does not pose a fire hazard.', '26307');
INSERT INTO safety_incidents VALUES ('822cffc01744ca7f3819310702a776760a8c15b6', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'High Chairs', 'Falls', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled high chairs and contact Bicystar Store for a full refund. Consumers should disassemble the high chair, cut the restraints and fabric seat cover, write "Recall" on the backseat and send photos of the destroyed high chairs to bicystarhighchair@outlook.com.', '26290');
INSERT INTO safety_incidents VALUES ('afeaeb63933cce72a49957aa441b1b27cfb070a3', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Dupray Neat Steam Cleaners', 'Burns', 'Mechanical Failure', 'Laceration / Cut', 'The firm has received 15 reports of boiler ruptures, including four reports of minor burns, bruises, lacerations, and a broken wrist, and at least seven reports of minor property damage.', 'Serious', 1, 0, 'Consumers should stop using the recalled steam cleaner immediately and go to dupray.com for instructions on receiving a free replacement safety boiler cap. Consumers will need their batch code, which is found on the bottom of the cleaner, to determine eligibility for the recall. The new safety cap is quick and easy to install with a simple screw-on design.', '26283');
INSERT INTO safety_incidents VALUES ('187da311b9d86b506686bf3d2e895d6d726c013a', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Evajoy 48-inch and taller above-ground pools', 'Drowning', 'Drowning Risk', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should contact Evajoy to request a free repair kit that removes the compression strap from the pool, while maintaining the structural integrity of the pool. In the interim, consumers should ensure that children cannot access the pool unattended or, alternatively, drain the pool until the repair can be installed.', '26308');
INSERT INTO safety_incidents VALUES ('152223bec1edf76ce4564d3e790e45dc121acd8a', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Grtard Magnet Stick Figure Men Toy Sets', 'The Magnetic Stick Figure Toy Sets Violate The Mandatory Standard For Toys Because They Contain Loose Magnets, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled magnetic stick figures and take them away from children. Contact Grtard for information on how to receive a full refund. Consumers will be asked to email a photo of the disposed product to Grtardrecall@outlook.com.', '26291');
INSERT INTO safety_incidents VALUES ('bad33c26ffad9a0b4ad9d306688f287b45180446', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Joyreal Busy Board Toys', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled toys immediately, take them away from children and contact Indream Store for a full refund. Consumers will be asked to destroy the busy board by writing "RECALLED" with permanent marker on the front of the toy and send a photo of the destroyed toy to indreamrecall@outlook.com. Consumers should then dispose of the recalled product.', '26303');
INSERT INTO safety_incidents VALUES ('261dda1924ea5976fc9e31294d74b143d8c337ad', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Magnetic Chess Games', 'The Recalled Magnetic Chess Games Violate The Mandatory Standard For Toys Because They Contain Loose Magnets Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic chess games immediately, take them away from children, and dispose of them. To receive a full refund, consumers will be asked to email a photo of the disposal to Kaiwenshangpinrecall@outlook.com.', '26289');
INSERT INTO safety_incidents VALUES ('f1589c2ce68e36c8438a3108029e724bc81ca5ef', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'High Bay Linear LED light fixtures', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of a LED light fixture catching fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the High Bay Linear LED light fixtures and contact PQL for free replacement retaining pins. Consumers should register their product at https://pqlighting.com/product-recall-notice.', '26278');
INSERT INTO safety_incidents VALUES ('663e42ea8ad63ba073eafb12c1e316308ea002dc', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Royal Oak Flame Saber Lighters', 'Fire', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled lighters immediately and contact Royal Oak for a full refund. Consumers will be given instructions on how to destroy the device and submit proof of destruction to receive a refund.', '26284');
INSERT INTO safety_incidents VALUES ('65c21395cdc1ea20989be1d0b559b5fcead23e48', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Vevor Retractable Baby Gates', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Serious', 1, 0, 'Consumers should stop using the recalled gates immediately and contact Sanven Technology for a full refund. Consumers should destroy the gate by cutting through the mesh and send a photo of the destroyed gate to recalling@vevor.com.', '26264');
INSERT INTO safety_incidents VALUES ('736b4993a025fac2c37627d795d4a02515d1161a', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Somgem Lightweight Tiny Pinky Pig and Yomin Toilet Lighters', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled lighters immediately and contact Elepdv for a full refund. Consumers will be asked to send a photo of the disabled lighter showing "Recalled" written on it to elepdv@163.com to receive a full refund. Consumers should dispose of the recalled lighters in accordance with state and local waste disposal procedures.', '26285');
INSERT INTO safety_incidents VALUES ('bbccfa3f23a09b3a2f91a59683152a69baeda7e3', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'SumDirect LED Mini Lights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled LED lights, place them in an area that children cannot access and properly dispose of the batteries. Contact SumDirect for a full refund. Consumers will be asked to send a photo of the product in the trash to recall@dgfuxin.cn. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26305');
INSERT INTO safety_incidents VALUES ('ddb0dc96eca61d1dd6800a6366a51a6f8a794800', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Tubby Tots Fizzy Flask Bath Magic bath foam set', 'Moisture Trapped Inside The Bath Foam Set Container Can Cause Pressure To Build Up, Allowing Pieces To Be Forcefully Ejected When Opened, Posing An Impact Hazard.', 'Explosion', 'Fracture / Blunt Trauma', 'The firm has received three reports of pieces ejecting forcefully from the plastic container when opened. Two consumers reported bruises and swelling after being struck in the arm and face, including a consumer who reported a chipped tooth.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled plastic flask bath foam sets and contact Surreal Brands for a full refund. Consumers should register at www.wonderfunbrands.com/recall, permanently mark the plastic flasks with the word "Recalled" and dispose of them in a sealed garbage bag for household waste collection.', '26286');
INSERT INTO safety_incidents VALUES ('767cc0b5e54b02abd5cdcfa9ab511e9d5930dca3', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Children''s Christmas Tree Toy Play Sets', 'Electric Shock', 'Electrical Fault', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled play sets immediately, take them away from children, and contact TheKiddoSpace for a free replacement toy of at least equal value to the purchase price of the recalled play set, including free shipping. Consumers will be asked to write "RECALLED" on the tree and submit a photo of the marked product to info@thekiddospace.com. Consumers should then discard the tree and storage box in accordance with their local waste disposal requirements.', '26300');
INSERT INTO safety_incidents VALUES ('955477ae5e12946759c3e288f3d8172ba9ff1a70', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'TheKiddoSpace Fingerpainting Kits', 'The Recalled Children’S Fingerpainting Kits Contain The Hazardous Substances Methanol And Ethylene Glycol And Are Intended For Children Under 12 Years Of Age, Which Violate The Federal Hazardous Substances Act. The Products Also Contain A Regulated Phthalate, Which Violate The Federal Phthalate Ban; Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Skin Irritation', 'TheKiddoSpace has received 18 reports worldwide, including one in the United States, of strong paint odor, skin irritation and swollen lymph nodes.', 'Moderate', 1, 0, 'Consumers should stop using the recalled handwriting kits immediately, take the pens and refills away from children and contact The KiddoSpace to receive free replacement pens and refills, including shipping. Consumers will be asked to dispose of the pens and refills according to local and state regulations and send a photo of the disposed products to info@thekiddospace.com.', '26294');
INSERT INTO safety_incidents VALUES ('1ac86669b46b5e3a7574e3fb3aef7953cbb6e762', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'KiddoSpace Children''s Flashcard Talking Toys', 'The Recalled Children''S Flashcard Toy Sets Contain Levels Of Lead That Exceed The Federal Lead Content Ban And Levels Of Phthalates That Exceed The Federal Phthalates Ban. Lead And Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Issues. In Addition, The Flashcards Also Violate The Mandatory Standard For Toys Because They Fail To Comply With The Short Circuit Protection Requirement For Battery-Operated Toys.', 'Electrical Fault', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled toys immediately, take them away from children and contact TheKiddoSpace for a free replacement toy or free USB cable, including shipping. - For the animal-shaped toy, consumers will be asked to write "RECALLED" in permanent marker on the unit and submit a photo of the marked product to info@thekiddospace.com to receive a replacement toy of at least equal value to the purchase price of the recalled animal-shaped toy. Consumers should then dispose of the recalled toys in accordance with their local waste disposal requirements. - For the rectangular toy, consumers will be asked to cut the USB cable and submit a photo of the cut USB cable to info@thekiddospace.com to receive a free replacement USB cable. Consumers should then dispose of the cut USB cable. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26296');
INSERT INTO safety_incidents VALUES ('f51d1b88b92015057dda97ee0a4b1d9145ea5e64', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'TheKiddoSpace Print and Cursive Handwriting Kits', 'The Pens In The Recalled Children''S Handwriting Kits Contain Levels Of Lead In The Nib That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled handwriting kits immediately, take the pens and refills away from children and contact The KiddoSpace to receive free replacement pens and refills, including shipping. Consumers will be asked to dispose of the pens and refills according to local and state regulations and send a photo of the disposed products to info@thekiddospace.com.', '26293');
INSERT INTO safety_incidents VALUES ('a65b165ba1a34cb1b9fb38b30ddca18bcd20d65d', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'TheKiddoSpace Children''s Montessori Egg Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled toys immediately, take them away from children and contact TheKiddoSpace for a free replacement toy or free USB cable, including shipping. - For the animal-shaped toy, consumers will be asked to write "RECALLED" in permanent marker on the unit and submit a photo of the marked product to info@thekiddospace.com to receive a replacement toy of at least equal value to the purchase price of the recalled animal-shaped toy. Consumers should then dispose of the recalled toys in accordance with their local waste disposal requirements. - For the rectangular toy, consumers will be asked to cut the USB cable and submit a photo of the cut USB cable to info@thekiddospace.com to receive a free replacement USB cable. Consumers should then dispose of the cut USB cable. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26297');
INSERT INTO safety_incidents VALUES ('e4585bce02f5c804b75525aa4f6ffa37487cb0e6', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'TheKiddoSpace Children''s Sensory Swing', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled swings immediately, take them away from children and contact TheKiddoSpace for a full refund. Consumers will be asked to destroy the swing by cutting the fabric in half and to send a photo of the destroyed swing to info@thekiddospace.com. Consumers should then dispose of the destroyed swing.', '26301');
INSERT INTO safety_incidents VALUES ('da46fb9a2aa18be69b43d6be98902b77888b0422', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'TheKiddoSpace Children''s Story Books', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled books immediately, take them away from children and contact TheKiddoSpace for a full refund. Consumers will be asked to write "RECALLED" in permanent marker on the book and send a photo of the marked book in the trash to info@thekiddospace.com.', '26292');
INSERT INTO safety_incidents VALUES ('83e3379d849f3b3dc82e0ed511d18b8f11d1beb0', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'TheKiddoSpace LED Soccer Hover Balls', 'Burns', 'Other', 'Burns', 'TheKiddoSpace has received three reports of a burning smell coming from the hover ball when in use. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled balls immediately, take them away from children and contact The KiddoSpace to receive a free replacement LED soccer hover ball, including shipping. Consumers will be asked to write "RECALLED" in permanent marker on the ball and send a photo of the marked ball to info@thekiddospace.com. Consumers should then dispose of the ball in accordance with their local waste disposal requirements.', '26298');
INSERT INTO safety_incidents VALUES ('0f4c52f64ef7ca987566491e7e67467d13e2eab7', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'TheKiddoSpace Peg Dolls in Cups Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled toys immediately, take them away from children and contact TheKiddoSpace for a full refund. Consumers will be asked to write "RECALLED" in permanent marker on the pieces and send a photo of the marked toys to info@thekiddospace.com. Consumers should then dispose of the toys.', '26299');
INSERT INTO safety_incidents VALUES ('43b869377e86bd33c01c12253c577fc227298981', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'TheKiddoSpace Reusable Water Balloons', 'The Cord Lock On The Recalled Water Ballons'' Storage Bags Contain A Regulated Phthalate, Which Violate The Federal Phthalate Ban. Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled reusable water balloons immediately, take the storage bag away from children and contact TheKiddoSpace to receive a free replacement bag, including shipping. Consumers will be asked to cut the storage bag in half and send a photo of the destroyed bag to info@thekiddospace.com. Consumers should then dispose of the destroyed bags in accordance with their local waste disposal requirements.', '26295');
INSERT INTO safety_incidents VALUES ('056f7f6adb5c7cd01d2dab84379128e11e1320c7', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Concord 360 Degree Rechargeable Light-Up Bike Helmet', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Concord Helmets and contact Todson for a full refund. Consumers should destroy the recalled helmets by cutting the straps off the helmets. Consumers can send photos of the helmet with the straps cut off to 360concordhelmet@todson.com to obtain a refund. Note: Do not throw this recalled helmet with a lithium-ion battery in the trash, the general recycling stream (e.g., street-level or curbside recycling bins), or used battery recycling boxes found at various retail and home improvement stores. Lithium-ion batteries must be disposed of differently than other batteries, because they present a greater risk of fire. Your municipal household hazardous waste (HHW) collection center may accept this recalled lithium-ion battery or device for disposal. Before taking your battery or device to a HHW collection center, contact that office ahead of time and ask whether it accepts lithium-ion batteries. If it does not, contact your municipality for further guidance. You can also visit Todson.com/360-concord-recall for more information on potential disposal locations.', '26304');
INSERT INTO safety_incidents VALUES ('c5be054de8c90fd736278c8b536baf9fb7433d66', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Trankerloop Baby Bath Seats', 'Injury', 'Instability / Fall Risk', 'Drowning', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bath seats and contact Trankerloop for a full refund. Consumers will be asked to write "Recalled" on the front of the bath seat in permanent marker, disassemble the bath seat by removing the back rest and arm restraints, cut the four suction cups on the bottom and email a photo of the disassembled recalled bath seat showing the marked front of the seat to hkkll147@outlook.com.', '26288');
INSERT INTO safety_incidents VALUES ('98e2d3fe499a9ddf6a231cdfac8ff47a43be2cc0', 'CPSC', '2026-02-26', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Zelbuck Magnetism Ball Game Toys', 'The Recalled Children''S Chess Games Violate The Mandatory Standard For Toys Because They Contain Loose Magnets Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, They Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled games immediately, take them away from children and contact n b plus for a full refund. Consumers will be asked to write "RECALLED" in permanent marker on the games and send a photo of the marked games to zelbuckrecall@sina.com. Consumers should then dispose of the recalled product.', '26302');
INSERT INTO safety_incidents VALUES ('99341dd122ce6c3f010c2f1d9643e5719552fc09', 'CPSC', '2026-02-24', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Christmas-themed Magnetic Chess Games', 'The Recalled Magnetic Chess Games Violate The Mandatory Standard For Toys Because They Contain Loose Magnets Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled magnetic chess games, take them away from children and contact Yiruikeji2024 for a full refund. Consumers will be asked to send a photo of the disposed product to yirui2024@yeah.net.', '26287');
INSERT INTO safety_incidents VALUES ('2d73c269abc2175499563c4c6e2bacce7a02bf0f', 'CPSC', '2026-02-19', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Huaker Magnetic Balls and Rods Sets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic balls and rods sets immediately, take them away from children and contact Huaker to receive a full refund. Consumers will be asked to throw the magnetic toy sets away and email a photo of the disposed product to Huaker-magnetic-balls@outlook.com.', '26272');
INSERT INTO safety_incidents VALUES ('21f46d6115f42cdeb40bc1a867102bbd2c60f862', 'CPSC', '2026-02-19', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'JJGoo LED Balloon Lights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled LED lights immediately, place them in an area that children cannot access and properly dispose of the batteries. Contact JJGoo for a full refund. Consumers should throw the balloon lights away and send a photo of the product in the trash to JJGooLEDBalloonLightsrecall@outlook.com. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26274');
INSERT INTO safety_incidents VALUES ('95aa2d32174e627298939c7a1387cd8d3e042a79', 'CPSC', '2026-02-19', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Joly''s 80% Vinegar (32 oz, pack of two)', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should move the vinegar products out of sight and reach of children immediately and contact Joly''s to receive a full refund and disposal instructions. Consumers will be asked to send an email to jolysllc@gmail.com with a photo of the recalled product in its original packaging and "RECALLED" printed on the container.', '26273');
INSERT INTO safety_incidents VALUES ('78cffa735082a6e4689cd33b60af219002fc3071', 'CPSC', '2026-02-19', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Meijer one-piece footed 12-, 18-and 24-month children''s sleepwear', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled sleepwear and return the product to a Meijer store for a full refund.', '26275');
INSERT INTO safety_incidents VALUES ('90d12aa316706f9ad30df09ac287c842f9e17546', 'CPSC', '2026-02-19', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Prismatic 3D Prints Book Nooks with Lights', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the book nooks immediately, remove the batteries and place them in an area that children cannot access. Consumers should contact Prismatic 3D Prints for instructions on receiving a free repair kit. The repair kit will include a part to permanently cover the spare battery holder and installation instructions. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26276');
INSERT INTO safety_incidents VALUES ('d7ab4f4bcca0b38329bd02e021cb3a2a1ac7d527', 'CPSC', '2026-02-19', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'SAMIT Youth Multi-Purpose Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Samit Outdoor for a full refund. Consumers should destroy the recalled helmet by cutting the straps off. Consumers can upload photos of the helmet with the straps cut off to usjialebei@foxmail.com to obtain a refund.', '26277');
INSERT INTO safety_incidents VALUES ('66a94dc83860ff671aad2718e461b01c1ca3ba8c', 'CPSC', '2026-02-19', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Vive Health Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using Vive Health Bed Rails immediately and contact Vive Health for a full refund. Consumers should write "RECALLED" on the upper and lower bedrails with a permanent marker and take a photo of the marked bed rail with the buyer''s name on a piece of paper, and email to recalls@vivehealth.com. Consumers should then dispose of the recalled product in accordance with the state and local waste disposal procedure. Only bed rails purchased after August 21, 2023, are included in this recall.', '26271');
INSERT INTO safety_incidents VALUES ('558814ba2f4c9036442a413fa0cf24b3d6ee4542', 'CPSC', '2026-02-12', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Beloems Adult Portable Bed Rails', 'Injury', 'Sharp Edges / Points', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled adult portable bed rails and contact Beloems for a full refund. Consumers should destroy the bed rails by cutting the handrails'' foam padding and writing "RECALLED" on the upper and lower rails with permanent marker, take a photo of the destroyed rails and send it to leioujiapin@163.com.', '26267');
INSERT INTO safety_incidents VALUES ('2ea07e7591db168e00ce5120b06fbf700ea0ce3c', 'CPSC', '2026-02-12', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'CheerKid Baby Bath Seats', 'Injury', 'Instability / Fall Risk', 'Drowning', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bath seats and contact Babibaby for a full refund. Consumers should write "Recalled" on the front of the bath seat in permanent marker, disassemble the bath seat by removing the back rest and arm restraints, discard the screws, cut the five suction cups on the bottom and send a photo of the disassembled recalled bath seat showing the marked front of the seat to CheerKid-Recall@outlook.com.', '26266');
INSERT INTO safety_incidents VALUES ('6348ad03d8040c2c7221fc9729bff8da09d36506', 'CPSC', '2026-02-12', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Fortemotus Adult Portable Bed Rails', 'Injury', 'Sharp Edges / Points', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled adult portable bed rails and contact Fortemotus Direct US for a full refund. Consumers should destroy the bed rails by cutting the handrails'' foam padding, take a photo of the destroyed rails and send it to fortemotusofficial@outlook.com', '26263');
INSERT INTO safety_incidents VALUES ('085cdd59e31a3feba497625179016e8559cfd439', 'CPSC', '2026-02-12', 2026, '2026-02', 'USA', 'United States', '', 'Other', '3-Pack Smoke Detector Fire Alarms', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the smoke detector fire alarms and contact lmm15957491237@163.com for instructions on how to receive a full refund through Amazon.com. Smoke alarms can be discarded in the household trash.', '26260');
INSERT INTO safety_incidents VALUES ('e54970f41ce98e5b17bbdd323614e7cd80b584e8', 'CPSC', '2026-02-12', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'SOOWERY 6-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Risks Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to the wall and place them in an area that children cannot access. With a permanent marker, write the word "recalled" on the top and all sides of the dresser. Contact SOOWERY for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to SOOWERYrecall@outlook.com showing disposal of the product.', '26261');
INSERT INTO safety_incidents VALUES ('ebcc38ddc3a12fca0721d1b5e9d617533fd85780', 'CPSC', '2026-02-12', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Colombia-themed Magnetic Board Games', 'The Recalled Board Games Violate The Mandatory Standard For Toys Because The Magnetic Game Pieces Contain Loose High-Powered Magnets, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled magnetic board games and take them away from children. Consumers should contact Surveying Accessories Cheaper for a pre-paid shipping label to return the board games for a full refund in the form of the original form of payment or check.', '26265');
INSERT INTO safety_incidents VALUES ('83b43a3050609d1b40b5a38ce00745a42e365350', 'CPSC', '2026-02-12', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Hydromassage Rotary Jet (6 fin) in Highlife Collection spas', 'Drowning', 'Drowning Risk', 'Drowning', 'The firm has received one report of a consumer whose hair was entangled in the jets. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled jets and go to the firm''s website http://www.hotspring.com/recalls to determine if their spa has them. If it is determined that the spa has the recalled parts, contact the firm to obtain instructions and a video that demonstrates how to turn the recalled jets off and how to install free replacement jet inserts in your spa. Consumers will need the serial number located on the front of the spa to make the determination.', '26268');
INSERT INTO safety_incidents VALUES ('68de52da15bb5f67a942ae22db1ecdc10fca9515', 'CPSC', '2026-02-09', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Aroeve brand air purifiers', 'Fire', 'Flammability / Overheating', 'Burns', 'Airova received 37 reports of the air purifiers overheating, including one report of fire. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled Aroeve air purifiers immediately and contact Airova for a free replacement air purifier.', '26244');
INSERT INTO safety_incidents VALUES ('b64a10be74e89af28dfcf5aabd3d0c2f1275d180', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Andy & Evan Children''s Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the pajama sets and contact Andy & Evan for a full refund. Consumers should cut the pajamas in half, take a photo of the destroyed pajamas and email it to recall@andyandevan.com, then dispose of the destroyed pajamas.', '26257');
INSERT INTO safety_incidents VALUES ('3f355c3b58625a05481a42348b688a3bd75b6109', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'PurSteam Mighty Lil Steamers and PurSteam Elite Travel Steamers', 'Burns', 'Drowning Risk', 'Burns', 'Between December 2020 and 2024, there were 80 reports of hot water being expelled from the PurSteam Elite Travel Steamer model PS-510, including 14 reports of burn injuries. Between December 2020 and 2024, there were 392 reports of hot water being expelled from the PurSteam Mighty Lil Steamer model PS-550, including 40 reports of burn injuries, two of which were reported as second-degree burns. There are additional reports of hot water being expelled from both steamer models, including reports o', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled steamers and visit recall.pursteam.com to submit a Recall Request. As part of the request process, consumers will be required to provide their contact information and then cut the steamer''s cord and upload a photo of the steamer with its cut cord, in order to receive a full refund. Consumers should keep their steamer until receiving their refund, as some consumers may be asked to return their steamer to Aterian with a prepaid shipping mailer.', '26250');
INSERT INTO safety_incidents VALUES ('f2bf615939c6498a217a2ca8f00b2b6fcaccabd6', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Lancaster Table & Seating Powder-Coated Aluminum Outdoor Chairs and Barstools', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received 36 reports of broken or bent chair legs, resulting in four falls and three injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled chairs and barstools and contact Clark Associates for a full refund to the original method of purchase or a store credit. Consumers should register their product online at www.lancastertableandseating.com/recalls/powder-coated-aluminum-chairs, mark the product with the word "Recalled" in paint or thick permanent marker in a visible location and dispose of the product in accordance with local and state laws.', '26253');
INSERT INTO safety_incidents VALUES ('3e29c7359adc2e43b82738a30ace0a5adb06b9af', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Cobelae Busy Book for Toddlers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled chairs and barstools and contact Clark Associates for a full refund to the original method of purchase or a store credit. Consumers should register their product online at www.lancastertableandseating.com/recalls/powder-coated-aluminum-chairs, mark the product with the word "Recalled" in paint or thick permanent marker in a visible location and dispose of the product in accordance with local and state laws.', '26254');
INSERT INTO safety_incidents VALUES ('6c3fe1508f5c7184e51b22b2d3560f6adf51c3e6', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Dresbe LED Christmas Headbands', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled headbands immediately and contact Dresbe for information on how to properly dispose of the product. Consumers will need to email a photograph of disposal to?dresberecall@shineprom.com?to receive the refund. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26249');
INSERT INTO safety_incidents VALUES ('81b371eb6349e97299a8081694c5e1114107190c', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Ammo Tabs Fiber Desiccant Tiles used for Firearms and Ammunition', 'Fire', 'Mechanical Failure', 'Not Specified', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Ammo tab and go to the firm''s website at https://www.norustzone.com to receive instructions on how to receive a full refund and to dispose of the tab.', '26256');
INSERT INTO safety_incidents VALUES ('205090883fa61ac8b94be027fe21ce8e2f44e374', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'EnHomee 10-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Risks Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers, if they are not anchored to the wall, and place them in an area that children cannot access. Contact EnHomee for instructions on how to identify affected units and dispose of the dressers to receive a full refund. Consumers must submit a photo to enhomeestore@gmail.com showing disposal of the product.', '26255');
INSERT INTO safety_incidents VALUES ('133b47e50f846f2c91429ad0c0e470580beb40b5', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Fixwal 7-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Risks Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to the wall, place them in an area that children cannot access and contact Momok for a full refund. Consumers should write "RECALLED" on the front, side, and back of the dresser with a permanent marker, take photos and email them to fixwaldresserrecall@outlook.co.', '26248');
INSERT INTO safety_incidents VALUES ('f7486c9f9a0c0dfac360364157cb25c6005de322', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Furnulem 5-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Risks Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to the wall and place them in an area that children cannot access. Contact Furnulem for instructions on how to dispose of the dressers for a full refund. Consumers should send a photo demonstrating disposal of the product to support@furnulem.com.', '26247');
INSERT INTO safety_incidents VALUES ('83b15f4ca29c6c3601065b1d1e7268fed2c56235', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'GM Gumili Wintergreen Essential Oil Bottles', 'The Essential Oil Contains Methyl Salicylate, Which Must Be In Child-Resistant Packaging, As Required By The Poison Prevention Packaging Act (Pppa). The Packaging For The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately secure the recalled essential oil out of the sight and reach of children and contact the firm to receive a full refund or free replacement bottle of essential oil. Consumers will be asked to take a photo of their product in the trash in order to receive a refund or replacement and email the photo to gumilius@outlook.com.', '26243');
INSERT INTO safety_incidents VALUES ('8ce4ce26e33495843e64e2559460210e89c784aa', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Kitosun Submersible LED Lights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled essential oil out of the sight and reach of children and contact the firm to receive a full refund or free replacement bottle of essential oil. Consumers will be asked to take a photo of their product in the trash in order to receive a refund or replacement and email the photo to gumilius@outlook.com.', '26246');
INSERT INTO safety_incidents VALUES ('e9644ed2b0ef40ff60956d856e7043b96d506cfd', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Little Cow Co. 9 oz candles in glass jars', 'Fire', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received two reports of glass jar breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles and contact Little Cow Company to receive a full refund. Consumers will be asked to use a permanent marker to draw an ''X" on the glass container, cut the wicks and email a photo of the marked jar can and cut wicks to Little Cow Company.', '26241');
INSERT INTO safety_incidents VALUES ('483a1bc65c015943ce189aba92f048d359ac9eab', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Lola + The Boys Youth Clothing with Drawstrings', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately take the recalled clothing away from children, remove the drawstrings to eliminate the hazard and contact Lola Plus The Boys for a full refund. Consumers should send a photo of the clothing without a drawstring, along with their name and the date, to customerservice@lolaandtheboys.com.', '26240');
INSERT INTO safety_incidents VALUES ('7e466fb5c7f7a5dec047129a8b4b42b39f792f17', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Organic Zing Birch Oil Bottles', 'The Essential Oil Bottles Contain Methyl Salicylate, Which Must Be In Child-Resistant Packaging, As Required By The Poison Prevention Packaging Act (Pppa). The Bottles For The Products Are Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately secure the recalled essential oil bottles out of the sight and reach of children and contact Linkers for a full refund and instructions on destroying the recalled bottles. Consumers will be asked to pour the contents of the bottle into the trash and email a photo of the disposed bottle to admin@linkersecomm.com.', '26242');
INSERT INTO safety_incidents VALUES ('5f8112887b02c54e7ce620828f4b3df45993f20e', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Semfri Children''s Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Semfri for a full refund. Consumers should destroy the helmet by cutting the straps and sending a photo of the destroyed helmet to Semfri_recall@163.com.', '26239');
INSERT INTO safety_incidents VALUES ('e6d8073eace5a3221d88e6e9d5e796184b88b9c2', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Shintenchi 6-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Risks Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers, if they are not anchored to the wall, and place them in an area that children cannot access. Contact Shintenchi for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to ShintenchiRecall@hotmail.com showing disposal of the product.', '26238');
INSERT INTO safety_incidents VALUES ('aadbf44f2a044a9fe8956ae01a437654f7ba80c9', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Yitahome, Uforic, Dextrus, Yintatech and ModFusion-branded Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Risks Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The?Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers, if they are not anchored to the wall, and place them in an area that children cannot access. Contact YITA for a full refund. Consumers should write "RECALL" on the dressers using a permanent marker, disassemble them and submit a photo of the disposed product to yitamotor@outlook.com.', '26251');
INSERT INTO safety_incidents VALUES ('29bf0dbec59d17ad47b9e65162de6738850e6b20', 'CPSC', '2026-02-05', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Lotus Joy Organic Sweet Birch Essential Oil Bottles', 'The Essential Oil Bottles Contain Methyl Salicylate, Which Must Be In Child-Resistant Packaging, As Required By The Poison Prevention Packaging Act (Pppa). The Bottles Are Not Child-Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately secure the recalled essential oil out of the sight and reach of children and contact Zan International Trading for a full refund. Consumers will be asked to pour the contents in the trash and take a photo of the bottle in the trash and email it to Zan International Trading at zantradellc@hotmail.com.', '26229');
INSERT INTO safety_incidents VALUES ('7e3ce9838937c95cba00caf4f44eac3afa9ed63d', 'CPSC', '2026-02-04', 2026, '2026-02', 'USA', 'United States', '', 'Other', 'Scepter Gas and Oil Combination Fuel Containers', 'Fire', 'Flammability / Overheating', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled fuel containers, place them out of reach of children and contact Mameix Retail for a full refund. Consumers will be asked to write "Recalled" with permanent marker on the container and submit a photo of it in the trash to scepterrecall@gmail.com.', '26252');
INSERT INTO safety_incidents VALUES ('ebedfe079be2f0d9499954d4e5a6ab2363a9a9cc', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'AiTuiTui Pull String Teething Toys', 'Injury', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'CPSC is aware of 15 choking incidents and two incidents of children able to bite pieces off the silicone strings.', 'Fatal', 1, 0, 'Consumers should stop using the teething toy immediately and contact Vanfun for full refund remedy. Consumers should cut and discard all string tentacles, write "DESTROYED" on the off-white main body of the toy using a permanent marker, and email a photograph of the destroyed product to recallmls@outlook.com.', '26219');
INSERT INTO safety_incidents VALUES ('f9863837a1cfa23a00c129410824734b4384c16b', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Bazic Silicone Glue', 'Fire', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled Bazic Silicone Glue immediately and contact Bazic Products for instructions on how to submit a photo of the product to receive a full refund. Note: The recalled glue should be disposed of in accordance with any local and state regulations, contact your local hazardous waste treatment center. Do not dispose of methanol in sewers, rainwater pipes or ordinary garbage cans to avoid causing fires or environmental pollution.', '26234');
INSERT INTO safety_incidents VALUES ('df7a7fe162730e8ad649a65870c7a05beb7976c5', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Urban Arrow FamilyNext Pro Cargo E-Bikes', 'Injury', 'Other', 'Not Specified', 'The firm has received three reports of buckles not fully latching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the e-bikes and contact Gazelle USA to arrange for a free repair of the bench assembly in the cargo area of the e-bike. The repair will include a replacement buckle and will be done at a dealership location.', '26236');
INSERT INTO safety_incidents VALUES ('8afec618b17c2a07727c9e834323c0008398b303', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Giraffe Plush Toy with clip, Llama Plush Toy with clip', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received one report of the leg detaching from the body of the plush toy, allowing the small beads to detach from the leg. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Giraffe Plush Toy with clip and the Llama Plush Toy with clip and return to the nearest Hobby Lobby Store for a full refund.', '26226');
INSERT INTO safety_incidents VALUES ('2a9ff85a0d7fecddc585de704e81bd4c4bfba142', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Sunneday and Blue Bay brand 48-inch and taller above-ground pools', 'Drowning', 'Drowning Risk', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should contact Starmatrix to request a free repair kit. In the interim, consumers should ensure that children cannot access the pool unattended or, alternatively, drain the pool until the repair can be installed.', '26227');
INSERT INTO safety_incidents VALUES ('027eb77a8e1a9ba78076e7f7b30c59e974cef943', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'LuxJet Submersible LED Lights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled LED Lights and contact LuxJet for instructions on how to destroy the product and obtain a full refund. Consumers should send a photo of the destroyed product to LuxJet via email at info@luxjet.com.cn. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26222');
INSERT INTO safety_incidents VALUES ('0ed520819443b4fbc3d45fb1bc3da11a54a84f24', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Ultimate Multivitamin+ Dietary Supplement Bottles', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled bottles out of sight and reach of children and contact Mindbodygreen for a free, child-resistant replacement cap. Once the supplements are secured, consumers can continue to use the supplements as directed.', '26221');
INSERT INTO safety_incidents VALUES ('545c4cb3c4dd38ac5b1d76fdef3b8029952611e5', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'NorthStar Hot Water Pressure Washers', 'Fire', 'Explosion', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled pressure washers and contact Northern Tool + Equipment to request a free repair by an authorized technician at a Northern Tool + Equipment service center or a Northern Tool + Equipment authorized third-party servicer. Consumers should visit https://www.northerntool.com/recall-details-pw to schedule the repair.', '26224');
INSERT INTO safety_incidents VALUES ('0e3d679cbf512084a0201c28de9ee67bdbe9d1e4', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Primark The Nightmare Before Christmas Glow-in-the-Dark Coloring Set', 'The Crayons In The Coloring Set Have High Levels Of Strontium And Aluminum, And This May Present A Risk If Ingested, Posing A Poisoning Hazard If Ingested By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Coloring Set and return it to a Primark store for a full refund in the form of the original payment.', '26230');
INSERT INTO safety_incidents VALUES ('06623c88e93b12c919224bbc1041f8fe45ce34d9', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Rear wheel bolts installed on model year 2026 Trek FX+ 1 and Electra Townie Go! electric bicycles', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received seven reports of the rear wheel bolts breaking on affected bicycles. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the bicycles with recalled bolts and contact an authorized Trek or Electra dealer to schedule a free repair at the dealer''s location. The dealer will replace the original black rear wheel bolts with new silver rear wheel bolts. Consumers can locate their nearest dealer at https://www.trekbikes.com./us/en_US/store-finder/. Trek will provide consumers who participate in the recall with a $10 in-store credit toward any Trek, Electra or Bontrager merchandise. The credit is valid through December 31, 2026.', '26220');
INSERT INTO safety_incidents VALUES ('2dccd0fce9c9c9f83f1c3e4eedd741af8a79f5db', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Sefudun Hair Growth Serum Kits', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled serum bottles out of sight and reach of children and contact Nengmiaokeji for a free replacement bottle of serum. Consumers will be asked to pour the contents of the bottle into the trash, take a photo of the empty bottle in the trash and email it to sesuall@outlook.com.', '26218');
INSERT INTO safety_incidents VALUES ('f703af5d139df7fd4d6126ce3f8f7e4e0e318120', 'CPSC', '2026-01-29', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Viofairy Hair Growth Serum', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled serum bottles out of sight and reach of children and contact FDAF for instructions on how to destroy the recalled bottles and to receive a free replacement. Consumers will be asked to pour the contents of the bottle into the trash and email a photo of the bottle in the trash to sesuall@outlook.com.', '26231');
INSERT INTO safety_incidents VALUES ('50ec035060e64b1bfa99466a8c732edda2644ecd', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Cumbor Retractable Safety Gates', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled gates and contact Aborder Products for a full refund. Consumers must destroy the gate by cutting through the mesh and send a photo of the destroyed gate to recall@cumbor.cn.', '26209');
INSERT INTO safety_incidents VALUES ('b102a4013c48e53678c3db2b9f29ec42ed85202f', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Magellan Odyssey Rocker Chairs', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'Academy Sports + Outdoors has received one report of the chair''s legs breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and return them to any Academy Sports + Outdoors store for a full refund. Consumers can also contact Academy''s Customer Care to return the chair by mail at no cost.', '26202');
INSERT INTO safety_incidents VALUES ('e3487046dff6e2268d3aa246ed7c4206e0b71817', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Based Online Fidget Magnet Ball Toys', 'The Magnet Ball Toys Violate The Mandatory Standard For Toys Because They Are Loose High-Powered Magnets, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, They Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnet ball toys immediately, take them away from children and contact Based Online to receive a full refund. Consumers should throw the magnet ball toys away and email photo of the disposal to Based Online at recall@mail.goclimber.cn.', '26207');
INSERT INTO safety_incidents VALUES ('244120697124301606626bb70f664c3c1d92c5e8', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Gagaku Wooden Ice Cream Shop Toy Playsets', 'The Recalled Toys Violate The Mandatory Standard For Toys Because They Contain High-Powered Magnets Which Can Loosen And Detach, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Mechanical Failure', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled toys, take them away from children and contact Brandworl.USA for a full refund. Consumers should destroy the toy by writing "RECALLED" with permanent marker on each piece of the toy and send a photo of the destroyed toy to Brandworl@gmail.com. Consumers should then dispose of the recalled toy.', '26205');
INSERT INTO safety_incidents VALUES ('d26eafc1eefb70592497fc9a6634ef2f7c159c2e', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Iristar Minoxidil Spray Bottles', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled spray bottles out of sight and reach of children and contact Moralowen for a free replacement bottle with a child-resistant closure. Consumers are instructed to transfer the contents of the recalled bottle into the new child-resistant bottle. Once the product is transferred, consumers can continue to use the product as directed.', '26210');
INSERT INTO safety_incidents VALUES ('b6fa8e3aac54138cab46373610a394b240396963', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Matrix Retail T30, TF30, T50, TF50, and T75 treadmills, Vision T9800, TF20, T40, and T80 treadmills', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 27 reports of overheating at the power cord-socket connection. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should inspect their treadmills to confirm whether they have a power cord bracket installed on the unit. If there is no power cord bracket, consumers should ensure that the power cord is completely inserted into the treadmill''s power socket before each use, until the treadmill is repaired. Consumers should contact Johnson Health Tech North America to receive a free replacement power cord with an automatic locking-style plug by mail for self-installation. To facilitate consumer participation in this recall, the installation of the replacement power cord does not require any tools.', '26203');
INSERT INTO safety_incidents VALUES ('0e23606f76d462222c416193e9b84f9a0428ff36', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Mikario Trading 5-in-1 Convertible Baby Gyms', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the baby gyms and contact Mikario Trading for a full refund. Consumers should remove the toy bar, cut the cushion in half and send a photo of the destroyed gyms to mikariorecall@gmail.com.', '26215');
INSERT INTO safety_incidents VALUES ('c3135ec5c0ca78ea83dd7ffd57b92c049b389bd0', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Angry Orange Enzyme Stain Removers', 'Environmental', 'Microbiological Contamination', 'Respiratory', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Angry Orange Enzyme Stain Remover products and contact Thrasio for a full refund. To receive a refund, consumers should take a picture of the product with "recalled" and their initials written on it in marker and email the photo to productrecall@angryorange.com. Consumers should then dispose of the product in its container with household trash. Do not empty the product prior to disposal. Do not attempt to recycle the product bottle.', '26201');
INSERT INTO safety_incidents VALUES ('dcc1ac23eeacf4d4cfc82211bf1dc5b5d875f2e7', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Topkay Torch Lighters', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled lighters and contact Xiyude for a full refund. Consumers should destroy the lighters by pulling out the black adjuster knob on the top of the product, then contact BCLighterService@outlook.com and submit a photo of proof of destruction to receive a full refund. Consumers should dispose of the recalled lighters in accordance with state and local waste disposal procedures.', '26206');
INSERT INTO safety_incidents VALUES ('b6144b816f3f8970fa4845d019c66f96b5b5b9fa', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Vndueey Magnetic Men Toy Sets', 'The Recalled Magnetic Stick Figure Toy Sets Violate The Mandatory Standard For Toys Because The Sets Contain Loose Magnets, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, They Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled magnetic toy sets, keep them away from children and contact Vndueey for a full refund. Consumers will be asked to cut all the magnetic stick figures in half and send a photo of the destroyed toy set to vndueeyrecall@outlook.com. Consumers should then dispose of the destroyed toy set.', '26208');
INSERT INTO safety_incidents VALUES ('354a712a52d8d5c6d847142ca4fab2207efc27d6', 'CPSC', '2026-01-22', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Yetonamr Pull String Teething Toys', 'Choking', 'Small Parts / Choking Hazard', 'Respiratory', 'CPSC is aware of 32 choking incidents.', 'Fatal', 1, 0, 'Consumers should stop using the teething toy immediately, take it away from children and contact Longyanguiheng to receive a full refund. Consumers should cut and discard all silicone string tentacles, write "DESTROYED" on the main body of the toy using a permanent marker, and email a photograph of the destroyed product to yetonamr_recall@163.com.', '26204');
INSERT INTO safety_incidents VALUES ('d5a1fdccdc10b0110faf5db6eb476fa0df6baed2', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Adams RealComfort and StyleWell Adirondack Patio Chairs', 'Injury', 'Mechanical Failure', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled chairs and return them to any Lowe''s or Home Depot store for a full refund.', '26192');
INSERT INTO safety_incidents VALUES ('19dfebc1098bfb2d9dbc009d9f32a97c6ce2e34a', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'BBWOO Baby Loungers', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby loungers and contact LSY Direct for a full refund. Consumers should remove the foam and pads from the baby lounger’s cover and cut the cover, foam, and pad in half. Consumers should email photos of the destroyed pieces to bbwoorecall@163.com to obtain a full refund.', '26185');
INSERT INTO safety_incidents VALUES ('1a3a4f49bffe837ff5cfa49153faa094b9710e46', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Frigidaire-brand Minifridges, model EFMIS121, with limited serial numbers', 'Fire', 'Electrical Fault', 'Burns', 'Curtis International has received at least six reports of the model EFMIS121 minifridges catching fire, with property damages.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled minifridges and follow the instructions to register for a refund at www.recallrtr.com/minifridge. Consumers should unplug and cut the power cord and write "Recall" using a permanent marker on the front door of the unit. Consumers should dispose of the recalled minifridges in accordance with local and state regulations.', '26199');
INSERT INTO safety_incidents VALUES ('04a2930094434dd1071e205c6eac4a634e697377', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Energizer® Large Power Indicator Lanterns', 'Burns', 'Flammability / Overheating', 'Burns', 'The firm reported one incident of the lithium-ion battery in a lantern overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled lanterns and contact Energizer for instructions on how to receive a full refund. Consumers will be asked to register for the recall by providing proof of the affected date code. Consumers will then be sent prepaid shipping materials to return their recalled lantern. Once the lantern is returned, consumers will be issued a refund. Note: Do not throw this recalled lithium-ion battery or device in the trash, the general recycling stream (e.g., street-level or curbside recycling bins), or used battery recycling boxes found at various retail and home improvement stores. Recalled lithium-ion batteries must be disposed of differently than other batteries, because they present a greater risk of fire. Your municipal household hazardous waste (HHW) collection center may accept this recalled lithium-ion battery or device for disposal. Before taking your battery or device to a HHW collection center, contact that office ahead of time and ask whether it accepts recalled lithium-ion batteries. If it does not, contact your municipality for further guidance."', '26183');
INSERT INTO safety_incidents VALUES ('1d04aa88690cef931e3222ad8e181489da65ffef', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Self-Feeding Pillows', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled self-feeding pillows and contact Greatale for a full refund. Consumers will be instructed to cut the self-feeding pillow with scissors and submit a photo of the destroyed recalled product, including the product''s tag, to greatale-recall@outlook.com. If the product''s tag was previously removed, consumers can demonstrate eligibility by providing their Amazon proof of purchase in the email.', '26195');
INSERT INTO safety_incidents VALUES ('46160486f0d584bcaa9a1869ec09c7ffee3ed89d', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'HEZI Branded Power Strips', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled power strips immediately and contact HEZI HOME for a full refund.', '26194');
INSERT INTO safety_incidents VALUES ('0bb6f346979b1508dce8018d1243da5d4f11367c', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Asher Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled children''s pajamas and contact Morgan Lane for a full refund. Consumers should cut the pajamas in half, take a photo of the destroyed garments, dispose of them and email the photo of the destroyed garments toinfo@morgan-lane.com to receive the refund.', '26193');
INSERT INTO safety_incidents VALUES ('db048ac86c933eb89a75e8eeee7756dea226ffd5', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'R.X.Y Bicycle Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact R.X.Y for a full refund. Consumers should destroy the helmet by cutting the straps and uploading photos of the helmet with the straps cut off to RXY-recall@outlook.com.', '26188');
INSERT INTO safety_incidents VALUES ('851f8fadd3855588c5bd12dc8b3f012a655d0250', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'RootStim Beard Growth Serum, 5% Minoxidil', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled serum bottles out of sight and reach of children, and contact RootStim for instructions on receiving a replacement product. Consumers will be asked to discard the original bottle.', '26198');
INSERT INTO safety_incidents VALUES ('81968046b75d56862b0893abc62ca11c6c5b9727', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Ruahouine Hair Growth Serum Bottles', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled serum bottles and place them out of sight and reach of children. Contact Ruahouine for instructions on how to destroy the recalled bottles and how to receive a refund or replacement bottle. Consumers will be asked to pour the contents of the bottle into the trash and take a photo of the bottle in the trash and email it to ruahouine@gmail.com.', '26182');
INSERT INTO safety_incidents VALUES ('aa865e0681c2ee9e5a0b65c3489ab5d484993f6d', 'CPSC', '2026-01-15', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'KEAWIS Crib Mattress', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the crib mattresses immediately and contact Yixing Trading for a full refund. Consumers should cut a large "X" across the main surface of the mattress, write the consumer''s name and date directly on the mattress surface, take a photo and email the photo of the destroyed mattress to Yixing Trading at support@keawis.com to receive a full refund.', '26191');
INSERT INTO safety_incidents VALUES ('0ecf6cbbabcfb610294957764625192a7a88933c', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Agrish Adult Portable Bed Rails', 'The Recalled Bed Rails Violate The Mandatory Standard For Adult Portable Bed Rails Because When The Bed Rails Are Attached To A Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Bed Rail And The Side Of The Mattress, Posing A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'The firm has received one report of a consumer fall involving an Agrish adult bed rail with model number 251.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled adult portable bed rails and contact Agrish Direct for a full refund. Consumers should go to http://www.agrish.online/recall to register for the recall and receive instructions on how to dispose of the recalled bed rail.', '26165');
INSERT INTO safety_incidents VALUES ('32d74757ff83f540544523719cc93bc771620592', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Walk-Behind Leaf Vacuums and Tow-Behind Leaf Vacuums', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 46 reports of loose pieces being ejected from the units. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled leaf vacuums and contact DR Power for a free repair kit that includes a metal outer shield to be bolted onto the existing chute of the recalled leaf vacuums and installation instructions.  Consumers can contact DR Power for information and assistance on making the repair. Consumers who responded to the original recall should nevertheless contact DR Power for the new remedy.', '26166');
INSERT INTO safety_incidents VALUES ('56668434dce84fbab1d5cf4931b63fef15197acd', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'BabyBond Retractable Safety Gates', 'Injury', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled gates and contact Infant Innovations at elsie@BabyBond-global.com for instructions to return the gates to any Target store for a full refund.', '26168');
INSERT INTO safety_incidents VALUES ('fedf98db292f8f0cc81291b22d06aebaefdd976d', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Isla Rae Magnetic Wireless Chargers', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled magnetic wireless chargers and go to https://www.recallrtr.com/powerbank to register for the recall and for instructions on how to receive a full refund. After registering, consumers should dispose of the power bank in accordance with local and state regulations and not discard it in the household trash.', '26179');
INSERT INTO safety_incidents VALUES ('099ff4591079587d5c7befe27b8012489a3c249c', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Joyful Journeys Baby Loungers', 'Injury', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby loungers and contact Joyful Journeys for a full refund. Consumers should remove the foam and pads from the baby lounger''s cover and cut the cover, foam, and pad in half. Consumers should email photos of the destroyed pieces to joyfuljourneysrecalls@myjoyfuljourneys.com to obtain a full refund.', '26181');
INSERT INTO safety_incidents VALUES ('95d96d35528bfc1ee7a2ee67c89d632e39e51eda', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Kori Gey Water Elf Toy Kits', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled toy''s light up luminous gasket (a LED light containing a button cell battery), take it away from children, and remove and properly dispose of the battery. Contact Qaniy for a full refund. Consumers should throw the toy''s gasket away and send a photo of the product in the trash to changshaaoyuan@outlook.com. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26178');
INSERT INTO safety_incidents VALUES ('e17d49e247764b859beb94f07afc93dd499bb410', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Julie and Judah pajama pants and shorts', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the pajama pants and shorts and contact Marcus Adler Glove for a full refund. Consumers will be asked to destroy the pajama pants and shorts by cutting them as directed and permanently marking them with the word "Recall" and a unique identifier. Consumers will be asked to email a photo of the destroyed garment to info@julieandjudahaccessories.com. Upon receipt of the refund, consumers should dispose of the recalled product in the trash.', '26170');
INSERT INTO safety_incidents VALUES ('87a14f0ee8fb6b023d323b48300acc9f7a26960e', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'NFSVLB Baby Bath Seats (blue)', 'Injury', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bath seats and contact NFSVLB to request a full refund. Consumers should write "Recalled" on the front of the bath seat in permanent marker, disassemble the bath seat by removing the back rest and arm restraints, discard the screws, cut the four suction cups on the bottom and send a photo of the disassembled recalled bath seat to NFSVLB at?amzmaihuayd@163.com. Upon receipt of the photo, NFSVLB will provide the consumer with a full refund.', '26171');
INSERT INTO safety_incidents VALUES ('24fe75588d52fdddcdb40fd9f23647e2dac670f1', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Loam Pedal Gen 2 aluminum alloy bicycle pedals', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received four reports of the pedal axle cracking and detaching from the crank. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Loam Pedal Gen 2 and contact PNW Components to receive free replacement axles once they become available. In the interim PNW Components is providing consumers with the Range Pedal, free of charge. PNW Components will follow up with consumers regarding the replacement axle system, estimated to begin shipping out to customers on January 5, 2026.', '26180');
INSERT INTO safety_incidents VALUES ('233a921624da69ab0c7ebb534f1b05e8b3ccca47', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Lterfear Multifunction Pounding Game', 'The Recalled Pounding Toys Violate The Mandatory Standard For Toys Because They Contain High-Powered Magnets, Which Can Detach, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Blood Poisoning, And Death.', 'Mechanical Failure', 'Poisoning / Ingestion', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled pounding toys and contact Findriver to receive a full refund. Consumers should write "RECALLED" on the base of the product with permanent marker, throw the product away, and send a photo of the disposed product to Findriverpoundingtoysrecall@outlook.com.', '26176');
INSERT INTO safety_incidents VALUES ('4ec4236022de741e3cbfa5777de0ff1613d730a1', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Rattan 6-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In A Risk Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers, if they are not anchored to the wall, and place them in an area that children cannot access. Consumers should write "RECALLED" on the front, side, and back with permanent marker, take photos and email them to FUQARHYrecall@outlook.com. Consumers should then dispose of the recalled product in accordance with state and local waste disposal procedures.', '26172');
INSERT INTO safety_incidents VALUES ('65cae06cec527bb2a20e66ad6632d6da2d50e3c0', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', '48" and 60" Natural Antler Chandeliers', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received four reports of canopy hardware components breaking and chandeliers detaching, including one report in which the chandelier fell to the floor. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should keep clear of the area directly beneath the chandelier hung on a vaulted ceiling or sloped beam and contact RH to schedule a free in-home repair. A technician will replace the canopy hardware of 48" and 60" chandeliers installed on a vaulted ceiling or sloped beam.', '26177');
INSERT INTO safety_incidents VALUES ('b837fca38c589ba0073ef53d494fac42c83cd775', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Sangohe Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact Sangohe for a full refund. Consumers should destroy the bed rails by cutting the handrails'' foam padding and writing "RECALLED" on the upper and lower rails with permanent marker, take a photo of the destroyed rails and email the photo to SGHproductrecall@163.com.', '26173');
INSERT INTO safety_incidents VALUES ('9efeacfa0854069abdfa0466c9ceeda216669839', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'SARO Braided Crib Bumpers', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported.', 'Fatal', 1, 0, 'Consumers should stop using the crib bumpers immediately and request a full refund in one of the following ways: For SARO Braided Crib Bumpers purchased in store at MacroBaby in Orlando, Florida, consumers should return the item to the store for a refund. For SARO Braided Crib Bumpers purchased online, consumers should email info@kalencom.com with the subject line "Crib Bumper Recall - Refund Request" and include name and phone number, along with a photo showing the crib bumper cut in half as proof of destruction.', '26169');
INSERT INTO safety_incidents VALUES ('f47f79a8474b05c84d50638fed0a56a72205b25b', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'Vasicar 18-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Risks Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers, if they are not anchored to the wall, and place them in an area that children cannot access. Contact Vasicar for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to vasicarus2025@outlook.com showing disposal of the product.', '26174');
INSERT INTO safety_incidents VALUES ('c86590371e2442e155cb8fb6355d5685ec280f93', 'CPSC', '2026-01-08', 2026, '2026-01', 'USA', 'United States', '', 'Other', 'YOLAAH Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the YOLAAH Bed Rail and contact YOLAAH for a refund. Consumers should use scissors to cut the black fabric mesh bag off the upper rail and cut the black safety strap in half. Then, using a permanent marker, write "RECALLED" on both the upper and lower rails. Finally, take a photo of the marked bed rails and email the photo to yolaahproductrecall@outlook.com. Consumers should then dispose of the recalled product in accordance with state and local waste disposal procedures.', '26175');
INSERT INTO safety_incidents VALUES ('401625347d4eac61823dac9dacb70c944c0fc460', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', '17 Stories Furniture 18-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazard That Can Result In Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately if they are not anchored to the wall and place them in an area that children cannot access. Contact 17 Stories Furniture for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to Drawer18Recall@outlook.com demonstrating disposal of the product.', '26156');
INSERT INTO safety_incidents VALUES ('4931222bc861bcd2584d56e4f06a263456b8ec5f', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'AMP MP2 Smart Fitness Machine', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 10 reports of the arm on the fitness machine not locking properly, resulting in lacerations to the head and bruising to the shoulder and other body.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled fitness machine and contact Amp Fit to schedule a free inspection and repair that will be conducted at the consumers'' residence by an authorized technician. The repair involves the replacement of a part within the shoulder cap of the locking mechanism that helps to ensure the locking mechanism is fully engaged.', '26150');
INSERT INTO safety_incidents VALUES ('7559e4984714a54b07294f8092fffb3a4f52af24', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'ANNQUAN Power Strips, Models EX-D112-05 and EX-D106-25', 'Fire', 'Electrical Fault', 'Respiratory', 'Hefei Juyuan Sporting Development has received seven reports of the power strips blowing a fuse. No fires or injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the ANNQUAN power strips and contact Hefei Juyuan Sporting Development to receive a full refund.', '26161');
INSERT INTO safety_incidents VALUES ('85b661ae772b6966d361b8ba8cf2132f44ba4359', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Blue Wave brand 48-inch and taller above-ground pools', 'Drowning', 'Drowning Risk', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should contact Blue Wave to request a free repair kit. In the interim, consumers should ensure that children cannot access the pool unattended or, alternatively, drain the pool until the repair can be installed.', '26163');
INSERT INTO safety_incidents VALUES ('c69f025ae345a40daf0d0ac5b5fcde731f0ddee9', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Electra Chandelier and Electra Three Tier Chandelier light fixtures', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received two reports of the chandelier light fixtures falling from the ceiling, with one incident involving property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately contact Currey & Company to receive a free in-home repair kit to replace the connection component. Currey will pay the consumer''s professional installation costs directly or reimburse consumers for the full cost of the professional installation of the repair.', '26155');
INSERT INTO safety_incidents VALUES ('a9fc697d29f9f86ab0413535ec25059bbbc4c900', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Feel The Beard Minoxidil Beard Growth Oil for Men', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled serum bottles out of sight and reach of children, and contact Feel The Beard for instructions on destroying the recalled bottles and receiving a replacement. Consumers will be asked to pour the contents of the bottle into the trash and take a photo of the bottle in the trash and email it to ziyad@feelthebeard.com.', '26158');
INSERT INTO safety_incidents VALUES ('b2e52a5cc72a79dedb115847c86e08f7b3a76780', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Furnulem 8-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers, if they are not anchored to the wall, and place them in an area that children cannot access. Contact Furnulem for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to support@furnulem.com demonstrating disposal of the product.', '26153');
INSERT INTO safety_incidents VALUES ('b9ed0c12e6bb78429e230eb0e86bc29b27a99845', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'JOKOSIS Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the JOKOSIS Bed Rails and contact JOKOSIS for a refund. Consumers should write "RECALLED" on the upper and lower rails with permanent marker, take a photo of the marked bed rails and email the photo to jokosisbedrailrecall@outlook.com. Consumers should then dispose of the recalled product in accordance with state and local waste disposal procedure.', '26160');
INSERT INTO safety_incidents VALUES ('2fc687ef18ac25a1b0d21b7dc152bc3beca8ba5e', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'KKL Fabric 9-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing A Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately if they are not anchored to the wall and place them in an area that children cannot access. Contact HK Brilliant for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to support-us@kkl-home.com demonstrating disposal of the product.', '26159');
INSERT INTO safety_incidents VALUES ('d34afb0965f2a04293e4cc096075fa16b1f2c66a', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Meaicezli Play Purse Sets', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the toy purse set immediately, take the toy cell phone and writing tablet away from children and contact Angeer-US for a full refund. Consumers will need to email a photograph confirming disposal of the toy cell phone and the writing tablet and send a photo to meaicezli-services@outlook.com. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26164');
INSERT INTO safety_incidents VALUES ('940199aa7407c52981f1d9f82b4f48a5a5a4df83', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Schwinn Ovation Bicycle Child Carriers', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Pacific Cycle is aware of one incident where the buckles released. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled carriers and contact Pacific Cycle for a full refund.', '26151');
INSERT INTO safety_incidents VALUES ('0d0839937181478140ee265c40dd8b97b0dde704', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Fat Tire Trikes', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Pedego has received 16 reports of the trike frame breaking, including one report of a laceration to the leg.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Fat Tire Trikes and contact Pedego to schedule a repair involving the replacement of a section of the frame, which will be installed by a Pedego dealer of their choice at no charge to the consumer. Consumers should fill out a registration form at https://pedegoelectricbikes.com/pages/product-recalls.', '26152');
INSERT INTO safety_incidents VALUES ('c906e3b3f6d0465ce3f74aa3cd6189697ab289aa', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Mamisan Pain Relieving Topical Ointment', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled ointment jars out of the sight and reach of children and contact Plantimex to receive a free replacement lid. Once the product is secured with the replacement lid, consumers can use the product, as directed.', '26157');
INSERT INTO safety_incidents VALUES ('06e9104eaea31aadd36f7fc9f6c19286716744ea', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'SereneLife brand 48-inch and taller above-ground pools', 'Other', 'Other', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should stop using the recalled above-ground pools immediately and contact SereneLife Home for a full refund. Consumers will need to provide photographic evidence of destruction or disposal of the product to receive a full refund from SereneLife Home.', '26162');
INSERT INTO safety_incidents VALUES ('5bed1231cbaa825f58d59db6c9991d95f7df09b2', 'CPSC', '2025-12-18', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'TopHomer Pool Drain Covers', 'Drowning', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners, pool operators and consumers should immediately stop using pools with the recalled pool drain covers. To receive a refund, consumers should remove the drain cover from the pool, take a photo of the removed cover, and send it to the recalling firm by email at Tophomer.recall@outlook.com. Ensure all pools and spas have VGBA-compliant drain covers and teach children to stay away from drains.', '26154');
INSERT INTO safety_incidents VALUES ('2c5e9f69a943126023528390e7b3f8e73f5f8aa4', 'CPSC', '2025-12-11', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'X-Pro Eagle 40cc Youth ATVs and FRP Sahara 40cc Youth ATVs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the X-Pro Eagle 40cc Youth ATVs and FRP Sahara 40cc Youth ATVs and contact Luyuan for a free repair from an authorized repair shop.', '26148');
INSERT INTO safety_incidents VALUES ('20b689e3f866953d9f24a37d9f1bf981a50614da', 'CPSC', '2025-12-11', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Little Bear 2-pack Soother Clip', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received five reports of the wooden buttons on the soother clip detaching, including one report where the screw was found inside an infant''s mouth and a second report of cuts to a child''s arm.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled soother clips and return them to a Primark store for a full refund in the original form of payment.', '26139');
INSERT INTO safety_incidents VALUES ('c49e8fa88125bf915d3c53c9428c7caae6200515', 'CPSC', '2025-12-11', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Vevor Ice Crushers', 'Fire', 'Flammability / Overheating', 'Entrapment', 'Sanven has received two reports of thermal events, including one fire.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ice crusher and contact Sanven for a full refund. Consumers should email a photograph of the ice crusher with the unplugged power cord cut in half to recalling@vevor.com.', '26147');
INSERT INTO safety_incidents VALUES ('899556369b98cd3c32c4452e83ff17ab3e0669c8', 'CPSC', '2025-12-11', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'VEVOR Garment Steamers', 'Burns', 'Mechanical Failure', 'Burns', 'The Firm has received six reports of hot water spitting, pouring out, leaking or dripping from the steamers, and 12 reports of issues with the water tank cap detaching, leaking, not staying closed, fitting loosely, or melting. The reported cap issues resulted in two burn injuries, including one consumer who received a permanent scar and a second-degree burn from the hot water, after the steamer''s cap suddenly detached and one consumer who received a minor burn on their hand and fingers from leak', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled steamers and contact Sanven Technology for a full refund. Consumers will be asked to provide their contact information and send a photo of the steamer with its unplugged cut power cord to receive a full refund.', '26142');
INSERT INTO safety_incidents VALUES ('645f2af3940a01eab641ff16f174a0ed4ea14054', 'CPSC', '2025-12-11', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'SKCAIHT Children''s Little Mermaid Costumes', 'The Children''S Costumes Contain A Prohibited Phthalate, Which Violates The Federal Phthalates Ban. Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled costumes and take them away from children. Contact SKCAIHT Direct for a full refund. Consumers should cut the dress and submit a photo of the destroyed costume to pafiney@outlook.com.', '26140');
INSERT INTO safety_incidents VALUES ('b3536e4cf92ae5f2195896c8e835487d9484c1df', 'CPSC', '2025-12-11', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Model Year 2026 Trek-branded Domane+ ALR 5, Domane+ ALR 6 AXS, Checkpoint+ SL 6 and Checkpoint+ SL 7 Electric Bicycles', 'Falls', 'Instability / Fall Risk', 'Skin Irritation', 'The firm has received three reports of the bicycle chainring coming loose on the recalled bikes. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact an authorized Trek dealer to schedule a free repair at the dealer location. The dealer will tighten the chainring bolts to the correct specification. Trek will provide consumers who participate in the recall with a $20 in-store credit toward Trek, Electra, or Bontrager merchandise. The credit is valid through December 31, 2026.', '26138');
INSERT INTO safety_incidents VALUES ('94d7637f5c414dfbf897ddac048d27fc79833440', 'CPSC', '2025-12-11', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Uuoeebb Infant Walkers', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled infant walkers immediately and contact BaoD for a full refund. Consumers should disassemble the walker, remove the fabric seat, write "Recalled" on the top of the tray in permanent marker, and email a photo of the recalled infant walker to BaoD at Uuoeebbrecalls@outlook.com. Consumers should dispose of the recalled infant walkers in accordance with state and local waste disposal procedures.', '26141');
INSERT INTO safety_incidents VALUES ('4d58b6b92fdefd92cd3073be463d2e9652fbcebf', 'CPSC', '2025-12-11', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'YCXXKJ Baby Bath Seats', 'Injury', 'Instability / Fall Risk', 'Drowning', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bath seats and contact BenTalk to request a full refund. Consumers should send two photos of the recalled bath seats to BenTalk at bentalkhere@outlook.com. The first photo should have "Recalled" written on the front of the bath seat in permanent marker. The second photo should show the bath seat disassembled with the components removed.', '26146');
INSERT INTO safety_incidents VALUES ('41bddad3065bce18012010ac32fc32dc7f05d971', 'CPSC', '2025-12-05', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'INIU BI-B41 Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'INIU has received 15 reports of power banks overheating, including 11 reports of fires that resulted in three minor burn injuries and property damage totaling over $380,000.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled planers and contact Grizzly Industrial for a free repair kit and installation instructions. The repair kit consists of an upgraded chip breaker adjustment rod, spacer, set screws, lock washers, and lock nuts.', '26135');
INSERT INTO safety_incidents VALUES ('aeb6814724dcb17da156d43f6696bd9f13b64c4e', 'CPSC', '2025-12-04', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Casaottima 13-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In A Risk Of Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to the wall and place them in an area that children cannot access. Contact Casaottima for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to support@casaottima.store showing disposal of the product.', '26127');
INSERT INTO safety_incidents VALUES ('5064ec654be8994b78a72f1c22dc16aa36e70699', 'CPSC', '2025-12-04', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'CreateOn Crayola-branded pip-Cubes', 'The Recalled Magnetic Building Cubes Contain Magnets That Can Become Loose If The Seams Separate, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled magnetic building cubes, take them away from children and contact CreateOn to receive a replacement set of pip-cubes. Consumers will receive a pre-paid label to return the recalled magnetic cubes in order to receive the replacement.', '26128');
INSERT INTO safety_incidents VALUES ('420825ba56b47825a41ec6e14ab5f87f27508942', 'CPSC', '2025-12-04', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Cubimana Treehouse Building Toy Sets', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled toy sets, take them away from children, and remove and properly dispose of the batteries. Contact Vatos Toys for a full refund. Consumers should throw the piece with the LED light away and send a photo of the product in the trash to shein.us@vatostoys.com. Note:?Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26133');
INSERT INTO safety_incidents VALUES ('9f6203462ed116f5af04de881a473f3d8d8031d2', 'CPSC', '2025-12-04', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'G0815 15" 3HP Heavy-Duty Planers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Grizzly Industrial has received seven reports of the rotating cutters of the planers breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled planers and contact Grizzly Industrial for a free repair kit and installation instructions. The repair kit consists of an upgraded chip breaker adjustment rod, spacer, set screws, lock washers, and lock nuts.', '26134');
INSERT INTO safety_incidents VALUES ('41a0f4b0e38577c22375a681c27c81b5d8274dd8', 'CPSC', '2025-12-04', 2025, '2025-12', 'USA', 'United States', '', 'Other', '14-ounce Children''s Sport Tumbler', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received 656 reports of the rivets on the handle coming loose. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled 14-ounce sport tumbler and contact HydroJug for a free replacement lid. Consumers should email HydroJug at service@thehydrojug.com and provide order details (if available), shipping address and photos of the bottom of the tumbler showing the serial number or that there is no serial number. Consumers will be asked to include photos of the recalled tumbler lid permanently marked with the word "Recalled" and to dispose of the recalled tumbler lid. HydroJug will confirm eligibility and send a replacement lid.', '26129');
INSERT INTO safety_incidents VALUES ('1eafcc0c1b25052279c94268000c57c3282325b2', 'CPSC', '2025-12-04', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'KTEBO Writing Tablet Toy', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled writing tablet toys and contact KTEBO for a free replacement set of tablet toys. Consumers should write "RECALLED" on the back of both tablet toys that came in the set, take a photo of the marked tablet toys, and submit the photos to writing-tablet-recall@ktebo.com with "Recall Proof" and their name in the subject line. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26131');
INSERT INTO safety_incidents VALUES ('185c3e60167710810f7c3c9bab0ca12abd999199', 'CPSC', '2025-12-04', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Little Pea Shop Crib Bumpers', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled crib bumpers and contact Little Pea Shop for a full refund. Consumers should remove the crib bumpers, cut the padding and email a photo of the destroyed bumpers to support@littlepeashop.com.', '26132');
INSERT INTO safety_incidents VALUES ('3dee7fdcfef62c33d3f601eb3f4db5611cdd7848', 'CPSC', '2025-12-04', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'FUFU&GAGA White Wood Frame Queen Size Murphy Wall Beds', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received two reports of the wall beds falling during assembly when the wall beds were not anchored to the wall, resulting in two injured consumers. One consumer sustained a laceration, a bruise, and a fractured growth plate in her finger, and another consumer sustained a laceration to his face that required eight stitches.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled wall beds and contact Ningbo Tianqi Electronic for a full refund. To obtain a refund, consumers will be provided with a disassembly kit that contains tools, brackets and screws with instructions on how to disassemble and discard the wall beds.', '26126');
INSERT INTO safety_incidents VALUES ('9af1c3e7c4384d90340911a4a4232a05490d57c3', 'CPSC', '2025-12-04', 2025, '2025-12', 'USA', 'United States', '', 'Other', 'Primark Water Balloon Pump', 'Injury', 'Explosion', 'Laceration / Cut', 'The firm has received two reports in the United States (and nine reports internationally) of the water balloon pumps rupturing, resulting in two reports of cuts on users'' hands and fingers in the United States (and nine reports of cuts internationally).', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled water balloon pumps and return them to a Primark store for a full refund in the form of the original payment.', '26124');
INSERT INTO safety_incidents VALUES ('288cd4f330f33ab6028946366230b1d203b737f3', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Alinux Baby Loungers', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby loungers and contact Winkids for a full refund. Consumers should remove the foam and pads from the baby lounger''s cover and cut the cover, foam and pad in half. Consumers should email photos of the destroyed pieces to alinuxrecall@163.com to obtain a full refund.', '26112');
INSERT INTO safety_incidents VALUES ('7ebd6a78592cfb166004a052db9f0a6a179e02b6', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Baby High Chairs (convertible)', 'Falls', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled high chairs and contact Rotinyard for a full refund. Consumers should disassemble the high chairs, cut the restraints and fabric seat cushion insert, and email photos of the destroyed restraints and cushion to trailblazeramz@outlook.com. Once the photos are received, Rotinyard will issue a full refund.', '26121');
INSERT INTO safety_incidents VALUES ('bc14a77fb00561855623e31a330ce5bd56d3ad97', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Ebern Designs Ojaswi 12-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to the wall and place them in an area that children cannot access. Contact Ebern Designs for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to Ojaswi12Drecall@outlook.com demonstrating disposal of the product.', '26107');
INSERT INTO safety_incidents VALUES ('a59befcd86571c86774d41ba9ad00200dcd79478', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Ikuso Safety Gates', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled safety gates and contact Ikuso to request a full refund. Consumers should send a photo of the recalled safety gates, with "Recalled" written on the front in permanent marker, to Ikuso at ikuso_door_gate@163.com. Consumers should dispose of the recalled safety gates in accordance with state and local waste disposal procedures.', '26114');
INSERT INTO safety_incidents VALUES ('f97adc27bde8edb4253f1377b4eaf54b32781061', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'KingPavonini Adult Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled adult portable bed rails immediately and contact KingPavonini to obtain a refund or free replacement bed rails. Consumers should follow these disposal steps: 1. Remove the bed rail from the bed. Range of Recalled Serial Numbers 2. Disassemble the upper and lower rails, connecting rails, and support legs (if present). CSFxxABTRxx-V1-4933 through CSFxxABTRxx-V1-6970 3. Use a permanent marker to write "RECALLED" on upper and lower rails. 4. Use scissors to cut the black storage bag and straps. 5. Write the buyer''s name on a piece of paper next to the disassembled product. 6. Take a photo of the disassembled parts with the note and upload it online at https://www.kingpavonini.com.cn. CSFxxABISxxTL-V1-4964 through CSFxxABISxxTL-V1-7224 7. Dispose of the recalled product in accordance with state and local waste disposal procedures. Consumers who have difficulty with any disposal step or need additional instruction should contact KingPavonini.', '26109');
INSERT INTO safety_incidents VALUES ('ef25d722cc78371fffac12a3a108692d1fad6f3f', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Macardac Baby Loungers', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby loungers and contact Macardac Products for a full refund. Consumers should remove the foam and pads from the baby lounger''s cover and cut the cover, foam and pad in half. Consumers should email photos of the destroyed pieces to macardacrecall@gmail.com to obtain a full refund.', '26113');
INSERT INTO safety_incidents VALUES ('cce29f770617ff17a89e19834995f751454f2c74', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'MyOnlyStyler Root Booster Hair Dryers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately unplug and stop using the recalled hair dryers and contact McLee Creations to receive a full refund. Consumers must submit a photo of the hair dryer with its power cord cut in half to the recall registration portal at https://www.myonlystyler.com/product-recall-registration/ and follow the disposal instructions provided on the website https://www.myonlystyler.com/product-recalls.', '26125');
INSERT INTO safety_incidents VALUES ('e8aa59fb8704a4a4c94096faf723f9c5ae1c82ac', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Outdoor Master Children''s and Youth Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Outdoor Master for instructions on how to register for a full refund.', '26122');
INSERT INTO safety_incidents VALUES ('36e0214f25f2eb0e55e4b45eaa3575140976ddd5', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Ozark Trail Tabletop 1-Burner Butane Camping Stoves', 'Fire', 'Flammability / Overheating', 'Burns', 'China Window Industry Co., Ltd. has received 26 reports of the camping stoves exploding or catching fire, including 16 reports of injuries such as second-degree burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled stoves and return the product to any Walmart retail store for a full refund.', '26120');
INSERT INTO safety_incidents VALUES ('22cedd37a0f879d2a250835b43be5772254a356b', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Sofoliana and Glotika Baby Loungers', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby loungers and contact Bosen US for a full refund. Consumers should remove the foam and pad from the baby lounger''s cover and cut the cover, foam and pad in half. Consumers should email photos of the destroyed pieces to BosenRecall@outlook.com to receive a full refund.', '26116');
INSERT INTO safety_incidents VALUES ('d701fa4edcac8c3d842d6233305df3df60111218', 'CPSC', '2025-11-26', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Vivohome Adult Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact Vivohome for a full refund. Consumers will be asked to write "RECALLED" on the rails with permanent marker and send of photo of the marked bed rails to support@3qmart.com. Consumers should then dispose of the recalled product in accordance with local requirements.', '26115');
INSERT INTO safety_incidents VALUES ('c53abed14225ae79d9acf2cc7ea190f001ce2363', 'CPSC', '2025-11-20', 2025, '2025-11', 'USA', 'United States', '', 'Other', '4-in-1 Baby Safety Cart Carriage', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled stroller and contact AliExpress to receive a full refund. Consumers will be required to cut the restraints and email a photo of the destroyed product to us_product_recall@aliexpress.com.', '26094');
INSERT INTO safety_incidents VALUES ('504afa016b81c1e9045d771938eda5dce7989502', 'CPSC', '2025-11-20', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Bearlala Baby Loungers', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby loungers and contact Nuoxuann for a full refund. Consumers should remove the foam and pads from the baby lounger''s cover and cut the cover, foam and pad in half. Consumers should email photos of the destroyed pieces to Recall-nuoxuann@outlook.com to obtain a full refund.', '26095');
INSERT INTO safety_incidents VALUES ('20f3aaac6b6c78f429fe45c7539793cde68a8d17', 'CPSC', '2025-11-20', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'MoonSoll and Magic Chems Fuel Bottles', 'Fire', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled fuel bottles, place them out of reach of children and contact Demlar for a full refund. Consumers will be asked to write "Do not use" and the Amazon order number with permanent marker on the container and submit a photo of it to info@demlar.com. Consumers should dispose of the fuel bottles in accordance with local and state regulations. Note: Consumers should follow local household hazardous waste (HHW) guidance for flammable liquids. Contact your city, county, or state HHW program for instructions, as requirements may differ by location. Safe approach: Keep the product in its container, clearly label it "Do Not Use," and bring it to a local HHW drop-off.', '26102');
INSERT INTO safety_incidents VALUES ('7c65bc2e9e3f1ce4a111c6337b19f66528dceafb', 'CPSC', '2025-11-20', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Grow ''N Stow Folding Learning Tower', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 14 reports of the folding towers collapsing, including one report of a child with bruises.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Grow ''N Stow Folding Learning Tower, keep it away from children and contact Little Partners, to receive a free repair kit, that includes a new crossbar with pin tabs and installation instructions. The new crossbar will have a sticker indicating that it is no longer part of the recall. Consumers should remove the old crossbar and dispose of it.', '26096');
INSERT INTO safety_incidents VALUES ('99d69294fcc2696cfb8231c18ee6386bf2ce475a', 'CPSC', '2025-11-20', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Anzmtosn Magnet Fidget Spinner Sets', 'The Recalled Magnet Spinner Sets Violate The Mandatory Standard For Toys Because The Sets Contain Loose Magnets, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, They Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic fidget spinner sets immediately, take them away from children and dispose of them. To receive a full refund, consumers should send a photo of the disposal to Anzmtosn via email at Anzmtosn53@163.com.', '26104');
INSERT INTO safety_incidents VALUES ('853b15cdd439217870cfa0198ddf59b8fc02dcde', 'CPSC', '2025-11-20', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Mallimoda Children''s Pajama Sets', 'Burns', 'Other', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled pajama sets and contact Mallimoda for a full refund. Consumers should cut the pajama sets in half and email a photo of the destroyed garments to mallimodarecall@hotmail.com with the consumer''s name and "Recall Proof" in the subject line.', '26101');
INSERT INTO safety_incidents VALUES ('116b1ec60db21c7fb57f4f05db5491428a5f5ca8', 'CPSC', '2025-11-20', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Play Yards', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled play yards and contact Anna Queen for a full refund. Consumers should disassemble the fabric cover from the play yard frame, cut up the cover and mattress pad and email a photo of the destroyed play yard to tingerservice@outlook.com to obtain a full refund. Consumers should then dispose of the destroyed play yard.', '26099');
INSERT INTO safety_incidents VALUES ('1a51cdd61c17a19057aa33201cd3327fb59bccee', 'CPSC', '2025-11-20', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Romorgniz Fabric 12- and 13-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately, if they are not anchored to the wall, and place them in an area that children cannot access. Contact Romorgniz for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to Romorgnizrecall@outlook.com demonstrating disposal of the product.', '26106');
INSERT INTO safety_incidents VALUES ('e34607c0476a26697e1a1d750e3c1558855cf7a2', 'CPSC', '2025-11-20', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Model Year 2025 Spartan SRT-XD and KGZ-XD riding lawn mowers', 'The Riding Mower''S Steering Arm Dampers Can Be Installed Incorrectly, Which Can Result In An Unexpected Bouncing Motion And Loss Of Operator Control, Posing A Crash Hazard.', 'Other', 'Fracture / Blunt Trauma', 'The firm has received 15 reports of the mower bouncing unexpectedly while in use, including one report of a minor injury involving scrapes and bruises.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Spartan riding mowers and contact an authorized Spartan dealer to schedule a free inspection and repair of the steering arm dampers at the dealer''s location. To verify whether your Spartan mower is affected by the recall, you will need your Spartan mower''s model and serial number. To confirm whether your mower is within the affected serial range, visit https://joinspartannation.com/recall-information/. To find a Spartan authorized service dealer near you, visit Spartan''s website at: https://joinspartannation.com/dealer-locator.', '26103');
INSERT INTO safety_incidents VALUES ('ea50d3169243826283e0b5fa5bfa930c0ad350fa', 'CPSC', '2025-11-13', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Portable Power Banks and Wireless Charging Stands', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received one report of a fire incident in the U.S. (and 15 reports internationally). Two minor burn injuries and property damage totaling $37,765 have been reported outside of the U.S.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled power banks and charging stands and contact Belkin to receive a full refund or store credit. Consumers should submit photos showing the front and back of the product with their recall submission form. Consumers can receive a full refund for the amount on the purchase receipt, if provided. If no receipt is provided, consumers can receive the average sales price for the model. Alternatively, consumers can choose to receive a Belkin store credit worth 20 percent more than the average sales price of the model. Note: Do not throw this recalled lithium-ion battery or device in the trash, the general recycling stream (e.g., street-level or curbside recycling bins), or used battery recycling boxes found at various retail and home improvement stores. Recalled lithium-ion batteries must be disposed of differently than other batteries, because they present a greater risk of fire. Your municipal household hazardous waste (HHW) collection center may accept this recalled lithium-ion battery or device for disposal. Before taking your battery or device to a HHW collection center, contact that office ahead of time and ask whether it accepts recalled lithium-ion batteries. If it does not, contact your municipality for further guidance.', '26090');
INSERT INTO safety_incidents VALUES ('dc4d62b83e155ae84d7606c4117c74b665cc9a00', 'CPSC', '2025-11-13', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Bettina Doll Set with Magic Light Unicorn', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately take the doll sets away from children, stop using the recalled toys and remove and properly dispose of the batteries. Consumers will be asked to throw the unicorn away and send a photo of the disposed product to bettinaftersales@outlook.com to receive a full refund.', '26085');
INSERT INTO safety_incidents VALUES ('33d2390052ef0b8fbceccbc3a336460b37839f00', 'CPSC', '2025-11-13', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Great Lakes Select Button Cell and Coin Batteries', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the Great Lakes Select Battery Packs immediately, place them in an area that children cannot access and contact Great Lakes Wholesale International to obtain a full refund. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26089');
INSERT INTO safety_incidents VALUES ('cebee2f8cca86fddd939481f425bf4901e520981', 'CPSC', '2025-11-13', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Certain Tesla Powerwall 2 AC Battery Power System', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 22 reports of overheating, including six reports of smoking and five reports of fire, resulting in minor property damage. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should ensure their Powerwall 2 system is online and check the Tesla App for a notification about whether their unit is included in the recall. Tesla has remotely discharged (or removed energy from the battery of) affected Powerwall 2 systems that are online, to prevent overheating, until the replacement is installed.', '26092');
INSERT INTO safety_incidents VALUES ('cc461c54aeafd4630ecd4e6b138fe0a454840015', 'CPSC', '2025-11-13', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Trek and Electra-branded Bicycles with Coaster Brakes and Replacement Rear Wheels with Coaster Brakes', 'The Coaster Brakes Can Fail To Engage, Resulting In The Rider Losing Control, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bicycles with coaster brakes and related replacement rear wheels and contact an authorized Trek or Electra dealer to schedule a free repair at the dealer.', '26088');
INSERT INTO safety_incidents VALUES ('0e142abb28c2b7327630e6ad0b5d10bdbf6d7fb7', 'CPSC', '2025-11-13', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Zigjoy Toddler Sleep Sacks with Feet', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the sleep sacks and contact Zigjoy-US for a full refund. Consumers should cut the sleep sacks in half, take a photo of the destroyed garments and email it to zjoy-us@outlook.com to receive the refund.', '26091');
INSERT INTO safety_incidents VALUES ('e4655ff1ffe6416155c815a79f1f51e4d5648b49', 'CPSC', '2025-11-13', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Zippee Activity Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Mobi Games is aware of one incident involving a child placing the toy in his/her mouth and gagging, resulting in vomiting and choking. The child was released from medical care with no further injuries.', 'Moderate', 1, 0, 'Consumers should stop using the recalled toy immediately, take it away from children and contact Mobi Games to receive a full refund. Consumers will be asked to register their product online by first confirming they have an affected version with spherical ends on the strings and then by providing a photo of the destroyed toy. Consumers will be directed to destroy the toy by cutting the spherical ends off the silicone strings and writing their initials and date on the teal cylinder.', '26086');
INSERT INTO safety_incidents VALUES ('ec2c07947982fa2fd0cbb78dd8ab85a5497088d8', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Neaude Adult Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled adult portable bed rails and contact Neaude for a full refund. Consumers should write "RECALLED" on the upper and lower rails with permanent marker, write "Bought on or after August 21, 2023" on a piece of paper, take a photo of this alongside the marked bed rails and email the photo to ruiye1234@outlook.com. Consumers should then dispose of the recalled product in accordance with state and local waste disposal procedures.', '26077');
INSERT INTO safety_incidents VALUES ('39755440f6463dea5738d2c71231b119c990e286', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Y''all Can DIY Liquid Bioethanol Fireplace Fuel Containers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled fireplace fuel immediately, place them out of reach of children, and contact Astemrey to receive free replacement container of fuel. To participate, consumers should clearly mark the product container with "DO NOT USE," the Amazon order number, then take a photo showing the entire product with the markings visible and email it to contact@astemrey.com for verification to receive the replacement. Once Astemrey verifies your request for replacement, properly dispose of the original bottle and contents. Only products manufactured and sold after January 12, 2025, are included in this recall. Note: Consumers should follow local household hazardous waste (HHW) guidance for flammable liquids. Contact your city, county, or state HHW program for instructions, as requirements may differ by location. Safe approach: Keep the product in its container, clearly label it ''Do Not Use,'' and bring it to a local HHW drop-off. Do not pour fuel into drains. Do not place fuel in household trash. Because requirements may vary by state, county, or city, consumers should always follow the disposal instructions provided by their local HHW program.', '26079');
INSERT INTO safety_incidents VALUES ('12fc22d981ec50305134a65729a63bca19267cad', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Kirkland Signature Valdobbiadene Prosecco DOCG bottles', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'F&F Fine Wines International, Inc. has received ten reports of the bottles shattering or breaking, resulting in one laceration injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bottles and not attempt to open them. Consumers should discard the recalled bottles in their household trash and contact Ethica Wines for instructions on how to obtain a full refund from Costco.', '26068');
INSERT INTO safety_incidents VALUES ('8c5aedb50656c1228c9b2233ba7792a6e634f962', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Criblike aftermarket play yard and non-full sized crib mattresses', 'Fire', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the crib mattresses and contact Criblike for instructions on requesting a full refund. Consumers should destroy the mattresses by cutting them in half, take a photo of the destroyed mattress and email the photo to Criblike-service_2025@outlook.com with "Recall Proof" and your name in the subject line.', '26069');
INSERT INTO safety_incidents VALUES ('da716e7f83ac81aecc2397140af9f6c1e37d71ac', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Inkari Plush Alpaca Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled plush toys and contact Inkari for a full refund. Consumers will be asked to cut the fur of the toy and send a photo to support@inkari-alpaca.com.', '26075');
INSERT INTO safety_incidents VALUES ('f2612f6cf8a3a7bf95004a5b938a91d79872bb6c', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Lezyne Pressure Over Drive Bicycle Floor Pumps', 'Injury', 'Explosion', 'Fracture / Blunt Trauma', 'Lezyne has received one report of a canister ejecting from its base, resulting in serious injuries to the fac.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled pumps and contact Lezyne for a free replacement pump, including shipping. Consumers will be asked to visit ride.lezyne.com/recall to register their recalled product and obtain instructions on how to properly dispose of their product. Proof of purchase (receipt) is not required.', '26078');
INSERT INTO safety_incidents VALUES ('8d7a9aa8e29d12c0e82c92959a78545ee25895c0', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Napei Collapsible Infant Bath Tubs', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the infant bath tubs and contact Sefon Store for instructions to receive a free replacement battery compartment. Consumers should provide their order number or a photo of the tracking label found on the bottom of the infant bath tub and email Sefon Store at Napeiservice00@outlook.com. Upon confirmation of your order number or a photo of the tracking label, Sefon Store will provide a replacement battery compartment to be delivered to the consumer. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26071');
INSERT INTO safety_incidents VALUES ('31f96a6886c03721686d7973d512edf9977da17d', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Peloton Original Series Bike+ Model PL02', 'Injury', 'Mechanical Failure', 'Fall Injury', 'Peloton has received three reports of the seat post breaking and detaching from the bike during use, including two reports of injuries due to a fall.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled exercise bikes and contact Peloton for a free repair. Peloton is offering consumers a free seat post that can be self-installed.', '26067');
INSERT INTO safety_incidents VALUES ('88e6b8b95221a302185f0c07afe2f805aed2fdfc', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Vevor Baby Swings', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the swings and contact Sanven Technology for a full refund. Consumers should remove the swing cover and cut it in half and send a photo of the destroyed cover with "Recalled" written with permanent marker on the swing''s base to recalling@vevor.com and then dispose of the swing in accordance with local and state laws.', '26074');
INSERT INTO safety_incidents VALUES ('3cf22d5797a05e46e2eecdee4a042307df70ee73', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'STIHL BR 800 Backpack Blower', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled STIHL BR 800 backpack blower and bring it to an authorized STIHL servicing dealer for a free inspection and replacement of the fan wheel.', '26072');
INSERT INTO safety_incidents VALUES ('c945bf969c86b5f3dd4d1998e68129994cb49194', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Three-Wheeled Children''s Scooter with Foot Brake', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'Konges Sløjd has received 18 reports of the left front wheel detaching, resulting in three injuries, including one report of a broken arm and a child''s lost tooth.', 'Moderate', 1, 0, 'Consumers should stop using the scooter immediately and contact Konges Sløjd for a full refund or voucher, by either providing a photo of the scooter disassembled by removing the scooter stem from the base of the scooter or returning the unit to the store where it was purchased.', '26070');
INSERT INTO safety_incidents VALUES ('448755331cfdc979105d891fd917b6cbae2d8d17', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Umeyda Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the nightgowns immediately and contact Umeyda Company for a full refund. Consumers should cut the nightgowns in half and email a photo of the destroyed garments to ameyda123@163.com to receive the refund. Consumers should dispose of the destroyed garments.', '26073');
INSERT INTO safety_incidents VALUES ('8b31ec409c5dcfb72bd693b868c14ec813760c7a', 'CPSC', '2025-11-06', 2025, '2025-11', 'USA', 'United States', '', 'Other', 'Children''s WYBITNY Bed Rails', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact WYBITNY for a full refund. Consumers should send a photo of the recalled bed rails, with "Recalled" written on the front in permanent marker, to WYBITNY by email at servicewybitny@outlook.com. Consumers should dispose of the recalled bed rails in accordance with state and local waste disposal procedures.', '26081');
INSERT INTO safety_incidents VALUES ('0bcf68171015884da7cb361f8f9429cb386b01e7', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Harppa 5-in-1 Convertible High Chairs for Babies and Toddlers', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the high chairs and contact Harppa for a replacement high chair. Consumers should email recall@harppababy.com and provide the order number, order date, or photo of the tracking label located on the seatback. Upon verification of the recalled product, Harppa will plan for the replacement high chair to be delivered to the consumer. To destroy the recalled high chair, consumers should disassemble the high chair, cut the restraints and seat cover, and email photos of the disassembled and destroyed parts. Consumers must provide proof that the recalled product has been destroyed.', '26061');
INSERT INTO safety_incidents VALUES ('9cc01417f5a4245ee9bd829260729ed67162be4a', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Avenco and Novilla Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the mattress immediately and contact PT Champion to receive a free fitted cover to put over their mattress, which will bring the mattress into compliance with mandatory flammability standard.', '26062');
INSERT INTO safety_incidents VALUES ('dd970ea25a3dc0e0e7806d46a10e69021146a65b', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Ana Dining Chair', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 149 reports of chair legs breaking, including 10 reports of injuries to the head, back, arms and face.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled dining chair and contact Crate & Barrel to obtain a free replacement chair and coordinate a free pick up of the recalled chair.', '26059');
INSERT INTO safety_incidents VALUES ('7082e7c9aeb5757b9467cea046be169d9c45ae00', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'DINBooonLUX 12-Inch Full Size Hybrid Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled mattress and contact DINBooonLUX for a full refund. Consumers should write "Recalled" on the mattress with a permanent marker, email a photo of the marked mattress to Dingbangrecall2025@outlook.com and certify disposal. Upon receipt of the photo and certification of disposal, consumers will be issued a full refund.', '26063');
INSERT INTO safety_incidents VALUES ('68a09d1c5eea66d23dff8d47613a7ed65118e9ef', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Grundens Youth Clipper 282 and Zenith 282 Jacket', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately take the recalled jackets away from children and remove the drawstrings to eliminate the hazard. Consumers can either return the jacket to Grundens for a full refund or upload a photo of the jacket with the drawstring removed to receive a partial store credit in the form of a 20% discount code. Consumers should go to https://grundens.com/pages/recall to participate in the recall.', '26053');
INSERT INTO safety_incidents VALUES ('caeb36dc8cd836a31ee904c7d33dcf478f7e5ace', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Destination Holiday Glow Light Stick Bracelets', 'The Green Glow Stick Bracelet Within The 12-Pack Container Can Leak, Posing A Skin Irritation Hazard.', 'Other', 'Skin Irritation', 'The firm has received one report of a green bracelet leaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should not use the green bracelet sold as part of the 12-pack of bracelets and return the bracelet or container to H-E-B to receive a full refund.', '26057');
INSERT INTO safety_incidents VALUES ('e813a3b805780fcba47df27c06cc85e4b26b00d8', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Children''s HOMEAL Bed Rails', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact HOMEAL for a full refund. Consumers should remove the cloth covering from the frame, cut the cloth in half, and email a photo of the destroyed cloth and frame to HOMEAL at homeal_recalls@outlook.com. Upon receipt of the photo, HOMEAL will issue a full refund. Consumers should dispose of the recalled bed rails in accordance with state and local waste disposal procedures.', '26060');
INSERT INTO safety_incidents VALUES ('d4b77eaffd500f9185be0066d06ebc76eada513a', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Knog Blinder 900 and Blinder 1300 Front Bicycle Lights', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received five reports of the battery catching on fire or exploding. No injuries reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycle light and register at http://www.knog.com/recall for instructions on how to receive a free replacement bicycle light. Consumers should dispose of the lithium-ion batteries in accordance with local and state regulations and not discard it in the household trash. Do not dispose of the light until you receive confirmation from Knog that your unit qualifies for the recall.', '26051');
INSERT INTO safety_incidents VALUES ('5d91ee785dac191eeff0f2aa6d3a4b8f4ba981da', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Milwaukee Tool M18 FUELTM Top Handle Chainsaw with either a 12" or 14" bar', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received two reports of the chain brake not activating, including one injury involving a lacerated finger.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled chainsaw and contact Milwaukee Tool for a free repair. Consumers should register their product at https://service.milwaukeetool.com/support/eservice to receive a prepaid shipping label to return their product to Milwaukee Tool for repair.', '26064');
INSERT INTO safety_incidents VALUES ('934c150221fb6725f3e71c7fef9f11d7816819db', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Organic Cotton Pack N Play Mattress Dual-Sided Portable Baby Crib Pad', 'The After-Market Play Yard Mattresses May Not Adequately Fit Certain Play Yards, Which Is In Violation Of The Mandatory Standard For Crib Mattresses, Posing A Deadly Entrapment Hazard. Babies Have Suffocated In Gaps Between An Undersized Mattress, Or Extra Padding, And Side Walls Of A Product, Especially When The Infant''S Face Becomes Trapped Against The Side And The Mattress, Preventing The Infant From Breathing.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled mattresses and contact Modera for a full refund. Consumers should cut the mattresses in half and send a photo of the destroyed mattress in the waste bin to recall@moderababy.com to receive a full refund.', '26052');
INSERT INTO safety_incidents VALUES ('8d4d2e6cf7c241a8f6cf64ee350971acac48eef9', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Model Year 2025-2026 Ranger XP 1000 NorthStar and Ranger Crew XP 1000 NorthStar Recreational Off-Road Vehicles (ROVs)', 'Fire', 'Electrical Fault', 'Not Specified', 'The firm has received five reports of sparking/smoking/melting and one report of fire. No injuries or property damage have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled ROVs and go to https://www.polaris.com/en-us/recalls/off-road/polaris-recalls-some-model-year-2025-2026-ranger-xp-1000-and-crew-xp-1000-vehicles/ to determine if their vehicle falls under the scope of the recall. Polaris is providing instructions on how to continue operating their vehicles until the repair can be completed or to contact an authorized Polaris dealer to schedule a free repair at the dealer''s location.', '26054');
INSERT INTO safety_incidents VALUES ('cf5dec216b5941398eca15793845560133a20987', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Halloween-themed Skeleton Wax Candle', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled candle and return them to any Kroger store for a full refund in the original form of payment.', '26065');
INSERT INTO safety_incidents VALUES ('2c42651c67b560ce84fba80dae956464e8ebb093', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Stealth and Covert Kayak Paddles', 'Drowning', 'Drowning Risk', 'Drowning', 'The firm has received 80 reports of the paddles breaking during use. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled kayak paddles and contact Werner Paddles for a full refund in the form of a check or store credit redeemable online. Consumers should fill out a recall form at https://wernerpaddles.com/pages/covert-stealth-recall-consumers. To collect the refund or obtain the store credit, consumers should follow the instructions on the Werner website and destroy the recalled kayak paddle by cutting the paddle into four equal pieces, halfway through each blade and halfway through the left and right side of the shaft and upload a photo of the destroyed paddle.', '26058');
INSERT INTO safety_incidents VALUES ('b609290513f150e1feaa43125cc6a455a194622d', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'WLIVE Fabric 16-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately, if they are not anchored to the wall, and place them in an area that children cannot access. Contact WLIVE for instructions on how to dispose of the dressers, to receive a full refund. Consumers must submit a photo to wliveproductrecall@wlivehome.com demonstrating disposal of the product.', '26066');
INSERT INTO safety_incidents VALUES ('8ab8d3f14f791b0652b9f631e08792699cc6208d', 'CPSC', '2025-10-30', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'YaFiti Fabric 12-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately if they are not anchored to the wall and place them in an area that children cannot access. Contact YaFiti for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to Yafitiservice@outlook.com showing disposal of the product.', '26055');
INSERT INTO safety_incidents VALUES ('afe4b9089524277224b6c0c74f13035bf41b3544', 'CPSC', '2025-10-23', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Scotch™ brand TL909-50 thermal laminator', 'Burns', 'Flammability / Overheating', 'Burns', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using and unplug the recalled laminators and contact the 3M Company to receive a full refund. Consumers will be asked to fill out a short form, confirm that their laminator is included in the recall, and upload a photograph of the machine with the unplugged power cord cut. The refund will come in the form of a check mailed to the consumer upon receipt of the completed form and confirmation that the machine''s power cord has been cut.', '26050');
INSERT INTO safety_incidents VALUES ('7124b14b6ac43d66723ce3183907c50c8b3c50e9', 'CPSC', '2025-10-23', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Bealife 5-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To A Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately, if they are not anchored to a wall, and place them in an area that children cannot access. Consumers should contact Bealife for instructions on how to dispose of the dressers and will be required to email a photo demonstrating disposal of the product to info@bealifehome.com to receive a full refund.', '26049');
INSERT INTO safety_incidents VALUES ('83627cfdef7af39389304fd2d8004667906e2ef1', 'CPSC', '2025-10-23', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Cranach Hardware Plastic Tip Restraint Kits', 'The Recalled Plastic Tip Restraint Kits (Also Referred To As Furniture Straps) Can Break Or Degrade, Posing Tip-Over And Entrapment Hazards That Can Result In Serious Injuries Or Death To Children Or Elderly Consumers Interacting With Furniture That Is Secured To The Wall With The Defective Plastic Tip Restraints.', 'Entrapment', 'Entrapment', 'CPSC is aware of at least 115 incidents where consumers reported that the defective plastic tip restraint kits broke, including six reported tip-over incidents. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should stop using Cranach Hardware plastic tip restraints immediately and contact Cranach Hardware for a free replacement tip restraint kit made of stainless steel. Keep children away from the unit while waiting for a replacement tip restraint kit. Consumers will need to provide photographic evidence of destruction or disposal of the product to receive a replacement tip restraint kit from Cranach Hardware.', '26038');
INSERT INTO safety_incidents VALUES ('2dd2d87f4f9703eccce3296718b477354774ed49', 'CPSC', '2025-10-23', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Bio Ionic One-Inch-Long Barrel Curling Iron', 'Burns', 'Mechanical Failure', 'Burns', 'The firm has received 258 reports of the curling iron barrel detaching, including six minor burn injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled curling iron, unplug it, and contact Bio Ionic to register for a free replacement curling iron. Consumers will be asked to cut off the plug and return the plug to the recalling firm using a prepaid shipping label.', '26046');
INSERT INTO safety_incidents VALUES ('1933d8b8b9a1dd7f98272fd18b3b57a084e842ae', 'CPSC', '2025-10-23', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'LEACHOI Bed Rail', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled adult portable bed rails immediately and contact LEACHOI Store to obtain a refund. Consumers should follow these disposal steps: 1 Remove the bed rail handle, U-shaped frame, side handle, and extension tubes (if present). 2 Write "RECALLED" on upper rail handle and silver U-shaped frame with a permanent marker. 3 Using scissors, cut the black fabric mesh bag off the upper rail and cut the black safety strap in half (if present). 4 Write the buyer''s name on a piece of paper next to the disassembled product. 5 Take a photo and upload it online at https://leachoi.com/leachoi-bed-rail-safety-recall/. 6 Dispose of the recalled product in accordance with local requirements. Consumers who have difficulty with any disposal step or need additional instruction should contact LEACHOI Store.', '26037');
INSERT INTO safety_incidents VALUES ('5f8b2322a29ffd563b65b946f63bf8d6ed797ea1', 'CPSC', '2025-10-23', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Bioremedy Infrared Sauna Blankets', 'Burns', 'Flammability / Overheating', 'Burns', 'The firm has received 65 reports of the sauna blankets overheating, including 32 reports of burn injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using and unplug the recalled sauna blanket and go to the firm''s website for instructions on how to participate in the recall and obtain a replacement sauna blanket. Consumers should dispose of the recalled sauna blankets in a manner consistent with local disposal regulations.', '26036');
INSERT INTO safety_incidents VALUES ('9152c546fb714dbcc75e9f311327f2daf597244c', 'CPSC', '2025-10-23', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Pack-N-Stroll Premium Folding Utility Wagon', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the utility wagons immediately and return the item to Costco to receive a full refund.', '26044');
INSERT INTO safety_incidents VALUES ('347240d1399781accacbfaa45b728cbf2daa9fc8', 'CPSC', '2025-10-23', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Tylö Halmstad and Kiruna Hybrid Saunas', 'Falls', 'Mechanical Failure', 'Fall Injury', 'Sauna360 has received seven reports of the benches breaking, including one consumer with head and neck injuries.', 'Moderate', 1, 0, 'Consumers should stop using the Tylö Halmstad and Kiruna Hybrid Sauna benches immediately and contact Sauna360 for a free repair. Sauna360 will provide a professional installer to retrofit the benches with additional hardware. Consumers will also receive a revised product manual from Sauna360 that includes the weight limit.', '26040');
INSERT INTO safety_incidents VALUES ('f614173fbe3ba8ee9ef2d864a74489463f966920', 'CPSC', '2025-10-23', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Scepter Gas and Oil Combination Fuel Containers', 'Fire', 'Flammability / Overheating', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled fuel containers, place them out of reach of children and contact Canada Prep and Ship for a full refund. Consumers will be asked to write "Recalled" with permanent marker on the container and submit a photo of it in the trash to info@canadaprepandship.com.', '26048');
INSERT INTO safety_incidents VALUES ('0bc2bbad0c9fb6d217eca5bbc9c9fc71d8b068e8', 'CPSC', '2025-10-23', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Scepter Gas and Oil Combination Fuel Containers', 'Fire', 'Flammability / Overheating', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the fuel containers, place them out of reach of children, and contact Pro Recycle to return the product free of charge for a full refund.', '26047');
INSERT INTO safety_incidents VALUES ('d10d668094abae782f801562d7507b038e030b31', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'AOWOS Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Serious Injuries Or Death To Children. The Dressers Violate The Mandatory Standard Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately, if they are not anchored to the wall, and place them in an area that children cannot access. Contact AOWOS for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to AOWOSRecall@outlook.com of the product showing disposal.', '26024');
INSERT INTO safety_incidents VALUES ('9899dbad6a94afdceb433f158d5d388e635f2859', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Belivium Baby Loungers', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the baby loungers immediately and contact Belivium for a full refund. Consumers should remove the sleeping pad, cut up the sides of the baby loungers and the sleeping pad and email a photo of the destroyed lounger to BeliviumRecall@163.com to obtain a full refund.', '26032');
INSERT INTO safety_incidents VALUES ('25d40de6868b2c9d698a377e125f5afdcf3e135b', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'NordicTrack Model NTRW19147 Rowing Machine', 'Fire', 'Flammability / Overheating', 'Not Specified', 'There have been eight reported incidents including two reports of fire, six reports of smoking or melting, and at least $6,000 in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using and unplug the recalled rowing machines. Consumers should contact iFIT to arrange for a free home repair by an authorized technician in the form of a replacement screen console.', '26025');
INSERT INTO safety_incidents VALUES ('a0683493cdacc515ce86edf6fb22f7451deb1a2b', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Byron Emperador Tables and Byron Reeded Stone Tables and Desks', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'RH has received one report of a dining table collapsing, resulting in lacerations.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled tables and desks and contact RH for a full refund of the purchase price and to coordinate pick up of the recalled tables and desks, free of charge. RH will issue the refund upon receiving the recalled table or desk.', '26023');
INSERT INTO safety_incidents VALUES ('52b148018600e75ad363241d24f1fc4af5661e8d', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Vaast A/1 bicycles and frames', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has had 22 consumers report frame fractures and three consumers report frame tube separation, one of which resulted in a minor injury after falling from the bike.', 'Minor', 1, 0, 'Consumers should immediately stop using the Vaast A/1 bicycles and frame and contact Super Wheels Inc. for a free replacement. Once consumers register their bike at Contact | VAAST Bikes, (www.vaastbikes.com/contact-us/), Super Wheels Inc. will provide the consumer with a replacement frame and pay (up to $200) for a bike shop technician to rebuild the bike with the replacement frame.', '26035');
INSERT INTO safety_incidents VALUES ('204acefd277a828d0340709b27950041a0218fb2', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'E-Z-GO Personal Transportation Vehicles (PTVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled vehicles until they have been inspected and repaired, if needed. Consumers can contact Textron E-Z-GO for inspection instructions or contact an authorized Textron E-Z-GO dealer to schedule a free inspection. If any signs of fuel leakage are detected, the vehicle will be repaired by an authorized dealer free of charge, by replacing the fuel line. Consumers who cannot take their recalled PTV to an authorized dealer for inspection or repair can contact Textron E-Z-GO or an authorized dealer for assistance.', '26021');
INSERT INTO safety_incidents VALUES ('5a0509d1643f86a91b21cf55d1bd12c13a49355d', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'VST gas-fired tankless water heaters', 'Injury', 'Other', 'Poisoning / Ingestion', 'The firm has received 33 reports of cracked exhaust ducts allowing exhaust fumes to leak out. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled water heater and contact VESTA.DS to have a certified technician install the free repair. Consumers who must continue using the water heater while awaiting repair should have working smoke and carbon monoxide alarms in their homes.', '26026');
INSERT INTO safety_incidents VALUES ('7266c15148bad20c63dac33770b68653e0104081', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Wilteexs Bioethanol Fuel Bottles', 'Fire', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled fuel bottles, place them out of reach of children, and contact Wilteexs for a full refund. Consumers will be asked to write "Do not use" and the Amazon order number with permanent marker on the bottle; and submit a photo of it to hongyaodemg@outlook.com. Consumers should dispose of the fuel bottles in accordance with local and state regulations.', '26030');
INSERT INTO safety_incidents VALUES ('34ae7a10472a6bd42fcc31e382bded3293fba9f9', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'WLIVE Fabric 12-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'The firm has received one report of the dresser tipping over. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately, if they are not anchored to the wall, and place them in an area that children cannot access. Contact WLIVE for instructions on how to dispose of the dressers, to receive a full refund. Consumers must submit a photo to wliveproductrecall@wlivehome.com demonstrating disposal of the product.', '26022');
INSERT INTO safety_incidents VALUES ('ff8d3a8b3d66da11c1306a66314627e74fdbc582', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Model Year 2017-2024 Yamaha Golf Car Vehicles', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled golf car vehicles and contact an authorized Yamaha Golf Car dealer to schedule the free installation of new brake shoes and pads. For consumers who cannot take their recalled golf car to an authorized dealer, Yamaha will provide transportation or will install the replacement brake shoes and pads at the location of the golf car.', '26027');
INSERT INTO safety_incidents VALUES ('a2a6367f85f8222eb29e5a51b38c343411b34ea3', 'CPSC', '2025-10-16', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Model Year 2021-2025 Yamaha Golf Car Vehicles', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled golf car vehicles and contact an authorized Yamaha Golf Car dealer to schedule the free installation of two stoplights. For consumers who cannot take their recalled golf car to an authorized dealer, Yamaha will provide transportation or will install the stoplights at the location of the golf cart.', '26028');
INSERT INTO safety_incidents VALUES ('ed81c21ff33d27cf96109134e387c1534aeb5af5', 'CPSC', '2025-10-09', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Bellabu Bear Children''s Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled children''s robes, take them away from children and contact Bellabu Bear for a full refund or store credit for the original purchase price. Consumers will be provided with a prepaid shipping label to return the recalled robes.', '26013');
INSERT INTO safety_incidents VALUES ('a666379d49445dfb4a74ffcc43eb878673d3f70c', 'CPSC', '2025-10-09', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Scripto® Premium Torch', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled torches and return them to the retailer for a full refund or store credit or contact Calico Brands for instructions on how to return the torches and receive a full refund. After contacting Calico Brands, consumers will receive a shipping label and appropriate hazmat packaging to return the torches free of charge.', '26006');
INSERT INTO safety_incidents VALUES ('2f1304871486d1146d6019b58b0bb3fd74543d59', 'CPSC', '2025-10-09', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Bmrwtg LED Tutu Skirts', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled skirt and remove and properly dispose of the batteries. Contact Bmrwtg for a full refund. Consumers should cut the skirt and send a photo of the destroyed skirt in the trash to bmrwtgrecall@outlook.com. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '26016');
INSERT INTO safety_incidents VALUES ('fe451b2046c7321c3216433e9ef4eb6d3b554cc0', 'CPSC', '2025-10-09', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'EcoFlow Delta Max 2000 Power Stations', 'Fire', 'Flammability / Overheating', 'Burns', 'EcoFlow Technology has received six reports of the recalled Power Stations catching fire, with property damage totaling over $850,000.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Power Stations and contact EcoFlow Technology for instructions on installing a free repair in the form of a firmware update.', '26010');
INSERT INTO safety_incidents VALUES ('c4f748f8cfaa61ab17010540e7ffe76bea6415b9', 'CPSC', '2025-10-09', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'ESR HaloLock Wireless Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 20 reports of the lithium-ion battery catching fire and exploding, resulting in property damage of about $30,000. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled power banks and contact Waymeet for a full refund. Consumers will be asked to send to support@esrtech.com their order number (not required) and a photo of the recalled power bank showing the model number with the word "Recalled" written on it in permanent marker. Consumers should dispose of the power banks in accordance with local and state hazardous waste disposal regulations. Note: Do not throw this recalled lithium-ion battery or device in the trash, the general recycling stream (e.g., street-level or curbside recycling bins), or used battery recycling boxes found at various retail and home improvement stores. Recalled lithium-ion batteries must be disposed of differently than other batteries, because they present a greater risk of fire. Your municipal household hazardous waste (HHW) collection center may accept this recalled lithium-ion battery or device for disposal. Before taking your battery or device to a HHW collection center, contact that office ahead of time and ask whether it accepts recalled lithium-ion batteries. If it does not, contact your municipality for further guidance.', '26011');
INSERT INTO safety_incidents VALUES ('fdf716003675b7c5b8cc8ffd3e05edc14635e7e0', 'CPSC', '2025-10-09', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Generic Magnetic Balls 1000pcs', 'The Recalled 3 Mm Magnetic Ball Sets Violate The Mandatory Standard For Toys Because The Magnet Sets Contain Loose Magnets Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic ball sets immediately and take them away from children and contact Ritons for instructions on how to receive a refund. Ritons will provide a prepaid label for consumers to return the recalled products.', '26012');
INSERT INTO safety_incidents VALUES ('944232dc642ec2c3cadd7a1024f3bc5650c6df30', 'CPSC', '2025-10-09', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Living Glow portable waist fan', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received four reports of the portable waist fan melting or catching fire. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled waist fan and register at https://www.waistfanrecall.info to receive a full refund. After registering for the recall, consumers should disable the portable fan per the firm''s instructions, then dispose of it in accordance with local and state regulations and not discard it in the household trash.', '26008');
INSERT INTO safety_incidents VALUES ('b5b79122fe4cedb75703518886b5d1ae77736281', 'CPSC', '2025-10-09', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Mom Genius Retractable Safety Gates', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled retractable safety gates immediately and contact Mom Genius for a full refund. Consumers must destroy the gate by cutting through the mesh and take a photo showing the destroyed gate. Submit the photo to product-recall@momgenius.com. Once the photo is received, Mom Genius will issue a full refund.', '26014');
INSERT INTO safety_incidents VALUES ('f2fb266194cea7c2a694102ac6662eae2afc7d5a', 'CPSC', '2025-10-09', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Ambiano Electric Pressure Cookers', 'Burns', 'Explosion', 'Burns', 'The firm has received 11 reports of incidents, in which the contents were expelled under pressure, including eight reports of severe burn injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pressure cookers and contact Tempo or ALDI for a refund. Consumers can either return the fully intact pressure cooker to any ALDI retail location for a full refund or submit a photo of the pressure cooker with the unplugged power cord cut and a photo showing the model number and date code via email to Tempo at serviceusa@tempo.org.', '26007');
INSERT INTO safety_incidents VALUES ('000b51eeaf2ebc536923545a3e26d721934f1d40', 'CPSC', '2025-10-09', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'YGJT Baby Loungers', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby loungers and contact YGJT Local Warehouse for a full refund. Consumers should remove the foam and pads from the baby lounger''s cover and cut the cover, foam and pad in half. Consumers should email photos of the destroyed pieces to YGJTrecall@outlook.com to obtain a full refund.', '26015');
INSERT INTO safety_incidents VALUES ('6e7193e6f8bbdfa61aa08eec85454a85e77d9ffd', 'CPSC', '2025-10-02', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Blossom Children''s Loungewear sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled loungewear sets immediately and contact Blossom for a full refund in the original form of payment or store credit. Consumers should destroy the garments by cutting them in half, then take a photo and dispose of them. Consumers should send a photo of the destroyed garments by email to sales@blossomocc.com to receive the refund. Proof of purchase (receipt) is not required.', '26003');
INSERT INTO safety_incidents VALUES ('d2c2a9ec056cc0d619bf7976cb7fc0be26855e2a', 'CPSC', '2025-10-02', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Dissolved Oxygen Test Kits', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled test kits out of sight and reach of children and contact Almpal for how to properly dispose of the recalled bottles and for information on how to receive a full refund. Prior to disposing of the recalled kits, consumers will be asked to submit a photo to the seller''s account through Amazon''s messaging platform. A full refund will be issued upon successful verification of the submitted images. Only unexpired kits are included in this recall, which involves kits sold after May 2025. Consumers should dispose of all kits, expired, unexpired or unused in accordance with local household hazardous waste regulation. Note: Physically returning the product is not required.', '26005');
INSERT INTO safety_incidents VALUES ('11053858f1f674eaa956e69687294d3ed96d01e3', 'CPSC', '2025-10-02', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Gunaito 10-Drawer Dressers', 'The Recalled Dressers Are Unstable, If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards, That Can Result In Injuries Or Death To Children. The Dressers Violate The Mandatory Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately, if they are not anchored to the wall, and place them in an area that children cannot access. Contact Gunaito for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to gunaito10recall@outlook.com showing disposal of the product.', '26004');
INSERT INTO safety_incidents VALUES ('c1245b4f76f6bb38f8a74319b3032f5a608d100e', 'CPSC', '2025-10-02', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'Evermore Surprise Eggs', 'The Toy Airplane Inside The Egg Contains Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the Surprise Eggs immediately and contact In Motion Design for a refund. Consumers should destroy the toy airplane, send a photo of the destroyed airplane to support@in-motion-design.com, and then dispose of the airplane in accordance with local and state laws.', '26001');
INSERT INTO safety_incidents VALUES ('c5e1cbaa6c44f4609bbf102601286f558c437041', 'CPSC', '2025-10-02', 2025, '2025-10', 'USA', 'United States', '', 'Other', 'BP125, BatPak 2F and BatPak 3F Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'Zyntony has received two reports of lithium-ion battery overheating and catching fire, even when not in use, resulting in one minor burn injury and property damage, totaling about $3,300.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled power banks and contact Kogalla for instructions on how to receive a free replacement power bank, including shipping. Consumers will be asked to fill out the online form at https://rtn.kogalla.com/products/request-batpak-replacement. Consumers should immediately dispose of the recalled power banks, in accordance with local and state regulations.', '26002');
INSERT INTO safety_incidents VALUES ('a7b22a4ca4fd83b4acfb063c59954e77b1d66ae0', 'CPSC', '2025-09-25', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Hoovy Cooling Gel Insert Pads for Car Seats and Strollers', 'Burns', 'Other', 'Burns', 'The firm has received one consumer report where the child experienced second degree burns to his back, requiring medical attention.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Cooling Gel Insert Pad and contact AMTRADING for instructions on receiving a full refund. Consumers can go to https://hoovyproducts.com/pages/product-recall for instructions on how to register for the recall and to dispose of the recalled pad.', '25476');
INSERT INTO safety_incidents VALUES ('8f0e396fcaab85a6e7b0bbc76c3153391fecf080', 'CPSC', '2025-09-25', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Autoez Bamboo Shades', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled shades and contact Autoez for a full refund. Consumers should remove the shades, cut the operating cord, write the word "Recalled" on the shades and dispose of the product in the garbage. Consumers should send a photograph of the destroyed window shades in the garbage to Autoez_recall@163.com.', '25478');
INSERT INTO safety_incidents VALUES ('4a9eca1748c9e60a23d4dacd3a94ad4f563f1cea', 'CPSC', '2025-09-25', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'RELIEVE Numbing Cream', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled numbing cream out of the sight and reach of children and contact Mad Rabbit via email or online for a free child-resistant lid to store the products. Once the product is secured, consumers can use the product, as directed.', '25477');
INSERT INTO safety_incidents VALUES ('a8ad2cab834458b82d04e0227aea123b17c89c0b', 'CPSC', '2025-09-25', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Persilux Zebra Blinds', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled blinds and contact Persilux for a free repair kit, including shipping. The repair kit consists of a replacement operating cord wand and installation instructions. Consumers should remove the blind, cut and remove the operating cord and send a photograph of the blinds, with the operating cord removed, to recall@persiluxhome.com.', '25479');
INSERT INTO safety_incidents VALUES ('f59cac541c0d923aaf9c190602130f4b43915eee', 'CPSC', '2025-09-25', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Oster French Door Countertop Ovens', 'Burns', 'Other', 'Burns', 'Sunbeam Products Inc. has received 95 reports of the doors unexpectedly closing, resulting in burn injuries to consumers, including two reports of second-degree burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled countertop ovens and contact Sunbeam Products Inc. to receive a free repair kit. The repair kit will include a clip-on device that provides additional holding force to help keep the doors in the open position when reaching in the oven, along with repair instructions and a QR code link to an installation video. The repair kit does not require any tool to install.', '25475');
INSERT INTO safety_incidents VALUES ('f97d89cffef4761bea4891b32201f4492b755595', 'CPSC', '2025-09-18', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Arizer Solo II portable electronic vaporizer devices', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received nine reports of the battery overheating, producing smoke, or ejecting material. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Arizer Solo II portable vaporizers and contact 7111495 Canada for a free replacement. Customers whose serial number is confirmed as impacted will receive a free Solo II MAX replacement and wax to be used for disposal. The recalled unit must be disabled by inserting the provided wax into the charging port, then disposed of at a local hazardous waste or battery recycling facility in accordance with local regulations. Note: Do not throw this recalled lithium-ion battery or device in the trash, the general recycling stream (e.g., street-level or curbside recycling bins), or used battery recycling boxes found at various retail and home improvement stores. Recalled lithium-ion batteries must be disposed of differently than other batteries, because they present a greater risk of fire. Your municipal household hazardous waste (HHW) collection center may accept this recalled lithium-ion battery or device for disposal. Before taking your battery or device to a HHW collection center, contact that office ahead of time and ask whether it accepts recalled lithium-ion batteries. If it does not, contact your municipality for further guidance.', '25470');
INSERT INTO safety_incidents VALUES ('289a11e3f9ff3e8253d732b99bb101f6f209ef15', 'CPSC', '2025-09-18', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'EnHomee 13-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Serious Injuries Or Death To Children. The Dressers Fail To Meet The Mandatory Standard Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to a wall and place them in an area where children cannot access them. Contact EnHomee for instructions on how to identify affected units and dispose of the dressers to receive a full refund. Consumers must submit a photo of the disposed dresser to enhomeestore@gmail.com.', '25474');
INSERT INTO safety_incidents VALUES ('981b2a0d349ac47da4e8c719052150594b7504ae', 'CPSC', '2025-09-18', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Tabletop Fire Pits', 'Fire', 'Flammability / Overheating', 'Burns', 'Five Below has received one report of flames escaping from a tabletop firepit. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled tabletop fire pits and contact Five Below to receive a full refund equal to the purchase price or $5. Consumers who return the fire pit will receive a refund in the original form of payment, cash or store credit. Consumers can also send to Recalls@FiveBelow.com a photo of the fire pit with their name and date written on the product in permanent marker and receive a refund in the form of a check or store credit. Consumers should dispose of the recalled fire pits. Proof of purchase (receipt) is not required to receive a full refund.', '25467');
INSERT INTO safety_incidents VALUES ('65f1a55e262e11562e41b9bef023e68ca9761221', 'CPSC', '2025-09-18', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'IcyBreeze Buddy Portable Misting Fans', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received seven reports of the misting fan overheating while charging, with two of those reports resulting in fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled IcyBreeze Buddy portable misting fan and visit https://www.icybreeze.com/buddy-recall-information for instructions on how to participate in the recall and obtain a $150 credit for use at one of the Solo Brands (for a listing of participating brands visit www.solobrands.com). Consumers will be asked to submit a form online that includes a photograph showing that the power cord has been cut. Consumers should immediately dispose of the misting fan in accordance with local and state regulations following submission of the online form. Proof of purchase is not required.', '25468');
INSERT INTO safety_incidents VALUES ('734417a5c4c33d533c5ac7c7421bcf17b5a08a1c', 'CPSC', '2025-09-18', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'LXDHSTRA Baby Loungers', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby loungers and crib bumpers and contact LXDHSTRA for a full refund. Consumers should remove the foam and pads from the baby lounger''s cover and cut the cover, foam, pad, and crib bumper in half. Consumers should email photos of the destroyed baby lounger and crib bumper to lxdhstrarecall@gmail.com to obtain a full refund.', '25473');
INSERT INTO safety_incidents VALUES ('a38a276c710e5b6fb1e773c3b3bea098b3264b62', 'CPSC', '2025-09-18', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Ambiano Cotton Candy Makers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 12 reports of sparking or fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cotton candy maker and contact Wuensche or ALDI for a refund. Consumers can either return the fully intact cotton candy maker to any ALDI retail location for a full refund or submit a photo of the cotton candy maker with the unplugged power cord cut and a photo showing the model number 836098 and date code 08/2024 via email to Wuensche at service@801service.net.', '25469');
INSERT INTO safety_incidents VALUES ('f5af22c5c50161173314ede2e6783d17bbe3bdc8', 'CPSC', '2025-09-18', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'YooxArmor Multi-Purpose Kids'' Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled kids'' helmets and contact YooxArmor for a full refund. Consumers should destroy the recalled helmet by cutting the straps off the helmet. Consumers can upload photos of the helmet with the straps cut off to service@yooxarmor.com to obtain a refund.', '25472');
INSERT INTO safety_incidents VALUES ('a0c083f3258296e2c2b7614fdd20757d0c60244d', 'CPSC', '2025-09-18', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Youbeien Crib Mobiles', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled toy and contact GKKBSJ for a refund. Consumers will be asked to throw away the product and send a photo of the disposed product to gkkbsjtoys@outlook.com to receive a full refund. If consumers wish to continue using the crib mobile, they can throw away only the remote and send a photo of the disposed remote to gkkbsjtoys@outlook.com to receive a refund of $8. The crib mobile is fully functional without the remote control via buttons on the unit. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25471');
INSERT INTO safety_incidents VALUES ('e995b5adf88f6dc6fe72c1482380e5f6d00280a9', 'CPSC', '2025-09-11', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Bariatric Fusion Iron Multivitamin Bottles', 'The Recalled Multivitamins Contain Iron, Which Must Be In Child-Resistant Packaging, As Required By The Poison Prevention Packaging Act. The Recalled Packaging Of The Iron-Containing Multivitamins Violates The Federal Standard For Child-Resistant Packaging Because The Bottle Caps Are Not Child-Resistant, Posing A Risk Of Deadly Poisoning, If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled bottles out of sight and reach of children, and contact Blueroot Health for information on how to obtain a free child-resistant replacement cap.', '25460');
INSERT INTO safety_incidents VALUES ('34a02f5fdcbf2f306103da013f95a568bb5dc91a', 'CPSC', '2025-09-11', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Paris Hilton Mini Beauty Fridges', 'Fire', 'Electrical Fault', 'Burns', 'The firm is aware of 27 reports of the mini fridge overheating and catching on fire. No injuries have been reported. Property damage has included damage to the unit and surrounding surfaces.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Paris Hilton Mini Beauty Fridge, unplug the unit, and register for the recall at www.epoca.com/minifridgerecall. To receive a refund, consumers will have to fill out the online form and submit three photographs; one should be the refrigerator''s door with the word "RECALL" written on it using a permanent marker, the second photograph should be of the label on the unit showing the model number and serial number and the last photograph should be of the cut, unplugged cord. Consumers should discard the recalled fridge according to local and state regulations.', '25459');
INSERT INTO safety_incidents VALUES ('9561ec173abd3d8f188cfb8fbf3e3facb69ee3eb', 'CPSC', '2025-09-11', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'In My Jammers Button Up Flare Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the recalled pajama sets immediately and contact In My Jammers for a full refund or store credit. Consumers should destroy the pajamas by cutting them in half, then take a photo of the destroyed pajamas and email it to recall@inmyjammers.com, then dispose of the pajamas.', '25462');
INSERT INTO safety_incidents VALUES ('d5a71028b90db92497371d08dd89fc110f25d74f', 'CPSC', '2025-09-11', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Children''s Wooden Cactus Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled toys and contact Yiwu Shiyi Trading for a full refund. Consumers will be asked to throw the product away and send a photo of the disposed product to yizhao2025@outlook.com.', '25461');
INSERT INTO safety_incidents VALUES ('c9e250971e227e74b040ec565f2e71041016a0ce', 'CPSC', '2025-09-04', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'Makita Professional Cordless Grease Guns and Makita Grease Gun Hoses', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received five reports of incidents worldwide of the grease gun hose failing, including five laceration injuries. All five incidents were reported outside the United States.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Makita Cordless Grease Guns and Makita Grease Gun Hoses and contact Makita for a free replacement hose.', '25455');
INSERT INTO safety_incidents VALUES ('cea84ebe9111edda1aee6a56937bdd00e6687a98', 'CPSC', '2025-09-04', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'AR-15 Chamber Lock Pro Firearm Locks', 'Fire', 'Mechanical Failure', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled AR-15 Chamber Lock Pro and secure their firearm using other means. Consumers should contact StopBox USA to receive a prepaid return shipping label and instructions to return their recalled AR-15 Chamber Lock Pro for their choice of a full refund or replacement AR-15 Chamber Lock Pro.', '25458');
INSERT INTO safety_incidents VALUES ('e0f54deba2e67f9cc663c05552178be97dd5596c', 'CPSC', '2025-09-04', 2025, '2025-09', 'USA', 'United States', '', 'Other', 'URMYWO Baby Loungers', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the baby loungers immediately and contact Pomona for a full refund. Consumers should remove the sleeping pad, cut up the sides of the baby loungers and the sleeping pad and email a photo of the destroyed lounger to urmyworecall@outlook.com to obtain a full refund.', '25456');
INSERT INTO safety_incidents VALUES ('0163e73f9d8720339113b7e7eb475a640f209b0d', 'CPSC', '2025-08-28', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Nimbus Lock Carabiners', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 21 reports of the closing mechanism breaking. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Nimbus Lock Carabiners and contact C.A.M.P. Consumers will be asked to fill out the recall form at www.camp-usa.com/nimbus-lock-safety-recall-registration-form, print a prepaid return shipping label and return the recalled product. C.A.M.P will inspect returned units and ship them back to consumers, if they pass inspection. Any units that do not pass inspection will be replaced free of charge.', '25444');
INSERT INTO safety_incidents VALUES ('702a1cd8ad604802df0bd4a1142ca914befc349f', 'CPSC', '2025-08-28', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'CT-ENERGY Lithium Coin Battery Chargers with Rechargeable 2032 Batteries', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the charger and remove the batteries and place them in an area that children cannot access. Contact CT New Energy Technology for a full refund, Child-Resistant Safety Case, or replacement kit. The complimentary repair kits and replacement kits will be available after August 30, 2025. Consumers will be asked to submit photos of the batteries'' destruction completely submerged in tap water to info@ct-energy.cn. Soaking the batteries in water for 24 hours discharges the battery. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25449');
INSERT INTO safety_incidents VALUES ('82440d5463868bb43bf30d59fc4f0bb6a3c2029d', 'CPSC', '2025-08-28', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'DT Swiss Carbon Fiber Road Wheels', 'A Defect In The Wheel Can Compromise The Wheel''S Structural Integrity, Posing A Crash Hazard.', 'Mechanical Failure', 'Skin Irritation', 'The firm has received six reports of the outermost carbon layer separating around the rim flange. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled wheels and contact DT Swiss to coordinate a replacement. Consumers should register the recalled wheels with DT Swiss at www.dtswiss.com/recall.', '25445');
INSERT INTO safety_incidents VALUES ('b09bff19325337350d868cf2f04653d4732b8040', 'CPSC', '2025-08-28', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Electric motors for gable- and roof-mounted attic fans', 'Fire', 'Electrical Fault', 'Burns', 'The firm has received 159 reports of incidents related to the recalled attic fan motors involving burning or fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled electric motors and contact Air Vent for a refund. Consumers will be asked to fill out the online registration and verification form with photos of the recalled attic fan motor. Upon confirmation that the consumer has a recalled attic fan motor, the consumer will receive a refund.', '25451');
INSERT INTO safety_incidents VALUES ('949f9ceae9a42ec47e455f6563ddb553594b9d24', 'CPSC', '2025-08-28', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Lulive 12-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Mandatory Standard Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately if they are not anchored to the wall and place them in an area that children cannot access. Consumers can contact Lulive for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo to lulive12recall@sina.com of the product demonstrating disposal.', '25447');
INSERT INTO safety_incidents VALUES ('6a48c06f09e335483bd4fecfdecda7065f7aa30d', 'CPSC', '2025-08-28', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Party Favors Lite-Up Torches and Mini Laser Pointers', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the Lite-Up Torches and Mini Laser Pointers, take them away from children and place them where children cannot access them. Consumers may contact MTC Trading to request a full refund. Consumers will need to email a photograph confirming disposal of the lite-up torches or mini laser pointers to mtcmans@gmail.com to receive the refund. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25450');
INSERT INTO safety_incidents VALUES ('3cb46ec46dc95d7a2a91d13d527f72d2627b513e', 'CPSC', '2025-08-28', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'RYOBI Electric Pressure Washers', 'Injury', 'Flammability / Overheating', 'Fracture / Blunt Trauma', 'TTI Outdoor Power Equipment has received 135 reports of capacitors overheating, including 41 reports of explosions, resulting in 32 injuries and/or fractures to the fingers, hands, face, and eyes.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled pressure washers and visit https://www.ryobitools.com/recall to determine if their pressure washer is included in the recall and to receive a free repair kit, including shipping and installation instructions. The repair kit consists of a replacement capacitor. Proof of purchase (receipt) is not required.', '25452');
INSERT INTO safety_incidents VALUES ('c8454732b628363de6e35cdf75744943f8fe6eaa', 'CPSC', '2025-08-21', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'CX Series Combi Boiler', 'Burns', 'Drowning Risk', 'Burns', 'The firm has received five reports of the hot water temperature fluctuating while in use. No injuries have been reported.', 'Minor', 1, 0, 'Contact IBC to schedule a free in-home repair by an authorized technician, who will install a mixing valve, if needed. Consumers can continue to use the recalled boilers for central heating.', '25441');
INSERT INTO safety_incidents VALUES ('9488d9b52430806825ae7458cacccbbd85f910aa', 'CPSC', '2025-08-14', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Children''s Spiral Tower Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately take the toy away from children and contact STWUQIKONG for a full refund. Consumers will be asked to throw the product away and send a photo of the disposed product to STWUQIKONG_RECALL@hotmail.com.', '25433');
INSERT INTO safety_incidents VALUES ('57e0df0879eae718b87fec9587ead31ec0023913', 'CPSC', '2025-08-14', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Drinkmate 1L Carbonation Bottles', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Drinkmate has received eight reports of the bottle exploding while in use, including four reports resulting in lacerations, impact injuries and hearing damage.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bottles and contact Drinkmate to receive a free replacement bottle. Consumers will be asked to fill out a replacement form at https://idrinkproducts.com/pages/drinkmate-safety-recall-of-1l-pet-bottles, upload a photo of the bottle permanently marked with the word "Recall" and properly dispose of it. Consumers will receive a code to order the free replacement bottle through Drinkmate''s website, shipping included.', '25435');
INSERT INTO safety_incidents VALUES ('bce421f76015999832f2bb38f81db29f650dbe91', 'CPSC', '2025-08-14', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Hair Dryers sold under the "Remington" brand, model number D3190DCDN', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately unplug and stop using the recalled hair dryers and contact Empower Brands to receive a full refund. Consumers must submit a photo of the hair dryer with its power cord cut in half to the recall registration portal at https://www.remingtonproducts.com/product-recalls and follow the disposal instructions provided on the website.', '25430');
INSERT INTO safety_incidents VALUES ('d29576d63a46f54bf4720328edc546c0be86a1e2', 'CPSC', '2025-08-14', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'ESR HaloLock Wireless Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received nine reports of the lithium-ion battery catching fire and exploding, resulting in property damage of about $20,000. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled power banks and contact Waymeet for a full refund. Consumers will be asked to send to support@esrtech.com their order number (not required) and a photo of the recalled power bank showing the model number with the word "Recalled" written on it in permanent marker. Consumers should dispose of the power banks in accordance with local and state hazardous waste disposal regulations. Note: Do not throw this recalled lithium-ion battery or device in the trash, the general recycling stream (e.g., street-level or curbside recycling bins), or used battery recycling boxes found at various retail and home improvement stores. Recalled lithium-ion batteries must be disposed of differently than other batteries, because they present a greater risk of fire. Your municipal household hazardous waste (HHW) collection center may accept this recalled lithium-ion battery or device for disposal. Before taking your battery or device to a HHW collection center, contact that office ahead of time and ask whether it accepts recalled lithium-ion batteries. If it does not, contact your municipality for further guidance.', '25437');
INSERT INTO safety_incidents VALUES ('c36d19b2518207318a35608347edcd30ae62cbfe', 'CPSC', '2025-08-14', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Firefly Safe & Green 32 oz. Fuel Bottles', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately remove the nozzle applicator from the recalled Safe & Green 32 oz. Fuel bottle and reinstall the child-resistant closure that was included with the product''s original packaging. If the child-resistant closure is not readily available, consumers should immediately secure the recalled Safe & Green 32 oz. fuel bottle out of the sight and reach of children. Consumers should contact Firefly Fuel for a free corrected label to put on the bottle and a free replacement child-resistant lid, if the original is missing.', '25434');
INSERT INTO safety_incidents VALUES ('2f716184d4498c30a3a336bd1e98cdb57550b4d4', 'CPSC', '2025-08-14', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Wolfgang Puck Stainless Steel Petite Tea Kettles', 'Burns', 'Instability / Fall Risk', 'Burns', 'Synergy Housewares has received at least 10 reports of incidents involving the kettle lids, including 5 resulting in injuries such as burns or scalding from the lid falling off the kettle during use.', 'Moderate', 1, 0, 'Consumers should stop using the tea kettle immediately and contact Synergy Housewares for a free new lid for the kettle.', '25432');
INSERT INTO safety_incidents VALUES ('80895ecd16ddd1f437e12b99e0436b5e4c429388', 'CPSC', '2025-08-14', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Electronic LED modules used on Floating Stairs and Rails', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 20 reports of modules overheating or melting. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should contact Viewrail to schedule an appointment for a technician to come to their residence and replace the module free of charge. Alternatively, consumers can request a refund for the module only in the form of a refund check. Consumers will receive the amount on the purchase receipt, or the sales price for the module, if no receipt is provided.', '25436');
INSERT INTO safety_incidents VALUES ('c30f81cda235772cd1640856963cec63566880e9', 'CPSC', '2025-08-14', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Werner 20'' and 24'' Multi-Max Pro Multi-Purpose Ladders', 'Falls', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 18 reports of falls, including 14 reports of injuries resulting in bruising, lacerations, head injuries and fractures to the wrist, leg and ribs.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ladders and contact Werner to receive a full refund. Consumers should register at http://www.wernerco.com/recalls to receive details on how to dispose of the recalled ladder. Once disposal is complete, Werner will issue a full refund in the form of a check.', '25431');
INSERT INTO safety_incidents VALUES ('5d2345fb1c96ca1ba938c605a068a730e348edf5', 'CPSC', '2025-08-07', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'LeymanKids Children''s Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled pajamas immediately and contact AliExpress to receive a full refund. Consumers should destroy the pajamas by cutting them in half, then take a photo and dispose of them. Consumers must send the photo of the destroyed pajamas to us_product_recall@aliexpress.com or by replying to the recall email sent by AliExpress.', '25425');
INSERT INTO safety_incidents VALUES ('c66f3bb7d21ca5e574c6a98c1381e23671649def', 'CPSC', '2025-08-07', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Altafit af28 Smartwatches', 'Fire', 'Flammability / Overheating', 'Burns', 'Deale International has received 39 reports of smartwatches melting, burning and catching on fire while charging, including six reports of burns to hands and property damage.', 'Minor', 1, 0, 'Consumers should immediately unplug the smartwatch''s charging pad and stop charging the recalled smartwatch. Consumers can contact Deale International for instructions on how to receive a free replacement. Consumers will be asked to cut the unplugged charging pad''s power cable and email a photo of the charging pad with the cut cable to altafitrecall@thedeale.com.', '25428');
INSERT INTO safety_incidents VALUES ('618ba2b6bd7a3407678326b1d2720436b324788c', 'CPSC', '2025-08-07', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Fieldsheer Heated Socks', 'Burns', 'Explosion', 'Burns', 'The firm has received 11 reports of socks causing pain and discomfort, resulting in 4 burns and blisters.', 'Moderate', 1, 0, 'Consumers should immediately stop using the heated socks and contact Fieldsheer Apparel Technologies for a full refund or replacement product of equal value. Consumers should dispose of the lithium-ion battery packs in accordance with applicable laws and regulations.', '25423');
INSERT INTO safety_incidents VALUES ('861c39caa41e6113d4671b4b4ff1c2e0b8306458', 'CPSC', '2025-08-07', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'La Ligne Enfant Bonne Nuit Pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled children''s pajamas away from children, stop using them and contact La Ligne for a full refund. Consumers will be asked to destroy the garments by cutting them in half and disposing them. Consumers should send a photo of the destroyed garment by email to lou@lalignenyc.com to receive a refund of $75 or store credit of $100.', '25427');
INSERT INTO safety_incidents VALUES ('b441cce2fab9e2f60ed1f3f282f38ce0e59effae', 'CPSC', '2025-08-07', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Monica Vinader 14k Yellow Gold Mini Heart Jewelry', 'The Jewelry Can Contain Excess Levels Of Cadmium, Which Can Be Toxic If Ingested By Young Children And May Cause Adverse Health Effects Through Long-Term Skin Exposure.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop wearing the recalled jewelry, store the jewelry safely out of reach of children, and contact Monica Vinader for a replacement or refund. Consumers can return the jewelry items via prepaid shipping label and receive a replacement or a full refund to their original payment method or, if unavailable, by secure wire transfer. To initiate a return and receive a replacement or refund, consumers may contact Monica Vinader or visit a Monica Vinader store. Nordstrom customers have the additional option to return the jewelry directly to Nordstrom.', '25424');
INSERT INTO safety_incidents VALUES ('628f01888f845fc920d336d62c7ca1c37386b4f8', 'CPSC', '2025-08-07', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Pet Zone Laser Pointer & LED Ball Pet Toys', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled pet toys and contact Petmate for a full refund. Note: Button cell and coin batteries are hazardous. If disposing of or recycling button cell or coin batteries, do so in a manner that follows local hazardous waste procedures.', '25421');
INSERT INTO safety_incidents VALUES ('3570144f64332c9c8822a68a81adeb3e3ba4e525', 'CPSC', '2025-08-07', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'Séfralls Minoxidil Hair Generation Serum', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled serum bottles out of sight and reach of children, and contact Guangzhou Ariel Biotech for instructions on destroying the recalled bottles and receiving a replacement. Consumers will be asked to pour the contents of the bottle into the trash and take a photo of the bottle in the trash and email it to sefralls@outlook.com.', '25426');
INSERT INTO safety_incidents VALUES ('e0ea50f219ddc623ad05bc87df6d95eb3e02849e', 'CPSC', '2025-08-07', 2025, '2025-08', 'USA', 'United States', '', 'Other', 'TEMI Go Basketball Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately take the toy away from children and contact TEMI Toys for a full refund. Consumers will be asked to throw the product away and send a photo of the disposed product to Temitoys@outlook.com.', '25422');
INSERT INTO safety_incidents VALUES ('f27aad8ad1e99d68c0f12afe905ecccfe69b8854', 'CPSC', '2025-07-31', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Amazon Basics Premium Foam Eurotop Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled mattress immediately and follow Amazon''s instructions for a full refund. Consumers will be asked to write "Recalled" on the mattress with a permanent marker, submit a photo of the marked mattress to http://amazoneurotoprecall.expertinquiry.com and certify disposal. Upon receipt of the photo and certification of disposal, consumers will be issued a full refund to a valid payment method in the consumer''s Amazon wallet or in the form of an Amazon gift card. The recalled mattresses should be disposed of in accordance with local laws. Amazon is contacting all known purchasers directly.', '25417');
INSERT INTO safety_incidents VALUES ('45a6b754b58d640545573c5a852e137ae8f067cb', 'CPSC', '2025-07-31', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Baby Loren Morning Dresses', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dresses immediately and contact Baby Loren for information on how to return the recalled dresses free of cost for a full refund. Baby Loren is contacting all known purchasers directly.', '25419');
INSERT INTO safety_incidents VALUES ('2ecfc54e7153451d42fb51813a86785f6b0657fc', 'CPSC', '2025-07-31', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'KidKraft Farm to Table Model Play Kitchen', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'In February 2023 in Oregon, a 23-month-old child was asphyxiated after his shirt got caught on one of the hooks while climbing and crawling through the opening at the back of the play kitchen where the toy kitchen accessories are held. The child was unable to rescue himself and died from strangulation and asphyxia.', 'Fatal', 1, 0, 'Consumers should immediately stop using the play kitchens, remove the original hooks, and contact Backyard Kids for free replacement hooks. Backyard Kids has agreed to a provide free replacement hooks to all consumers with affected units as a part of this recall.', '25415');
INSERT INTO safety_incidents VALUES ('2439a1f9aca5593d2f6a3729668081fc327960bf', 'CPSC', '2025-07-31', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Cosco 2-Step Kitchen Stepper', 'Injury', 'Mechanical Failure', 'Fall Injury', 'Cosco has received 34 reports of the safety bar detaching or breaking, including two incidents resulting in head injuries.', 'Moderate', 1, 0, 'Consumers should stop using the safety bar on the recalled kitchen stepper immediately and store the stepper away from children until repaired. Contact Dorel to receive a free repair kit, including shipping. The repair kit includes a sliding locking mechanism that attaches to the safety bar to prevent the safety bar from detaching or breaking during use. Consumers will also receive installation instructions and an additional warning label to place onto the product.', '25412');
INSERT INTO safety_incidents VALUES ('6a1d8af93c33c01c21cae6edec36f32d658ff50d', 'CPSC', '2025-07-31', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'IKEA 365+ VÄRDEFULL garlic presses', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'IKEA has received a total of 10 incident reports globally, including three reports of lacerations and finger splinters. No incidents or injuries have been reported in the U.S.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled garlic press and return it to any IKEA store for a full refund. If you are unable to return it to one of their stores, please contact IKEA for instructions on how to dispose of the recalled product to receive a full refund. Proof of purchase (receipt) is not required to receive a full refund.', '25420');
INSERT INTO safety_incidents VALUES ('c1225af4950aae08fc04f875c92677a18dbf665a', 'CPSC', '2025-07-31', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Leatherman Charge Plus and Charge Plus TTi Multi-Tools', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Charge Plus multi-tools and go to www.leatherman.com/pages/charge-recall to determine if their multi-tool falls within the scope of this recall. Consumers will not be asked for proof of purchase and will receive a pre-paid shipping label to return the recalled Leatherman Charge Plus and Charge Plus TTi multi-tools to the firm to be repaired free of charge.', '25414');
INSERT INTO safety_incidents VALUES ('0cb262ffcf2a5ecbcdc75870d915c0aa7efded05', 'CPSC', '2025-07-31', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Magnetic Floating Stackers toys', 'The Recalled Magnetic Floating Stackers Toys Violate The Mandatory Standard For Toy Magnets Because They Contain Magnets That Can Loosen And Detach From The Toy, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Blood Poisoning And Death.', 'Mechanical Failure', 'Poisoning / Ingestion', 'The firm has received 31 reports of magnets separating from the toy stacker. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should take the product away from children immediately and contact Tegu for instructions on receiving a free replacement stacker toy.', '25413');
INSERT INTO safety_incidents VALUES ('663ee4106ec1536fe007435b7ef1180d6c7f33d7', 'CPSC', '2025-07-31', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'RIDGID 18Volt Brushless 21-Degree Framing Nailers and RIDGID 18Volt Brushless 30-Degree Framing Nailers', 'Injury', 'Mechanical Failure', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled nailers and visit powertools.ridgid.com/recall to determine if their nailer is included in the recall and for instructions on how to obtain a free repair. TTI Consumer Power Tools will send a prepaid label to the consumer to return the recalled nailer, the software in the nailer will be updated, and then the nailer will be shipped back to the consumer.', '25416');
INSERT INTO safety_incidents VALUES ('83f65ccdf234212be4e9c867252451cce43e537f', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Aiho Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Fail To Meet The Mandatory Standard, As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to a wall and place them in an area where children cannot access them. Contact Aiho for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo of the disposed dresser to support@aiholife.com.', '25400');
INSERT INTO safety_incidents VALUES ('11975a1acfddecf4a65293ed88cb7b6ca1234c18', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Apollo City Model Year 2024 Electric Scooters', 'Injury', 'Instability / Fall Risk', 'Laceration / Cut', 'The firm has received 10 reports of the weld cracking on the stem of the scooter, including four riders who reported coming off the scooter; one reported injury including abrasions.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled scooters and contact Apollo for a free replacement stem. To participate in the recall, please go to https://apolloscooters.co/pages/apollo-city/recall and fill out the online form. Apollo is recommending that all consumers take their scooters to a service repair location so they can replace the stem on the recalled scooter free of charge. Consumers can go to https://apolloscooters.co/pages/locations-near-you to find the closest service repair location.', '25402');
INSERT INTO safety_incidents VALUES ('e3c20d946dae331a841415bbf5d9f6e2c1f09651', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', '100% Natural Pure Gum Spirits of Turpentine Bottles', 'The Recalled Bottles Contain Turpentine, Which Must Be In Child-Resistant Packaging, As Required By The Poison Prevention Packaging Act. The Turpentine Bottles Violate The Mandatory Standard For Child-Resistant Packaging, Posing A Deadly Poisoning Hazard To Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled turpentine bottles out of the sight and reach of children. Consumers should contact Creekwood Naturals for a free replacement child-resistant closure. Consumers must complete a form online at https://creekwoodnaturals.com/pages/recall to receive the replacement.', '25399');
INSERT INTO safety_incidents VALUES ('1fdac6c5179e236e98d5a761b9f16f5d2b9e3d0e', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Frigidaire-brand Minifridges, models EFMIS129, EFMIS137, EFMIS149 and EFMIS175, limited to the listed serial numbers', 'Fire', 'Electrical Fault', 'Respiratory', 'Curtis International has received at least 26 reports of the minifridges smoking, sparking, burning, melting, overheating and catching fire, with property damages totaling more than $700,000. Two consumers reported smoke inhalation injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled minifridges and follow the instructions to receive a refund at www.recallrtr.com/minifridge. Consumers should unplug and cut the power cord and write "Recall" using a permanent marker on the front door of the unit. Consumers should dispose of the recalled minifridges in accordance with local and state regulations.', '25395');
INSERT INTO safety_incidents VALUES ('02d23c7c6f5c1a46be63c2626839ac0cb2703210', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Georgia Pine Gum Spirits of Turpentine Bottles', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled turpentine bottles out of the sight and reach of children and contact Diamond G Forest Products for information on how to obtain a free replacement child-resistant closure.', '25397');
INSERT INTO safety_incidents VALUES ('4830309ca78fc227abd3d22e40c62faafefb7df7', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'FENGQS F7 Pro E-bikes', 'Fire', 'Flammability / Overheating', 'Burns', 'FENGQS has received 13 reports of e-bikes igniting, two resulting in fires with property damage totaling $4,000.', 'Moderate', 1, 0, 'Consumers should stop using the recalled e-bikes immediately and contact FENGQS for a full refund. Consumers will be asked to write their name, the word "recalled," and the current date next to the battery''s production date, with a permanent marker. Consumers must then submit a photo clearly showing this information and confirm disposal of the battery in accordance with applicable laws and regulations. Consumers should submit the photo to recall@fengqs.work. Note: Do not throw this recalled lithium-ion battery or device in the trash, the general recycling stream (e.g., street-level or curbside recycling bins), or used battery recycling boxes found at various retail and home improvement stores. Recalled lithium-ion batteries must be disposed of differently than other batteries, because they present a greater risk of fire. Your municipal household hazardous waste (HHW) collection center may accept this recalled lithium-ion battery or device for disposal. Before taking your battery or device to a HHW collection center, contact that office ahead of time and ask whether it accepts recalled lithium-ion batteries. If it does not, contact your municipality for further guidance.', '25403');
INSERT INTO safety_incidents VALUES ('eb59917e646ce55044a46ac7ff664b7967e0a1dd', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Rechargeable Electric Bug Zapper Racket, Fly Swatter, and Mosquito Swatter for Indoor and Outdoor use', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received three reports of the swatter catching on fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Electric Bug Zapper Racket, Fly Swatter or Mosquito Swatter and contact iMirror for a full refund. iMirror will provide pre-paid shipping labels for the return of the product. Once the product is received, the refund will be processed immediately to the customer''s original payment method. Customers will be notified directly through the Amazon platform and/or receive an email about the refund process and how to return the product.', '25396');
INSERT INTO safety_incidents VALUES ('d966538da68f0632da58bcb1cf7d3862d088ccd1', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Minecraft Light-Up Slap Ruler Bracelets', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'Innovative Designs has received one report of a battery separating from the toy. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Minecraft Light-Up Ruler Bracelets and take them away from children. Contact Innovative Designs for information on disposal and for a full refund. Consumers will need to email a photograph of disposal to info@innovativenyc.com to receive the refund. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25404');
INSERT INTO safety_incidents VALUES ('bc45d671e9513ad97414f40684ef6a31995316dd', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'LED Gloves', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled LED gloves, take them away from children and dispose of them. Contact Minongad for a full refund. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25398');
INSERT INTO safety_incidents VALUES ('1506f7390ee735547b0f2184c4b6e2c25fb6b7a6', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'LIVACTI Retractable Safety Gates', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled gates immediately and contact Qeyan and Yanyanny for instructions on how to receive a full refund. Consumers must destroy the gate by cutting through the mesh and take a photo showing the destroyed gate. Submit the photo to support@livactihome.com.', '25401');
INSERT INTO safety_incidents VALUES ('798fbf0b8a938f69d74e98cada3d67e9e901a394', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Pura 4 Smart Home Fragrance Diffusers with detachable covers', 'The Magnets On The Inside Cover Can Detach, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Mechanical Failure', 'Poisoning / Ingestion', 'The firm has received three reports of the magnets detaching from the cover. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately dispose of the existing detachable cover while waiting for the replacement cover, keep the diffusers out of the reach of children and pets, and contact Pura Scents to receive a free replacement front cover. Pura Scents is contacting all known purchasers directly.', '25408');
INSERT INTO safety_incidents VALUES ('ebca410a38b2b881599d8958ff415b8524e3f6a3', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Transpro Electric Scooters', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'Transpro US Inc. has received one report of a scooter catching fire, causing at least $200,000 in property damage. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using and charging the recalled scooters and contact Transpro to receive a full refund or a free replacement scooter. Visit https://transprous.com/recall-escooters for instructions to disable the scooter. Consumers will need to submit their information through an online claim form or by email and will need to submit evidence of product destruction with their claim. Consumers should dispose of the entire scooter following local and state hazardous waste disposal procedures. Transpro is contacting all known purchasers directly.', '25405');
INSERT INTO safety_incidents VALUES ('bd07ffe83e671d93976684df69aa2e8b12329447', 'CPSC', '2025-07-24', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'HydroTech 5/8-inch Expandable Burst-Proof Hoses', 'The Recalled Hoses Can Burst, Posing An Impact Hazard And A Risk Of Temporarily Impaired Hearing.', 'Explosion', 'Fracture / Blunt Trauma', 'The firm has received at least 222 reports of the hoses bursting, resulting in at least 29 injuries, including one bone bruise, two sprains and five reports of temporarily impaired hearing from the sound of the hose bursting.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled hoses. Consumers that purchased products from Ace Hardware, Do It Best, Home Depot or Walmart should bring their hoses to those stores to return them for a full refund. Consumers who purchased products from other retailers should cut off the regulator-end of their hose and contact Winston Products for a full refund. To receive the refund, consumers should submit photos of the cut hose, showing the date code location with the consumer''s initials and the date written in permanent marker on the regulator, to Winston Product''s online form at https://hydrotechproducts.com/recall.', '25394');
INSERT INTO safety_incidents VALUES ('2ab5adebc92be989ddf5f616aa2156d40ecde2b7', 'CPSC', '2025-07-21', 2025, '2025-07', 'USA', 'United States', '', 'Other', '48-inch and taller above-ground pools with compression straps running on the outside and over the vertical support legs', 'Drowning', 'Drowning Risk', 'Drowning', 'CPSC believes that nine children between the ages of 22 months and 3 years old have drowned, after gaining access to the pools via the footholds. The incidents occurred in California, Texas, Florida, Michigan, Wisconsin and Missouri between 2007 and 2022. CPSC is also aware of three other incidents in 2011 and 2012 where children who gained access to the recalled pools were reported to have previously used the compression strap to gain entry to the pool.', 'Moderate', 1, 0, 'Consumers should contact Bestway, Intex or Polygroup to request a repair kit. In the interim consumers should ensure that children cannot access the pool unattended or, alternatively, drain the pool until the repair can be installed.', '25393');
INSERT INTO safety_incidents VALUES ('0004f2e0295109e5e605e340596b20b91a96c656', 'CPSC', '2025-07-17', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Babyletto Kiwi Electronic Recliner and Swivel Gliders with USB port', 'The Usb Module In The Recliner Arm Can Overheat And Spark, Posing An Overheating Hazard.', 'Flammability / Overheating', 'Not Specified', 'The firm has received 37 reports of incidents of overheating, smoking or sparking including one minor injury. No fires or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled recliners and contact Babyletto to receive a free repair kit. Consumers should register at babylettorecall.com/ to receive their free repair kit and installation instructions. Once consumers have completed the repair, consumers should dispose of the original USB module in their household trash.', '25392');
INSERT INTO safety_incidents VALUES ('09564ceac3204c65783000a861cea2c477126a30', 'CPSC', '2025-07-17', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'CasaClean Handheld Steamers', 'Burns', 'Drowning Risk', 'Burns', 'Deale has received 26 reports of the recalled steamers leaking water or steam, including 13 consumers receiving burns.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled handheld steamers and contact Deale for instructions on how to safely cut the cord near the base of the machine, to provide proof of destruction, and to receive a refund. Consumers must take a photo of the cord that is cut near the base of the machine and upload the photo, along with their contact information, to the Recall Request form at www.thedeale.com/pages/casaclean-safety-recall to receive the refund.', '25389');
INSERT INTO safety_incidents VALUES ('6492e9cd872cb2d4415d18f8971665229a1bc53e', 'CPSC', '2025-07-17', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'iStore Magnetic Wireless Power Banks (IST-09991/W05 model only)', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received three reports of the wireless power banks overheating and exploding while they were charging, including one incident that resulted in a minor burn to the victim''s arm. The firm received reports of property damage of about $15,000.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled wireless portable power bank and go to the firm''s website to participate in the recall. Consumers will be asked to submit two photographs via email to recall@istore.co. The first photograph should be the front of the power bank with the word "Recalled" and the date written on it with permanent marker. The second photograph should include the model number, which is located on the back of the power bank. A purchase receipt will be requested but will not be required to participate in the recall. Consumers should immediately dispose of the power banks in accordance with local and state hazardous waste disposal regulations.', '25390');
INSERT INTO safety_incidents VALUES ('daf855499ca10b0275543a9d203f399346ede3a4', 'CPSC', '2025-07-17', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Primark DTR (direct-to-retail) Stitch Scented Highlighters (4-pack)', 'The Scented Highlighters, Which Resemble Cups With Straws, Contain Phthalates; A Violation Of The Federal Phthalates Ban. Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled scented highlighters and return them to a Primark store for a full refund in the form of the original payment.', '25388');
INSERT INTO safety_incidents VALUES ('6a15a22ebd3e22a90eda4cc4b7d88942706aa3bc', 'CPSC', '2025-07-17', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Traveller Aluminum Loading Ramps', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 35 reports of ramps bending or breaking, including two reports of ramps breaking and causing knee and other injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ramps. Consumers will be asked to return the ramps to any Tractor Supply store or call the firm for instructions on how to send a photo of the product with the word "Recalled" using permanent paint to customersolutions@tractorsupply.com for a full refund.', '25387');
INSERT INTO safety_incidents VALUES ('9329a633484baec12ca689c34a15f1f86ca6a8a0', 'CPSC', '2025-07-17', 2025, '2025-07', 'USA', 'United States', '', 'Other', '36-volt lithium-ion batteries used with VIVI E-bikes', 'Fire', 'Flammability / Overheating', 'Burns', 'VIVI is aware of 14 reports of incidents of batteries overheating, including three reports of fires. No injuries reported.', 'Minor', 1, 0, 'Consumers should immediately stop using e-bikes with the recalled lithium-ion batteries and contact VIVI to receive a free replacement battery and battery charger. Consumers must dispose of the recalled battery at a household hazardous waste (HHW) collection center or follow the instructions of their municipality and confirm that this was done by sending an email to vivirecall@163.com. Note: Do not throw the recalled lithium-ion battery in the trash, in the general recycling stream (e.g., street-level or curbside recycling bins), or in used battery recycling boxes found at various retail and home improvement stores. Recalled lithium-ion batteries must be disposed of differently than other batteries, because they present a greater risk of fire. Your municipal HHW collection center may accept this recalled lithium-ion battery or device for disposal. Before taking your battery or device to an HHW collection center, contact it ahead of time and ask whether it accepts recalled lithium-ion batteries. If it doesn''t, contact your municipality for further guidance.', '25391');
INSERT INTO safety_incidents VALUES ('f374cc63a7c68c647cfd52f1d0a73613cb573fc5', 'CPSC', '2025-07-10', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'AUGNORYE Padded Cushioned Crib Bumpers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled padded cushioned crib bumpers and contact YIXIA for a full refund. Consumers should remove the crib bumpers, cut the straps and padding and email a photo of the destroyed bumpers to Yixiakejirecall@163.com to obtain a full refund. YIXIA and Amazon are contacting all known purchasers directly.', '25384');
INSERT INTO safety_incidents VALUES ('cea528c6bbc37d6f28bc72a9df28eb91283b6026', 'CPSC', '2025-07-10', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Braided crib bumpers', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the crib bumpers, remove them from the crib immediately and contact Haoyunm for a refund. Consumers should cut the bumper in half, take a photo of it, and email the photo to hyzhongtshung@outlook.com.', '25383');
INSERT INTO safety_incidents VALUES ('6e18a266d5cada79ef2e2e7bc0997bad7f5a5465', 'CPSC', '2025-07-10', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Creekliybear "Pack and Play" Aftermarket Play Yard Mattresses', 'The Aftermarket Play Yard Mattresses Violate The Mandatory Standard For Crib Mattresses As The Mattresses Exceed Thickness Requirements And May Not Adequately Fit Certain Play Yards, Posing A Deadly Entrapment Hazard.  Babies Can Suffocate In Gaps Between An Undersized Mattress, Or Extra Padding, And Side Walls Of A Product, Especially When The Infant''S Face Becomes Trapped Against The Side And The Mattress, Preventing The Infant From Breathing.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the mattresses and contact Kbabyea for a full refund. Consumers should cut the mattresses in half and send a photo of the cut-mattress in the waste bin to Kbabyearecall@outlook.com to receive a full refund.', '25379');
INSERT INTO safety_incidents VALUES ('7ef36bfd3c71994cb9f0ec0a76fb289f806ac5ff', 'CPSC', '2025-07-10', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Dearlomum Retractable Safety Gates', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled gates immediately and contact Signbaby for instructions to receive a full refund. Consumers will be asked to disassemble the gates and destroy them by cutting the mesh and to send a photo of the destroyed gates to regcards.team@gmail.com. Once the photo is received, Signbaby will issue a full refund. Signbaby and Amazon are contacting all known purchasers directly.', '25385');
INSERT INTO safety_incidents VALUES ('8bc0679e717b8f83b78d1a4f5e1ddcc1f4898f8b', 'CPSC', '2025-07-10', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Momentum Vida E+ E-Bikes', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received four reports of broken fork steerer tubes. No injuries have been reported.', 'Minor', 1, 0, 'To determine whether a Momentum Vida E+ bicycle is included in this recall, consumers should look at the third character of the bike''s serial number. Bikes with a serial number in which the third character is "H", "J" or "K" are included in this recall and must have their forks replaced free of charge. Bikes with a serial number in which the third character is "G" require additional visual inspection by an authorized Giant Bicycle dealer to determine fork status.', '25381');
INSERT INTO safety_incidents VALUES ('4bfeee1d4a911c4ca28112a3f171595cc49f1f0c', 'CPSC', '2025-07-10', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'SPPTTY Kids 14- and 18-inch Bicycles', 'Multiple Components Of The Children''S Bicycles Contain Levels Of Lead That Exceed The Federal Lead Content Ban, Posing A Lead Poisoning Hazard To Children. In Addition, The Black Paint On The Bicycle Pumps Contains Lead That Exceeds The Federal Lead Paint Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled children''s bicycles immediately and contact Shenzhen Yihuachuang Technology for a full refund. To receive a refund, consumers should dismantle the bicycles, take a photo, and send the photo by email to lishkjie@163.com. After submitting proof of destruction, consumers should dispose of the recalled bike.', '25382');
INSERT INTO safety_incidents VALUES ('74d22851ab8dec91741023da02f66d5eeb85f836', 'CPSC', '2025-07-10', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Ozark Trail 64 oz Stainless Steel Insulated Water Bottles', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Walmart has received three reports of consumers who were injured when struck in the face by a lid forcefully ejected from these bottles upon opening. Two consumers suffered permanent vision loss after being struck in the eye.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled water bottles and contact Walmart for a full refund. Consumers can bring the bottle to their nearest Walmart store for a refund.', '25377');
INSERT INTO safety_incidents VALUES ('8fd9705353bca1aa3cefa534ec38c51ef3bc4e65', 'CPSC', '2025-07-10', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'WLIVE Fabric 15-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Federal Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to a wall and place them in an area that children cannot access. Contact WLIVE for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo of the disposed dresser to wliveproductrecall@wlivehome.com. WLIVE and Amazon are contacting all known purchasers directly.', '25380');
INSERT INTO safety_incidents VALUES ('b436d6639144fa59c3f69ac5865b9bc62fc0961a', 'CPSC', '2025-07-03', 2025, '2025-07', 'USA', 'United States', '', 'Other', '509 helmets and 509 for Polaris helmets', 'Injury', 'Mechanical Failure', 'Skin Irritation', 'The firm received one incident where the rider''s helmet became detached during a crash, resulting in a concussion.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets. Consumers with a recalled "509" branded Tactical 3.0 or Tactical 2.0 (small/medium manufactured in 2023) helmet should contact 509 for instructions on how to participate in the recall and to receive a choice of a refund (if purchased online), or a credit to be used on 509''s website or a replacement helmet. Consumers with a recalled "509 for Polaris" branded Tactical 3.0 or Tactical 2.0 (small/medium manufactured in 2023) helmet should contact Polaris for a choice of a refund, a credit to use at a Polaris dealership or on the Polaris website, or a replacement helmet. Proof of purchase is not required. All helmets should be discarded in the local household trash after consumers have confirmed their helmet is being recalled by 509 or Polaris and follow the destruction instructions located on the website. Polaris is also providing their customers who have the recalled 509 and 509 for Polaris helmets with Fidlock®, with instructions on how to inspect the webbing on the chin strap to make sure it is repaired, by routing it correctly. 509 and Polaris are contacting all known purchasers directly.', '25374');
INSERT INTO safety_incidents VALUES ('4c49a986fbef457cadba3d9755b1e53d0d8dc9fa', 'CPSC', '2025-07-03', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'DEWALT® Grinder Flap Discs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received three reports of the flap disc coming apart while in use on the grinder, including three injuries resulting in cuts and scrapes.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled flap discs and go to the DEWALT website at https://www.dewalt.com/support/safety-notices-and-recalls/flap-disc-recall to participate in the recall. Consumers will be asked to write "Recall" on the disc and upload a photograph to the firm''s website. Consumers will then be asked to certify that they disposed of it in the trash to receive a refund.', '25367');
INSERT INTO safety_incidents VALUES ('5ca86020ce007cd70c6953fa8f97c2d305f0e84b', 'CPSC', '2025-07-03', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Predator 2000W Power Stations', 'The Wires In The Power Station''S Ac Outlet Receptacles Are Reversed When The Product Is In Emergency Power Supply ("Eps") Mode, Posing A Shock Hazard To Consumers Operating The Power Station.', 'Other', 'Electric Shock', 'The firm has received one report of the wires being reversed in EPS mode. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled power stations and return them to their local Harbor Freight Tools store for a free replacement unit that will be available at the store. Harbor Freight Tools is contacting all known purchasers directly.', '25366');
INSERT INTO safety_incidents VALUES ('6ef06e420a21c1084296c91bbe5681e0446376f3', 'CPSC', '2025-07-03', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Jeriflyer 8-inch pool drain covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Standards Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners/operators and consumers should immediately stop using pools with the recalled pool drain covers. To receive a refund, consumers should remove the drain cover from the pool, take a photo of the removed cover, and send it to the recalling firm by email at Junjuanshop2025@outlook.com. Ensure all pools and spas have VGBA compliant drain covers and teach children to stay away from drains. Junjuanshop and Amazon are contacting all known purchasers directly.', '25368');
INSERT INTO safety_incidents VALUES ('18e6f83dd2f39022380e91e712107976caf93cd5', 'CPSC', '2025-07-03', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Hyper Tough, Worx and Portland Chainsaws and Pole Saws', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled products and contact Positec for a pre-paid shipping label, and a new box as needed, to return the units free of charge. Positec will provide a free replacement chainsaw or pole saw upon receipt of the recalled product.', '25371');
INSERT INTO safety_incidents VALUES ('83bebe64f8d5fcb6992d88e5fa0aabf10645644c', 'CPSC', '2025-07-03', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'SNLN Party Supply Toys', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled party supply toys and take them away from children. Contact Yiwu Dixikeji Douxiangongsi for a full refund. To receive a refund, consumers should send a photo of the recalled toys being disposed of in the trash by email at dixikeji@gmail.com. Yiwu Dixikeji Douxiangongsi and Amazon are contacting all known purchasers directly. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25372');
INSERT INTO safety_incidents VALUES ('7d192d698a24733e4a5cff285289094617e0a1c9', 'CPSC', '2025-07-03', 2025, '2025-07', 'USA', 'United States', '', 'Other', 'Trane and American Standard Gas/Electric Packaged Units', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of gas leaking from the recalled two-stage gas furnace/air conditioners. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the heating mode of the recalled units and contact their dealer who installed the unit to schedule an appointment for a free inspection and repair, by replacing the ignition board of the unit. Consumers with Trane products can locate their nearest dealer at www.trane.com/residential/en/dealer-locator/. Consumers with American Standard products can locate their nearest dealer at www.americanstandardair.com/find-your-dealer/. Consumers can also contact Trane or American Standard directly for support.', '25369');
INSERT INTO safety_incidents VALUES ('b26de1ee0d3bcb99b1427bdcbf10ef3ba2bd7bd4', 'CPSC', '2025-06-26', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Bell Sports Bicycle Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the recalled helmets immediately and contact Bell Sports for a full refund. Consumers should destroy the recalled helmet by cutting the straps off the helmet. Consumers can upload photos of the helmet with the straps cut off to consumersupport-bell@bellhelmets.com to obtain a refund. Bell Sports is contacting all known purchasers directly.', '25359');
INSERT INTO safety_incidents VALUES ('6e6af037887bdfbefb00d2baa34232b1cd7c920f', 'CPSC', '2025-06-26', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Boyro Baby Walkers', 'Injury', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using and disassemble the recalled baby walkers immediately and contact Boyro Baby for instructions on receiving a full refund. Consumers will be asked to destroy the disassembled baby walker and email three photos of the destroyed product to boyrobaby@outlook.com. Once the three photos have been received, Boyro Baby will issue a refund. Boyro Baby and Amazon are contacting all known purchasers directly.', '25361');
INSERT INTO safety_incidents VALUES ('e727714c06e10935bc1328b1d88a91ce364d8179', 'CPSC', '2025-06-26', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'DR Power LiPRO rechargeable lithium-ion battery packs (5.0 Ah)', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received two reports of incidents of fire and/or overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled battery packs and contact DR Power for a pro-rated refund, based on the battery''s age. Consumers will need to show proof of the battery pack''s destruction by uploading two photographs in accordance with the destruction instructions (provided on the firm''s recall website), and filling out the recall form online at https://www.drpower.com/5AHB-recall. If consumers choose to dispose of the recalled battery pack''s lithium-ion battery, it should be done in accordance with local and state regulations.', '25355');
INSERT INTO safety_incidents VALUES ('6265e3406310190193eea85685e7190b0cb1c82b', 'CPSC', '2025-06-26', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'California Gold Nutrition Iron Supplements: Daily Prenatal Multi, Ultamins Women''s Multivitamin, and Ultamins Women''s 50+ Multivitamin', 'The Recalled Dietary Supplements Contain Iron, Which Must Be In Child-Resistant Packaging, As Required By The Poison Prevention Packaging Act. The Iron-Containing Dietary Supplement Packages Violate The Federal Standard For Child-Resistant Packaging Because The Bottles And Blister Packs Are Not Child-Resistant, Posing A Risk Of Deadly Poisoning, If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled supplement bottles out of sight and reach of children and contact iHerb for a refund and information on how to safely discard the packaging and product. To receive a refund, consumers should email ProductRecall@iherb.com with the subject line: "Iron Supplement Refund" and provide the following information: Name; Product(s) name & quantity ordered; Evidence of destruction: initial and date each product package and include a photo with your initials and the date visible; Optional: Provide the order number associated with the purchase(s), which can be found by logging into consumer''s account and viewing the "Order History". iHerb is contacting all known purchasers directly.', '25354');
INSERT INTO safety_incidents VALUES ('507469be85f2c4be53d850b13ee63cf5560cf41a', 'CPSC', '2025-06-26', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'LED Fireplace Lanterns', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using and remove the battery from the lanterns'' remote control and place it in an area that children cannot access. Consumers can contact Green Pastures Wholesale for information on how to receive a free UPS shipping label to return the product and to receive a full refund. Green Pastures Wholesale is contacting all known purchasers directly. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local procedures for hazardous household waste, not in the trash.', '25360');
INSERT INTO safety_incidents VALUES ('66cc6d00e1617bde24be00a7df9da5058e6b5876', 'CPSC', '2025-06-26', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Peg Perego Tatamia 3-in-1 Recliner, Swings and High Chairs', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled products and contact Peg Perego for a full refund. Consumers should contact Peg Perego for a prepaid shipping label and packaging to send the products back to Peg Perego. Peg Perego and Amazon are contacting all known purchasers directly.', '25706');
INSERT INTO safety_incidents VALUES ('e7441e035ea0eafd8cef1a1f4a04f3111e443f09', 'CPSC', '2025-06-26', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Swivel Port equine bits from Bob Avila collection', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The company has received five reports of bits breaking.No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bits and contact Professional''s Choice Sports Medicine Products to receive a full refund or free replacement. Upon receipt of the product, Professional''s Choice will send a refund payment by check or ship a replacement product, whichever the consumer prefers. Professional''s Choice will provide a pre-paid shipping label to consumers. Consumers can also contact the retailer from which the product was originally purchased for a refund.', '25358');
INSERT INTO safety_incidents VALUES ('1da83731d3c218f433ed35c203134222474cdaed', 'CPSC', '2025-06-26', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Vevor Single Post Handrails', 'Injury', 'Other', 'Not Specified', 'Vevor has received five reports of the handrails breaking, resulting in injuries, including one head injury.', 'Moderate', 1, 0, 'Consumers should stop using the recalled handrails immediately and contact Vevor for a full refund. Vevor will provide pre-paid shipping labels for the consumers to return the handrails. Alternatively, consumers can provide photographic evidence of disposal or destruction of the product to recalling@vevor.com. Vevor is contacting all known purchasers directly.', '25362');
INSERT INTO safety_incidents VALUES ('fddf75a3f1617c58ec8e88dca94713fe5d6d7769', 'CPSC', '2025-06-26', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Converta camping cots and Converta camping suspension stretchers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received seven reports of the seatback adjustment mechanism pinching consumers'' fingers, including two reports of fractured fingers.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled camping cots and suspension stretchers and contact The Coleman Company for a free repair kit, including installation instructions.', '25353');
INSERT INTO safety_incidents VALUES ('5237f3178dc751ae13d24a80a904347f959d6796', 'CPSC', '2025-06-26', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Shoulder Relief Saddle Cinches', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 19 reports of the cinch coming apart and the saddle falling off, including one report of a rider fracturing their ribs.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Shoulder Relief Cinch and contact Total Saddle Fit for a free replacement, and instructions on how to return the original cinch (pre-paid shipping label will be provided). Total Saddle Fit is contacting all known purchasers.', '25357');
INSERT INTO safety_incidents VALUES ('c2087b3113cdb233931827f8ad474f77118bb480', 'CPSC', '2025-06-18', 2025, '2025-06', 'USA', 'United States', '', 'Other', '4 Liter/6 Can Minifridges', 'Fire', 'Electrical Fault', 'Burns', 'CPSC has received at least 70 reports of the minifridges smoking, burning, melting or catching fire. Two fires resulted in extensive property damages, together totaling more than $360,000 in reported damages.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled minifridges and contact AstroAI for a free replacement minifridge. To receive a replacement minifridge, consumers should send a photo of the recalled minifridge, showing the model number and serial number, with "Recalled" written on the minifridge in permanent marker to AstroAI by email at recall@astroai.com or through the online portal at https://www.astroai.com/product-recall. Consumers should dispose of the recalled minifridges in accordance with state and local waste disposal procedures.', '25342');
INSERT INTO safety_incidents VALUES ('eff2487ed638309ae652c5eea98016ec4c465c65', 'CPSC', '2025-06-18', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Crayan Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled mattresses immediately and contact Crayan to receive a full refund. Consumers will be instructed to mark the mattress permanently with the word "Recalled" in large font across the white top panel and submit a photo of the marked mattress to crayan_service@hotmail.com to certify disposal prior to receiving a full refund. The firm is contacting all known purchasers directly.', '25344');
INSERT INTO safety_incidents VALUES ('9c6e22cfe596fc9739dab9db1e317c1a2a04afd8', 'CPSC', '2025-06-18', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'MaxKare Electric Blankets', 'Fire', 'Flammability / Overheating', 'Burns', 'Yumo has received 34 reports of overheating, including three reports of burn injuries and two reports that the blankets caught on fire.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled blankets and contact Yumo for instructions on how to properly dispose of the blankets. Consumers will be asked to upload a photo of the blanket to yumoofficial@126.com and confirm disposal in order to get a full refund.', '25351');
INSERT INTO safety_incidents VALUES ('6182e2db0f13e1b06be68dc4feb0bfba9c85fd90', 'CPSC', '2025-06-18', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Model Year 2023-2024 Ranger XP Kinetic and Model Year 2025 Pro XD Kinetic ROVs', 'Fire', 'Electrical Fault', 'Not Specified', 'The firm has received 47 reports of filter failures with the recalled ROVs, including six reports of melting/fire and four reports of sparking/smoke. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should contact an authorized Polaris dealer to schedule a free repair at the dealer''s location. Polaris is contacting all registered owners directly and providing instructions on how to continue operating their vehicles until the repair can be completed. The instructions are available at https://www.polaris.com/en-us/recalls/off-road/polaris-recalls-some-model-year-2023-2024-ranger-xp-kinetic-and-model-year-2025-pro-xd-kinetic-vehicles', '25343');
INSERT INTO safety_incidents VALUES ('44d2f1fc92e163a611155686886b44adc9fd272d', 'CPSC', '2025-06-18', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'TADAKAZU Baby Loungers', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby loungers and contact TADAKAZU for a full refund. Consumers should remove the sleeping pad, cut up the sides of the baby loungers and the sleeping pad, and email a photo of the destroyed lounger to tadakazurecall@yeah.net to obtain a full refund. TADAKAZU and Amazon are contacting all known purchasers directly.', '25345');
INSERT INTO safety_incidents VALUES ('361ba84307e7cc43de24e037085e2dfed6309e45', 'CPSC', '2025-06-18', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'YaFiti 12-Drawer White Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Federal Standard As Required By The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not properly anchored to a wall and place them in an area that children cannot access. Contact YaFiti for instructions on how to dispose of the dressers to receive a full refund. Consumers must submit a photo of the disposed dresser to Yafitiservice@outlook.com. YaFiti and Amazon are contacting all known purchasers directly.', '25341');
INSERT INTO safety_incidents VALUES ('40c17d435574849a86c7f8c587f0abeb6fc67c78', 'CPSC', '2025-06-12', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Oliver & Smith 6-inch Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled mattresses immediately and contact Agro Superior Group to receive a free fitted cover to put over their mattress, which will bring it into compliance with federal standards for mattress flammability. The firm is contacting all known purchasers directly.', '25337');
INSERT INTO safety_incidents VALUES ('dec4b38b7b786d0c0da1f4163c0c663f685f817f', 'CPSC', '2025-06-12', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Giraffe highchairs', 'Injury', 'Mechanical Failure', 'Fall Injury', 'The firm has received 22 reports of the legs of the chair detaching, including 13 reports of minor injuries.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled highchairs and contact Bugaboo to receive a free repair kit including an Allen key and new screws to install into the product''s legs. Bugaboo is contacting all known purchasers directly.', '25336');
INSERT INTO safety_incidents VALUES ('22cb0ce68c24d422238aa8be52fab57bf96e6230', 'CPSC', '2025-06-12', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Manual Retractable Security Pool Covers', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Pool owners and operators should immediately contact Endless Pools for a free inspection and a free repair by an Endless Pools support services representative. Endless Pools will inspect the pool covers and send out a service representative to remedy any entrapment and drowning risks posed by improper installation. Pool owners and operators should not allow children to use or access the pool or pool cover unsupervised. Until the repair for the pool cover is completed, keep children away from the pool cover when closed. To prevent serious injury or death due to entrapment under the pool cover, do not allow anyone - especially children - to sit, stand, or jump on the pool cover at any time. Endless Pools is contacting all known purchasers directly.', '25339');
INSERT INTO safety_incidents VALUES ('71e3c365eab9f5e1ce9b3296366888121ff2ab12', 'CPSC', '2025-06-12', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Skywalker Pro Via Ferrata Sets, Skywalker Pro Turn Via Ferrata Sets and Skywalker Pro Via Ferrata Packages', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the Via Ferrata Sets and contact Mammut Sports Group for a full refund. Mammut Sports Group will provide return labels for consumers to return their recalled products to receive their refund. Consumers should email warranty.usa@mammut.com to request the prepaid return labels.', '25335');
INSERT INTO safety_incidents VALUES ('51797ad4fbbfd4b8f39183f532535186c7dd7229', 'CPSC', '2025-06-12', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Anker PowerCore 10000 power banks (model A1263 only)', 'Fire', 'Explosion', 'Burns', 'Anker has received 19 reports of fires and explosions. This includes two reports of minor burn injuries not requiring medical attention and 11 reports of property damage totaling over $60,700.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled power banks and contact Anker Innovations for instructions on receiving a free replacement power bank. Visit https://www.anker.com/product-recalls to register for the recall. To receive a replacement, consumers will be required to submit a photo of their recalled power bank showing the model number, serial number, their name, the date of the photograph, and the word "recalled" written on the power bank in permanent marker. A purchase receipt will be requested but will not be required to participate in the recall. Consumers will also be required to confirm disposal of the power bank in accordance with applicable laws and regulations before receiving a replacement.', '25338');
INSERT INTO safety_incidents VALUES ('4a37b0724204571f57c4c0a4808b5b946318eda7', 'CPSC', '2025-06-12', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'RYOBI 40V 24-Inch Cordless Hedge Trimmers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 27 reports of the blade activating after pressing just one of the controls, including 16 reports of injuries that resulted in minor and some severe lacerations.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled RYOBI 40V 24-Inch Cordless Hedge Trimmers and visit https://www.ryobitools.com/recall to determine if their trimmer is included in the recall. The recalled trimmer must be returned to TTI Outdoor Power Equipment (TTIOPE), in order to receive a free replacement trimmer (pre-paid label will be provided). Proof of purchase (receipt) is not required. TTIOPE is contacting all known purchasers.', '25334');
INSERT INTO safety_incidents VALUES ('8be51ab7d35eea888329b6706f3722061118e3cb', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Apollo America 51000-600 Combination Smoke and Carbon Monoxide Detectors', 'Fire', 'Mechanical Failure', 'Respiratory', 'None reported', 'Fatal', 1, 0, 'Vivint is sending a free replacement detector to all known purchasers. Consumers should continue using the recalled detectors until they install the replacement detector. Consumers should install the replacement detector immediately upon receipt. Detailed instructions on how to remove the recalled detector and install the replacement can be found here: Replacement Guide. Consumers should contact Vivint with questions about whether their detector is included in this recall or the status of their replacement detector. Once the replacement detector is installed, consumers should write "recalled" on the original product, remove the batteries, dispose of the detector in their household garbage, and dispose of the batteries in accordance with local and state regulations. Consumers can review Protect Your Family from Carbon Monoxide Poisoning | CPSC.gov for more information about preventing carbon monoxide poisoning.', '25322');
INSERT INTO safety_incidents VALUES ('170986cdcd2f0c61a85b85046b8f9afbb0d5d5a0', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Casters on Direct Scaffold Supply Multi-Purpose Baker Style Scaffolding Products', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received two reports of casters breaking or failing, including one injury where a caster failure led to a fall and bruising injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled casters and contact the firm for instructions to receive free replacement caster wheels. Contact Direct Scaffold Supply to receive a prepaid shipping label and packaging that can be used to return the recalled caster wheels. Once the casters are returned, new replacement casters will be sent to the consumer''s address.', '25324');
INSERT INTO safety_incidents VALUES ('8fe098d6bf3c4f798aaeb3225ac1725b4d36c34e', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Battery-Powered Chainsaws', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 20 reports of incidents of fire, sparks and/or smoke. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chainsaws and contact DR Power for a refund. Consumers will receive a pro-rated refund for the chainsaw tool based on the chainsaw''s age. Consumers will need to show proof of the chainsaw''s destruction by uploading a photograph in accordance with the destruction instructions and filling out the recall form online. For instructions on destroying the chainsaw, visit https://www.drpower.com/BPC-recall. If consumers choose to dispose of the recalled chainsaw''s lithium-ion battery, consumers should recycle the lithium-ion batteries in accordance with local and state regulations.', '25323');
INSERT INTO safety_incidents VALUES ('8b19d5102f3dfc24292b3736a9eadcd0d8fc17a9', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', '2-in-1 Funlio Convertible Baby High Chairs', 'Falls', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled high chair immediately, disassemble it and contact Ecogoods for information on how to receive a full refund. Consumers will be instructed to cut the restraint straps and email photos of the disassembled and destroyed components to funlioproductrecall@outlook.com. Ecogoods is contacting all known purchasers directly.', '25318');
INSERT INTO safety_incidents VALUES ('17fac75853d48378551384f0e79a76ec12c4f253', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Hobby Toy Hammer Ball sets', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled toys immediately and contact Shantou Haochengheng Technology for information on how to destroy the product and obtain a full refund. Shantou Haochengheng Technology and Amazon are also contacting all known purchasers directly.', '25314');
INSERT INTO safety_incidents VALUES ('c0128bf29dd302424c8e2e1decd8f38c0b8bf7e4', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'HTP residential gas boilers', 'Fire', 'Flammability / Overheating', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled boilers and contact HTP to arrange to have a certified technician install the repair at no cost to the consumer. Consumers who must continue using the boiler while awaiting repair should have working smoke and carbon monoxide alarms in their homes.', '25325');
INSERT INTO safety_incidents VALUES ('64ada8ed677153dfde0e55debc77e8fe29f2c08a', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'BowFlex 552, 52.5 LB Adjustable Dumbbells and BowFlex 1090, 90 LB Adjustable Dumbbells', 'The Weight Plates Can Dislodge From The Handle During Use, Posing An Impact Hazard.', 'Other', 'Fracture / Blunt Trauma', 'Johnson Health Tech Trading has received 12 reports of the plates dislodging during use with no injuries for units it sold. Nautilus received 337 reports of the plates dislodging during use for units it sold, including 111 resulting in injuries such as concussions, abrasions, broken toes or contusions.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Bowflex adjustable dumbbells and contact Johnson Health Tech Trading for a refund of the purchase price in the form of a voucher, or a replacement for units sold by Johnson Health Tech Trading. For units sold by BowFlex Inc. (formerly Nautilus Inc.), consumers can request a refund in the form of a prorated voucher and a one-year JRNY digital fitness membership. Consumers will be sent a pre-paid shipping label to return the handle and base for each returned dumbbell. Johnson Health Tech Trading is contacting all known purchasers directly.', '25311');
INSERT INTO safety_incidents VALUES ('1898d4f0614891387fff07338f5fe205c4dd3760', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Lutron-branded power interfaces for LED tape lights', 'The Power Interface Can Fail During A Significant Power Surge (E.G., Lightning Strike), Posing A Shock Hazard To Consumers If They Touch The Led Tape Lights.', 'Other', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled power interfaces and any connected lighting and turn off the power at the circuit breaker. Consumers should contact Lutron for instructions on how to receive their free replacement power interface and how it will be installed at no charge. Consumers should go to https://residential.lutron.com/us/en/safety/safety-recall to determine if their unit is included in this recall and, if so, to register to receive installation of the replacement power interface. If a unit is included, Lutron will provide the free replacement power interface and a pre-paid mailing label that the consumer can use to return the unit to Lutron.', '25317');
INSERT INTO safety_incidents VALUES ('2a0b305fb71a422c03ecabacef3b6579fe87cd07', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'U and U+ Window Air Conditioners', 'Pooled Water In The Air Conditioners Can Fail To Drain Quickly Enough, Which Can Lead To Mold Growth. Mold Exposure Poses Risks Of Respiratory Issues Or Other Infections To Some Consumers.', 'Drowning Risk', 'Respiratory', 'The firm is aware of at least 152 reports of mold in the air conditioners, including 17 reports of consumers experiencing symptoms such as respiratory infections, allergic reactions, coughing, sneezing and/or sore throats from mold exposure.', 'Moderate', 1, 0, 'Consumers with the recalled air conditioners should immediately contact Midea for a free repair or a full or prorated refund, which will be based on the purchase date or date of manufacture. Consumers who want a refund will be requested to send the unit back to Midea using a free shipping label or submit a photograph showing that they cut the unplugged power cord of the unit to receive a refund. Consumers who continue using the air conditioners while awaiting a repair should visit www.MideaUrecall.expertinquiry.com for instructions on how to inspect their unit prior to continuing use.', '25320');
INSERT INTO safety_incidents VALUES ('b50ba9db04b1aef40539c00b2ce2fb86dbc7b722', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'NTI residential gas boilers', 'Other', 'Other', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'The boiler door can fail to seal properly, due to incorrect burner door studs, allowing flames and gases to escape, posing fire and carbon monoxide (CO) poisoning hazards that can result in death or serious injury.', '25326');
INSERT INTO safety_incidents VALUES ('2978697be40a4d428cbe97110d9bc6c257f30015', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Portable Hook-On Chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the hook-on chair immediately and contact Ravmix for information on how to receive a refund. Consumers will be instructed on how to disassemble the product, cut the restraint straps and cloth seat, and email photos of the disassembled product and parts to Ravmix. Upon receipt of the photos, Ravmix will issue a full refund. Ravmix is contacting all known purchasers directly.', '25316');
INSERT INTO safety_incidents VALUES ('27ee74d557e1255d0ad7461afc3f0fe721c661c8', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Rinnai i-Series Plus gas boilers', 'The Boiler Door Can Fail To Seal Properly Due To Incorrect Screws, Allowing Carbon Monoxide (Co) Gases To Escape, Posing A Carbon Monoxide Poisoning Hazard.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled boilers and contact Rinnai to arrange to have a certified technician install the repair at no cost to the consumer. Consumers who must continue using the boiler while awaiting repair should have working carbon monoxide alarms on each level of their homes and outside sleeping areas.', '25313');
INSERT INTO safety_incidents VALUES ('caad1b489f9cb224f15ee9b490347031d26ffd20', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Haul ST and LT E-bikes with telescopic seat posts', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received 13 reports of incidents, including two minor injuries consisting of scrapes and bruises.', 'Minor', 1, 0, 'Consumers should immediately stop using Specialized Globe-branded Haul ST e-bikes and Haul LT e-bikes and contact an authorized Specialized retailer to schedule a free repair at the retailer. The repair will consist of a new post made of a different material.', '25319');
INSERT INTO safety_incidents VALUES ('88fb8d047d6780437871e317f3bd52574b6a0aee', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'Yamaha Golf Car Vehicles', 'The Accelerator Pedal Spring Can Fail To Return To Idle When A Consumer Stops Pressing The Accelerator Pedal, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'Yamaha has received at least 2,200 reports of incidents involving accelerator pedal return spring failures. No injuries have been reported.', 'Minor', 1, 0, 'Yamaha is expanding the repair to include a free replacement of the accelerator pedal return spring assembly. Consumers should immediately stop using the recalled golf car vehicles (even if they have already had their golf car vehicles repaired as part of prior recalls) and contact an authorized Yamaha Golf Car dealer to schedule a free replacement of the accelerator pedal spring assembly. Consumers who received a repair from a prior recall are being contacted directly by Yamaha with additional information about how to schedule the installation of a replacement accelerator pedal spring assembly. Yamaha dealers are prepared to conduct mobile service and/or provide unit transportation if necessary. Yamaha is contacting all registered owners directly.', '25321');
INSERT INTO safety_incidents VALUES ('1b80233764df64c2c60cccc5562033794c0077d6', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'ZHORANGE Portable Bassinets', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled portable bassinets and contact DFD Trading for a full refund. Consumers should remove the sleeping pad, cut the sides of the portable bassinets and the sleeping pad, and email a photo of the destroyed bassinet to zhorange8695@gmail.com to obtain a full refund. DFD Trading and Amazon are contacting all known purchasers directly.', '25315');
INSERT INTO safety_incidents VALUES ('b867e2f2831a2990d468ad3c988bdc8f02b705dd', 'CPSC', '2025-06-05', 2025, '2025-06', 'USA', 'United States', '', 'Other', 'ZRWD Infant Swings', 'Chemical', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled infant swings and contact ZRWD for a full refund. Consumers should send a photo of the swing cover cut in half and of the swing with "Recalled" written with permanent marker on its base to zrwdrecall@163.comand then dispose of the swing. ZRWD and Amazon are contacting all known purchasers directly. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local procedures for hazardous household waste, not in the trash.', '25312');
INSERT INTO safety_incidents VALUES ('7e1fd430f7a06318297986e7b3f1bcda27020c16', 'CPSC', '2025-05-29', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'BASDEHEN Kitchen Faucets, model number CFDTTH-000-YGH', 'The Recalled Faucets Were Tested And Found To Contain Lead That Can Leach Into Water At Levels That Can Be Particularly Harmful To Infants And Young Children. The Faucets Were Also Found To Leach Other Contaminants. Lead Ingestion Can Cause Harmful Neurological Effects On Infants And Young Children, Including Attention-Related Behavioral Problems, Decreased Cognitive Performance And Lower Iq.', 'Drowning Risk', 'Poisoning / Ingestion', 'None reported', 'Serious', 1, 0, 'Consumers should immediately stop using these faucets and contact Chenfeng Store about disposal and a refund. Consumers will need to provide a photograph of disposal to receive the refund. Amazon is contacting all known purchasers directly. Until these faucets can be replaced, consumers should only consume water from the faucets after running the water for 15 seconds.', '25305');
INSERT INTO safety_incidents VALUES ('db6c6e4c9f8357bd143b5f973c36a26baa350253', 'CPSC', '2025-05-29', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'iWALK Magnetic Wireless Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 15 reports of the lithium-ion battery catching fire, resulting in 10 burn injuries.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled power banks and contact U2O Global for a full refund. To receive a refund, consumers should send a photo of the recalled power bank, showing the model number and the serial number, with "Recalled" written on the power bank in permanent marker to U2O Global by email at service@iwalk.net. Consumers should dispose of the recalled power banks in accordance with local hazardous waste disposal procedures.', '25304');
INSERT INTO safety_incidents VALUES ('1244f620c29fc83e0e839b28c7e524935fed2d25', 'CPSC', '2025-05-29', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'KICIMPRO Kitchen Faucets, model number KM800-01-06BN', 'The Recalled Faucets Were Tested And Found To Contain Lead That Can Leach Into Water At Levels That Can Be Particularly Harmful To Infants And Young Children. Lead Ingestion Can Cause Harmful Neurological Effects On Infants And Young Children, Including Attention-Related Behavioral Problems, Decreased Cognitive Performance And Lower Iq.', 'Drowning Risk', 'Poisoning / Ingestion', 'None reported', 'Serious', 1, 0, 'Consumers should immediately stop using these faucets and contact Kicimpro about disposal and a refund. Consumers will need to provide a photograph of disposal and their order number to receive the refund. Kicimpro is contacting all known purchasers directly. Until these faucets can be replaced, consumers should only consume water from the faucets after running the water for 15 seconds.', '25306');
INSERT INTO safety_incidents VALUES ('9b7e5695ce213b5adf5f7d80b7a4679b133b0d98', 'CPSC', '2025-05-29', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Minka Vortic Flow Series light fixtures', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received two reports of the light fixtures partially detaching. No fallen light fixtures or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately contact Minka Lighting to schedule a free inspection and an on-site repair to replace the connection component.', '25301');
INSERT INTO safety_incidents VALUES ('21e23a06a9035213ccf0e4f42f3ec7d2c3289fa5', 'CPSC', '2025-05-29', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Unity Teeter Tunnels with Lexan Tops', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received two reports of children falling under the end of the seesaw plank of the recalled Unity Teeter Tunnels. One child sustained a liver laceration when the end of the seesaw plank landed on her abdomen and the second child suffered fractures to his right tibia and right fibula when the end of the seesaw plank landed on him.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled teeter tunnels and contact Playworld Systems to schedule a free repair. Playworld Systems will send a certified playground installer to each location to repair the unit. Playworld Systems is contacting all known purchasers directly and will request that consumers place the teeter tunnels out of service until the repair is completed.', '25303');
INSERT INTO safety_incidents VALUES ('507d2b9082879b768cd9a4644cc5c4070bde7e29', 'CPSC', '2025-05-29', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'My First Snowman Toys', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received 47 reports of the brim of the top hat breaking. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should stop using the recalled snowman immediately, take off the toy snowman''s hat and keep it away from children. Contact The Step2 Company for instructions on how to dispose of the top hat and receive a free replacement. The Step2 Company is notifying all known purchasers directly.', '25308');
INSERT INTO safety_incidents VALUES ('feedc6124383706af66d30eedad0322e8770af90', 'CPSC', '2025-05-29', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'VFAUOSIT Kitchen Faucets, model number 06BNV', 'The Recalled Faucets Were Tested And Found To Contain Lead That Can Leach Into Water At Levels That Can Be Particularly Harmful To Infants And Young Children. The Faucets Were Also Found To Leach Other Contaminants. Lead Ingestion Can Cause Harmful Neurological Effects On Infants And Young Children, Including Attention-Related Behavioral Problems, Decreased Cognitive Performance And Lower Iq.', 'Drowning Risk', 'Poisoning / Ingestion', 'None reported', 'Serious', 1, 0, 'Consumers should immediately stop using these faucets and contact Whisper08 about disposal and a refund. Consumers will need to provide a photograph of disposal and their order number to receive the refund. Whisper08 is contacting all known purchasers directly. Until these faucets can be replaced, consumers should only consume water from the faucets after running the water for 15 seconds.', '25307');
INSERT INTO safety_incidents VALUES ('6d508baff2fb8c1541ccbf8ddaeed59f7b7f5752', 'CPSC', '2025-05-29', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'WeHwupe Adult Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'The firm has received one report involving the BRX-8002 model bed rail, which broke during use, resulting in a fall injury.', 'Fatal', 1, 0, 'Consumers should stop using the recalled adult portable bed rails immediately and contact WeHwupe Store to obtain a free replacement. Consumers should follow these disposal steps: 1 Remove the upper rail, connecting rails, bottom rail and legs (if present). 2. Write "RECALLED" on the upper and bottom rails with a permanent marker. 3. Using scissors, cut the black fabric mesh bag off the upper rail and cut the black safety strap in half (if present).  4. Write the buyer''s name on a piece of paper next to the disassembled product. 5. Consumers should take a photo and upload it online at https://chunqushop.com/wehwupe-bed-rail-safety-recall. 6. Dispose of the recalled product in accordance with local requirements. Consumers who have difficulty with any disposal step or need additional instruction should contact WeHwupe Store. WeHwupe Store is also contacting all known purchasers directly.', '25302');
INSERT INTO safety_incidents VALUES ('2f27bf7ae0d589264d840210c15bc36b6c275a06', 'CPSC', '2025-05-22', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Rolanstar 6-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Performance Requirements Of The Sturdy Act Because They Can Tip Over With Fewer Than 60 Pounds Applied Horizontally, And The Dressers Also Fail To Meet The Labeling Requirements Of The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately if they are not anchored to the wall and place them in an area that children cannot access. Areson, through Amazon Logistics Service, is contacting all known purchasers directly. Contact Areson for instructions on how to receive a full refund and how to submit a photo showing the disposal of the product to the firm at Support@Areson.shop.', '25292');
INSERT INTO safety_incidents VALUES ('1fefbc3809def10cc90d1adc274e2b54965ce19a', 'CPSC', '2025-05-22', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Holiday Lane Infant Footed Pajamas', 'Injury', 'Other', 'Not Specified', 'Macy''s has received four reports of the elastic being too tight on infants'' ankles, resulting in chafing, imprinting or restricting blood circulation.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled pajamas, take them away from children and contact Macy''s for instructions on how to receive a refund. Consumers should not return the recalled pajamas to the stores. Consumers will be asked to fill out the recall form at https://www.recallrtr.com/footedpajamas. Once consumers fill out the recall form, they will be sent a pre-addressed, postage-paid envelope to return the footed pajamas free of charge. Macy''s will issue a $26.50 refund via check upon receipt of the recalled product. Macy''s is contacting all known purchasers directly.', '25291');
INSERT INTO safety_incidents VALUES ('c62af03df2077ea200d7ebd89b03d883a902978c', 'CPSC', '2025-05-22', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Nezmdi Baby Swings', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled infant swings immediately and contact Nezmdi for a full refund. Consumers should send a photo of the swing cover cut in half with "Recalled" written with permanent marker on its base to yingpengds@163.com, and then dispose of the swing in accordance with state and local procedures. Nezmdi is contacting all known purchasers directly. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25290');
INSERT INTO safety_incidents VALUES ('ff57dcb774657cda651aa2a57dc90463520d24a4', 'CPSC', '2025-05-22', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'DTR Plush Bag Stitch and DTR Plush Bag Angel', 'Injury', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately take the recalled plush bags away from children, stop using them and return them to a Primark store for a full refund in the form of the original payment.', '25294');
INSERT INTO safety_incidents VALUES ('460b2b8005947f5489388b7e85e94f1d20a89b1a', 'CPSC', '2025-05-22', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Sivan Six-Drawer Double Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Performance Requirements Of The Sturdy Act Because They Can Tip Over With Fewer Than 60 Pounds Applied Horizontally, And The Dressers Also Fail To Meet The Labeling Requirements Of The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not anchored to a wall and place them in an area that children cannot access. Consumers can contact Anji Guyou Furniture for instructions on how to dispose of the dressers to receive a full refund. Consumers must email a photo showing disposal of the product to guyouproductrecall@163.com. Anji Guyou Furniture and Wayfair are also contacting all known purchasers directly.', '25293');
INSERT INTO safety_incidents VALUES ('c79c0e0d89a97c2205de057d48b32e5b7ad2e06e', 'CPSC', '2025-05-15', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Boyro Baby Convertible High Chairs', 'Falls', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using and disassemble the recalled high chairs immediately and contact Boyro Baby for instructions on receiving a full refund. The instructions will include instructions on cutting the restraint system and seat cushions, and emailing photos of the disassembled and destroyed pieces of the high chair to boyrobaby@outlook.com. Once the photos have been received, Boyro Baby will issue a refund.', '25278');
INSERT INTO safety_incidents VALUES ('065d144b249bfcd9b767c0a821dcc9c0ef98d663', 'CPSC', '2025-05-15', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Children''s Mini Danica Loungewear Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled pajamas immediately and contact BuddyLove for information on how to dispose of the product to obtain a full refund or store credit for the original purchase price. Consumers should destroy the garments by cutting them in half and email a photo of the destroyed garment to Recall@buddylove.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. BuddyLove is contacting all known purchasers directly.', '25287');
INSERT INTO safety_incidents VALUES ('5e8d5f5cbfed495f729bff5857b5c989e03f4a35', 'CPSC', '2025-05-15', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Child Safety Gates', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled gates immediately and contact the third-party seller by email for information on how to dispose of the product and submit proof of destruction to obtain a full refund. The third-party sellers and Amazon are contacting all known purchasers directly.', '25286');
INSERT INTO safety_incidents VALUES ('6ce3b435ceba48ab12a60e7f8e813ce852766af8', 'CPSC', '2025-05-15', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'PlayTab Rollers Tile Toys', 'The Recalled Rollers Tile Toy Violates The Mandatory Federal Regulation For Toy Magnets Because It Contains A Magnet That Can Become Loose, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Other Metal Objects, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting, And/Or Blockage Of The Intestines, Infection, Blood Poisoning, And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the rollers tile toys immediately and contact the firm for instructions on how to dispose of the product to obtain a $10 credit for use at fatbraintoys.com, or a replacement PlayTab tile. Fat Brain Toy Co. is contacting all known purchasers directly.', '25281');
INSERT INTO safety_incidents VALUES ('d68d6645b1a2978dd2458de6ad0930c9054c5074', 'CPSC', '2025-05-15', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Chill Pill Magnetic Haptic Fidget Toys Red Bumpy', 'The Recalled Magnetic Fidget Pill Toy Violates The Mandatory Federal Regulation For Magnets, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the magnetic fidget pill toys immediately and take them away from children. Contact FidgetThings via email at fidgetthings@gmail.com to receive a pre-paid label to return the toy, or for instructions on how to dispose of the toy, to receive a full refund. FidgetThings is notifying all known purchasers directly.', '25285');
INSERT INTO safety_incidents VALUES ('34203d5484c57048ae4b83829a81bd7818f3a8a5', 'CPSC', '2025-05-15', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'GASGAS and Husqvarna Off-Road Motorcycles', 'The Front Brake Caliper Can Crack, Reducing The Braking System''S Effectiveness, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop riding the recalled motorcycles and contact an authorized GASGAS Motorcycles or Husqvarna Motorcycles dealer to schedule a free inspection and free repair at the dealership. It is necessary to have the front brake caliper inspected by an authorized dealer to determine if it is defective or not defective. KTM/GASGAS and Husqvarna Mobility are contacting all known purchasers directly.', '25283');
INSERT INTO safety_incidents VALUES ('40fd6489356318dc82197cdc17af2f69b3b2c153', 'CPSC', '2025-05-15', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Digital Wall Clocks', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled digital wall clock''s remote control, remove the lithium coin battery from the remote and dispose of or recycle it in accordance with local hazardous waste procedures. Consumers should write "RECALLED" in permanent marker on the remote and then email a photo of the remote being disposed of in the trash to recall@lianaocoltd.com to receive a full refund for the recalled digital clock. Leon Rading and Amazon are contacting all known purchasers directly. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25280');
INSERT INTO safety_incidents VALUES ('3f88837ec696184bf3473013f7a5570ef1c470cb', 'CPSC', '2025-05-15', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'LivingCaring Adult Portable Bed Rails', 'Low Risk', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled adult portable bed rails. To receive a refund, consumers should send a photo of the disposed bed rail or an Amazon purchase receipt to the recalling firm by email at Jerryhe@sourcing-cn.com. Shanghai Kai Rong Xin Xi Ke Ji Co. Ltd. and Amazon are contacting all known purchasers directly.', '25282');
INSERT INTO safety_incidents VALUES ('fc682849350b6b3cee608d26525c974692ec3f27', 'CPSC', '2025-05-15', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'NICREW 15" Submersible RGB LED Lights with remote controls', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled product, remove the battery from the remote control and place it in an area that children cannot access. Contact Nicrew for a free replacement of the remote and information on how to properly dispose of the product. Consumers need to email the Amazon order number and a photo showing the remote was destroyed by the consumer to nicrew@support.com to obtain the replacement. Nicrew and Amazon are contacting all known purchasers directly. Note: Button cell and coin batteries are hazardous. These batteries should be disposed of or recycled by following local hazardous waste procedures.', '25279');
INSERT INTO safety_incidents VALUES ('39858380fa4074fe6f0646166208ca36a48b62ae', 'CPSC', '2025-05-15', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Model Year 2023-2025 Ranger XP 1000 NorthStar and Ranger XP 1000 NorthStar Crew Recreational Off-Road Vehicles (ROVs)', 'Injury', 'Other', 'Skin Irritation', 'The firm has identified two vehicles with loose seat belt fasteners. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ROVs and contact an authorized Polaris dealer to schedule a free inspection and repair at the dealer''s location. Polaris advises that consumers may continue to operate the recalled ROVs prior to inspection and repair at the dealer, only if they conduct an inspection by following the Seat Belt Fastener Verification Instructions located on the firm''s website. To continue operating the recalled ROVs prior to getting the repair, the fasteners must be secure where the seat belt anchor is attached to the vehicle frame. Polaris has contacted registered owners directly.', '25284');
INSERT INTO safety_incidents VALUES ('fe67d59b7ef1d728b0b83ef76611fea391ce5eb2', 'CPSC', '2025-05-08', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Delta Gas Ball Valves', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Delta-branded Gas Ball Valves and contact Masco Canada to confirm that their product is part of the recall and receive instructions on how to get a refund. Masco Canada will also reimburse the cost of labor to remove the units and dispose of them. Masco is contacting all known purchasers directly.', '25255');
INSERT INTO safety_incidents VALUES ('180852db6139614ee95fb3fba9eb70306d633da4', 'CPSC', '2025-05-08', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Maril Brand Scented Candles', 'Fire', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received three reports of the candle''s glass breaking while in use. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candle and contact DEMDACO for a full refund in the form of original payment. Contact DEMDACO via email at customercare@demdaco.com for instructions on how to receive a refund and pre-paid shipping label to return the candle. Proof of purchase (receipt) is not required. Consumers should not return the recalled candles to retail stores. DEMDACO is contacting all known purchasers directly.', '25250');
INSERT INTO safety_incidents VALUES ('156af5156b86be78f85bac791bc9870a275b6642', 'CPSC', '2025-05-08', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Kid Comfort, Kid Comfort Pro and Kid Comfort Active Child Carriers', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 13 reports of hinges cracking and breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled child carriers and contact Deuter to receive a free replacement child carrier. Consumers should fill out the recall form at https://www.deuter.com/us-en/service/kid-comfort-recall, print a prepaid return shipping label, and return the product. Deuter is contacting all known purchasers directly.', '25256');
INSERT INTO safety_incidents VALUES ('0e1f33670a7a8b07520055647e6904e732417d71', 'CPSC', '2025-05-08', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Igloo 90 Qt. Flip & Tow Rolling Coolers', 'The Tow Handle Can Pinch Consumers'' Fingertips Against The Cooler, Posing Fingertip Amputation And Crushing Hazards.', 'Sharp Edges / Points', 'Laceration / Cut', 'Since the recall was announced in February 2025, Igloo has received 78 reports of fingertip injuries, including 26 resulting in fingertip amputations, bone fractures or lacerations.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled coolers and contact Igloo for a free replacement handle.', '25253');
INSERT INTO safety_incidents VALUES ('baf864f17edf66e4824cb2cd1541af17d4b24a25', 'CPSC', '2025-05-08', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Bliss Hair Dryers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately unplug and stop using the recalled hair dryers and contact Legend Brands to receive a full refund. Consumers will be asked to destroy the hair dryers by cutting the cord and disposing of the product. Consumers must send a photo of the destroyed hair dryers to support@shoptrakk.com. Legend Brands is contacting all known purchasers directly.', '25257');
INSERT INTO safety_incidents VALUES ('0305e34f968368f3daf867da9fd29c19692a32f8', 'CPSC', '2025-05-08', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Stainless steel cable railing kits', 'The Bottom Hole On The Cable Support Posts Is Over Four Inches From The Bottom Of The Base Plate, Posing An Entrapment Hazard To Consumers.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the cable railing kits immediately, prevent children from accessing the area where they are located, and contact Vevor for a full refund. Vevor will provide pre-paid shipping labels so that consumers can return the recalled cable railing kits. Alternatively, consumers can provide photographic evidence of disposal or destruction of the cable support posts to recalling@vevor.com.', '25251');
INSERT INTO safety_incidents VALUES ('333f6e13920bd7c5ec4e3fb2bda7cdd765152803', 'CPSC', '2025-05-08', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Xylolin Peg Doll Toy Sets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should take the product away from children immediately, dispose of the product and send a picture to Babywants for a full refund. Amazon is contacting all known purchasers directly.', '25252');
INSERT INTO safety_incidents VALUES ('a9ef77c7e0a13da969a9aec3203a951357a35e4f', 'CPSC', '2025-05-08', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'YAMAHA PA-300C AC Power Adaptors', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received four reports of adaptors burning or smoking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using and unplug the recalled PA-300C AC Power Adaptor and contact Yamaha Corporation of America for a free replacement adaptor. Visit www.yamaha.com/us/support/pa300crecall/ for instructions to participate in the recall. Consumers will need to submit their information through an online form or by email, and will need to submit evidence of product destruction with their claim. Consumers should not damage their recalled adaptor until they have read the recall instructions online. Consumers who own a Yamaha-brand Clavinova® digital piano with a recalled adaptor should unplug the piano and contact Yamaha. Yamaha will provide piano technician services to perform an on-site inspection of the piano and provide a free replacement adaptor.', '25254');
INSERT INTO safety_incidents VALUES ('ee2b2e5adbca15fd1f8d351e40be928567920355', 'CPSC', '2025-05-01', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Baseus 65W 30000mAh Portable Chargers (model number BS-30KP365)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Baseus has received 76 reports of incidents involving the portable chargers, including 72 reports of bulging and four reports of fire, including three reports of property damage.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled portable chargers and contact Baseus to receive a free replacement charger. The replacement portable charger will have the same model number (BS 30KP365) and a different serial number ending in the letter "A." Consumers will need to submit a photo of the recalled portable charger showing the model number and serial number to the firm''s recall registration page. Consumers without an order number will need to submit a photo of the portable charger with their name and date written on the portable charger in permanent marker. Visit https://www.baseus.com/pages/recall_select_BS-30KP365 to register and get instructions on how to receive a free replacement. To receive a replacement, consumers will be required to confirm disposal of the portable charger in accordance with applicable laws and regulations.', '25248');
INSERT INTO safety_incidents VALUES ('0684da00f104eb277836dc735c0c8b739e7be24f', 'CPSC', '2025-05-01', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Dlesot Snap Hair Clips', 'The Painted Hair Clips Contain Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Lead Poisoning Hazard To Children. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled hair clips away from children, stop using them and contact YFLGOTOO. Consumers will need to provide a picture of disposal, to receive the remedy. Amazon is contacting all known purchasers directly.', '25245');
INSERT INTO safety_incidents VALUES ('15d19ca2172d73471c2e7808efbe2a6fe5214182', 'CPSC', '2025-05-01', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'St. Nicholas Square Christmas Tea Light Candle Holders', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received two reports of tea light candle holders catching on fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled tea light candle holders and return them to any Kohl''s store for a full refund, in the form of a Kohl''s gift card or in the original form of payment. Kohl''s will provide a pre-paid shipping label for consumers who purchased the candle holders online. Kohl''s is contacting all known purchasers directly.', '25246');
INSERT INTO safety_incidents VALUES ('5382a76e0446d87d9dcdad346c67670bfcb18801', 'CPSC', '2025-05-01', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Kubota Utility Vehicles', 'The Ball Joint Connected To The Front Suspension Arm Can Loosen And Separate From The Front Suspension Arm, Resulting In The Driver Losing Wheel Support Of The Utility Vehicle, Posing A Crash Hazard To Consumers.', 'Other', 'Skin Irritation', 'The firm has received four reports of loosened or separated ball joints. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact an authorized Kubota dealer to schedule a free inspection and repair at the dealer''s location. Kubota is contacting registered owners directly.', '25249');
INSERT INTO safety_incidents VALUES ('71f2c9c823e1714fdc25da108bc5b9388c5a2e90', 'CPSC', '2025-05-01', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'Heckler 9 Electric Bicycles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received three reports of fires, including some property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled electric bicycles, disconnect the battery from the bike and charger, and visit the manufacturer''s website at https://santacruzbicycles.com/pages/recall-heckler-9-lithium-ion-battery to determine if their bicycle is affected and, if so, to register for a free replacement battery to be sent to them. If their battery is involved in this recall, consumers will be required to write "Recalled" on the involved affected battery and upload a photograph of it to https://santacruzbicycles.com/pages/recall-heckler-9-lithium-ion-battery. These consumers should then dispose of the battery in accordance with local and state regulations following registration.', '25244');
INSERT INTO safety_incidents VALUES ('2cf7d096a1dc9709ccea71bfc25b7e6fec6d3f9b', 'CPSC', '2025-05-01', 2025, '2025-05', 'USA', 'United States', '', 'Other', 'SharkNinja Foodi OP300 Series Multi-Function Pressure Cookers', 'Burns', 'Explosion', 'Burns', 'SharkNinja has received 106 reports of burn injuries, including more than 50 reports of second- or third-degree burns to the face or body, with 26 lawsuits filed.', 'Minor', 1, 0, 'Consumers should immediately stop using the product''s pressure-cooking function and contact SharkNinja for a free replacement lid. Consumers can continue to use the product''s air frying and other functions.', '25247');
INSERT INTO safety_incidents VALUES ('dbfa8524ab8885cfcde16239636d875fc14fae82', 'CPSC', '2025-04-24', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'LED Strip Lights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled LED strip lights immediately and contact AliExpress to receive a full refund. Consumers should destroy the lights by cutting them in half and disposing of them. Consumers must send a photo of the destroyed lights to us_product_recall@aliexpress.com or by replying to the recall email sent by AliExpress. AliExpress is contacting all known purchasers directly. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25232');
INSERT INTO safety_incidents VALUES ('47c7ef8db2aedecb040d965064cf907ce18f9e08', 'CPSC', '2025-04-24', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Kids Thrill Shape Sorter Car Toys', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled shape sorter car toys immediately and contact Deals Oasis for information on how to return the product for a full refund. Amazon is contacting all known purchasers directly.', '25237');
INSERT INTO safety_incidents VALUES ('8506e0554dd64b35b22420e46d3ff6b90cd6714f', 'CPSC', '2025-04-24', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Huffy 12-Volt Children''s Ride-On Tonka Dump Trucks', 'Fire', 'Flammability / Overheating', 'Burns', 'Huffy has received three reports of the controller overheating, and one report of a fire that consumed the ride-on truck. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled children''s dump trucks and contact Huffy for a free replacement controller. Huffy is contacting all known purchasers directly.', '25235');
INSERT INTO safety_incidents VALUES ('b04ac1596e2ef174283a30dceba31a96edeab894', 'CPSC', '2025-04-24', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Sondiko Butane Torches', 'Burns', 'Other', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using and dispose of the recalled torches and contact Sondikodirt for information on how to return them to obtain a full refund. Sondikodirt and Amazon are contacting all known purchasers directly.', '25236');
INSERT INTO safety_incidents VALUES ('3d1fae27d71fe5523badc87e582a99be4317fff6', 'CPSC', '2025-04-24', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Huffy Torex 24V Utility Terrain Vehicle (UTV) Ride-on toys', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 20 reports of incidents of the UTVs smoking or catching fire, resulting in five minor burns.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled UTVs and contact Huffy Corporation to schedule a free repair. Consumers can have the repair done by a third party. Huffy Corporation will reimburse consumers up to $50 for charges incurred in the third-party repair.', '25239');
INSERT INTO safety_incidents VALUES ('5340c5fea14d8622c18099a83ec1afee08edd7d3', 'CPSC', '2025-04-24', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Model Year 2025 KX series competition and cross-country motorcycles', 'The Primary Gear For The Crank Shaft Can Fail, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled competition and cross-country motorcycles and contact a Kawasaki dealer for a free repair. The primary gear will be replaced with a new gear. The repair will take place at an authorized Kawasaki dealership.', '25238');
INSERT INTO safety_incidents VALUES ('5995cf1787a428122eee3c132205a8db6ab69713', 'CPSC', '2025-04-24', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Roll Up Window Blinds', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled window blinds and contact BTAMREE for a full refund. Consumers should remove the window blind, mark it with the word "Recalled" and dispose of the product in the garbage. Consumers should take a photograph of the window blinds destroyed in the garbage and upload the photo to sales@cy-bamboo.com to register their product and to receive a refund. BTAMREE is contacting all known purchasers directly.', '25234');
INSERT INTO safety_incidents VALUES ('bd9397e8a234227deff5845fadc96e7421d80aea', 'CPSC', '2025-04-24', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'LuckupShein Window Roll Up Shades', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled window shades, cut the operating cord and contact LuckupShein to receive a free repair, consisting of a replacement operating cord device. Consumers will be asked to send a photo of the recalled product with the operating cord cut to luckupshein@163.com. Once the firm receives the picture of the product with the original cord cut, consumers will be sent a replacement operating cord wand device with installation instructions.', '25233');
INSERT INTO safety_incidents VALUES ('89baa0f79042ce3b1d7ff51c00d133ca45f6517a', 'CPSC', '2025-04-17', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Tip-Over Restraint Kits', 'The Plastic Zip Tie Used With The Recalled Furniture Tip Kits Can Become Brittle Or Break, Which Can Allow A Clothing Storage Unit That Is Anchored To The Wall To Detach During A Furniture Tip-Over Event, Posing A Tip-Over And Entrapment Hazard That Can Result In Death Or Serious Injuries To Children.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should contact American Bolt and Screw to get a free replacement tip-over restraint kit. All known purchasers are being contacted directly by American Bolt and Screw. Consumers can contact Rooms to Go for assistance in determining whether their chest or dresser came with the affected tip-over restraint kit. Keep children away from the unit while waiting for a replacement tip kit. Consumers should dispose of the recalled tip-over restraint in their household trash once they have installed the replacement tip-over restraint.', '25231');
INSERT INTO safety_incidents VALUES ('b2b738d707f0cba8c720bfe7aa08e6fd1877f142', 'CPSC', '2025-04-17', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Casely Wireless Portable Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 51 consumer reports of the lithium-ion battery overheating, expanding or catching fire while they were charging their phones, resulting in six minor burn injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled wireless portable power banks and contact Casely for a free replacement. To receive the free replacement, consumers should go to the firm''s website and fill out the online form and submit two photographs; one should be the front of the power bank with the word "Recalled" on it and the date written in permanent marker. The second photograph should have the model number on it, which is located on the back of the power bank. Then upload the photos to the firm''s website at https://www.getcasely.com/pages/2025-recall. Consumers should immediately dispose of the power banks in accordance with local and state regulations. Proof of purchase (receipt) is not required. Casely is contacting all known purchasers directly.', '25227');
INSERT INTO safety_incidents VALUES ('891218fb304ee195d33bbacfa39dcb1484899f46', 'CPSC', '2025-04-17', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'COMEONROA Infant Swings', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the recalled infant swings immediately and contact Eonroacoo for a full refund. Consumers should send a photo of the swing cover cut in half, and of the swing with "Recalled" written with permanent marker on its base, to eonroacoorecall@126.com and then dispose the swing in accordance with local and state laws. Eonroacoo and Walmart are contacting all known purchasers directly. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25228');
INSERT INTO safety_incidents VALUES ('5a5e2850381a14562230469fb5a7bcf8dba87bf6', 'CPSC', '2025-04-17', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Joydeco Roller Window Shades', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately put the window shade''s cords up and away from children and contact Shanghai Chushuo Electronic Commerce Co. Ltd to receive a full refund or free replacement operating cord wand. Consumers must send a photo of the recalled product with the operating cord cut to amazonservice@joydeco.com. Once the firm receives the photo, consumers will receive a repair kit with installation instructions through Shunfeng Express or UPS. The firm is contacting all known purchasers directly.', '25230');
INSERT INTO safety_incidents VALUES ('ae893e9263c8e710e29360a211fef26c2c69c514', 'CPSC', '2025-04-17', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Glow Sticks and Glasses Party Pack Toys', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled glow sticks and glasses and take them away from children. Consumers should remove the batteries in the glow sticks and party glasses immediately and contact Leetous for information on how to dispose of the product for a full refund. Leetous and Amazon are contacting all known purchasers directly. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25229');
INSERT INTO safety_incidents VALUES ('3be1261b5a08564b7b2ea611b0f46389b5ca660c', 'CPSC', '2025-04-17', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'The North Face Women''s Shellista V Mid Waterproof Boots', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 28 reports of the top hook catching on the lace of the other boot, including 15 reports of minor injuries in the United States.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled boots and contact The North Face for instructions on how to return the boots and receive a full refund in the original form of payment, a gift card, or via check if the purchase was made with cash. After contacting The North Face, consumers will receive a shipping label to return the boots free of charge.', '25226');
INSERT INTO safety_incidents VALUES ('fe5b3b338f4c8916a0afd54f7e35322efea0a8ae', 'CPSC', '2025-04-10', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Bebamour baby bath seats', 'Injury', 'Instability / Fall Risk', 'Drowning', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled bath seats immediately and contact Bebamour by email at amanda@babyleading.com for information on how to dispose of the product and submit a photograph to obtain a full refund. Bebamour and Amazon are contacting all known purchasers directly.', '25220');
INSERT INTO safety_incidents VALUES ('89fbb2d6c07bfccae25f0a900accd257fda276fc', 'CPSC', '2025-04-10', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Babyjoy Convertible 6-in-1 High Chair Activity Centers', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled high chair activity centers and contact Costway for a full refund and instructions on how to return or dispose of the product. Consumers can return the product by receiving a prepaid shipping label or provide photos of the destroyed product to recall@costway.com. Upon receipt of the returned product or photos of the destroyed product, Costway will issue the refund. Costway and Amazon are contacting all known purchasers directly.', '25222');
INSERT INTO safety_incidents VALUES ('a9a12518f4eb21ab9aaf8ad31a06cf32918e9371', 'CPSC', '2025-04-10', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Brunch & Go Stroller Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Fisher-Price has received five reports of the yolk of the toy egg cracking and breaking. In two reports, an infant had a small piece in their mouth. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled stroller toys, keep them away from children, and contact Fisher-Price to receive a free replacement stroller toy. Consumers will be asked to permanently mark the egg component of the stroller toy with the word "Recall" and the unique identifier, and upload a photo of the marked toy at https://service.mattel.com/us/recall.aspx. Upon receipt of the replacement confirmation email, consumers should dispose of the recalled product in the trash. For specific instructions on how to mark the stroller toy and upload the photo, consumers should go to https://service.mattel.com/us/recall.aspx. Fisher-Price is contacting all known purchasers directly.', '25215');
INSERT INTO safety_incidents VALUES ('3d9cc61a81d80fec97839567178ba4c7430e1445', 'CPSC', '2025-04-10', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Tissue Box Toy sold with Fisher-Price 3-in-1 SnugaPuppy Activity Centers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Fisher-Price has received one report of the tissue box toy coming apart and an infant placing the small support bracket in their mouth. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled tissue box toy, remove it from the activity center, keep it away from children and contact Fisher-Price to receive a free replacement toy for the activity center. Consumers will be asked to mark the tissue box toy permanently with the word "Recall" and the unique identifier, mark "X" on the sensory cloth tissues, and upload a photo of the marked toy at https://service.mattel.com/us/recall.aspx. Upon receipt of the replacement confirmation email, consumers should dispose of the recalled product in the trash. For specific instructions on how to mark the box and upload the photo, consumers should go to https://service.mattel.com/us/recall.aspx. Fisher-Price is contacting all known purchasers directly.', '25216');
INSERT INTO safety_incidents VALUES ('c62331e53e409e62070a5a1f2818655f64133dfa', 'CPSC', '2025-04-10', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Long-Haul 5L ATV Gas Cans', 'Fire', 'Flammability / Overheating', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled fuel containers immediately, place them out of reach of children, and contact Jonas C for information on how to return or dispose of the product to obtain a full refund or partial refund. The firm is providing a full refund to consumers who purchased the product after January 1, 2024, and partial refund for purchases before December 31, 2023. Jonas C and Amazon are contacting all known purchasers directly.', '25219');
INSERT INTO safety_incidents VALUES ('76254e7b8532c89d9e5738775c83b4ca5aa788fe', 'CPSC', '2025-04-10', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Safetussin Max Strength Multi-Symptom Cough, Cold and Flu tablets blister packs', 'The Safetussin Over-The-Counter Cold Medicine Contains Acetaminophen, Which Must Be In Child-Resistant Packaging As Required By The Poison Prevention Packaging Act. The Packaging Of The Products Is Not Child-Resistant As A Tablet Can Be Pushed Through The Foil, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately secure the product out of the sight and reach of children and contact Kramer Laboratories for information on how to return or dispose of the product for a full refund. Only the packaging is being recalled, not the medicine itself, but both should be disposed.', '25223');
INSERT INTO safety_incidents VALUES ('b233b0b465e0a3e053bbb3b7717435de96ea7b45', 'CPSC', '2025-04-10', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'E-Bully Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled ATVs immediately and contact Lil Pick Up for a free repair from an authorized repair shop.', '25218');
INSERT INTO safety_incidents VALUES ('30a51c12dcd56819f2b8a40334c57f7978b3d584', 'CPSC', '2025-04-10', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Kentfield Solid Wood Eight-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate Performance Requirements Of The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled Kentfield Dressers immediately and contact Modus for a free repair kit and the option to request free in-home installation of the kit. Modus Furniture is contacting all known purchasers directly.', '25217');
INSERT INTO safety_incidents VALUES ('96c5a5de9880b590b0eb4f6d31e7f96291218ee3', 'CPSC', '2025-04-10', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Multifunctional Puzzle Crab Toys', 'The Recalled Magnetic Multifunctional Puzzle Crab Toy Set Violates The Mandatory Federal Regulation For Magnet Toys, Posing An Ingestion Hazard. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled Multifunctional Puzzle Crab Toy immediately, keep it away from children and contact JinJiang Baimei to receive a pre-paid label to return the recalled magnetic pieces for a full refund. JinJiang Baimei and Walmart.com are notifying all known purchasers directly.', '25221');
INSERT INTO safety_incidents VALUES ('1a0ca71931f434f7508c81611c9f605d76c6c30d', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Foldable Travel Hair Dryers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately unplug and stop using the recalled hair dryers and contact AliExpress to receive a full refund. Consumers will be asked to destroy the hair dryer by cutting the cord and disposing of it. Consumers must send a photo of the destroyed hair dryer to us_product_recall@aliexpress.com or by replying to the recall email sent by AliExpress. AliExpress is contacting all known purchasers directly.', '25209');
INSERT INTO safety_incidents VALUES ('279312c60ab40345fd528a9747795aa0b64f7fa0', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'LVOE Hair Dryers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately unplug and stop using the recalled hair dryer and contact AliExpress to receive a full refund. Consumers will be asked to destroy the hair dryer by cutting the cord and disposing of it. Consumers must send a photo of the destroyed hair dryers to us_product_recall@aliexpress.com or by replying to the recall email sent by AliExpress. AliExpress is contacting all known purchasers directly.', '25211');
INSERT INTO safety_incidents VALUES ('4ad4bd9e138b5e79bc702ef5b6ee704d564f6532', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Mini Travel Hair Dryers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately unplug and stop using the recalled hair dryer and contact AliExpress to receive a full refund. Consumers will be asked to destroy the recalled hair dryer by cutting the cord and disposing of it. Consumers must send a photo of the destroyed hair dryer to us_product_recall@aliexpress.com, or by replying to the recall email sent by AliExpress. AliExpress is contacting all known purchasers directly.', '25210');
INSERT INTO safety_incidents VALUES ('65ca3755114b008615e4444872157464b31d4645', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Ashland 10-inch and 14-inch two-bar casement window hinge tracks', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received two reported incidents involving a window sliding arm becoming disengaged from the hinge tracks. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should leave windows in the closed and locked positions and immediately contact AmesburyTruth to coordinate a free window inspection by a professional, who will install free replacement hinge tracks for those with a manufacturing defect.', '25212');
INSERT INTO safety_incidents VALUES ('86082e852a1983b7542a6f4415329aca691c0ab2', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'DEWALT 70,000 BTU Outdoor Portable Cordless Forced Air Propane Heaters', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 11 reports of overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled heaters and contact Enerco to request new instructions and a warning sticker describing how to start the heater using the power button. The new instructions and warning sticker are also available via Enerco''s website at https://www.enercogroupinc.com/recall. Enerco and Lowe''s are contacting all known purchasers directly.', '25203');
INSERT INTO safety_incidents VALUES ('379ce41f9b3dc7b674993b28eba7909c56961918', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Room2Room LED Iridescent Bear Lights', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 28 reports of the USB cord overheating and melting, including six reports of burns to fingers. There were also two reports of property damage, including burns to a wall and a headboard.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled lights and either return them to any Five Below store or contact Five Below customer service for a full refund. Consumers can receive a refund to the original credit card used for purchase, cash, or store credit when they return the lights to the store where purchased, or a check or store credit from Five Below customer service when they submit a photo of the light with the cord cut. Consumers should then dispose of the light in their household trash. Proof of purchase (receipt) is not required to receive a full refund.', '25204');
INSERT INTO safety_incidents VALUES ('8115089a4b282015d730adc96870d91e2efa69da', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Accessory Heaters for Model Years 2022-2024 Honda Pioneer 1000, 2023-2025 Pioneer 700, and 2022-2024 Honda Talon 1000 Side-by-Side vehicles', 'Fire', 'Flammability / Overheating', 'Burns', 'Honda has received three reports of the recalled accessory heaters overheating, including two incidents resulting in fires and vehicle damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled accessory heaters immediately and contact an authorized Honda Powersports dealer to schedule an appointment for a free repair. Honda is contacting all known purchasers directly.', '25207');
INSERT INTO safety_incidents VALUES ('08348a08aa3f55907760217613ae8fb4c7461794', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'HONEYJOY Convertible and Foldable High Chairs', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled high chairs and contact HONEYJOY to register for a full refund. Consumers should remove the seat, write "RECALLED" in large letters on the front and rear of the seatback using a marker, and email a photograph of the defaced product to honeyjoyrecall@hotmail.com to obtain a full refund. Consumers will need to follow disposal instructions provided by HONEYJOY. HONEYJOY and Amazon are contacting all known purchasers directly.', '25206');
INSERT INTO safety_incidents VALUES ('e8b4434ebc2a41cdc425a1e96991e54b21d91c6c', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Model Year 2022-2025 RZR Pro R and RZR Pro R 4 Recreational Off-Road Vehicles (ROVs)', 'Injury', 'Other', 'Not Specified', 'The firm has identified two vehicles with missing fasteners and one vehicle with a fastener that was not tightened. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ROVs and contact an authorized Polaris dealer to schedule a free inspection and repair at the dealer''s location. Polaris advises that consumers may continue to operate the recalled ROVs prior to inspection and repair at the dealer, but only if they conduct an inspection by following the ROPS Fastener Verification Instructions located on the firm''s website, and if the consumer finds the fasteners on the vehicle''s ROPS pillar joints are secure and in place while they are waiting for the repair to be completed at the dealer. Polaris is contacting registered owners directly.', '25208');
INSERT INTO safety_incidents VALUES ('991d9f619950750ad1f2b5c53ef3749c2bf09493', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Vivitar Blender Bottles', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received one report where the consumer was able to remove the bottle from the base while the blades were engaged. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled blender bottles and contact Sakar for instructions on how to receive a full refund in the form of a $5 Target gift card or a check, and a pre-paid return shipping label. The recalled blender must be returned to Sakar to receive the refund. Proof of purchase (receipt) is not required. Consumers should not return the recalled units to Target stores. Sakar is contacting all known purchasers.', '25214');
INSERT INTO safety_incidents VALUES ('fc88c29e61089b52b4244587071665f6bb682e06', 'CPSC', '2025-04-03', 2025, '2025-04', 'USA', 'United States', '', 'Other', 'Superb Sports Baby Bath Seats', 'Injury', 'Instability / Fall Risk', 'Drowning', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled bath seats immediately, and contact DualOranges Store via email at info@dualoranges.com for information on how to dispose of the product and submit a photograph to obtain a full refund. DualOranges Store and Amazon are contacting all known purchasers directly.', '25205');
INSERT INTO safety_incidents VALUES ('682050c017e378081c983e6d01451679e51f85d6', 'CPSC', '2025-03-27', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'APOTHEKE''s Pumpkin Ginger 3-Wick Scented Candles', 'Fire', 'Sharp Edges / Points', 'Laceration / Cut', 'APOTHEKE has received six reports of the candle''s flames burning too high; four resulting in minor property damage, including singed surfaces and one minor burn to a consumer''s hand.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles and contact APOTHEKE to receive a full refund in the form of an APOTHEKE online store credit or a check. Crate & Barrel is contacting all known purchasers directly. After the refund request is submitted, candles should be immediately discarded.', '25199');
INSERT INTO safety_incidents VALUES ('592ef3f4e6550a78c58f1c9a4fe564a9224871cf', 'CPSC', '2025-03-27', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'George Oliver Dressers', 'Low Risk', 'Entrapment', 'Entrapment', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not properly anchored to a wall and place them in an area that children cannot access. Contact Pliman for instructions to receive a full refund. Consumers should write "RECALL" on the dressers using a permanent marker, disassemble them and submit a photo of the disposed product to plimangeorgeoliver@gmail.com. Pliman and Wayfair are contacting all known purchasers directly.', '25202');
INSERT INTO safety_incidents VALUES ('f892b7d049f7a11e7e95d5ebd014eb2771fc0fe0', 'CPSC', '2025-03-27', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Children''s Steel Utility Bunk Beds', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should disassemble the bunk beds immediately until repaired. Contact Interior Resources for disassembly instructions and to receive a free repair kit, including shipping, and to schedule the free installation of the repair kit by a professional, when it becomes available from the manufacturer. The repair kit will reduce the spacing between the guardrail and end support and the spacing around the mattress supports. Interior Resources has contacted all known purchasers directly.', '25705');
INSERT INTO safety_incidents VALUES ('ca48c7cf30c74014e4590632de7223f2f691b723', 'CPSC', '2025-03-27', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Cra-Z-Art Gemex/Gel2Gem Jewelry Kits', 'The Recalled Jewelry-Making Kits Contain A Resin That, When Liquid, Can Cause Skin, Eye And Respiratory Irritation Or Sensitization When Inhaled, Touched Or Ingested. The Resin Contains An Acrylate (Hydroxyethylmethacrylate "Hema") In Amounts Prohibited In Children''S Products By The Federal Hazardous Substances Act. Already Created Jewelry Should Be Inspected To Confirm It Is Fully Cured. If There Is Liquid Or Any Liquid Residue Present, The Jewelry Should Not Be Worn And Should Be Stored Away From Children. Once Cured, The Resin No Longer Presents The Hazard.', 'Chemical / Toxic Substance', 'Respiratory', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the jewelry making kits immediately and contact LaRose Industries for a full refund. LaRose is contacting all known purchasers directly.', '25197');
INSERT INTO safety_incidents VALUES ('915bd541aea40528e6b3007d687c4bf83f9e5110', 'CPSC', '2025-03-27', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'LINKCOO Blackout Roller Window Shades', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled window coverings, cut their cord and contact LINKCOO to receive a free repair, consisting of a replacement operating cord device. Consumers will be asked to send a photo of the recalled product with the operating cord cut to recalllinkcoo@163.com. Once the firm receives the photo, consumers will be sent a replacement short operating cord with installation instructions. Amazon is contacting all known purchasers directly.', '25198');
INSERT INTO safety_incidents VALUES ('918b511eb9bb0edd6ed8dad271faf9909a06c0d5', 'CPSC', '2025-03-27', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'NFH Iron SAP, NFH Heme Iron SAP and NFH Prenatal SAP bottles', 'The Recalled Dietary Supplements Contain Iron, Which Must Be In Child-Resistant Packaging, As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Is Not Child-Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately secure the recalled supplement bottles out of sight and reach of children, and contact NFH for information on how to obtain a free replacement child-resistant bottle. NFH is contacting all known purchasers directly. This recall only includes the bottle.', '25201');
INSERT INTO safety_incidents VALUES ('24c5ea1d6f132d078bed228e332c5ecddcc3e14f', 'CPSC', '2025-03-27', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Specialized Vado and Como IGH E-Bikes with Chain Guards', 'Falls', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the Specialized Vado and Como IGH e-bikes and contact their nearest authorized Specialized retailer for a free installation of an updated protective chain/belt guard. Specialized Bicycle is contacting all known purchasers directly.', '25200');
INSERT INTO safety_incidents VALUES ('b97394a80fb6b10ae744f365b308a22bd666e3c2', 'CPSC', '2025-03-20', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Aiper Seagull Pro ZT6001 cordless robotic pool cleaners', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 19 reports of the recalled pool vacuums melting, smoking or catching on fire while charging causing five incidents of property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pool vacuums and contact Aiper to receive a free replacement Aiper Scuba S1 robotic pool cleaner. Aiper will provide a free return label for consumers to send the recalled product back to Aiper. Within 15 days of receiving the recalled Seagull Pro, Aiper will ship the replacement product. Aiper is contacting all known purchasers directly.', '25187');
INSERT INTO safety_incidents VALUES ('3e8e51daeaf0045ded4f48a6e8d70794992f2261', 'CPSC', '2025-03-20', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Benadryl Liquid Elixir, 100 mL bottles', 'The Benadryl Contains Diphenhydramine, Which Must Be In Child-Resistant Packaging As Required By The Poison Prevention Packaging Act. The Packaging Of The Products Is Not Child-Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately secure the Benadryl out of the sight and reach of children and contact Arsell for a full refund. Consumers will be asked to submit their Amazon order number and a photo demonstrating disposal of the recalled Benadryl to recall@arsellsupport.com. Only the bottle is being recalled, not the medicine itself, but both should be disposed of. All known purchasers are being contacted directly.', '25194');
INSERT INTO safety_incidents VALUES ('1e557f4ce541db75fb0f540eae7e49b2fa884fdd', 'CPSC', '2025-03-20', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Model Year 2025 Ski-Doo and Lynx snowmobiles equipped with a 600R E-TEC, 850 E-TEC or 850 E-TEC Turbo R engine', 'The Engine Control Module (Ecm) Lower Mount Support Could Have Broken In Production And Left A Loose Part Inside The Engine Compartment, Allowing It To Enter The Throttle Body Area And Lead To A Stuck Throttle. This Poses A Crash Hazard And Risk Of Serious Injuries Or Death.', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received four reports of a stuck throttle. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact a BRP dealer to schedule a free appointment. Dealers will inspect the ECM and the throttle body area to look for any ECM lower mount support broken part. If found, dealers will remove the detached part and replace the ECM free of charge. BRP is contacting all known purchasers.', '25188');
INSERT INTO safety_incidents VALUES ('4f69a1300e17f0ebbcec5cb6b1852f03a590954b', 'CPSC', '2025-03-20', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'GIKPAL 10 Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate Performance And Labeling Requirements Of The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if they are not properly anchored to a wall and place them in an area that children cannot access. Contact ONME Direct for instructions to receive a full refund and submit a photo of the consumer disposing of the product to onmeus@outlook.com. ONME Direct and Walmart are contacting all known purchasers directly.', '25192');
INSERT INTO safety_incidents VALUES ('c86d4bea745a2fb6ac06821a6cf2e1b7fd9edcf4', 'CPSC', '2025-03-20', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Kimpex Ski and Adaptor Kits', 'Injury', 'Mechanical Failure', 'Skin Irritation', 'The firm has received two reports of the skis falling off snowmobiles. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using snowmobiles equipped with the recalled Kimpex ski kits and adaptor kits, and contact a Kimpex dealer for a free repair kit.', '25186');
INSERT INTO safety_incidents VALUES ('43a4aa240cbf269b2c860c7d69d1e43d88acdf6b', 'CPSC', '2025-03-20', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Segway Ninebot Max G30P and Max G30LP KickScooters', 'Falls', 'Sharp Edges / Points', 'Fracture / Blunt Trauma', 'Segway has received 68 reports of folding mechanism failures, including 20 injuries to include abrasions, bruises, lacerations and broken bones.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled scooters and contact Segway to receive information to determine whether the folding mechanism needs adjustment and to receive a free maintenance kit. The kit includes tools and instructions for checking and tightening the folding mechanism and keeping it properly maintained.', '25193');
INSERT INTO safety_incidents VALUES ('30f648aeadbb3149b475e939047a0a2d52138a59', 'CPSC', '2025-03-20', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Bella Pro Series and Cooks Steam Espresso machines', 'Burns', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 18 reports of the handles ejecting, eight of which reported burn and/or laceration injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled espresso machines and contact Sensio for a refund.', '25191');
INSERT INTO safety_incidents VALUES ('799b0061a34cd6b0c7f388edf91d5150905604dd', 'CPSC', '2025-03-20', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'FitRx SmartBell XL Quick-Select 10-90 lbs. Adjustable Dumbbells', 'Weight Plates Can Dislodge From The Dumbbell Handle During Use, Posing An Impact Hazard To Consumers.', 'Other', 'Fracture / Blunt Trauma', 'There have been more than 60 reports of weight plates dislodging during use, which have been linked to at least seven injuries, including bruises, contusions and abrasions.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled adjustable dumbbells and contact Tzumi Electronics for a free repair consisting of a new dumbbell handle and storage tray.', '25184');
INSERT INTO safety_incidents VALUES ('b9a59f182dcdf6e2ff0379be098a13d175d8b945', 'CPSC', '2025-03-20', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'VC Group MagSafe Wireless Power Pack Portable Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 19 reports of the product overheating or catching on fire, resulting in 10 minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled wireless portable power banks and contact VC Group for a free replacement power bank. To receive a replacement, consumers will be required to provide photographs of their power bank with the word "Recalled" written in permanent marker before uploading them to the firm''s website at https://velvetcaviar.com/pages/magsafe-battery-pack-recall. Consumers should dispose of the power banks in accordance with local and state regulations.', '25190');
INSERT INTO safety_incidents VALUES ('eaa0a84059a9ce6c6b49ed8fdf1fab55b58a2d1c', 'CPSC', '2025-03-20', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Woolite Delicates detergent in 50-fluid-ounce bottles', 'Environmental', 'Microbiological Contamination', 'Eye Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Woolite Delicates detergent with lot codes S24364, S24365 and S24366 and contact Reckitt for a full refund. To receive a refund, consumers should write their name and "Recalled" in permanent marker on the back of the product, then take a photo with the UPC and lot code visible, and email the photo to ConsumerCare_USA@reckitt.com. Once consumers receive their refund, they should dispose of the product by closing the bottle tightly and placing it in household trash. Do not empty the product prior to disposal. Do not attempt to recycle the product bottle.', '25189');
INSERT INTO safety_incidents VALUES ('3cc23a259f9f77c0e83f91134952ae6c1d0f60fd', 'CPSC', '2025-03-13', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'BD Vision Climbing Harness', 'Injury', 'Instability / Fall Risk', 'Eye Injury', 'Black Diamond has received one report involving the harness waist belt failing. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled BD Vision harnesses and contact Black Diamond for a full refund (in the form of a credit card reimbursement) or a one-time-use $200 credit, which can be used at a Black Diamond store or on the Black Diamond website. Contact Black Diamond for a pre-paid shipping label to return the recalled harness. Black Diamond is contacting all known purchasers.', '25181');
INSERT INTO safety_incidents VALUES ('334b24b1c68b8e9a191e9170f374aa27143e3df9', 'CPSC', '2025-03-13', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'BMC-branded Kaius 01 bicycles and framesets', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'BMC has received two reports of the V5 fork steerers separating from the bicycle frame. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact an authorized BMC dealer for a free inspection and a free replacement of the forks. BMC is contacting all known purchasers directly.', '25177');
INSERT INTO safety_incidents VALUES ('f85f51316a06c50b4f7cefb9fef6b9469a9b3608', 'CPSC', '2025-03-13', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Silicone Rosary and Decade teethers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received 92 reports of the safety snap clasp detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled teethers and contact Chews Life to receive a free repair. Consumers will be provided with a prepaid shipping label to return the recalled teethers to Chews Life. Chews Life will mail consumers the repaired teethers at no charge.', '25180');
INSERT INTO safety_incidents VALUES ('3002d55eeef72a318b9a72a0ce914b48cfbfb283', 'CPSC', '2025-03-13', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Gerolsteiner 750ml Sparkling Water Bottles', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Gerolsteiner sparkling water bottles, and return the bottles from the affected lots to the store where they were purchased for a full refund. Consumers will not be asked for proof of purchase, but will need to return the recalled bottle to receive a refund (in the form of cash or credit).', '25183');
INSERT INTO safety_incidents VALUES ('933f8429c16805f2006e5e646c6fd06fe5311fe5', 'CPSC', '2025-03-13', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Konwin Desktop Heaters', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm received eight reports of fans burning and melting. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled desktop heaters and return them to any Meijer store for a full refund through the original form of payment.', '25179');
INSERT INTO safety_incidents VALUES ('451d08220473d2c3330f3069d855c89f108a6571', 'CPSC', '2025-03-13', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Onasti Toddler Tower Stools', 'Injury', 'Mechanical Failure', 'Fall Injury', 'Blissful-Time has received four reports of the stool collapsing or tipping over, including two injuries, with one causing bruising and the other a brain injury to a toddler.', 'Moderate', 1, 0, 'Consumers should stop using the recalled stools and store them away from children until repaired. Contact Blissful-Time to receive a free repair kit, including shipping. The repair kit consists of two steps, one base, and one guardrail. Blissful-Time is contacting all known purchasers directly.', '25182');
INSERT INTO safety_incidents VALUES ('adefd654ea26b74aa929e3f8da037b071013865a', 'CPSC', '2025-03-13', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Retractable Safety Gates', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled gates immediately and contact HabiLife Direct for a full refund. Consumers will be asked to destroy the gates by cutting the mesh and disposing of the gates. Consumers must send a photo of the destroyed gates to service@hblife.fans. HabiLife Direct and Amazon are contacting all known purchasers directly.', '25178');
INSERT INTO safety_incidents VALUES ('b0960794a1b11db82920d5d9ba1b4865ebb34e1a', 'CPSC', '2025-03-13', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Sublue Mix underwater scooters and replacement batteries (black batteries only)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Sublue has received 161 reports of thermal and swelling incidents involving the lithium-ion batteries, including eight reports of fire, one report of injury, and two reports of property damage totaling $651,400.', 'Moderate', 1, 0, 'Consumers should stop using the scooters with the recalled batteries immediately and contact Sublue for a free new generation battery replacement (gray battery). Sublue will provide a battery collection kit for the consumer to return the recalled battery and will provide the replacement battery upon return of the recalled battery. Note: Do not throw this recalled battery in the trash or in used battery recycling boxes found at various retail and home improvement stores. Recalled lithium-ion batteries should be disposed of in accordance with any local and state ordinances, following the procedures established by municipal recycling centers for damaged, defective, or recalled lithium batteries, because these potentially hazardous batteries must be handled differently than other batteries.', '25169');
INSERT INTO safety_incidents VALUES ('3e6144a98ff19da241cc0d6579bbbf4e5162932d', 'CPSC', '2025-03-06', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'BD Recon LT Avalanche Transceivers', 'Injury', 'Mechanical Failure', 'Not Specified', 'The firm has received six reports of the switch mechanism malfunctioning due to corrosion. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled avalanche transceivers and contact Black Diamond for a full refund, a replacement transceiver, or a free repair. Consumers will not be asked for proof of purchase and will receive a pre-paid shipping label to return the recalled transceivers. Black Diamond is contacting all known purchasers. Consumers should go to https://warranty.bdel.com/beaconRecall2025/StepOne to participate in the recall. The repair involves replacing the original zinc coated steel insert with a corrosion resistant stainless-steel version. The replacement option allows the consumer to exchange their BD Recon LT avalanche transceiver for a BD Guide BT or BD Recon X avalanche transceiver. Both the BD Guide BT and BD Recon X transceivers utilize a different switch design. Consumers also have the option to return their device for a full refund (credit card reimbursement).', '25167');
INSERT INTO safety_incidents VALUES ('6f8e830bdb6c4204b25040b44cd039b54d13ca7c', 'CPSC', '2025-03-06', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Marie-Chantal Children''s Nightgowns, Pajama Sets and Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately take the recalled children''s garments away from children, stop using them and contact Marie-Chantal for a full refund. Consumers will be asked to destroy the garments by cutting them in half and disposing of them according to local and state recycling guidelines. Consumers should send a photo of the destroyed garment to recall@mariechantal.com to get the refund. Marie-Chantal is contacting all known purchasers directly.', '25168');
INSERT INTO safety_incidents VALUES ('3346cb5e9478d6911bd5871232559c2a7914476d', 'CPSC', '2025-03-06', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Lolanta Children''s Bathrobes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bathrobes, take them away from children, and contact Nanchang Zhongcangjishi E-commerce for a full refund. Consumers will be asked to destroy the garments by cutting them in half and emailing a photo of the destroyed garment to business@lolanta.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Amazon and Nanchang Zhongcangjishi E-commerce are contacting all known purchasers directly.', '25171');
INSERT INTO safety_incidents VALUES ('82cfcd69ef7f6ef945759fcf412ef98a85e127a6', 'CPSC', '2025-03-06', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Love Our Home Braided Crib Bumpers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using and remove the recalled crib bumpers from the crib. To receive a full refund, consumers should cut the crib bumper in half, take a photo of it, and email the photo to loveourhomerecall@163.com. Love Our Home is contacting all known purchasers directly.', '25172');
INSERT INTO safety_incidents VALUES ('5aecea0d604570debfb3e1ba2310ee907e9b191c', 'CPSC', '2025-03-06', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Nuby Stroller Fans', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Luv n'' care has received seven reports of children''s fingers accessing the fan blade, resulting in six laceration injuries.', 'Moderate', 1, 0, 'Consumers should stop using the stroller fan immediately and contact Luv n'' care for information on how to return the product to obtain a free replacement. Luv n'' care is contacting all known purchasers directly.', '25160');
INSERT INTO safety_incidents VALUES ('ee401729dabbdb677ae58aa1c033a271b4d7647c', 'CPSC', '2025-03-06', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Auto World Unassembled Deluxe Pit Kit Slot Cars', 'The Recalled Unassembled Deluxe Pit Kit Slot Cars Violate The Mandatory Federal Regulation For Magnets Because The Magnets Used To Power The Car Are Loose Prior To Assembly, Posing An Ingestion Hazard To Children. Assembled Models Do Not Pose This Risk And Are Therefore Not Subject To This Recall. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should keep the recalled, unassembled Deluxe Pit Kit slot cars away from children and contact Round 2 to receive a pre-paid label to return the recalled slot cars for a full refund. Round 2 is notifying all known purchasers directly.', '25170');
INSERT INTO safety_incidents VALUES ('16b6339de76fcac43a9c0410c1aa367b546677a3', 'CPSC', '2025-03-06', 2025, '2025-03', 'USA', 'United States', '', 'Other', 'Phosphate Reagent #1 Bottles sold within the Taylor Phosphate Test Kits', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the recalled Phosphate Reagent #1 bottles immediately, place them in a safe and secure location away from the reach of children and contact Taylor Water Technologies for information on how to properly dispose of the recalled bottle and obtain a free replacement bottle. Only unexpired Phosphate Reagent #1 bottles are included in this recall and eligible for the free replacement. Taylor Water Technologies is contacting all known purchasers directly.', '25173');
INSERT INTO safety_incidents VALUES ('bfb0f24840b444d984611f2ad3d09cdd0365591b', 'CPSC', '2025-02-27', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'ARVA Neo BT Pro Avalanche Transceivers', 'Injury', 'Mechanical Failure', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled device and contact NIC IMPEX ARVA CORP. for a free inspection and repair. The firm will give consumers a shipping label to return the recalled transceiver.', '25164');
INSERT INTO safety_incidents VALUES ('a5fd079f68459540bc579fdc642e5e5b80e40350', 'CPSC', '2025-02-27', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Canyon Speedmax CF Triathlon Bicycles', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact a Canyon Authorized Service Partner to schedule a free repair. The repair will include removal and inspection of the fork steerer tube, a fork replacement, if needed, and preventative reinforcement of the clamping area of the fork steerer tube. Canyon is contacting all known purchasers directly.', '25156');
INSERT INTO safety_incidents VALUES ('3e5ac42160fb2db6ab47aa7ed83cdbad9108c257', 'CPSC', '2025-02-27', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Babyjoy High Chairs', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled high chairs and contact Costway for a full refund and instructions on how to return or dispose of the high chairs. Consumers can return the product by receiving a prepaid shipping label or provide photos of the destroyed product to recall@costway.com. Upon receipt of the returned product or photos of the destroyed product, Costway will issue the refund. Costway is contacting all known purchasers directly.', '25166');
INSERT INTO safety_incidents VALUES ('bf470ea49a10eb2b8679ce759c76ebb8772f2859', 'CPSC', '2025-02-27', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Forever 21 Children''s Pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the recalled pajamas immediately and contact Forever 21 for a full refund. Consumers will be asked to destroy the pajamas by cutting the top and bottom pieces in half and disposing of them. Consumers must send a photo of the destroyed pajamas to recall@forever21.com. Forever 21 is contacting all known purchasers directly.', '25158');
INSERT INTO safety_incidents VALUES ('1e01f99431d044917df67db1e783b3ee36ef3d16', 'CPSC', '2025-02-27', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Goal Zero Solar Series Combiner Cables for Solar Panels', 'Fire', 'Mechanical Failure', 'Not Specified', 'The firm has received two reports of fires involving property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled products and contact Goal Zero to receive a refund of the purchase price in the original form of payment for the recalled Series Combiners. Consumers should register for a refund on the firm''s website and then discard the recalled product in the trash in accordance with any local and state ordinances.', '25159');
INSERT INTO safety_incidents VALUES ('96008a020ec7d69529789dc33f8d842e47018b3f', 'CPSC', '2025-02-27', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'TRUBLUE iQ and TRUBLUE iQ+ Auto Belays', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 109 reports of incidents of slow retraction, including one injury involving the auto belay not retracting, resulting in a fractured leg.', 'Fatal', 1, 0, 'Consumers should immediately stop using recalled auto belay devices and contact Head Rush Technologies for a free onsite inspection and repair.', '25165');
INSERT INTO safety_incidents VALUES ('2a2fdf7fe30723df304ff4170f53f7dda1577d97', 'CPSC', '2025-02-27', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Ellerbeck Wall Sconces', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Minor', 1, 0, 'Consumers should inspect their wall sconce and confirm that the product is installed as a plug-in fixture without an electrical box. Upon confirmation, consumers should immediately unplug and stop using the recalled sconces and visit www.kichler.com/legal/safety-information/recall-information-43115 to determine whether their sconce is included in this recall. If sconces are subject to this recall, consumers should complete a Contact Us webform available at www.kichler.com/customer-care/contact-us and select "Product Question" from the drop-down menu. Once contacted, Kichler will provide instructions on how to destroy the recalled product and how to provide a photograph confirming the destruction to obtain a free replacement wall sconce.', '25162');
INSERT INTO safety_incidents VALUES ('3b9ccce3c964cef475e9db3460891cf0f027edd8', 'CPSC', '2025-02-27', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'P.J. Salvage Pajama Sets and Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately take the recalled pajamas and robes away from children, destroy the garments by cutting them in half, and fill out the online registration form on the recall site www.pjsalvage.com/pages/recall-information with verification of garment destruction.', '25161');
INSERT INTO safety_incidents VALUES ('022c38e02522bd1a047f9d4b38b2a1c445b810b6', 'CPSC', '2025-02-27', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Prestige Solo, Prestige Excellence, and Aerco Esteem condensing gas boilers', 'Injury', 'Flammability / Overheating', 'Poisoning / Ingestion', 'Triangle Tube has received two reports of death due to CO poisoning associated with the recalled boilers. In 2015, a 47-year-old woman died from CO poisoning associated with a Prestige Solo 175 boiler, and in 2016, an 85-year-old man died from CO poisoning associated with a Prestige SOLO TriMax 175 boiler, following a repair. Triangle Tube has also received 25 reports of CO leaks from the recalled boilers.', 'Fatal', 1, 0, 'Consumers with recalled boilers should immediately contact Triangle Tube to schedule a free boiler inspection and, if applicable, free installation of a new boiler ignition system. Consumers who continue using the recalled boilers while awaiting repair should have working carbon monoxide alarms on each level of their homes and outside sleeping areas. Consumers who do not have a carbon monoxide alarm can contact Triangle Tube to have one shipped to them free of charge.', '25157');
INSERT INTO safety_incidents VALUES ('ea021a5a083cf565957092c90bf333f58992c8ca', 'CPSC', '2025-02-27', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Style Life Eleven Baby Loungers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled baby loungers immediately and contact Wayfair for information on how to dispose of the product to obtain a full refund. Wayfair is contacting all known purchasers directly.', '25704');
INSERT INTO safety_incidents VALUES ('4496c571b4a83a472634fb0d58f66fc84e730e7e', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Tow Behind Field and Brush Mowers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 10 reports of blade carrier detachments. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the tow behind field and brush mower and contact DR Power to arrange for a free repair of the blade carrier assembly at the dealer''s location.', '25140');
INSERT INTO safety_incidents VALUES ('ff54e4b923eafc7e28ee77377670522460f320e1', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Fjorden iPhone Camera Grips', 'Chemical', 'Chemical / Toxic Substance', 'Burns', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled camera grip immediately and place it in an area that children cannot access. Contact Fjorden Electra AS to obtain a free replacement of the button cell battery tray and instructions. Fjorden Electra AS is notifying all known purchasers directly.', '25142');
INSERT INTO safety_incidents VALUES ('93e423ab07eda8471b9bb193f6f67eac3d0c95a0', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Holosun Firearm Dot Sights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Firearm Dot Sights and place them in an area that children cannot access. Contact Holosun Technologies for instructions on receiving a free recall kit which includes a battery compartment enclosure with the required labeling and an updated instruction manual for HS503G-ACSS models. For HE512C-GD models, Holosun Technologies will provide free return shipping to install a compliant battery compartment tray and include a compliant instruction manual and new packaging. Holosun Technologies is contacting all known purchasers directly. Note: Button cell and coin batteries are hazardous. Batteries should be disposed of or recycled by following local procedures for hazardous household waste, not in the trash.', '25143');
INSERT INTO safety_incidents VALUES ('5371e711e606d15e2bb75d3c37521153613a5439', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Homebox Blackout Roller Window Shades', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately put the window blind''s cords up and away from children and contact Zhejiang Mingjing Textile to receive a free repair, consisting of a replacement operating cord device or a free replacement cordless blind. Consumers must upload a photo of the recalled product with the operating cord and curtain fabric cut at http://www.hoteamtex.net/por.jsp?id=2&_jcp=5_2. Once the firm receives a video or picture of the product with the original pull cord cut, consumers will be sent a replacement operating cord wand device with installation instructions or replacement cordless blinds through Amazon. Amazon is contacting all known purchasers directly.', '25147');
INSERT INTO safety_incidents VALUES ('1d075cbfb22fbb58a7ab6f3c3cfa2e768e4e0f27', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Kubota Utility Tractors model MX5400DTC', 'The Clutch Cable Can Break On The Recalled Mx5400Dtc Utility Tractors, Resulting In Reduced Braking Power, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'The firm has received 33 reports of the clutch breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled utility tractors and contact an authorized Kubota dealer to schedule a free inspection and a free repair at the dealer''s location. Kubota is contacting all known registered owners directly.', '25141');
INSERT INTO safety_incidents VALUES ('047aa86b1646fc0e39285b1e9411bd8211274809', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Rebecca''s Toys & Prizes Bowling Pin Sipper Cups', 'The Red Tape On The Bowling Pin Sipper Cups Contains Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled cups away from children and stop using them. Contact Nazzaro for a full refund. Nazzaro is contacting all known purchasers directly.', '25139');
INSERT INTO safety_incidents VALUES ('aa15f53764e0e48f1296acfc1f18076c028fb5f8', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'OdorStop Boot and Shoe Dryers and Deodorizers', 'Fire', 'Electrical Fault', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled OdorStop Boot and Shoe Dryers and Deodorizers and contact OdorStop to receive a free repair. OdorStop will install a new in-line fuse into the recalled products and return them to the consumer. Consumers should visit https:/OdorStop.com/recall to register for the recall and to receive instructions to obtain a free return label to return the product for a free repair.', '25152');
INSERT INTO safety_incidents VALUES ('c6f6787558f1c530730f00913d69018cba1eab33', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Sauder and Sauder Beginnings Dressers and 4-Drawer Chests tip-over restraint straps', 'The Tip-Over Restraint Straps Can Fail When Used On Certain Sauder Clothing Storage Units (Dressers And 4-Drawer Chests) To Prevent Tip-Over Incidents, Posing Tip-Over And Entrapment Hazards That Can Result In Death Or Serious Injuries To Children.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately check if their clothing storage unit has a date of manufacture sticker on the back of the unit, between July 2020 and August 2023. If so, consumers should contact Sauder to arrange for a free replacement tip-over restraint kit to be mailed to the consumer at no cost. Consumers should remove the old tip-over restraint and install the new one once received. Keep children away from the unit while waiting for a replacement tip-over restraint kit.', '25146');
INSERT INTO safety_incidents VALUES ('24a41f6fd73c6f039d840f6948cf3bdb11d4631f', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'SEJOV Five-Drawer Dressers', 'Low Risk', 'Entrapment', 'Entrapment', 'The firm has received two reports of the dressers being unstable. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should stop using the recalled dressers immediately if they are not properly anchored to a wall and place them in an area that children cannot access. Contact SEJOV for instructions to receive a full refund and submit a photo of the consumer disposing of the product. Amazon is contacting all known purchasers directly.', '25145');
INSERT INTO safety_incidents VALUES ('2a04554efe97a90ab104da83e2204ab8aef7dc38', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'ShadesU Roller Window Shades', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately put the window blind cords up and away from children and contact Shadeks for instructions to return the shades for a free repair. Shadeks will remove the long operating cord and update the shades to a cordless design. Consumers will need to provide their contact information and address to receive a free shipping label. Amazon is contacting all known purchasers directly.', '25151');
INSERT INTO safety_incidents VALUES ('fcc0d28afcbbfd06ca2fdbbcf0724678d4b3ed2f', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Model Year 2024 Z Miami SE and Z Adventure Core Electric Bicycles', 'Injury', 'Other', 'Skin Irritation', 'The firm has received 21 reports of loose retaining pins and/or related brake failure, resulting in one minor injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled e-bikes and contact the firm for a free repair kit. Consumers will receive a new retaining pin and up to $50 toward the cost of the professional installation of the new pin. Consumers will be asked to send a copy of their installation receipt to Super73 for reimbursement of the installation cost. Super73 and its retailers are contacting all purchasers directly.', '25149');
INSERT INTO safety_incidents VALUES ('ca88525a87fd56becd18b782bda82c7abeb80475', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'SuperATV carrier bearings for Polaris RZR XP Turbo or Turbo S Recreational Off Highway Vehicles (ROVs)', 'Fire', 'Flammability / Overheating', 'Burns', 'SuperATV has received 24 reports of the fuel tank contacting the prop shaft, including 19 reports that a hole or crack had formed in the fuel tank, including one reported fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using ROVs with the recalled carrier bearings, remove them from the Polaris RZR XP Turbo or Turbo S vehicles, and register online at https://form.jotform.com/243023918871055 to receive a postage-paid label to return the recalled bearings. SuperATV will mail consumers free replacement carrier bearings upon receipt of the recalled carrier bearings. SuperATV is notifying all known purchasers directly. No purchase receipt is required.', '25150');
INSERT INTO safety_incidents VALUES ('86283d1452892286534bfd4b7609e2da110643bd', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Electra E-bikes', 'The Rear Fender Can Come Loose And Can Contact The Rear Wheel And Stop The Bike Unexpectedly, Causing The Rider To Lose Control Of The Bike, Posing A Crash Hazard.', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received two reports of the rear fender coming loose and making contact with the rear wheel, including one injury that involved a fractured shinbone, meniscus tear and scrapes.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Electra e-bikes and contact an authorized Trek or Electra retailer to receive a free repair to replace the rear fender bolts. Trek is contacting all known purchasers directly.', '25137');
INSERT INTO safety_incidents VALUES ('8955a5ed5f28d6f61b6838657f126a1b02d7a6bf', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Triumph TF250-X Closed Course Competition Motorcycles', 'Injury', 'Electrical Fault', 'Not Specified', 'The firm has received 16 incident reports of the switch cube cracking. Seven of those resulting in the motorcycle starting unexpectedly. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled off-road motorcycles, disconnect the battery and contact an authorized Triumph Motorcycle dealer for a free repair, including the free replacement of the right-hand switch cube. Triumph Motorcycles America is contacting all known purchasers directly.', '25144');
INSERT INTO safety_incidents VALUES ('14181cbcb13d148c454fd832ebb701ebfb19fc53', 'CPSC', '2025-02-20', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Swagtron SG-5 Swagger 5 Boost Commuter Electric Scooters', 'Fire', 'Flammability / Overheating', 'Burns', 'There have been seven reports of the lithium-ion batteries in the electric scooters overheating, smoking, melting or igniting, with one ignition resulting in a fire, causing a burn injury and substantial property damage to a residential apartment building.', 'Fatal', 1, 0, 'Consumers should immediately stop using and charging the recalled electric scooters, cut the throttle cord, and dispose of the entire product following local and state hazardous waste disposal procedures. Consumers who purchased their electric scooters from Walmart or Sam''s Club will receive an email with instructions on how to receive a full refund.', '25138');
INSERT INTO safety_incidents VALUES ('02ec1999783b5ac551df4970d3ea5862b2256bd4', 'CPSC', '2025-02-13', 2025, '2025-02', 'USA', 'United States', '', 'Other', '6-in-1 Pounding Games', 'The Recalled 6-In-1 Pounding Game Violates The Mandatory Federal Regulation For Magnets Because It Contains A Magnet That Can Become Loose, Posing An Ingestion Hazard To Children. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled pounding games immediately and take them away from children. To receive a full refund, please dispose of the product so it is out of the reach of children, take a photo of the disposal, and send it to DMITOY via email at dmitoy202405@163.com or message it to DMITOY on Temu.com. DMITOY is notifying all known purchasers directly.', '25134');
INSERT INTO safety_incidents VALUES ('1f408441ec8f89fe7a08573d1cdf4d79d1fba8d8', 'CPSC', '2025-02-13', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Youth Solitude Jackets', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately take the recalled jackets away from children and remove the drawstrings to eliminate the strangulation hazard. Consumers can either return the jacket to AFTCO for a full refund or upload a photo of the jacket without the drawstring and receive a $25 gift card. Consumers should go to www.aftco.com/recall to participate in the recall. AFTCO is contacting all known purchasers.', '25135');
INSERT INTO safety_incidents VALUES ('827cd0b7206b7e7116e8c1d6b7b2265d238f3c28', 'CPSC', '2025-02-13', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Igloo 90 Qt. Flip & Tow Rolling Coolers', 'The Tow Handle Can Pinch Consumers'' Fingertips Against The Cooler, Posing Fingertip Amputation And Crushing Hazards.', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 12 reports of fingertip injuries, including fingertip amputations, bone fractures, and lacerations.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled coolers and contact Igloo for a free replacement handle.', '25136');
INSERT INTO safety_incidents VALUES ('391c541edc3d73c893c84c886086e5cf92ad5b76', 'CPSC', '2025-02-13', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Multi-Mode Sleep Lamps', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled portable lamps and contact BlockBlueLight to request a full refund in the original form of payment, a store credit or a free replacement lamp. Consumers should dispose of the recalled portable lamps in accordance with local and state regulations.', '25132');
INSERT INTO safety_incidents VALUES ('64ab902cb31a3dbb12351d51c09a8d6620cdf818', 'CPSC', '2025-02-13', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'LoGest Climbing Ropes with Carabiners and LoGest Climbing Ropes with Heavy-Duty Metal Hooks', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'LoGest has received 13 reports of the recalled ropes breaking, including one report of a fall that resulted in a severe spinal cord injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the climbing ropes, uninstall them, and register for a full refund at www.LoGestRopeRecall.com. Consumers will receive a form to sign as part of the disposal of the climbing ropes. Consumers must follow the disposal directions on the form and email a photo of the disposed rope to LoGestRecall@gmail.com to receive their refund. Full refunds will be issued via Amazon to the original form of payment associated with the order. Amazon is contacting all known purchasers directly.', '25130');
INSERT INTO safety_incidents VALUES ('ecb127bce3921e97a83f905ca253ccbc1835057b', 'CPSC', '2025-02-13', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'SHEIN EVRYDAY Kids'' Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear away from children and stop using them, and contact SHEIN for a full refund. SHEIN is contacting all known purchasers directly.', '25131');
INSERT INTO safety_incidents VALUES ('e60753439176b32933a135b99b9ab775493f2e6e', 'CPSC', '2025-02-13', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Spritz Taper Resin Hanukkah Dino Menorahs', 'Fire', 'Flammability / Overheating', 'Burns', 'Target has received 58 reports of the menorahs scorching, charring, melting or catching on fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled menorahs and return them to any Target store for a full refund in the form of a Target gift card or refund in the original form of payment. Consumers may also contact Target to receive a prepaid return label to return the menorah by mail.', '25133');
INSERT INTO safety_incidents VALUES ('372243ae896170419b099c19830a8ef7e4a903ee', 'CPSC', '2025-02-13', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'T4E TR50 Air Pistols', 'The Co2 Cartridge Can Be Unintentionally Ejected With Force From The Handle, Posing An Impact Hazard.', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 30 reports of the CO2 cartridge unintentionally ejecting with force, including seven reports of injury, such as fractured hands, broken fingers and contusions.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled air pistols and contact Umarex to register for a free replacement air pistol and free shipping to return the recalled product.', '25119');
INSERT INTO safety_incidents VALUES ('a1f66a000c07bfad4b21d32271be010839856122', 'CPSC', '2025-02-06', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Ariens® DELUXE-, PLATINUM- and PROFESSIONAL-series Snow Throwers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled snow throwers and contact Ariens Company or an authorized dealer for a free repair at their local dealership. Ariens Company and its authorized dealers will confirm whether a unit has already been inspected and/or repaired and will perform all necessary repairs on affected units.', '25124');
INSERT INTO safety_incidents VALUES ('7e8097b3e49b0aa3fddd84962c36c6c9a1a44c36', 'CPSC', '2025-02-06', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Bobcat & Steiner AirFX Finish Mower Deck attachments', 'The Recalled Mower Decks Cannot Be Secured In The Upright Or Tilted Position By The Locking Pins During Maintenance Or Service, Posing A Crush Hazard.', 'Entrapment', 'Entrapment', 'The firm is aware of five incidents where the locking pins were unable to be installed to secure the deck in the upright or tilted position. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately inspect and determine whether locking pins can be inserted while the deck is in the upright or tilted position during maintenance or service. Contact Doosan Bobcat North America or a Bobcat dealer to obtain a free repair, which will be available in the near future. Until then, if the locking pins cannot be inserted, obtain two straps, each rated for 1,500 lbs., and wrap a strap around each front tractor axle, securing each strap to the mower deck when performing service or maintenance. Consumers should contact Doosan if they are unable to obtain straps, and straps will be provided at no cost to the consumer. Doosan Bobcat North America is contacting all known purchasers.', '25121');
INSERT INTO safety_incidents VALUES ('2c2e8dd0001dec01a4e090abb4aa15572aa0b870', 'CPSC', '2025-02-06', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'America''s Got Talent microphones', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received three reports of the lithium-ion batteries igniting, resulting in smoke and fire damage to walls and floors. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled microphones and contact Jazwares for a full refund. Consumers will receive their refund in the form of a pre-paid gift card. After registering for the recall, consumers should dispose of the microphone in accordance with local and state regulations and not in the ordinary trash.', '25125');
INSERT INTO safety_incidents VALUES ('ec5c378fefef95b8a815e91113bfef63bb8babaa', 'CPSC', '2025-02-06', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Slide-In and Freestanding Electric Ranges', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received three reports of the lithium-ion batteries igniting, resulting in smoke and fire damage to walls and floors. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should contact LG for a free warning label and placement instructions. The label reminds consumers to use the Lock Out/Control Lock function on the range control panel to disable activation of the heating elements when the range is not in use. View the LG instructional video regarding Control Lock/Lock Out feature at https://vimeo.com/1037322282. Consumers are cautioned to keep children and pets away from the knobs, to check the range knobs to ensure they are off before leaving home or going to bed, and not to leave objects on the range when the range is not in use.', '25126');
INSERT INTO safety_incidents VALUES ('cc6ffacf85bb0b3230b71cc3d154da732d4a805d', 'CPSC', '2025-02-06', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Pella Reserve and Lifestyle Sliding Patio Doors and Lifestyle Windows', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately remove the battery in the sensor from the sliding door panels and in the windows'' remote control and place them in an area that children cannot access. Contact Pella for instructions on how to receive a free replacement remote, including shipping, or to schedule a door repair by a qualified technician, free of cost. Pella is contacting all known purchasers directly.', '25120');
INSERT INTO safety_incidents VALUES ('d43abc200ff551ca62a28df507cfcd536c5e1174', 'CPSC', '2025-02-06', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Sling Carriers', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled sling carriers, take a photo of the sling carrier cut into pieces and email the photo to 1251530867@qq.com or message Sunkids Factory on Temu.com to receive a full refund. Sunkids Factory is contacting all known purchasers directly.', '25123');
INSERT INTO safety_incidents VALUES ('df0125e5d43c80541ba1ea23940a33004b5030f1', 'CPSC', '2025-02-06', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'Roll Up Window Blinds', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled window coverings and contact Thy Trading Company for a full refund. Consumers should remove the window blind, mark it with the word "Recalled", and dispose of the product in the garbage. Consumers should take a photograph of the window blind destroyed in the garbage and upload the photo to thytradingllc@outlook.com to register their product to receive a refund. Thy Trading Company is contacting all known purchasers directly.', '25128');
INSERT INTO safety_incidents VALUES ('8a4543d35aa3ae0da27dccad385227493ab0f1e0', 'CPSC', '2025-02-06', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'TravisMathew Women''s Sweatshirts and Women''s and Men''s Hoodies', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled garments immediately and contact TravisMathew for a full refund or store credit for the original purchase price. Consumers will be asked to destroy the garments by cutting them in half and disposing of them. Consumers must send a photo of the destroyed garment and sewn-in garment tag to info@travismathew.com. Upon receipt of the photo, consumers will receive a full refund or store credit at the purchase price.', '25118');
INSERT INTO safety_incidents VALUES ('3baac2fbc800266c78396dc03bd298bf9ce472ff', 'CPSC', '2025-02-06', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'RYOBI 40-Volt Brushless 21" Cordless Walk-Behind Mowers', 'Fire', 'Flammability / Overheating', 'Burns', 'TTI has received 97 reports of overheating while the mower was in use, including five reports of fires. Two minor burn injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled mower and contact TTI Outdoor Power Equipment Inc. ("TTI") for instructions on how to disable the recalled mower and receive a free replacement 21" walk-behind mower.', '25127');
INSERT INTO safety_incidents VALUES ('75fba5ea2437cde3357861a697163d7c0f3ae8d2', 'CPSC', '2025-02-06', 2025, '2025-02', 'USA', 'United States', '', 'Other', 'UVIPC Baby Gates', 'The Recalled Baby Gates Violate The Federal Safety Regulations For Expansion Gates And Expandable Enclosures. For The Versions With A Pet Door, A Child''S Torso Can Fit Through The Secondary Opening And, For The Other Versions That Are Adjustable, A Child''S Torso Can Fit Through The Opening Between The Gate Slat And Side Wall. These Violations Pose An Entrapment Hazard To Children.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled gates immediately and contact Xianshengyouli via email at xianshengyouli@outlook.com for information on how to dispose of the product and submit proof of destruction to obtain a full refund. Xianshengyouli and Amazon are contacting all known purchasers directly.', '25122');
INSERT INTO safety_incidents VALUES ('abf51d32b5cf7d30c2659679b66e20b92d2506c7', 'CPSC', '2025-01-30', 2025, '2025-01', 'USA', 'United States', '', 'Other', '6-in-1 Multi Styler and 5-in-1 Multi Styler Hair Dryers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately unplug and stop using the recalled hair dryers and contact AliExpress to receive a full refund. Consumers should destroy the recalled hair dryers by unplugging the hair dryer, cutting the cord and then send an image of the destroyed hair dryer to AliExpress. AliExpress is directly contacting all purchasers. Consumers should email the photo of their destroyed hair dryer to AliExpress by replying to the email from AliExpress about the recall. Upon receipt of the photo, AliExpress will issue the customer a full refund.', '25112');
INSERT INTO safety_incidents VALUES ('8effe1a6351ace8cbfdc850fc79f0894f5e46174', 'CPSC', '2025-01-30', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'AMX Global Portable Folding Stadium Seats', 'Injury', 'Entrapment', 'Entrapment', 'AMX Global has received five reports of the security hook breaking, including two reports of falls and one injury involving bruising, headaches and a pinched nerve.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled seats. Consumers are directed to destroy the recalled seat by cutting through the fabric of the seat and backrest. Consumers are further directed to take a photo of the destroyed recalled seat, including the consumer''s initials and the date in the photo, and send the photo to AMX Global at support@stadiumseatrecall.com to receive a full refund.', '25114');
INSERT INTO safety_incidents VALUES ('df8683427f96f8ccc51cb53de7841cfc530f3891', 'CPSC', '2025-01-30', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Cabinet Health 4 oz. Refillable Medicine Bottles', 'The Plastic Lid''S Closure Can Degrade After Repeated Openings, Causing The Lid''S Child-Resistance To Diminish, Posing A Risk Of Poisoning, If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately secure the recalled bottles out of the sight and reach of children and contact Cabinet Health for a free replacement lid. Consumers will be asked to submit a photo demonstrating the destruction of the recalled lid. Cabinet Health and Amazon are contacting all known purchasers directly. This recall does not affect the medication within the bottles.', '25110');
INSERT INTO safety_incidents VALUES ('e9fcb352debc323593a90d25ca781ee989e31f13', 'CPSC', '2025-01-30', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Cozchique, Tebbis and Beeziac Girls Pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them, and contact Tupop to receive a full refund. Consumers should destroy the garments by cutting the top and bottom in half and dispose of them. Consumers should send the recalling firm a photo of the destroyed garments by email at bzzservice@hotmail.com to receive a full refund. Tupop and Amazon are contacting all known purchasers directly.', '25113');
INSERT INTO safety_incidents VALUES ('7a7af55bdd0cb23ae273a798479bf91c7dd5b2a2', 'CPSC', '2025-01-30', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Greater Goods Digital Kitchen Scales', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately remove the battery in the digital kitchen scale and place it in an area that children cannot access. Contact Greater Goods for information on how to receive a free recall kit, which includes a new replacement battery door that can be secured to the scale, the required labeling, and an updated instruction manual. Greater Goods, Amazon and Walmart are contacting all known purchasers directly.', '25111');
INSERT INTO safety_incidents VALUES ('b18c01f7e54eab4f5ddb2f0ead6cf140a5d091d9', 'CPSC', '2025-01-30', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Matrix-brand Training Cycles', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 63 reports of seats unexpectedly lowering, including two reports that users fell off the cycle when the seat lowered. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cycles and contact Johnson Health Tech North America Inc. to schedule a service technician to install a free repair kit.', '25109');
INSERT INTO safety_incidents VALUES ('8fe60b0b0908f2ae7617b4413eff7eb45bbc89ed', 'CPSC', '2025-01-30', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Pearhead Infant Learning Toy Sets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the egg shaker immediately and contact Pearhead for information on how to return the product to obtain a free replacement and refund. Pearhead is contacting all known purchasers directly.', '25115');
INSERT INTO safety_incidents VALUES ('3dcfbbc34cec930bfed005d30ab3be933266aeb5', 'CPSC', '2025-01-23', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'ChrisDowa Roller Window Shades', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately put the window blind''s cords up and away from children and contact Shaoxingkeqiao Nenghaozhenfang to receive a free operating cord wand. Consumers must send a photo of the recalled product with the cord cut to recallchrisdowa@163.com. Once the firm receives the photo, consumers will receive a repair kit with installation instructions via Amazon or FedEx. The firm is contacting all known purchasers directly.', '25105');
INSERT INTO safety_incidents VALUES ('2cd8682ed45261eecd6b509aa842cb002c5e1010', 'CPSC', '2025-01-23', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Children''s Holiday Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them, and contact Duluth Trading for a full refund of the full price in the original form of payment or as store credit. Consumers will be asked to destroy the garments by cutting the top and bottom in half and disposing of them. Consumers must send a photo of the destroyed garment to ProductRecallK0040@duluthtrading.com. Duluth Trading is contacting all known purchasers directly.', '25102');
INSERT INTO safety_incidents VALUES ('c40aac2afd1e3bf1d889d27e1f23e65ce1e01297', 'CPSC', '2025-01-23', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'GM12 and GMP12 Folding Knives', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received eight reports of the lock failing during use. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled knives and contact GiantMouse for a full refund or for a free repair, including shipping, after the original knife has been returned to the firm. Consumers will not be asked for proof of purchase and will receive a pre-paid shipping label to return the recalled knife. GiantMouse is contacting all known purchasers.', '25104');
INSERT INTO safety_incidents VALUES ('648cf284d8733e601c5ea798bd67642ad42c76e3', 'CPSC', '2025-01-23', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'NQDTPBOR Multi-Purpose Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the recalled helmets immediately and contact TPBOR for a full refund. To receive a refund, consumers should destroy the helmet by cutting the straps, then take a photo, and send the photo to the recalling firm by email at nqdtpbor@outlook.com. After submitting proof of destruction, consumers should dispose of the recalled helmet. TPBOR and Amazon are contacting all known purchasers directly.', '25103');
INSERT INTO safety_incidents VALUES ('0ea2ad076f0af697706d886a7108cc18f9293741', 'CPSC', '2025-01-23', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Teckwe Hair Dryer Brushes', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately unplug and stop using the recalled hair dryers and contact SHEIN to receive a full refund. Consumers should destroy the recalled hair dryers by unplugging the hair dryer, cutting the cord and disposing of them in accordance with local and state recycling laws, and send an image of the destroyed hair dryer to Shein at uscsteam@shein.com. Upon receipt of the photo, SHEIN will issue the customer a full refund. Shein is directly contacting all purchasers.', '25106');
INSERT INTO safety_incidents VALUES ('4260c14d8e5cf88d7df2712d63d356d9fec8b57d', 'CPSC', '2025-01-16', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'HallyBee Farmhouse 5-Drawer Dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Do Not Comply With The Performance Requirements Of The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled HallyBee Farmhouse 5-Drawer Dressers, if they are not properly anchored to wall, and place them in an area that children cannot access. With a permanent marker, write the word "recalled" on the top and all sides of the dresser. Contact YKHallyBee for instructions to receive a full refund and submit a photo of disposing of the product to the firm at yueke113@163.com.', '25094');
INSERT INTO safety_incidents VALUES ('8d92952249c9ddc8beec832decdd941f786eab0e', 'CPSC', '2025-01-16', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Mini Bella Bunny Pajamas, Mini Camille Pajamas and Mini Petra Nightgown', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them, and contact Ivy City for a full refund. Consumers should destroy the garments by cutting them in half and disposing of them. Consumers should email Ivy City a photo of the destroyed garment at hello@ivycityco.com to receive a refund. Ivy City is contacting all known purchasers directly.', '25096');
INSERT INTO safety_incidents VALUES ('82d83e7aafabb1e90a6c6728a60e77382fd413d2', 'CPSC', '2025-01-16', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'MS725dvn and MX725adve Specialty Printers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received two reports of the printers overheating including one reported fire. No damage or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled printers and contact Lexmark to receive a free repair part. The repair part snaps into the unit inside the rear access panel.', '25090');
INSERT INTO safety_incidents VALUES ('165b116cc0a95a84a575e34b0967741c44555e5d', 'CPSC', '2025-01-16', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Northern Tool + Equipment Adjustable Swivel Shop Stools with Backrests', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Northern Tool + Equipment has received reports of 271 incidents related to the recalled stools, including 18 reports of injuries from falls, and 20 reports of falls without injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled stools and contact Northern Tool + Equipment to receive a free replacement stool by completing the form at https://www.northerntool.com/recall-details-20230. The stool should be disposed of in accordance with any local and state laws.', '25091');
INSERT INTO safety_incidents VALUES ('7e268da4080e64221b473cd39d1aee341846b2fe', 'CPSC', '2025-01-16', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Model Year 2024-2025 Ranger XD 1500 and Crew XD 1500 ROVs', 'Injury', 'Other', 'Skin Irritation', 'The firm has received 20 reports of the doors opening unexpectedly while the recalled ROVs were in use. No injuries or crashes have been reported.', 'Serious', 1, 0, 'Polaris is contacting registered owners directly and providing instructions on how to inspect their door handles to verify that the doors are properly closed. This will allow some consumers to continue to safely operate their vehicles until the repair can be completed.', '25092');
INSERT INTO safety_incidents VALUES ('95244a01b0014568ab06780a2e8bcf60d74f4265', 'CPSC', '2025-01-16', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Samurai Mini Smoke Alarms', 'Fire', 'Mechanical Failure', 'Respiratory', 'Three61 has received eight reports of the alarms failing to activate in the presence of smoke. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately contact Three61 for a free replacement alarm, including shipping. To register, consumers must write "Recalled" with a permanent marker on the smoke alarm and submit a photo of the marked product to the recall website at www.samuraibrands.com/recall. Once registered, the firm will immediately ship the replacement alarm. Consumers should keep the recalled smoke alarms installed until receiving the replacement alarm. Consumers should install the replacement alarms immediately upon receiving them. Three61 is contacting all known purchasers directly.', '25095');
INSERT INTO safety_incidents VALUES ('88eb2e2c49a9540a9d3ade9e95f99ad6fe7266b5', 'CPSC', '2025-01-16', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'WorkPro® Momentum Office Chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Veyer has received seven reports of consumers falling out of the chair, resulting in two minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chair until repaired, and contact Veyer to receive a free repair kit, including shipping, and installation instructions. The repair kit consists of a back bracket, three bolts, an Allen wrench and a decorative cover. Veyer is contacting all known purchasers directly.', '25097');
INSERT INTO safety_incidents VALUES ('4e6f4871556752d1e5847fadf1b933dbf0cca967', 'CPSC', '2025-01-16', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'VH2 Whole Room Heaters', 'Fire', 'Electrical Fault', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled heaters and contact Vornado to confirm that their product is part of the recall and receive instructions on how to receive a free replacement heater.', '25093');
INSERT INTO safety_incidents VALUES ('aa9a265952e6754b1b6181dff05a4ba7f8468be8', 'CPSC', '2025-01-08', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Wemfg Children''s Multi-Purpose Bike Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Wemfg for a full refund. To receive a refund, consumers should destroy the helmet by cutting off the straps, take a photo of the detached straps, and send it with their Amazon order number to the recalling firm by email at 961837339@qq.com. After submitting proof of destruction, consumers should dispose of the recalled helmet. Wemfg and Amazon are contacting all known purchasers directly.', '25088');
INSERT INTO safety_incidents VALUES ('4f6b0a11565873105238087c866bf7085533f8dc', 'CPSC', '2025-01-08', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'SIG SAUER ROMEO5 Red Dot Sights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled firearm sights and contact SIG SAUER for instructions on how to submit a picture of the serial number to receive a free recall kit, which includes a new cap with the required labeling and an updated instruction manual. Consumers will be provided with instructions on how to locate the serial number. Note: Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local hazardous waste procedures.', '25087');
INSERT INTO safety_incidents VALUES ('240ada2d8000e7c905d9ee276581071c0733f46b', 'CPSC', '2025-01-02', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Euqee Wintergreen Essential Oils', 'The Essential Oil Contains Methyl Salicylate, Which Must Be In Child-Resistant Packaging, As Required By The Poison Prevention Packaging Act (Pppa). The Packaging For The Products Is Not Child-Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately secure the recalled essential oil out of the sight and reach of children and contact DLWL-US for a full refund. Consumers can request a pre-paid label and free packaging to return the Euqee Wintergreen Essential Oil. DLWL-US and Amazon.com are contacting all known purchasers directly.', '25081');
INSERT INTO safety_incidents VALUES ('93f3be530f0b7ac764e3ded9b5ff6d0a76cbbeaa', 'CPSC', '2025-01-02', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'John Deere ZTrak™ Zero Turn Mowers with Kawasaki Engines', 'Fire', 'Flammability / Overheating', 'Burns', 'Kawasaki has received five reports of fires and 26 reports of melting and/or smoking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled mowers and contact an authorized John Deere dealer for a free repair. Kawasaki and John Deere are contacting all known purchasers directly.', '25083');
INSERT INTO safety_incidents VALUES ('db7780e08b96aca362ccba488380df999ab1020d', 'CPSC', '2025-01-02', 2025, '2025-01', 'USA', 'United States', '', 'Other', 'Yaomiao Children''s Jewelry Sets', 'The Recalled Jewelry Sets Contain Levels Of Lead That Exceed The Federal Lead Content Ban And Levels Of Cadmium That Are Prohibited In Children''S Products By The Federal Hazardous Substances Act. Lead And Cadmium Are Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled jewelry sets, take them away from children and contact LordRoads for a full refund. Consumers will be asked to dispose of the recalled jewelry sets and send a photo of the disposed sets to simlordroadple@163.com. LordRoads and Amazon are contacting all known purchasers directly.', '25082');
INSERT INTO safety_incidents VALUES ('19810591e051610e87bc7925b671a104ca54dfb2', 'CPSC', '2024-12-26', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Inclusive Orbit merry-go-rounds', 'The Space Between The Rotating Platform And The Stationary Outer Rim Can Leave A Gap That Narrows Too Much, Posing A Crushing Hazard To Children.', 'Entrapment', 'Entrapment', 'The firm has received reports of two incidents of fingers getting trapped in the gap between the rotating platform and the outer rim, resulting in two finger crushing injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled merry-go-rounds and contact the owner of the equipment, such as park director or school principal, to determine if equipment has been inspected and repaired. Contact BCI Burke to schedule an inspection and free onsite repair.', '25080');
INSERT INTO safety_incidents VALUES ('9cf72706e455d204a9dc621a934790a55b8bff38', 'CPSC', '2024-12-26', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'PIEPS Pro IPS Avalanche Transceivers', 'Injury', 'Other', 'Not Specified', 'Black Diamond has received one report of the battery compartment not operating correctly. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the avalanche transceivers and contact Black Diamond for a full refund or free repair, including shipping. Consumers will not be asked for proof of purchase and will receive a pre-paid shipping label to return the recalled transceivers. Black Diamond is contacting all known purchasers.', '25077');
INSERT INTO safety_incidents VALUES ('e1f5dddd571b02e7f1bd4ab09c83063e300b084f', 'CPSC', '2024-12-26', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'GIKPAL 12-Drawer Dressers', 'Low Risk', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers, if they are not properly anchored to a wall, and place them in an area that children cannot access. Contact ONME Direct for instructions to receive a full refund and submit a photo of the consumer disposing of the product. ONME Direct and Walmart are contacting all known purchasers directly.', '25079');
INSERT INTO safety_incidents VALUES ('c9d71701f17961c56d8dc386dde609a5a46e99dc', 'CPSC', '2024-12-26', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Precor Resolute Cable Multi-Station Exercise Equipment', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'Precor has received nine reports of the pulley dropping during use, including two minor head injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled exercise equipment. Precor is directly contacting all known gyms with the recalled exercise equipment to coordinate a free on-site repair by a qualified service technician, including installation of a redesigned pop-pin and a missing warning label.', '25078');
INSERT INTO safety_incidents VALUES ('c68c5b299f17d9b6ce6d853483278f72fa96e40a', 'CPSC', '2024-12-19', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Charmast power banks, model W1056', 'Fire', 'Flammability / Overheating', 'Burns', 'Charmast has received 44 reports of the recalled power banks expanding, igniting, melting, overheating or smoking, including four reports of consumers receiving burns or blisters.', 'Moderate', 1, 0, 'Consumers should stop using the recalled power banks immediately and contact Charmast for instructions on how to receive a full refund. To receive a refund, consumers will be required to provide photographs of their model W1056 power bank, their names and dates of the photograph written in indelible (permanent) marker above the label, and the severed power cord. Consumers should dispose of the power banks in accordance with local and state regulations.', '25072');
INSERT INTO safety_incidents VALUES ('1ac5b3f4db6bb0c185e8c7532fd58c438b598f2a', 'CPSC', '2024-12-19', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'SKIL 40V 5.0 Ah Lithium-Ion Batteries', 'Fire', 'Flammability / Overheating', 'Respiratory', 'The firm has received 100 reports of thermal incidents involving the batteries including overheating, melting, smoking and fire. These included eight reports of minor burns and/or smoke inhalation and 49 reports of related property damage.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled lithium-ion batteries and contact Chervon for a free replacement or refund for the price of the battery. Consumers should register for the recall online at www.skil.com/recalls. Chervon will provide a battery collection kit for the consumer to return the recalled battery and will provide the requested remedy upon return of the recalled battery.', '25071');
INSERT INTO safety_incidents VALUES ('ce215484f6b98d5d34f696212afa4168702a1397', 'CPSC', '2024-12-19', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Elongdi Magnetic Building Sticks Sets', 'The Recalled Magnetic Building Sticks Set Violates The Mandatory Federal Regulation For Magnet Toys Posing An Ingestion Hazard. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'None reported. CPSC estimates 2,400 magnet ingestions were treated in hospital emergency departments from 2017 through 2021. CPSC is aware of eight deaths since 2005 through 2021 involving the ingestion of hazardous magnets, including two outside of the United States.', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic building stick sets immediately, take them away from children, and contact Elongdi to receive a pre-paid label to return the recalled magnetic building sticks for a full refund. Amazon is notifying all known purchasers directly.', '25069');
INSERT INTO safety_incidents VALUES ('69cbc380896c278953d6b49ce0edf42eb60cc72f', 'CPSC', '2024-12-19', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Silicone spoons for babies', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received two reports of the spoon tip breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled spoons, keep them away from children and contact Melii Baby Inc. to receive a free replacement set. Consumers should take photographs of the spoons, discard the spoons in household waste, and then email the photographs to care@meliibaby.com to receive the free replacement set.', '25070');
INSERT INTO safety_incidents VALUES ('46bb5107412d81aa2e1ca8dfdfee708df84830fd', 'CPSC', '2024-12-12', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'HTRC C240 battery chargers', 'Fire', 'Flammability / Overheating', 'Burns', 'HTRC has received 32 reports of fire and other thermal incidents, including five reports of significant property damage and one report of injury.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled chargers and contact HTRC for instructions on how to return the chargers for a full refund.', '25066');
INSERT INTO safety_incidents VALUES ('9ab9fac51b58d8a1e39023deb1e414a83c280e9e', 'CPSC', '2024-12-12', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Wireless Decorative Tree Light Controllers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 10 reports of overheating, including one report of a fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using this product and return it to their place of purchase to receive a full refund.', '25067');
INSERT INTO safety_incidents VALUES ('b2376437f199a624f59e50daa5da60958a9f9c01', 'CPSC', '2024-12-12', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Switchback and Trigger Action travel mugs', 'Burns', 'Mechanical Failure', 'Burns', 'Stanley has received 91 reports worldwide, including 16 in the U.S., of the recalled travel mugs'' lids detaching during use, resulting in 38 burn injuries worldwide, including two burn injuries in the U.S., with 11 consumers worldwide requiring medical attention.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled travel mugs and contact Stanley to receive a free replacement lid, including shipping.', '25063');
INSERT INTO safety_incidents VALUES ('aa97f1bf22e4b71716fa8726894e574a97f0f6ca', 'CPSC', '2024-12-12', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Wall Teester Bed Crowns', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 10 reports of incidents of the bed crowns failing due to broken mounting tabs, including one incident of the bed crown detaching from the wall. One injury has been reported, resulting in a scratch to the consumer''s cheek.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bed crowns and contact Touch of Class to request either a full refund or free replacement. Consumers can request the firm to pick up the bed crown or request a prepaid FedEx shipping label to return the item. Consumers will receive a replacement teester bed crown or a $149 refund, once the item is returned. Touch of Class is contacting consumers directly.', '25064');
INSERT INTO safety_incidents VALUES ('fd1ddbb6def283eb4c8f77387f80d193861934e9', 'CPSC', '2024-12-12', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Yoto Mini speakers', 'Fire', 'Flammability / Overheating', 'Burns', 'Yoto has received nine reports from U.S. consumers and three from a UK consumer of the speaker overheating or melting. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled speakers, take them away from children and contact Yoto to receive a free battery replacement kit. Consumers should request the battery replacement kit even if they already received the smart cable in the April 2024 recall. Consumers should dispose of lithium-ion batteries in accordance with local and state regulations and not in the trash.', '25065');
INSERT INTO safety_incidents VALUES ('38732af5debc13c25131f555a5eff8b259d9c478', 'CPSC', '2024-12-05', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Redfield 12- and 18-Gun Fireproof Safes', 'Injury', 'Other', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the Redfield 12- and 18-Gun Fireproof Safes and return them to any Academy Sports + Outdoors store for a free replacement or a refund. Consumers can also contact Academy''s Customer Care to arrange for a replacement or refund.', '25060');
INSERT INTO safety_incidents VALUES ('db26edfe6393ab7c24c608d89dd2f5fa8960314a', 'CPSC', '2024-12-05', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Anker Soundcore (A3102) and PowerConf Bluetooth (A3302) Speakers', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 33 reports of incidents involving the lithium-ion batteries in the speakers overheating, some of those involve incidents of smoking and small fires, including one minor burn injury in connection with an overheating unit.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled speakers, and ensure they are powered off and are not connected to any external power source or charger. Visit Anker at https://support.anker.com/s/emailcontactus to verify the speaker''s SN code and to fill out product recall information. Anker Innovations Limited will provide further instructions on how to obtain a replacement speaker free of charge. Because of the lithium-ion batteries, consumers should dispose of the speaker in accordance with local and state regulations and not in the trash.', '25056');
INSERT INTO safety_incidents VALUES ('63da917568bccfd5c7a3871c1a97a4a26d729a8f', 'CPSC', '2024-12-05', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Belkin BoostCharge Pro Fast Wireless Charger Power Banks 10K', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of the recalled power bank catching fire, resulting in a house fire involving property damage.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled power banks and contact Belkin to receive a full refund or store credit. Consumers will need to submit photos showing the front and back of the power bank with their recall submission form. Consumers should dispose of the lithium-ion battery in accordance with local and state regulations and not in household trash.', '25061');
INSERT INTO safety_incidents VALUES ('aaf5f578a189473271962533a5df3fe7cb0487bb', 'CPSC', '2024-12-05', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'High Bay LED light fixtures', 'Fire', 'Electrical Fault', 'Burns', 'The firm has received seven reports of loose LED boards burning. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the High Bay LED light fixture that shows any sign of a loose LED board or discoloration of the lens and turn the circuit off. Customers can contact NetZero USA to schedule a free inspection and on-site repair to replace the plastic pins or replace the LED board. NetZero is contacting all known purchasers.', '25058');
INSERT INTO safety_incidents VALUES ('a6c4450a2ee7ff2e014a4dfded579109d1856ec8', 'CPSC', '2024-12-05', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Model Year 2024 Ranger Recreational Off-Road Vehicles (ROVs) and ProXD and Bobcat Utility Task Vehicles (UTVs)', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has identified three reports of improper welds. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop carrying passengers in the recalled vehicles and contact an authorized Polaris dealer to schedule a free inspection and, if needed, a free repair. Polaris is contacting all registered owners directly.', '25702');
INSERT INTO safety_incidents VALUES ('9721c5941d9fa8109bb97c05deedc1a9baf79531', 'CPSC', '2024-12-05', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Model Year 2024-2025 RZR XP 1000 and XP 4 1000 ROVs', 'Fire', 'Electrical Fault', 'Not Specified', 'The firm has received a total of three reports of incidents including two reports of fires and one report of melted wires. No injuries have been reported.', 'Minor', 1, 0, 'Polaris is contacting all registered owners directly and providing a full-battery cover to them by mail that can be self-installed or installed for free by an authorized Polaris dealer. Consumers can continue to operate the recalled ROVs before installation of the battery cover only if the battery positive terminal cover (red) is undamaged. The consumer can confirm the cover is undamaged by completing the Battery Positive Terminal Cover (Red) Verification and Seat Installation Instructions provided by Polaris at https://prdservicemanagementstg.blob.core.windows.net/fieldcommunications/9942029r01.pdf. If the battery positive terminal cover (red) is damaged, the recalled ROV should not be operated until the repair is complete.', '25703');
INSERT INTO safety_incidents VALUES ('910a54b40760ac466941911d9a605a8377f74c17', 'CPSC', '2024-12-05', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'Temp-tations Oven Gloves', 'Burns', 'Other', 'Burns', 'QVC has received 162 reports of insufficient heat protection including 92 reports of minor burns.', 'Minor', 1, 0, 'Consumers should immediately stop using the oven gloves and contact QVC to receive a refund.', '25059');
INSERT INTO safety_incidents VALUES ('c60f37b208f3fd4c447c64d4b40e2b5d7f6a0084', 'CPSC', '2024-12-05', 2024, '2024-12', 'USA', 'United States', '', 'Other', 'The Legendary ''VACATION'' by Vacation Black Label Scented Candles', 'Fire', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received seven reports of high candle flames, some of which resulted in the glass container breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles and contact Vacation Inc. to receive a refund of $42. Consumers should visit https://vacation.inc/candlerecall for instructions on how to register for the recall, upload a photo of the candle with a note indicating the date and customer initials, indicate whether the refund should be in the form of a check or ACH electronic payment, and confirm disposal of the candle in the trash. Vacation Inc. is contacting all known purchasers directly.', '25057');
INSERT INTO safety_incidents VALUES ('e04c6da01cce802d7cc45e24d108d88f8797fca6', 'CPSC', '2024-11-21', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Dorel Wall Beds', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 22 reports of the beds falling, resulting in 10 injuries including concussions, contusions, cuts and bruises.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled wall beds and contact Dorel for information on coordinating for reimbursable professional inspection and, if necessary, reinstallation, after submitting their professional quote to Dorel. All known purchasers are being contacted directly.', '25053');
INSERT INTO safety_incidents VALUES ('b3e5a7e0ce79b4bdb49b5b7273343e9dbc3a01a1', 'CPSC', '2024-11-21', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Segway Ninebot P100 KickScooters', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 31 reports of broken front forks, including six reports of injuries, including a fracture, cuts, scrapes, bruises and shoulder pain.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled KickScooters and contact Segway for a free repair. Segway will direct consumers to a local store for the repair (where available) or provide a pre-paid shipping label to ship the product to a national service center for repair. Segway is contacting all known purchasers directly.', '25052');
INSERT INTO safety_incidents VALUES ('0ff7b59240057b02cc3cc546f7f8326e25b1acd6', 'CPSC', '2024-11-21', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'South Shore Cribs', 'The Spacing Between Some Of The Crib''S Slats Is Wider Than Allowed Under The Federal Safety Standard, Posing An Entrapment Hazard To Children.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled cribs and contact South Shore for information on how to disassemble the product. To receive a full refund, take a photo of the disassembled crib in an outdoor waste container and email the photo to service@southshorefurniture.com. South Shore, Amazon.com and Walmart.com are contacting all known purchasers directly.', '25054');
INSERT INTO safety_incidents VALUES ('d6e9854bcf23246f9a62c5e844f2643da943b755', 'CPSC', '2024-11-21', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Nerf Barrage Youth Bike Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the recalled Nerf Barrage helmets immediately and contact Todson Inc. for a full refund. To receive a refund, consumers should destroy the helmet by cutting off the straps, then take a photo, and send the photo to the recalling firm by email at NerfHelmetRecall@Todson.com. After submitting proof of destruction, consumers should dispose of the recalled helmet. Todson is contacting all known purchasers directly.', '25051');
INSERT INTO safety_incidents VALUES ('41966c2f5e398595eaa9432d826c75606be3b4bf', 'CPSC', '2024-11-14', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Hallmark Keepsake Christmas Tree Ornaments featuring the Cad Bane character from Star Wars: The Book of Boba Fett', 'The Brown Paint On The Exterior Of The Recalled Christmas Tree Ornaments Did Not Fully Dry Before Packaging, Causing Mold To Grow On The Exterior Surface Of The Ornament, Posing Risk Of Respiratory Issues To Consumers Due To Mold Exposure.', 'Microbiological Contamination', 'Respiratory', 'The firm is aware of 16 consumer reports of the recalled tree ornaments having mold on them when they were taken out of the box. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ornament and return it to their Hallmark Gold Crown store or follow the return instructions online at www.hallmark.com to receive a postage paid shipping label for a full refund. Consumers will receive a full refund in the form of original payment. No purchase receipt is required to receive the refund.', '25041');
INSERT INTO safety_incidents VALUES ('da35629078fc51902a67e6c4ddf005b65628624f', 'CPSC', '2024-11-14', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Medical King Bed Assist Rail adult bed rails', 'When The Recalled Bed Rails Are Attached To An Adult''S Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Bed Rail And The Side Of The Mattress. This Poses A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'Medical King has received one report of a death involving the Bed Assist Rail with Adjustable Heights, model number 7007. In November 2023, at a residential care facility in South Carolina, a 66-year-old man died after becoming entrapped between his mattress and the bed rail.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact Medical King to receive a free repair kit or a replacement bed rail, depending on the model.', '25046');
INSERT INTO safety_incidents VALUES ('b4fb306a5aa7ad2dd8bfa01f8ffa14ebe2e176f6', 'CPSC', '2024-11-14', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'DeNova Detect Brand Combination Natural Gas and Carbon Monoxide Alarms', 'After Alerting Consumers To The Presence Of Natural Gas Or Carbon Monoxide, The Recalled Alarm Can Go Into Sleep Mode When The Alert Lasts Less Than Four Minutes. During This Time, The Alarms Can Fail To Detect And Alert Consumers To A New Incidence Of Natural Gas Or Carbon Monoxide, Posing A Risk Of Carbon Monoxide Poisoning.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately register online at www.denovadetect.com/safetynotice-dd622 to receive a prepaid shipping package and replacement alarm. Consumers should continue using the recalled alarms until they install the replacement alarms. Once they receive the replacement alarm, consumers should ship the recalled alarm back in the provided prepaid shipping package.', '25045');
INSERT INTO safety_incidents VALUES ('6d8883cf81b39cc9644ef27e347c134ed52ff26c', 'CPSC', '2024-11-14', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Cultivar Planter Boxes', 'Injury', 'Other', 'Not Specified', 'The firm has received 23 reports of the planter box frame breaking, including one injury involving a consumer who broke their toes.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled planter boxes and contact Outdoor Essentials for a full refund. Consumers can receive a refund in the form of a gift card or store credit. A consumer will receive the amount on the purchase receipt, or they will receive $275 for the model if no receipt is provided. Consumers will be asked to mark the recalled planter box with the word "Recalled" with permanent marker and upload a photo of it to www.outdooressentialproducts.com/recall. Consumers should then dispose of the recalled product.', '25042');
INSERT INTO safety_incidents VALUES ('b55108aeb10ebd1eb8ae9b0ec7d324e5663b9a7a', 'CPSC', '2024-11-14', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Celebration Girl''s Summer Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them, and contact Petidoux for a full refund. Consumers will be asked to destroy the garments by cutting the top and bottom in half and disposing of them in accordance with local and state recycling procedures. Consumers must send a photo of the destroyed garment to customerservice@petidoux.com. Upon receipt of the photo, consumers will have the option of receiving a full refund or a store credit worth 1.25 times the purchase price.', '25040');
INSERT INTO safety_incidents VALUES ('6ca7cd89c237c6d1d370b7d695684108ff8943d0', 'CPSC', '2024-11-14', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'YOYO³ strollers', 'Injury', 'Other', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled strollers and go to https://recall.stokke.com/yoyo3 to register their product to receive a full refund in the form of a refund check.', '25044');
INSERT INTO safety_incidents VALUES ('681ce46658a980d995684134d6560bfeb40168f3', 'CPSC', '2024-11-14', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'woom bicycles OFF 5, OFF AIR 5, OFF 6, OFF AIR 6, and ORIGINAL 6', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received five reports of the crank breaking, including one report of an injury to a child.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact woom bikes USA for instructions on how to get a free replacement crankset. Consumers can use the online crank checker tool found at woom.com to determine if their bicycle is affected by the recall. Consumers with affected cranksets will be sent a free replacement that must be installed by a bike repair technician at their preferred bike shop. Reimbursement in the way of a check will be issued for the consumer''s crank replacement expense upon submission of the repair receipt. All known purchasers are being contacted directly by woom.', '25043');
INSERT INTO safety_incidents VALUES ('62e64297cc6664eda9ea2459ec92f9afaa2b24af', 'CPSC', '2024-11-07', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Baofali 4-in-1 Microfiber Crib Safety Bumpers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using and remove the recalled crib bumpers from the crib. To receive a full refund, take a photo of the crib bumper cut in half and email the photo to 2540535966@qq.com or message to Baofali Trading on Temu.com. Dispose of the destroyed crib bumper in accordance with local and state laws. Baofali Trading is contacting all known purchasers directly.', '25033');
INSERT INTO safety_incidents VALUES ('8630f9cd17b904a8c86b62294846315a4a8be69e', 'CPSC', '2024-11-07', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Dreamgro Lullaby mermaid travel soothers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received one report of the soft star detaching from the toy. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled soothers and take them away from children. Return the soother to the store where purchased for a full refund.', '25030');
INSERT INTO safety_incidents VALUES ('8e43ed77876d914c617432536cfeccc527861ced', 'CPSC', '2024-11-07', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'GoveeLife and Govee Smart Electric Space Heaters', 'Fire', 'Flammability / Overheating', 'Burns', 'The firms have received 113 reports of overheating, including seven reports of fires and one report of a minor burn injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled electric space heaters and contact the brands for a refund. Unplug the electric space heater, cut the power cord, and send an image of the destroyed electric space heater, the manufacturer''s label and SN Code on the bottom or side of the unit to GoveeLife or Govee through the link https://recall.goveelife.com/heater-recall. Consumers who do not have the original order number will receive a refund ranging from $31.80 to $106.63, depending on the model purchased. For consumers who do have the original order number, they will receive a full refund of the purchase price. Consumers can find the order number in their purchase records on online sales channels. They can also contact heatersupport@goveelife.com if they have problems finding the order number.', '25036');
INSERT INTO safety_incidents VALUES ('84af2d84acc5927d0c49615c7d5156260749fcf9', 'CPSC', '2024-11-07', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Guava Roam Strollers', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 67 reports of the brake lock disengaging. The firm has also received 152 reports of the brake pedal not engaging when pushed down. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled strollers and contact Guava Family for instructions on how to register for a free repair kit and new installation instructions.', '25032');
INSERT INTO safety_incidents VALUES ('4ce5f3e998f444afb8671e7b7e85fbdbebbca698', 'CPSC', '2024-11-07', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Kyte Baby Slumber Suits', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled slumber suits immediately and contact Kyte Baby for instructions on how to destroy or return the garments for a full refund or a store credit for the original purchase price plus free shipping and handling. Kyte Baby is contacting all known purchasers directly.', '25031');
INSERT INTO safety_incidents VALUES ('35d8d483a8c429f24b465f96a30f359b2fc10915', 'CPSC', '2024-11-07', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'MAG Battery Packs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Quad Lock has received 39 reports of incidents in the United States, including three reports of fire and 36 reports of smoking, melting, cracking or swelling, resulting in two reports of property damage. Quad Lock has received 170 reports of incidents internationally, including four reports of fire and 166 reports of smoking, melting, cracking or swelling, resulting in one report of property damage.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled battery packs, remove them from the charger and contact Quad Lock for a full refund of the purchase price or a store credit. Visit www.quadlockcase.net/recall to participate in the recall. Consumers should dispose of lithium-ion batteries in accordance with local and state regulations and not in the trash.', '25035');
INSERT INTO safety_incidents VALUES ('fe073d42df6a16fcdb22033a224a88abde370176', 'CPSC', '2024-11-07', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Tala Muse Portable Lamps', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of a battery overheating, causing a fire that resulted in property damage to a side table and bed. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled portable lamps and contact Tala North America to receive a free replacement bulb. Consumers will be asked to complete a replacement request form, attach a photo of the product and state the number of recalled bulbs. Consumers should safely dispose of the bulbs. Replacement bulb(s) will be mailed to consumers at no cost. Tala is contacting purchasers directly.', '25038');
INSERT INTO safety_incidents VALUES ('5491a024fd29c74a6f0b9c2c3481031aadda5523', 'CPSC', '2024-11-07', 2024, '2024-11', 'USA', 'United States', '', 'Other', 'Wolf Dual Fuel ranges with infrared griddles', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 36 reports of griddles turning on. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ranges and contact Wolf Appliance to schedule a free repair in their home.', '25034');
INSERT INTO safety_incidents VALUES ('9535fab9102fdc0f1bdab11a2d6d0e63e7708aa9', 'CPSC', '2024-10-31', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Tumblers with a Metal Straw', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received four reports of incidents, resulting in four laceration injuries to the hand and mouth.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled metal straw that comes with the tumbler and contact HALO for instructions on how to receive a free replacement silicone straw, after returning the metal straw. If consumers don''t want to keep the tumbler either, they can return it with the metal straw and receive a refund in the form of a $15 gift card. The original tumbler and metal straw must be returned to HALO to receive the refund. Proof of purchase (receipt) is not required to receive a replacement or refund. HALO will provide a pre-paid label for shipping the recalled units. Consumers should not return the recalled units to Wawa stores.', '25025');
INSERT INTO safety_incidents VALUES ('78c78a6d3e6dac39ba26b2f53b52bb27a11782bc', 'CPSC', '2024-10-31', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Bauer 20V Battery-Powered 4-Gallon Backpack Sprayers', 'Chemical', 'Flammability / Overheating', 'Not Specified', 'Harbor Freight Tools has received eight reports of the battery overheating, including reports of smoking, melting and fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled sprayers and contact Harbor Freight Tools for instructions on returning the sprayer hose and wand to the nearest store for a full refund in the form of a Harbor Freight Tools gift card. Consumers should flush the sprayer with water and cut the sprayer hose and wand off the product with scissors. If unable to return the sprayer hose and wand to a Harbor Freight Tools store, contact Harbor Freight Tools using their toll-free number or email address to request a prepaid return shipping label. Harbor Freight Tools is contacting all known purchasers directly.', '25027');
INSERT INTO safety_incidents VALUES ('9da174ed93584595643166836446c5b2fbb85312', 'CPSC', '2024-10-31', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Humane Charge Case Accessory for Ai Pin', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of a charge case overheating and melting during charging. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Charge Case Accessory and contact Humane to receive a full refund or free replacement. Consumers will have the option to receive a refund or a replacement Charge Case Accessory. Consumers who purchased the Charge Case Accessory will receive a $149 refund, while consumers who purchased the Charge Case as part of the Ai Pin Complete System will receive a $129 refund. The approved replacement Charge Case Accessory will be available in approximately 3 to 6 months. Consumers should dispose of the product in accordance with any local and state laws, and not in the trash.', '25026');
INSERT INTO safety_incidents VALUES ('fa5a1f29ce6792c462f06bfda6f33953d21f73c5', 'CPSC', '2024-10-31', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Manhattan Comfort Floating Wall Theater Entertainment Centers and Panels', 'Injury', 'Mechanical Failure', 'Fall Injury', 'The firm has received 51 reports of the panels detaching, including three minor injuries such as scrapes and bruising.', 'Minor', 1, 0, 'If the recalled floating wall theater entertainment center and panels have been attached to drywall without toggle bolts, consumers should clear the space underneath and immediately around the entertainment center and stay away from it. Consumers should contact Manhattan Comfort for a free repair. The repair will consist of providing consumers with toggle bolts and instructions on how to remove and reinstall the floating theater. If the bottom panel of the recalled floating wall theater entertainment center has been attached to any wall surface without the included safety screw, consumers should immediately stop using the entertainment center and contact Manhattan Comfort for a free repair. The repair will consist of providing consumers with a replacement safety screw and instructions on how to apply the safety screw.', '25028');
INSERT INTO safety_incidents VALUES ('bf915cd1e7521ce454577e86c54776f6cbd21453', 'CPSC', '2024-10-31', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Model Year 2023-2024 Ranger XP Kinetic Recreational Off-Road Vehicles (ROVs)', 'Fire', 'Flammability / Overheating', 'Skin Irritation', 'The firm has received one report of unintended acceleration and fire and six reports of melting on or around the motor controller unit. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled ROVs and contact an authorized Polaris dealer to schedule a free inspection of the motor controller unit and its components. If the high voltage cables are loose or damaged Polaris will provide a free repair at the dealer''s location. Polaris is contacting registered owners directly.', '25024');
INSERT INTO safety_incidents VALUES ('aa6192cabb5b53919e030081bb826d877459b0ec', 'CPSC', '2024-10-31', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Vevor Baby Gates', 'The Gates Violate The Federal Safety Regulations For Expansion Gates And Expandable Enclosures. A Child''S Torso Can Fit Through The Opening Between The Gate Slat And Side Wall, Posing An Entrapment Hazard To Children.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the gates and contact Sanven Technology via email at csr@vevor.com for information on how to dispose of the product and submit a photograph to obtain a full refund. Sanven Technology is contacting all known purchasers directly.', '25029');
INSERT INTO safety_incidents VALUES ('088880adc89692a9ee094c41236683c598828ce0', 'CPSC', '2024-10-24', 2024, '2024-10', 'USA', 'United States', '', 'Other', '2024 CFORCE 800 Touring and 2024 CFORCE 1000 Touring All-Terrain Vehicles (ATVs)', 'The Throttle Lever On The Recalled Atvs Can Fail To Return To The Idle Position When A Driver Releases It, And The Vehicle Could Then Unexpectedly Continue To Accelerate, Posing A Crash Hazard.', 'Other', 'Fracture / Blunt Trauma', 'CFMOTO has received four reports of the throttle failing to return to the idle position and including one report of the vehicle crashing, including one minor impact injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact an authorized CFMOTO dealer to schedule a free repair at the dealership. CFMOTO has issued a stop ride notice to consumers and is contacting all registered owners and dealers directly.', '25019');
INSERT INTO safety_incidents VALUES ('23dc845c3e2fde41dc507559023a7448933578a2', 'CPSC', '2024-10-24', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Commercial Pro 100 sold with 5 lb grip handles', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'PowerBlock has received four reports of weight plates slipping beyond the handle during use. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled handles and contact PowerBlock for instructions on receiving free replacement 5 lb grip handles. PowerBlock is contacting all known purchasers directly.', '25020');
INSERT INTO safety_incidents VALUES ('395245e94f45cb67f2752c0b83109d2e5ec6e7a1', 'CPSC', '2024-10-24', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Ricky Powersports Tumble Weed Youth and TGB Blade Adult All-Terrain Vehicles (ATVs)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled ATVs immediately and contact Ricky Powersports to arrange to return the ATVs for a full refund.', '25021');
INSERT INTO safety_incidents VALUES ('def9da8a0df767ed891b87a49f9f0d765608e40c', 'CPSC', '2024-10-17', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Anker Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 28 reports of incidents of the batteries overheating, exploding, and the power bank catching on fire. Two injuries which included first and second degree burns to the consumer''s hands have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled power banks and contact Anker Innovations for instructions on receiving a free replacement power bank. Visit https://www.anker.com/product-recalls to register for the recall. Consumers should dispose of the lithium-ion batteries in accordance with local and state regulations.', '25011');
INSERT INTO safety_incidents VALUES ('fe5eea76ad4fe5481e236eab466c04c9ea9c251d', 'CPSC', '2024-10-17', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Colsen-branded fire pits', 'Fire', 'Flammability / Overheating', 'Burns', 'CPSC has received 31 reports of flame jetting and flames escaping from the concrete container; resulting in 19 burn injuries. Two incidents resulted in third degree burns to more than 40% of victims'' bodies, and at least six incidents have involved surgery, prolonged medical treatment, admission to burn treatment facilities, short-term disability, loss of function, physical therapy, or permanent disfigurement.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled fire pits and dispose of them. Do NOT resell or donate them. It is a violation of federal law to sell or distribute recalled products. The firm stopped selling Colsen-branded fire pits less than one year after it acquired the product business and does not have the financial resources to offer a remedy to consumers.', '25015');
INSERT INTO safety_incidents VALUES ('f3bc1d08139ac816962197f35a2cc0ba7fe30bad', 'CPSC', '2024-10-17', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Nub, Serie V, Cain, and Oliva branded Promotional Cigar Slim Lighters', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using and dispose of the recalled promotional cigar lighters. Oliva Cigars is contacting all known businesses and wholesalers who could have provided the promotional item to consumers. As the product was given away for free, no refund or replacement will be provided.', '25012');
INSERT INTO safety_incidents VALUES ('1501862e027aecde7c967aef7c4295d9a61cfdcd', 'CPSC', '2024-10-17', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Model Years 2022-2024 Arctic Cat Prowler Pro / Pro Crew and Tracker Off Road 800SX / 800SX Crew Side by Side Recreational Off Highway Vehicles (ROVs)', 'The Vehicle Can Move When On An Incline And "Park" Is Displayed On The Digital Dash. This Can Allow The Vehicle To Roll Away, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'The firm has received 12 reports of vehicles moving while in the park position. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Textron Specialized Vehicles to schedule a free repair. The repair kit will include a new shift cable bracket, shift sensor, and a decal to be placed at the dash display. The new shift sensor will allow the dash to display an "E" for shift error if "park" on the vehicle is not fully engaged. Customers will be directly notified to bring their vehicle to an authorized dealership to have the kit added at no cost. Textron is contacting all known purchasers directly.', '25701');
INSERT INTO safety_incidents VALUES ('c76d86e726d2bdb4c1f2906cfcddcfffa32a480f', 'CPSC', '2024-10-10', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'All Models of Fisher-Price Snuga Swings', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Between 2012 and 2022, there have been reports of five deaths involving infants 1 to 3 months of age when the product was used for sleep. In most of those incidents, the infants were unrestrained and bedding materials were added to the product.', 'Fatal', 1, 0, 'Consumers should immediately remove both the headrest (by cutting the tether) and the body support insert from the seat pad before continuing to use the swing. Fisher-Price will provide a $25 refund to consumers who remove and destroy the headrest and body support insert. Instructions can be found at www.service.mattel.com.', '25009');
INSERT INTO safety_incidents VALUES ('ca7c45d99d200e1282051ed8df40586ccab6e3ee', 'CPSC', '2024-10-10', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Gimars Playpen with Mat', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using and keep children away from the recalled playpens. Consumers should disassemble the playpen and cut the fabric floor, mattress pad and basketball hoop accessory each into two pieces. Then, consumers should upload photos of the cut product using the online submission form or email the photos to Gimars-Aftersales@outlook.com to obtain a full refund. Shenzhen Jingdu Technology and Amazon are contacting all known purchasers directly.', '25008');
INSERT INTO safety_incidents VALUES ('df9c67972ec481940f4f50905531b2d2349b77fd', 'CPSC', '2024-10-10', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Allen + Roth-branded Lighted Bathroom Mirrors', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Lowe''s has received 44 reports of the mirror''s glass detaching from the wall attachment base. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Allen + Roth mirrors, turn the power off and contact Homewerks Worldwide for instructions on how to remove and dispose of the mirror for a full refund or free replacement mirror, including shipping. Homewerks Worldwide and Lowe''s are contacting all known purchasers directly.', '25005');
INSERT INTO safety_incidents VALUES ('eade8dcf6698bc98897899ae40eb9cb95e976165', 'CPSC', '2024-10-10', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Halloween Projector Flashlights', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received nine reports of overheating including six reports of smoke or fire, resulting in four reports of minor burn injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled flashlights and return them to any Target store for a full refund. Consumers should turn off the product, remove the batteries, mark the product with "recalled" in permanent marker prior to returning the flashlight to Target. Target is contacting all known purchasers directly.', '25010');
INSERT INTO safety_incidents VALUES ('b854ca799db5d3b2a0c6dac4b32ab4880bd39cff', 'CPSC', '2024-10-10', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Droyd Fury Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Droyd ATVs and contact Reyhee Group for a free repair kit, consisting of a replacement handlebar cover and new safety warning labels. Reyhee Group is contacting all known purchasers directly.', '25006');
INSERT INTO safety_incidents VALUES ('a6326c25973892813a6a3e0e8bcc54598f7b02ae', 'CPSC', '2024-10-10', 2024, '2024-10', 'USA', 'United States', '', 'Other', 'Droyd multi-purpose helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the recalled Droyd helmets immediately and contact Reyhee for a full refund. To receive a refund, consumers must cut the straps off the helmet and submit two photos: one photo of both straps cut off and one photo of the helmet and cut straps inside of a trash can. Send both photos along with name and address to Reyhee Group at support@droyd.com. Reyhee Group is contacting all purchasers directly.', '25007');
INSERT INTO safety_incidents VALUES ('67552e8e8196675602298af58fc05befa2d3a2bc', 'CPSC', '2024-09-26', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'John Deere 1023E, 1025R, and 2025R Compact Utility Tractors', 'The Front Bell Crank In The Brake Linkage Can Fail Causing The Tractor To Lose Braking, Resulting In A Crash Hazard.', 'Other', 'Fracture / Blunt Trauma', 'The firm has received four reports of the brake linkage failing, including one hospitalization and two impact injuries and minor property damage to the tractors.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled tractors and contact an authorized John Deere dealer to schedule an appointment to bring the tractor into the dealer for a free repair. If the consumer is not able to transport the tractor to a dealer''s location, then the dealer will make arrangements to repair the unit at the consumer''s residence. John Deere is contacting all known purchasers directly.', '24377');
INSERT INTO safety_incidents VALUES ('e7186153c52e822cda7be6d25283be27dc0119c2', 'CPSC', '2024-09-26', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Multi-Grip Tub Safety Bars', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Liberty Hardware has received fourteen reports of the plastic sticker grip pads becoming dislodged after installation or otherwise needing replacement, including one fall with a minor injury reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Multi-Grip Tub Safety Bars and contact Liberty Hardware. Consumers can request to receive a pre-paid label and free packaging to return the Multi-Grip Tub Safety Bars for a $35 refund.', '24378');
INSERT INTO safety_incidents VALUES ('c926ddcdaba1307fad07897a62523622041ac8f3', 'CPSC', '2024-09-19', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Cabinet Heaters', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled cabinet heaters, unplug the unit, and contact Caframo Limited for instructions on how to receive a free repair or replacement unit. Caframo will provide a pre-paid shipping label for consumers to return the product to Caframo for repair. If the product cannot be repaired, Caframo will mail the consumer a replacement. Caframo is contacting all known purchasers directly.', '24371');
INSERT INTO safety_incidents VALUES ('3cb497d8f122329ffa1d3616cf5aeeb99c3f8434', 'CPSC', '2024-09-19', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Ceither Adult Portable Bed Rails', 'The Recalled Bed Rails Violate Federal Regulations For Adult Portable Bed Rails, Posing A Serious Entrapment Hazard And Risk Of Death By Asphyxiation. When The Bed Rails Are Attached To A Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Bed Rail And The Side Of The Mattress.', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled adult portable bed rails. To receive a refund, consumers should send a photo of the disposed bed rail, along with a statement that they bought the product on or after August 21, 2023 or an Amazon purchase receipt, to the recalling firm by email at xchan524@outlook.com. The company will only provide refunds for bed rails purchased on or after August 21, 2023.', '24370');
INSERT INTO safety_incidents VALUES ('fd6c73c8dca8e217e06363237ce4b94e0564ac8c', 'CPSC', '2024-09-19', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Newmemo Children''s Ring Sets', 'The Rings Contain Levels Of Lead That Exceed The Federal Lead Content Ban And Levels Of Cadmium That Are Prohibited In Children''S Products By The Federal Hazardous Substances Act. Lead And Cadmium Are Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled rings, take them away from children and contact Newmemo for a full refund. Consumers will be asked to dispose of the recalled jewelry and send a photo of the disposed product to cly2167@163.com. Newmemo and Amazon are contacting all known purchasers directly.', '24366');
INSERT INTO safety_incidents VALUES ('f8d57cca912feabb6ccc3959695f0547d9d76042', 'CPSC', '2024-09-19', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Platform Beds with Upholstered Square Tufted Headboards', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 245 reports of the beds breaking, sagging or collapsing during use, causing 18 injuries, including contusions and bruises.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled beds and contact Lucid for a free replacement bed frame. Consumers must write "recalled" on the support rails of the bed with a permanent marker and send a photo of the bed, as well as a photo of the support rails on the underside of the bed or a photo of the law label, to recall@lucidmattress.com to receive the free replacement product.', '24372');
INSERT INTO safety_incidents VALUES ('0e80f4b5989b510327e4f469a0308e5574aa02c9', 'CPSC', '2024-09-19', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Place & Time battery-operated desk lamps', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received three reports of the battery compartment melting or popping while the lamp was charging with the USB cord. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled desk lamps and return them to Jo-Ann Stores for a full refund. Consumers without a purchase receipt will receive a $23 store credit. Consumers who are unable to return the lamp to a store can email a photo of the purchase receipt to customer.service@joann.com with the subject "Desk Lamp Recall Refund" to receive an electronic gift card for the amount on the purchase receipt, or a $23 store credit if the consumer does not have the receipt and provides a photo of the lamp.', '24373');
INSERT INTO safety_incidents VALUES ('e980597ed97a0d786a27e356ac4fe46ffbb0416a', 'CPSC', '2024-09-19', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Model Year 2024 RANGER XD 1500 and Crew XD 1500 Recreational Off-Road Vehicles (ROVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of fire. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the winch in the recalled ROVs and contact an authorized Polaris dealer to schedule a free repair to confirm a proper winch ground connection at the dealer''s location. Polaris is contacting registered owners directly.', '24374');
INSERT INTO safety_incidents VALUES ('12e0e210974f9015d61f66f48cd87f51cf00e20e', 'CPSC', '2024-09-19', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Model Year 2023-2024 Polaris Sportsman 850, XP 1000, and XP 1000 S ATVs and fuel pump kits and fuel tank assemblies', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 14 reports of fuel leaking from the recalled ATVs and three reports of fire. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact an authorized Polaris dealer to schedule a free repair to replace the fuel pump at the dealer''s location. Polaris is contacting registered owners directly.', '24369');
INSERT INTO safety_incidents VALUES ('c522a3ec090c632d4af0b76495c2bfc33481a476', 'CPSC', '2024-09-19', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Baby Tummy Time Gallery', 'The Recalled Baby Tummy Time Gallery Art Card Pockets Have Clear Plastic Coverings That Contain Levels Of A Phthalate That Exceeds The Federal Phthalates Ban. Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Baby Tummy Time Gallery and contact Wee Gallery for information on how dispose of the product and to obtain a refund of $39.95. Wee Gallery and Amazon.com are contacting all known purchasers directly.', '24368');
INSERT INTO safety_incidents VALUES ('5dd9aa668cfe4abe48cc35be8a8dd38d277b2612', 'CPSC', '2024-09-12', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'AirJet and HydroJet Spa Pumps', 'Fire', 'Flammability / Overheating', 'Not Specified', 'CPSC is aware of at least three fires reportedly involving the spa pumps, including one house fire that occurred in January 2024 in Kansas City, Missouri, which resulted in a fatality, and one additional fire that resulted in significant property damage. No additional injuries have been reported. There are seven additional incidents reportedly involving the spa pumps, which are currently under investigation. At this time no injuries have been reported with these additional incidents.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled spa pumps, and contact Bestway to receive a free replacement spa pump or a refund of $100 for AirJet spa pumps, or $189 for HydroJet spa pumps.', '24359');
INSERT INTO safety_incidents VALUES ('91249675833c2bcfa9eec86a3c75097ebe6f4dbb', 'CPSC', '2024-09-12', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Cadet-branded Apex72 Electric Heaters', 'Fire', 'Mechanical Failure', 'Not Specified', 'The firm has received one report of a heater fan malfunctioning and causing the unit to ignite. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled heaters and contact Glen Dimplex for information on the free heater replacement and installation of the new heater at no cost to the consumer. Glen Dimplex Americas is working with apartment complexes and other living facilities directly to replace the recalled heaters and install replacements. For consumers who purchased and installed the recalled heater independently, Glen Dimplex Americas will provide for the installation of the replacement heater by a qualified technician at no cost to the consumer.', '24360');
INSERT INTO safety_incidents VALUES ('cb27d8ef867dd6dc525a33e94a84be74e19a9774', 'CPSC', '2024-09-12', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'GOETAS Pool Drain Covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Regulations Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported.', 'Moderate', 1, 0, 'Pool owners/operators and consumers should immediately stop using pools with the recalled pool drain cover; and remove, replace and dispose of the recalled drain covers. Take a photo of the recalled cover and send it to the recalling firm by email at Atlaspool@163.com to receive a full refund. Ensure all pools and spas have Virginia Graeme Baker Pool and Spa Safety Act (VGBA) compliant drain covers and teach children to stay away from drains. Amazon is contacting all known purchasers directly.', '24361');
INSERT INTO safety_incidents VALUES ('238b8b6d31780209a38986cbb1633c969b2ba27e', 'CPSC', '2024-09-12', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Bright Builder Fort Kits with Flashlights', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'Intellio Toys has received one report of the batteries coming out the flashlight while handling it. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the flashlights in the recalled fort kits, keep them away from children, and contact Intellio Toys for instructions on how to receive a refund between $10 and $15, depending on the model. Consumers can continue to use the fort kits without the flashlights. Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local procedures for hazardous household waste. Amazon and Intellio Toys are contacting all known purchasers directly.', '24363');
INSERT INTO safety_incidents VALUES ('f3df5b9b50db3de63789334c981abace5c86f5e8', 'CPSC', '2024-09-12', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'MJKSARE High Chairs', 'Falls', 'Entrapment', 'Entrapment', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the high chair, and contact TONGAO for instructions on how to dispose of the chair and receive a full refund. Amazon is contacting all known purchasers directly.', '24362');
INSERT INTO safety_incidents VALUES ('43126f3b100b369b3794002a33833dbc505fe3c9', 'CPSC', '2024-09-12', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Petzl GYM, PANDION and PANJI climbing harnesses', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'There has been one report of a user in the United States suffering serious injuries from a fall.', 'Fatal', 1, 0, 'Consumers and operators of climbing gyms, adventure parks, search and rescue operations, and adventure guide companies should immediately stop using the recalled harnesses and contact Petzl America for a free repair.', '24358');
INSERT INTO safety_incidents VALUES ('5c521113af2309b306e7dfd681ffcae331b4e43a', 'CPSC', '2024-09-12', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Stanley Jr. Kids Wheelbarrow and 7-piece Garden Sets', 'The Painted Long Hoe And Rake Of The Recalled Garden Set Contain Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Lead Poisoning Hazard To Children. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported.', 'Moderate', 1, 0, 'Consumers should stop using the long hoe and rake in the garden set immediately. Visit Red Toolbox''s recall website, https://www.recall-rtb.com/, for information on how to obtain a free replacement long hoe and rake. The consumer will need to fill out a form and upload photos of disposing these items and the white label on the bottom of the wheelbarrow showing the 12.2023 manufacturing date. Costco is contacting all known purchasers directly.', '24357');
INSERT INTO safety_incidents VALUES ('18bbb4784ecb7495f752715c9a362d99a77dc334', 'CPSC', '2024-09-05', 2024, '2024-09', 'USA', 'United States', '', 'Other', 'Ceiling Hoists with Straps', 'Injury', 'Entrapment', 'Not Specified', 'The firm has received four reports of incidents, including one minor injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the Ceiling Hoist with Straps and contact Delta Cycle Corp to receive free replacement straps. Consumers should cut the old straps with buckles in half and discard them. If consumers are using the ceiling hoist to hold a bicycle (and not using included straps), no recall action is needed.', '24354');
INSERT INTO safety_incidents VALUES ('db454e3e19ce5c24a05651103fd41e47c20824df', 'CPSC', '2024-08-29', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Dumbbell toy sold with Baby Biceps Gift Set', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received seven reports in the United States of the ends of the dumbbell coming off of the product. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled dumbbell toy, take it away from young children, and contact Fisher-Price to receive a refund. Visit www.service.mattel.com/us/recall.aspx for instructions on how to upload a photograph of the dumbbell toy and how to properly dispose of it. Once the consumer provides confirmation that the dumbbell toy will be disposed of as directed, the consumer will be paid $10 for the dumbbell toy only. Consumers can keep the remaining toys in the Baby Biceps Gift Set. Proof of purchase (receipt) is not required to receive a refund for the dumbbell.', '24351');
INSERT INTO safety_incidents VALUES ('0c3d0a187eaa40d85324b45ff7cfa6dec2d8f4fc', 'CPSC', '2024-08-29', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Glow in Dark Party Supplies Toy Sets', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Bunny Ears Headbands found in Glow in Dark Party Supplies Toy Sets and take them away from children. Consumers should cut the battery compartment off the Bunny Ears Headbands and contact OleOleToy for instructions on how to receive a full refund. Button cell batteries are hazardous. Batteries should be disposed of or recycled by following local procedures for hazardous household waste. Amazon is notifying all known purchasers directly.', '24352');
INSERT INTO safety_incidents VALUES ('cd718441c503e52660e6e56d8b89898a1497ad98', 'CPSC', '2024-08-29', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'HALO 1000 Portable Power Stations', 'Fire', 'Flammability / Overheating', 'Respiratory', 'A 79-year-old man in Bradenton, Florida died from smoke inhalation from a fire involving the recalled portable power station in his home in June 2022. In addition to the death, the firms have collectively received four reports of fires involving the HALO 1000 Portable Power Station, including two reports of smoke inhalation, one of which included burn injuries.', 'Fatal', 1, 0, 'Consumers should immediately stop using the portable power stations and contact the HALO Recall hotline for a free replacement portable power station.', '24350');
INSERT INTO safety_incidents VALUES ('07b9f66a9991e57c4377c4dd8beacfc7407de8e9', 'CPSC', '2024-08-22', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'TRUBLUE Speed Auto Belay Devices', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received one incident report involving brake failure, causing the user to fall, resulting in a broken ankle.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled auto belay devices and contact Head Rush Technologies for a free inspection and repair. Head Rush Technologies is contacting all known purchasers directly.', '24347');
INSERT INTO safety_incidents VALUES ('95e47167abc1a7cde82b827297711ff5869aa461', 'CPSC', '2024-08-22', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Squeeze Plush Ball Toys', 'Injury', 'Drowning Risk', 'Eye Injury', 'The firm has received two reports of incidents. One incident involved a child having their eyes flushed out by a medical professional to remove glitter.', 'Moderate', 1, 0, 'Consumers should immediately stop using the Squeeze Plush Ball Monster Squeezable and Easter Squeezable toys and return the toys to the store where purchased for a full refund of $5 in the form of cash. If it is not possible for a consumer to return the recalled product to a store, they can contact Shawshank for a postage-paid label to return their toys to Shawshank for a full refund of $5 in the form of a check.', '24348');
INSERT INTO safety_incidents VALUES ('0ebbd20514250e044eacd8b66abc2e242054c83b', 'CPSC', '2024-08-22', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Siemens SolarReady Meter Combos', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received eight reports of overheating, including one report of a localized fire. No injuries have been reported.', 'Minor', 1, 0, 'Contact Siemens to determine if your SolarReady Meter Combo is included in this recall. Siemens will arrange for an on-site inspection, and repair or replacement of recalled meter combos by a licensed contractor at no cost to the consumer. Siemens is contacting distributors directly.', '24346');
INSERT INTO safety_incidents VALUES ('9b6f3a0affe9856f4a6284f89af2332488541eb0', 'CPSC', '2024-08-15', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Ambiano Single Serve Coffee Makers', 'Burns', 'Drowning Risk', 'Burns', 'ALDI has received 25 reports of the recalled coffeemakers expelling hot water from the top of the machine, including three reports of burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled coffee makers. Consumers may return the unit to an ALDI store for a full cash refund of $49.99, plus applicable sales tax. Alternatively, consumers may receive a $75 ALDI electronic gift card when they visit www.recallrtr.com/aldicoffeemaker, register the recalled coffee maker, and receive instructions on how to cut the unplugged cord, dispose of the product, and upload photos of the coffee maker showing the model number, registration number, and cut cord.', '24341');
INSERT INTO safety_incidents VALUES ('805c928a503b0bc05471a6f26cc8031e2b9c719d', 'CPSC', '2024-08-15', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Berkley Jensen Gazebos', 'Injury', 'Other', 'Not Specified', 'BJ''s Wholesale Club is aware of at least 137 incidents of panels dislodging from the gazebo''s roof, one resulting in minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled gazebos, stay away from them, and request a free repair kit, including shipping, to secure the gazebo''s roof panels.', '24745');
INSERT INTO safety_incidents VALUES ('171a1884a1689aa907a729234edbfd892aafe2c3', 'CPSC', '2024-08-15', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'VARMFRONT Power Banks', 'Fire', 'Flammability / Overheating', 'Not Specified', 'IKEA has received three incident reports globally. No injuries have been reported. Additionally, no incidents or injuries have been reported in the U.S.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled banks and return them to any IKEA store for a free replacement product or for a full refund. If you are unable to return it to a store, contact IKEA for instructions on how to dispose of the VARMFRONT Power Bank to receive a full refund. Proof of purchase (receipt) is not required to receive a full refund.', '24344');
INSERT INTO safety_incidents VALUES ('45c879d3fd069f0ed15b7a6754e6fa27a9f8b103', 'CPSC', '2024-08-15', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Mamibaby and Cosy Nation Baby Loungers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled loungers, and contact MEIXIA Shop for information on how to dispose of the product to obtain a full refund. MEIXIA Shop and Amazon are contacting all known purchasers directly.', '24340');
INSERT INTO safety_incidents VALUES ('a7df4608ad2c29fc0efcc21e3732846b8beccdb6', 'CPSC', '2024-08-15', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'DeWALT Battery Push walk-behind mowers and DeWALT Battery Self-Propelled walk-behind mowers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 10 reports of mowers failing to shut off when the bail handle is released and one report of a mower starting without a key inserted. The incident in which a mower started without a key inserted resulted in a finger laceration for which no medical attention was required.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mowers if the mower has gotten wet and contact DeWALT to receive a free repair at an authorized service center nearby.', '24345');
INSERT INTO safety_incidents VALUES ('d40b2ea71141661a601820bfff1b78d4cd186bcf', 'CPSC', '2024-08-15', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Mango Tangerine Scented Candles', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 14 reports of incidents involving high flames with the recalled candles, including three reports of minor property damage and two reports of minor burns.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Mango Tangerine Scented Candles sold in June 2024 and return the candle to any Trader Joe''s store for a full cash refund of $4, or complete the Product Feedback Form online at https://www.traderjoes.com/home/contact-us/product-feedback to receive a $4 Trader Joe''s gift card by mail. Consumers will receive a response from Customer Relations requesting a receipt or a photo of the candle.', '24342');
INSERT INTO safety_incidents VALUES ('10e7d24cf2557d5e45103c8c076c1c8f1f938294', 'CPSC', '2024-08-08', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Finger-Ease Guitar String Lubricants', 'The Recalled Guitar String Lubricant Contains A Contaminant, Posing A Risk Of Skin Irritation.', 'Other', 'Skin Irritation', 'The firm has received one report of minor skin irritation.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled guitar lubricant and contact Chem-Pak to receive a free replacement. Do not empty the product prior to disposal or pour the product down the toilet or drain. Consumers should mark the bottom of the product with the word "Recalled" and the date in permanent marker, then upload a photo of marked product, the product''s model number and lot code, and a photo of the disposed product in the trash, and submit the photo online at https://chem-pak.com/productrecalls/. Upon successful registration, the firm will issue a replacement to purchasers.', '24337');
INSERT INTO safety_incidents VALUES ('f27b0b13607c9eb98504bf925ba7714f21a3273a', 'CPSC', '2024-08-08', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Slide-in Electric Ranges', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Samsung has received over 300 reports of unintentional activation of the front-mounted knobs by humans or pets since 2013. These ranges have been involved in approximately 250 fires. At least 18 fires caused extensive property damage. Approximately 40 injuries have been reported, eight of which required medical attention, and there have been reports of seven fires involving pet deaths.', 'Fatal', 1, 0, 'Consumers should contact Samsung to receive a free set of knob locks or covers compatible with their model of electric slide-in range to install. Consumers using the recalled ranges without knob locks or covers are cautioned to keep children and pets away from the knobs, to check the range knobs to ensure they are off before leaving the home or going to bed, and to not leave objects on the range when the range is not in use. Consumers with Wi-Fi enabled ranges can enable the "Cooktop On" notification on the Samsung SmartThings app to receive alerts on their smartphone when a cooktop burner is turned on.', '24335');
INSERT INTO safety_incidents VALUES ('25758d73bca6a54fbaa441ba4769035263488b8f', 'CPSC', '2024-08-08', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'SMEG Refrigerators', 'Injury', 'Mechanical Failure', 'Fall Injury', 'The firm has received nine reports of the refrigerator door falling off. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled refrigerators and contact SMEG USA to schedule a free repair by a certified service provider. Consumers will be asked to email a photo of both the refrigerator''s model number and the serial number to recall@smegusa.com.', '24334');
INSERT INTO safety_incidents VALUES ('8b18c7e489c418f7664821db0b17197186ab9d83', 'CPSC', '2024-08-01', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'LED Light-up Jelly Ring Toys', 'Chemical', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled light-up jelly ring toys immediately, take them away from children, and contact Attom Tech for instructions on how to properly dispose of the product and receive a full refund. Button cell batteries are hazardous. Consumers should take the batteries to a recycling facility, or to their local facility that specializes in collection and disposal of household hazardous waste. Amazon is notifying all known purchasers directly.', '24328');
INSERT INTO safety_incidents VALUES ('9310285651ac3688f068cf8eb9fea2314e33fd7d', 'CPSC', '2024-08-01', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Beberoad New Moon Travel Bassinets', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bassinets and contact Beberoadlove for instructions on how to receive a full refund, and how to properly dispose of the product. Beberoadlove and Amazon are contacting all known purchasers directly.', '24324');
INSERT INTO safety_incidents VALUES ('143afcb5776633ae771abd067cbe5e60aeaa1f1c', 'CPSC', '2024-08-01', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Brompton T-Line Foldable Bicycles', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 13 reports of incidents of steering misalignment or loss of steering control worldwide. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact an authorized Brompton dealer to schedule an appointment for a free repair to tighten the steerer clamp bolts on the handlebar stem. Brompton is contacting all registered owners and dealers directly.', '24332');
INSERT INTO safety_incidents VALUES ('ed8d1b5bb7986d7dd0c1f2180b02219d6bcfc47a', 'CPSC', '2024-08-01', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'ECHO gas-powered backpack blowers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled blowers, and contact an authorized ECHO dealer (www.echo-usa.com/store-locator) to schedule an appointment to bring the ECHO gas-powered backpack blower in for free installation of a new replacement fuel line. ECHO is contacting all known purchasers directly.', '24329');
INSERT INTO safety_incidents VALUES ('d126b6d9ce3e41a6ecafa558904dc913dc4b899b', 'CPSC', '2024-08-01', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Avocado Organic Cotton Mattress Pad Protectors', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mattress pads and contact Avocado Green Mattress to obtain a free replacement mattress pad, including shipping, at no charge. Consumers should cut the mattress pad in two, and write the date and initial the law label attached to the mattress pad. Then, consumers should upload photos of the cut mattress pad and dated and initialed law label to www.avocadogreenmattress.com/pages/recall.', '24330');
INSERT INTO safety_incidents VALUES ('89d20961ea2fe9cdbdfa4a616f5125bcf7043640', 'CPSC', '2024-08-01', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Origin 21 Oval and Rectangle Black Framed Wall Mirrors', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 15 reports of the mirrors separating from the metal hanger and falling. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled mirrors, and contact Huahong Art Home Shares for instructions on how to receive a full refund. Consumers will be asked to email photos of the mirror to receive the refund, or arrange for a pre-paid shipping box. Huahong Art Home Shares is contacting all known purchasers directly.', '24327');
INSERT INTO safety_incidents VALUES ('da49f180a146189eeeb0543038ba823bf4a66589', 'CPSC', '2024-08-01', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Papablic Archie Infant Swings', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled swings immediately, and contact Shenzhen Two Pony for information on how to dispose of the products and submit proof of destruction to obtain a full refund. Shenzhen Two Pony and Amazon are contacting all known purchasers directly.', '24325');
INSERT INTO safety_incidents VALUES ('80e586e2787a13f019cbea5030c2d436a076bbed', 'CPSC', '2024-08-01', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Peace Sports Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled ATVs immediately and contact Peace Industry Group for a full refund.', '24326');
INSERT INTO safety_incidents VALUES ('6d5ba13c073806cf61e92b798f45c9d34b947dc0', 'CPSC', '2024-08-01', 2024, '2024-08', 'USA', 'United States', '', 'Other', 'Jeune French Contemporary Upholstered Panel Cribs', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received two reports of a metal insert loosening and detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cribs and contact RH to receive a full refund of the purchase price, or a new replacement crib with shipping at no charge. If no receipt is available, the consumer will receive a $1,260 cash refund, credit, or a new replacement crib with shipping at no charge. RH will provide free pickup of the recalled crib, and is contacting all known purchasers directly.', '24331');
INSERT INTO safety_incidents VALUES ('7c8d4a976cbc3262b106fd48e5c042804dabfc2d', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Lancaster Table & Seating Standard Height Plastic Restaurant High Chairs', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received nine reports of the T-bar located at the front of the chair coming loose or breaking off. Two injuries have been reported, including one report of a child falling out of the high chair, resulting in minor scrapes and bruises.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled high chairs and contact Clark Associates for a full refund. Consumers should register their product online at https://www.lancastertableandseating.com/recalls/plastic-high-chairs-recall and dispose of the product in accordance with local and state recycling laws.', '24311');
INSERT INTO safety_incidents VALUES ('83d12e95485ffb82f7ff0cb75bbfa60eeaf97de4', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Hover-1 Dynamo E-scooters', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'DGL Group has received 22 reports of the e-scooter''s brakes failing, which resulted in seven injuries, including abrasions, contusions, a dislocated shoulder, fractured teeth, lacerations and strains.', 'Serious', 1, 0, 'Consumers should stop using the recalled e-scooters immediately and contact DGL Group for instructions on how to receive a full refund. To receive a refund, consumers will be required to provide photographs of their e-scooter''s serial number and severed motor cable.', '24321');
INSERT INTO safety_incidents VALUES ('349766a7b58fd59b0451c09e78d76710dd4a3f21', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Wood dining chairs', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received three reports report of the chair breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled wood dining chairs and contact Grand Rapids Chair Company for a free repair, by Grand Rapids Chair Company personnel at the consumer''s location.', '24314');
INSERT INTO safety_incidents VALUES ('939eb5740dcc4cd7bb8a528564570d11d2e5291f', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'ProForm Rapid Strike 50 LB Adjustable Dumbbell Sets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'The firm has received eight reports of weight plates dislodging during use with three resulting in injuries, including contusions and abrasions.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ProForm Rapid Strike 50 LB Adjustable Dumbbell Sets, and contact iFIT to receive a free repair in the form of a replacement for the molded tray. iFIT is contacting all known purchasers directly.', '24310');
INSERT INTO safety_incidents VALUES ('a4e6a54cd67fd4369ff67e1674c13542b51e3c5b', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', '2024 Kawasaki Mule PRO 1000 Off-Highway Utility Vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Kawasaki has received three reports of fires occurring during engine start up. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact a Kawasaki dealer to schedule a free repair. A technician will reprogram the ECU and install a sub-harness on the vehicle. Kawasaki is contacting all known purchasers directly.', '24312');
INSERT INTO safety_incidents VALUES ('7ee267e811596aadaf76ce71d6c9ce1946611bd9', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Ophanie Large Pink Area Rugs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of a fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled rugs immediately and contact Ophanie for a full refund. Consumers will be asked to destroy the product by cutting it in half, and to provide proof of destruction by sending a photo of the cut product to recall@liyi99.com to receive a full refund. Ophanie is contacting all known purchasers directly.', '24315');
INSERT INTO safety_incidents VALUES ('991c5fefd5a96256b60e94c99a1e76aa5608fc05', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Razor Icon electric scooters', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 34 reports of partial or complete downtube separation with two reported injuries, including bruising.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled scooters and contact Razor to receive a refund or coupon. Consumers with proof of purchase for recalled scooters bought on or after March 11, 2023, can receive a full refund. All other consumers can request a $700 coupon for a future purchase on razor.com or a $300 refund. Consumers will be asked to remove the handlebar and return only the handlebar to Razor. Razor will send consumers a prepaid shipping label and pouch for the return. The scooter''s lithium-ion batteries must be disposed of in accordance with any local and state laws, and not in the trash. The rest of the scooter should be disposed of separately in accordance with any local and state laws.', '24313');
INSERT INTO safety_incidents VALUES ('4c8388a1190b4eeab3879dbe546909b6b98b852e', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Besrey Twins Strollers', 'Choking', 'Entrapment', 'Entrapment', 'None reported.', 'Moderate', 1, 0, 'Consumers should stop using the stroller immediately and contact Stiger for information on how to dispose of the product to obtain a full refund. Stiger and Amazon are contacting all known purchasers directly.', '24316');
INSERT INTO safety_incidents VALUES ('7af4f7c4e410fa24ffe27dd91aa054e23f4624d4', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', '2024 Arctic Cat Mountain 600 Snowmobiles', 'The Pin On The U-Joint Of The Steering Knuckle Was Not Swagged Correctly, Which Can Allow The Pin To Come Out Of The U-Joint And Cause The Rider To Lose Steering Control, Posing A Crash Hazard.', 'Instability / Fall Risk', 'Skin Irritation', 'The firm has received six reports of cross pins that have become loose or have fallen out. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the 2024 Arctic Cat Mountain 600 Snowmobile, and contact their local authorized Arctic Cat dealer for a free inspection of the steering column u-joint and free repair, if needed. The steering post joint on the Snowmobile will be inspected. If the pin is properly swagged, there is no repair needed. If the steering post joint pin was not properly swagged, the entire steering post assembly will be replaced.', '24317');
INSERT INTO safety_incidents VALUES ('2d4b2ce8917c797c340f719b290009cec4f05dac', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Essential Values Golf Grip Solvent and Golf Grip Kits', 'The Recalled Cleaning Product Violates The Federal Hazardous Substances Act Because It Is Deceptively Labeled As "Safe And Non-Toxic" And Lacks The Required Cautionary Statements For Petroleum Distillates, Posing A Risk Of Poisoning To Consumers.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Golf Grip Solvent and/or Golf Grip Kits and contact Torquay eTrading for information on how to obtain a free corrected label to put on the bottle. Torquay eTrading, Amazon, eBay and Walmart are contacting all known purchasers directly.', '24322');
INSERT INTO safety_incidents VALUES ('9ce5a2206cad40338e941e9106ee5d014eaf0bed', 'CPSC', '2024-07-25', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Victor Electric Folding Soft Bullet Toy Guns', 'Injury', 'Other', 'Eye Injury', 'None reported.', 'Moderate', 1, 0, 'Consumers should stop using the recalled toy guns immediately and contact Youjiu for a full refund. To receive a refund, consumers should remove the magazine and the battery, cut the black and red wires linked to the battery, take a photo of the destroyed toy gun, and send the photo to Youjiu''s store through Temu''s onsite messaging system at https://www.temu.com/fr-en/office-king-m-55622325238.html.', '24318');
INSERT INTO safety_incidents VALUES ('216c56a621724982731e6a66cae38ca1c452fb19', 'CPSC', '2024-07-18', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'BISSELL® Steam Shot™ Handheld Steam Cleaners', 'Burns', 'Drowning Risk', 'Burns', 'BISSELL has received 183 reports of hot water or steam escaping from the product, including 157 reports of minor burn injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled steam cleaners, and contact BISSELL to receive either a $60 credit to be used towards a BISSELL.com purchase, or a $40 refund for each of the recalled steam cleaners. Consumers should visit www.BISSELL.com/steamshotrecall to register for the recall, and for instructions on how to cut the cord and take and upload a photo of the steam cleaner showing the model number and cut cord.', '24309');
INSERT INTO safety_incidents VALUES ('bfa5b23d6754e9b216eb766278a33552102bbaba', 'CPSC', '2024-07-18', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'CFMOTO ZFORCE 950 HO Sport Side-by-Side ROVs (2022-2023)', 'The Shock Absorber Rod Assembly Can Unthread And Detach, Causing Suspension Collapse, Posing Crash And Tip-Over Hazards To The Rider.', 'Mechanical Failure', 'Fall Injury', 'CFMOTO Powersports has received approximately 86 reports of incidents in which the shock absorber failed and the suspension collapsed, including one tip-over which resulted in impact injury to the ribs.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ROVs, and contact an authorized CFMOTO dealer to schedule an appointment to bring the recalled vehicle into the dealer for a free repair. CFMOTO has issued a Stop Ride notice to consumers, and is contacting all registered owners and dealers directly to provide more details about the repair.', '24307');
INSERT INTO safety_incidents VALUES ('8f39bfdd8f0bf74736aa4ef6d7da63805e84d1be', 'CPSC', '2024-07-18', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Brilliant Bee Rattles', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled rattles, take them away from children, and return the product to the place of purchase to receive a full refund, or contact Manhattan Toy for instructions on how to return the product to receive a full refund. Proof of purchase is not required to receive a full refund.', '24308');
INSERT INTO safety_incidents VALUES ('e6914266796557df02d931c921747d455b6bd777', 'CPSC', '2024-07-11', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Atomi Smart Heaters', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received one report of the heater turning on without user input. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled heaters, unplug the units, and follow the instructions online at www.atomiheaterrecall.com to receive a full refund. Consumers will be asked to cut the unplugged unit''s power cord and upload a photograph of the cut cord, as well as a photograph of the manufacturer''s label on the underside of their units during the registration process.', '24298');
INSERT INTO safety_incidents VALUES ('e27877fd39e278fb31e286fdce29a1d543b77cdc', 'CPSC', '2024-07-11', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'LED High Bay Light Fixtures', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received three reports of fires involving the recalled fixtures. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately inspect the fixture for any sign of pin degradation, a loose LED board, or discoloration of the lens. Consumers should immediately stop using light fixtures that show any sign of a loose LED board or discoloration of the lens, and turn the circuit off. Customers can contact BLP for more information, and register online at www.highbayrecall.net to schedule a free inspection and on-site repair to replace the plastic pins with metal pins.', '24302');
INSERT INTO safety_incidents VALUES ('70706d173952d5108f3b1f91c2b9167749188096', 'CPSC', '2024-07-11', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Lovely Angel Children''s Lace Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children, stop using them, and contact Lovely Angel to receive a full refund. Consumers should destroy the garments by cutting them in half and disposing of them in accordance with local and state recycling laws. Consumers should send the recalling firm a photo of the destroyed garment at wangmaxime@163.com or via Lovely Angel''s online store to receive a refund. Lovely Angel is contacting all known purchasers directly.', '24300');
INSERT INTO safety_incidents VALUES ('39b0527ed1e5671bc39754904028c0989e96abb2', 'CPSC', '2024-07-11', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Children''s Long-Sleeve/Pants Two-Piece Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them, and contact Fashion Online to receive a full refund. Consumers should destroy the garments by cutting the top and bottom in half and disposing of them in accordance with local and state recycling laws. Consumers should send the recalling firm a photo of the destroyed garments by email at 327937323@qq.com, or via message to Fashion Online on Temu.com to receive a refund. Fashion Online is contacting all known purchasers directly.', '24296');
INSERT INTO safety_incidents VALUES ('37bdd85cc046ce74716fde5f77544c5c4f1387c1', 'CPSC', '2024-07-11', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Children''s Button-up Short-Sleeve/Shorts Two-Piece Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them, and contact JUVENNO KIDS to receive a full refund. Consumers should destroy the garments by cutting the top and bottom in half and dispose of them in accordance with local and state recycling laws. Consumers should send the recalling firm a photo of the destroyed garments by email at 603262718@qq.com or via message to JUVENNO KIDS on Temu.com to receive a refund. JUVENNO KIDS is contacting all known purchasers directly.', '24301');
INSERT INTO safety_incidents VALUES ('01fa3e63a9bdcbe77c1a5f0e50b3e5f6873b3c1e', 'CPSC', '2024-07-11', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Halloween Witch Hats', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled hats and return the product to any Claire''s or Icing store for a full refund.', '24299');
INSERT INTO safety_incidents VALUES ('4fd0dbf9eb1941c4046b967baf9e960736cef197', 'CPSC', '2024-07-11', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Metal-framed Armchairs', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received five reports of the chair legs breaking; four resulting in minor injuries, including soreness and contusions.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled armchairs and return them to any Ross store. Consumers will receive a full refund or a $50 store credit. No purchase receipt will be required.', '24297');
INSERT INTO safety_incidents VALUES ('2afbad6441399885aea47c89fd656d818375ff00', 'CPSC', '2024-07-11', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'TonGass pool drain covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Standards Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported.', 'Moderate', 1, 0, 'Pool owners/operators and consumers should immediately stop using pools with the recalled pool drain covers. To receive a refund, consumers should remove the drain cover from the pool, take a photo, and send it to the recalling firm by email at tongass@126.com. Ensure all pools and spas have Virginia Graeme Baker Pool and Spa Safety Act (VGBA) compliant drain covers, and teach children to stay away from drains. TonGass is contacting all purchasers directly.', '24303');
INSERT INTO safety_incidents VALUES ('10d3d1e39f9d2d8895a9f4e97fe6d3a2a377b918', 'CPSC', '2024-07-03', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Model Year 2023-2024 Off-Road Motorcycles', 'Injury', 'Mechanical Failure', 'Skin Irritation', 'The firm has received one report of a crash, resulting in a knee injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled off-road motorcycles, and contact American Honda Motor to schedule an appointment for a free inspection and repair. Honda is contacting all known purchasers directly.', '24288');
INSERT INTO safety_incidents VALUES ('e4e99bbdfaa5affea2bc36bf130c03783c4d9ae9', 'CPSC', '2024-07-03', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Tideway High-Speed Hair Dryers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately unplug and stop using the recalled hair dryers, and contact Tideway Shop to receive a free replacement. Consumers should destroy the recalled hair dryers by unplugging the hair dryer, cutting the cord and disposing of them in accordance with local and state recycling laws, and send an image of the destroyed hair dryer to info@tideway.shop or tidewayshopify@gmail.com. Upon receipt of the photo, Focusee will send the customer a replacement hair dryer with an immersion protection device.', '24290');
INSERT INTO safety_incidents VALUES ('ff5cbe698c48da9067e3aab8103afe6abee3f159', 'CPSC', '2024-07-03', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'Power Adapters sold with Rest 1st Generation sound machines', 'The Plastic Housing Surrounding The Ac Power Adapter Supplied With Some Rest 1St Generation Sound Machines Can Come Off When Removing The Adapter From The Power Outlet, Leaving The Power Prongs Exposed And Posing A Shock Hazard To Consumers.', 'Electrical Fault', 'Electric Shock', 'The firm has received 19 reports of the plastic housing surrounding the AC power adapter coming off, including two reports of consumers who experienced a minor electrical shock.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled power adapters sold with Rest 1st Generation sound machines, and contact Hatch for a free replacement power adapter. Consumers should unplug the cord, cut the cord on the recalled power adapter, take a photo of the adapter showing the model number and the cut cord, upload the photo, and provide their name and mailing address at www.hatch.co/adapterrecall. Hatch is contacting all registered owners directly.', '24291');
INSERT INTO safety_incidents VALUES ('69ef4c33340fc826cfdcdf2dfea2de94ec45d0ec', 'CPSC', '2024-07-03', 2024, '2024-07', 'USA', 'United States', '', 'Other', 'SWOMOG Children''s Two-Piece Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them and contact SWOMOG to receive a full refund. Consumers should destroy the garments by cutting the top and bottom in half, and disposing of them in accordance with local and state recycling laws. Consumers should email the recalling firm a photo of the destroyed garment at swomogservice@163.com to receive a refund. SWOMOG is contacting all known purchasers directly.', '24289');
INSERT INTO safety_incidents VALUES ('5cf686d4ba9aee7da3d6d51da5172b0c9eb76781', 'CPSC', '2024-06-27', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Tie Dye Fur Toy Trunk Storage Chests', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled toy storage chests, and return them to any At Home store for a full refund.', '24284');
INSERT INTO safety_incidents VALUES ('1878a582bfab6185aea31fc488bb9766dc0c94c1', 'CPSC', '2024-06-27', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Baseus Magnetic Wireless Charging Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'Baseus has received 171 reports of incidents, including 132 reports of bulging or swelling batteries and 39 reports of fires, resulting in 13 burn injuries and about $20,000 in property damage.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Baseus power bank models, and contact Baseus for a full refund with proof of purchase, or a $36 cash refund without proof of purchase. Consumers will need to submit a photo of the recalled power bank showing the model number to the firm''s recall registration page. Consumers without an order number will need to submit a photo of the power bank with their name and the date written in permanent marker. Baseus and Amazon are notifying all known purchasers directly. Consumers should dispose of the battery in accordance with local and state regulations.', '24287');
INSERT INTO safety_incidents VALUES ('48dc43b0565d52003b613ece6e1adc4e29be2f88', 'CPSC', '2024-06-27', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Daikin FIT, Amana Brand S-series, and Goodman SD heat pumps', 'A Power Interruption In The Heat Pump Can Result In The Product Providing Heat When The Power Resumes, Despite The Thermostat Being In Cooling Mode, Posing A Risk Of Excessive Heat Exposure To Consumers.', 'Other', 'Not Specified', 'None reported', 'Minor', 1, 0, 'Daikin Comfort Technologies (DCT) is updating the software remotely for consumers whose Daikin FIT, Amana Brand S-series, and Goodman SD heating and cooling systems are connected to WiFi. Consumers with systems not connected to WiFi should register for the recall at http://www.goodmanmfg.com/fit-recall to receive instructions to perform the update.', '24286');
INSERT INTO safety_incidents VALUES ('fe7baab64906ebf3e5ef7c87952fef0364dcd6d7', 'CPSC', '2024-06-27', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Hayden Bookcase', 'The Recalled Bookcase Is Unstable If It Is Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Death Or Serious Injuries To Children.', 'Entrapment', 'Entrapment', 'In August 2023, Dania Furniture received one report of a tip-over incident with an unanchored bookcase that resulted in the death of a 4-year-old child.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bookcase, if it is not anchored to the wall, and place it in an area that children cannot access. Contact Dania Furniture to set up a free in-home installation of a tip-over restraint kit. If mounting/anchoring services cannot be completed for any reason, or if consumers would prefer a refund, Dania Furniture will provide a full refund of the purchase price of the recalled bookcase to consumers upon its return, and arrange for the pickup and/or disposal of the recalled bookcase. Dania Furniture is also contacting all purchasers directly.', '24744');
INSERT INTO safety_incidents VALUES ('dc39f75c9602b1784d646885fc447c233ae8faec', 'CPSC', '2024-06-27', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Co-op Cycles REV 12-, 16-, or 20-inch Kid''s Bicycles with training wheels (all model years 2022-2024)', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received four reports of the training wheels falling off. Injuries included reports of scrapes, bruising, and one involving broken arms.', 'Moderate', 1, 0, 'If training wheels are being used, consumers should immediately stop using the recalled bicycle, and contact their local REI store to schedule a free repair that includes replacement training wheel attachments. If it is not possible to visit an REI store, contact REI for a free repair kit to be shipped. If the bicycle is being ridden without training wheels, customers can continue using the bicycle.', '24283');
INSERT INTO safety_incidents VALUES ('3590c892ca417d90b9502976ee6ac24f7db84f97', 'CPSC', '2024-06-27', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Brookstone TurboVac Handheld Rechargeable Vacuums', 'Fire', 'Electrical Fault', 'Not Specified', 'The firm has received two reports of serious fires caused by the vacuums, resulting in property damage.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Brookstone TurboVac Handheld Rechargeable Vacuums (Model No. BSBVAC301), and contact Southern Telecom to receive a full refund.', '24285');
INSERT INTO safety_incidents VALUES ('5757853fa262ac82c4fcdce08865da0774481e15', 'CPSC', '2024-06-25', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Miniverse Make It Mini Sets with Liquid Resins', 'The Recalled Make It Mini Sets Contain Resins That, When Liquid, Can Cause Skin, Eye, And Respiratory Irritation Or Sensitization When Inhaled, Touched, Or Ingested By Children Or Adults. The Resins Contain Acrylates (Hydroxyethylmethacrylate "Hema" And Isobornyl Acrylate "Iboa") In Amounts Prohibited In Children''S Products By The Federal Hazardous Substances Act. After The Resins Cure, They No Longer Present This Hazard.', 'Chemical / Toxic Substance', 'Respiratory', 'MGA has received 26 reports of incidents with this product from children and adults, including reports of skin burns and irritation, and respiratory irritation, with one report that a consumer''s asthma was triggered.', 'Moderate', 1, 0, 'Consumers should immediately stop using any units with unused resins and contact MGA to receive a pre-paid label to return either: (a) the entire product, including the unused resin, if the product has not been opened, or (b) the unused resins and a photograph of the product, if the product has been opened. Consumers will receive a full refund or replacement product, at the consumer''s choice.', '24281');
INSERT INTO safety_incidents VALUES ('b404d5922413ea51998e1c178d74040b15cb78a7', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Cargo bicycles', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Cargo bicycles, and contact Babboe for a full refund and to arrange for the company to pick up the bicycle.', '24275');
INSERT INTO safety_incidents VALUES ('e254217e1c583a9854ef1cda40f87aebb423fbc3', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Frontgate Resort Collection Newport Aluminum and Teak Chaises', 'When Adjusting The Backrest While Seated, The Adjustable Backrest Can Unexpectedly Descend With Force, Posing Finger Crushing And Amputation Hazards.', 'Entrapment', 'Entrapment', 'Cinmar has received three reports of incidents involving consumers'' fingers becoming entrapped between the adjustable backrest and the chair frame, resulting in two partial finger amputation injuries, and one finger-crushing injury requiring surgery.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled chaise lounge chairs, and contact Cinmar for a free repair. Consumers must submit a photo of the chaise to Cinmar to receive a free repair kit, including a new backrest support bar and assembly instructions.', '24273');
INSERT INTO safety_incidents VALUES ('d5d790a0659684bdec1ec8d2b418e0c236e9a7be', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Yeti Link Expansion Modules and EC8 Cables', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received two reports of the cables melting inside a vehicle, causing minor property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Yeti Link modules and cables, and contact Goal Zero to receive a free replacement kit. The kit includes a new Yeti Link module and all the necessary cables with a new connector and instructions. Goal Zero will mail a box and prepaid postage to each consumer who registers at www.goalzero.com/pages/notices-recalls. All replacement kits will be mailed to consumers after they have returned the recalled module. All cables can be discarded in the household trash. Goal Zero is contacting all known purchasers.', '24270');
INSERT INTO safety_incidents VALUES ('efde197a89d5168e24c973a4fa82c769578c6dd3', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'TRUBLUE iQ Auto Belay Devices', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 31 reports of incidents involving impaired retraction, including one consumer fall. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using recalled auto belay devices, and contact Head Rush Technologies for a free inspection and repair.', '24277');
INSERT INTO safety_incidents VALUES ('d4077649eaa86c4249cf080a5038a39ba79ae149', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'JoyJolt Drinkware Declan Single-Wall Glass Coffee Mugs', 'Burns', 'Sharp Edges / Points', 'Laceration / Cut', 'There have been 103 incidents of the recalled coffee glasses breaking at the base, resulting in 56 injuries, including 35 burns across the body from spilled hot liquids, and 21 cuts. Seven incidents required medical attention, including surgery and stitches.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled coffee glasses, and contact MM Products for a full refund.', '24272');
INSERT INTO safety_incidents VALUES ('21aba7eb4c76739fd9c1998f2c08b0c347f182e7', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'myCharge POWER HUB All-In-One 10,000mAh portable chargers', 'Fire', 'Flammability / Overheating', 'Burns', 'There have been a total of 120 reports involving the portable chargers overheating. myCharge received five reports of incidents, including two reports of residential fires, resulting in approximately $165,000 in reported property damage; and Costco received 115 returns of the portable chargers, mentioning melting, expanding, smoking, fire, burning, exploding, or sparking. There have been no reports of injuries requiring medical attention.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled portable chargers, and contact myCharge for a free replacement portable charger.', '24271');
INSERT INTO safety_incidents VALUES ('3322fb77f1bd213d6487dc476cff5fde5adc6f44', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Lavender scented candles in a round wooden bread bowl', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received eight reports of flames reaching excessive heights, including three reports of minor burns.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled lavender scented candle in a round wooden bread bowl, and return the product to any Cracker Barrel Old Country Store® location for a full refund.', '24278');
INSERT INTO safety_incidents VALUES ('49b629b7ba3772dc45067506ebfe2b489ab49577', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Cedona Natural View six-drawer dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Do Not Comply With The Performance Requirements Of The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the dresser immediately and contact Rooms To Go for a free replacement. Rooms To Go will schedule a free delivery of the replacement and remove the recalled dresser. Rooms to Go is contacting all known purchasers directly.', '24279');
INSERT INTO safety_incidents VALUES ('8d8d4e2df75480f02ee899f9f0bf21a30bc4a73d', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Instinct Professional Vector Motor Cordless Hair Clippers', 'Fire', 'Flammability / Overheating', 'Burns', 'StyleCraft has received six reports of the batteries overheating or causing a fire, including one minor burn.', 'Minor', 1, 0, 'Consumers should immediately stop using and charging the recalled clippers, and visit StyleCraft for instructions to remove the battery and to receive a free battery replacement. Batteries can be replaced by visiting one of StyleCraft''s authorized service centers, or by returning the unit to StyleCraft by mail in a pre-paid shipping package. Consumers should dispose of the battery in accordance with local and state regulations.', '24269');
INSERT INTO safety_incidents VALUES ('6c9eebafa8fe20ac1544f67d7fdbb0ec1ed4bc92', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Theefun Kids Gardening Tools Sets', 'The Brown Handle Strings Contain Levels Of Phthalates That Exceed The Federal Phthalate Ban. Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take these recalled toy gardening tools sets away from young children, and contact Thousandshores to receive a full refund. Consumers should cut off the brown handle strings from the gardening tools and dispose of them in accordance with local and state recycling laws. Thousandshores and Amazon are contacting all known purchasers directly.', '24274');
INSERT INTO safety_incidents VALUES ('3e248ea8617f262a3e860b5faa0101ed913aa05c', 'CPSC', '2024-06-20', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Vitamix Ascent® Series and Venturist® Series 8-ounce and 20-ounce Blending Containers and Blade Bases', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Vitamix has received 27 reports of lacerations, including 11 reports from the prior 2018 recall, when consumers'' hands came in contact with exposed blades.', 'Moderate', 1, 0, 'All consumers, including consumers who participated in the 2018 recall, should immediately stop using the recalled 8-ounce and 20-ounce blending containers and blade bases, and contact Vitamix for a repair kit consisting of a protective plastic shroud to attach over the blade base and additional instructional labels.', '24276');
INSERT INTO safety_incidents VALUES ('2f08be1a10f2362730e0c874ad8e3bc90053a3ee', 'CPSC', '2024-06-13', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Nap Queen Sleep Victoria Hybrid Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should stop using the recalled mattresses immediately, and contact Nap Queen to receive a free fitted cover to put on their mattress to bring it into compliance with the federal standard. The firm is contacting all known purchasers directly.', '24263');
INSERT INTO safety_incidents VALUES ('8a8935c18e3b1cd4c1a1288a4b15172367a73461', 'CPSC', '2024-06-13', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Bambu Lab A1 3D printers', 'Fire', 'Electrical Fault', 'Electric Shock', 'The firm has received a total of 19 reports of damaged cables, including one cable sparking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled 3D printers, and contact Bambu Lab to arrange either (1) return of their A1 3D printers for a full refund, or (2) for free replacement of the heatbed and cable by a local electronics repair facility. Consumers requesting a full refund will be sent a prepaid shipping label to return the printer. Consumers should not attempt to fix the recalled product themselves. Bambu Lab has contacted all known purchasers.', '24264');
INSERT INTO safety_incidents VALUES ('00009be34ca29bf4510287843a6e874ddddd361e', 'CPSC', '2024-06-13', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Neve Strap Crampons and Accessory Kits', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received three reports of incidents of the crampons becoming loose or the heel cup becoming detached by hikers. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Neve Strap Crampons and accessory kits, and contact Black Diamond Equipment to receive a full refund. Consumers will receive a prepaid return label to mail them back to Black Diamond Equipment, after which they will be issued a refund. The firm is contacting all known purchasers.', '24261');
INSERT INTO safety_incidents VALUES ('96b2c55698e9b8de7470eef21c7f3af692628c18', 'CPSC', '2024-06-13', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Amana, Daikin, and Goodman branded air conditioning and heat pump packaged units', 'Fire', 'Electrical Fault', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should not attempt to open the outside electrical panel of the recalled air conditioning and heat pump units, and immediately contact Daikin Comfort Technologies Manufacturing L.P. (DCT) for a free repair and inspection. DCT is contacting all known purchasers directly.', '24260');
INSERT INTO safety_incidents VALUES ('fa2a302097a977e7fb8d4afc2129ef9473fc0826', 'CPSC', '2024-06-13', 2024, '2024-06', 'USA', 'United States', '', 'Other', '1 Set Puzzle "Magnetic", "Magnetism", or "Magnetism Intelligence Strategy Game" Magnetic Battle Chess Games', 'The Recalled Magnetic Chess Games, Which Include 20 Magnet Pieces, Violate The Mandatory Federal Toy Magnet Regulation Because The Set Contains One Or More Magnets That Fit Within Cpsc''S Small Parts Cylinder, And The Magnets Are Stronger Than Permitted. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported. CPSC estimates 2,400 magnet ingestions were treated in hospital emergency departments from 2017 through 2021. CPSC is aware of seven deaths since 2005 involving the ingestion of hazardous magnets, including two outside of the United States.', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic chess games immediately, take them away from children, and contact Outad Good Life for instructions on how to receive a full refund. Consumers can also visit their Temu account, find the relevant order in "Your Orders" and click on the "Return/Refund" button. Follow the detailed instructions on the Return and Refund Policy page on Temu.com to receive a return shipping label to send back the recalled products for free. Outad Good Life is notifying all known purchasers directly.', '24265');
INSERT INTO safety_incidents VALUES ('a2b76f204326ec3aa5ee37eca9dbd5e704837446', 'CPSC', '2024-06-13', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Beaumont Plus ST Bikes with disc brakes', 'Injury', 'Other', 'Skin Irritation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bicycles and take them to the authorized dealer where purchased, or https://retrospec.com/pages/dealer-locator/ for free installation of a new front fork.', '24266');
INSERT INTO safety_incidents VALUES ('6f27dc45fc1e4e4094c124e3c41946c8c58dc572', 'CPSC', '2024-06-13', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Lomi Roll-On Waxing Kits', 'Fire', 'Electrical Fault', 'Burns', 'The firm has received two reports of the warmer''s power cord overheating and/or short-circuiting, including two consumers who suffered burns, and one incident of property damage.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled waxing kits, and contact Southern Telecom for a full refund. Consumers will be asked to write "Recalled" with a permanent marker on the wax warmer, unplug the warmer, cut the unplugged power cord, and submit a photo to Southern Telecom.', '24262');
INSERT INTO safety_incidents VALUES ('590369541eb68dc14e4a01153e15006696735170', 'CPSC', '2024-06-06', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Good Earth Rechargeable Integrated Lights', 'Fire', 'Flammability / Overheating', 'Respiratory', 'There is a report of one customer who died, and another who was treated for smoke inhalation when the product overheated and caused a fire in their home. Good Earth Lighting is aware of nine additional reports of lights overheating, including six that resulted in fires and property damage.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled lights, and contact Good Earth Lighting to receive a free replacement light of at least equal value to the purchase price of the recalled light, including shipping, at no charge. Consumers will be asked to write the date and initial next to the model number on the back of the light, and write "Recalled" on the front of the light. Consumers will also be asked to upload photos to https://goodearthlighting.com/productrecall.', '24254');
INSERT INTO safety_incidents VALUES ('3075603334a57a174a5347a1d8b2cf2dd4d398c7', 'CPSC', '2024-06-06', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Kawasaki Engines used in Bad Boy Mowers, BigDog, Bobcat, Cub Cadet, Hustler, John Deere, and Kubota brand lawn and garden equipment', 'Fire', 'Flammability / Overheating', 'Burns', 'Kawasaki has received eight reports of fires with the recalled engines. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using lawn and garden equipment with the recalled engines and contact Kawasaki, John Deere, Cub Cadet, Hustler, BigDog or Kubota, depending on the product owned, or an authorized dealer, to schedule a free repair. Kawasaki and the mower manufacturers are contacting all known purchasers directly.', '24256');
INSERT INTO safety_incidents VALUES ('8563231c202d38db57c5a7c5b44298282bd8f4c3', 'CPSC', '2024-06-06', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Sanctuary and Sports Afield Biometric Firearm Safes', 'Injury', 'Other', 'Not Specified', 'The firm is aware of 77 reports of the safe being opened by unauthorized users. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the biometric feature of the recalled safe, remove the batteries from the safe, and only use the key when storing firearms. Contact SA Consumer Products to receive a free repair kit.', '24255');
INSERT INTO safety_incidents VALUES ('f1488c503e81bf303809edcc2e6e5797de97e712', 'CPSC', '2024-06-06', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Wild Country Ropeman 1 ascenders', 'The Teeth Of The Recalled Ascenders Can Fail To Engage, Making It Difficult Or Impossible For The User To Ascend.', 'Other', 'Not Specified', 'None reported', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled Ropeman 1 ascenders, and contact Wild Country to coordinate return of the recalled product and shipment of a free replacement ascender. Consumers can also return the recalled Ropeman 1 ascenders to Wild Country directly or at any authorized Wild Country Dealer for a free replacement.', '24259');
INSERT INTO safety_incidents VALUES ('b24566080f2d96cb74b8616ef04f6785668ee364', 'CPSC', '2024-06-06', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'Sling Carriers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled sling carriers and contact Joybuy Marketplace Express for instructions on how to properly dispose of the product and receive a full refund. Joybuy Marketplace Express and Walmart are notifying all known purchasers directly.', '24258');
INSERT INTO safety_incidents VALUES ('38ddc0a01de133732b1416e014cb10daca158968', 'CPSC', '2024-06-06', 2024, '2024-06', 'USA', 'United States', '', 'Other', 'FURminator deShedding Ultra Premium Dog Conditioner (1 Gallon)', 'Environmental', 'Microbiological Contamination', 'Eye Injury', 'The firm has received four reports of mold developing in the container. No injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled pet conditioner and contact the firm to receive a full refund. Do not empty the product prior to disposal or pour the product down the toilet or drain. Consumers should mark the product with the word "Recalled", upload a picture of the product''s UPC, date, and customer initials, then upload a photo of the disposed product in the trash online at www.prodprotect.com/recall/FURminator. Upon successful registration, the firm will issue a refund to purchasers.', '24257');
INSERT INTO safety_incidents VALUES ('808ab7f1e18c286dd945fc8b69038b18a128ccb6', 'CPSC', '2024-05-30', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'CRAFTSMAN® V20 Cordless Tillers/Cultivators', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received one report of incorrect attachment of the bottom portion of the unit. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled tillers/cultivators and contact CRAFTSMAN for new assembly instructions illustrating how to properly attach the bottom portion of the tillers/cultivators. The updated assembly instructions are also available on CRAFTSMAN''s website at https://www.craftsman.com/pages/safety-notices-and-recalls-cmctl320b. CRAFTSMAN and sellers of the recalled tillers/cultivators are sending updated assembly instructions to known purchasers.', '24249');
INSERT INTO safety_incidents VALUES ('b98b006a4345ca79ed75c2327a56fd10fc15a2b6', 'CPSC', '2024-05-30', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'ADIOS! Super Vinegar All Natural Cleaner, 30%', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled cleaner immediately and contact Compare Brands for information on how to obtain a free corrected label to put on the cleaner bottle. Compare Brands and Amazon are contacting all known purchasers directly.', '24247');
INSERT INTO safety_incidents VALUES ('cdda8ba5da66d90f5e05568fbb5c8565ad74ac71', 'CPSC', '2024-05-30', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Crib Bumpers', 'Infants Can Suffocate If They Roll Or Move On The Crib Bumper In A Position That Obstructs Breathing. Padded Crib Bumpers Are Banned Under Federal Law.', 'Other', 'Choking / Suffocation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled crib bumpers and contact AliExpress for a full refund. To receive a refund, consumers should destroy the crib bumpers by cutting the straps and the padding and send a photo as proof of destruction by directly replying to the email from AliExpress. AliExpress is contacting all known purchasers.', '24246');
INSERT INTO safety_incidents VALUES ('4f9e6e728895e6e91c105ce05bb8b291b65fcd2d', 'CPSC', '2024-05-30', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Medline Bed Assist Bar adult bed rails', 'When The Recalled Bed Rails Are Attached To An Adult''S Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Bed Rail And The Side Of The Mattress. This Poses A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'Medline has received two reports of entrapment deaths associated with the Bed Assist Bars. The deaths occurred in July 2019 and November 2023 and involved a 76-year-old woman at a senior nursing facility in Iowa and an 87-year-old woman at a residential care facility in South Carolina.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact Medline to receive a full refund.', '24248');
INSERT INTO safety_incidents VALUES ('3e5d7a361415e33fbe2c0fa797f85dcb0231ced1', 'CPSC', '2024-05-23', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'TOPINCN Pool Drain Covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Standards Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners/operators and consumers should immediately stop using pools with the recalled pool drain covers, remove the drain cover from the pool, take a photo of it and sent it to the recalling firm by email at sanure710@126.com to receive a full refund. Ensure all pools and spas have Virginia Graeme Baker Pool and Spa Safety Act (VGBA) compliant drain covers and teach children to stay away from drains. Sanure is contacting all purchasers directly.', '24239');
INSERT INTO safety_incidents VALUES ('41324ea89f035f1aefeda59b516651533771bd83', 'CPSC', '2024-05-16', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'CHZHVAN Combination Smoke and Carbon Monoxide Detectors', 'Fire', 'Flammability / Overheating', 'Not Specified', 'There are five reports of the detectors failing to alarm in the presence of smoke. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled combination smoke and carbon monoxide detectors, and contact Haikouhuidishangmaoyouxiangongsi to receive a full refund.', '24236');
INSERT INTO safety_incidents VALUES ('310884a634ac767ef23264d564f7ff241e78d1ef', 'CPSC', '2024-05-16', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Frigidaire and Kenmore Smooth-top Freestanding Electric Ranges', 'Fire', 'Flammability / Overheating', 'Respiratory', 'Since the recall was announced in August 2009, Electrolux has received at least 212 reports of the ranges behaving erratically, including 14 reports of fires and eight reports of injuries involving burns to hands or arms, as well as smoke inhalation.', 'Moderate', 1, 0, 'Contact Electrolux or register online to participate in the recall. Based on the serial number, it will be determined if consumers have a range that can be repaired or not. Consumers with impacted ranges should contact Electrolux for steps to avoid a burn injury, including not leaving anything on the range when it is not in use. If the range is repairable, a free inspection and repair will be scheduled. If the range is not repairable, consumers will receive a refund in the form of a $50 electronic gift card and reimbursement of up to $60 for the haul-away fee for their recalled range, once they have submitted proof of purchase of a new range and the haul-away fee paid. Electrolux may reimburse haul-away fees over $60 when consumers provide receipts or other documentation showing paid haul-away fees.', '24235');
INSERT INTO safety_incidents VALUES ('242253ea549a3047b8581c6527c8efe31684af9e', 'CPSC', '2024-05-16', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Super Lube Syncopen Synthetic Penetrant, Super Lube Fire Resistant Hydraulic Fluid, and Super Lube Metal Protectant and Corrosion Inhibitor (consumer sizes of five gallons or less)', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled Super Lube® products out of the sight and reach of children, and contact Kano Laboratories for a full refund. Consumers will need to provide proof of possession by emailing a photo of their product to info@super-lube.com to receive their full refund.', '24237');
INSERT INTO safety_incidents VALUES ('da7422578f33dbe1b39ffaad6e54d6243d481fa5', 'CPSC', '2024-05-09', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Zegoo Children''s Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children, stop using them, and contact Zegoo Home to receive a full refund. Consumers should destroy the garments by cutting them in half and disposing of them in accordance with local and state recycling laws, and send an image of the destroyed or disposed-of garment to zegoohome@126.com. Zegoo Home is contacting all known purchasers directly.', '24230');
INSERT INTO safety_incidents VALUES ('0803d5f2b9d2a0a291f9edbf1f30547ef5484492', 'CPSC', '2024-05-09', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'SIORO Children''s Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using them, and contact SIORO for a full refund. Consumers should destroy the garments by cutting them in half, and send a photo of the destroyed garment to amazonus@sioro.com. Upon receipt of the photo, SIORO will refund consumers the purchase price. Afterwards, consumers should dispose of the destroyed garments in accordance with local and state recycling laws.', '24233');
INSERT INTO safety_incidents VALUES ('8a2242e2f52e05f47029c638b557738e4d6ca767', 'CPSC', '2024-05-09', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Toy Pinwheels', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received one report of the fastener cap coming loose and being swallowed by a child.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled pinwheels and dispose of the product. As the product was given away for free, no refund or replacement will be provided.', '24227');
INSERT INTO safety_incidents VALUES ('4b2527e3931dc5edcda45adb0ee61065c867b764', 'CPSC', '2024-05-09', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Korimefa Multi-Purpose Bike Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Korimefa helmets and contact Yangxi for a full refund. To receive a refund, consumers should destroy the helmet by cutting off the straps, then take a photo, and send the photo to the recalling firm by email at marketing.us@hotmail.com. After submitting proof of destruction, consumers should dispose of the recalled helmet. Yangxi is contacting all purchasers directly.', '24232');
INSERT INTO safety_incidents VALUES ('c7d04b24da2ac2167deba02c11c7fe1c702d93be', 'CPSC', '2024-05-09', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Spin Swivel Chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 190 reports of the base of the swivel chair breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled swivel chairs, and contact Article for a free replacement base and installation instructions. Article is contacting all known purchasers directly.', '24231');
INSERT INTO safety_incidents VALUES ('a385ffc6f023f6a82e10e103a0d1861f72610a6b', 'CPSC', '2024-05-09', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Arctic Cat Model Year 2024 Catalyst 600 snowmobiles', 'The Steering Caps, Which Are Used To Hold The Handlebar In Place, Can Crack And Cause The Handlebars To Become Unstable, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'The firm has received 95 reports of incidents from dealers during initial snowmobile setups of steering caps cracking while being torqued. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Arctic Cat 2024 Catalyst 600 snowmobiles, and contact the local authorized Arctic Cat dealer to schedule a free repair of the steering caps.', '24228');
INSERT INTO safety_incidents VALUES ('095d1c8819cce3ba711dbf22fda12d0a3154da96', 'CPSC', '2024-05-09', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Prowler Pro and Tracker 800SX Utility Vehicles (UTVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 48 reports of incidents of fuel leakage around the cap. No injuries have been reported.', 'Minor', 1, 0, 'Customers should immediately stop using the recalled utility vehicles, and contact an authorized dealer for a free inspection and repair. Textron Specialized Vehicles is contacting all known purchasers directly.', '24229');
INSERT INTO safety_incidents VALUES ('b3ad9cb455df70c2815b94076ba691a60a5d53ba', 'CPSC', '2024-05-09', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'ZLINE Wall Ovens', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'The firm has received 95 reports of incidents of the door spring releasing or breaking through the top of the oven door. One minor injury has been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ovens until the oven door is repaired. Contact ZLINE to obtain a free replacement door and instructions on replacing it. Consumers can register online at https://zlinekitchen.com/recalls-walloven to begin the repair process. Consumers who require physical assistance may request a service visit. ZLINE is contacting all purchasers directly.', '24226');
INSERT INTO safety_incidents VALUES ('a07c5b30f46d911cc41485d98ab0fb82146c47e5', 'CPSC', '2024-05-02', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Honda Lawnmowers, Replacement Engines, and Pressure Washers Engines', 'Injury', 'Other', 'Not Specified', 'Honda has received 2,966 reports of incidents related to camshaft failures since the last recall, in addition to the 2,197 reported incidents in the September 2023 recall, including 38 reports of minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled lawnmowers and recalled pressure washers equipped with the recalled general-purpose engines, and contact an authorized Honda Power Equipment dealer to schedule an appointment for a free inspection and repair.', '24220');
INSERT INTO safety_incidents VALUES ('3c7299a1c3802511feedfd94568c183c9d9dd1fe', 'CPSC', '2024-05-02', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Arctic Cat 8000 and 9000 Series Snowmobiles', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Arctic Cat has received more than 200 reports of clutch failures, including six where clutch fragments hit consumers. Four of those included reports of minor foot and toe injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles, and contact Arctic Cat to schedule for a free installation of an additional clutch guard and inspection of the primary clutch. If the primary clutch is cracked, Arctic Cat will replace it free of charge.', '24223');
INSERT INTO safety_incidents VALUES ('15c7b4de202c0a08cdf88de6d020828c8f2dec47', 'CPSC', '2024-05-02', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Project Watson Eyelid Wipes for Dogs', 'When The Recalled Dog Eyelid Wipes Are Opened And In Use, Bacteria And Fungi, Which Are Organisms Found Widely In The Environment, Soil, And Water, Can Be Introduced And Grow In The Container, Posing A Risk Of Serious Infection To People With Weakened Immune Systems. Individuals With Wounds May Also Be At Higher Risk Of Infection. People With Healthy Immune Systems Are Not Typically Affected.', 'Microbiological Contamination', 'Laceration / Cut', 'The company has received seven reports of a substance developing in the container after the product had been opened and in use. No illness of consumers or pets has been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled eyelid wipes and request a full refund by submitting a picture of their product via an online form at http://eyelidwiperecall.com/. The refund will be in the form of a check sent to consumers via U.S. mail. Consumers should then dispose of the product in its container with household trash.', '24224');
INSERT INTO safety_incidents VALUES ('7baea3aabe93cddedf8c69b232f0ec6c491b471c', 'CPSC', '2024-05-02', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Mill Valley Jr. six-drawer youth dressers', 'The Recalled Dressers Are Unstable If They Are Not Properly Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children. The Dressers Violate The Performance Requirements Of The Sturdy Act.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the dressers immediately, keep children away from them, and contact Rooms To Go for a free replacement dresser. Rooms To Go will schedule a free delivery of the replacement, and remove the recalled dresser. Rooms To Go is contacting all known purchasers directly.', '24217');
INSERT INTO safety_incidents VALUES ('2477052d80a3154d5f25809c8d78dfd4f6ae4b9d', 'CPSC', '2024-05-02', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Creativity Street Foam Pattern Rollers', 'The Recalled Foam Pattern Rollers Are Intended For Children And Contain Levels Of Lead That Exceed The Federal Lead Content Ban In The Rollers'' Handles. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled foam pattern rollers and take them away from children. Contact Dixon Ticonderoga to receive a pre-paid label to return the recalled product. When the foam pattern rollers are received, consumers will receive a full refund. All known purchasers are being contacted directly by the firm or retailer.', '24221');
INSERT INTO safety_incidents VALUES ('dcb09f5abc7179a1de055938537336814adbfc7e', 'CPSC', '2024-05-02', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Walk-Behind Leaf Blowers and Vacuums, and Tow-Behind Leaf Vacuums', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 22 reports of loose pieces being ejected from the units. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled leaf blowers and vacuums, and contact DR Power for a free dealer-installed repair.', '24222');
INSERT INTO safety_incidents VALUES ('794d55c5204e127dabf945bd3ed059ff7c4dc27b', 'CPSC', '2024-05-02', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Youth Sipper Bottles', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm reported one incident of the silicon sleeve coming off. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled bottles away from children, stop using them, and contact Igloo to receive a replacement bottle or refund. Consumers should destroy the silicone spout by removing the silicone spout and cutting it into two separate pieces down the center. Consumers should then take a photo of the spout in two separate pieces, then discard the two pieces in the trash. Consumers should submit a photo of the spout in two separate pieces to customerservice@shop.igloocoolers.com to receive a refund in the form of a $15 online store credit, a $15 gift card to be mailed to consumers, or a replacement bottle. If consumers have the original purchase receipt, they can submit a photo of the receipt along with a photo of the destroyed bottle for a full refund in the form of the original method of payment. Consumers who purchased the recalled bottles at Rural King must contact Igloo to receive a replacement bottle, or a refund in the form of a $15 credit to purchase another product at igloocoolers.com or the Igloo company store in Texas, or a $15 gift card. Customers who purchased at Academy Sports + Outdoors can also return the product directly to the store for a full refund in the form of the original method of payment, a $15 gift card, or store credit.', '24215');
INSERT INTO safety_incidents VALUES ('a0cea4719267007b0e2b4515e0dbdb53b7250501', 'CPSC', '2024-05-02', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Model Year 2024 Prostar S4 Titan Adventure 155 ES Snowmobiles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received three reports of fuel leaking from the recalled snowmobiles. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles, and contact an authorized Polaris dealer to schedule a free repair to replace the pump flange assembly gasket. Polaris has issued a Stop Ride notice to consumers, and is contacting registered owners directly about the remedy.', '24218');
INSERT INTO safety_incidents VALUES ('56d99ec7d568b106d651003998165de8f4c2e0f4', 'CPSC', '2024-05-02', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'SKIMS Children''s Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them, and contact SKIMS for a full refund. Consumers will be asked to destroy the garment by cutting the top and bottom in half, and upload a photo of the destroyed garments to: https://www.recallrtr.com/pajamasets. Upon receipt of the photo, consumers will be issued a full refund of the purchase price, plus a credit toward a future SKIMS purchase. SKIMS will contact all known purchasers directly.', '24216');
INSERT INTO safety_incidents VALUES ('4f7595a3e94b9bf88578609284db81bfe3e1a674', 'CPSC', '2024-05-02', 2024, '2024-05', 'USA', 'United States', '', 'Other', 'Commercial Refrigerators with Secop Compressors', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 14 reports of fires resulting in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using commercial refrigerators with Secop compressors with model number NLE11MN, and contact True Manufacturing for a free repair. The original Secop ePTC starter in the compressor with the RSCR motor configuration will be replaced with the CSIR motor configuration. Consumers can register their unit for retrofit at www.true-secopcompressor-retrofit.com or www.true-secopcompressor-recall.com, and an on-site service visit by a technician will be scheduled. True Manufacturing is contacting all known purchasers directly.', '24219');
INSERT INTO safety_incidents VALUES ('4409c9a3bf8d77713def7c9740784efa2ca5b1d9', 'CPSC', '2024-04-25', 2024, '2024-04', 'USA', 'United States', '', 'Other', '3M™ Peltor™ X4 Series Earmuffs', 'The Recalled Noise-Reducing Earmuffs Can Develop Cracks In The Colored Portion Of The Plastic Cups, Posing A Risk Of Overexposure To Loud Noise And Sound.', 'Other', 'Not Specified', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled earmuffs and contact 3M to receive free replacement earmuffs, including free shipping.', '24205');
INSERT INTO safety_incidents VALUES ('e8c9bdf15bae6982d0842643a7c280489be3bcfd', 'CPSC', '2024-04-25', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Crate & Barrel Hampshire Cribs', 'Injury', 'Other', 'Not Specified', 'The firm has received 12 reports of incidents of the mattress support pins becoming loose. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cribs and contact Crate & Barrel for a free repair or full refund. Crate & Barrel is contacting all known purchasers directly.', '24209');
INSERT INTO safety_incidents VALUES ('02749ef775be957d36234b31b2b9bbe61209fa32', 'CPSC', '2024-04-25', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Crosman Icon Air Rifles', 'Injury', 'Other', 'Not Specified', 'The firm has received one report of an unintended discharge. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled air rifles and contact Crosman to receive a refund in the form of a Crosman store credit or a refund check after returning the air rifle. Crosman will mail a box with instructions and prepaid postage to each consumer who registers at www.crosman.com/iconrecall. Crosman is contacting all known purchasers.', '24212');
INSERT INTO safety_incidents VALUES ('6d966cfdc1bfa00949955837383205e4c25f352d', 'CPSC', '2024-04-25', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Mario Kart™ 24V Ride-On Racer Cars', 'If The Acceleration Pedal On The Battery-Operated Ride-On Toy Becomes Clogged With Debris, It Can Stick After The User''S Foot Is Removed From The Pedal, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'The firm has received 65 reports of incidents of debris-clogged pedals sticking, of which 15 of the vehicles crashed into permanent structures with one minor injury, a chafed hand.', 'Serious', 1, 0, 'Consumers should immediately stop using the 24V Ride-On cars and contact JAKKS Pacific to receive a free repair kit. The repair kit includes a free replacement pedal with installation instructions.', '24210');
INSERT INTO safety_incidents VALUES ('4215c68a7a9d8d53bee166042d6f0fac77d03447', 'CPSC', '2024-04-25', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Kid''s Bike Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Chau River Sports Outdoors for a full refund. To receive a refund, consumers should destroy the helmet by cutting off the straps, and send photos of the helmet with the straps cut through the onsite messaging system by clicking on the "message" icon on Temu.com at Chau River Sports Outdoors store page as proof of destruction, then dispose of the recalled helmet.', '24211');
INSERT INTO safety_incidents VALUES ('35ba1500dbbda580da6532c1569655bdfe2b2ef8', 'CPSC', '2024-04-25', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Oregon, PowerPro, Country Tuff, and Speeco branded log splitters and cylinder kits', 'Injury', 'Other', 'Not Specified', 'The firm has received seven reports of forward movement of the rod and attached splitting wedge at an unexpected increased speed. No injuries have been reported.', 'Minor', 1, 0, 'If consumers experience the wedge failing to retract, the consumer should immediately stop using the recalled product and contact Oregon Tool or their dealer to schedule a time for Oregon Tool or the dealer to install a free replacement cylinder. Consumers should not attempt to fix the recalled product themselves. Consumers can locate their nearest dealer by visiting www.oregonproducts.com/en/dealer-locator and searching by location for an Outdoor Power Equipment dealer.', '24208');
INSERT INTO safety_incidents VALUES ('89a7482f446f6852d007468589fbb14766828408', 'CPSC', '2024-04-24', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Sant and Abel Children''s Two-Piece Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them, and contact Sant and Abel for a full refund. Consumers should destroy the garments by cutting them in half and disposing of them in accordance with local and state recycling laws. Consumers should send the recalling firm a photo of the destroyed garment at returns@santandabel.com to receive a refund. Sant and Abel is contacting all known purchasers directly.', '24207');
INSERT INTO safety_incidents VALUES ('552db811162f86642b135e9aee9eae66a911d932', 'CPSC', '2024-04-18', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Gossamer Pro AGX+ cranksets', 'Injury', 'Mechanical Failure', 'Fall Injury', 'The firm has received 277 reports of bicycle crankarms loosening or detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the bicycles with the recalled cranksets, and contact Full Speed Ahead for instructions on how to receive free dealer installation of a new replacement crankset.', '24203');
INSERT INTO safety_incidents VALUES ('ed60e16b38125f055207f1af9ffccdb2d862561f', 'CPSC', '2024-04-18', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Gasaciods Children''s Multi-Purpose Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Gasaciods helmets, and contact Fengwang Sports for a refund. To receive a refund, consumers should destroy the helmet by cutting off the straps, take a photo, and send it to the recalling firm either by email at george66305@163.com, or by sending onsite messages to Fengwang Sports on Temu.com. After submitting proof of destruction, consumers should dispose of the recalled helmets.', '24201');
INSERT INTO safety_incidents VALUES ('452771e7c544375eda2d59783e8a044374593da9', 'CPSC', '2024-04-18', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Randder 2-Pack Liquid Fuel Bottles', 'Burns', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fuel bottles, place them out of reach of children, and contact Render Store for information on how to receive a new child-resistant cap.', '24202');
INSERT INTO safety_incidents VALUES ('67951fc44f34e79fa68d1da10bf801352b08e678', 'CPSC', '2024-04-11', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'BRS Liquid Fuel Bottles', 'Burns', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fuel bottles, place them out of reach of children, and contact Huenco for instructions on how to dispose of the product to receive a full refund.', '24192');
INSERT INTO safety_incidents VALUES ('c7efaf79188d9c8fe8d8b21acb326fe519a18487', 'CPSC', '2024-04-11', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Delta Cycle and Dimension Stem Raisers', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received one report of a stem raiser shifting during use. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled stem raisers, and contact Delta Cycle to schedule a free repair at an independent bicycle dealer.', '24194');
INSERT INTO safety_incidents VALUES ('85776367769f9ab8a846c3e6f17a42a75782f867', 'CPSC', '2024-04-11', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Fischer RC4 Junior Ski Boots', 'Injury', 'Mechanical Failure', 'Fall Injury', 'The firm has received one report of an incident of the ski boot cuff rotated. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled RC4 Junior Ski Boots and contact Fischer Sports for instructions on how to receive a refund, a free replacement, or a free repair.', '24191');
INSERT INTO safety_incidents VALUES ('b1f7f1df762a72450829f208d05f25f966b769b4', 'CPSC', '2024-04-11', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'GhostBed-branded Natural Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the mattress, and contact GhostBed to receive a free cover to put on the mattress to bring it into compliance with the federal regulation. GhostBed is contacting all known purchasers directly.', '24198');
INSERT INTO safety_incidents VALUES ('cdeda9be2e2c267e89e1fad89245a496c9f26476', 'CPSC', '2024-04-11', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Intimidator and Mahindra branded utility vehicles (UTVs)', 'The Universal Joint Can Fail And Pierce And Sever The Brake Line, Posing A Crash Hazard.', 'Other', 'Fracture / Blunt Trauma', 'The firm has received 40 reports of incidents, including 12 involving a brake line impact. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact an Intimidator or Mahindra authorized dealer to schedule a free repair.', '24196');
INSERT INTO safety_incidents VALUES ('3d18be5a65e7a973dcbd3fcd4181657656a5f2ed', 'CPSC', '2024-04-11', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Matrix T1 and T3 Series Commercial Treadmills', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Matrix Fitness has received one report of a fire in a fitness facility since the last recall, in addition to the 58 reported in the January 2022 recall, of the treadmill''s power cord and socket sparking, smoking, and/or melting, including seven reports of fire; two resulting in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Exercise facilities should inspect their treadmills to confirm whether they have a power cord bracket installed on the unit. If the bracket is not already installed, facilities should ensure that the power cord is completely inserted into the power socket on the treadmills prior to each use, until repaired. Contact Johnson Health Tech North America to schedule a free installation of a power cord bracket or to order a power cord bracket for self-installation. Johnson Health Tech North America is contacting all known purchasers directly.', '24743');
INSERT INTO safety_incidents VALUES ('76a2e3088527d2ba6502f215cde41e50d68a6189', 'CPSC', '2024-04-11', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Red Land Cotton "Quilts" and "Quilted Shams"', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received three reports of consumers being jabbed by a sharp metal needle from the product, including one breaking the skin on a consumer''s hand.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled quilts and quilt shams and visit www.redlandcotton.com/pages/voluntary-quilt-recall for instructions on how to participate in the recall. Red Land Cotton will be offering a replacement product (of the same value) or a refund in the form of a store credit or a refund check. Consumers will be asked to provide proof of purchase, in the way of photos of the recalled products, a purchase receipt or other form of payment documentation. Red Land Cotton is notifying all known consumers who purchased the recalled products.', '24193');
INSERT INTO safety_incidents VALUES ('39875acea1346a0c66ce64039ae408495e5ab2a8', 'CPSC', '2024-04-11', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Touchat Large Fuzzy Area Rugs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled rugs immediately and contact Touchat for a full refund. Consumers will be asked to destroy the product by cutting it in half, and to provide proof of destruction by sending a photo of the cut product to jurysun@outlook.com to receive a full refund. Touchat is contacting all known purchasers directly.', '24195');
INSERT INTO safety_incidents VALUES ('d3555f1d341407b74beb44ea6f93abab7b4c0168', 'CPSC', '2024-04-11', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Yoto Mini speakers', 'Fire', 'Flammability / Overheating', 'Burns', 'Yoto has received six reports from U.S. consumers and one from a UK consumer of the speaker overheating or melting. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled speakers, take them away from children, and contact Yoto to receive a free replacement smart charging cable. Consumers can send a photograph of the old cable cut through the middle to receive a new replacement cord.', '24190');
INSERT INTO safety_incidents VALUES ('d06759e9e8449bd63bd395180714442dcb3d48b7', 'CPSC', '2024-04-11', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Zipline Kits', 'Falls', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 20 reports of the cable breaking, resulting in nine injuries including lacerations and one broken clavicle.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled zipline kits and contact Jugader for a free repair kit. Consumers must submit a photo of the cable and the trolley or their online purchase order number to receive a free repair kit, including a new cable and updated installation instructions.', '24199');
INSERT INTO safety_incidents VALUES ('336c3f3669a2ac77fb3a3d0c216eb7ba19e192f2', 'CPSC', '2024-04-05', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Tide Pods, Gain Flings, Ace Pods and Ariel Pods liquid laundry detergent packets packaged in flexible film bags. This recall announcement applies only to bags distributed in the United States.', 'Injury', 'Mechanical Failure', 'Poisoning / Ingestion', 'No confirmed cases directly relating to this packaging defect. The firm has received four reports of children in the United States accessing the liquid laundry packets, three of which reported ingestion during the time period that the recalled lots were sold, but it is not known if these laundry packets came from recalled bags.', 'Fatal', 1, 0, 'Consumers should immediately secure the recalled bags out of sight and reach of children and contact Procter & Gamble for a full refund and a free replacement child-resistant bag to store the product. Consumers can also receive a cabinet lock for securing laundry materials. Consumers should check to see if their bag is part of the recall by checking the lot code on their bag. Recalled lot codes will be listed at pg.com/bags and are found on the bottom of the package. Consumers with recalled bags can submit a photo of the recalled product, showing the lot code to participate in the recall.', '24189');
INSERT INTO safety_incidents VALUES ('4a78e30eb8facb5b66d5f2003e3996534a5e71dd', 'CPSC', '2024-04-04', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'C2 Crank Cocking Aid for Crossbows', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Excalibur has received 538 reports of the C2 Crank cocking aid hooks breaking during use, resulting in plastic projectiles flying and hitting consumers, including one injury where a consumer reportedly suffered a permanent eye injury.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled C2 Crank and contact Excalibur Crossbow to receive instructions on receiving free replacement rope and hooks.', '24180');
INSERT INTO safety_incidents VALUES ('e8cfd1a77da75f637023cd6b1ff632854e63f57d', 'CPSC', '2024-04-04', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Endurance® Hand Bed Rails', 'When Attached To An Adult''S Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Rail And The Side Of The Mattress. This Poses A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'In December 2022, an 86-year-old man died at an assisted living facility in Connecticut, and in August 2023, a 99-year-old man died at his home in California. CPSC previously announced the recall on December 22, 2021, following the entrapment death of an 86-year-old man in California. He died at his home in December 2012, reportedly from the Endurance Hand Bed Rail (model P1410).', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails. For consumers who own the recalled bed rails sold or imported on or after November 1, 2015, Essential Medical Supply Inc., will provide a refund. The amount of the refund will be pro-rated based on the age of the bed rail.', '24179');
INSERT INTO safety_incidents VALUES ('aea92271017d2a6ad24a3973eb30a89500ad8d1f', 'CPSC', '2024-04-04', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Children''s Two-Piece Pajamas and Lounge Dresses', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them, and contact Lovey & Grink for a full refund. Consumers who purchased the product will be asked to destroy the garments by cutting them in half and disposing of them in accordance with local and state recycling laws. Consumers must send a photo of the destroyed garment to recall@loveyandgrink.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '24183');
INSERT INTO safety_incidents VALUES ('9f63574dee0888a741b147da9b3694659569521a', 'CPSC', '2024-04-04', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Thule RideAlong rear-mounted Child Bike Seats', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled RideAlong seat and contact Thule Group to register for free replacement harness padding and to receive instructions on how to return the recalled padding. Thule is contacting all known consumers.', '24182');
INSERT INTO safety_incidents VALUES ('fd3b28144262da0b7576097378a7faf5b8603041', 'CPSC', '2024-04-04', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'BLACK+DECKER Model HGS011 Easy Garment Steamers', 'Burns', 'Drowning Risk', 'Burns', 'Since the recall was announced in November 2022, Empower Brands has received 317 reports of hot water expelling from the recalled steamers, including 82 reports of burn injuries, seven of which were second-degree burns. 94 of these incident reports involved units that were repaired as part of the original recall or models featuring the updated design, including 19 burn injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled BLACK+DECKER Model HGS011 Easy Garment Steamers, and contact Empower Brands to receive a full refund. There have been continued reports of burn injuries involving units that were repaired as part of the previous recall in November 2022. The remedy has now been changed to a refund for all units. Consumers, including those who received a replacement upper assembly as part of the November 2022 recall, should contact Empower Brands for a full refund.', '24181');
INSERT INTO safety_incidents VALUES ('3df2c82428a3eea7d614c96f19f98a4725c8234c', 'CPSC', '2024-04-04', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Mainstays Electric Mini Choppers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Walmart has received five reports of lacerations, two of which required medical attention, including stitches. Injuries occurred during assembly of the product or during cleaning/handling of the product.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled choppers, and contact Walmart to receive a full refund. Consumers can bring the chopper to their nearest Walmart store for a refund.', '24178');
INSERT INTO safety_incidents VALUES ('11be4331ce9500d5eba27ffcb880095fd9bd833a', 'CPSC', '2024-04-04', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Grão de Gente Baby Nests', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Grão de Gente baby nests and contact Zazaba International Inc. for instructions on how to properly dispose of the product and receive a full refund. Zazaba International Inc. is contacting all known consumers directly.', '24184');
INSERT INTO safety_incidents VALUES ('8c67653d401e1c73c67dd9463023241594cc497a', 'CPSC', '2024-04-04', 2024, '2024-04', 'USA', 'United States', '', 'Other', 'Grão de Gente Crib Bumper Bedding Sets', 'Infants Can Suffocate If They Roll Or Move On The Crib Bumper In A Position That Obstructs Breathing. Padded Crib Bumpers Are Banned Under The Safe Sleep For Babies Act Of 2021.', 'Other', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Grão de Gente crib bumpers and contact Zazaba International Inc. for instructions on how to properly dispose of the product and receive a full refund. Zazaba International Inc. is contacting all known consumers directly.', '24185');
INSERT INTO safety_incidents VALUES ('803497dfa943d8261bd7cd03fe6648d9cb8f2407', 'CPSC', '2024-03-28', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Berkley Jensen Citronella 72-inch Tiki Torches', 'Burns', 'Instability / Fall Risk', 'Burns', 'The firm has received nine reports of the tiki torch top breaking open and/or falling off, resulting in two reports of burn injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled tiki torches and contact BJ''s Wholesale Club for a full refund. Consumers should destroy and dispose of or return the tiki torches (with the fuel reservoir empty) to BJ''s Wholesale Club to receive a refund.', '24177');
INSERT INTO safety_incidents VALUES ('82848565bae12137cf90aacec5643ba2d08a039f', 'CPSC', '2024-03-28', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Forias Pack and Play Mattresses', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pack and play mattresses and discard them by cutting them in half, then send a photo of destroyed mattress to customer.care@forias.com to receive a full refund. Amazon and Forias Direct are contacting all known purchasers directly.', '24742');
INSERT INTO safety_incidents VALUES ('329bfe5fc16195b846e7c51eadb9666770bf68f3', 'CPSC', '2024-03-28', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Model Year 2022-2023 Snowmobiles equipped with PATRIOT BOOST Engines', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 17 reports of fuel leaks. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact Polaris or an authorized Polaris dealer to schedule a free repair to replace the fuel line. Polaris has notified consumers to stop riding the vehicles and is notifying all dealers and contacting registered owners directly.', '24741');
INSERT INTO safety_incidents VALUES ('8f8ea5fa767386bcfed8da312579dfb887d8d893', 'CPSC', '2024-03-28', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Purefog High Density Natural Fog Juice Liquids', 'The Recalled Fog Liquid Can Expire Sooner Than The Expiration Date Listed On The Product. This Can Pose A Risk Of Respiratory Or Other Infections In Individuals With Compromised Immune Systems, Damaged Lungs Or An Allergy To Mold.', 'Allergen', 'Respiratory', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled product, discard the unused product by pouring it down the drain, and contact the firm for a full refund. Consumers are being contacted directly by Amazon.com.', '24176');
INSERT INTO safety_incidents VALUES ('c051b339edddcfc9e9385181e496238e113572d0', 'CPSC', '2024-03-28', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Magnetic Beads HIGH POWER 5mm', 'The Magnetic Beads Violate The Requirements Of The Mandatory Federal Magnet Regulation Because They Contain One Or More Magnets That Fit Within Cpsc''S Small Parts Cylinder, And The Magnets Are Stronger Than Permitted. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other Or Another Metal Object And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported. CPSC estimates 2,400 magnet ingestions were treated in hospital emergency departments from 2017 through 2021. CPSC is aware of seven deaths since 2005 involving the ingestion of hazardous magnets, including two outside of the United States.', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic beads immediately, take them away from children and contact Stateside Bead Supply to receive a pre-paid label to return the recalled products for a full refund. Stateside Bead Supply is notifying all known purchasers directly.', '24175');
INSERT INTO safety_incidents VALUES ('f568e1bd721d2d3376a3e6ea3b37513acf9cb5f3', 'CPSC', '2024-03-21', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'BRS and BULin Liquid Fuel Bottles', 'Burns', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fuel bottles, place them out of reach to children, and contact Tentock for instructions on how to dispose of the product to receive a full refund.', '24172');
INSERT INTO safety_incidents VALUES ('eaa3b76fa6a77790de5d218641cce7e2d52e6e5e', 'CPSC', '2024-03-21', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Crown Aruba IV (AWR Series) gas-fired hot water boilers', 'Burns', 'Other', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers with the recalled boilers should immediately contact Crown Boiler for a free repair that includes a free replacement main burner gas orifice, and a free replacement blocked vent switch if needed. Consumers who continue using the recalled boilers while awaiting repair should have working carbon monoxide alarms installed outside of sleeping areas and on each floor of the home. Consumers can review Protect Your Family from Carbon Monoxide Poisoning | CPSC.gov for more information about preventing carbon monoxide poisoning.', '24168');
INSERT INTO safety_incidents VALUES ('2c99286b10a6049ec597eb13f0e248bbf12eac09', 'CPSC', '2024-03-21', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Sneaker Basel Double Magnetic Levitation Displays', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received one report of an incident in the U.S. where the magnets collided and shattered during use, without injury. The firm has received seven reports of incidents in Australia where the magnets collided and shattered during use, including four minor injuries.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled displays, store them away and contact Culture Kings for a full refund. Consumers should keep the magnets at least six inches apart during handling. If the magnets come together, consumers should not attempt to separate them. Consumers will be asked to request free "Recalled Product" stickers for the magnets and to place a sticker on the metal side of each magnet, destroy the display by cutting the power cord, and upload a photo of the stickered magnets and destroyed display to https://www.recallrtr.com/sneakerdisplays. The magnets and sneaker display should be discarded after the refund is received.', '24166');
INSERT INTO safety_incidents VALUES ('e7ad8f068e626f9a2224ccb764ba937ca7625f43', 'CPSC', '2024-03-21', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Fisher-Price Little People Mickey and Friends Figures', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Fisher-Price has received three reports of the heads detaching from the Donald Duck or Daisy Duck figures, including one report of a detached head in the mouth of a young child. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Donald Duck and Daisy Duck figures, take them away from children, and contact Fisher-Price to receive a pre-paid return label to return the two figures and receive a $10 refund. This recall only involves the Donald Duck and Daisy Duck figures that are part of the figure pack.', '24167');
INSERT INTO safety_incidents VALUES ('38118ed16dc03e727b45d674835e0edbec5eede8', 'CPSC', '2024-03-21', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Metallic Mugs included in 2023 Holiday Starbucks-branded Gift Sets', 'Burns', 'Flammability / Overheating', 'Laceration / Cut', 'There have been 12 incidents of the mugs overheating or breaking resulting in 10 injuries, including nine severe burns/blisters on fingers or hands, and one cut on a finger. One incident required medical attention.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mugs, and either return them to the place of purchase or contact Nestlé USA for a full refund. Consumers can receive a cash or gift card refund when they return the mug to the store where purchased, or a check from Nestlé USA when they visit https://www.nestleusa.com/info/contact-us-landing, scroll down to "Leave Us a Message", click on "Complaint", select "Recall" from the drop-down menu, attach a photo of the mug or the gift set identifier code, complete the form and hit send. Proof of purchase (receipt) is not required to receive a full refund.', '24171');
INSERT INTO safety_incidents VALUES ('087a26714112351b0b758897afdd0852f3e8868a', 'CPSC', '2024-03-21', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Ravin R500 Model Crossbows', 'Injury', 'Other', 'Not Specified', 'The firm has received one report of the crossbow unexpectedly discharging. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Ravin R500 series crossbows and contact Ravin Crossbows for a free repair.', '24174');
INSERT INTO safety_incidents VALUES ('922710266bb2c947aa4ee75b69a31b1f3cdacd13', 'CPSC', '2024-03-21', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Happiness USA Liquid Rolling Candy', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Twenty Four Six Foods has received one report of the rolling ball dislodging, resulting in a seven-year-old child choking in New Jersey in July 2023. The child underwent emergency surgery to successfully remove the rolling ball from his throat.', 'Fatal', 1, 0, 'Consumers should immediately stop using the candy, take it from children, and contact Twenty Four Six Foods for a full refund. Twenty Four Six Foods is contacting known purchasers directly.', '24169');
INSERT INTO safety_incidents VALUES ('0f680a270f84b685c2a278170805ace2408d24dc', 'CPSC', '2024-03-14', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Air Fryers and Air Fryer Ovens', 'Fire', 'Flammability / Overheating', 'Laceration / Cut', 'The firm has received 24 reports of overheating/melting or glass shattering, including six reports of air fryers catching on fire. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Insignia air fryers and air fryer ovens and visit https://www.recallrtr.com/airfryer for instructions on how to submit photos of the recalled unit(s), the model number, purchase receipt, and on the destruction of the unit. Consumers can receive a refund in the form of a refund check or a Best Buy store credit. A consumer will receive the amount on the purchase receipt, or they will receive the average sales price for the model if no receipt is provided. Consumers should not return the recalled air fryers or air fryer ovens to Best Buy stores. Best Buy has contacted all known purchasers directly.', '24159');
INSERT INTO safety_incidents VALUES ('f3c432bf7dc54024cef48ed5e7c0ace85fee79d1', 'CPSC', '2024-03-14', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'System Sensor L-series low frequency Sounders and Strobes for residential apartments and commercial buildings', 'Fire', 'Mechanical Failure', 'Not Specified', 'Honeywell has received two reports of low or no sound output during installation. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should contact the firm to arrange for a free inspection and free repair.', '24158');
INSERT INTO safety_incidents VALUES ('b32ed60c0a5b785f85ecc3212df1a1a0a8feaf19', 'CPSC', '2024-03-14', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Tracker Off Road OX EV Vehicles', 'Fire', 'Drowning Risk', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the Tracker OX EV and contact their authorized Tracker Off Road dealer or service center to schedule a free inspection and repair of the battery module. Textron advises that until the Tracker Off Road dealer or service center has completed this service, do not charge the recalled vehicle and park the recalled vehicle outdoors at least 15 feet away from any buildings or other vehicles. Textron Specialized Vehicles is contacting all known purchasers.', '24160');
INSERT INTO safety_incidents VALUES ('d2ca3deb4673ffbfd0de0d1ce15bfbedb8f0c538', 'CPSC', '2024-03-14', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'U.S. Boiler, New Yorker Boiler, Advantage, FORCE and Archer brand gas-fired hot water residential boilers', 'Burns', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Moderate', 1, 0, 'Consumers with the recalled boilers should immediately contact U.S. Boiler to receive a free repair that includes a free replacement main burner gas orifice and a free replacement blocked vent switch if needed. Consumers who continue use of the boilers while awaiting repair should have working carbon monoxide alarms outside of sleeping areas and on each floor of the home.', '24161');
INSERT INTO safety_incidents VALUES ('36b685ebc26e95fb40a3876f85f0333795125f1c', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'EverFrost Battery Powered Coolers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received five reports of overheating, smoke and/or fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled coolers, and contact Anker for a free replacement lithium-ion battery pack. Visit https://www.anker.com/anker-solix/cooler-battery-recall-pps to file a claim, and for instructions on how to replace the battery pack. Recalled lithium-ion batteries should be disposed of in accordance with any local and state laws, and not in the trash.', '24146');
INSERT INTO safety_incidents VALUES ('539c3cc79f23baba44d57b5441bd88f84ed1528a', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Bubble Bear Crib Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled crib mattresses and contact the firm by email to receive a full refund and for directions on how to dispose of the mattresses. Shenzhen Coral Island Furniture and Amazon are contacting all purchasers directly by email. Consumers should use scissors to cut out the top fabric on both sleep surfaces, and submit photos of each side to coralisland2020@outlook.com to receive a refund and instructions on how to dispose of the mattress.', '24155');
INSERT INTO safety_incidents VALUES ('87870dd47e9a0b70be92e3058e2fcb0b1e662e04', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Bracelet sold with Skechers Watch and Jewelry Gift Sets', 'The Clasp On The Braided Black Bracelet Sold As Part Of The Gift Set Contains High Levels Of Lead And Cadmium. Lead And Cadmium Are Toxic And Can Cause Adverse Health Effects In Children.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bracelet in the gift set, dispose of it in the trash and contact the website or store where purchased for a full refund of the gift set''s purchase price.', '24151');
INSERT INTO safety_incidents VALUES ('274a6601ade4e6cf189c070b23383f83a99744c3', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', '216-Piece 5mm Magnet Balls', 'Cpsc Testing Determined The Magnetic Ball Sets Do Not Comply With The Requirements Of The Mandatory Federal Toy Regulation Because They Contain One Or More Magnets That Fit Within Cpsc''S Small Parts Cylinder And The Magnets Are Stronger Than Permitted. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported. CPSC estimates 2,400 magnet ingestions were treated in hospital emergency departments from 2017 through 2021. CPSC is aware of seven deaths involving the ingestion of hazardous magnets, including two outside of the United States.', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnets immediately, take them away from children and contact Getallfun.com to receive a pre-paid label to return the recalled products. Upon receipt of the products, consumers will receive a full refund. Getallfun is notifying all known purchasers directly.', '24147');
INSERT INTO safety_incidents VALUES ('74eb782f5150268ab4086ffc5a3bab6ac560ccd2', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'GT LaBomba bicycles', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received five reports of damage to the bicycle headtube/downtube weld, causing the bicycle headtube to separate from the bicycle frame. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact an authorized GT dealer for a free replacement frame.', '24148');
INSERT INTO safety_incidents VALUES ('758e60d6ce8d182bb76bf8a4971523672bf9da6d', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Magnetic Stones Toy Creativity Development DIY Magnetic Beads, 5mm (.2 inch)', 'The Recalled 5Mm Magnetic Ball Sets Violate The Mandatory Federal Toy Magnet Regulation Because They Contain One Or More Magnets That Fit Within Cpsc''S Small Parts Cylinder, And The Magnets Are Stronger Than Permitted. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported. CPSC estimates 2,400 magnet ingestions were treated in hospital emergency departments from 2017 through 2021. CPSC is aware of seven deaths since 2005 involving the ingestion of hazardous magnets, including two outside of the United States.', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic ball sets immediately, take them away from children, and contact Joybuy Marketplace Express to receive a pre-paid label to return them for a full refund. Joybuy Marketplace Express is notifying all known purchasers directly.', '24144');
INSERT INTO safety_incidents VALUES ('08c7718a1eebe7e2180268152c5c365222c7cb4f', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Jool Baby Nova Baby Infant Swings', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled swings for sleep, and contact Jool Baby to receive a free repair kit, including shipping. Consumers should upload a photo of the warning label to the firm''s online registration page at www.JoolBaby.com/recall. Once registered, Jool Baby will send consumers a repair kit consisting of a new seat with updated on-product warnings, updated plush toys and an updated remote control.', '24145');
INSERT INTO safety_incidents VALUES ('639d7aefe5e5643b95614d5946ce1539de9bb9bd', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'SINGES 3-in-1 Baby High Chairs and Booster Seats', 'Falls', 'Mechanical Failure', 'Fall Injury', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled high chairs and return them to Walmart for a full refund. Shenzhen Yingjieshang Trade and Walmart are contacting all known purchasers directly.', '24153');
INSERT INTO safety_incidents VALUES ('0e43ea28685eeaacb1e572dff7f3b0f7e29dba29', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Eco Terra Hybrid Latex Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mattress and contact Sleep Technologies to receive a free cover to put on the mattress to bring it into compliance with the federal regulation. Sleep Technologies is contacting all purchasers directly.', '24150');
INSERT INTO safety_incidents VALUES ('04e2a70ccd1a7c1bdadd84fad470cdac28837eb8', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Model Year 2024 Arctic Cat Catalyst 600 Series Snowmobiles', 'Injury', 'Other', 'Not Specified', 'The firm has received three reports of brake line damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact Textron Specialized to arrange for a free inspection and free repair at a dealer or to receive a free repair kit, including shipping. Textron Specialized will mail consumers a repair kit which consists of a cable tie, installation instructions, and a turn card for consumers to repair their vehicle themselves. Textron Specialized Vehicles is contacting all purchasers directly.', '24154');
INSERT INTO safety_incidents VALUES ('b9a34dc7853e1aed5de5fb3a20cd71a0bcec4ba2', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Tommy Bahama brand children''s pants sets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled pants away from children and cut off the faux drawstrings to eliminate the hazard. Consumers can also contact TJX for instructions on how to destroy the pants and obtain a full refund. Consumers can also return the pants to any Marshalls store for a full refund.', '24152');
INSERT INTO safety_incidents VALUES ('197d08645d4de651112d7befa4342ec7dd963b2c', 'CPSC', '2024-03-07', 2024, '2024-03', 'USA', 'United States', '', 'Other', 'Yamaha PA-10 AC Power Adaptors', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the PA-10 AC Power Adaptor and contact Yamaha for a free replacement. Yamaha will provide a free replacement AC Power Adapter to any consumer who purchased a Yamaha mixing console that contained a defective PA-10 AC Power Adapter and/or purchased a defective PA-10 AC Power Adapter as a stand-alone replacement part.', '24149');
INSERT INTO safety_incidents VALUES ('22d924ccf1b01102eed6a8e502eab8785b130262', 'CPSC', '2024-02-29', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Ski-Doo® MXZ and Renegade Snowmobiles equipped with Pilot X Skis', 'Injury', 'Other', 'Skin Irritation', 'The firm has received 27 reports in the United States of the snowmobile''s left ski breaking. There are no reports of injuries in the United States. The firm is aware of one incident in Canada resulting in an injury.', 'Serious', 1, 0, 'Consumers should immediately stop using the snowmobiles, and contact BRP to schedule a free inspection and repair at the dealership by replacing the left ski free of cost. BRP is contacting all purchasers directly.', '24140');
INSERT INTO safety_incidents VALUES ('6477e5f9144a9c4009a3cfbb2d6e9704f62a6d2e', 'CPSC', '2024-02-29', 2024, '2024-02', 'USA', 'United States', '', 'Other', '2021 through 2023 Model Year Cannondale Dave bicycles', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received two reports of damage to the bicycle headtube/downtube weld, causing the bicycle headtube to separate from the bicycle frame. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact an authorized Cannondale dealer for a free replacement frame.', '24136');
INSERT INTO safety_incidents VALUES ('92fce375fb88f7ec361cceae20e208c7b7ef78ee', 'CPSC', '2024-02-29', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Liverpool Football Club (L.F.C.) Children''s Pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them and contact Liverpool Football Club for a full refund. Consumers should destroy the garments by cutting them in half and disposing of them in accordance with local and state recycling laws. Consumers should send the recalling firm a photo of the destroyed garment using https://store.liverpoolfc.com/us-product-recall. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '24138');
INSERT INTO safety_incidents VALUES ('6203c813806195e8cf3547ffc7d1909c683a4b7d', 'CPSC', '2024-02-29', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Electric Height-Adjustable Mobile Stands for Large Interactive Flat Panel Displays', 'Falls', 'Entrapment', 'Entrapment', 'The firm has received one report of the wheelbase welds breaking while the stand was being moved. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled mobile stands and contact SMART Technologies ULC for an on-site replacement of the wheelbase free of charge. SMART and its authorized resellers are contacting known purchasers directly.', '24134');
INSERT INTO safety_incidents VALUES ('631d3ac38f34f1d5952d7ee01274fb23aa9aa395', 'CPSC', '2024-02-29', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Heritage Store Hydrogen Peroxide Mouthwash', 'The Recalled Mouthwash Contains Ethanol In A Concentration Which Must Be In Child-Resistant Packaging, As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child-Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled mouthwash in a safe location out of reach and sight of children, and contact Nutraceutical Corporation for a full refund or free replacement product, including shipping, depending on availability. Consumers will be asked to dispose of the product. Nutraceutical is contacting all known purchasers directly.', '24142');
INSERT INTO safety_incidents VALUES ('4df8474baac0e704492c5ab7b1c1d7e7886622d3', 'CPSC', '2024-02-29', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Children''s Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the children''s pajamas immediately and contact Oso & Me for a full refund. Consumers who purchased the product will be asked to destroy the garment by cutting the top and bottom in half, and sending the recalling firm a photo of the destroyed garment to ProductRecall@osoandme.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '24135');
INSERT INTO safety_incidents VALUES ('e61f63141517d6bb6b421b58b50f182af02e759b', 'CPSC', '2024-02-29', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Sandford Family 6-Player Croquet Sets', 'The Paint Or Surface Coating On The Red Mallet, Blue Mallet, Red Hoop, And Winning Post Contain Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Lead Poisoning Hazard. In Addition, The Coating On The Red And Blue Mallets Contains Levels Of Regulated Phthalates That Exceed The Prohibition Of Specific Phthalates. Lead And Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled family croquet sets, and contact DOM Sports for information on how to email a photo of the recalled product being disposed of to support@domsports.com to receive the free replacement parts. DOM Sports and Amazon are contacting all known purchasers.', '24141');
INSERT INTO safety_incidents VALUES ('823426485bb66e1a851fd35dcbe609b9ec826385', 'CPSC', '2024-02-29', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Camplux portable tankless water heaters', 'Fire', 'Drowning Risk', 'Not Specified', 'Camplux has received 19 reports of fire incidents involving the recalled water heaters. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately turn off and stop using the recalled portable water heaters and contact The Home Appliances for a free repair kit. The repair kit consists of a replacement gas regulator with a quick connect attachment that allows for easy connection and disconnection without the need to screw in the gas regulator. Instructions for installing this repair kit will also be provided.', '24137');
INSERT INTO safety_incidents VALUES ('5efaf749e514c0ed5270bc83f6c93c74b0c3905d', 'CPSC', '2024-02-29', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Vanilla Underground "Minecraft TNT" One-Piece Pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them and contact Vanilla Underground for a full refund. Consumers should destroy the garments by cutting them in half and disposing of them in accordance with local and state recycling laws. Consumers should send a photo of the destroyed garment to customercare@vanillaunderground.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '24133');
INSERT INTO safety_incidents VALUES ('f05e8485e6747a0b03becd3ce33a94a52aec59eb', 'CPSC', '2024-02-29', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Vernier Go Direct® Charge Stations', 'Burns', 'Flammability / Overheating', 'Burns', 'The firm has received two reports of the chargers overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Vernier Go Direct Charge Station, and contact Vernier to receive instructions on how to return their charge station for a free repair. Vernier is contacting all known purchasers directly.', '24132');
INSERT INTO safety_incidents VALUES ('4eb848c45be1772b988d2722a23af5b69f032b14', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Awesafe Biometric Gun Safes', 'Injury', 'Other', 'Not Specified', 'The firm has received reports of 71 incidents of the recalled gun safes being opened by unauthorized users when the biometric lock failed to secure the safe. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the biometric feature, remove the batteries, and only use the key for the recalled safes to store firearms until they get the free replacement safe. Contact Awesafe to receive instructions on disabling the biometric feature and to receive a free replacement safe. Consumers will be asked to disable the biometric reader and email a photo of the disabled biometric reader to Recall@awesafeus.com in order to receive a replacement safe. The instructions on how to safely disable the biometric reader are also located at http://awesafeus.com/RECALL. Once they receive their replacement safe, consumers should discard the recalled safe in accordance with local laws.', '24127');
INSERT INTO safety_incidents VALUES ('5459eac092f7a1f77c4caaac894b667f3e106a06', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'MouTec brand Biometric Firearm Safes', 'Injury', 'Other', 'Not Specified', 'The firm received one report of the safe opened by an unauthorized user, a 6-year-old boy. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the biometric feature of the recalled safe, remove the batteries from the safe, and only use the key when storing firearms. Contact BBRKIN to receive a repair kit or to receive a free replacement safe. Consumers will be asked to disable the biometric reader and email a photo of the disabled biometric reader to support@bbrkin.com in order to receive a replacement safe. The instructions on how to safely disable the biometric reader are also located at www.securitysafe.store/recallreplacement.', '24128');
INSERT INTO safety_incidents VALUES ('49523117d14e9be0032c9109bdbb6b2866d1812b', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Bulldog Biometric Firearm Safes', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm received four reports of the safe being opened by an unauthorized user. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the biometric feature of the recalled safe, remove the batteries from the safe, and only use the key when storing firearms. Contact Bulldog to receive a repair kit or free replacement safe for consumers with the Magnum Biometric Pistol Vaults, or a free replacement safe for consumers with the Magnum Biometric Top Load Pistol Vaults.', '24130');
INSERT INTO safety_incidents VALUES ('7a36dfbecfeac028d5cdeb181003ebbd59dfd10d', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'MSR camping cooking pots', 'Burns', 'Mechanical Failure', 'Burns', 'The company has received 22 reports of the pot handle either detaching or becoming loose, including two reports of burn injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled camping cooking pot, and contact Cascade Designs for instructions on submitting a photo of the product to receive a free replacement pot handle/lifter. The replacement pot handle/lifter does not require tools to install.', '24126');
INSERT INTO safety_incidents VALUES ('60792134827a047c57bf913a036bfd289d15ace0', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'EVAS 20-lb. propane exchange cylinders', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should stop using the recalled EVAS 20-lb. propane cylinders immediately, close the top valve completely and return them to any AmeriGas Propane Exchange retail location for a free replacement. Consumers can find exchange retail locations at https://www.amerigas.com/locations/find-propane. Worthington advises consumers to close the valve on top of the cylinder completely when returning them.', '24124');
INSERT INTO safety_incidents VALUES ('2af3c13a6226b2c78652f2a41516978cf643d8eb', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'ÅSKSTORM 40W USB Chargers', 'Burns', 'Electrical Fault', 'Electric Shock', 'IKEA has received 17 incident reports globally, including five reports of burns and four reports of electric shock. No incidents or injuries have been reported in the U.S.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled chargers and return the charger to any IKEA store for a full refund; or, if you are unable to return it to a store, contact IKEA for instructions on how to dispose of the ÅSKSTORM 40W USB Chargers to receive a full refund. Proof of purchase (receipt) is not required to receive a full refund.', '24125');
INSERT INTO safety_incidents VALUES ('734bddc19d85b2d3649e20e05c0eb57c036c7307', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'JURLEA Area Rugs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should stop using the rugs immediately and contact Yalande-US for a full refund. Consumers will be asked to destroy the product by cutting it in half, and to provide proof of destruction by sending a photo of the cut product to yalande_us2021@163.com to receive a full refund. Yalande-US is contacting all known consumers directly.', '24123');
INSERT INTO safety_incidents VALUES ('f13469a803554654c447e070504b97b9b34c0caa', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Machir Biometric Personal Safes', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 15 reports of the recalled safes being opened by unauthorized users when the biometric lock failed to secure the safe. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the biometric lock feature, remove the batteries, and only use the key for the recalled safes to store their items until they get the free replacement. Contact Machir to receive instructions on disabling the biometric lock feature and on how to receive a free replacement safe. Consumers will be asked to disable the biometric reader and email a photo of the disabled biometric reader to Info@machir.com in order to receive a replacement safe. The instructions on how to safely destroy the biometric reader are also located at http://machir.com/biorecall/.', '24129');
INSERT INTO safety_incidents VALUES ('34ef71d070b413c3d36300f8dce460effb05bbf4', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Magik & Kover Pack and Play Mattresses', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using and destroy the recalled mattresses, and contact Magik & Kover to receive a full refund and for directions on how to dispose of the mattress. Magik & Kover and Amazon are contacting all purchasers directly.', '24738');
INSERT INTO safety_incidents VALUES ('3ae9cb51060d69d008ed463b705b59eb8c71316e', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Model Year 2022-2024 MATRYX Snowmobiles equipped with PATRIOT 650 and 850 Engines', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Polaris has received 109 reports of clutch failure, including nine reports where the clutch components separated from the unit and one incident that resulted in a laceration injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact Polaris or an authorized Polaris dealer to schedule a free repair to replace the primary (drive) clutch. Polaris has notified consumers to stop riding the vehicles and is notifying all dealers and contacting registered owners directly.', '24740');
INSERT INTO safety_incidents VALUES ('dc653e84823d92adf469fb529e2f0818d45afe05', 'CPSC', '2024-02-22', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Spring Spirit and Biloban Pack and Play Mattresses', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using and destroy the recalled mattresses, and contact Biloban to receive a full refund and for directions on how to dispose of the mattresses. Biloban and Amazon are contacting all purchasers directly.', '24739');
INSERT INTO safety_incidents VALUES ('9dbd27ffbcb605a9c81d7c0e038e969350055fbb', 'CPSC', '2024-02-21', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Toshiba Laptop AC Adapters', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 679 reports of the recalled AC adapters overheating or catching on fire, melting, and burning. This includes 43 reports of minor burn injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled AC adapters and contact Dynabook Americas for a free replacement AC adapter. Visit https://support.dynabook.com/axx2024 to identify if the AC adapter is part of the recall and for instructions on how to order a replacement. Consumers need to submit a photo of their AC adapter with the power cord cut and certify proper disposal to dba-acadapter2024@dynabook.com to receive a free replacement.', '24122');
INSERT INTO safety_incidents VALUES ('0eb6ae0e771cfac287b706d26900ebbf39e58392', 'CPSC', '2024-02-15', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Bell Soquel Youth Helmets', 'Injury', 'Entrapment', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Bell Soquel Youth Helmets and contact Bell Sports for a refund. To receive a refund, consumers should destroy the helmet by cutting off the straps and upload photos of the helmet with the straps cut to consumersupport-bell@bellhelmets.com to prove destruction, then dispose of the recalled helmet.', '24118');
INSERT INTO safety_incidents VALUES ('dd2a41a052326b1445d4ca8a9554c13baf250201', 'CPSC', '2024-02-15', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'BRS and BULin Liquid Fuel Bottles', 'Fire', 'Flammability / Overheating', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fuel bottles and place them out of reach to children. To receive a full refund, WAOLi is asking consumers to initial and date the bottles, and then submit a photo of them in the trash along with their refund request.', '24119');
INSERT INTO safety_incidents VALUES ('5a967238eabe33207745085b70775ed5a0fb807c', 'CPSC', '2024-02-15', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Digital Electric Smokers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'Char-Broil received 79 reports of consumers who experienced a minor electric shock from touching the smokers while in use, including one report of a consumer developing a finger blister after the shock.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled electric smokers and contact Char-Broil for a free repair kit. The repair kit consists of a Ground Fault Circuit Interrupter ("GFCI") plug (also known as a "pigtail"), a clamshell enclosure to secure the GFCI pigtail, and a cable clamp. Instructions for installing each of these repair kit items will also be provided.', '24116');
INSERT INTO safety_incidents VALUES ('dc752a4c7ff2d44bc311b6aebc1214b41f84538a', 'CPSC', '2024-02-15', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Frigidaire rear-controlled ranges', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Frigidaire rear-controlled ranges and contact Electrolux Group for a free repair/professional installation of a new control panel. Consumers should not use the range while awaiting the service call. Consumers should unplug the unit until repaired by an authorized servicer.', '24117');
INSERT INTO safety_incidents VALUES ('92385c86abc6cdcf4efbc558a022a1efd7f4bde3', 'CPSC', '2024-02-15', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Rhino 24-foot Hot Foot Climbing Sticks', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'FeraDyne has received nine reports of the recalled climbing sticks breaking, resulting in three reports of laceration injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled climbing sticks and contact FeraDyne to receive a full refund. Consumers can return the recalled product with a FeraDyne-provided prepaid mailer or receive instructions on how to destroy the climbing stick.', '24120');
INSERT INTO safety_incidents VALUES ('01a7e4287cd4abc1c06839b081fe7d188097c37b', 'CPSC', '2024-02-15', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Calipso "Combi" and Tiller & Rowe "Growing Table-Mini Greenhouse and Raised Garden Bed"', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 10 reports of the recalled greenhouses overheating, including one report of injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the "Combi" and "Growing Table-Mini Greenhouse and Raised Garden Bed" and contact Ocean State Job Lot for a full refund. Consumers who purchased this product at Ocean State Job Lot stores can return it to the store for a full refund or contact Customer Service for additional instructions. Home Lot (eCommerce) customers should prominently mark "DO NOT USE" in permanent marker on the product and dispose of the product. Consumers who purchased from Home Lot will need to submit a photograph of the recalled product with "DO NOT USE" marked on it to Home Lot customer service at support@mrpearl11.com for a refund to their original method of payment. Consumers can visit https://about.oceanstatejoblot.com/category/product-recalls/ or https://about.oceanstatejoblot.com/ and click on "Product Recalls" at the bottom of the page for more information.', '24121');
INSERT INTO safety_incidents VALUES ('79c2e8673556fb23b463d7e14386d31b483c3a73', 'CPSC', '2024-02-08', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Lolanta children''s hooded flannel bathrobes', 'Fire', 'Flammability / Overheating', 'Burns', 'None Reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled bathrobes away from children, stop using them and contact Nanchang Zhongcangjishi E-commerce for a full refund. Consumers should destroy the garments by cutting them in half and email a photo of the destroyed garment to business@lolanta.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '24114');
INSERT INTO safety_incidents VALUES ('bd33d59d25a19b1f0f3e5f6dbef34c6e2943a387', 'CPSC', '2024-02-08', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Frigidaire Branded Side by Side Refrigerators with Slim Ice Buckets', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Electrolux Group has received 343 reports of plastic pieces breaking off, including two incidents resulting in laceration and ingestion injuries when the pieces were dispensed out of the recalled ice bucket.', 'Moderate', 1, 0, 'Consumers should immediately stop using the ice makers and contact Electrolux Group to request a replacement ice bucket assembly component, free of charge.', '24110');
INSERT INTO safety_incidents VALUES ('7a1b43cbd4a152cc0f2a1f73ad25f36c4ff2684e', 'CPSC', '2024-02-08', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'CableMod Graphics Processing Unit (GPU) V1.0 and V.1.1 Angled Adapters', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 272 reports of the adapters becoming loose, overheating and melting into the GPU, with at least $74,500 in property damage claims in the United States. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled angled adapters and contact CableMod for instructions on how to safely remove their adapter from the GPU and for a full refund, including cost of shipping, or a $60 store credit for non-customized products, with free standard shipping. Consumers will be asked to destroy the adapter and upload a photo of the destroyed product to https://cablemod.com/adapterrecall/. The instructions on how to safely remove the adapter are also located on that site. Once destroyed, consumers should discard the adapter in accordance with local laws.', '24112');
INSERT INTO safety_incidents VALUES ('bca629689400d797c7ab05ef876456a1ceb9f506', 'CPSC', '2024-02-08', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Gas-powered Grass Trimmers', 'Fire', 'Electrical Fault', 'Burns', 'The firm has received 12 reports of the recalled grass trimmers catching on fire, electrical spark or arcing, including two reports of property damage and one report of a consumer who suffered burns on their leg and arm when they attempted to extinguish a fire.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled grass trimmers and contact an authorized Husqvarna dealer to receive a free repair. The dealer locator is available at https://locations.husqvarna.com/us/.', '24113');
INSERT INTO safety_incidents VALUES ('6065b9049146188431da589b725de0ba218e5cbc', 'CPSC', '2024-02-08', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Steamfast, Vornado and Sharper Image-branded handheld garment steamers', 'Burns', 'Drowning Risk', 'Burns', 'Vornado has received 122 reports of hot water spraying or spitting from the steam nozzle, including 23 reports of burn injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled garment steamers and contact Vornado for a full refund or free replacement handheld garment steamer, depending on model.', '24109');
INSERT INTO safety_incidents VALUES ('a168211aec5413c5de037a76a55dd668e6887eb7', 'CPSC', '2024-02-08', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Disposable Lighters', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled lighters immediately and contact VPR Brands for instructions on how to destroy the device and submit proof of destruction to receive a full refund.', '24111');
INSERT INTO safety_incidents VALUES ('aab5626d0e174d1018a90ff3490fc13c384cf7ff', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'BISSELL® brand Multi Reach Hand and Floor Vacuum Cleaners', 'Fire', 'Flammability / Overheating', 'Burns', 'BISSELL has received 17 reports of the recalled vacuum cleaners smoking and emitting a burning odor. Six of the reports included the battery pack catching fire, three of which resulted in minor property damage and two resulting in minor burn injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vacuums and contact BISSELL for instructions on how to deplete the charge on the battery and receive a free replacement vacuum. Recalled lithium-ion batteries should be disposed of in accordance with any local and state laws and not in the trash.', '24107');
INSERT INTO safety_incidents VALUES ('a28da5a5ab74e82dc376f601f1a2d89ffc0ca766', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'BMX Race Box One Bicycle Stems', 'Injury', 'Other', 'Skin Irritation', 'The firm has received one report of a stem faceplate''s cracking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycle stems and contact Box Components for a full refund or a free replacement stem, including shipping.', '24105');
INSERT INTO safety_incidents VALUES ('74686ce8104d52bc5deb7c3f06ea349bf2ecddbc', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Ekouaer Girl''s Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children, stop using them and contact Ekouaer for a full refund. Consumers should destroy the nightgowns by cutting them both vertically and horizontally and disposing of them in accordance with local and state recycling laws. Consumers should send an image of the destroyed recalled nightgowns to Ekouaer by email at walshkelly15@gmail.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '24100');
INSERT INTO safety_incidents VALUES ('4f0b490a331ba74f23b4a6b995fad7b3d29c287d', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Children''s nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children, stop using them and contact Stripe and Stare for a full refund. Consumers should destroy the garments by cutting them in half and send Stripe and Stare a photo of the destroyed product by email at hellousa@stripeandstare.com. Upon receipt of the photo, Stripe and Stare will issue a full refund of the purchase price.', '24101');
INSERT INTO safety_incidents VALUES ('4a06cb4751d2c5eef0b754ebb800137b4483654c', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Magnetic DIY Balls Magic Cube, 5mm', 'The Magnetic Ball Sets Do Not Comply With The Requirements Of The Mandatory Federal Toy Regulation Because They Contain One Or More Magnets That Fit Within Cpsc''S Small Parts Cylinder And The Magnets Are Stronger Than Permitted. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract To Each Other Or To Another Metal Object And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported. CPSC estimates 2,400 magnet ingestions were treated in hospital emergency departments from 2017 through 2021. CPSC is aware of seven deaths since 2005 involving the ingestion of hazardous magnets, including two outside of the United States.', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic balls immediately, take them away from children, and contact DailySale to receive a pre-paid label to return the recalled magnetic balls for a full refund. DailySale is notifying all known purchasers directly.', '24097');
INSERT INTO safety_incidents VALUES ('68554a910e538a500b52e83a6386bc7d2d05bb35', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'NextGen Children''s Bicycles', 'Injury', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled bikes away from children, stop using them, and contact the firm for instructions on returning the bicycles for a full refund.', '24104');
INSERT INTO safety_incidents VALUES ('6e7bb63644daf7713f8a609b0217a6f93f7f540c', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Fishing Games', 'The Fishing Game Does Not Comply With The Requirements Of The Mandatory Federal Toy Regulation Because It Contains One Or More Magnets That Fit Within Cpsc''S Small Parts Cylinder And The Magnets Are Stronger Than Permitted. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract To Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported. CPSC estimates 2,400 magnet ingestions were treated in hospital emergency departments from 2017 through 2021. CPSC is aware of seven deaths since 2005 involving the ingestion of hazardous magnets, including two outside of the United States.', 'Fatal', 1, 0, 'Consumers should stop using the recalled fishing game immediately, take it away from children and contact Huihuang Trading to receive a pre-paid label to return the recalled products. Upon receipt of the products, consumers will receive a full refund. Huihuang Trading Inc. is notifying all known purchasers directly.', '24096');
INSERT INTO safety_incidents VALUES ('2b481814cfcfb801e17de8d86ca5270631e9d950', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'NordicTrack 50 LB iSelect Voice-Controlled Adjustable Dumbbells', 'The Weight Plates Can Dislodge From The Handle During Use, Posing An Impact Hazard.', 'Other', 'Fracture / Blunt Trauma', 'There were 40 reports of weight plates dislodging during use with eight resulting in injuries such as contusions and abrasions.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled NordicTrack 50 LB iSelect Voice-Controlled Adjustable Dumbbells and contact iFIT to receive a full refund. iFIT is contacting all known purchasers directly.', '24102');
INSERT INTO safety_incidents VALUES ('645300bc9a4c857d9bec40b27ddca0c38cf38660', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Slide & Seek Ball Runs with Wooden Knobs', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Lovevery has received 33 reports of the wooden knob detaching during shipping and six reports of the wooden knob detaching after shipment. No injuries have been reported.', 'Minor', 1, 0, 'Consumers with a recalled ball run should immediately take it away from children, stop using it, and contact Lovevery for a free replacement. Consumers will receive a free replacement after registering on the firm''s website, removing and marking the affected door with a specific case number (which will be emailed to known purchasers), uploading a photo of their marked door to www.recallrtr.com/ballrun, and affirming to Lovevery that the door will be disposed of in the trash. Lovevery is contacting all known purchasers directly.', '24098');
INSERT INTO safety_incidents VALUES ('3db5a7fb207aa541fc525e08beae0c75fbf03122', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'DECEMBER HOME® Replacement Light Bulbs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received one report of an incident involving a 3V bulb used in a 120V fixture resulting in a "short out" in the fixture. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled light bulbs and return them to Meijer for a full refund.', '24099');
INSERT INTO safety_incidents VALUES ('e61ede48c851bad9b65d84b1bf56a73624fd4826', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Lithium-ion battery sold for Pixy Flying Cameras', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Snap has received four reports of the battery overheating and bulging, resulting in one minor battery fire and one minor injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the Pixy Flying Camera, remove the battery and stop charging it. Consumers should then visit www.pixy.com for instructions on how to participate in the recall, receive a refund of the purchase price, and dispose of the battery in accordance with local and state regulations. The Pixy flying camera and other Pixy accessories are also separately eligible for a refund of the purchase price.', '24095');
INSERT INTO safety_incidents VALUES ('c0a6b8b6bedc7b4e112ebd6ccafccf1442b75bf3', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Shift Brake Levers', 'The Clamp Bolt On The Brake Lever Can Come Loose, Posing A Crash Hazard To The Rider. A Rider Uses The Brake Lever To Activate The Braking System To Slow Or Stop The Bicycle.', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled SRAM shift brake levers and inspect their levers for tightness. If the shift brake lever rotates or is loose, the consumer will be offered a free brake installation inspection at an authorized SRAM retailer. If the brake installation is loose at the dealer inspection, the clamp bolt assembly will be tightened or replaced at no charge to the consumer.', '24103');
INSERT INTO safety_incidents VALUES ('a18a209611a6e356ff497f40c6b9570f1a4e764e', 'CPSC', '2024-02-01', 2024, '2024-02', 'USA', 'United States', '', 'Other', 'Snow globes (Little Wanderer)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 39 reports of the snow globe cracking or fracturing. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using and discard the recalled snow globes. Contact the Museum of Modern Art for a full refund. The museum is contacting all known purchasers.', '24106');
INSERT INTO safety_incidents VALUES ('5e33ab912f08241cf95cfde4f01bcc0aa6bd15fe', 'CPSC', '2024-01-25', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'BRS Fuel Bottles', 'Burns', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fuel bottles, place them out of reach of children, and contact OAREA Outdoor Gear for information on how to return or dispose of the product to receive a full refund.', '24090');
INSERT INTO safety_incidents VALUES ('743f9f6c965b64758cc61692fbe098891edd9505', 'CPSC', '2024-01-25', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Allegro plastic side chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 16 reports of chairs breaking apart while in use, resulting in two injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the Allegro plastic side chairs and contact Clark Associates for a full refund or a store credit. Consumers should submit a photograph to Clark online at lancastertableandseating.com/recalls/allegro-side-chair-recall/ displaying "DO NOT USE" in paint or thick permanent marker in a clear visible location on the chairs, and dispose of the product(s). Clark Associates is contacting all known purchasers directly.', '24091');
INSERT INTO safety_incidents VALUES ('ded8fe1e3a7a04441a8c8859841ca0ef825024f5', 'CPSC', '2024-01-25', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Ascend Cabrillo and Minaret Electric Bikes', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received three reports of the battery catching on fire, resulting in one injury of second-degree burns.', 'Minor', 1, 0, 'Consumers should immediately stop using and unplug the recalled electric bikes. Consumers should enter their serial number on www.pacific-cycle.com/safety-notices-recalls before returning the bike(s) to confirm their electric bike is part of the recall. Return the recalled bikes to Bass Pro Shops or Cabela''s to receive a full refund.', '24092');
INSERT INTO safety_incidents VALUES ('3746b035775d24d56a996e160953e8102f2f164e', 'CPSC', '2024-01-25', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Maverick Coastal 60-inch Outdoor Ceiling Fans', 'Injury', 'Sharp Edges / Points', 'Fracture / Blunt Trauma', 'The firm has received nine reports of fan blades cracking or breaking. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ceiling fans and contact Visual Comfort & Co. to obtain free replacement new blades. If the consumer is not able to install the blades, consumers should schedule installation of the repair kit by a certified electrician. Once the repair kit has been installed, consumers should send the invoice to Visual Comfort for the installation charges, to receive a reimbursement in the full amount of the cost of the service in the form of a check.', '24094');
INSERT INTO safety_incidents VALUES ('640ca321416f5d2c7d40d243f8d68e29da62d669', 'CPSC', '2024-01-25', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Yaomiao Children''s Rhinestone Silver Tiaras', 'The Rhinestones Embedded In The Recalled Tiaras Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled tiaras away from children, stop using them and contact LordRoadS for a refund. LordRoadS and Amazon are contacting all known purchasers.', '24093');
INSERT INTO safety_incidents VALUES ('80c9b113a0fe39a98d32b322c64c4f22000f9353', 'CPSC', '2024-01-18', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Bokser Home 100% Cotton Mattress Pads', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled mattress pads immediately and contact Bokser Home for a full refund. Consumers who purchased the mattress pads will be asked to destroy the product by cutting it with scissors and sending Bokser Home a photo of the destroyed mattress pad at support@bokserhome.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '24085');
INSERT INTO safety_incidents VALUES ('ecdc59c8382586dca46a2d9618b61707753b9e1a', 'CPSC', '2024-01-18', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Upholstered Low Profile Standard and Platform Beds', 'Injury', 'Mechanical Failure', 'Fall Injury', 'Home Design has received 128 reports of the beds breaking, sagging or collapsing during use, including 36 injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled beds and contact Home Design for free replacement slats and side rails. Consumers must send an image of the bed and the law label, or proof of purchase, to recall@homedesign-us.com to receive the free repair. Home Design is contacting known purchasers directly.', '24084');
INSERT INTO safety_incidents VALUES ('4c64818872123e9b1cd518c3d4cb2a139bbc8b85', 'CPSC', '2024-01-18', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Tilt-Up Bath & Shower Seats', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 62 reports of the shower seats breaking, including 4 reports of injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled shower seats and contact Steamist to determine if their product is included in the recall and for instructions for how to participate in the recall.', '24086');
INSERT INTO safety_incidents VALUES ('2c66902c91743d9996bce0d0c19f084e862cc864', 'CPSC', '2024-01-11', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'New Age Industries ("New Age") Furniture tip kits or tip restraints', 'The Plastic Zip Tie Used With The Recalled Furniture Tip Kits Can Become Brittle Or Break, Which Can Allow A Clothing Storage Unit That Is Anchored To The Wall To Detach During A Furniture Tip-Over Event, Posing A Tip-Over And Entrapment Hazard That Can Result In Death Or Serious Injuries To Children.', 'Entrapment', 'Entrapment', 'Furniture companies have received two reports of the New Age tip kits breaking. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately check if their clothing storage unit has a date of manufacture sticker or stamp of November 2019 or later. If so, and if the tip kit is made of plastic, consumers should contact Alliance4Safety for a free replacement tip kit. Keep children away from the unit while waiting for a replacement tip kit.', '24078');
INSERT INTO safety_incidents VALUES ('8b0926011eb7b7e737b0de0487211a5b78b6884c', 'CPSC', '2024-01-11', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Justin Boots Keaven WP Met Guard Work Boots Model SE4570', 'The Work Boots Can Be Missing The Metatarsal Guard, Posing An Impact Hazard To The User''S Feet.', 'Other', 'Fracture / Blunt Trauma', 'The firm has received one report of an injury when a heavy object fell on a consumer''s foot, resulting in bruising.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled boots and contact Boot Royalty Company for instructions on how to receive free replacement boots.', '24082');
INSERT INTO safety_incidents VALUES ('e00d928e4bfc7835c74f5703c71998447bd213d7', 'CPSC', '2024-01-11', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Evaporator coil drain pans', 'Fire', 'Flammability / Overheating', 'Respiratory', 'DCT has received a total of 31 reports of fire involving the drain pans, including five reports since the recall was reannounced in July 2022. The incidents resulted in one reported smoke inhalation and several reports of significant fire and smoke damage to residences.', 'Moderate', 1, 0, 'Consumers should contact Daikin Comfort Technologies Manufacturing L.P. (DCT) to determine whether your unit is included in this recall and to register for the free repair by a qualified technician. DCT is contacting all registered consumers where records indicate their gas furnace system is subject to the recall.', '24080');
INSERT INTO safety_incidents VALUES ('f37855315fe0c752c615a0063cde60260277648a', 'CPSC', '2024-01-11', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Scout Kid''s Bike Helmets', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Retrospec for a full refund. To receive a refund, consumers should destroy the helmet by cutting off the straps and mark the helmet with their initials and the date near the Retrospec logo on the right side of the helmet. Consumers should upload a photo of the helmet, showing the straps cut off, their initials, date, and Retrospec logo, to the recall registration page at https://retrospec.com/pages/retrospec-scout-recall to prove destruction, and then dispose of the recalled helmet.', '24081');
INSERT INTO safety_incidents VALUES ('573b1df95be2cb445773a3989b11bebafc51679a', 'CPSC', '2024-01-04', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Bell Slope Adult Helmets', 'Injury', 'Entrapment', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Bell Adult Slope helmets and contact Bell Sports for a refund. To receive a refund, consumers should destroy the helmet by cutting off the straps and upload photos of the helmet with the straps cut to consumersupport-bell@bellhelmets.com to prove destruction, then dispose of the recalled helmet.', '24074');
INSERT INTO safety_incidents VALUES ('6b4ec9cb4b4dd1c581c6542a6d29eb2b1ca056ed', 'CPSC', '2024-01-04', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Redeemer Men''s Work Boot Model DH 5379', 'Injury', 'Sharp Edges / Points', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled boots and contact H.H. Brown Shoe Company for a prepaid shipping label to return the boots for a free replacement of Redeemer DH5379 Work Boots with puncture-resistant soles.', '24072');
INSERT INTO safety_incidents VALUES ('435de52befb424f4b33eb248edda1f3458848116', 'CPSC', '2024-01-04', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Therapist Select Percussion Personal Massagers', 'Fire', 'Flammability / Overheating', 'Burns', 'Homedics has received 17 reports of the massagers overheating, including one report of a burn to the consumer''s thumb.', 'Moderate', 1, 0, 'Consumers should immediately stop using or charging the recalled massagers and contact Homedics for instructions to receive a full refund or a refund in the form of a credit toward any Homedics product, including a 20% bonus.', '24076');
INSERT INTO safety_incidents VALUES ('4154e79fcef0bbd486668815a1edb930817f0b6a', 'CPSC', '2024-01-04', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'Class 2 Sinch.2 Folding E-Bicycles', 'Injury', 'Other', 'Skin Irritation', 'The firm has received six reports of the recalled e-bikes accelerating unexpectedly. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled e-bikes and contact a Ride Aventon authorized dealer to schedule a free repair, including a software update to the controller.', '24075');
INSERT INTO safety_incidents VALUES ('d7f9651b48b809660c5ce89ef2b082c28baade4d', 'CPSC', '2024-01-04', 2024, '2024-01', 'USA', 'United States', '', 'Other', 'UBBCARE Play Yard Mattresses', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using and dispose of the recalled mattresses and contact UBBCARE to receive a full refund and for directions on how to dispose of the mattress. UBBCARE and Amazon are contacting all purchasers directly.', '24077');
INSERT INTO safety_incidents VALUES ('8e98a3017b18a4d8c753620b036e8d8d919ffe17', 'CPSC', '2023-12-28', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'BlendJet 2 Portable Blenders', 'Fire', 'Flammability / Overheating', 'Laceration / Cut', 'The firm has received approximately 329 reports of the blades breaking while in use, and an additional 17 reports of overheating or fires resulting in property damage claims of approximately $150,000. The firm has received about 49 reports of minor burns and one report of a laceration injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled blenders and contact BlendJet for a free replacement of the BlendJet 2 base unit. Consumers will need to remove and cut the rubber seal from the base of their recalled blender into three or more pieces and upload or email a photo showing the serial number on the bottom of the unit and its rubber seal in pieces to BlendJet at www.blendjet.com/safetyandrecall or safety@blendjet.com to receive a free replacement base. Consumers can identify whether they have a recalled unit by entering the serial number of their unit into the "Is my BlendJet 2 Recalled?" tool located at www.blendjet.com/safetyandrecall, or by calling BlendJet toll-free number at 844-334-0562.', '24069');
INSERT INTO safety_incidents VALUES ('138aa8e097b041df8ce1131b042839b86adea5fa', 'CPSC', '2023-12-28', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Simpson Gas Pressure Washers with Electric Start', 'Burns', 'Flammability / Overheating', 'Burns', 'FNA has received two reports of batteries in the pressure washer''s electric start feature overheating and damaging the units. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled gas pressure washer and contact FNA Group Inc. for instructions on how to have their unit repaired free of charge at an authorized repair facility. The repair will replace the lithium battery in the electric start system with a sealed lead acid battery.', '24070');
INSERT INTO safety_incidents VALUES ('c1df59c5f20d66a4db164f8152b33be0039095cc', 'CPSC', '2023-12-28', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Relax 5mm Science Kit, Large Hematite Magnets Magnetic Stones Building Blocks', 'The Recalled 5Mm Magnetic Ball Sets Do Not Comply With The Requirements Of The Mandatory Federal Magnet Regulation Because The Sets Contain One Or More Magnets That Fit Within Cpsc''S Small Parts Cylinder, And The Magnets Are Stronger Than Permitted. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning, And Death.', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported. CPSC estimates 2,400 magnet ingestions were treated in hospital emergency departments from 2017 through 2021. CPSC is aware of seven deaths involving the ingestion of hazardous magnets, including two outside of the United States.', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic balls immediately, take them away from children and contact Joybuy to receive a pre-paid label to return the recalled products for a full refund. Joybuy is notifying all known purchasers directly.', '24071');
INSERT INTO safety_incidents VALUES ('7f8848400947bdc0dd3808778f5eb696b982e5c0', 'CPSC', '2023-12-21', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'HEAO 4-in-1 High Chairs', 'Injury', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm is aware of one incident that resulted in a laceration to a child''s finger that required medical attention.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled high chairs and contact Brandline for instructions on how to dispose of the products and receive a full refund.', '24064');
INSERT INTO safety_incidents VALUES ('f8b24425643bb2347dae33e8681290059b69de01', 'CPSC', '2023-12-21', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Hover-1 Helix hoverboards (Camouflage and Galaxy colors only)', 'Fire', 'Flammability / Overheating', 'Respiratory', 'DGL has received three reports of fire, which are associated with five reports of people experiencing headaches, nausea, or coughs from smoke inhalation and approximately $25,000 in reported property damage.', 'Moderate', 1, 0, 'Consumers should stop using the recalled hoverboards immediately and contact Hover-1 for instructions as to how to receive a free replacement hoverboard.', '24065');
INSERT INTO safety_incidents VALUES ('21479cee9698447e25ccf9d8e63c6ff734237aac', 'CPSC', '2023-12-21', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Rhino Tree Stands', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled tree stands and contact FeraDyne Outdoors for instructions to receive a replacement tree stand safety harness. FeraDyne will ship the replacement safety harness free of charge. Consumers will need to submit proof of destruction of the original safety harness.', '24066');
INSERT INTO safety_incidents VALUES ('dcc2ca3b27ba1da5431df7a00fa4a98d14543968', 'CPSC', '2023-12-21', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Portable Rechargeable Power Stations', 'Fire', 'Flammability / Overheating', 'Burns', 'Klein Tools received four reports of overheating. No injuries have been reported. No lithium-ion battery fires have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Blackfire and Klein Tools power stations and return the recalled Blackfire and Klein Tools power stations to their original place of purchase. Klein Tools is contacting all known purchasers directly.', '24067');
INSERT INTO safety_incidents VALUES ('23f74c75e504e966e825b2b99e0679b15f49129d', 'CPSC', '2023-12-21', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Litti City Premier Doctor Playset and Teacher Purse Set, Litti Pritti Stylist Handbag Set, and Prextex Slime Eggs', 'All The Dress-Up Playsets And The Slime Eggs Contain Levels Of Certain Phthalates That Exceed The Federal Phthalate Standard. In Addition, The Litti City Teacher Purse Dress-Up Playset, The Litti Pritti Handbag Playset, And The Slime Eggs Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead And Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled playsets and slime eggs and contact Perch for more information on how to dispose of the product and to get a full refund after providing proof of destruction. Perch, Amazon and Walmart will contact all known purchasers directly.', '24737');
INSERT INTO safety_incidents VALUES ('318921b9aa629b92615fd03b160e57bb6f83ff4f', 'CPSC', '2023-12-21', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Pella Architect Series Casement Windows', 'Injury', 'Mechanical Failure', 'Fall Injury', 'The firm has received one report of a window sash detaching from the frame and falling. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should keep the recalled casement windows shut and locked at all times and contact Pella to receive a free repair by a Pella-designated service technician.', '24732');
INSERT INTO safety_incidents VALUES ('e12c5b653984d59e21d1fec89031997369299fad', 'CPSC', '2023-12-21', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Foldable wood and rope bistro set chairs', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received eight reports of the wooden frame of the chair breaking or collapsing when a consumer was seated in the chair, resulting in six reports of minor injuries, including bruising and an ankle strain.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and contact TJX for instructions on how to receive a full refund and dispose of chairs. Consumers can also return the recalled chairs to any HomeGoods, Marshalls, T.J. Maxx, Homesense or Sierra store for a full refund.', '24068');
INSERT INTO safety_incidents VALUES ('b07a6de503206377564afe0427c10c18b7cf1a2b', 'CPSC', '2023-12-14', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Can-Am® Commander series, Defender series, Maverick Trail series equipped with an HD7 or 700 engines side-by-side vehicles (Model Year 2022 and 2023)', 'The Operator''S Guide Maintenance Schedule Section Contains Incorrect Information Regarding Proper Maintenance Intervals For The Clutch Which Can Lead To Clutch Failure, Including Fragments To Be Ejected From The Vehicle If Not Serviced, Posing A Risk Of Serious Injuries.', 'Mechanical Failure', 'Not Specified', 'The firm has received one report of a clutch malfunction. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled Model Year 2022 and 2023 Can-Am Commander series, Defender series, Maverick Trail series equipped with an HD7 or 700 engines side-by-side vehicles until they have reviewed the new maintenance instructions. BRP will mail a free revised maintenance information booklet to registered owners. BRP is contacting all known purchasers directly.', '24735');
INSERT INTO safety_incidents VALUES ('578e4f3fa72d5ae99be1db077f47651f8aab224f', 'CPSC', '2023-12-14', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'PowerXL™ DUAF-10 and DUAF-005 Vortex Dual-Basket Air Fryers', 'Burns', 'Other', 'Burns', 'The firm has received 41 reports of the product breaking during use, including three reports of burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled dual basket air fryers and contact Empower Brands to receive a full refund.', '24051');
INSERT INTO safety_incidents VALUES ('9c3f2a2072161def7149416504bb6e4a872f6e5e', 'CPSC', '2023-12-14', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Utility Vehicles', 'Components Of The Steering Shaft/Steering System Could Have Been Improperly Assembled Which Can Lead To Loss Of Control, Posing Crash And Collision Hazards.', 'Chemical / Toxic Substance', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact an authorized Kubota dealer to schedule a free inspection and free repair. Kubota is contacting all known purchasers directly.', '24736');
INSERT INTO safety_incidents VALUES ('88d36ecfb6d0dc781602a729fd88e7ff516c171d', 'CPSC', '2023-12-14', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Model Year 2023-2024 Ranger XP Kinetic Recreational Off-Road Vehicles (ROVs)', 'Injury', 'Other', 'Skin Irritation', 'The firm has received eight reports of loss of throttle response. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Polaris or an authorized Polaris dealer to schedule a free repair, including an update to the vehicle control system. Polaris has notified consumers to stop riding the vehicles and is contacting registered owners directly.', '24055');
INSERT INTO safety_incidents VALUES ('84e063d0b9958ec52a4ff1c43e3d30ac7a57a2e4', 'CPSC', '2023-12-14', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Model Year 2021-2024 RZR 200 Youth ROVs', 'Injury', 'Instability / Fall Risk', 'Laceration / Cut', 'Polaris has received 32 reports of the steering system locking, including two reports of crashes and two reports of rollover/tip over, which resulted in two injuries involving abrasions.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact an authorized Polaris dealer to schedule a free repair to replace the steering rack assembly. Polaris has notified consumers to stop riding the vehicles and is contacting registered owners directly.', '24056');
INSERT INTO safety_incidents VALUES ('d2eed6131d7a06ecd13a7a524cc5e70cabe80859', 'CPSC', '2023-12-14', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Room & Board Griffin Duo Bunk Beds', 'Injury', 'Mechanical Failure', 'Fall Injury', 'Two incidents of the bunk bed collapsing have been reported. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bunk beds and inspect each of the eight brackets to determine if set screws have been installed. If they have been installed in each bracket, new set screws are not needed. If any brackets are missing set screws, a set screw must be installed before the bunk bed is used again. Room & Board is contacting all purchasers directly with information on how to perform the bunk bed inspection and repair, and is providing free set screw repair kits to consumers upon request. For consumers unable to perform the inspection or repair, Room & Board will send a representative to their home to inspect for and install the set screws as necessary, free of charge. Room & Board has provided this link to a repair video: https://go.roomandboard.com/037D13.', '24060');
INSERT INTO safety_incidents VALUES ('baa95b78bda9b59c2dea933ad87864f6bc425ca7', 'CPSC', '2023-12-14', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Savvy Rest Quilted Cotton Mattress Pads', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled mattress pads immediately and contact Savvy Rest for a full refund. Consumers who purchased the mattress pads will be asked to destroy the product by cutting it with scissors and sending the recall firm a photo of the destroyed mattress pad at info@savvyrest.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '24058');
INSERT INTO safety_incidents VALUES ('5558c4d2de6ddfd59ba3fe9d3a5b60afd8fdbdd3', 'CPSC', '2023-12-14', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Traeger Flatrock Flat Top Propane Grills', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 57 reports of flame adjustment knobs being incorrectly labeled. No fires or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Traeger Flatrock Flat Top Grills and contact Traeger for inspection instructions and, if the burner control knobs are incorrectly labeled, consumers will receive a free repair kit.', '24061');
INSERT INTO safety_incidents VALUES ('8240cb898a4c2dc88f76457e9fc254eb5c70e24a', 'CPSC', '2023-12-14', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Steamfast Home & Away Travel Steam Irons', 'Fire', 'Flammability / Overheating', 'Electric Shock', 'Vornado has received a total of 74 reports of incidents, including 18 additional reports of the iron''s power cord smoking, sparking, catching fire, or overheating at the power cord, or of the power cord becoming damaged. Vornado has received two reports of minor shocks.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled irons and visit the Steamfast or Vornado website to register for the recall and receive a refund or a free replacement iron.', '24050');
INSERT INTO safety_incidents VALUES ('eff3ae7a84ac7b5dcdb3038bd465d3942d8a2efc', 'CPSC', '2023-12-14', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Collegiate English Horse-Riding Saddles', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 12 reports of saddle''s rivet or stirrup bar breaking. One fall injury has been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled saddles and contact Weatherbeeta for instructions to return the recalled saddle to receive a free replacement saddle, including free shipping, similar to theirs. Weatherbeeta is contacting all known purchasers directly.', '24734');
INSERT INTO safety_incidents VALUES ('412c25cf49061d00247419fdb46a1f140a126761', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Bugaboo Dragonfly Seat Strollers', 'Injury', 'Other', 'Not Specified', 'Bugaboo has received one report in the United States and seven reports in South Korea of the backrest of the seat moving downward during use when in parent-facing mode. No injuries have been reported in the U.S.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled seats and contact Bugaboo for a free replacement stroller seat. Bugaboo is contacting all known retailers and purchasers directly.', '24730');
INSERT INTO safety_incidents VALUES ('53757e49c9321b3c1df7691eb8f33e80d71e0ec1', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Bunkhouse and Lotsa LITES! Connectable Mini String Lights', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received three reports of the recalled string lights overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using and unplug the recalled string lights and contact DM Merchandising for a full refund and information on how to take part in this recall. DM Merchandising is contacting all known purchasers directly.', '24733');
INSERT INTO safety_incidents VALUES ('2f77442a4f487535a4e0fca4d0edd68d761805ad', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Squids 3705 Wire Tool Attachments - Screw Gate Tool Tail', 'Injury', 'Other', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled wire tool attachment and contact Ergodyne for a prepaid shipping label to return the product and receive a $4 refund per wire tool (up to $24 per six pack) in the form of a credit towards another Ergodyne product. Ergodyne is contacting all known purchasers directly.', '24728');
INSERT INTO safety_incidents VALUES ('5fb92941f4d0dfa9f8d87c25299cef39cbe30ed2', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Bubba Bull Plush Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received one report of an eye detaching from the plush toy. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled plush toys, take them away from young children and contact Mary Meyer to receive a free replacement. Upon return or verification of destruction, consumers will receive a replacement Bubba Bull plush, or a different plush of equivalent value.', '24042');
INSERT INTO safety_incidents VALUES ('27cde5c0028038839095434a5536e689d750e177', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Moonsea Pack and Play Mattresses', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pack and play mattresses, and contact Moonseasleep to receive a full refund and for directions on how to dispose of the mattresses. Moonseasleep and Amazon are contacting all purchasers directly.', '24731');
INSERT INTO safety_incidents VALUES ('d7b6623bb23bcbc9776022c15712f4940a11d982', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Nap Queen 12-inch Maxima Hybrid Mattress', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mattresses and contact Nap Queen to receive a free fitted cover to put on the mattress to bring it into compliance with the federal standard.', '24041');
INSERT INTO safety_incidents VALUES ('3816037b69db86587c8bc8b06f80653d6aedb04d', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Oreck Discover Upright Vacuums', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'The firm has received 41 reports of a prong detaching from its plug. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vacuums and contact Oreck or their local Oreck dealer for instructions on how to obtain a free repair. To locate the nearest authorized dealer, go to "Find Your Local Store" at www.oreck.com.', '24039');
INSERT INTO safety_incidents VALUES ('924cc6d2ba264450661b0415313a9e9581e99ba2', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Wooden Music Shaker and "DTR M&M Maracas" Baby Rattles', 'Choking', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'The firm has received five reports of the rattles breaking apart in the United Kingdom. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled baby rattles away from children, stop using them and return them to a Primark store for a full refund.', '24049');
INSERT INTO safety_incidents VALUES ('bbc2d3bf3bdf3cd164daa37d42e5b069bb2d3abb', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'SABRE Aim & Fire Pepper Gel Spray with Training Canisters', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received two reports of the red nozzle missing. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled SABRE Aim & Fire Pepper Gel Spray with Training Canisters and contact Security Equipment Corporation for instructions on receiving a free replacement product. The firm will provide a free shipping label to return the product.', '24040');
INSERT INTO safety_incidents VALUES ('c161f0659c55727f96318119c5aee4bfbc22f096', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', '2022 Fugleman UT10E and UT10X Utility-Terrain Vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of a vehicle fire with property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled UTVs and bring the vehicles to an authorized Segway Powersports dealer for a free repair, which includes the installation of an upgrade kit. The firm has contacted all known purchasers.', '24727');
INSERT INTO safety_incidents VALUES ('57b40e846ee7885d629c6878c73e45342261d96b', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Windsor Queen Xtrabed Mobile Murphy Beds', 'Injury', 'Entrapment', 'Entrapment', 'The firm has received 19 reports of the Xtrabed''s outer case breaking and falling when opened from the front, resulting in 11 injuries to consumers'' shoulders, back, legs, knees or feet. The firm has received one report of a tip-over resulting in bruising to the arm.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Xtrabeds and contact J Grubb Designs, a wholly owned subsidiary of SourceOne Ventures, to schedule a free home repair by a technician. Consumers who opt to not receive the repair can instead select a full refund. J Grubb Designs is contacting all known purchasers directly.', '24047');
INSERT INTO safety_incidents VALUES ('8b292c342d42e59a8009c8bcde1e0adb9861f02c', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Vibe Bear Playyard Mattresses', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using and destroy the recalled mattresses, and contact Vibe Bear by email to receive a full refund and for directions on how to dispose of the mattresses. Vibe Bear and Amazon are contacting all purchasers directly.', '24729');
INSERT INTO safety_incidents VALUES ('af8eb35f24d252d6502ae931a70a30343e911056', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Wet & Forget "Xtreme Reach" Outdoor Rapid Application Moss, Mold, Mildew & Algae Stain Remover with Hose End Nozzle', 'The Hose End Nozzle Clip Can Dislodge And Allow The Cleaning Solution To Spray On Users, Posing A Risk Of Skin And Eye Irritation And Other Injuries.', 'Other', 'Skin Irritation', 'The firm has received 3,188 reports of dislodgement of the nozzle insert, including 157 reports of exposure to the cleaning solution and 28 reports that include complaints of skin or eye irritation.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Wet & Forget "Xtreme Reach" Outdoor Mold & Mildew Stain Remover with Hose End Nozzle and contact the firm for a free replacement nozzle. Consumers should not resume use of the stain remover until the replacement nozzle has been installed. Once replaced, the original nozzle should be discarded.', '24043');
INSERT INTO safety_incidents VALUES ('d2eaf7b16f06fe035fcc7cbf76c90938c5d48d0d', 'CPSC', '2023-12-07', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Colorful Metal Neodymium Magic Magnetic Balls - 8 color, 5mm', 'Cpsc Testing Determined The Magnetic Ball Sets Do Not Comply With The Requirements Of The Mandatory Federal Toy Regulation Because They Contain One Or More Magnets That Fit Within Cpsc''S Small Parts Cylinder And The Magnets Are Stronger Than Permitted. When High-Powered Magnets Are Swallowed, The Ingested Magnets Can Attract Each Other, Or Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'None reported. CPSC estimates 2,400 magnet ingestions were treated in hospital emergency departments from 2017 through 2021. CPSC is aware of seven deaths involving the ingestion of hazardous magnets, including two outside of the United States.', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnetic balls immediately, take them away from children and contact XpressGoods to receive a prepaid label to return the recalled products for a full refund or store credit. XpressGoods is notifying all known purchasers directly.', '24048');
INSERT INTO safety_incidents VALUES ('7ca9105ed283c86554ead6bb1bc9cf26d00e39ee', 'CPSC', '2023-12-05', 2023, '2023-12', 'USA', 'United States', '', 'Other', 'Foiresoft Zebra Roller Blinds', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled roller blinds and contact Softfunch Inc. for instructions to receive a full refund. Consumers will need to provide proof of destruction by sending a photo of the cut product with cut cords to the firm. The consumer should then throw away the unit in their trash. Softfunch is contacting all known purchasers directly.', '24726');
INSERT INTO safety_incidents VALUES ('f0397f239389d7fe3e108f54fb7b00ed30465e47', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Heated Throws and Blankets', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received nine reports of the throws and blankets burning, melting or overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled electric throws and blankets and contact Berkshire Blanket & Home Co. for a full refund. Consumers must complete an online recall registration form, submit a photo of the destroyed blanket showing the cut cord, and submit a photo of the wash label after writing "Refund" and an assigned 5-digit refund code on the wash label to receive a full refund.', '24034');
INSERT INTO safety_incidents VALUES ('2f2cd703c1d5cc7c5d5999daea74562079bcf957', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Knob-control electric radiant cooktops, model GE JP3030', 'Burns', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'GE Appliances has received 83 reports of incidents in which a burner failed to regulate temperature accurately and/or power off when the knob was turned to the "off" position. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately contact GE Appliances to arrange for free installation of a replacement burner knob assembly. When not in use, turn the unit off at the circuit breaker. Do not leave flammable materials or empty cookware on or near the cooktop. In the affected units, the burner can remain on following use even after being turned to the "off" position. In this case, the "On" indicator light will not be illuminated, but the "Hot Cooktop" light corresponding to the burner will remain illuminated until power to the cooktop is turned off at the breaker switch.', '24033');
INSERT INTO safety_incidents VALUES ('86fbe0a92c0948805ea7f00930252f7db893b193', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Klickpick Home Children''s Cup Sets', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled cups away from children, stop using them and contact Klickpick Home for a full refund. Klickpick Home and Amazon are contacting all known purchasers directly.', '24725');
INSERT INTO safety_incidents VALUES ('fd73b292a79fe23d7a87026f5a9ca5b309b37d3c', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'DODO Baby House Pack and Play Mattresses', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using and destroy the pack and play mattresses by cutting them in half, then contact DODO Baby House to send photos of destroyed recalled products for a full refund. DODO Baby House and Amazon are contacting all purchasers directly.', '24723');
INSERT INTO safety_incidents VALUES ('c33a47a6a23c45af3d1f02e5b72dad7219dc31ee', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'YPSI and Z4 Inclined Sleeper Bassinets', 'The Recalled Bassinets Violate The Safe Sleep For Babies Act Because They Were Marketed For Infant Sleep And Have An Incline Angle Greater Than 10 Degrees. Infant Fatalities Have Occurred In Inclined Sleeper Products After The Infants Rolled From Their Back To Their Stomach Or Side While Unrestrained, Or Under Other Circumstances. The Bassinets Also Violate The Infant Sleep Products Regulation Because They Do Not Have A Stand.', 'Other', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bassinets and contact Peg Perego for instructions on how to receive a full refund or repair instructions for the recalled bassinets. Consumers who purchased their bassinet for a stroller system or with a stand will be given instructions on how to disable the backrest recline adjustment feature. Peg Perego will offer a $50 cash incentive for consumers who provide proof of backrest disengagement for bassinets part of this recall. Consumers who solely purchased the bassinet should return the product for a full refund. Peg Perego and Amazon are contacting all known purchasers directly.', '24719');
INSERT INTO safety_incidents VALUES ('783a5ea7859595968c925641205018b47a202816', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Polaris Snowmobiles, Model Year 2022 PATRIOT 850 MATRYX RMK, INDY and SWITCHBACK', 'Injury', 'Other', 'Not Specified', 'The firm has received nine reports of the ring gear failing, including one injury where the ligament was separated from the rider''s foot.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact Polaris or an authorized Polaris dealer to schedule a free repair to replace the primary (drive) clutch. Polaris has notified consumers to stop riding the snowmobiles and is contacting registered owners directly.', '24722');
INSERT INTO safety_incidents VALUES ('ee80567dd79e3a11e101f896233aa94620cd676c', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Model Year 2023 PATRIOT 9R MATRYX PRO RMK and PATRIOT 9R MATRYX RMK KHAOS Snowmobiles', 'Injury', 'Other', 'Not Specified', 'The firm has received 91 reports of clutch failure, including nine reports where the clutch components separated from the unit. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact Polaris or an authorized Polaris dealer to schedule a free repair to replace the primary (drive) clutch, install a clutch guard kit and receive an owner''s manual addendum. Polaris is notifying all dealers and registered owners directly.', '24720');
INSERT INTO safety_incidents VALUES ('ca3feea6da0220097b75dfbb8851bcc148d4cb22', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Russound Loudspeakers Model AW70V6', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received one report of a recalled loudspeaker falling. The damage was contained to the loudspeaker itself. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately remove the recalled speakers that are mounted at elevated positions. Contact Russound to arrange for a free replacement loudspeaker.', '24032');
INSERT INTO safety_incidents VALUES ('8f4657ac68c013ab8b9f79dfd48f37a7bf07a418', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Supacaz Orbitron Pedals', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received 21 reports of pedals breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Supacaz Orbitron Pedals and contact Specialized for a full refund. All known purchasers are being contacted directly by retailers who sold this product.', '24718');
INSERT INTO safety_incidents VALUES ('ee4c06df40cd6ccc52ead0456186be0d7e5583a3', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Tiblue 8 oz and 12 oz children''s cups', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the cups away from children, stop using them and contact FENGM for a full refund. FENGM and Amazon are contacting all known purchasers directly.', '24724');
INSERT INTO safety_incidents VALUES ('ec93d2f13776b5ededaecc8a950b372e98e86097', 'CPSC', '2023-11-30', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Vibe Bear Playyard Mattresses', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using and destroy the mattresses by cutting them in half and contact Beyond Baby recallguof@outlook.com to send photos of destroyed recalled products for a full refund. Beyond Baby and Amazon are contacting all purchasers directly.', '24721');
INSERT INTO safety_incidents VALUES ('09fd6cc7aecc6bf53189e5f7d7f6faea158803e9', 'CPSC', '2023-11-22', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Balloon Time Mini Helium Tanks', 'Injury', 'Other', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mini helium tanks. Consumers should point the tank away from themselves and others, and carefully remove the plastic safety seal and cap. Release all helium in a well-ventilated area and then clearly write their name, "RECALLED" and destruction code on the front of the tank with a non-erasable marker. Consumers should register online at www.recallrtr.com/miniheliumtank and upload a photo of their product for a full refund. After receiving a refund, consumers should properly discard the product.', '24030');
INSERT INTO safety_incidents VALUES ('408c1cce56a4ccfb0bc7bd062a00dfa6ac502ba9', 'CPSC', '2023-11-22', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Lenovo USB-C Laptop Power Banks', 'Fire', 'Electrical Fault', 'Entrapment', 'The firm has received one report of a fire causing minimal property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Lenovo USB-C Laptop Power Banks and contact Lenovo for a free replacement as well as instructions for properly disposing of lithium-ion batteries according to local and state regulations.', '24031');
INSERT INTO safety_incidents VALUES ('9142c6675bf96a5fb75b9458d786438b3f7bb494', 'CPSC', '2023-11-22', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'MI 1615 and 1617 Sliding Glass Doors; Window World 4000 Series and 8000 Series Sliding Glass Doors', 'Injury', 'Other', 'Not Specified', 'None reported', 'Serious', 1, 0, 'Consumers should avoid areas with the recalled doors during hurricane conditions and contact MI Windows and Doors to schedule a free repair. Prior to repair, cover the doors with plywood or other suitable protection if a hurricane warning is issued for your location. MI Windows and Doors is contacting all known purchasers directly.', '24717');
INSERT INTO safety_incidents VALUES ('be3da108bafe4312f7bc28b318630143004a4cf2', 'CPSC', '2023-11-22', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'PandaEar Stainless Steel Toddler Cups, 8 oz.', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled cups away from children, stop using them and contact PandaEar for a full refund. PandaEar and Amazon are contacting all known purchasers.', '24716');
INSERT INTO safety_incidents VALUES ('e0a43da29d2520646746fe58dbace361d533eed4', 'CPSC', '2023-11-21', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'ZLINE 30-inch, 36-inch and 48-inch RG gas ranges', 'Injury', 'Other', 'Poisoning / Ingestion', 'Before the recall, ZLINE received 44 reports of carbon monoxide emission, including three reports of consumers seeking medical attention. After the recall was announced, ZLINE received 131 reports that the repair was not completed successfully and that the ranges were still emitting dangerous levels of carbon monoxide.', 'Fatal', 1, 0, 'These ranges were recalled in January 2023, and consumers were offered a repair. ZLINE is expanding the remedies available to consumers to also include a replacement range or a refund. All consumers who have an affected range should immediately stop using the oven compartment, even if they have already had their range repaired as part of the prior recall. Consumers who have received a repair are being contacted directly by ZLINE with additional information and about the offer of an inspection, a replacement range or a refund. Consumers who have not yet scheduled a repair as part of the recall should contact ZLINE for information regarding available remedies. Consumers may continue to use the range tops which are unaffected by the issue.', '24028');
INSERT INTO safety_incidents VALUES ('2f756b46b38019efaba8e01bfb7a9b1929810ef8', 'CPSC', '2023-11-16', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Women''s high heeled sandals (Spring Summer 2024 collection, Louisa, Linden and Seigel Heel Sandals)', 'Falls', 'Mechanical Failure', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled shoes and contact Khaite for a full refund. For those who purchased shoes through a Khaite store or Khaite.com, email info@khaite.com for instructions on how to return and to receive free shipping and a full refund. Purchasers from third-party retailers must return the product to the third-party retailer to receive a full refund or store credit.', '24027');
INSERT INTO safety_incidents VALUES ('9a3427853d668df222de7553137ded871ba0ac19', 'CPSC', '2023-11-16', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'LAOION Children''s Cups', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the cups away from children, stop using them and contact LAOION for a full refund. LAOION and Amazon are contacting all known purchasers directly.', '24714');
INSERT INTO safety_incidents VALUES ('54c723b7bbe88211c464b611bc1994f02d8af5eb', 'CPSC', '2023-11-16', 2023, '2023-11', 'USA', 'United States', '', 'Other', '13-Piece Toy Mushroom Peg Sorters', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received five reports of the mushroom tops detaching from the stems. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled toys away from young children and return them to any Target store for a full refund or contact Target to receive a prepaid return label to return the toy set by mail. Target is contacting all known purchasers directly.', '24715');
INSERT INTO safety_incidents VALUES ('c075300ce251b941b487167fe5f25945b44c7a95', 'CPSC', '2023-11-16', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Red Shed® Hammock Swing Chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Tractor Supply has received 13 reports of incidents of the buckle on the strap breaking or its stitching breaking, including three reports of consumers falling to the ground.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Red Shed® Hammock Swing Chairs and contact Tractor Supply for a full refund.', '24026');
INSERT INTO safety_incidents VALUES ('f0c5f05687e706d7d289e9d3f1cb9d28f1376545', 'CPSC', '2023-11-09', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Armada, Atomic, and Salomon ski bindings', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received two reports of incidents of the front binding failing. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ski bindings and return them to any authorized Armada, Atomic Ski, or Salomon dealer for a free inspection and a free replacement of the toe portion of the ski bindings, if included in the recall. Authorized dealers can verify if a binding is included in this recall based on its serial number. The serial number is only visible during disassembly, and the firm asks consumers to allow dealers only to disassemble the bindings. Consumers should not disassemble bindings on their own.', '24021');
INSERT INTO safety_incidents VALUES ('631e8681ea30ca3a74c0cc13ab6240a35fac4ecf', 'CPSC', '2023-11-09', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Children''s Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children, stop using them and contact iMOONZZZ for a full refund. Consumers will be asked to destroy the garments by cutting them in half and disposing of them in accordance with local state recycling laws. Consumers should send the recalling firm a photo of the destroyed garment by email at imoonzzz-recall@cdreame.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. iMOONZZZ is contacting all known purchasers directly.', '24712');
INSERT INTO safety_incidents VALUES ('7a7ea94ea7085121a2f5d8f582f340e29beb1785', 'CPSC', '2023-11-09', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Tow-Behind Field & Brush Mowers', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 14 reports of fires causing damage to the mowers.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mowers and contact DR Power Equipment for a prorated refund or credit toward a new DR Power product. The prorated refund or credit will be determined based on the age of the unit. DR Power is contacting all known purchasers directly.', '24022');
INSERT INTO safety_incidents VALUES ('319f0e79afee3b4adaccde1028cc53364ca73ee4', 'CPSC', '2023-11-09', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'IKEA LETTAN Mirrors', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'IKEA has received 10 incident reports globally in addition to the 55 reported in the previous recall, and one report of the plastic fittings coming loose and the mirror falling off the wall in the U.S. in addition to the one in the previous recall. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled mirrors and contact IKEA to order a free set of replacement wall fittings and instructions. Alternatively, customers can return the mirror to any IKEA store for a full refund. Proof of purchase (receipt) is not required to receive a full refund.', '24024');
INSERT INTO safety_incidents VALUES ('3f8cf605b1357ad1cd3c0107890476b1b1f3ed57', 'CPSC', '2023-11-09', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Magnolia 26 oz. 3-Wick Glass Candles', 'Fire', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 13 reports of excessive flames on the wicks, resulting in the glass container breaking. Four of these incidents resulted in minor property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles and contact Magnolia for a full refund. Consumers who purchased the candles online will be contacted directly. Magnolia Market is directly contacting all known purchasers.', '24710');
INSERT INTO safety_incidents VALUES ('9f48e0da7f048622f114830651cc50ff6f02d3d1', 'CPSC', '2023-11-09', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Model Year 2023 RANGER XP 1000 NorthStar and XP 1000 NorthStar Crew Off-Road Vehicles', 'Fire', 'Flammability / Overheating', 'Skin Irritation', 'Polaris has identified one report of fire and three reports of kinked brake lines. Polaris is not aware of any reports of crashes or injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Polaris or an authorized Polaris dealer to schedule a free inspection, and repair if needed. Polaris has notified consumers to stop riding the vehicles and is contacting registered owners directly.', '24711');
INSERT INTO safety_incidents VALUES ('e34f494540d09eb2ab7f000fc13826567d6580b6', 'CPSC', '2023-11-09', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Model Year 2022 and 2023 Arctic Cat Prowler Pro / Pro Crew and Tracker Off Road 800SX / 800SX Crew Side by Side Recreational Off Highway Vehicles (ROVs)', 'The Vehicle Can Move When On An Incline And "Park" Is Displayed On The Digital Dash. This Can Allow The Vehicle To Roll Away, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'The firm has received 12 reports of vehicles moving while in the park position. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Textron Specialized Vehicles to schedule a free repair. The repair kit will include a new shift cable bracket, shift sensor, and a decal to be placed at the dash display. The new shift sensor will allow the dash to display an "E" for shift error if "park" on the vehicle is not fully engaged. Customers will be directly notified to bring their vehicle to an authorized dealership to have the kit added at no cost. Textron is contacting all known purchasers.', '24709');
INSERT INTO safety_incidents VALUES ('08d2b03a32178731e2eab308765c2ba7375838aa', 'CPSC', '2023-11-09', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Electric Powered E-Z-GO ELiTE Express L6 and EliTE Express S6 PTV and Tracker OX EV vehicles', 'The Vehicle''S Internal Motor Wiring Can Become Damaged Over Time. Under Certain Conditions, This Issue Can Cause The Vehicle To Move Unintentionally. This Movement Poses A Crash Hazard.', 'Electrical Fault', 'Skin Irritation', 'Textron Specialized Vehicles received one report of the vehicles moving unexpectedly. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the E-Z-GO PTV and Tracker OX vehicles and contact their dealership or Textron Specialized Vehicle for a free repair. Textron Specialized Vehicles is contacting all purchasers directly.', '24713');
INSERT INTO safety_incidents VALUES ('79ad70b0c38b46473aff0a2a943ecd6e4896b760', 'CPSC', '2023-11-09', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Style Selections 42-inch-wide Infrared Quartz Electric Fireplaces', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Twin-Star and Lowe''s have received 24 reports of overheating, fire or smoke incidents. These include two reports of property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using and unplug the recalled electric fireplace and contact Twin-Star for a refund of the purchase price. Consumers should complete the online recall registration form at www.twinstarhome.com/recall or call Twin-Star for information on how to take part in this recall.', '24023');
INSERT INTO safety_incidents VALUES ('3625a10c67f3557ad0024b5b4bb9354354404294', 'CPSC', '2023-11-02', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Creativity Street Assorted Craft Buttons', 'The Recalled Children''S Craft Buttons Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled buttons immediately and contact Dixon Ticonderoga to receive a pre-paid label to return the recalled buttons. When the buttons are received, consumers will receive a full refund.', '24019');
INSERT INTO safety_incidents VALUES ('f2a1eaad5d450071bbdfaebcc3667be7158f707d', 'CPSC', '2023-11-02', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Grizzly Industrial and Shop Fox Wood Lathes', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Grizzly Industrial has received four reports of the cutting tool breaking, including one injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled wood lathes and contact Grizzly Industrial for details on how to receive a free repair kit, including shipping. The repair kit consists of an upgraded faceplate, tool rest and tool rest base.', '24016');
INSERT INTO safety_incidents VALUES ('720537a9b135543da241c691de0d62773471c554', 'CPSC', '2023-11-02', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Lochinvar, A.O. Smith and State Industries brand condensing residential boilers', 'Burns', 'Other', 'Poisoning / Ingestion', 'Lochinvar has received nine reports of broken flue collectors. Lochinvar has received no reports of injury.', 'Minor', 1, 0, 'Consumers with the recalled boilers should immediately contact the installer or a qualified technician to schedule a free repair. The repair will consist of installing a steel plate, which will be affixed to the base of the flue collector to act as a reinforcement. Consumers who continue use of the boilers while awaiting repair should have working carbon monoxide alarms outside of sleeping areas and on each floor of the home.', '24018');
INSERT INTO safety_incidents VALUES ('c7a81a580166eb9a16b2c1af9eac5c61059678c1', 'CPSC', '2023-11-02', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Electric bicycles', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received one report of a fall including one minor injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled electric bikes and contact Murf''s store for a free repair. Consumers can perform this repair themselves with the repair video available at https://youtu.be/yomCMeGnVTE. Murf Electric Bikes is contacting all purchasers directly.', '24708');
INSERT INTO safety_incidents VALUES ('a7fb9091269513f282dc36f9172fd4c255f0ccc6', 'CPSC', '2023-11-02', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Infant Bath Seats', 'Drowning', 'Instability / Fall Risk', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled infant bath seats and contact UncleWu Life to receive a pre-paid label to return the infant bath seat. Upon receipt of the returned infant bath seats, consumers will be issued a full refund. UncleWu Life and Amazon are notifying all known purchasers directly.', '24707');
INSERT INTO safety_incidents VALUES ('cbb8041a2b8b51f9cec856150f6e18008ad29ff0', 'CPSC', '2023-11-02', 2023, '2023-11', 'USA', 'United States', '', 'Other', 'Yoocaa baby loungers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled baby loungers and contact Yoocaa Direct for instructions on how to receive a full refund and properly dispose of the product. Yoocaa Direct and Amazon are contacting all known purchasers directly.', '24017');
INSERT INTO safety_incidents VALUES ('9728a8cdc27aeb2119e631121ba3b96a921566ed', 'CPSC', '2023-10-26', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Insignia pressure cookers', 'Burns', 'Explosion', 'Burns', 'Best Buy has received 31 reports of incidents in which the contents were expelled under pressure, including 17 reports of burn injuries, some of which involved reports of second-degree and severe burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled pressure cookers and contact Best Buy for a free replacement of the inner pot and floating locking valve for signaling pressure.', '24013');
INSERT INTO safety_incidents VALUES ('a6987d367fbe22b72ba8e7c801db8c059fdf221a', 'CPSC', '2023-10-26', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Bobcat-branded and Kubota-branded stand-on zero-turn lawnmowers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled lawnmowers and contact Doosan Bobcat North America or Kubota Tractor Corp for a free inspection and repair. The firms are contacting all known purchasers directly.', '24706');
INSERT INTO safety_incidents VALUES ('aa76d740a78ddabb446390fc127a3affd8ef5ff0', 'CPSC', '2023-10-26', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Cosco Jump, Spin & Play Activity Centers', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 141 reports of the straps detaching or breaking including 38 minor injuries involving bumps, bruises and scratches.', 'Minor', 1, 0, 'Consumers should stop using the recalled activity centers immediately and contact Dorel for a replacement. Consumers will be instructed to cut through the straps of the activity centers and send a photo of the cut straps to Dorel to receive a free replacement activity center.', '24014');
INSERT INTO safety_incidents VALUES ('57b406a7515be129a225900dd7d94f47414973dd', 'CPSC', '2023-10-26', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Kawasaki Lawn Mower Engines used in Ariens, Gravely, Husqvarna, John Deere and RedMax brand lawn mowers', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled engines used in lawn and garden equipment and contact Kawasaki Motors Manufacturing Corp. USA for a free repair.', '24705');
INSERT INTO safety_incidents VALUES ('fe1e5add85f6fc4167c5d844a07f6b802845c502', 'CPSC', '2023-10-19', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Biometric Gun Safes', 'Injury', 'Flammability / Overheating', 'Not Specified', 'CPSC is aware of a recent lawsuit alleging a 12-year-old boy died from a firearm obtained from one of these safes. There have been 39 incidents of consumers reporting that their safes have been accessed by unpaired fingerprints.', 'Fatal', 1, 0, 'Consumers should immediately stop using the biometric reader in the recalled gun safes, remove the batteries, and contact Fortress to receive a free replacement safe.', '24011');
INSERT INTO safety_incidents VALUES ('64940994b5ed513b34b7af87fec561be20c150f3', 'CPSC', '2023-10-19', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Model Year 2023 RZR PRO XP and PRO XP 4 and Model Year 2024 RZR XP and XP 4 ROVs', 'The Improperly Routed Brake Line Can Contact The Front Wheels During Vehicle Operation Resulting In Brake Line Damage And Brake Loss, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'The firm received three reports of the brake line being incorrectly installed and experiencing loss of brakes, including one report that a unit hit a large rock. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair. If the routing is incorrect, an authorized Polaris dealer will repair the unit at no cost. Polaris has notified consumers to stop riding the vehicles and is contacting registered owners directly.', '24704');
INSERT INTO safety_incidents VALUES ('ccd2f18f4d43bf324ee00e5bde9df1a02339a48a', 'CPSC', '2023-10-19', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Thomas & Friends Wooden Railway Troublesome Truck & Crates and Thomas & Friends Wooden Railway Troublesome Truck & Paint', 'Choking', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'Thomas & Friends Wooden Railway has received one report of the plastic connector becoming loose and detaching from the product. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the toys and go to www.service.mattel.com and click on "Recalls & Safety Alerts" for instructions on how to receive a pre-paid return label via email from Fisher-Price. Upon receipt of the returned product, consumers will be sent a full refund.', '24010');
INSERT INTO safety_incidents VALUES ('b41daa51819270dd608ddf53bd66da12f3600e8a', 'CPSC', '2023-10-12', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Gevi Household Countertop Nugget Ice Makers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 263 reports of incidents of metal blades breaking off the auger and the broken blades then going into the ice basket. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Countertop Nugget Ice Makers manufactured before June 1, 2022, and contact Far Success Trading Limited to receive a free replacement. The firm will provide instructions to disable your present ice maker, which should then be disposed of. Far Success Trading Limited is notifying all known purchasers directly. Consumers should send a photo of the product label on the back of their present ice maker to the email address or website designated above by Far Success Trading Limited.', '24008');
INSERT INTO safety_incidents VALUES ('4efc68bfa5a4345cd4d07d148ad34d022ac7264e', 'CPSC', '2023-10-12', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Crystal Clear Sodium Hydroxide, 2 lb. bags', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of sight and reach of children and contact Family Health Products to receive free replacement child resistant packaging and a new label. All known purchasers are being contacted directly by the firm and Amazon.', '24703');
INSERT INTO safety_incidents VALUES ('9f0e295f3029cf4260b1074e1a6686e5ebf2ec3b', 'CPSC', '2023-10-12', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Sleepyhead Loveys and Bandana Bibs', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The company received two reports of care instruction labels becoming detached from the recalled Lovey. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled Sleepyhead Loveys and Bandana Bib away from children and remove the care instruction label to eliminate the hazard or, if consumers do not wish to remove the label, they can return the products using pre-paid shipping from the company for a full refund.', '24007');
INSERT INTO safety_incidents VALUES ('98fca24466d69f81dc4e45bd7439cacb7a817a44', 'CPSC', '2023-10-12', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'The FORT Children''s Play Tents', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'There have been 17 reports of loose or broken magnets associated with The FORT children''s play tents, resulting in laceration injuries to two adults and a pinched finger to one child.', 'Moderate', 1, 0, 'CPSC urges consumers to dispose of recalled children''s play tents and NOT to resell or donate them. It is a violation of federal law to sell or distribute recalled products. The firm is no longer in business, so there is no remedy for consumers.', '24006');
INSERT INTO safety_incidents VALUES ('8a4a580bde81e0b559bc8b4f0478ac9dc82f8890', 'CPSC', '2023-10-12', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'YourHealthToolkit 5-pound children''s weighted blankets', 'A Young Child Can Become Entrapped By Unzipping And Entering The Blanket, Posing A Risk Of Death By Asphyxiation.', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the children''s weighted blankets and contact Amazon to receive a full refund. YourHealthToolkit is contacting all purchasers directly via Amazon with instructions on how to disable all product functionality or return the product.', '24702');
INSERT INTO safety_incidents VALUES ('4e43d713878c05d6d9297bcc381ed2502ea175fa', 'CPSC', '2023-10-05', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Slime Licker Sour Rolling Liquid Candy', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received two reports of the rolling applicator ball detaching from the container. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Slime Licker Sour Rolling Liquid Candy, take it away from children and contact Candy Dynamics for a full refund of product that is not empty of liquid candy. Consumers should contact Candy Dynamics to receive free shipping to return their non-empty product.', '24001');
INSERT INTO safety_incidents VALUES ('332e92452ad4738ecff861feadfd034126e86d47', 'CPSC', '2023-10-05', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Rene Rofe Girl Children''s Blanket Sleepers and Hooded Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled blanket sleepers and robes away from children, stop using them and contact International Intimates for a full refund. Consumers should destroy the garments by cutting them in half and send International Intimates a photo of the destroyed recalled product by email at recall@renerofe.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '24004');
INSERT INTO safety_incidents VALUES ('0a1fc8f4012ed5a5623ea362478c5afb24ddd09c', 'CPSC', '2023-10-05', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Cocco Candy Rolling Candy', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'CPSC has received one report of a 7-year-old girl who choked and died after the candy''s rolling ball dislodged and became trapped in her throat in New York in April 2023.', 'Fatal', 1, 0, 'Consumers should stop using the recalled rolling candy, take it away from children and contact the firm to receive a refund.', '24002');
INSERT INTO safety_incidents VALUES ('202777e47eea2bbea6e8ae586b4e4ea25753a062', 'CPSC', '2023-10-05', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Capri Blue Pet Sprays and Shampoos', 'Environmental', 'Microbiological Contamination', 'Eye Injury', 'The company is aware of reported infections with eleven dogs and is investigating these reports to see if there is any connection to the recalled products.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled products purchased from June 2023 through August 2023 and should visit www.CBPetCareRecall.com and complete the refund request form or call the firm toll-free. Consumers should take a picture of the product with their initials and date written in marker and email it to CBPetCareRecall@curiobrands.com and dispose of the product in its container with household trash. Do not empty the product prior to disposal.', '24701');
INSERT INTO safety_incidents VALUES ('3d80d3b23c7d1d409f149aa3746e5783cf2ccbef', 'CPSC', '2023-10-05', 2023, '2023-10', 'USA', 'United States', '', 'Other', 'Russound MCA-88 Multizone Controller Amplifiers', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 16 reports of smoking, charring and burning. The damage has been contained to the unit only. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Russound MCA-88 Multizone Controller Amplifiers and contact Russound to arrange for a free replacement unit to be installed at no cost by a certified professional installer.', '24003');
INSERT INTO safety_incidents VALUES ('8d16373dd7d4fe40d25b15847edc15d5f7b0ac8e', 'CPSC', '2023-09-29', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Onewheel Electric Skateboards (all models)', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'Future Motion has received dozens of reports of incidents involving the electric skateboards, including four reported deaths between 2019 and 2021 and injuries such as traumatic brain injury, concussion, paralysis, upper-body fractures, lower-body fractures and ligament damage. The reported deaths resulted from head trauma and, in at least three of those incidents, the rider was not wearing a helmet.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Onewheel electric skateboards. Consumers with the Onewheel GT, Onewheel Pint X, Onewheel Pint, or Onewheel+ XR electric skateboards should download or update the Onewheel app, and use the app to update the firmware on their board to include Haptic Buzz alert functionality. Haptic Buzz is a tactile and audible warning system that provides the rider with a buzzing sensation and sound when nearing the limits of the board or when in low battery or error states. The firmware update for the Onewheel GT will be available within one week, with the firmware update for the Pint X, Pint, and XR launching within six weeks.', '23299');
INSERT INTO safety_incidents VALUES ('93ed02f9a13efc7833e7d2a4f26bcc7ecb2b2a83', 'CPSC', '2023-09-28', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Solaray Liposomal Multivitamins', 'The Recalled Dietary Supplements Contain Iron, Which Must Be In Child-Resistant Packaging, As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child-Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled multivitamins in a safe location out of reach and sight of children. Contact Nutraceutical Corporation for instructions on how to dispose of the product and receive a full refund or a product replacement with the proper child-resistant packaging. The replaced product will be identical to the existing product aside from the new lid. Nutraceutical Corporation and Solaray are contacting all known purchasers directly.', '23297');
INSERT INTO safety_incidents VALUES ('3f9c0c51cba72b9c6d0fb0a9d6958c2f52ffbf0a', 'CPSC', '2023-09-28', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Model Year 2023 Polaris RANGER XP 1000 / XP 1000 Crew and RANGER 1000 / 1000 Crew, Model Year 2024 Polaris Pro XD Full-Size Diesel Crew, Model Year 2024 Gravely ATLAS JSV-3400, and Model Year 2024 Bobcat UV34XL Gas', 'Injury', 'Other', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Polaris or an authorized Polaris (Polaris vehicles only), Arien (Gravely vehicles only), or Bobcat (Bobcat vehicles only) dealer to schedule a free inspection or repair, if needed. Polaris has notified consumers to stop riding the vehicles and is contacting registered owners directly to provide more details about the repair.', '23796');
INSERT INTO safety_incidents VALUES ('2c974531c3abee0c95005186727a1dfd51ff3c48', 'CPSC', '2023-09-28', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Zevo Fly, Gnat and Fruit Fly Flying Insect Killer3 Value Packs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled insect spray and contact Procter & Gamble for a full refund, by filling out a form online at www.zevoinsect.com/recall. Consumers must provide a photo of the bottom of the canister with the lot number visible or a sales receipt. After requesting a refund, consumers should dispose of the product by placing it in the household trash. Do not empty the product prior to disposal.', '23296');
INSERT INTO safety_incidents VALUES ('ea80855589e52c1ce4bd3226ca4bc8777df636a1', 'CPSC', '2023-09-28', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Rust-Oleum Professional Fluorescent Pink Inverted Marking Spray Paint cans', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received five reports of the spray valve assembly and plastic cap detaching with force, causing paint to splatter. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled spray paint cans, take a photo of the product and the date code on the bottom of the can, wrap the product in a plastic bag, and place it out of reach of children. Consumers should contact Rust-Oleum for a full refund at recall@rustoleum.com. Consumers will be asked to provide the photos of the product and the date code on the bottom of the can, and name and mailing address to receive the refund. Consumers should dispose of the recalled product in accordance with local requirements.', '23298');
INSERT INTO safety_incidents VALUES ('293ef9af4ad34dd30010eeeb66d8d8f729ed4d01', 'CPSC', '2023-09-28', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Secura Air Fryers', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received nine reports of the air fryers catching fire, burning and smoking. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled air fryers and contact Secura for an Amazon gift card in the amount of $45 or a free replacement at consumer''s choice with Secura products as listed on Secura''s webpage at https://www.thesecura.com/recall/. To receive the gift card or replacement product consumers must provide their contact information and submit photos of the recalled unit with the power cord cut off and include information of the product''s date code located at the bottom of the product. No receipt is needed to receive a replacement. Secura is contacting all known purchasers.', '23794');
INSERT INTO safety_incidents VALUES ('5f00a3630ac2de75a92cb6286a70d76a7eb521e9', 'CPSC', '2023-09-28', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Trek Allant+ 7 bicycles with Tektro brakes', 'The Rear Brake Hose Can Kink And Break When Turning The Handlebars, Causing The Rider To Lose Control Of The Bike, Posing A Crash Hazard.', 'Other', 'Fracture / Blunt Trauma', 'The firm has received 58 reports of riders losing control of the recalled bikes, including two minor injuries involving scrapes and bruises.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Trek Allant+ 7 bicycles and contact their local authorized Trek dealer for a free repair.', '23295');
INSERT INTO safety_incidents VALUES ('d8366cf249f47ab20d914a2ed1a0ee795942f6da', 'CPSC', '2023-09-21', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'DR Power Chipper Shredders', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 79 reports of parts coming loose inside the housing of the chipper shredder or pieces of metal ejecting, including two reports of injuries. The firm has received three reports of hoppers unexpectedly detaching from the chipper shredder, including one minor abrasion injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chipper shredders and contact DR Power Equipment to receive a full refund or a free repair including shipping.', '23291');
INSERT INTO safety_incidents VALUES ('e24aa16be65cb4408dafe309d156733f86cbd8bc', 'CPSC', '2023-09-21', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Novaform ComfortGrande 14-inch and Novaform DreamAway 8-inch Mattresses', 'The Mattresses Could Have Been Exposed To Water During The Manufacturing Process Allowing Mold To Develop And Posing A Health Risk To Individuals With Compromised Immune Systems, Damaged Lungs Or An Allergy To Mold.', 'Allergen', 'Allergic Reaction', 'The firm has received 541 reports of mold on the mattresses. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should contact FXI to receive a full refund or a free replacement mattress including free delivery of the new mattress and pick up and disposal of the recalled mattress. Costco is contacting all known purchasers directly.', '23793');
INSERT INTO safety_incidents VALUES ('28654350531c525b836a1455942caf2bca26c847', 'CPSC', '2023-09-21', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Men''s clasp beaded bracelets', 'The Clasp On The Beaded Bracelet Contains Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled men''s clasp beaded bracelet and contact H&M to return the product in a prepaid mailer for a full refund.', '23293');
INSERT INTO safety_incidents VALUES ('f5d3b6b501224acec186ff7d83e84c0683822ef1', 'CPSC', '2023-09-21', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'HONEY JOY Infant Swings', 'The Swing Violates The Safe Sleep For Babies Act Because The Product Was Marketed For Infant Sleep And Has An Incline Angle Greater Than 10 Degrees. Infant Fatalities Have Occurred In Inclined Sleepers, After The Infants Rolled From Their Back To Their Stomach Or Side While Unrestrained, Or Under Other Circumstances. The Swing Also Violates The Safety Standard For Infant Swings.', 'Other', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled infant swing and contact HONEY JOY for instructions on how to receive a full refund and properly dispose of the product. HONEY JOY and Amazon are contacting all known purchasers.', '23290');
INSERT INTO safety_incidents VALUES ('a546d6c59549fd3ea78bf9ba3ac674a21dfcb639', 'CPSC', '2023-09-21', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Rainbow Road Series Board Books', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Make Believe Ideas has received two reports of the plastic rings detaching in the United States and one in Australia. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled books and contact Make Believe Ideas to receive a refund in the form of a gift card by registering online at www.recallrtr.com/rr. Following registration, consumers will be provided instructions on how to dispose of their book(s) and asked to confirm that they have disposed of the books.', '23292');
INSERT INTO safety_incidents VALUES ('9f1d479af03f9506a7da8d89c64570ab60478149', 'CPSC', '2023-09-21', 2023, '2023-09', 'USA', 'United States', '', 'Other', '11-Speed Bonded Hollowtech II Road Cranksets', 'The Recalled Bonded Crank Parts Can Separate And Break, Posing A Crash Hazard To Consumers.', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 4,519 incidents of cranksets separating, and six reported injuries, including bone fractures, joint displacement and lacerations.', 'Moderate', 1, 0, 'Consumers should immediately stop using the cranksets manufactured before July 1, 2019, and contact an authorized Shimano dealer to schedule a free crankset inspection. Only consumers whose cranksets show signs of bonding separation or delamination during the inspection will be provided a free replacement crankset and installation.', '23294');
INSERT INTO safety_incidents VALUES ('17c66ceecddec7903eca9d4b27072204184d6037', 'CPSC', '2023-09-14', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Honda Lawnmowers and Pressure Washer Engines', 'Injury', 'Other', 'Not Specified', 'Honda has received 2,197 reports of incidents related to camshaft failures, including seven reports of minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled lawnmowers and pressure washers equipped with recalled engines and contact an authorized Honda Power Equipment dealer to schedule an appointment for a free inspection and repair.', '23287');
INSERT INTO safety_incidents VALUES ('b4d62821384952978effd75c1a903269868e7b78', 'CPSC', '2023-09-14', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Insignia and Yardbird fire tables with lava rocks', 'Fire', 'Flammability / Overheating', 'Fracture / Blunt Trauma', 'Best Buy has received six reports of lava rocks splitting or ejecting from the recalled Insignia fire tables with one report of minor property damage. There have been no reports of injuries. Best Buy has received two reports of lava rock splitting or ejecting from the recalled 2017 Yardbird fire tables with one report of minor property damage. There have been no reports of injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fire tables and contact Best Buy for a free repair consisting of replacement fill material of fire-safe glass beads. Best Buy is contacting all known purchasers directly.', '23792');
INSERT INTO safety_incidents VALUES ('aa59e22a8c7a32b650447226891982d6d75ff6e1', 'CPSC', '2023-09-14', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Chuckle & Roar Ultimate Water Beads Activity Kits', 'Choking', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'Buffalo Games received one report of a 10-month-old child''s death from swallowing the recalled water beads in July 2023 in Wisconsin. Buffalo Games also received a report that a 9-month-old child was seriously injured in November 2022 in Maine from swallowing the water beads which caused an intestinal obstruction requiring surgery to remove them.', 'Fatal', 1, 0, 'Consumers should immediately stop using and take away the recalled water beads from children. Contact Buffalo Games for a full refund and instructions on how to return the product in a prepaid mailing package supplied by the firm or return the product to any Target store.', '23286');
INSERT INTO safety_incidents VALUES ('e05094f1efa102a9eddac617461f24b0fb011ba0', 'CPSC', '2023-09-14', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Generac Portable Generators', 'Fire', 'Flammability / Overheating', 'Burns', 'Generac has received reports of 27 incidents of the generators overheating and pressurizing or expelling fuel when opened, including three incidents resulting in severe burn injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled generators and contact Generac for a free repair kit.', '23288');
INSERT INTO safety_incidents VALUES ('56deceff73ab1b0427126bb083053d11934e3a64', 'CPSC', '2023-09-14', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'STIHL MSA 300 chain saws', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled STIHL MSA 300 chain saw and bring it to an authorized STIHL servicing dealer for the free replacement of the brake drum and brake band.', '23282');
INSERT INTO safety_incidents VALUES ('598c16c7936daa603b54b58266a76eb853a3916e', 'CPSC', '2023-09-14', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Foldable Bistro Set Chairs', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received seven reports of the wooden frame of the chair breaking or collapsing when a consumer was seated on the chair, including four reports of minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and contact TJX for instructions on how to receive a full refund and dispose of chairs. Consumers can also return the recalled chairs to any HomeGoods, Marshalls, T.J. Maxx, or Homesense store for a full refund.', '23280');
INSERT INTO safety_incidents VALUES ('0f30f1b49015892d1b307324972722937ac1be04', 'CPSC', '2023-09-07', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'ARGO Xplorer ATVs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received two reports of fuel overflow incidents, including one fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ARGO Xplorer ATVs. ARGO is contacting all known purchasers directly with instructions to contact an authorized ARGO ATV dealer for a free inspection and repair of the fuel system. The dealer will perform an inspection of the vent system, re-route and extend the vent hose, and install a fuel neck insert.', '23790');
INSERT INTO safety_incidents VALUES ('03d9cb738613ae0590908beae9aae428268349bd', 'CPSC', '2023-09-07', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Emporia Smart Plugs', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'The firm has received two reports that the plugs were not properly grounded causing the units not to operate. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled smart plugs and contact Emporia to receive a full refund or a free replacement smart plug. Emporia will remotely disable the smart plug and consumers should discard the smart plug. The smart plug must be connected to the internet for remote disabling process to be effective. Consumers unable to connect to the internet to allow the remote disabling process can ship the item back to Emporia at no cost. Once the smart plug is disabled or returned to Emporia, a free replacement smart plug or a full refund will be issued.', '23274');
INSERT INTO safety_incidents VALUES ('d9fa38024cc8e3b086150059b367ca1983b8d8b1', 'CPSC', '2023-09-07', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Liquefied Petroleum Gas Compact Regulators', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled regulators, turn off the propane cylinder valve, and disconnect the regulator. Consumers should contact their RegO distributor or RegO to receive a free replacement regulator. Consumers should discard the recalled regulator.', '23275');
INSERT INTO safety_incidents VALUES ('c5cdcb08bfa92566ff7ee1600915d7b484fb3f54', 'CPSC', '2023-09-07', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Disc brake calipers sold on Lectric e-bicycles', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'The firm has received four reports of loss of braking power including two injuries that involved cuts, scrapes and a broken bone.', 'Moderate', 1, 0, 'Consumers should immediately stop using Lectric e-bikes with the recalled disc brake calipers and contact the firm for a free mechanical caliper repair kit. Consumers will receive up to $100 towards the cost to install front and rear mechanical brake calipers. Lectric Ebikes is contacting all purchasers directly.', '23789');
INSERT INTO safety_incidents VALUES ('3124ed186cf529d1e140642a6793729956f8658f', 'CPSC', '2023-09-07', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'Pirelli P ZERO Race TLR Bicycle Tires', 'Falls', 'Chemical / Toxic Substance', 'Fall Injury', 'Pirelli has received one report of rapid air loss, resulting in a minor injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled tires and contact Pirelli to receive a free replacement product or a full refund.', '23276');
INSERT INTO safety_incidents VALUES ('085d7c6f392129e9c39dd0bbdba039bcc6b06af7', 'CPSC', '2023-09-07', 2023, '2023-09', 'USA', 'United States', '', 'Other', 'ADC brand 30 lb. capacity stacked commercial clothes dryers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received two reports of fuel overflow incidents, including one fire. No injuries have been reported.', 'Minor', 1, 0, 'Distributors, owners or laundry operators should immediately stop using the recalled models and contact Whirlpool for a free repair. Whirlpool is contacting known purchasers directly.', '23791');
INSERT INTO safety_incidents VALUES ('c07d872d96f1297cb8e9a5811f46c8e3b0590a1f', 'CPSC', '2023-08-31', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Apollo Phantom Electric Scooters', 'Injury', 'Mechanical Failure', 'Laceration / Cut', 'The firm has received seven reports of the bolt breaking resulting in the stem detaching or loosening, including three injuries of bruising, cuts and abrasions.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled scooters and contact Apollo for a free replacement bolt to repair the scooter. The firm will send instructions with a video link demonstrating how consumers can install the new bolt on their scooter at home. Apollo will also make its servicing and partner locations available to any customers to have the bolt replaced or tightened free of charge. Apollo is contacting all known purchasers directly.', '23270');
INSERT INTO safety_incidents VALUES ('77831481b28f11e316f9d40df030fdb40883a966', 'CPSC', '2023-08-31', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Ski-Doo and Lynx Snowmobiles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received six reports of snowmobile fuel leaks. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the snowmobiles and contact BRP to schedule a free inspection and repair by replacing the fuel return hose. BRP is contacting all purchasers directly.', '23786');
INSERT INTO safety_incidents VALUES ('018b7fa4ffc33644e9f17b1dd62f16ff5e517dc0', 'CPSC', '2023-08-31', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'DIYChemicals: Potassium Hydroxide/KOH Flakes and Sodium Hydroxide', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of sight and reach of children. Contact Chemboys to receive free replacement child resistant packaging and a new label. All known purchasers are being contacted directly by the firm.', '23787');
INSERT INTO safety_incidents VALUES ('986422059c2a3256fd149f0347ad87fc97b03dfb', 'CPSC', '2023-08-31', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Frigidaire Stainless-Steel 30-inch 4 Burner and 36-inch 5 Burner Gas Cooktops', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Electrolux has received 63 reports of the control knobs cracking or breaking, including one minor injury from a gas leak and one report of fire.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cooktops, check for plastic control knobs with a black shaft and contact Electrolux Group for a free set of replacement knobs. Consumers can continue to use knobs with a chrome-colored shaft. The firm is contacting known purchasers directly.', '23269');
INSERT INTO safety_incidents VALUES ('8816d03cd17d0348288ccfdbf6468a4bf4624714', 'CPSC', '2023-08-31', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Polaris Snowmobiles, Model Year 2022-2023 MATRYX PRO RMK and MATRYX RMK KHAOS', 'Injury', 'Sharp Edges / Points', 'Fracture / Blunt Trauma', 'The firm has received four reports of puncture wounds caused by impact with the handlebar hooks.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact Polaris or an authorized Polaris dealer to schedule a free repair. Polaris is offering consumers free replacement handlebar hooks that can be self-installed or installed by an authorized Polaris dealer. Polaris is notifying all dealers and registered owners directly.', '23788');
INSERT INTO safety_incidents VALUES ('1bafdea7bd2ea2279af07a90dd264ae3ea2dad62', 'CPSC', '2023-08-31', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Glass Doorknobs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received five reports of the recalled doorknobs breaking and causing laceration injuries requiring stitches.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled doorknobs and contact Prime-Line for instructions on how to receive a full refund.', '23271');
INSERT INTO safety_incidents VALUES ('cd984ccca670da34b157678e938b615fc3056a3d', 'CPSC', '2023-08-31', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Boon Flair & Flair Elite highchairs', 'Falls', 'Mechanical Failure', 'Fall Injury', 'TOMY has received 34 reports of the chair separating from the base, including 24 falls resulting in 11 injuries such as bruising or scratches.', 'Moderate', 1, 0, 'Consumers should stop using the recalled highchairs immediately and contact TOMY for a free repair kit. Consumers will receive a set of bolts and split and flat washers to repair the recalled highchair.', '23272');
INSERT INTO safety_incidents VALUES ('628758273ad7504e7bba58be0ab516790e5dba4c', 'CPSC', '2023-08-24', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Aiper Elite Pro GS100 cordless robotic pool vacuum cleaners', 'Fire', 'Electrical Fault', 'Burns', 'The firm has received 17 reports of the recalled pool vacuums overheating including one report of a minor burn to a consumer''s fingertip, which did not require medical treatment. No property damage has been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled pool vacuums and contact Aiper to receive a free replacement of Aiper''s Seagull Pro robotic pool cleaner. Aiper will provide a free return label for consumers to send the product back to Aiper. Within seven days of receiving the recalled Elite Pro, Aiper will ship the replacement product. Aiper is contacting all purchasers directly.', '23784');
INSERT INTO safety_incidents VALUES ('26f2da1c5befd4af743decbe6ab332782a0ea4ad', 'CPSC', '2023-08-24', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Kids bike helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Ecnup for a full refund. To receive a refund, consumers should destroy the helmet by cutting off the straps, email photos of the helmet with the straps cut off to bikebikeliu@hotmail.com to prove destruction, and then dispose of the recalled helmet. Ecnup is contacting all purchasers directly.', '23785');
INSERT INTO safety_incidents VALUES ('d56610040e63dd20fd664a9cab5ca432298794e9', 'CPSC', '2023-08-17', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Ubio Labs power banks', 'Fire', 'Flammability / Overheating', 'Respiratory', 'Costco has received three reports of fire, including one report of fire on a commercial flight resulting in four reports of smoke inhalation and one report of a minor burn injury to passengers.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled power banks and contact Costco for a full refund. Ubio Labs is no longer in operation. Costco has contacted all known purchasers directly.', '23783');
INSERT INTO safety_incidents VALUES ('dbf9ea3b29b4c5a09f26333f8fb7b3a95f0c911b', 'CPSC', '2023-08-17', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Midwest Lubricants Sodium Hydroxide', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of sight and reach of children and contact Midwest Lubricants for a free replacement with child resistant packaging and a new label. Midwest Lubricants and Amazon are contacting all known purchasers directly.', '23782');
INSERT INTO safety_incidents VALUES ('1521ab006292340358474058f8025b37d4e9575c', 'CPSC', '2023-08-17', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Simplay3 Toddler Towers', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The Simplay3 Company has received 16 reports of the toddler tower tipping over while in use, including 10 reports of injuries, 6 of which were head contusions.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Simplay3 Toddler Tower, take it away from children and contact the firm to receive a free set of stabilizing bases to be attached to the toddler tower.', '23265');
INSERT INTO safety_incidents VALUES ('3711a7f8a50f6f618cbe043498bb77deb8b4484a', 'CPSC', '2023-08-17', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Zipadee Kids Convertible House Bed Frames and Montessori Floor Beds', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'At least two children have become entrapped in the bed rails. They include a 21-month-old boy (no injuries sustained) and a 4-year-old girl in February 2023 who sustained minor injuries.', 'Fatal', 1, 0, 'CPSC urges consumers to dispose of the recalled beds and NOT to resell or donate them. It is a violation of federal law to sell or distribute recalled products. The firm has filed for dissolution with the State of Ohio and has represented to CPSC that it is unable to offer a remedy to consumers.', '23263');
INSERT INTO safety_incidents VALUES ('1809a240390fd7a285776293bf3e480c6287ae96', 'CPSC', '2023-08-16', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Dehumidifiers', 'Fire', 'Flammability / Overheating', 'Burns', 'Gree has received reports of at least 23 fires, 688 incidents of overheating, and $168,000 in property damage with the recalled dehumidifiers.', 'Moderate', 1, 0, 'Consumers should immediately stop use, unplug the dehumidifiers, and contact Gree to receive a refund.', '23262');
INSERT INTO safety_incidents VALUES ('dec99c0ee91d032a3ff3f1fa4f8153d69817987f', 'CPSC', '2023-08-10', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Fireworks', 'Fire', 'Explosion', 'Burns', 'The firm has received 72 reports of fireworks prematurely exploding. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fireworks and contact 13131 Imports for a full refund. Information on how to properly dispose of the products, or how to return them to the Red Apple Fireworks store where purchased, or to Red Apple if purchased online is at www.bbinc.co/voluntary-product-safety-recalls.', '23260');
INSERT INTO safety_incidents VALUES ('590d0c0ef7fe070fd658d85863eec17f9310b5de', 'CPSC', '2023-08-10', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Model Year 2021 RZR XP Turbo and RZR Turbo S Recreational Off-Road Vehicles', 'Fire', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 206 reports of clutch failures, including reports of six fires, two injuries, and one vehicle tip-over.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Polaris or an authorized Polaris dealer to schedule a free repair. The dealer will replace the primary (drive) clutch free of charge. Polaris has notified consumers to stop riding the vehicles and is notifying all dealers and registered owners directly to provide more details about the repair.', '23780');
INSERT INTO safety_incidents VALUES ('b9a3d4598b78f82f250d66d31a0f211ee2e87fbe', 'CPSC', '2023-08-10', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Polaris Off-Road Vehicles, Bobcat and Gravely Utility Vehicles, Fuel Pump Kits and Fuel Tank Assemblies', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Polaris has received three reports of fuel leaks. No fires or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Polaris or an authorized Polaris (Polaris vehicles only), Gravely (Gravely vehicles only), or Bobcat (Bobcat vehicles only) dealer to schedule a free inspection and repair. The dealer will replace the fuel pump or fuel tank, depending on the vehicle type, free of charge. Polaris, Gravely, and Bobcat have notified consumers to stop riding the vehicles and are notifying all dealers and registered owners about this recall and free repair.', '23258');
INSERT INTO safety_incidents VALUES ('db1a60b0cef8cef7066f2233f26ed08f92aa8cce', 'CPSC', '2023-08-10', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Room & Board Natural Organic Latex and Latex and Spring Crib Mattresses', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the crib mattresses and contact Room & Board to receive a full refund. Restwell Mattress Co. and Room & Board are contacting all purchasers directly and will arrange for pick up at no charge.', '23781');
INSERT INTO safety_incidents VALUES ('69a4562bafd52a7b392803710e35e535eac5ef59', 'CPSC', '2023-08-10', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Carboys', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 30 reports of incidents of the recalled carboy''s glass breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled carboys and return them to the place of purchase for a full refund.', '23259');
INSERT INTO safety_incidents VALUES ('37d03a43bbb21ad8839c8abc012b1c6f0d0d324a', 'CPSC', '2023-08-10', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Electric and stovetop pressure cookers', 'Burns', 'Explosion', 'Burns', 'Sensio has received 63 reports of incidents, including 61 burn injuries, some of which involved second and third degree burns to the face, torso, arms, and hands.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled pressure cookers and contact Sensio for a refund.', '23256');
INSERT INTO safety_incidents VALUES ('ba949e0924b3bd80b0f24c408c38f0ca97c1d5c1', 'CPSC', '2023-08-10', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Threshold Glass Jar Candles', 'Burns', 'Sharp Edges / Points', 'Laceration / Cut', 'Target received 19 reports of the candle jar breaking or cracking during use, resulting in one minor injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles and return them to any Target store for a full refund, or contact Target to receive a prepaid return label to return the candles by mail.', '23255');
INSERT INTO safety_incidents VALUES ('2b89c9da22ce0dab00c96f3edfd684f783ae6817', 'CPSC', '2023-08-10', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Baby and Toddler Boy Basic Stretch Straight Leg Jeans', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received one report of snaps detaching from the jeans. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled jeans away from children and return the jeans to any The Children''s Place store for a full refund. The Children''s Place is notifying all known purchasers.', '23257');
INSERT INTO safety_incidents VALUES ('90c15f961b3d229fb12d9b4b1ff905cfd34a690e', 'CPSC', '2023-08-03', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Honda Model EU7000is Portable Generators', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled portable generators and contact an authorized Honda Power Equipment dealer to schedule an appointment for a free repair. Honda is contacting all known purchasers directly.', '23251');
INSERT INTO safety_incidents VALUES ('4f6ec6d7d4e728a3a1511ca43031723a9e27226a', 'CPSC', '2023-08-03', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Avena Mini Table Lamps', 'Fire', 'Electrical Fault', 'Not Specified', 'Crate and Barrel has received two reports of arcing or smoking when plugging in the lamp. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Avena Mini Table Lamp and contact Crate & Barrel for instructions on how to receive a full refund. Crate & Barrel is contacting all known purchasers directly.', '23778');
INSERT INTO safety_incidents VALUES ('7d34c3dc2e135bbbe23baaafb14bd93edf82937d', 'CPSC', '2023-08-03', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Amana Packaged Terminal Air Conditioners/Heat Pumps (PTACs) equipped with "DigiAir" modules', 'Fire', 'Flammability / Overheating', 'Burns', 'DCT has received 52 reports of incidents with the "DigiAir" compressor, including 10 that resulted in fires. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should contact Daikin Comfort Technologies Manufacturing, L.P. (DCT) for instructions on disabling the DigiAir compressor in the recalled PTACs and to arrange for the free repair of the unit by a qualified technician. DCT is contacting all known purchasers directly.', '23779');
INSERT INTO safety_incidents VALUES ('517f75fcb2f71a9467507b183f9e49d416571207', 'CPSC', '2023-08-03', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Maggie''s Farm 14 oz Bed Bug & Flea Killer', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received four reports of cans rupturing. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Bed Bug & Flea Killer, take a photo of the recalled can and lot code, wrap the product in a plastic bag or several layers of paper, and dispose of it in the trash. Consumers should use caution to avoid skin and eye contact if the can appears to be leaking. Consumers should submit their photo of the can, their contact information and written confirmation that they will dispose of the recalled can to Maggie''s Farm at info@maggiesfarmproducts.com to receive a full refund.', '23252');
INSERT INTO safety_incidents VALUES ('6de19cb5da5952869f6fbfa45a49b7f157307058', 'CPSC', '2023-08-03', 2023, '2023-08', 'USA', 'United States', '', 'Other', 'Philips Avent Digital Video Baby Monitors', 'Burns', 'Flammability / Overheating', 'Burns', 'Philips has received 23 reports of Philips Avent video baby monitors overheating in Europe, including seven reports of minor injuries. No incidents or injuries have been reported in the United States.', 'Minor', 1, 0, 'Consumers should immediately stop using the Digital Video Baby Monitors and contact Philips Avent for a free replacement.', '23250');
INSERT INTO safety_incidents VALUES ('f5ecbbae3f427c2b8a9c651bf216e1900deb0ab2', 'CPSC', '2023-07-27', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'Timberline Solar Energy Shingles', 'Fire', 'Mechanical Failure', 'Not Specified', 'The firm has received one report of fire and five reports of thermal incidents resulting in property damage, including damage to the roof deck. No injuries have been reported.', 'Minor', 1, 0, 'GAF Energy will replace all jumper modules and check the electrical components of each solar shingle for defects, and repair free of charge. GAF Energy has been remotely shutting off impacted systems until the remediation is complete and consumers will be compensated for monetary losses due to the loss of solar energy generation during that time. GAF Energy is contacting known owners of the energy shingles directly by phone to schedule the repair and replacement of the recalled jumper modules and affected electrical components. If consumers have not been contacted by GAF Energy, they should contact their installers to determine if their solar energy shingles'' components are recalled.', '23777');
INSERT INTO safety_incidents VALUES ('175811de9c8724916865cae4256fecbde64675b8', 'CPSC', '2023-07-27', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'Sky Wheels', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received a total of 15 reports of the Sky Wheel detaching from the rail of the play set including three reported injuries involving lacerations to the scalp.', 'Minor', 1, 0, 'Businesses should contact Soft Play to schedule a free inspection. If needed, a repair will be made. Soft Play has contacted all known businesses/operators directly. Businesses have also been advised to communicate to customers to not use the Sky Wheel until it is inspected and, if necessary, repaired.', '23776');
INSERT INTO safety_incidents VALUES ('9b2524d96439baa1f01fbb91fada6a059fb3aa3d', 'CPSC', '2023-07-27', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'Showrunner II Consoles, with included wireless phone chargers, sold with fitness equipment', 'Fire', 'Electrical Fault', 'Not Specified', 'True Fitness has received one report of a fire. No injuries have been reported.', 'Minor', 1, 0, 'Commercial facilities with these recalled products should immediately turn off and unplug the exercise equipment containing the console and contact True Fitness to receive a free replacement console.', '23249');
INSERT INTO safety_incidents VALUES ('5253e9fd3321c408232e1ff7d3d2007012c36b62', 'CPSC', '2023-07-20', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'Pottery Barn Kids Penny Convertible Cribs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received two reports of the end panels separating from the crib. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cribs and contact Pottery Barn Kids to schedule delivery and installation of new end panels for the crib and removal of the old end panels or a full refund. The firm is contacting all known purchasers.', '23775');
INSERT INTO safety_incidents VALUES ('2295b62f0137e7b490d0797a7458fb7059c5889c', 'CPSC', '2023-07-20', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'Superlight Rocks', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported in the U.S.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Wild Country Superlight Rocks and contact Wild Country to coordinate free shipment for a free replacement. Consumers may choose to have their recalled Superlight Rocks replaced immediately with the Wild Country Rocks 40-RWA or the new Superlight Rocks (available in September 2023).', '23247');
INSERT INTO safety_incidents VALUES ('b5cb0486d9ba9aa28f68f3baa1db33d353535811', 'CPSC', '2023-07-20', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'CUPKIN Double-Walled Stainless Steel Children''s Cups', 'The Stainless-Steel Cups Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the cups away from children and stop using them. Contact Soojimus for a full refund. Soojimus and Amazon are contacting all known purchasers directly.', '23774');
INSERT INTO safety_incidents VALUES ('f06fcea42f7bad27151e80d25da1b00fa487a6db', 'CPSC', '2023-07-13', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'Gas-fired hot water residential boilers', 'The Recalled Residential Boilers Can Be Missing The Flue Inspection Cover Plate, Posing A Risk Of Exposure To Combustion Flue Gasses And A Carbon Monoxide Poisoning Hazard.', 'Flammability / Overheating', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled gas-fired hot water residential boilers and contact ECR International to arrange for a free inspection and repair in the form of a free installation of the inspection cover plate, if missing.', '23243');
INSERT INTO safety_incidents VALUES ('49918c98f045c89ffcd36eb2eb008ec1893f61b5', 'CPSC', '2023-07-13', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'Frigidaire Gas Laundry Centers', 'Fire', 'Flammability / Overheating', 'Respiratory', 'Electrolux Group has received 23 reports of fire and one report of a smoke inhalation injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the dryer of the recalled Laundry Centers and contact Electrolux Group for a free inspection, repair and lint removal service. Electrolux Group is contacting known purchasers directly. Consumers can continue to use the washer which is unaffected by the issue.', '23244');
INSERT INTO safety_incidents VALUES ('01aa347e73aaf48f8d9df98ea69c5b61aaed02ab', 'CPSC', '2023-07-13', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'Yamaha Personal Transportation Vehicles', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Yamaha Personal Transportation Vehicles and contact Yamaha Golf-Car company for a free repair. Yamaha is contacting all registered owners directly.', '23773');
INSERT INTO safety_incidents VALUES ('139d921a1ccd0833caecf0420435270f23e46292', 'CPSC', '2023-07-06', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'Residential 300 Series Snow Blowers', 'Injury', 'Other', 'Not Specified', 'The firm has received 22 reports where the auger pulley bolt loosened and the drive unexpectedly became engaged. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled snow blowers and contact an authorized Husqvarna Professional Products dealer for a free repair. The dealer locator is available at https://locations.husqvarna.com/us/.', '23240');
INSERT INTO safety_incidents VALUES ('10a1c552778dafaaaafbda0e12be27522bef394e', 'CPSC', '2023-07-06', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'VRURC portable chargers', 'Fire', 'Flammability / Overheating', 'Respiratory', 'VRURC has received one report of fire during a commercial flight, which resulted in four flight attendants being transported to the hospital for smoke inhalation.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled portable chargers and contact VRURC for a free replacement product.', '23238');
INSERT INTO safety_incidents VALUES ('4e2d06002e340ff48a679598c75a2676b5225144', 'CPSC', '2023-07-06', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'woom ORIGINAL Bicycles', 'Falls', 'Mechanical Failure', 'Laceration / Cut', 'The firm has received 77 reports of the handlebar stem detaching or loosening, resulting in 19 injuries involving bruising, cuts or abrasions.', 'Moderate', 1, 0, 'Consumers should stop using the recalled bicycles and contact woom Bikes USA for a free repair kit. woom Bikes USA is contacting all known purchasers directly.', '23239');
INSERT INTO safety_incidents VALUES ('8b84c3feabdd903522222cf86b7a2dc83efdc8f7', 'CPSC', '2023-07-06', 2023, '2023-07', 'USA', 'United States', '', 'Other', 'Model Year 2023 Yamaha Golf Car, Personal Transportation Vehicles (PTV) and Umax', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled 2023 Yamaha Golf Car, PTV and Umax and contact Yamaha for a free inspection and repair. Yamaha is contacting known purchasers directly.', '23772');
INSERT INTO safety_incidents VALUES ('ab17af7f02988c9bbeca277530b2fbe9a1cae62a', 'CPSC', '2023-06-29', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Bose Acoustimass, Lifestyle and Companion bass modules (produced before April 2006)', 'Fire', 'Electrical Fault', 'Not Specified', 'The firm has received 21 reports worldwide of the bass modules igniting or melting, including three incidents of fires resulting in property damage to carpeting, an entertainment cabinet and to materials surrounding the bass box. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using and unplug the recalled bass modules and contact Bose to arrange for a free repair of the bass module or a 40% discount on a replacement product.', '23234');
INSERT INTO safety_incidents VALUES ('48624fe1de2b282df87b5818294310fdfdc9acf7', 'CPSC', '2023-06-29', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Canvas Baby Hammock Swings', 'The Inclined Sleeper Is A Banned Hazardous Product Under The Safe Sleep For Babies Act Since The Product Was Marketed For Infant Sleep And Has An Incline Angle Greater Than 10 Degrees. Infant Fatalities Have Occurred In Inclined Sleepers After The Infants Rolled From Their Back To Their Stomach Or Side While Unrestrained, Or Under Other Circumstances.', 'Other', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby hammock swings and contact CaTeam for instructions on how to receive a full refund and properly dispose of the product. CaTeam and Amazon are contacting all known purchasers.', '23237');
INSERT INTO safety_incidents VALUES ('1e9ec926b15fb907351c24dea67bd3caf13cf7ce', 'CPSC', '2023-06-29', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Haven & Key Leather Woven Chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 11 reports of the chairs cracking or breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and contact H-E-B to return the chairs for a full refund. H-E-B is contacting all known purchasers directly.', '23771');
INSERT INTO safety_incidents VALUES ('69edfd58e9727f67387f0f221732ae54bb3404e9', 'CPSC', '2023-06-29', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Wood Metropolitan Bluetooth Record Players with 3-Speed Turntables', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received six reports of the units overheating or catching on fire, including one minor injury and one report of minor property damage.', 'Minor', 1, 0, 'Consumers should immediately unplug and stop using the recalled record players and contact Victrola to receive a free replacement. Consumers should keep the recalled record players until successfully registering for the recall, at which time the firm will provide consumers with disposal instructions.', '23235');
INSERT INTO safety_incidents VALUES ('0cf76208c9966baac81cc1ffec62cf9011f58424', 'CPSC', '2023-06-22', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Boost The Mood Ceramic Mugs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of a mug smoking while microwaving.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ceramic mugs and contact Michael Giordano International to receive a $10 cash refund for the value of the ceramic mug. Consumers will be directed to dispose of their mugs after successfully registering for the recall.', '23228');
INSERT INTO safety_incidents VALUES ('8831883a5d24a3b567fc3f89b449026c09f639de', 'CPSC', '2023-06-22', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Havertys Concord Dual Power Recliner Chairs', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received nine reports of the chair back detaching including two consumers who reported injuries involving the back, neck and hip.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled recliner chairs and contact Havertys for a free repair by a service technician to install a replacement part in the metal power assembly mechanism. Havertys is contacting known purchasers directly.', '23769');
INSERT INTO safety_incidents VALUES ('c0e90f9f311fc1a3bc73924e81677963a6b795b8', 'CPSC', '2023-06-22', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Zooby video baby monitors for cars', 'Fire', 'Mechanical Failure', 'Not Specified', 'The firm has received three reports of the baby monitors catching fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately remove the battery from the plush camera and can continue using the zooby plush camera and monitor plugged in. Contact Infanttech for a free replacement battery. Infanttech is contacting all known purchasers.', '23770');
INSERT INTO safety_incidents VALUES ('421a74ef48ad24c4f22df1376fb7c8bd794f777a', 'CPSC', '2023-06-22', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Ferrous Sulfate (Iron) Enteric-Coated Tablets, 324 mg - 100 Tablet Bottles', 'The Recalled Dietary Supplements Contain Iron Which Must Be In Child-Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child-Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled dietary supplements in a safe location out of reach and sight of children and contact Nationwide Pharmaceutical for information on how to dispose of the product. Consumers can also return the product to the place of purchase to receive a refund of the purchase price.', '23227');
INSERT INTO safety_incidents VALUES ('9243c621cdcd6e4ca798e83efbe2135f15846acb', 'CPSC', '2023-06-22', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Poseidon M28A Dive Computers', 'Injury', 'Mechanical Failure', 'Not Specified', 'The firm has received one report within the U.S. of water intake causing the depth sensor and other electronic components of the dive computer to malfunction. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled dive computers and contact Poseidon Diving Systems at m28a@poseidon.com to return the product via free return shipping and receive a free repair.', '23226');
INSERT INTO safety_incidents VALUES ('d0131e990594375bdc52892a0bd7bdc620c172fd', 'CPSC', '2023-06-22', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Steam Humidifiers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 103 reports of the recalled humidifiers overheating, including 10 incidents resulting in smoke or residential fires, totaling more than $10 million in damage.', 'Moderate', 1, 0, 'Consumers should immediately stop using and shut off the recalled humidifiers and contact Research Products to receive a free electrode wire repair kit and assistance with identifying a qualified contractor to schedule an appointment for a free replacement of their electrode connector wires.', '23231');
INSERT INTO safety_incidents VALUES ('693c24c47238869b3758a93e6eac8e4e5593396b', 'CPSC', '2023-06-22', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Hurtle Multi-Purpose Helmet', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Sound Around to receive a full refund of the purchase price. To receive a refund consumers should destroy the helmet by cutting off the straps, upload photos of the helmet with the straps cut to the recall registration website and then dispose of the recalled helmet. Consumers who received the unit as a free promotion should dispose of the unit so that children cannot use it.', '23230');
INSERT INTO safety_incidents VALUES ('a389f13e8bd5d0683287f5718543f15c1662d9d2', 'CPSC', '2023-06-22', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Robo Alive Junior Baby Shark Sing & Swim Bath Toys (full-size) and Robo Alive Junior Mini Baby Shark Swimming Bath Toys (mini-size)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Zuru is aware of 12 reports of children falling or sitting onto the recalled full-size Baby Shark bath toy, resulting in impalement injuries, lacerations and puncture wounds, including to children''s genital, anorectal and facial areas. Nine of the incidents required stitches or medical attention. There have been no reported incidents or injuries involving the Mini Baby Shark bath toys.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled bath toys and contact Zuru for a full refund of $14 for each full-size bath toy or $6 for each mini-size bath toy, in the form of a prepaid virtual Mastercard. Consumers should disable the tail fin (by cutting it on the full-size bath toy or by bending it on the mini-size bath toy), mark the body of the shark bath toy with the word "recalled" and the unique code provided during registration for the recall, then upload a photo of the product, showing it is disabled and marked, at https://www.recallrtr.com/bathshark. Upon receipt of the photo, Zuru will issue a refund to purchasers.', '23229');
INSERT INTO safety_incidents VALUES ('ec169021533ff3dc39f8913d0927535d35c0a65e', 'CPSC', '2023-06-15', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'SCUBA Diving Buoyancy Compensating Devices OceanPro, Excursion, Hera', 'Drowning', 'Drowning Risk', 'Drowning', 'The firm has received 73 reports of broken weight pocket handles. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled SCUBA Diving Buoyancy Compensating Devices and contact Huish Outdoors to receive free replacement weight pockets.  Pockets are detachable and easily replaceable. Consumers should dispose of the current weight pockets.', '23222');
INSERT INTO safety_incidents VALUES ('53d108ac382715ab1ded6730740e9f43c2d0796b', 'CPSC', '2023-06-15', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Promax hydraulic disc brakes sold on Trek bicycles', 'The Brake Hose Can Detach From The Brake Lever, Posing A Crash Hazard.', 'Mechanical Failure', 'Skin Irritation', 'Trek has received 195 reports of brake hoses detaching from the brake lever in the United States. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the bicycles with the recalled brakes and contact their local authorized Trek dealer for a free inspection and repair. Consumers can check their bike''s serial number at www.trekbikes.com/us/en_US/promax-recall-inquiry/ to determine if their bike is included in this recall.', '23223');
INSERT INTO safety_incidents VALUES ('3a5d2cfcdc85e219f0eb50ffe70bcf2a3e436601', 'CPSC', '2023-06-08', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Armstrong Air and Air Ease single stage gas furnaces', 'A Component Inside The Furnace Was Improperly Assembled, Causing The Furnace To Produce High Levels Of Carbon Monoxide (Co) Under Certain Operating Conditions, Which Poses A Risk Of Co Poisoning To The Consumer.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Contact Allied Air Enterprises to schedule a free in-home repair by an authorized technician who will replace the incorrect component. Allied Air Enterprises is contacting all known distributors directly, who will work with dealers to contact all known consumers who purchased the recalled units. Consumers who continue to use the recalled furnaces while awaiting repair should have working carbon monoxide alarms on every level of the home and outside sleeping areas.', '23218');
INSERT INTO safety_incidents VALUES ('180498bee2be5c68a9464a38925a899461358d41', 'CPSC', '2023-06-08', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Party Time Collection Loveseats, Sofas and Recliners', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The company is aware of six reports of the cupholder with LED lighting overheating, resulting in fire and smoke damage and damaged furniture. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately unplug the loveseats, sofas, and recliners and contact Ashley Furniture Industries for a free repair.', '23215');
INSERT INTO safety_incidents VALUES ('93704afc89013d86a9bf816a2a93c17f910c596b', 'CPSC', '2023-06-08', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Giro Merit Bicycle Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Giro Merit helmets and contact Giro for a free replacement helmet or a full refund.', '23216');
INSERT INTO safety_incidents VALUES ('42ee7d69b8090d9f72fb3b8e3cc3f2ad84b4d361', 'CPSC', '2023-06-08', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Little Cotton Clothes Pajamas and Nightdresses', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled children''s pajamas and nightdresses away from children, stop using them and contact Little Cotton Clothes for instructions on how to dispose of the pajamas for a full refund. Little Cotton Clothes is directly contacting all known purchasers.', '23767');
INSERT INTO safety_incidents VALUES ('e4008836889b1186b264efba9f8a2549eadad88b', 'CPSC', '2023-06-08', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Deux Par Deux Children''s One-Piece and Two-Piece Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled children''s pajamas away from children, stop using them and contact Deux Par Deux for instructions on how to dispose of the pajamas for a full refund. Deux Par Deux is directly contacting all known purchasers.', '23766');
INSERT INTO safety_incidents VALUES ('262dd145461a20ad773f83ca6550391435eeb02d', 'CPSC', '2023-06-08', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'John Deere™ XUV590E, XUV590M and XUV590M S4 Gator™ utility vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled XUV590 Gator utility vehicles immediately and contact an authorized John Deere dealer for a free inspection, and if necessary, free repair. John Deere is contacting all known purchasers directly.', '23768');
INSERT INTO safety_incidents VALUES ('87f1b8ab489569d14f606d3c0f6f99aa03c9f4cb', 'CPSC', '2023-06-08', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Arctic Cat 8000 Series Snowmobiles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received nine reports of fuel leaks and one reported fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact Textron Specialized Vehicles to arrange for a free inspection and free repair. Textron Specialized Vehicles is contacting all purchasers directly.', '23765');
INSERT INTO safety_incidents VALUES ('cc77fd8f92b670c70d5309a968d918b8d268ca06', 'CPSC', '2023-06-08', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Haining Degao Benches', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 21 reports of the legs breaking or detaching from the bench when a consumer was seated on a bench at a store, including 17 reports of injuries involving bruises, scratches and back strains.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled benches and contact TJX for instructions on how to participate in the recall and dispose of the benches from home to receive a full refund. Consumers can also return the recalled benches to any Marshalls or T.J. Maxx store for a full refund.', '23217');
INSERT INTO safety_incidents VALUES ('28a596a47c50df323c69b935ea39e3fb8115caed', 'CPSC', '2023-06-08', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Narskido Infant Bath Seats', 'Drowning', 'Instability / Fall Risk', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled infant bath seats and contact TopGlore through the Amazon platform for a full refund of the purchase price. Consumers will be asked to dispose of the recalled product. TopGlore and Amazon are notifying all known purchasers directly through the Amazon platform.', '23763');
INSERT INTO safety_incidents VALUES ('457fc3a004f299ff15f602ccec24d35818f7d4a6', 'CPSC', '2023-06-08', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Kate and Laurel Astora and Valenti Mirrors', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received seven reports of the mirror detaching from the frame and breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled mirrors and contact Uniek for instructions on how to remove and dispose of the mirror for a full refund. Consumers will be asked to email or text a photo of the properly disposed mirror. Uniek, through its retail partners, is contacting all known purchasers directly.', '23764');
INSERT INTO safety_incidents VALUES ('55bc04b087657bdddbc6accaff20b6fc87090e9d', 'CPSC', '2023-06-01', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'EGO Power+ Model HT2410 Cordless Brushless Hedge Trimmers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 34 reports in the U.S. of the trimmers starting unexpectedly, including eight reports of lacerations requiring stitches.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled hedge trimmers and contact Chervon for a free repair of the rear trigger switch.', '23212');
INSERT INTO safety_incidents VALUES ('b37dc2ec06156f1fa4086ca5a248a771da24c5b2', 'CPSC', '2023-06-01', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'PowerXL Self-Cleaning Juicers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Empower Brands is aware of 261 reports of incidents including 47 reports of injuries, some of which involved severe cuts requiring emergency treatment, stitches, bruises and ingestion of small particles requiring medical attention.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled PowerXL Self-Cleaning Juicers and contact Empower Brands to receive a full refund.', '23213');
INSERT INTO safety_incidents VALUES ('d904fdd7d71763e9e8cd59d231d67cc2a8a51f3f', 'CPSC', '2023-06-01', 2023, '2023-06', 'USA', 'United States', '', 'Other', 'Jetson Nova and Star 3-Wheel Kick Scooters', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received 12 reports of the wheels loosening or falling off the scooters, including one report of an injury involving scratches/bruises to a child''s face.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Jetson Nova and Star 3-Wheel Kick Scooters and contact Jetson for a free repair kit. The kit includes two screws, two bolts and an Allen key, along with repair instructions and a QR code link to an installation video. Consumers will not need additional tools to install the repair kit.', '23211');
INSERT INTO safety_incidents VALUES ('548b034620df254f5eca01805bf0e418ccaac9e1', 'CPSC', '2023-05-25', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'The Preschool Electric Bicycles', 'The Paint On The Recalled Electric Bikes Contains Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Lead Poisoning Hazard. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Preschool electric bicycle and contact Bunch Bikes for free replacement wood panels. Bunch Bikes is contacting all purchasers directly.', '23761');
INSERT INTO safety_incidents VALUES ('ded753349e764298eef0cdaab1596c9428b17e28', 'CPSC', '2023-05-25', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Janod Sweet Cocoon Activity Tables', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled activity tables and contact Juratoys for a free repair kit.', '23210');
INSERT INTO safety_incidents VALUES ('90a22195a752801828f5afd0a3ca84c5e2925dca', 'CPSC', '2023-05-25', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'The Good and the Beautiful Math 1 and Math 3 Boxes with metallic whiteboards', 'The Paint On The Recalled Electric Bikes Contains Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Lead Poisoning Hazard. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Sharp Edges / Points', 'Laceration / Cut', 'There have been four reports of the boxes detaching each resulting in minor lacerations.', 'Minor', 1, 0, 'Consumers should immediately take the recalled whiteboards away from children, discard them and contact The Good and the Beautiful to receive a free non-metallic replacement. Consumers should visit www.goodandbeautiful.com/math-1-quality-reporting/ for the Math 1 Box and www.goodandbeautiful.com/math-3-quality-reporting/ for the Math 3 Box to complete a form with their contact information. The Good and the Beautiful is contacting known consumers directly.', '23762');
INSERT INTO safety_incidents VALUES ('439a873e094b2cf7663e06eac69253deddd6aea5', 'CPSC', '2023-05-18', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'PhysiciansCare Allergy, Allergy Plus and Cold and Cough', 'The Recalled Products Contain Diphenhydramine Hydrochloride And Acetaminophen Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach of children and contact Acme United for information on how to dispose of the products and receive a refund of Acme United''s average selling price of between $5 and $19.', '23203');
INSERT INTO safety_incidents VALUES ('c5fff5e2020f3912ab95cf288207185e401b5ed8', 'CPSC', '2023-05-18', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Cole & Mason 505WEG Pepper Mills Item Number H50501PWE', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received three reports of incidents of metal shards coming off the pepper mill into consumers'' food. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pepper mills and return them to Wegmans for a full refund. Wegmans is directly contacting consumers who purchased the recalled pepper mills.', '23758');
INSERT INTO safety_incidents VALUES ('08cc7bd247770ef72cedf323be4c590ffa02fc88', 'CPSC', '2023-05-18', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'BQQZHZ Combination Smoke and Carbon Monoxide Detectors', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The detectors can fail to alert consumers to the presence of hazardous smoke and fire.', 'Not Reported', 0, 0, 'Consumers should stop using and dispose of these products immediately and install working smoke detectors.', '23207');
INSERT INTO safety_incidents VALUES ('27096670d5ae6566482b73b356d4380d5bece930', 'CPSC', '2023-05-18', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Ventura Adult Bike Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Cycle Force for a full refund. To receive a refund, consumers should destroy the helmet by cutting off the straps, complete the form at www.bikeaidonline.com/recall-ventura-sport-helmet, email photos of the helmet with the straps cut off to bikeaid@cyclefg.com to prove destruction, and then dispose of the recalled helmet. Cycle Force is contacting all purchasers directly.', '23759');
INSERT INTO safety_incidents VALUES ('54bb48f76bdd52c4a2ffce8da38f5b067bba7c40', 'CPSC', '2023-05-18', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'PowerXL Stuffed Wafflizer waffle makers', 'Burns', 'Other', 'Burns', 'The firm has received 44 reports of incidents including 34 burn injuries with three requiring medical attention.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled PowerXL Model ESWM02 (five inch) and Model ESWM03 (seven inch) Stuffed Wafflizer waffle makers and contact Empower Brands to receive a free latch adaptor part and written instructions to complete the repair.', '23205');
INSERT INTO safety_incidents VALUES ('dcecb48a17d0aa8e5a800f9517241795c3f5ac5a', 'CPSC', '2023-05-18', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Personal Chiller Mini Fridge Gamer Beverage Refrigerators with LED Lights', 'Burns', 'Flammability / Overheating', 'Burns', 'The firm has received six reports of the power cord overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled refrigerator and contact Kell Electronic to receive a full refund or a replacement cord. Once unplugged, the firm is asking consumers to use scissors to cut the cord, take a photo of the cut cord then throw the cord away. Consumers will need to submit the photo to the firm to receive the full refund or replacement cord.', '23206');
INSERT INTO safety_incidents VALUES ('241bccdf9e302970270a4cfbefa7f2709faa0fb7', 'CPSC', '2023-05-18', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Model Year 2021-2023 RZR Pro XP 4 and Model Year 2022-2023 RZR Turbo R 4 vehicles Recreational Off-Road Vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received five reports of fuel leaks, including one report of fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Polaris or an authorized Polaris dealer to schedule a free repair. The dealer will replace the fuel pump assembly free of charge. Polaris has notified consumers to stop riding the vehicles and is notifying all dealers and registered owners directly to provide more details about the repair.', '23760');
INSERT INTO safety_incidents VALUES ('236db158ed06687453f9b9a44b0bfddc2b8a8ebe', 'CPSC', '2023-05-18', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Shimano PRO Vibe Alloy stems for road bicycles', 'Injury', 'Other', 'Skin Irritation', 'The firm has received two reports of the recalled bicycle stems cracking in the U.S. No injuries have been reported in the United States.', 'Minor', 1, 0, 'Consumers should immediately stop using bicycles with PRO Vibe alloy handlebar stems and take them to the place where purchased or a Shimano authorized retailer to determine if the stem on their bike is included in the recall and for a free replacement stem and free installation.', '23757');
INSERT INTO safety_incidents VALUES ('421bf7117922cf10b8a5acc284989eca2eb2a388', 'CPSC', '2023-05-18', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Threshold Glass Jar Candles', 'Burns', 'Sharp Edges / Points', 'Laceration / Cut', 'Target received 137 reports of the candle jar breaking or cracking during use. Six injuries were reported, including lacerations and severe burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled candles and return them to any Target store for a full refund or contact Target to receive a prepaid return label to return the candles by mail.', '23204');
INSERT INTO safety_incidents VALUES ('d1265d9d95ec2a1934446578a6413552d1b34005', 'CPSC', '2023-05-11', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Advent 4F, Advent 4FL, Advent 6 and Advent 6L golf carts', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received two reports of injuries from falls involving lacerations, scratches and bruising.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled golf carts and contact the dealer where it was purchased to arrange for a free inspection and repair. Advanced EV is contacting all known purchasers directly.', '23756');
INSERT INTO safety_incidents VALUES ('9963c1bddb0eaad851ad464c06c3f24ae3910f59', 'CPSC', '2023-05-11', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Continental Cabinets and Hampton Bay Kitchen Wall Cabinets', 'The Cabinets Can Detach From The Wall, Posing An Impact Hazard.', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'There have been 90 reports of incidents involving 111 cabinets partially separating or detaching from the wall. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cabinets and contact American Woodmark for a free repair kit which includes two brackets with aesthetic covers and screws. Assistance with the repair kit installation will be provided upon request.', '23199');
INSERT INTO safety_incidents VALUES ('9ffb7409c34852c305bcbf750747ebecbcf2e2b2', 'CPSC', '2023-05-11', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Ski-Doo snowmobiles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'BRP has received 14 reports of fuel leaks which resulted in four fires.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact a Ski-Doo dealer to determine if their snowmobile is included in this recall and to schedule a free repair. BRP is contacting all known purchasers directly to coordinate the free repair with dealers to inspect and if necessary install a new E-TEC fuel injector hose retainer screw.', '23755');
INSERT INTO safety_incidents VALUES ('311ade79973f9c01f6086b1eb58253a90b04e283', 'CPSC', '2023-05-11', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Peloton Bikes Model PL01', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Peloton has received 35 reports of the seat post breaking and detaching from the bike during use, including 13 reports of injuries including a fractured wrist, lacerations and bruises due to falling from the bike.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled exercise bikes and contact Peloton for a free repair. Peloton is offering consumers a free seat post that can be self-installed.', '23201');
INSERT INTO safety_incidents VALUES ('9f8898f5806d0241f63415cf149cb6aac7ffbd83', 'CPSC', '2023-05-11', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Blue Ridge utility knives', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received two reports of the blade protruding in the original packaging, both resulting in laceration injuries.', 'Moderate', 1, 0, 'Consumers should immediately and carefully inspect the packaging containing the Blue Ridge Utility Knife to determine whether the blade tip is protruding through the package. Carefully remove the knife from the packaging, avoiding the blade tip, and discard the packaging. To apply the repair, secure the knife by retracting and locking the knife in the closed position. Once the knife is removed from the packaging, the knife can be used in typical fashion.', '23200');
INSERT INTO safety_incidents VALUES ('2ea5581f6f11770936c417bc34c3e7123be8159c', 'CPSC', '2023-05-11', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Gold Metal and Ribbed Glass Cocktail Shakers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received three reports of the shaker cracking and breaking, involving two incidents of lacerations, which did not require medical attention.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled cocktail shakers and contact World Market for a full refund. Consumers can return the product to a local World Market store or submit a photo of the recalled cocktail shakers and state that the product will be properly disposed of and no longer be used. No receipt is needed to receive a refund.', '23198');
INSERT INTO safety_incidents VALUES ('2dff8a2ba879decb3d00dd400206974572131f71', 'CPSC', '2023-05-04', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Sahara Folding Food Dehydrators', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 15 reports of the dehydrator overheating. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Sahara Folding Food Dehydrators, remove the polyester air filter and contact Berkshire Innovations for a free repair. The repair is replacing the air filter with a non-flammable metal screen air filter. The air filter is designed for easy toolless access by consumers.', '23753');
INSERT INTO safety_incidents VALUES ('deed03de50eab0f1fe2459a3a39257d9e9ae9cb8', 'CPSC', '2023-05-04', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'L.O.L. Surprise! Trick or Treat subscription boxes sold with Metal Doll Pins', 'The Paint On The Children''S Metal Doll Pins Contains Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Lead Poisoning Hazard. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled metal doll pins away from children, stop using them and contact CultureFly for a $10 refund. Consumers will receive an e-mail with instructions to return or dispose of the recalled metal doll pins in accordance with local state laws. Consumers will be contacted directly by CultureFly.', '23752');
INSERT INTO safety_incidents VALUES ('aab1ab07e4a357efbd7312bdb42f0457be95f0cf', 'CPSC', '2023-05-04', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Severe Weather Doorglass Inserts', 'Injury', 'Other', 'Not Specified', 'None reported', 'Minor', 1, 0, 'Consumers need to be aware the recalled severe weather doorglass insert may not function as expected, and should immediately contact ODL to arrange for a free repair by a qualified technician. The doorglass insert will be repaired or replaced free of charge.', '23196');
INSERT INTO safety_incidents VALUES ('81f5d4895565046084a50a07428f3e94b87d3979', 'CPSC', '2023-05-04', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Model Year 2022-2023 MATRYX RMK KHAOS and PRO Snowmobiles', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 164 reports of the brake system overheating, including 22 reports of fires.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact Polaris or an authorized Polaris dealer to schedule a free repair. The dealer will conduct a check of the snowmobile braking system and install a software update. Polaris is notifying all dealers and registered owners directly.', '23751');
INSERT INTO safety_incidents VALUES ('582677be841fa216ae6252828992260b106e61e5', 'CPSC', '2023-05-04', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Ricky Powersports Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Other', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact Ricky Powersports for a free repair from an authorized repair shop.', '23195');
INSERT INTO safety_incidents VALUES ('f368a1e42978d89fbf4a355050ce26efcd3b8380', 'CPSC', '2023-05-04', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Children''s white robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using them and contact The Company Store for a full refund. Consumers should destroy the robes by cutting them both vertically and horizontally and dispose of them in accordance with local state recycling laws. The Company Store is contacting all known purchasers directly.', '23754');
INSERT INTO safety_incidents VALUES ('4850388765307fa469a30c0e07b3043c878da14c', 'CPSC', '2023-05-04', 2023, '2023-05', 'USA', 'United States', '', 'Other', 'Twin Over Twin Bunk Beds', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'Walker Edison Furniture has received reports of 14 incidents of the bunk beds slats breaking, including one report of minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bunk beds and contact Walker Edison Furniture to receive a free repair kit consisting of 12 wooden slats and new instructions. Walker Edison is contacting known purchasers directly.', '23193');
INSERT INTO safety_incidents VALUES ('f05413d1e19f25dc5f8e2f7ce1bd8285d9b56868', 'CPSC', '2023-04-27', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Recon LT Avalanche Transceivers', 'The Recalled Transceivers Can Unexpectedly Enter Search Mode Due To Interference From Other Beacons. If This Occurs, The Device Could Fail To Transmit The Position Of Survivors Of An Avalanche, Resulting In Delayed Search And Rescue Operations, Which Could Result In Severe Bodily Harm Or Death If The Skier Is Buried Under Snow.', 'Other', 'Not Specified', 'The firm has received seven reports of the transceiver mode changing while in use. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled transceivers and perform a free repair which consists of a firmware update which is done by downloading the Pieps App for iOS or Android devices, connecting the transceiver via Bluetooth, and then following the on-screen prompts to receive a full refund. Consumers can also take the recalled transceivers to a Black Diamond store or ship the transceiver to the Black Diamond service center to have the firmware installed.', '23190');
INSERT INTO safety_incidents VALUES ('8d89cb1d7704f2a1e7bd1829b48184e20d18469d', 'CPSC', '2023-04-27', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Screaming Plush Monkey Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled toys away from children and contact Diamond Visions for instructions on how to receive a full refund.', '23194');
INSERT INTO safety_incidents VALUES ('7d3d4d3f44564fab6f2268458dfbca186b89570f', 'CPSC', '2023-04-27', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Easter Bunny and Boutique Butterfly Jewel Necklaces', 'The Necklaces Have High Levels Of Cadmium. Cadmium Is Toxic If Ingested By Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the Easter Bunny and Boutique Butterfly Jewel Necklace and contact Creative Education of Canada for a full refund. Consumers should cut the recalled necklace chain in half (with scissors) and provide a photo to the firm as proof of destruction. The firm is contacting all known purchasers.', '23192');
INSERT INTO safety_incidents VALUES ('bf2689976b910da16aa65d57636f936c2df93f1f', 'CPSC', '2023-04-27', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'EGL Motor ACE-branded Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact EGL Motor to schedule an appointment for a free repair from an authorized repair shop. The firm will repair reflectors, headlights, chest protector, engine stop switch, parking brake, maximum speeds, and spark arrestor on the recalled models.', '23191');
INSERT INTO safety_incidents VALUES ('daf99f527426cffedbe4579eb8deaa822855ace1', 'CPSC', '2023-04-27', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Ejoyous pool drain covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Standards Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners/operators and consumers should immediately stop using pools with the recalled pool drain covers. Consumers should remove the drain cover from the pool and contact the firm at liuliusingus@163.com for instructions on how to return the drain cover for a full refund. Ensure all pools and spas have Virginia Graeme Baker Pool and Spa Safety Act (VGBA) compliant drain covers and teach children to stay away from drains. Liusin is contacting all purchasers directly.', '23749');
INSERT INTO safety_incidents VALUES ('28115830834ec514fc0ee7c69071b37a3a9473c6', 'CPSC', '2023-04-27', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Pool drain covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Standards Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners/operators and consumers should immediately stop using pools with the recalled pool drain covers. Consumers should remove the drain cover from the pool and contact the firm at vijayli2233@outlook.com for instructions on how to return the drain cover for a full refund. Ensure all pools and spas have Virginia Graeme Baker Pool and Spa Safety Act (VGBA) compliant drain covers and teach children to stay away from drains. Vijayli is contacting all purchasers directly.', '23750');
INSERT INTO safety_incidents VALUES ('3f3989128aaa6909c6c70ea78abcf0c1d2b06261', 'CPSC', '2023-04-27', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Pool and spa drain covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Standards Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners/operators and consumers should immediately stop using pools with the recalled pool drain covers. Consumers should remove the drain cover from the pool and contact the firm at Jdbvxaa@hotmail.com for instructions on how to return the drain cover for a full refund. Ensure all pools and spas have Virginia Graeme Baker Pool and Spa Safety Act (VGBA) compliant drain covers and teach children to stay away from drains. Pickloud is contacting all purchasers directly.', '23748');
INSERT INTO safety_incidents VALUES ('0cc7b0b6d4736e03e3c1bc7992c3e6aa511adaf2', 'CPSC', '2023-04-27', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Steamfast Home & Away Travel Steam Irons and Brookstone Steam Bug Travel Steam Irons', 'Fire', 'Flammability / Overheating', 'Electric Shock', 'Vornado has received 50 reports of incidents, including 38 reports of the iron''s power cord smoking, sparking, burning or other signs of overheating and 12 reports of cord damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled irons and visit the Steamfast or Vornado website to register for the recall and receive a refund of $19.99.', '23189');
INSERT INTO safety_incidents VALUES ('4234089fedd680db768fba3515cf50b99602ad14', 'CPSC', '2023-04-20', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Children''s robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using them and contact Bagno Milano for a full refund. Consumers who purchased the robes will be asked to destroy the robes by cutting them both vertically and horizontally and disposing of them in accordance with local state recycling laws. Consumers should send the recalling firm a photo of the destroyed robes at support@bagnomilanousa.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Consumers who purchased the robes from Amazon.com will be contacted through Amazon''s messaging platform. Bagno Milano is contacting all known purchasers directly.', '23746');
INSERT INTO safety_incidents VALUES ('20d1298f72aa931267b96db0d3c4ed3ef7ad0f27', 'CPSC', '2023-04-20', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'DynaDrive Fresh Water Well Pumps', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'Davey has received one report of a consumer in Australia who experienced an electrical shock. No incidents or injuries have been reported in the United States.', 'Moderate', 1, 0, 'Consumers should not attempt to turn the pumps off, change settings on the pumps, inspect or repair the pumps, or otherwise touch the pumps. Consumers should register their pump(s) on Davey''s website to schedule a free inspection to verify that the connections are correctly grounded and, if necessary, repair the grounding. Consumers can register their pump(s) on the firm''s website at https://www.daveywater.com/us/product-service-campaign-dynadrive.', '23186');
INSERT INTO safety_incidents VALUES ('ccc3822aef42e65c1fc7df0bc0432b78e023536d', 'CPSC', '2023-04-20', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Children''s Fishing Rods sold with Kid Casters No Tangle Combos', 'The Fishing Rods Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled fishing rods away from children, stop using them and contact Lil Anglers for a full refund or free replacement fishing rod.', '23184');
INSERT INTO safety_incidents VALUES ('14c71cafaf071e6c8e4f610db1269f4c6d6207ef', 'CPSC', '2023-04-20', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Lelinta Multi-Purpose Kids Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the recalled helmets immediately and contact Lucky Global for a full refund. Lucky Global is contacting all known purchasers directly.', '23747');
INSERT INTO safety_incidents VALUES ('7263410723689ff308ae6a8812f351a9c5212f37', 'CPSC', '2023-04-20', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Children''s sleepwear', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear garments away from children, stop using them and contact Changshu Lingshang Trading Co. LTD for a full refund. Consumers should destroy the garments by cutting them in half and email Changshu Lingshang Trading Co. LTD a photo of the destroyed garment at chengye19642012@163.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Changshu Lingshang Trading Co. LTD. and Amazon are contacting all known purchasers directly.', '23187');
INSERT INTO safety_incidents VALUES ('e5adc2f34687ec423f651b662a7c3d375d8baee8', 'CPSC', '2023-04-20', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Children''s sleepwear', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear garments away from children, stop using them and contact Taizhou Jiawang Trading Co. LTD for a full refund. Consumers should destroy the garments by cutting them in half and email Taizhou Jiawang Trading Co. LTD. a photo of the destroyed garment at lingwushihao50@163.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Taizhou Jiawang Trading Co. LTD. and Amazon are contacting all known purchasers directly.', '23188');
INSERT INTO safety_incidents VALUES ('b885e9a6c15c2f519c0c077f6b48557ec3080db1', 'CPSC', '2023-04-20', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Rollerblade® Fury Inline Skates and Rollerblade® Fury brake supports', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'Rollerblade has identified 11 reports of brake supports fracturing or breaking off of the skates. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled skates and contact Rollerblade USA to receive a free replacement brake support. Rollerblade USA is contacting known purchasers directly, including schools and rental facilities.', '23185');
INSERT INTO safety_incidents VALUES ('7ddbe0c01c8fc3a983dbf80bf598cec6bd3325f6', 'CPSC', '2023-04-20', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'DeWALT, Stanley and Craftsman Fiberglass Sledgehammers', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 192 reports of the sledgehammer''s head detaching, including two reported injuries to consumers'' face and head.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled sledgehammers and contact Stanley Black & Decker for instructions to receive a full refund. Consumers must provide their contact information.', '23183');
INSERT INTO safety_incidents VALUES ('a43fdc888dbb07218f87bb26c7804a29d04e9cc4', 'CPSC', '2023-04-13', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'FunnyPaja Children''s Bathrobes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled bathrobes away from children, stop using them and contact FunnyPaja for a full refund. Consumers should destroy the bathrobes by cutting them both vertically and horizontally and disposing of them in accordance with local state recycling laws. FunnyPaja and Amazon are contacting all known purchasers directly.', '23744');
INSERT INTO safety_incidents VALUES ('71aa6924bc33c591e5eca660df9c49e15989f833', 'CPSC', '2023-04-13', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Arshiner Children''s Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children, stop using them and contact Arshiner for a full refund. Consumers should destroy the nightgowns by cutting them both vertically and horizontally and disposing of them in accordance with local state recycling laws. Consumers should send an image of the destroyed recalled nightgowns to Arshiner by email at arshiner.recall@gmail.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Arshiner and Amazon are contacting all known purchasers directly.', '23743');
INSERT INTO safety_incidents VALUES ('093559dd8818fdd0df918e05616a338d9ba97f06', 'CPSC', '2023-04-13', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Children''s robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using them and contact Goumi. Consumers should destroy the robes by cutting them both vertically and horizontally and disposing of them in accordance with local state recycling laws. Consumers should send an image of the destroyed recalled robes to Goumi by email at productrecall@goumikids.com. Upon receipt of the image, consumers will be issued instructions on how to receive a $48 store credit towards a replacement product. Goumi is contacting known consumers directly.', '23745');
INSERT INTO safety_incidents VALUES ('be5e34e600ed2e576aad096a6dcd18b81cff3288', 'CPSC', '2023-04-13', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Luxor A/V carts', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'Three children have died, and one child was seriously injured in incidents where recalled A/V carts carrying a "box" shaped television (CRT TV) tipped over and landed on them. The incidents occurred between 2006 and 2016.', 'Fatal', 1, 0, 'Consumers should stop using the recalled carts immediately and contact Luxor for a free repair. Luxor will provide metal ballast kits, which should be installed by the consumer to the lower shelf of the cart to add stability and weight. New warning labels cautioning consumers to place no more than 25 lbs. on each shelf will also be provided. Consumers should attach these warning labels on each shelf.', '23177');
INSERT INTO safety_incidents VALUES ('119fbcf055aabec6a83c7988d9189189432825bf', 'CPSC', '2023-04-13', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Flo Smart Water Monitor Lithium-Ion Battery Back-Ups', 'Fire', 'Flammability / Overheating', 'Not Specified', 'There have been three reports of backup batteries that have overheated and caught fire. No injuries have been reported, but minor property damage has been reported.', 'Minor', 1, 0, 'Consumers should immediately unplug and stop using their recalled battery back-up and contact Moen for instructions to disable their battery back-up before disposing of the unit in accordance with applicable laws for the disposal of lithium-ion batteries.', '23178');
INSERT INTO safety_incidents VALUES ('6d55b7527d0e85862c8d7969248d9ebbd5b603fd', 'CPSC', '2023-04-06', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'BISSELL® Cordless Multi-Surface Wet Dry Vacuums Models 2551R and 25518', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vacuums and contact BISSELL for a free battery pack replacement. Consumers can either take the recalled product to a local BISSELL authorized service center for a free battery pack replacement or schedule a free in-home repair visit from an authorized BISSELL service technician to replace the existing battery pack.', '23176');
INSERT INTO safety_incidents VALUES ('3e0cdd52f186876e63a1da3e5fc827c9c61fb0e9', 'CPSC', '2023-04-06', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'BLÅVINGAD fishing games', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Globally, IKEA has received notice of four incident reports of the rivet coming loose. None of the reported incidents occurred in the U.S. or required medical attention.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled BLÅVINGAD fishing game and contact IKEA for a full refund.', '23175');
INSERT INTO safety_incidents VALUES ('26563fd248aede1bfaf75ce057f3a359ce793bbd', 'CPSC', '2023-04-06', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Alugator Ride 3.0 Hoe and Alugator Ride SE avalanche shovels', 'Injury', 'Other', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled avalanche shovels and follow the instructions at https://mammut.prezly.com/recall-notice-for-a-call-for-inspection-shovel-locking-mechanism to inspect the connection between the shaft and the shovel head to make sure it properly locks into position. If the connection does not lock into position, consumers should contact Mammut to obtain a prepaid return shipping label to return the shovel for a free repair or a free replacement shovel.', '23174');
INSERT INTO safety_incidents VALUES ('9708127baa04762f1357201b80105bde2ce5d9c6', 'CPSC', '2023-04-06', 2023, '2023-04', 'USA', 'United States', '', 'Other', 'Basket with Balls toys sold with Monti Kids Tummy-Time, 4-6M Play and Early Gross Motor subscription boxes', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received two reports of the small parts inside the ball being released. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled toys and contact Monti Kids for instructions on receiving a refund of $12. Consumers should show proof of destroying the recalled ball by cutting the blue crochet ball in half and then throwing the recalled ball in the garbage. Once they have cut the ball in half, they should send a photo of destruction to customercare@montikids.com. Consumers should state in the email that the recalled ball has been removed from use and indicate their refund preference either back to the credit card used for payment or a mailed check. Monti Kids is contacting all known purchasers.', '23742');
INSERT INTO safety_incidents VALUES ('f2a8bdd2164065e8c6e045561b567b106f96decf', 'CPSC', '2023-03-31', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'The Laundress Fabric Conditioners', 'Chemical', 'Chemical / Toxic Substance', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled fabric conditioners and contact The Laundress for instructions to receive a full refund. Consumers who have previously requested a refund for these products in response to The Laundress'' December 2022 recall and reimbursement program should not submit a new request. Consumers who purchased the recalled products on or after January 2021 can request a refund using either a photo of the lot code with their initials and the date written in marker or a receipt, or if purchased through www.TheLaundress.com, consumers can submit their e-mail address for a refund. Consumers who purchased the recalled products before January 2021 should take a photo of the lot code with their initials and the date written in marker and contact The Laundress for a full refund of the purchase price, with receipt, or of the manufacturer''s suggested retail price, without receipt.', '23172');
INSERT INTO safety_incidents VALUES ('9df576161fa006b9e32989d378f4200fa2d5f5be', 'CPSC', '2023-03-30', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Open Cycle UP Ekar, UPPER Ekar, WIDE Ekar and MIND Ekar bicycles', 'The Rear Brake Can Fail, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'Open Cycle has received two reports of Campagnolo brake hoses becoming damaged. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and framesets and contact their local bicycle dealer to schedule free installation of the repair kit. The repair kit includes a hydraulic brake hose/line, and a new frame insert for the rear brake hose and rear shift cable.', '23168');
INSERT INTO safety_incidents VALUES ('56e862cbdfe9ab820cd9c0aa896ecb553edb1284', 'CPSC', '2023-03-30', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Cannondale Tesoro Neo X Speed Electric Bicycles', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact Cannondale for instructions on how to receive a free repair. Cannondale is contacting all known purchasers directly.', '23169');
INSERT INTO safety_incidents VALUES ('3374acff0edc2ba409d2b9f8705ffced23655abf', 'CPSC', '2023-03-30', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Carhartt Men''s Force Relaxed 5 Pocket Work Pants', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled work pants and return the pants to Dicks Sporting Goods or Carhartt for a full refund. If consumers want to keep the pants, they can cut the loop out of the hems and send a photo to Carhartt at just_ask_us@carhartt.com showing proof that the cord was removed to get a full refund.', '23171');
INSERT INTO safety_incidents VALUES ('96f2fcedc014d3d0c540cf39bdb8af7a2bbe3cf1', 'CPSC', '2023-03-30', 2023, '2023-03', 'USA', 'United States', '', 'Other', '2-in-1 Outdoor Kids Swings', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received seven reports of swing seat restraint straps breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the 2-in-1 Outdoor Kids Swings and contact Delta Enterprise Corp for free replacement straps.', '23170');
INSERT INTO safety_incidents VALUES ('ff057f5540d36bb2df537568bcef96a411e5acb0', 'CPSC', '2023-03-30', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Battery packs and replacement batteries on XS Series Pulsators, Swimmers, Crazy Kicker, and Flasher motion decoys used for waterfowl hunting', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 20 reports of overheating, including nine fires, seven of which involved property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled XS motion decoy battery packs and XS replacement battery packs and contact Higdon Outdoors for free replacement battery packs and chargers.', '23166');
INSERT INTO safety_incidents VALUES ('7fedba59fafc7d6222ca5e9b7335cb12301b7577', 'CPSC', '2023-03-30', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Adult Bike Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact JBM International for a full refund. Consumers should destroy the recalled helmet by cutting off the straps and email a photo of the helmet with the straps cut off to jbmgearcs@gmail.com. Then dispose of the recalled helmets after submitting proof of destruction. JBM International is contacting all known purchasers directly.', '23741');
INSERT INTO safety_incidents VALUES ('e6dea2bfc369fe78cda66ac3d1ddf5bc9cf45af1', 'CPSC', '2023-03-30', 2023, '2023-03', 'USA', 'United States', '', 'Other', '42-volt Jetson Rogue self-balancing scooters/hoverboards', 'Fire', 'Flammability / Overheating', 'Burns', 'A 10-year-old girl and her 15-year-old sister died from a fire on April 1, 2022 in Hellertown, Pennsylvania. The Hellertown Borough Fire Marshal determined that a 42-volt Jetson Rogue was the point of origin of the fire. There have been multiple other reports of the recalled scooters/hoverboards burning, sparking or melting, several of which involved reports of flames.', 'Fatal', 1, 0, 'Consumers should immediately stop using and stop charging the recalled scooters/hoverboards and contact Jetson for a full refund. Jetson is contacting all known purchasers directly.', '23165');
INSERT INTO safety_incidents VALUES ('2e8c5ad40ecaf75ba3cfe7c6e9526feab770a25d', 'CPSC', '2023-03-30', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'STYLR Hair Stylers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled hair stylers and contact Solexio or the retailer or distributor from whom they purchased the product for a full refund.', '23167');
INSERT INTO safety_incidents VALUES ('92128f87f03e6aded7e4acc3b7dccbecaae8920c', 'CPSC', '2023-03-30', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Model Years 2022-2023 RZR Pro R and Pro R 4 Recreational Off-Road Vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received four reports of the alternator failing, including two incidents of fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free repair. The dealer will replace the alternator free of charge. Polaris has notified consumers to stop riding the vehicles and is contacting registered owners directly to provide more details about the repair.', '23740');
INSERT INTO safety_incidents VALUES ('99e3558e923e7c73ab2be909fa2ce18d869a6a73', 'CPSC', '2023-03-23', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Burnham Commercial Natural Gas Boilers', 'Burns', 'Flammability / Overheating', 'Burns', 'The firm has received two reports of flame rollouts. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled boilers and contact the installer or distributor to schedule a free boiler repair. The firm is contacting distributors directly.', '23738');
INSERT INTO safety_incidents VALUES ('6fef9543b27c348bb537e86223003353fb732a9d', 'CPSC', '2023-03-23', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Kawasaki FT730V-EFI Lawn Mower Engines', 'Fire', 'Explosion', 'Burns', 'Kawasaki has received four reports of incidents involving the high-pressure fuel lines leaking including one fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using mowers with the recalled engines and contact Kawasaki or a Kawasaki dealer to schedule a free repair. Kawasaki is contacting all known purchasers directly.', '23163');
INSERT INTO safety_incidents VALUES ('b054c554601d3b6d07bf89bf22edcf509de6e2df', 'CPSC', '2023-03-23', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Arctic Cat Alterra 600 and Tracker 600 All-Terrain Vehicles (ATVs)', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact Textron Specialized Vehicles to arrange for a free inspection and free repair. Textron Specialized will instruct dealers to inspect the main frame A-arm mount brackets for cracks before adding the support bracket. The main frame weldment will be replaced, free of cost, along with the addition of the strengthening brackets, if the main frame A-arm mount bracket is cracking. Textron Specialized Vehicles is contacting all purchasers directly.', '23739');
INSERT INTO safety_incidents VALUES ('5a0a8c553bc9eb213dd0193a96f3b705d5770541', 'CPSC', '2023-03-17', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Mockingbird Single Strollers', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 13 reports of cracks in the frame of Single Strollers. No injuries to children in the strollers have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Single strollers and contact Mockingbird to receive a free frame reinforcement kit, which includes two frame clamps that attach to the sides of the stroller to reinforce the frame. Mockingbird is contacting all known purchasers directly.', '23161');
INSERT INTO safety_incidents VALUES ('85335d582f87635eec859d6185b9366a6e9e5b82', 'CPSC', '2023-03-16', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Ecoxall Sodium and Potassium Hydroxide', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled products and store them in a safe location out of sight and reach of children. Consumers should contact Ecoxall for instructions on how to dispose of the recalled product at their local hazardous waste center and how to receive a full refund. Consumers should confirm they have disposed of the recalled product by email, along with a photo of the recalled product or disposal receipt, to EcoxallLLC@gmail.com to receive the refund. Amazon is contacting all purchasers.', '23155');
INSERT INTO safety_incidents VALUES ('5eafcb66042d5bfdaa67aeaa3823112607631e2b', 'CPSC', '2023-03-16', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Fredericksburg Farms 10 Ounce Scented Candles with Glass Lids', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received four reports of consumers receiving lacerations on their hands after the glass candle jars broke.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled scented candles and should not attempt to forcibly remove the lid if it does not come off easily. Contact Fredericksburg Farms for instructions on how to return the product for a full refund.', '23156');
INSERT INTO safety_incidents VALUES ('4017876cccdd746c6c228cbef290a4fe17264f97', 'CPSC', '2023-03-16', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'IKEA LETTAN Mirrors', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'IKEA has received 55 incident reports globally, and one report of the plastic fittings coming loose and the mirror falling off the wall in the U.S.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mirrors and contact IKEA to order a free set of replacement wall fittings and instructions. Alternatively, customers can return the mirror to any IKEA store for a full refund. Proof of purchase (receipt) is not required to receive a full refund.', '23159');
INSERT INTO safety_incidents VALUES ('1c8ec4ebf6547c70a26fc0618cb9c94cb96e6000', 'CPSC', '2023-03-16', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Nurtec® ODT (rimegepant) orally disintegrating tablets, 75mg 8-Unit Dose blister pack', 'The Recalled Prescription Drugs Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately secure the recalled product out of the sight and reach of children and contact Pfizer for a free child resistant pouch to store the product. Once the product is secured, consumers can continue to use it as directed.', '23154');
INSERT INTO safety_incidents VALUES ('bcb37f455ac2f1b73fc8b5dff9feea0c490acaea', 'CPSC', '2023-03-16', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Model Years 2021-2023 Sportsman 450 and 570 All-Terrain Vehicles (ATVs)', 'Fire', 'Electrical Fault', 'Skin Irritation', 'The firm has received five reports of fire and three reports of damaged wires. Of the five reports of fire, two reports also indicated a loss of the front brake function.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact a Polaris dealer to schedule a free repair. Polaris has notified consumers to stop riding the vehicles and is contacting registered owners directly to provide more details about the repair.', '23734');
INSERT INTO safety_incidents VALUES ('3a522a0d17df1bc334829019da2326d0577684e2', 'CPSC', '2023-03-16', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'STIHL docking stations sold with STIHL iMOW® robotic lawn mowers', 'Fire', 'Electrical Fault', 'Not Specified', 'STIHL has received eight reports of thermal overheating including two reports of fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled STIHL iMOW docking stations and contact STIHL or an authorized STIHL servicing dealer for a free at-home repair of their docking station.', '23158');
INSERT INTO safety_incidents VALUES ('584adc4f7d968966884b75eda7306eac071fa474', 'CPSC', '2023-03-16', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Sunbeam® Queen Size Heated Blankets', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 13 reports of the blankets overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using and unplug the recalled blankets and contact Star Elite for a full refund. Consumers will be asked to complete the online recall registration form available at www.productrecall.sunbeamhome.com and to destroy the blanket by cutting the power cord at the plug, marking an "X" with permanent marker on the wash label and sending the recalling firm a photo of the destroyed blanket.', '23157');
INSERT INTO safety_incidents VALUES ('90c9bf9a9ad564c5f45eb8390351ec9f75b104e1', 'CPSC', '2023-03-09', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Kindred Bravely Bamboo Nursing Hoodies', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled nursing hoodies, cut the fully extended drawstring cords and discard the cords. Consumers can also request a $75 store credit by filling out an online form at www.kindredbravely.com/pages/bamboo-hoodie-safety-recall and providing a photo of the cut drawstrings cords and company branding.', '23149');
INSERT INTO safety_incidents VALUES ('dbb92c4955f9f39f22ba7d2434b3af5921af66cd', 'CPSC', '2023-03-09', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Bedsure Electric Heating Blankets and Pads', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 137 reports of the blankets and pads catching fire, burning, melting and overheating in consumer homes, causing minor property damage. These include 17 reports of burn injuries, including one report of second-degree burns.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled electric heating blankets and pads and contact Bedsure for a full refund. Consumers must have possession of the unit and submit photos of the recalled unit following the instructions provided during registration at www.safety.bedsurehome.com to receive their refund. The firm is contacting all known purchasers.', '23735');
INSERT INTO safety_incidents VALUES ('973c0a69c31431824782235238874dc484382d7d', 'CPSC', '2023-03-09', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Vaunn Medical Bed Assist Rail adult bed rails', 'When The Recalled Bed Rails Are Attached To An Adult''S Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Bed Rail And The Side Of The Mattress. This Poses A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact BeyondMedShop for a free repair. The firm expects the remedy to be available in May 2023.', '23151');
INSERT INTO safety_incidents VALUES ('732c26d010d1e58a6660417a090ebd5108bec21c', 'CPSC', '2023-03-09', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Baby Crib Bumpers', 'Infants Can Suffocate If They Roll Or Move On The Crib Bumper In A Position That Obstructs Breathing. Padded Crib Bumpers Are Banned Under Federal Law.', 'Other', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled crib bumpers and contact Meiling Hou for a full refund. Consumers who purchased the crib bumpers will be asked to cut the tie strings of the crib bumper and send the recalling firm a photo of the destroyed product at houmeiling111@outlook.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Meiling Hou is contacting all known purchasers directly.', '23737');
INSERT INTO safety_incidents VALUES ('6855038f3c7f520a410743a22b3a29ec093e35a5', 'CPSC', '2023-03-09', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Calico Critters® Animal Figures and Sets sold with Bottle and Pacifier Accessories', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Epoch Everlasting Play LLC is aware of three incidents involving the pacifier accessory, including two deaths. One fatal incident involved a 2-year-old child in 2018 in New Mexico, and the other fatal incident involved a 9-month-old child in 2015 in Japan (with a pacifier accessory distributed by Epoch Japan).', 'Fatal', 1, 0, 'Consumers should immediately take the recalled bottle and pacifier accessories away from children and contact Epoch Everlasting Play LLC for instructions on how to submit a photo of the recalled bottle and/or pacifier accessory along with contact information and confirmation of destruction to receive a free replacement accessory.', '23150');
INSERT INTO safety_incidents VALUES ('b25b4379eb4d0d1fc842eb39c4021e17bf144c51', 'CPSC', '2023-03-09', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Anker 535 Power Banks (PowerCore 20k)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 10 reports of incidents involving overheating, including one report of minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled power banks and contact Fantasia Trading to receive a full refund as well as instructions for properly disposing of lithium-ion batteries according to local and state regulations. Fantasia Trading and its retailers are notifying all known purchasers directly.', '23147');
INSERT INTO safety_incidents VALUES ('2930d71980f5794fe5aed0aa1a1978b0cd3072ac', 'CPSC', '2023-03-09', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Pure Outdoor Cooking Systems', 'Fire', 'Electrical Fault', 'Not Specified', 'The firm has received one report of insulation igniting. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled outdoor cooking system and contact Monoprice for a full refund. Monoprice is contacting all purchasers directly.', '23736');
INSERT INTO safety_incidents VALUES ('9825b51c5582207cde6d627fc9c6c5bb4a1f28a2', 'CPSC', '2023-03-09', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Aprepitant capsules and Lidocaine and Prilocaine cream', 'The Recalled Prescription Drugs And Products That Contain Lidocaine Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately secure the medications out of the sight and reach of children and contact Sandoz for a free child resistant pouch to store the products. Once the medication is secured, consumers can continue to use the medication as directed.', '23146');
INSERT INTO safety_incidents VALUES ('2da8d5389be8562519953152bed9fe484dc8e49a', 'CPSC', '2023-03-09', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'SRTH Small Room Tower Heaters', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled heaters and visit Vornado''s website to register for the recall and to receive a full refund.', '23148');
INSERT INTO safety_incidents VALUES ('a0bfb8f5992e706e9f25e27e765cf8718b8bf0ff', 'CPSC', '2023-03-09', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'YETI soft coolers and gear cases', 'Injury', 'Mechanical Failure', 'Poisoning / Ingestion', 'The firm has received 1,399 reports of the magnet-lined closures degrading or failing, including reports of missing or detached magnets. No magnet ingestions or injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled products and contact YETI to receive a full refund or replacement product. Visit www.yeti.com for instructions on returning the product free of charge for the choice of a suggested replacement product of equal or greater value or full refund in the form of a YETI gift card with an additional $25 value.', '23145');
INSERT INTO safety_incidents VALUES ('2ef01faffc686cdb9b62b862a43c237f17128d10', 'CPSC', '2023-03-02', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'CTRL Imperial Wakeboard Bindings', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received 21 reports of either the boot detaching from the binding baseplate or from the mount used to connect the binding baseplate to the wakeboard cracking. No injuries or falls have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bindings and contact Active Sports for a free replacement product or a refund. The firm is contacting all known purchasers.', '23733');
INSERT INTO safety_incidents VALUES ('7460bb4e4537658775a8c2c91ddaf37eb3c551d9', 'CPSC', '2023-03-02', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'DR®Power PRO XL501 Chipper Shredders', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received six reports of the chipper shredders ejecting pieces of metal. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chipper shredders. DR Power Equipment is contacting all known purchasers and automatically sending them a repair kit with installation instructions. Consumers will also be provided with a small sticker with letters "NF" to place on the unit''s data tag to indicate that the scroll has been replaced. Consumers not wishing to make the repair themselves will be directed to a servicing dealer to make the free repair for them, including transportation to and from the dealer.', '23732');
INSERT INTO safety_incidents VALUES ('ce5a7ddb52d9991bf3ffa87ec21ff9d73d90f74b', 'CPSC', '2023-03-02', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Adult workwear sweatshirts and hoodies', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled garments and contact Helly Hansen for a full refund or replacement. Helly Hansen will provide a full refund or a credit towards the purchase of a free replacement item upon submission of a photograph of the garment cut in half by email to highpri.support.na@hellyhansen.com.', '23141');
INSERT INTO safety_incidents VALUES ('77071c84fdfe59554b3d9970856bd54b3feef811', 'CPSC', '2023-03-02', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Multi-Purpose Kids Bike Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Ouwoer Direct for a full refund. To receive a refund, consumers should destroy the helmet by cutting off the straps, then email a photo of the helmet with the straps cut off to Ouwoer@hotmail.com as proof of destruction. Consumers should dispose of the recalled helmets after submitting proof of destruction. Ouwoer Direct is contacting all purchasers directly.', '23730');
INSERT INTO safety_incidents VALUES ('0e3188568199575007701714171f0f0b73b07885', 'CPSC', '2023-03-02', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Infant Capilene Midweight Base Layer Sets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Patagonia has received one report of a snap detaching from the shoulder of the bodysuit and being mouthed by a baby.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Patagonia Infant Capilene Midweight Base Layer Sets and contact Patagonia for a full refund. Patagonia will provide consumers with prepaid labels to return the recalled product, and a full refund upon receipt of the product.', '23138');
INSERT INTO safety_incidents VALUES ('0171a27ac9447ff6ddf15ac8b71c62bc75d6a824', 'CPSC', '2023-03-02', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Children''s Bamboo Plates', 'The Recalled Children''S Bamboo Plates Have Elevated Levels Of Lead And Formaldehyde. Both Lead And Formaldehyde Are Toxic If Ingested By Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled plates away from children, stop using them and return them to a Primark store for a full refund or consumers can contact Primark for instructions on how to properly dispose of the product to also receive a full refund.', '23139');
INSERT INTO safety_incidents VALUES ('2c60513a77df86ba29b5da80829f4723f6944b6b', 'CPSC', '2023-03-02', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'RELiON InSight Series® lithium batteries', 'Fire', 'Flammability / Overheating', 'Burns', 'The company has received five reports of batteries overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled RELiON InSight Series® 48V batteries and contact RELiON Battery for a free repair. RELiON will provide a shipping container for the free return of the recalled batteries. A repaired battery with equivalent remaining cycle life will be shipped back immediately. RELiON will also extend the warranty on replaced batteries for an additional six months beyond the original warranty period.', '23140');
INSERT INTO safety_incidents VALUES ('dfc07848a6a8a2dd73cf809c068e891791236ee3', 'CPSC', '2023-03-02', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Classic Whimsy children''s pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled children''s pajamas away from children, stop using them and contact Smocked Runway for instructions on how to receive a pre-paid mailer and return the pajamas for a full refund in the original form of payment or store credit for the original purchase price. Smocked Runway is directly contacting all known purchasers.', '23731');
INSERT INTO safety_incidents VALUES ('003505326b5085f452c7bfc7cbeb2aa745921f67', 'CPSC', '2023-03-02', 2023, '2023-03', 'USA', 'United States', '', 'Other', 'Office Chairs', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 12 reports in which the back of the chair broke or detached from the seat base when a consumer was seated in a chair at a store, including 10 reports of injuries, including contusions, strains, numbness, bruising and one reported concussion.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled chairs and contact TJX for instructions on how to participate in the recall and dispose of the chairs from home to receive a full refund. Consumers can also return the recalled chairs to any Marshalls, T.J. Maxx, HomeGoods or Homesense store for a full refund.', '23137');
INSERT INTO safety_incidents VALUES ('d78505e8dc069928510709f98729d97e88c9f8b9', 'CPSC', '2023-02-23', 2023, '2023-02', 'USA', 'United States', '', 'Other', '1st stage scuba regulators', 'Injury', 'Drowning Risk', 'Drowning', 'The firm has received one report of a broken turret connection screw. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled scuba regulators and contact XDEEP for a full refund or free replacement. The replacement includes a different model. Consumers can return the recalled regulator to the place of purchase or contact Tec Dive Gear to obtain a parcel label to return the regulator for free. 1st Stage is contacting all known purchasers.', '23133');
INSERT INTO safety_incidents VALUES ('f457591cc06c1246f3af75a237ef34b2bd9f8f0b', 'CPSC', '2023-02-23', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Lancaster Table & Seating brand High Chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received three reports of high chairs breaking while in use and children falling. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled high chairs and return them to any of the Restaurant Store locations in Pennsylvania, New Jersey, Delaware or Maryland or contact Clark Associates for a free replacement or refund in the form of a store credit and instructions on how to properly discard the product. Consumers will be asked to submit a photo of the dismantled or destroyed product and dispose of it.', '23134');
INSERT INTO safety_incidents VALUES ('ddb6560f8f8d2c1f41e053abfceeaf9a47a8b459', 'CPSC', '2023-02-23', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Replacement lower blade guards for 12-inch Chicago Electric Miter Saws', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received one report of the recalled replacement lower blade guard breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled replacement lower blade guards and contact Harbor Freight for a free lower guard assembly kit and installation instructions. Harbor Freight is contacting all known purchasers.', '23729');
INSERT INTO safety_incidents VALUES ('719d5c8b79bef06f184eb08c9120812da43bb270', 'CPSC', '2023-02-23', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Mainstays Three-Wick Candles', 'Fire', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 12 reports of the candle burning too close to the side of the container and the glass cracking, resulting in one report of a minor cut and multiple reports of damage to nearby items. The firm has received one report of a fire.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles and contact Star Soap Star Candle Prayer Candle to receive a full refund.', '23129');
INSERT INTO safety_incidents VALUES ('f150a8a758050e61890aeaffd48a185c51835246', 'CPSC', '2023-02-23', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'LumaRail Bed Assist Rails', 'When The Recalled Bed Rails Are Attached To An Adult''S Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Bed Rail And The Side Of The Mattress. This Poses A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'Platinum has received one report of a death involving the Bed Assist Rail with Legs (model PHB4000). In October 2021, an 81-year-old man at a nursing home in Pennsylvania died from positional asphyxia after becoming entrapped between his mattress and the bed rail.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact Platinum Health for a free repair kit. Consumers who use model PHB7000D on twin beds will receive a free replacement bedrail redesigned to properly fit twin beds.', '23136');
INSERT INTO safety_incidents VALUES ('765231f2fa9128e9992e4b49b2e4fd2cab2542d6', 'CPSC', '2023-02-23', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Polaris Timbersled Snow Bike Conversion Kits', 'The Quickdrive Fastener Can Loosen While Operating, Leading To Brake Failure, Posing A Crash Hazard.', 'Chemical / Toxic Substance', 'Skin Irritation', 'The firm has received seven reports of loose fasteners. No crashes or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled snow bike kits and contact a Polaris dealer to schedule a free repair. Polaris is contacting registered owners.', '23728');
INSERT INTO safety_incidents VALUES ('42af0e8697bcd0b33b06c22c0660f2073bc57484', 'CPSC', '2023-02-23', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'F1 LT and F1 GT Ski Boots', 'Injury', 'Mechanical Failure', 'Fall Injury', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ski boots and contact SCARPA for instructions on replacing the screws. Consumers can either take the recalled ski boots to an authorized SCARPA dealer to have the screws replaced free of cost or request SCARPA to send them the free screws, including shipping, for self-replacement. A video demonstrating the repair is available at https://us.scarpa.com/community/support/contact-scarpas-recall-team.', '23131');
INSERT INTO safety_incidents VALUES ('9461df4b572b323c0f10b278c79ec35d4fed0011', 'CPSC', '2023-02-23', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Aderes bookcases', 'The Recalled Bookcases Are Unstable And Can Tip Over If Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Death Or Injuries To Children.', 'Entrapment', 'Entrapment', 'TJX has received two reports of bookcases that were unstable and began to tip forward. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bookcases and contact TJX for either a full refund or a refund in the form of store gift card and for instructions on how to receive a free pick-up of the bookcase. TJX is contacting known purchasers directly.', '23135');
INSERT INTO safety_incidents VALUES ('bfa4aa7b9c9033baa1d04729f5f71891a2eaed53', 'CPSC', '2023-02-23', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Cosori Air Fryers', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 205 reports of the air fryers catching fire, burning, melting, overheating and smoking. These include 10 reports of minor, superficial burn injuries and 23 reports of minor property damage.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled air fryers and contact Cosori to receive their choice of a free replacement air fryer or another Cosori product by registering at recall.cosori.com. During registration consumers must provide their contact information and submit photos of the recalled unit with the cord cut off. No receipt is needed to receive a replacement.', '23130');
INSERT INTO safety_incidents VALUES ('a2df233b421879e440109fe88d4a7bb64ab47857', 'CPSC', '2023-02-23', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'SmartBase® Euro Slats Metal Platform Bed Frames', 'Injury', 'Chemical / Toxic Substance', 'Not Specified', 'The firm has received 14 reports of the bed frame collapsing including one report of an unspecified injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled metal bed frames and contact Zinus to obtain a free repair kit consisting of reinforcing brackets to be installed on the corners of the base, an appropriate tool and hardware, and both printed and video instructions (available at www.zinus.com/requestkit).', '23132');
INSERT INTO safety_incidents VALUES ('4e7c295af7aaeaba42db781f03188210d0d82d05', 'CPSC', '2023-02-16', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Wicked Lights ScanPro Night Hunting Headlamps', 'Burns', 'Other', 'Burns', 'Allpredatorscall.com has received 14 reports of the wire heating up and melting, including two burn injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled headlamps and contact AllPredatorCalls.com for a repair in the form of a free replacement battery compartment with a safety power circuit.', '23120');
INSERT INTO safety_incidents VALUES ('3ca4bc694275316227836951e7438ad4c91b34a8', 'CPSC', '2023-02-16', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Children''s nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children, stop using them and destroy the nightgowns by cutting them in half. Betsy & Lace is contacting all known purchasers directly.', '23123');
INSERT INTO safety_incidents VALUES ('97ce6c0808ce99ab62e6bbcc6a6a1201cfd2f05a', 'CPSC', '2023-02-16', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Children''s nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children, stop using them and contact Oaks Apparel for a full refund. Consumers who purchased the nightgowns will be asked to destroy the nightgowns by cutting them in half and send the recalling firm a photo of the destroyed garment at jennifer@oaksapparel.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. The Oaks Apparel Company is contacting all known purchasers directly.', '23121');
INSERT INTO safety_incidents VALUES ('bb056c58a69acc95b9516fa3a58e0741be2c36d5', 'CPSC', '2023-02-16', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Children''s pajamas and headbands', 'Fire', 'Flammability / Overheating', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled products away from children, stop using them and contact Hatley USA for a full refund. Consumers should destroy the pajamas by cutting them in half, break the headband and send Hatley USA a photo of the destroyed recalled products by email at service@hatley.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Consumers can also return the recalled products to any Hatley USA store.  Hatley USA is contacting all known purchasers directly.', '23122');
INSERT INTO safety_incidents VALUES ('18e53a84beb3eaf7760c37715c1885456eb1ace1', 'CPSC', '2023-02-16', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'My First Mickey Mouse, Minnie Mouse, Buzz Lightyear, and Stitch Figurines', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received 10 reports of small parts detaching from the figurines. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled toys away from children and contact Kids Preferred for instructions on receiving a full refund.  Consumers who register for the recall will receive a pre-paid shipping label to return the product to the firm for a full refund.', '23127');
INSERT INTO safety_incidents VALUES ('a714c72447fad36921ef030830de78cfe89e0ffb', 'CPSC', '2023-02-16', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'KLIM Backcountry Probes A300', 'Injury', 'Other', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled probes and contact KLIM by email at orders@KLIM.com and enter "A300 Probe Recall" in the subject line to receive a full refund.  KLIM will send consumers free shipping material and a pre-paid shipping label to return the probes. KLIM is contacting all purchasers directly.', '23125');
INSERT INTO safety_incidents VALUES ('eff30a74f95603dafa450b4d7554b115d4446b17', 'CPSC', '2023-02-16', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Electric bicycles', 'The Bicycle''S Front Fork Can Crack, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact Linus Bike to schedule a free fork replacement. Linus is contacting all known purchasers directly.', '23727');
INSERT INTO safety_incidents VALUES ('58320b358b40c0acfc547db94d8cc68b24ea72db', 'CPSC', '2023-02-16', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Paradise Grills First Generation Outdoor Kitchens', 'Fire', 'Explosion', 'Burns', 'The firm has received two reports of the grill exploding, causing severe burns to the consumers.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled grills and contact Paradise Grills to receive a new 16"x 4" stainless steel vent to be installed on the First Generation Outdoor Kitchen. Consumers located in Florida, Texas, Georgia and Alabama should immediately contact Paradise Grills to schedule a date for completion of their free repair.  This includes labor and a new vent. Consumers located in all other states should immediately contact Paradise Grills to receive free shipment of the vent, installation instructions, and reimbursement for the installation cost by a qualified professional or technician. The firm will require a copy of the installer''s invoice or billing statement (marked "Paid") for the installation service. Paradise Grills is contacting all known purchasers directly.', '23126');
INSERT INTO safety_incidents VALUES ('86a2af6b5fcde170acbcfa18ecf446841dc048e1', 'CPSC', '2023-02-09', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Model Year 2023 Can-Am side-by-side vehicles', 'Fire', 'Mechanical Failure', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Can-Am dealer for a free repair to replace the fuel hose assembly. BRP is contacting all known purchasers directly.', '23723');
INSERT INTO safety_incidents VALUES ('f9ff33adfe5da1a406b0f2795b75a82b493726d2', 'CPSC', '2023-02-09', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'LiftMaster myQ Garage Door Control Panels', 'The Control Panel''S Secondary Entrapment Protection System Can Fail Causing The Garage Door To Close Even With An Obstruction Present, Posing An Entrapment Hazard.', 'Entrapment', 'Entrapment', 'None reported in the U.S.', 'Moderate', 1, 0, 'Consumers should immediately contact the Chamberlain Group to receive a free repair kit, including shipping. The repair kit consists of a replacement garage door control panel and installation instructions. Installation instructions can also be found at https://support.chamberlaingroup.com. Chamberlain Group is contacting all known purchasers directly.', '23725');
INSERT INTO safety_incidents VALUES ('0aa4750c76f9115635168d891bf37e48eb986333', 'CPSC', '2023-02-09', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Equestrian helmets', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Ovation Protégé helmets and return them to the retailer they were purchased from or to any Ovation authorized dealer for a free replacement Ovation Deluxe Schooler helmet or contact English Riding Supply for a $60 refund. The replacement helmet or refund will be provided upon return of the recalled helmet OR proof of destruction of the recalled helmet. (Consumers are not required to return the physical helmet to English Riding Supply.) To destroy recalled helmets, consumers should cut off the harness straps. Consumers should email a photo of the cut harness and a photo of the interior manufacturing label, clearly showing the manufacturing date and serial number, to helmets@englishridingsupply.com. The manufacturing label is located on the interior foam liner underneath the comfort liner, so consumers will need to remove the comfort liner to access the manufacturing label.', '23116');
INSERT INTO safety_incidents VALUES ('1f99135b36ac8b110ef1e474fe734dfb862479ec', 'CPSC', '2023-02-09', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'IKEA ODGER Swivel Chairs, Anthracite', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'IKEA has received four reports of the leg base of the ODGER Swivel Chair in anthracite breaking, including two reports of consumers being injured as a result of a fall, in the U.S.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled chairs and return any chair bearing a date stamp before and including 2221 (YYWW) to any IKEA store or contact IKEA for instructions on how to dispose of the chair to receive a full refund. Proof of purchase (receipt) is not required.', '23118');
INSERT INTO safety_incidents VALUES ('5a8ea8cc95665fc56b1d09c3b6812d93e20b5d38', 'CPSC', '2023-02-09', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Silver Lining Cloud Activity Gyms', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Skip Hop has received 12 reports of children putting the raindrops on the cloud toy in their mouths. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately remove the raindrops on the cloud toy by cutting them off with a pair of scissors, take a photo of the cloud toy with the raindrops removed, discard the raindrops in the household trash, and submit the photo of the cloud toy with the raindrops cut off at www.skiphoprecall.com. Upon receipt of the photo, consumers will be issued a $10 Skip Hop gift card and a free shipping code.', '23117');
INSERT INTO safety_incidents VALUES ('977b9cad34f1e71e30e93e71aa4ff48b1b7853f1', 'CPSC', '2023-02-09', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'E-Z-GO Personal Transportation Vehicles (PTVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Textron Specialized Vehicles has received 30 reports of the electronic board overheating, including two resulting in a fire with property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled PTVs, turn the key switch to the OFF position and do not connect electric powered PTVs to a charger or a power outlet. Contact Textron Specialized Vehicles to schedule a free repair. The dealer will install a fiberglass/aluminum thermal insulation protective sleeve over the USB charge port module. Textron Specialized Vehicles is contacting all purchasers directly.', '23726');
INSERT INTO safety_incidents VALUES ('4a21df538bc62da861429207c5e57ce241c8e80f', 'CPSC', '2023-02-09', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Baby Sleep Sacks', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received 17 reports of the zipper detaching from the sleep sack. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using, take the recalled sleep sack and cut it in half with a pair of scissors, take a photo of it, and discard it in the household trash. Contact WeeSprout to receive a $17 refund or credit in the form of a gift card. Email a photo documenting that the sleep sack has been destroyed along with your contact information to weecare@weesprout.com to receive the refund or credit. WeeSprout is contacting all known purchasers.', '23724');
INSERT INTO safety_incidents VALUES ('91043c062a83d5e1ac1311dbdfa625eab0eada2d', 'CPSC', '2023-02-08', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Fabuloso Multi-Purpose Cleaners', 'Environmental', 'Microbiological Contamination', 'Respiratory', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Fabuloso Multi-Purpose Cleaner products and contact Colgate-Palmolive Company for a full refund or a free replacement product. To receive a refund or replacement, consumers should take a picture of the product''s UPC and lot code and dispose of the product in its container with household trash. The consumer recall form can be found on www.fabulosorecall.com. Do not empty the product prior to disposal.', '23115');
INSERT INTO safety_incidents VALUES ('98cf52601e00a352c3f56212b9c2cd40c6b2b104', 'CPSC', '2023-02-02', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Children''s Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using and destroy them by cutting them in half and contact Betusline Official Apparel for a full refund. Consumers who purchased the garments from Amazon.com will be contacted through Amazon''s messaging platform.', '23111');
INSERT INTO safety_incidents VALUES ('a230912385be066b1b43f895fa091f68e409b922', 'CPSC', '2023-02-02', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Children''s robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using them and contact BTPEIHTD for a full refund. Consumers who purchased the robes will be asked to destroy the garments by cutting them in half and send BTPEIHTD a photo of the destroyed garment by email. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. BTPEIHTD and Amazon are contacting all known purchasers directly.', '23110');
INSERT INTO safety_incidents VALUES ('6d1a87be5b2e0d33d722ddf609a93df9d9021d1e', 'CPSC', '2023-02-02', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Children''s robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using them and contact ChildLikeMe for a full refund. Consumers should destroy the robes by cutting them in half and email a photo of the destroyed garment to ChildLikeMe at mtiinns@163.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. ChildLikeMe and Amazon are contacting all known purchasers directly.', '23112');
INSERT INTO safety_incidents VALUES ('90774ddb5d2390505cfadd6f7473ec98efd1ba1d', 'CPSC', '2023-02-02', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Children''s Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using them and contact SGMWVB for a full refund. Consumers who purchased the robes will be asked to destroy the garments by cutting them in half and send SGMWVB a photo of the destroyed robe by email. SGMWVB and Amazon are contacting all known purchasers directly.', '23113');
INSERT INTO safety_incidents VALUES ('566518d9e5e59bcf33f6870b9fd28e0e027f0f2e', 'CPSC', '2023-02-02', 2023, '2023-02', 'USA', 'United States', '', 'Other', 'Children''s pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled children''s pajamas away from children, stop using them and contact Paper Cape for a full refund or a refund in the form of store credit for the original purchase price + 10%. Consumers should destroy the recalled children''s pajamas by cutting them in half then send Paper Cape a photo of the destroyed garment. Upon receipt of the photo, consumers will be issued a full refund of the purchase price or store credit for the original purchase price + 10%. Paper Cape is contacting all known purchasers directly.', '23109');
INSERT INTO safety_incidents VALUES ('f87cf4986b9de5749ab6946546a63fde4c6269b3', 'CPSC', '2023-01-26', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Children''s Lounge Pants', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled children''s sleepwear away from children, stop using them and contact Properly Tied for instructions on how to receive a pre-paid mailer to return the lounge pants for a full refund. Properly Tied is contacting all known purchasers.', '23106');
INSERT INTO safety_incidents VALUES ('c3789ceb124b0ec3d2393c866f825850c95a43be', 'CPSC', '2023-01-26', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'ZLINE 30-inch, 36-inch and 48-inch RG gas ranges', 'Injury', 'Other', 'Poisoning / Ingestion', 'The firm has received 44 reports of carbon monoxide emission, including three reports of consumers seeking medical attention.', 'Fatal', 1, 0, 'Consumers should immediately stop using the oven compartment of the recalled ranges until their oven compartment is repaired.Consumers may continue to use the range tops which are unaffected by the issue. Contact ZLINE to obtain a free in-home repair.', '23107');
INSERT INTO safety_incidents VALUES ('fb5da92de962dcaffe600f6221d9734a985d5dba', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Children''s Pajama Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajama sets away from children, stop using them and contact the Selfie Craft Company. Consumers are to destroy the recalled pajama sets by cutting them in half vertically and submitting a photo of the destroyed pajama set to Selfie Craft Company for a full refund. Selfie Craft Company is contacting all known purchasers directly.', '23097');
INSERT INTO safety_incidents VALUES ('1402ab3044454b251bb33d660eace8c597bdd5cb', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Hot Chocolate Pots', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled pots and contact Williams-Sonoma for instructions on how to return the product for a full refund plus a $20 gift card.', '23096');
INSERT INTO safety_incidents VALUES ('b763ce7d3c52322d041aaeb10c5062bedd2e2cee', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Heavy Duty Headlight Sealant', 'The Recalled Headlight Sealant Contains Low-Viscosity Hydrocarbons Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging For The Products Does Not Meet Federal Child Resistant Packaging Requirements, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled product and store it in a safe location out of sight and reach of children. Contact Meguiar''s for information on how to dispose of the recalled product and how to obtain a free replacement.', '23105');
INSERT INTO safety_incidents VALUES ('bd36ef1719c5b1ed9914bc570facb1b21b1b798b', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Children''s sleepwear', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear garments away from children, stop using them and contact Hainan Chong Yu Industrial for a full refund. Consumers should destroy the garments by cutting them in half and email Hainan Chong Yu Industrial a photo of the destroyed garment at lingershierhao22@163.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Hainan Chong Yu Industrial and Amazon are contacting all known purchasers directly.', '23101');
INSERT INTO safety_incidents VALUES ('855e8a34e809ae35db28ceb11b45e06a0a3bdb60', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Children''s sleepwear', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear garments away from children, stop using them and contact Mianzhu Ye Xin Trading for a full refund. Consumers should destroy the garments by cutting them in half and email Mainzhu Ye Xin Trading a photo of the destroyed garment at lingbahao08@163.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Mianzhu Ye Xin Trading and Amazon are contacting all known purchasers directly.', '23099');
INSERT INTO safety_incidents VALUES ('0bedf0cee6dcdb48d3365df9a4de9ae74cbf3d83', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Children''s sleepwear', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear garments away from children, stop using them and contact Shanghai Jing Cheng Landscape Engineering Company for a full refund. Consumers should destroy the garments by cutting them in half and email Shanghai Jing Cheng Landscape Engineering Company a photo of the destroyed garment at 591025473@qq.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Shanghai Jing Cheng Landscape Engineering Company and Amazon are contacting all known purchasers directly.', '23102');
INSERT INTO safety_incidents VALUES ('a171faa949c9238a293c03f2082421eade37ca6f', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Children''s sleepwear', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear garments away from children, stop using them and contact Shanghai Jinhui Gardening Center for a full refund. Consumers should destroy the garments by cutting them in half and email Shanghai Jinhui Gardening Center a photo of the destroyed garment at ttdd024@163.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Shanghai Jinhui Gardening Center and Amazon are contacting all known purchasers directly.', '23103');
INSERT INTO safety_incidents VALUES ('e6e1445f2ab0bdeb9ea58a7c8a1404fdabf30767', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Children''s sleepwear', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear garments away from children, stop using them and contact Shanghai Xunao Elevator for a full refund. Consumers should destroy the garments by cutting them in half and email Shanghai Xunao Elevator a photo of the destroyed garment at chenye1964@163.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Shanghai Xunao Elevator and Amazon are contacting all known purchasers.', '23104');
INSERT INTO safety_incidents VALUES ('21179bb0609ba831a30faff82ad1128e84d69802', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Children''s sleepwear', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear garments away from children, stop using them and contact Weihai Juanhai Decoration Material for a full refund. Consumers should destroy the garments by cutting them in half and email Weihai Juanhai Decoration Material a photo of the destroyed garment at suzhoudt123@163.com. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Weihai Juanhai Decoration Material and Amazon are contacting all known purchasers directly.', '23100');
INSERT INTO safety_incidents VALUES ('db650764baa08fbb8f414cd7a071a4436b1e410d', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Taylor and Finch six-wick scented candles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Ross has received five reports of candles combusting and the glass container breaking, including one report of minor injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles and return them to a Ross location for a full refund.', '23094');
INSERT INTO safety_incidents VALUES ('0093b3b5808f1422b726b93b1ab22be97a902113', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Credhedz Lizard Helmets, Crayola Dry Erase Helmets and Tony Hawk Multi-Purpose Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Sakar for instructions to return the helmet to Sakar for a refund in the form of a $30 gift card. Contact Sakar for prepaid postage packaging to return the helmet to them. Do not return the helmet to the retailer. Sakar is contacting all known purchasers.', '23098');
INSERT INTO safety_incidents VALUES ('cb095f1055bc468a20e2054368374e12a1e9dd2e', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Children''s robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using them and contact Vaenait Baby for a full refund. Consumers who purchased the robes will be asked to destroy the robes by cutting them in half and send the recalling firm a photo of the destroyed garment. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Vaenait Baby will contact all known purchasers.', '23095');
INSERT INTO safety_incidents VALUES ('86f7f55ab89a28c408359e0b1a8cc2f68d3f3ebc', 'CPSC', '2023-01-19', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Vanessa 42-inch Fire Tables', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Ove Decors has received one incident report of a gas hose melting causing the table to catch fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fire tables, make sure the gas tank is OFF, and contact Ove Decors for a free repair kit, including shipping. Consumer will receive a spring hook to keep the hose away from the heat shield and a warning label.', '23093');
INSERT INTO safety_incidents VALUES ('8e41a3f34722a778b0b9f827575e86e608d9a00d', 'CPSC', '2023-01-12', 2023, '2023-01', 'USA', 'United States', '', 'Other', '2019-2021 Honda Talon 1000 ROVs', 'Injury', 'Other', 'Skin Irritation', 'The firm has received a total of 18 reports of incidents, including one report of a loss of control, resulting in a crash with minor injuries to the occupants.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled recreational off-highway vehicles and contact an authorized Honda Powersports dealer to schedule an appointment for a free inspection and repair, which includes proper tightening and thread deformation of the intake funnel screw. American Honda is contacting all known purchasers directly.', '23090');
INSERT INTO safety_incidents VALUES ('1b62807143dbcb6a09f64c017238f17a9d51b2f7', 'CPSC', '2023-01-12', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'BISSELL® Cordless Multi-Surface Wet Dry Vacuums Models 2551, 2551W and 25519', 'Fire', 'Flammability / Overheating', 'Burns', 'BISSELL has received 66 reports of the vacuum smoking and emitting a burning odor; including five reports of the battery pack catching on fire, three of which resulted in minor property damage and one resulting in a burn injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vacuums and contact BISSELL for a free battery pack replacement. Consumers can either take the product to a local BISSELL authorized service center for a free battery pack replacement or schedule a free in-home repair visit from an authorized BISSELL service technician to replace the existing battery pack.', '23091');
INSERT INTO safety_incidents VALUES ('e56c19b03af69df47a1a345a34dbd08f040b4e6e', 'CPSC', '2023-01-12', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'LG 86-inch smart televisions and stands', 'The Tv Can Become Unstable While On The Assembled Stand, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Injuries Or Death To Children And Others.', 'Instability / Fall Risk', 'Entrapment', 'LG Electronics has received 22 reports of TV stand instability, resulting in 12 reports of tip-overs. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers using the TV''s supporting stand legs should immediately detach it and place the television in a safe location away from children. Contact LG Electronics for instructions on how to inspect the unit and to obtain replacement screws and stand parts, including help from a technician for a free repair. Consumers who wall-mounted their TVs do not need to stop using their TVs.', '23721');
INSERT INTO safety_incidents VALUES ('df525d46a4237394b0fb195657be14b71da63f8c', 'CPSC', '2023-01-12', 2023, '2023-01', 'USA', 'United States', '', 'Other', '1620 vinyl single-hung impact windows with window opening control devices', 'Injury', 'Mechanical Failure', 'Fall Injury', 'None reported', 'Serious', 1, 0, 'Consumers should immediately close and lock the recalled windows and contact MI Windows and Doors for a free repair. MI will arrange for a free in-home repair to replace the window opening control devices. MI Windows and Doors is contacting all known purchasers directly.', '23722');
INSERT INTO safety_incidents VALUES ('fc11ba880e0bd2ee5804969644ceb5442b62f904', 'CPSC', '2023-01-09', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'All models of Rock ''n Play Sleepers', 'Infant Fatalities Have Occurred In The Rock ''N Play Sleepers, After The Infants Rolled From Their Back To Their Stomach Or Side While Unrestrained, Or Under Other Circumstances.', 'Other', 'Not Specified', 'On April 12, 2019, at the time the original recall was announced, over 30 fatalities were reported to have occurred in the Rock ''n Play Sleepers after the infants rolled from their back to their stomach or side while unrestrained, or under other circumstances. Since the recall, approximately 70 additional fatalities have been reported, which includes at least 8 fatalities that were reported to have occurred after the initial recall announcement. Approximately 100 deaths have reportedly occurred ', 'Fatal', 1, 0, 'Consumers should stop using the Rock ''n Play immediately and contact Fisher-Price for a refund or voucher. It is illegal to sell or distribute the recalled sleepers.', '23088');
INSERT INTO safety_incidents VALUES ('48250e92ec60c5bc4107957a72c44e6ba5ad27ce', 'CPSC', '2023-01-09', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'All models of Kids2 Rocking Sleepers', 'Infant Fatalities Have Occurred In The Rocking Sleepers, After The Infants Rolled From Their Back To Their Stomach Or Side While Unrestrained, Or Under Other Circumstances.', 'Other', 'Not Specified', 'A total of 15 infant fatalities were reported to have occurred in the Kids2 Rocking Sleepers, after the infants rolled from their back to their stomach or side while unrestrained, or under other circumstances. Eleven deaths were reported to have occurred before the recall, (including five deaths previously reported by CPSC and Kids2 at the time of the original recall). Four fatalities were reported to have occurred after the recall was announced. Kids2 notes that in some of the reports, it has b', 'Fatal', 1, 0, 'Consumers should stop using the rocking sleeper immediately and contact Kids2 for a refund. It is illegal to sell or distribute the recalled sleepers.', '23089');
INSERT INTO safety_incidents VALUES ('1b385130b981ac1821d6b69b5110f61533ba3eb9', 'CPSC', '2023-01-05', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Children''s pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children, stop using them and contact P.J. Salvage for instructions on how to receive a pre-paid mailer and return the pajamas for a full refund. Consumers who purchased the pajamas directly from P.J. Salvage will be contacted via email and/or postage mail.', '23085');
INSERT INTO safety_incidents VALUES ('4fa30523761fd01e4051bd1f23351561573db703', 'CPSC', '2023-01-05', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Model Year 2020-2023 Sportsman 1000 S and Scrambler 1000 S All-Terrain Vehicles (ATVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 16 reports of fire, including one report of personal injury and one report of property damage, outside the U.S.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free repair. Polaris will instruct dealers to install new fuel filler neck clamps and, if needed, a fill neck cover. Polaris has notified consumers to stop riding the vehicles and is contacting registered owners directly to provide more details about the repair.', '23720');
INSERT INTO safety_incidents VALUES ('655a3528b8cccadd447c4668bdbcc5bf5f16079e', 'CPSC', '2023-01-05', 2023, '2023-01', 'USA', 'United States', '', 'Other', 'Bicycle handlebars and bicycles', 'Injury', 'Other', 'Skin Irritation', 'QBP has received 37 reports of the handlebars cracking or fracturing while in use. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled handlebars and bicycles, and bring the recalled handlebars and bicycles to a local bicycle retailer for free installation of a replacement carbon handlebar or an alternative aluminum handlebar.', '23086');
INSERT INTO safety_incidents VALUES ('49578e2104fea2f05c2a2463facd704d8e19b6ed', 'CPSC', '2022-12-29', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Body Glove Tandem Inflatable Stand Up Paddle Board, ULI Inventor Inflatable Paddle Board, ULI Zettian Inflatable Supyak and ULI Lila Inflatable Supyak', 'Drowning', 'Drowning Risk', 'Drowning', 'Surf 9 has received three reports of the Body Glove boards deflating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled boards and return them to Costco for a full refund or contact Surf 9 for instructions on how to receive a refund. Costco is contacting all known purchasers directly.', '23082');
INSERT INTO safety_incidents VALUES ('fa7933f2e5a5dd6c4b11944c1c9d7dfcf3ca73df', 'CPSC', '2022-12-29', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Yamaha Viking Off-Road Side-by-Side vehicles', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Yamaha Motor Corporation U.S.A. for a free inspection and repair. Yamaha is contacting all registered owners directly.', '23719');
INSERT INTO safety_incidents VALUES ('7e31f55910daf29c77e108865982db7110a8c554', 'CPSC', '2022-12-29', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'ZLINE 30-inch and 36-inch RG gas ranges', 'Injury', 'Other', 'Poisoning / Ingestion', 'The firm has received 44 reports of carbon monoxide emission, including three reports of consumers seeking medical attention.', 'Fatal', 1, 0, 'Consumers should immediately stop using the oven compartment of the recalled ranges until a free repair is available. Consumers may continue to use the range tops which are unaffected by the issue. Contact ZLINE, who is working to develop repairs for all affected units.', '23083');
INSERT INTO safety_incidents VALUES ('ef905f2f51a25cae2e1690fcf02be77f1cf03fef', 'CPSC', '2022-12-22', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Nomad Battery-Powered Tankless Diving Systems', 'Drowning', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'BLU3 has received 21 reports of divers experiencing restricted airflow. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Nomad tankless diving systems and contact BLU3 to schedule a free repair at an approved service center. BLU3 is contacting all known purchasers directly. The repair cannot be performed by the consumer.', '23076');
INSERT INTO safety_incidents VALUES ('9364b8650bab9ce635233aeacb4d3a44fab23bd5', 'CPSC', '2022-12-22', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'GASGAS Off-Road Motorcycles', 'Injury', 'Chemical / Toxic Substance', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop riding the recalled motorcycles and contact an authorized GASGAS Motorcycle dealer to schedule a free repair, which involves replacing the CDI box. KTM is contacting all known purchasers directly.', '23075');
INSERT INTO safety_incidents VALUES ('5bcb21ed90991ad605b8b0dae9b88c1d2db3222a', 'CPSC', '2022-12-22', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Home Bed Rails', 'When The Bedrail Is Attached, Users Can Become Entrapped Within The Bed Rail Or Between The Bed Rail And The Side Of The Mattress. This Poses A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact Nova Medical Products for a free repair or replacement, depending on the model. Nova Medical Products expects the remedy to be available beginning in March 2023.', '23081');
INSERT INTO safety_incidents VALUES ('8472bf284a1786e736db2fa4b7d9e0626be06da0', 'CPSC', '2022-12-22', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Pacific Igniter and Pacific Bubble Pop 20" kids'' bicycles', 'Falls', 'Instability / Fall Risk', 'Laceration / Cut', 'The firm has received 23 reports of incidents of the bicycle''s handlebars becoming loose during use. Ten injuries involving bruising and abrasions have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop riding the recalled bicycles and contact Pacific Cycle to receive a free repair kit, which will contain a bolt, nut, washer and grease packet with instructions to apply grease to the bolt.', '23077');
INSERT INTO safety_incidents VALUES ('f50e1fe12e806e8b3b88974b9905bdf4311d81f9', 'CPSC', '2022-12-22', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Samsung Top-Load Washing Machines', 'Fire', 'Flammability / Overheating', 'Respiratory', 'Samsung has received 51 reports of smoking, melting, overheating or fire involving the washers; 10 of which resulted in property damage. Three consumers have reported injuries due to smoke inhalation.', 'Moderate', 1, 0, 'Consumers should immediately check whether their washer''s software has been updated to prevent the hazard; and, if not, consumers should immediately stop using the washer until the software is updated. Instructions on how to check whether a washer''s software has been updated can be found here https://www.samsung.com/us/support/tlw-sw-update. All Wi-Fi equipped washers that are plugged into a power source and actively connected to the internet will automatically download the free software repair over-the-air when they are connected to the internet. Consumers who have not connected their Wi-Fi equipped washer to the internet should contact Samsung for instructions on how to download the software repair. Consumers whose washer does not have Wi-Fi capability or who otherwise wish to receive a free software repair without connecting to the internet, should immediately stop using the washer and contact Samsung directly for a free dongle to plug in and download the free software repair.', '23080');
INSERT INTO safety_incidents VALUES ('460360e01908dc144901ba70b6de6cd27511ecff', 'CPSC', '2022-12-22', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Pillowfort™ Weighted Blankets', 'A Young Child Can Become Entrapped By Unzipping And Entering The Blanket, Posing A Risk Of Death By Asphyxiation.', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'A 4-year-old girl and a 6-year-old girl reportedly became entrapped in the cover of the weighted blanket and died due to asphyxia at Camp Lejeune, North Carolina in April 2022. Target has received four reports of children becoming entrapped in these weighted blankets, including the two fatalities.', 'Fatal', 1, 0, 'CPSC and Target are urging consumers to stop using the recalled weighted blankets immediately and contact Target for a refund. Target is also contacting all known purchasers directly to arrange returns. The consumer will receive a refund of $40 in the form of a credit for use at Target stores or online at www.target.com, or the amount on the purchase receipt if higher.', '23078');
INSERT INTO safety_incidents VALUES ('d5f1cbfd5982ca26028ef9af468d02ddd2053892', 'CPSC', '2022-12-15', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Good Matters Three-Wick Candles', 'Fire', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received four reports of the candles catching on fire, cracking or breaking apart while in use, resulting in minor property damage and one consumer being burned.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles and contact the firm for instructions on how to cut the candle wicks and dispose of the product for a full refund. Consumers will be asked to certify disposal.', '23072');
INSERT INTO safety_incidents VALUES ('533a371178cefe054876f951682dda0f8a2d7539', 'CPSC', '2022-12-15', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Thornhill Dark Brown and Natural Baby Cribs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received six reports of incidents of the mattress support pins not fitting correctly or falling out of the crib. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cribs and contact Crate and Barrel for a full refund or free replacement. Crate and Barrel is contacting all purchasers directly.', '23717');
INSERT INTO safety_incidents VALUES ('23696ec8cfe11626907fde34b06eb4fcd38429dd', 'CPSC', '2022-12-15', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Gyroor C3 e-bikes', 'Fire', 'Flammability / Overheating', 'Respiratory', 'Gyroor has received two reports of battery packs igniting and two reports of injuries that required medical treatment, including burns to the consumer''s foot and smoke inhalation.', 'Moderate', 1, 0, 'Consumers should stop using the battery packs on the recalled e-bikes immediately and contact Gyroor for a repair in the form of a free replacement battery pack. Gyroor is contacting all known purchasers directly.', '23716');
INSERT INTO safety_incidents VALUES ('86fd60bb0454fe86c64b3c7514f84173a89c4fbe', 'CPSC', '2022-12-15', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Waterproof Foam Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mattresses and contact ESS Universal to arrange for shipment of a cover with zipper for consumers to place over the foam core that will bring the mattresses into compliance, free of charge. ESS Universal USA is contacting all purchasers directly.', '23718');
INSERT INTO safety_incidents VALUES ('17d369ac1d6f5529327c7f211dcc28d10302dea4', 'CPSC', '2022-12-15', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'D-Ring Fritz Mirrors', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received seven reports of the mirror detaching and falling. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Fritz mirror and contact Gabby for instructions on how to remove and dispose of the mirror for a free replacement mirror, including shipping. Consumers will be asked to submit a photo of the back of disposed product and certify that the product will no longer be used.', '23071');
INSERT INTO safety_incidents VALUES ('1e0af31d5ee848215eb807610ce8beb62bf2a230', 'CPSC', '2022-12-15', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Rosso Motors eQuad X and eQuad Q Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact Rosso Motorsports to arrange to return the recalled ATVs for a refund amount according to the following depreciation schedule: Purchase Date Refund Requested by Consumer (from Recall Announcement Date) Refund Amount After August 1, 2020 0-6 months 100% 6-12 months 80% 12-18 months 65% 18+ months 40% Between August 1, 2019 and July 31, 2020 0-6 months 80% 6-12 months 65% 12+ months 40% Prior to August 1, 2019 0-6 months 65% 6+ months 40%', '23069');
INSERT INTO safety_incidents VALUES ('3750c3b2e517e5101ec4a12441d584e9ace9f7a2', 'CPSC', '2022-12-15', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Samnyte Tattoo Numbing Creams', 'The Packaging Is Not Child Resistant As Required By The Poison Prevention Packaging Act. The Tattoo Numbing Cream Contains Lidocaine, Posing A Risk Of Poisoning To Young Children If They Ingest It.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cream and store it in a location out of reach of children. Contact Liu Xianli for instructions on how to dispose of the product to receive a full refund. Liu Xianli is contacting all known purchasers directly.', '23070');
INSERT INTO safety_incidents VALUES ('a2a14626a2faa628508469e33aa8a91430c5932f', 'CPSC', '2022-12-15', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'SIMU DMI6 Hz motors sold with awnings and shutters', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the manual override feature if their motorized awnings or shutters are not connected to a GFCI outlet or circuit breaker. Consumers should contact SIMU for assistance in identifying the motor and to arrange for a free inspection and replacement motor.', '23073');
INSERT INTO safety_incidents VALUES ('32a0e2f371e02ee2bd1e8738ad3c914fb4942621', 'CPSC', '2022-12-15', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Jacuzzi® Hot Tubs and Sundance® Spas', 'Burns', 'Drowning Risk', 'Burns', 'Sundance Spas has received 185 reports of inaccurate temperature readings. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should use an accurate external thermometer to confirm the water temperature to be no higher than 104 degrees prior to entering the hot tub to prevent injuries and burns. Consumers should not enter the recalled hot tubs if the external thermometer temperature reads higher than 104 degrees. Contact a local authorized Jacuzzi dealer at www.jacuzzi.com/en-us/find-a-dealer/ for Jacuzzi brands and a Sundance Spas dealer at www.sundancespas.com/en-us/find-a-dealer/ for Sundance Spas brands, to schedule a free repair. Sundance Spas and Jacuzzi Hot Tub are contacting all known purchasers directly.', '23068');
INSERT INTO safety_incidents VALUES ('eff32023a70345c6890bf8479981e7178b695182', 'CPSC', '2022-12-12', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Art of Green laundry detergent products', 'Environmental', 'Microbiological Contamination', 'Eye Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Art of Green laundry detergent products and contact the firm for a full refund. To receive a refund, consumers should take a photo of the UPC and date code and dispose of the product by closing the bottle tightly and placing it in household trash. Do not empty the product prior to disposal.', '23066');
INSERT INTO safety_incidents VALUES ('c17de6555a90f45c69c36bf86a30ae75de730a14', 'CPSC', '2022-12-08', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Scotch TL1302 Thermal Laminators', 'Fire', 'Mechanical Failure', 'Not Specified', '3M has received nine reports of the laminators catching on fire, including three reports of minor property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately unplug and stop using the recalled laminators and contact 3M for a full refund and instructions on how to properly dispose of the laminator. Consumers should fill out the online recall registration form. 3M will then email the consumer directly to request additional information and inform consumers of how to properly dispose of the laminator.', '23064');
INSERT INTO safety_incidents VALUES ('0c97d83811d88ed1d7f94cb73188de02b328c868', 'CPSC', '2022-12-08', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Cordless Window Shades Battery Packs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received five reports of the batteries overheating in consumer homes, one report of a battery overheating in a commercial factory, and one report of a fire in a commercial warehouse. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled battery packs and contact the U.S. service center of Ningbo Dooya Mechanic and Electronic to obtain a free replacement battery pack. Consumers will be provided with free return shipping boxes for the recalled batteries.', '23057');
INSERT INTO safety_incidents VALUES ('152c5ed4b497f07d12e0bd8cbbe9178d1e9e18ac', 'CPSC', '2022-12-08', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Traditional 90 and Traditional 110 Gas Fireplaces', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received four reports of incorrect fireplace installation, all resulting in fires, causing property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fireplaces until they have been in contact with Ortal or their authorized Ortal dealer to determine whether their fireplace needs a retrofit plate. A retrofit plate will only be installed if the fireplace is positioned on a wooden base or floor. Ortal is directly contacting all known dealers, installers, distributors, homeowners, and any other individuals that purchased or installed the recalled products. Ortal will install a retrofit plate and provide an inspection free of charge to consumers.', '23065');
INSERT INTO safety_incidents VALUES ('95c27b4333b3419d1c7f26f8c1ac46c059e10e22', 'CPSC', '2022-12-08', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Fall 2022 Darkest Blue Fleece Women''s Sweatshirts and Men''s Shorts', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should stop using the recalled products immediately and contact Life is Good to request a postage-paid shipping label to return the products for a full refund. Upon receipt and verification of the recalled product, consumers will be issued a full refund. Life is Good is contacting all known purchasers directly.', '23063');
INSERT INTO safety_incidents VALUES ('d1f2bc07a57d4350f74c15570a9572b280593c2d', 'CPSC', '2022-12-01', 2022, '2022-12', 'USA', 'United States', '', 'Other', '2022 model year Honda TRX90X ATVs', 'Injury', 'Other', 'Skin Irritation', 'The firm has received one report of the throttle cable getting stuck resulting in a crash and minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled all-terrain vehicles (ATVs) and contact an authorized Honda Powersports dealer to schedule an appointment for a free inspection and repair. Honda is contacting all known purchasers directly.', '23715');
INSERT INTO safety_incidents VALUES ('2b9625398914a24bc0209c65d06fd83412dd93ec', 'CPSC', '2022-12-01', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Cuisinart Compact Blender & Juice Extractor Combos Model CBJ-450', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received three reports of incidents in which the blender blade detached during use. In one of the incidents the blade perforated the blender container. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled blender part of the compact blender and juice extractor combos and contact Conair for a free replacement blade assembly. Consumers will receive instructions on how to install the replacement blade assembly after discarding the existing blade assembly, and after verifying disposal of the existing blade assembly. No tools are needed, and the new assembly can be inserted into the unit in the identical manner that the original assembly was in accordance with the operating instructions that the consumer received when the product was purchased. The juice extractor is unaffected and may continue to be used.', '23056');
INSERT INTO safety_incidents VALUES ('f2fde3e8cb95f4e9663eaed0f4181d11625fb5fb', 'CPSC', '2022-12-01', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Gotway and Begode unicycles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'There has been a total of 14 reported incidents of the recalled unicycles catching on fire, including reports of property damage and one injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled unicycles and contact eWheels for a free replacement battery pack. eWheels is contacting all known purchasers directly.', '23055');
INSERT INTO safety_incidents VALUES ('7dea769060ab126d8486fabe1057e273c75a69a4', 'CPSC', '2022-12-01', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Discovery Cubes Animal Hide and Seek Activity Toy', 'Choking', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'One consumer report noticed the open seam on the toy''s house. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled toy away from the child, cut the toy in half with a pair of scissors, take a photo of it, and discard it in the household trash. Contact HABA to receive a $30 refund or gift card. Email a photo documenting that the toy has been destroyed, along with your contact information to recall@habausa.com to receive the refund. HABA is contacting all known purchasers.', '23714');
INSERT INTO safety_incidents VALUES ('0e71dd506f4df527586842e2965b565187a49dc1', 'CPSC', '2022-12-01', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Aduro surge protectors', 'Fire', 'Flammability / Overheating', 'Electric Shock', 'JBR Solutions has received one report of incorrect polarization of the surge protector. No injuries or fires have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled surge protectors and contact JBR Solutions to receive a full refund. JBR Solutions is contacting known purchasers directly.', '23059');
INSERT INTO safety_incidents VALUES ('7fb2376b470bb69f8778b96652fe548c5aa2c8db', 'CPSC', '2022-12-01', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Kubota RTV-XG850 Model Utility Vehicles', 'Injury', 'Other', 'Not Specified', 'Kubota has received five reports of incidents worldwide of steering shaft shearing. No injuries or deaths have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact an authorized Kubota dealer to schedule a free inspection and free repair. Kubota is contacting all known purchasers directly.', '23713');
INSERT INTO safety_incidents VALUES ('f2756c0dce73af0c2b7c0028cba1dce6c0a94763', 'CPSC', '2022-12-01', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Model Years 2021-2022 RZR Pro XP 4 Recreational Off-Road Vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received five reports of fuel leaks including one report of fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free repair. The dealer will replace the fuel tank assembly free of charge. Polaris has notified consumers to stop riding the vehicles and is contacting registered owners directly to provide more details about the repair.', '23712');
INSERT INTO safety_incidents VALUES ('ee4a6f3fb8f83be50af667af6d20e0b169ba8e74', 'CPSC', '2022-12-01', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Viper Level PRO SD Treestands', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received two reports of the treestand''s cable dislodging. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Viper Level PRO SD treestand and contact Summit Treestands LLC for a full refund.', '23061');
INSERT INTO safety_incidents VALUES ('796fc7683577ae666a12fbafcac8576e34114673', 'CPSC', '2022-12-01', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'Cloud Island 4-Piece Plush Toy Sets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received four reports of tires detaching from toy vehicles. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled plush toys away from young children and return them to any Target store for a full refund or contact Target to receive a prepaid return label to return the toy set by mail.', '23060');
INSERT INTO safety_incidents VALUES ('80ecb9413e0bbf4fc80b52f9691109ea2bec04fd', 'CPSC', '2022-12-01', 2022, '2022-12', 'USA', 'United States', '', 'Other', 'The Laundress laundry and household cleaning products', 'Environmental', 'Microbiological Contamination', 'Respiratory', 'The company is aware of 11 consumers who have reported Pseudomonas infections and is investigating these reports to see if there is any connection to the recalled products.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled products. Consumers who purchased the recalled products on or after January 2021 may request a refund using either a photo of the lot code with their initials and the date written in marker or a receipt, or if purchased through www.TheLaundress.com, consumers can submit their e-mail address for a refund. Consumers who purchased the recalled products before January 2021 should take a photo of the lot code with their initials and the date written in marker and contact The Laundress for a full refund of the purchase price, with receipt, or of the manufacturer''s suggested retail price, without receipt. After requesting a refund, consumers should dispose of the product by closing the bottle tightly and placing it in household trash. Do not empty the product prior to disposal.', '23058');
INSERT INTO safety_incidents VALUES ('2f88fa4fa51e9d204e7439565df7dc9d62937e6d', 'CPSC', '2022-11-23', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Children''s clothing sets', 'The Textile Ink Painted On The Recalled Clothing Sets Contains Levels Of Lead That Exceed Either The Federal Lead Paint Ban Or The Federal Lead Content Ban, Posing A Lead Poisoning Hazard. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled children''s clothing sets away from children and contact Bentex for instructions on how to return or dispose of the recalled clothing to receive a full refund.', '23052');
INSERT INTO safety_incidents VALUES ('4c99112e664b3ccd35ae044b52b037900162161f', 'CPSC', '2022-11-23', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Green Sprouts Stainless Steel Straw Bottles, Sippy Cups and Sip & Straw Cups', 'The Recalled Stainless-Steel Bottles And Cups Bottom Base Can Break Off, Exposing A Solder Dot That Contains Lead, Posing A Lead Poisoning Hazard To The Child. Lead Is Toxic If Ingested By Young Children, And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'The firm has received seven reports of incidents of the bottles'' base breaking off exposing the solder dot. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled stainless steel bottles and cups away from children and discard the bottles and cups. Contact Green Sprouts for a full refund in the form of store credit or your money back. Green Sprouts is contacting all known purchasers directly.', '23711');
INSERT INTO safety_incidents VALUES ('ff4acaab8251f2a287a220d5b3c59cf3b55a7153', 'CPSC', '2022-11-23', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Indigo branded Papa Bear and Mama Bear Mugs', 'Burns', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Papa Bear and Mama Bear mugs and return them to the Indigo store for a full refund.', '23053');
INSERT INTO safety_incidents VALUES ('ed1d3a1fe5e81f47569d4fafd765fa13de0d36b9', 'CPSC', '2022-11-17', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Rainbow Stacking Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled stacking toys away from children, stop using them and contact Professor Puzzle for instructions on how to remove and dispose of the sticker or to receive a refund of $20 for the 11-inch toy and $15 for the 7-inch toy. Consumers will be asked to return the product in a prepaid mailer. Consumers can also return the product to the retail store for a full refund of the purchase price.', '23049');
INSERT INTO safety_incidents VALUES ('15d55fa9b222515136f030b2f50191457e0e8569', 'CPSC', '2022-11-17', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Model Year 2021-2023 MATRYX, 2015-2022 AXYS, and 2013-2014 Pro-Ride Snowmobiles', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 30 reports of fuel tank bursting, including 16 incidents of fire and one report of a second-degree burn.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact Polaris or an authorized Polaris dealer to schedule a free repair, consisting of replacing the fuel tank assembly. Polaris has notified consumers to stop riding the snowmobiles. However, if a consumer needs to start their snowmobile in order to move it safely, they must make sure the fuel tank is full, and if it is not, they need to fill the tank with fresh gasoline. Polaris is notifying all dealers and contacting all known purchasers directly.', '23710');
INSERT INTO safety_incidents VALUES ('20ce00777df65020e88095a5f42dd44e5860de92', 'CPSC', '2022-11-17', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Infant''s Yellow Footed Fleece Pajamas with Animal Graphic', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled infant footed fleece pajamas away from children and return them to a Carter''s store location for a full refund in the form of a gift card. Consumers can also contact Carter''s to request a free return label and envelope to return the pajamas for a refund in the form of an electronic gift card.', '23048');
INSERT INTO safety_incidents VALUES ('8aecb262e0c9f900767817d0a49681eb2d8745e9', 'CPSC', '2022-11-10', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Generac® and DR® 6500 Watt and 8000-Watt portable generators', 'An Unlocked Handle Can Pinch Consumers'' Fingers Against The Generator Frame When The Generator Is Moved, Posing Finger Amputation And Crushing Hazards.', 'Entrapment', 'Entrapment', 'The firm has received a total of 37 reports of injuries, 24 resulting in finger amputations and five in finger crushing.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled portable generators, unless the locking pin has been inserted to secure the handle in place before and after moving the generator, and contact Generac for a free repair kit consisting of a set of spacers to move the handle away from the frame, eliminating the pinch point. Customers who had responded to the original recall will automatically be sent a new kit.', '23040');
INSERT INTO safety_incidents VALUES ('0f004ac12b9109f6bf6c0d88558bdbe3dbedbc7b', 'CPSC', '2022-11-10', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Hunter branded Devon Park, Astwood, Highland Hill, Kerrison and Van Nuys light fixtures', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'Hunter has received seven reports of the lights causing the circuit breaker to trip. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled lighting products and contact Hunter to receive a full refund.', '23041');
INSERT INTO safety_incidents VALUES ('1220a2399da75273c80c9b2907fb913e135424fa', 'CPSC', '2022-11-10', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Mockingbird Single-to-Double Strollers', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 138 reports of cracks in the frame, including eight injuries involving cuts, scratches or bruising to children in the strollers.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Single-to-Double strollers and contact Mockingbird to receive a free frame reinforcement kit, which includes two frame clamps that attach to the sides of the stroller to reinforce the frame. Mockingbird is contacting all known purchasers directly.', '23042');
INSERT INTO safety_incidents VALUES ('e5f913b7e2321da14e0eaa1ae5f5a938300060d2', 'CPSC', '2022-11-03', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Bolt Foldable Children''s Scooters', 'The Paint On The Recalled Scooters Contains Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Lead Poisoning Hazard. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled scooters away from children, stop using them and contact Anker Play Products for a full refund.', '23031');
INSERT INTO safety_incidents VALUES ('e7a3bc245de799fd0de5dac2c904fb96ad441acb', 'CPSC', '2022-11-03', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Stashables Finger Skateboard Ramp Sets', 'Surface Paint On The Miniature Skateboard And Scooter Toys In The Ramp Sets Contain Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Risk Of Lead Poisoning. The Miniature Scooter Toy Also Fails To Comply With The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled miniature scooters and skateboards away from children and contact BS Interactive to receive free replacement scooters and skateboards, including free shipping. Consumers will be asked to submit a photo of the disposed recalled scooters and skateboards. BS Interactive is contacting all known purchasers directly.', '23707');
INSERT INTO safety_incidents VALUES ('aad708d6a836b1577cc6775dc40ba151d28102ba', 'CPSC', '2022-11-03', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Breeze Ave, Breeze Shore and Breeze Step women''s shoes in navy colors', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop wearing the shoes and visit https//www.clarkusa.com for instructions on how to receive a full refund. Consumers will need to upload a photo of their shoes in order to determine if they are included in this recall. If included in the recall, Clarks will send consumers free shipping materials and a pre-paid shipping label to send back the shoes. Consumers may also return their shoes to the place where purchased.', '23036');
INSERT INTO safety_incidents VALUES ('681b5637157d103abfff2b1cd95b4e269d161914', 'CPSC', '2022-11-03', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'BLACK+DECKER Model HGS011 Easy Garment Steamers', 'Burns', 'Drowning Risk', 'Burns', 'Empower Brands has received 241 reports of hot water expelling from the steamer, including 32 reports of burn injuries, two of which were second-degree burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled BLACK+DECKER Model HGS011 Easy Garment Steamers and contact Empower Brands to receive a free replacement upper assembly for their steamer.', '23034');
INSERT INTO safety_incidents VALUES ('0a5e9d5f462c95b6afac4b41c4593b287f234704', 'CPSC', '2022-11-03', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'FUUL 1.9L Pure Liquid Paraffin Lamp Oil', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Fatal', 1, 0, 'Consumers should stop using the recalled product immediately, store it in a safe location out of reach of children and contact FHS Retail for a full refund. Consumers should email written affirmation that they have disposed of the recalled product, along with a photo of the recalled product, to FUULrecall@gmail.com to receive the refund. Amazon is contacting purchasers.', '23032');
INSERT INTO safety_incidents VALUES ('3f973a256712c8c412f7719ebf1fa42ce0eca280', 'CPSC', '2022-11-03', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'MYX I, MYX II and MYX II Plus Connected Exercise Bicycles', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'Myx has received 864 reports of the pedals loosening or detaching, including 75 reports of injuries resulting in bruises and cuts.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled exercise bikes until the pedals are properly tightened per the instructions that Myx is providing consumers via email. Consumers should contact Myx to schedule a free, in-home repair if their bike''s pedals have previously detached and have not already been repaired by Myx. Instructions are also available at https://www.myxfitness.com/pages/cpsc. Myx is contacting all known purchasers directly.', '23708');
INSERT INTO safety_incidents VALUES ('0aa8e5dc7d29c0806a759ff038dfd011da127ef8', 'CPSC', '2022-11-03', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Power Plus Tora Portable Power Charging Stations', 'Fire', 'Explosion', 'Not Specified', 'Power Plus has received two reports of fires. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Power Plus Tora portable power charging stations and contact Power Plus for instructions on how to return the recalled charging station at no cost to the consumer and to receive a full refund. Power Plus is contacting all known purchasers directly.', '23030');
INSERT INTO safety_incidents VALUES ('e74a1592c2fe025f61843fe42c44eff5eb46a490', 'CPSC', '2022-11-03', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'RadWagon 4 Electric Cargo Bikes', 'The Rim Strip On The Tires Can Be Misaligned, Causing The Tube To Pop And Damage The Tire. Additionally, The Tires With A Ribbed Sidewall Can Unexpectedly Go Flat, Risking Serious Injuries From Loss Of Control And/Or Crash.', 'Other', 'Fracture / Blunt Trauma', 'The firm has received 137 reports of tires blowing out, deflating and separating from the sidewalls. There were eight injuries including five reports of road rash, cuts and/or bruises and one report of a broken wrist and one report of a broken arm.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled E-Bikes and contact Rad Power Bikes to schedule a free repair to replace both tires and rim strips. Rad Power Bikes is contacting all known purchasers directly.', '23709');
INSERT INTO safety_incidents VALUES ('d1dd71754efe61daecd7b2b6e34b3ad00bdd544c', 'CPSC', '2022-11-03', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'AirWick Fresh New Day® aerosol air fresheners - "Fresh Linen" and "Fresh Waters" scents', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received five incident reports including two reports of the can leaking, two reports of the can rupturing and one report of both the can leaking and rupturing. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled air fresheners, wrap the product in several layers of paper, and dispose in accordance with state and local requirements. Use caution to avoid skin and eye contact if the can appears to be leaking. Reckitt is offering consumers a voucher for a free replacement Fresh New Day aerosol air freshener. Consumers should contact Reckitt to submit a photo of the recalled can, along with their contact information and written confirmation that they will dispose of the can to receive a voucher for a free replacement.', '23035');
INSERT INTO safety_incidents VALUES ('c6aed178adee153642e2c8fd09326fd18705598b', 'CPSC', '2022-11-03', 2022, '2022-11', 'USA', 'United States', '', 'Other', 'Tangame Busy Houses', 'The Yellow-Painted Metal Zipper Contains Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Lead Poisoning Hazard; The Orange Plastic Phone Cord Contains Levels Of Lead That Exceed The Federal Lead Content Ban; And The Horn''S Blue Plastic Bulb Contains A Regulated Phthalate That Exceed The Prohibition Of Specific Phthalates. Phthalates And Lead Are Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should take these recalled toys away from young children immediately and contact Tangame Toys for information on how to dispose the product or components for a full refund.', '23033');
INSERT INTO safety_incidents VALUES ('0525b319bba6c35738a47afc3d8ef7c05290d6af', 'CPSC', '2022-10-27', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Amazon Basics Executive Desk Chairs', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'Amazon has received 13 reports of chair leg bases breaking, including one report of a minor shoulder injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and contact Amazon for instructions on how to dispose of the chairs for a full refund. Consumers will be asked to upload a photo of the chair''s leg base and certify disposal of the chair. Upon receipt of the photo and certification of disposal, consumers will be issued a full refund to a valid payment method in the consumer''s Amazon wallet or an Amazon gift card. Amazon is contacting all known purchasers directly.', '23704');
INSERT INTO safety_incidents VALUES ('c1e9129403fc6b16e4470583749b82204d750ac2', 'CPSC', '2022-10-27', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Punisher Adult Cycling Helmets', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Bike USA Inc. for instructions on receiving a full refund. Consumers should not return the helmet to online retailers. Bike USA Inc. will contact all known purchasers.', '23706');
INSERT INTO safety_incidents VALUES ('3d9534f42404bbb689e24ce15ad7a3dea00b7294', 'CPSC', '2022-10-27', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Meic power adapters sold with Brother AirSure DF-2 Dynamic Filtration Tabletop Air Purifiers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'The company has received one report of an incident of the adapter breaking and exposing its metal prongs. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Meic AC power adapter and contact Brother for a free replacement AC power adapter and instructions on how to return the Meic AC power adapter.', '23024');
INSERT INTO safety_incidents VALUES ('3a935a108f0f216c3d42a6e9c2e63dfb0ffa42e0', 'CPSC', '2022-10-27', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Goalsetter wall-mounted basketball goals', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'A 14-year-old boy was killed when the recalled Goalsetter wall-mounted basketball goal fell on him in Granger, Indiana in June 2018. Goalsetter has received four reports of incidents of the wall-mounted basketball goal detaching from a wall, including the boy''s death. In one of the other incidents a consumer sustained severe facial injuries, and in another incident a consumer sustained a fractured leg.', 'Fatal', 1, 0, 'Consumers should stop using the recalled wall-mounted basketball goals immediately and contact Goalsetter for free removal of the basketball goal with a full refund or a free inspection of the installed wall-mounted basketball goal and free installation of an additional safety bracket.', '23027');
INSERT INTO safety_incidents VALUES ('099784ac23518b4cd42cec8f7167c9e291b0fae2', 'CPSC', '2022-10-27', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Horizon T101-05 Treadmills', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'Horizon has received at least 874 reports where the treadmills unexpectedly changed speed or stopped, including 71 reports of injury, including bruises, abrasions and two broken bones.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled T101-05 treadmills and contact Horizon to receive a free USB with a software repair to install on the treadmills.', '23026');
INSERT INTO safety_incidents VALUES ('85f65c9f5da9db68898a00802c9d317d88ea85a0', 'CPSC', '2022-10-27', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'LG Energy Solution "RESU 10H" Lithium-Ion Residential Energy Storage System Batteries', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of the lithium storage batteries smoking and catching fire, resulting in property damage. No injuries have been reported.', 'Minor', 1, 0, 'LG Energy Solution Michigan will arrange for remote software updates to recalled batteries that are connected online. The diagnostic software updates are designed to monitor the recalled battery cells and shut down the battery if a fire risk is detected. If the battery shuts down, please contact LG Energy Solution Michigan for further instructions. Do not attempt to turn the battery on again. LG Energy Solution Michigan, its distributors, and its installers are contacting owners directly if their units are not connected online to arrange for a technician visit to manually update the diagnostic software.', '23705');
INSERT INTO safety_incidents VALUES ('dcf03aace9cd3cf32f155793d6d050549ea397ce', 'CPSC', '2022-10-27', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Tesla Cyberquad for Kids by Radio Flyer, Model Number 914', 'The Cyberquad Fails To Comply With The Federal Mandatory Safety Standard Requirements For Youth Atvs, Including Mechanical Suspension And Maximum Tire Pressure. Additionally, The Cyberquad Lacks A Cpsc-Approved Atv Action Plan, Which Is Required To Manufacture, Import, Sell, Or Distribute Atvs.', 'Explosion', 'Fracture / Blunt Trauma', 'Radio Flyer has received one report of an incident where the single-rider Cyberquad tipped over when driven by an eight-year-old child and a 36-year-old adult female, resulting in a bruised left shoulder to the adult female.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Cyberquad and contact Radio Flyer for a full refund. Consumers can obtain a full refund by removing the product''s motor controller and sending the controller back to Radio Flyer via a prepaid envelope. Removing the motor controller will permanently disable the Cyberquad. Radio Flyer is contacting all consumers directly. Directions on how to locate, remove and return the motor controller can be found on the Radio Flyer recall website. Additional information on disposing of the remainder of the Cyberquad is available on the recall website under FAQs at www.radioflyer.com/recalls. Consumers who return the motor controller and incur costs disposing of the remainder of the Cyberquad will receive up to $50 to cover costs associated with disposal.', '23025');
INSERT INTO safety_incidents VALUES ('5b2ddf544e57a5b1853ac0c08765773f28eb9d81', 'CPSC', '2022-10-25', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Pine-Sol® Scented Multi-Surface Cleaners in Lavender Clean®, Sparkling Wave®, and Lemon Fresh scents, CloroxPro® Pine-Sol® All Purpose Cleaners, in Lavender Clean®, Sparkling Wave®, Lemon Fresh, and Orange Energy® scents, and Clorox® Professional™ Pine-Sol® Lemon Fresh Cleaners. Original Pine-Sol® (Pine scent) is not included in this recall.', 'Environmental', 'Microbiological Contamination', 'Eye Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using Pine-Sol Scented Multi-Surface Cleaners in Lavender Clean, Sparkling Wave, and Lemon Fresh scents, CloroxPro Pine-Sol All Purpose Cleaners, in Lavender Clean, Sparkling Wave, Lemon Fresh, and Orange Energy scents, and Clorox Professional Pine-Sol Lemon Fresh Cleaners that have date codes printed on the bottle beginning with "A4" and followed by a five-digit number less than 22249, which represents products produced prior to September 2022. Consumers should take pictures of the 12 digit UPC code and the date code, dispose of the product in its container with household trash, and contact Pine-Sol for a full refund of the purchase price, with receipt, or of the manufacturer''s suggested retail price, without receipt.', '23022');
INSERT INTO safety_incidents VALUES ('6d7c7b97afd66d8fad9c8abcfab3375dc584ae3f', 'CPSC', '2022-10-20', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Apeks Exotec SCUBA Diving Buoyancy Compensator Devices (BCDs)', 'Injury', 'Drowning Risk', 'Drowning', 'The firm has received one report of buoyancy control loss due to a dump valve stuck open. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled buoyancy compensator devices and take them back to the place where purchased for a free repair. If a consumer is unable to return the product to a dealer where purchased, they should reach out to AQUALUNG directly for instructions to receive a free repair.', '23021');
INSERT INTO safety_incidents VALUES ('4d386a44ccc091055afe06216b525fc2e711ba5a', 'CPSC', '2022-10-20', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Birds Choice Hanging and Pole-Mounted Acrylic Bird Baths', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received two reports of the recalled bird baths causing overheating, smoking, fire and scorching to homes'' decking and siding. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled acrylic bird baths and contact Backyard Nature Products to return them for a full refund. The company will email consumers pre-paid shipping labels or send labels by mail. Backyard Nature Products is contacting all known purchasers directly.', '23020');
INSERT INTO safety_incidents VALUES ('f1a03fdb120a9a79e7650afb4b62e155f648b13c', 'CPSC', '2022-10-20', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Gel Blaster SURGE 1.0 toy guns', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Gel Blaster has received 30 reports of smoking or fire near the handle of the gel blaster where the lithium-ion battery is located. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Gel Blaster SURGE Model 1.0 and contact Gel Blaster to receive a prepaid mailer to return the product and receive a full refund. Gel Blaster is contacting known purchasers directly.', '23019');
INSERT INTO safety_incidents VALUES ('01497f491470ab24843501a9d5d95498d6ecaeb9', 'CPSC', '2022-10-20', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Butterfly Net Sets and Army Action Figure Playsets', 'Components Of The Recalled Butterfly Net Sets And The Action Figure Playsets Contain Levels Of Certain Phthalates And Lead That Exceed The Federal Phthalate And Lead Content Standards. Phthalates And Lead Are Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled butterfly net sets and the action figure playsets away from children and contact Juvo Plus for a full refund of the purchase price. Consumers will be asked to register their butterfly net sets and submit a photo of the disposed product with the nets cut and the handles initialed and dated. For the action figure playsets, consumers will be asked to register their product, certify that the product will no longer be used and has been disposed as directed, and submit a photo of the disposed product. Upon receipt of the photo and validation, consumers will be issued a full refund of the purchase price. Juvo Plus is contacting all known purchasers directly or through a third party as applicable.', '23703');
INSERT INTO safety_incidents VALUES ('53d5b63bac8d1db628d38b248803cb1348c7d72e', 'CPSC', '2022-10-20', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Mittal International Baby Blankets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported in U.S.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled baby blankets and return them to any HomeGoods, Marshalls or T.J. Maxx store for their choice of a full refund or store credit. Alternately, consumers can contact TJX for instructions on how to submit a photo of the recalled blanket, along with their contact information and written confirmation that they will discard the blanket to receive a full refund or a refund in the form of a store gift card.', '23018');
INSERT INTO safety_incidents VALUES ('82069fea0c055d7bce45e4e3334a3cecf47fbe09', 'CPSC', '2022-10-13', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Ski-Doo snowmobiles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'BRP has received five reports of fuel leaks which resulted in two fires.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact a Ski-Doo dealer for a free repair. BRP is contacting all known purchasers directly to coordinate the free repair with dealers to inspect and, if necessary, install a new E-TEC fuel injector hose retainer screw.', '23702');
INSERT INTO safety_incidents VALUES ('ddaf672dae7d01b5bfd5560ba5f9c81d2423c2d9', 'CPSC', '2022-10-13', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Children''s Bathrobes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear away from children and contact Ekouaer for a full refund. Consumers who purchased the bathrobes will be asked to destroy the garments by cutting them in half and send the recalling firm a photo of the destroyed garment. Upon receipt of the photo, consumers will be issued a full refund of the purchase price. Ekouaer and Amazon will contact all known purchasers.', '23011');
INSERT INTO safety_incidents VALUES ('a1878ad15689556302e42e5a549ff00d63c4ff31', 'CPSC', '2022-10-13', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Children''s Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear away from children and contact Jammers Apparel Group for a full refund. Consumers who purchased the nightgowns will be asked to destroy the garments by cutting them in half and send the recalling firm a photo of the destroyed garment. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '23010');
INSERT INTO safety_incidents VALUES ('9f7eb3e4b400bebe56191b02755e9add0f708492', 'CPSC', '2022-10-13', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Scuba Buoyancy Compensator Devices (BCDs) with LP inflator hose', 'Drowning', 'Drowning Risk', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled scuba BCDs and contact Cressi-sub to receive a free replacement hose with installation instructions including a pre-paid mailing label for returning the recalled hoses. The firm is contacting all known purchasers regarding the recall.', '23013');
INSERT INTO safety_incidents VALUES ('0e14c66ce28659b09255e5415067a34ca0d06ba6', 'CPSC', '2022-10-13', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Early Learning Centre Little Senses Lights & Sounds Shape Sorter Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported in the U.S.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled toys away from children, stop using the recalled red cube, discard them, and contact Addo Play for a free replacement red cube. The shape sorter toy can be used without the red cube.', '23009');
INSERT INTO safety_incidents VALUES ('3a725b154719101525ed9e56b796c951f3c74da7', 'CPSC', '2022-10-13', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Ancheer E-bikes', 'Fire', 'Explosion', 'Burns', 'Ancheer has received six reports of incidents involving fire, explosions, or sparks, including four reports of burn injuries.', 'Moderate', 1, 0, 'Consumers should stop using the recalled e-bikes immediately and contact Ancheer for a free replacement battery and battery mount.', '23007');
INSERT INTO safety_incidents VALUES ('1bcea158f47ab5203f9aad0fdfde270789f2e56e', 'CPSC', '2022-10-13', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Magic Chef Air Fryers', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled air fryers and provide a picture of the rating label to the firm to receive instructions to disable the air fryer and receive a refund in the form of a newair.com credit. The credit amount will be $50 or the amount on the purchase receipt if higher. No receipt is needed to get the $50 credit. Consumers can also register to participate in the recall at https://www.newair.com/pages/recall-registration.', '23012');
INSERT INTO safety_incidents VALUES ('66d8161171d1c49ee0793f96360a9fa05b66e41f', 'CPSC', '2022-10-13', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Children''s Rings', 'The Metal Base Of The Ring Contains Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled rings away from children and contact U.P. Fashion for information on how to properly dispose of the rings and receive a full refund.', '23008');
INSERT INTO safety_incidents VALUES ('f44ea55acf1b7fd876b086229240f7a6ebc70415', 'CPSC', '2022-10-13', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'U-Line Outdoor Series 24-inch Built-In Convertible Freezers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'U-Line has received three reports of freezer fires. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately turn off and unplug the recalled outdoor freezers and contact U-Line to schedule a free pickup of the recalled freezers and installation of a free replacement unit. Replacement options include a freezer, refrigerator drawers or refrigerator.', '23006');
INSERT INTO safety_incidents VALUES ('c13b7e4b8d2fcbdfde1f292b2036b7b42a4fac17', 'CPSC', '2022-10-06', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Optimus Gemini portable 2-burner stoves', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled stoves and return them to the place of purchase for a full refund or contact Katadyn North America to receive a prepaid mailer to return the stove for a full refund. Katadyn North America is contacting all known purchasers directly or through its retail partners.', '23004');
INSERT INTO safety_incidents VALUES ('93d0d08fa8d7f53c47361d4a991f2beca3117aca', 'CPSC', '2022-10-06', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Eames Desk Units and Eames Storage Units', 'The Surface Paint On The Tan Side Panels Of The Desks And Storage Units Contains Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Lead Poisoning Hazard. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled desks and storage units immediately. Contact MillerKnoll for either a full refund and free pickup of the desks and storage units, or to receive a free repair kit that includes a replacement panel requiring a screwdriver and a needle nose plier for consumers to install. MillerKnoll is contacting all purchasers directly.', '23701');
INSERT INTO safety_incidents VALUES ('9c7bbbf2a90e144582197deb788cbd1be9998b72', 'CPSC', '2022-10-06', 2022, '2022-10', 'USA', 'United States', '', 'Other', '9-inch Swift Straps', 'Injury', 'Instability / Fall Risk', 'Skin Irritation', 'The firm has received 129 reports of the straps breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Swift straps attached to bicycle bags, discard them and contact Swift Industries for a free replacement strap. Swift is contacting all known purchasers.', '23003');
INSERT INTO safety_incidents VALUES ('56e37846c1168f4343b774f0086d3573e9ce5703', 'CPSC', '2022-10-06', 2022, '2022-10', 'USA', 'United States', '', 'Other', 'Hearth & Hand™ with Magnolia Tea Kettles', 'Fire', 'Flammability / Overheating', 'Burns', 'Target has received 27 reports of incidents with the tea kettles which included the kettles leaking, wobbling/moving on the stovetop while in use, the handle grip breaking off, and the paint chipping/melting on the bottom of the kettle. One consumer reported a fire due to the paint chipping off of the bottom of the kettle. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled tea kettles and return them to any Target store for a full refund or contact Target to receive a prepaid return label to return the tea kettle by mail.', '23002');
INSERT INTO safety_incidents VALUES ('dcad3b9f9f1d4ad541591488f89684767f97bcf3', 'CPSC', '2022-09-29', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Children''s Bowtie Hairclips', 'The Crystals On The Hairclip Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled hairclips away from children and contact BE Jewel Accessories for information on how to properly dispose of the hairclips and receive a full refund.', '22233');
INSERT INTO safety_incidents VALUES ('8ebb5d8f563961931ea2a9773995a2c84c4bcd5c', 'CPSC', '2022-09-29', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Residential elevators', 'Young Children Can Become Entrapped In The Space Between The Exterior Landing (Hoistway) Door And The Interior Elevator Car Door Or Gate If There Is A Hazardous Gap And Suffer Serious Injuries Or Death When The Elevator Is Called To Another Floor.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should keep unsupervised young children away from the recalled residential elevators and contact Cambridge Elevating Inc. for instructions on how to measure for space guards to correct any hazardous gap. Space guards will be provided free of charge and assistance with space guard installation will be provided upon request.', '22234');
INSERT INTO safety_incidents VALUES ('f1382f481eee6847eaabff342ef275ea7cbab52e', 'CPSC', '2022-09-29', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Residential elevators', 'Young Children Can Become Entrapped In The Space Between The Exterior Landing (Hoistway) Door And The Interior Elevator Car Door Or Gate If There Is A Hazardous Gap Between The Doors And Suffer Serious Injuries Or Death When The Elevator Is Called To Another Floor.', 'Entrapment', 'Entrapment', 'In July 2021, a 7-year-old child died in a vacation home in North Carolina after becoming entrapped in a residential elevator.', 'Fatal', 1, 0, 'Consumers should keep young children away from the recalled residential elevators and contact Custom Elevator for instructions on how to measure for space guards to correct any hazardous gap. Space guards will be provided free of charge and assistance with space guard installation will be provided upon request.', '22235');
INSERT INTO safety_incidents VALUES ('4759d164716b161ac71317ecb7a35cd1b60fd82d', 'CPSC', '2022-09-29', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Flynn Twin Full Bunk Beds With Ladders', 'The Space Between The Second Rung Of The Bed''S Ladder And The Lower Bunk Frame Is Wider Than 3.5 Inches, Posing An Entrapment Hazard To Children, When The Mattress Is Removed.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Consumers should block children''s access to the bunk beds and contact Value City Furniture or American Signature Furniture for a free replacement ladder. Hillsdale, through Value City Furniture or American Signature Furniture, is providing a replacement ladder with repair instructions to all known consumers. Hillsdale is contacting all known purchasers directly.', '22778');
INSERT INTO safety_incidents VALUES ('f6278843c04e204439e616a666eb6ed2cbb79817', 'CPSC', '2022-09-29', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'HyperJuice Stackable GaN USB-C Chargers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Hyper Products has received seven reports of the charger overheating resulting in damage to the charging units. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled HyperJuice Stackable GaN USB-C Chargers and contact Hyper Products for refund in the form of a www.Hypershop.com store credit for the amount of the purchase price for the 65W and the 100W chargers.', '22236');
INSERT INTO safety_incidents VALUES ('220b7ef10e92f8850aa481d398651cd55cd836dc', 'CPSC', '2022-09-29', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'HyperJuice 130W USB-C Battery Packs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Hyper Products has received two reports of the battery pack overheating, resulting in smoke, melting and property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled HyperJuice 130W USB-C Battery Packs and contact Hyper Products for a refund in the form of a www.Hypershop.com store credit for the purchase price of the product.', '22237');
INSERT INTO safety_incidents VALUES ('12409891a510c62f0bf874427e73ae19963c8cb3', 'CPSC', '2022-09-29', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Toddleroo Rotating Cabinet Latches', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'North States Industries has received 19 reports of the latching button dislodging or detaching, including one report of a child gagging on a dislodged button.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled cabinet latches and contact North States Industries for a refund. Consumers will be asked to send North States Industries photos of the front and back of the product, and confirm that they have destroyed or disposed of the latches. Upon receipt of the photos and confirmation, consumers will be issued a refund of $5.50 or the purchase price indicated on the receipt if available.', '22232');
INSERT INTO safety_incidents VALUES ('c35427c679586d98550bdb51f484d5ba016705ee', 'CPSC', '2022-09-29', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'BarJam Brackets', 'Injury', 'Instability / Fall Risk', 'Skin Irritation', 'The firm has received three reports of incidents of the brackets breaking and cracking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled BarJam Brackets attached to bicycle handlebars, discard them and contact Rockgeist for free redesigned replacement brackets. Rockgeist is contacting all known purchasers directly.', '22780');
INSERT INTO safety_incidents VALUES ('c255c16fd0f3226d47e5dbaa265c7532e5748e9a', 'CPSC', '2022-09-29', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'E-Z-GO RXV Personal Transportation Vehicles (PTV)', 'Injury', 'Other', 'Laceration / Cut', 'Textron has received 335 reports of incidents of the steering knuckles and A-arms on the PTVs breaking, including one incident that resulted in two reports of abrasion injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled PTVs and contact Textron Specialized Vehicles for a free repair. Textron Specialized Vehicles is contacting all purchasers directly.', '22779');
INSERT INTO safety_incidents VALUES ('27222e5da07b6ab6fb39d8a753a123cb7a57b2bc', 'CPSC', '2022-09-29', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Yamaha Viking Off-Road Side-by-Side vehicles', 'Injury', 'Other', 'Skin Irritation', 'The firm has received four reports of incidents of the brake pipe making contact with the drive shaft causing brake fluid to leak. No injuries or accidents have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Yamaha Motor Corporation U.S.A. for a free inspection and repair. Yamaha is contacting all registered owners directly.', '22781');
INSERT INTO safety_incidents VALUES ('c09c16d2aa8be435b777cc2f923d609a766e34f7', 'CPSC', '2022-09-22', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Ceramic Mugs with Cork Bottoms', 'Burns', 'Other', 'Burns', 'Accompany USA has received one report of the mug breaking after hot liquid was poured into it. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ceramic mugs and contact Accompany USA to receive a full refund.', '22228');
INSERT INTO safety_incidents VALUES ('a15772f79d00c8ed9f5140a3d4fecbbffa426445', 'CPSC', '2022-09-22', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Ladders sold with Canyon Lake and Cottage Colors Bunk Bed and Hutch Sets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ladders and the top bunk of the bunk beds, remove the ladders to prevent access to the top bunk, and contact Rooms To Go for a free replacement ladder. Rooms to Go is contacting all known purchasers.', '22777');
INSERT INTO safety_incidents VALUES ('746d96ab2f23915363215a9821c94e996e9e0214', 'CPSC', '2022-09-22', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Miffy First LED Lights', 'Burns', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Miffy First Lights and visit https://www.mrmaria.com/bluemodule for instructions on how to determine which LED module is being recalled. Consumers who purchased the Miffy First LED Light at a local store, should bring the light to the store to have the module replaced free of charge. Consumers who purchased the light online (or if the retailer is no longer in business) should take one photo of the blue label on the bottom of the light and one photo of the date embossed underneath the right foot of the light and email both photos together with their shipping address and phone number to bluemodule@mrmaria.com to receive an upgraded LED module free of charge.', '22226');
INSERT INTO safety_incidents VALUES ('f111b2b7e47c16d1f2fe0403afe88dbb21978171', 'CPSC', '2022-09-22', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Pool and spa drain covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Standards Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners/operators and consumers should immediately stop using pools and spas with the recalled pool or spa drain covers and contact Angzhili for a full refund. Consumers should remove the drain cover from the pool and/or spa and submit a photo of the drain cover to the firm at 3262863806@qq.com as proof of removal and to receive the refund. Consumers should dispose of the recalled pool or spa drain covers after submitting proof of removal. Angzhili is contacting all purchasers directly.', '22776');
INSERT INTO safety_incidents VALUES ('8fb54d9b757de3ea926ba37961c8304cf5c8dca1', 'CPSC', '2022-09-22', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Pool and spa drain covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Standards Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners/operators and consumers should immediately stop using pools and spas with the recalled pool or spa drain covers and contact Chyir Myd for a full refund. Consumers should remove the drain cover from the pool and/or spa and submit a photo of the drain cover to the firm at myd1928209480@sina.com as proof of removal and to receive the refund. Consumers should dispose of the recalled pool or spa drain covers after submitting proof of removal. Chyir Myd is contacting all purchasers directly.', '22773');
INSERT INTO safety_incidents VALUES ('37ecfd4b7b713e882142de9f40d51e73c4f67500', 'CPSC', '2022-09-22', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Pool and spa drain covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Standards Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners/operators and consumers should immediately stop using pools and spas with the recalled pool or spa drain covers and contact Goetas for a full refund. Consumers should remove the drain cover from the pool and/or spa and submit a photo of the drain cover to the firm at Atlaspool@163.com as proof of removal and to receive the refund. Consumers should dispose of the recalled pool or spa drain covers after submitting proof of removal. Goetas is contacting all purchasers directly.', '22775');
INSERT INTO safety_incidents VALUES ('8ed86961b064ea74b699873929349a66fda69040', 'CPSC', '2022-09-22', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Spalding Momentous EZ Portable Basketball Goals', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received 26 reports of weld failures including three backboards separating from the pole. One injury involving the backboard hitting a consumer on the shoulder/upper torso and one injury hitting a consumer on the head has been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the portable basketball goals and contact Spalding to arrange for a technician to remove the original arm and install a new arm on the goal system. Spalding is contacting all known purchasers.', '22227');
INSERT INTO safety_incidents VALUES ('2a439fc5f8f4685719c19069638aa3ecff908fe7', 'CPSC', '2022-09-22', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Pool and spa drain covers', 'The Recalled Drain Covers Do Not Conform To The Entrapment Protection Standards Of The Virginia Graeme Baker Pool And Spa Safety Act (Vgba), Posing An Entrapment Hazard To Swimmers And Bathers.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Pool owners, operators and consumers should immediately stop using pools and spas with the recalled pool or spa drain covers and contact Find4Fix for a full refund. Consumers should remove the drain cover from the pool and/or spa and submit a photo of the drain cover to the firm at guix12@hotmail.com as proof of removal and to receive the refund. Consumers should dispose of the recalled pool or spa drain covers after submitting proof of removal. Find4Fix is contacting all purchasers directly.', '22774');
INSERT INTO safety_incidents VALUES ('8e08c673acfa8468a517bd1341153440d226ec22', 'CPSC', '2022-09-15', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Cityscape Travel Jogger Strollers, Model TJ75B12A', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled strollers. Baby Trend and Amazon are contacting all purchasers directly with instructions for how to return the strollers at no cost in exchange for either a $175 e-voucher for use at Baby Trend''s online store or a full refund. If you do not receive communication from either Baby Trend or Amazon, contact Baby Trend.', '22772');
INSERT INTO safety_incidents VALUES ('0008f7b20346d9f4a9161267e7627bd2ed38616e', 'CPSC', '2022-09-15', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Model Year 2022 Cervélo R5 and Caledonia-5 bicycles and Cervélo ST31 LT replacement stems', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 13 reports of handlebar slippage. One injury has been reported, resulting from a fall.', 'Moderate', 1, 0, 'Consumers should immediately stop using the two recalled models of Cervélo bicycles and Cervélo replacement stems and contact their authorized Cervélo dealer to arrange for a free repair to replace the faceplate.', '22222');
INSERT INTO safety_incidents VALUES ('18de56319297aa60b8c99c1945e39c7546afcea7', 'CPSC', '2022-09-14', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'thyssenkrupp Access Corp. Residential Elevators', 'Injury', 'Entrapment', 'Entrapment', 'There have been three incidents involving these elevators, including a 2-year old child who died in 2017 and a 2010 incident that left a 3-year old child permanently disabled.', 'Fatal', 1, 0, 'Homeowners should immediately contact TKA for a free inspection and free installation of the free space guard(s). Alternatively, TKA will provide inspection and installation instructions directly to homeowners who do not wish to have an installer come into their home.', '22221');
INSERT INTO safety_incidents VALUES ('71ec20f0a221ae82b8242d5aeb4c57e235b978ac', 'CPSC', '2022-09-08', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Children''s HearMuffs sound compression ear muffs', 'Burns', 'Other', 'Burns', 'The firm has received 19 reports of rupturing batteries. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled HearMuffs and contact Hearing Lab Technology/Lucid Audio to receive two new replacement AAA batteries free of charge.', '22217');
INSERT INTO safety_incidents VALUES ('983f78b84927663156e7a0e132225183f63d7115', 'CPSC', '2022-09-08', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Ivy Bronx, Orren Ellis, Stellar Home Furniture, and Wade Logan branded Murphy Beds', 'Falls', 'Sharp Edges / Points', 'Fracture / Blunt Trauma', 'The firm has received 146 reports of the beds falling or breaking including 62 injuries involving broken bones, bruising, lacerations, concussions and other injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Murphy beds and contact Cyme Tech to schedule a free inspection and repair of the bed. Cyme Tech is contacting all known purchasers directly.', '22771');
INSERT INTO safety_incidents VALUES ('e52eb122b6e687543b6fbcf986e54a502cc21715', 'CPSC', '2022-09-08', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Roots & Harvest Wide Mouth Pint Canning Jars', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled jars and contact LEM to receive a full refund. LEM will provide a return shipping container free of charge and a prepaid return label. LEM is assisting in contacting all known purchasers. Orscheln Farm & Home is contacting known purchasers directly.', '22218');
INSERT INTO safety_incidents VALUES ('edb901d749039de5dab8089805fb6799bc3bca7d', 'CPSC', '2022-09-08', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Tethrd One Stick GEN 2 Climbing Sticks', 'Injury', 'Explosion', 'Fall Injury', 'Tethrd has received five reports of a step breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled climbing sticks and contact the manufacturer for instructions on returning the recalled products at no cost to the consumer. The manufacturer will have the stick tested and if determined not to conform to manufacturer''s specifications, will be replaced at no cost to the consumer. Tethrd is contacting all known purchasers directly.', '22770');
INSERT INTO safety_incidents VALUES ('2fbd2973cdc4bba52800347df4725d1cff4b7a98', 'CPSC', '2022-09-01', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Otter MOMO Children''s Sandals', 'The Inner Layer Of The Recalled Sandals Contains Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled sandals and contact Kolan for information on how to properly dispose of the shoes and receive a full refund. Kolan is contacting all known purchasers directly.', '22769');
INSERT INTO safety_incidents VALUES ('2bb2a552bcfa8ce6b2b6707d44bdad61937c98b5', 'CPSC', '2022-09-01', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Sun Joe Cordless Lawn Mowers models 24V-X2-17LM and 24V-X2-17LM-CT', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 31 reports of either the blade or the bolt securing the blade on the recalled lawn mowers detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled lawn mowers and contact Snow Joe for instructions on how to determine whether their lawn mower is included in the recall and if so, instructions on how to inspect and secure the lawn mower blade.', '22213');
INSERT INTO safety_incidents VALUES ('f26c815c5b36f01ad7abe21d72d490d3e896e781', 'CPSC', '2022-09-01', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Novogratz brand Outdoor Metal Hanging Chairs', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received 22 reports of the chairs tipping or falling over, or breaking at the hook or chain, resulting in 16 injuries including bruises and a mild concussion.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and return them to any HomeGoods, Homesense or HomeGoods/T.J. Maxx or Marshalls combination stores for their choice of either a full refund or store credit of equivalent value.', '22214');
INSERT INTO safety_incidents VALUES ('f75bb00cc7770daf5cf6987517b45c43a469ab4e', 'CPSC', '2022-09-01', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'UPPAbaby All-Terrain RIDGE Jogging Strollers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received one reported incident, resulting in a fingertip amputation to a child who was not in the stroller while in use.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled strollers and contact UPPAbaby to receive free replacement brake discs for both wheels.', '22215');
INSERT INTO safety_incidents VALUES ('ea2c3aa2bd98ba7e0f58375d57d6ce893f52988e', 'CPSC', '2022-09-01', 2022, '2022-09', 'USA', 'United States', '', 'Other', 'Infant Bath Seats', 'Drowning', 'Instability / Fall Risk', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled infant bath seats and contact Yuboloo to receive a pre-paid label to return the infant bath seats. Upon receipt of the infant bath seats, consumers will be issued a full refund for the purchase price. Yuboloo is notifying all known purchasers directly.', '22768');
INSERT INTO safety_incidents VALUES ('cbd18b9a62e9ea020573a907c9a140550d68b5a6', 'CPSC', '2022-08-25', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Big Game Hunters Mud Kitchens', 'The Brass Water Tap Of The Play Kitchen Contains Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Big Game Hunters Mud Kitchen, remove and dispose of the brass water tap, and contact DOM Enterprises & Mfg. Ltd. ("DOM Sports") for a free replacement water tap. Consumers will be contacted through Amazon''s messaging platform.', '22207');
INSERT INTO safety_incidents VALUES ('d4c9ff0e8270591ae16742ea5a95725900d1b403', 'CPSC', '2022-08-25', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Kidoozie My First Activity Desk Toys', 'When Attached To A Crib, A Protruding Knob On The Activity Desks Can Become Entangled With Clothing On A Child, Posing An Entanglement Hazard. The Opening In The Handle On The Desks Can Also Pose A Jaw Entrapment Hazard To Children Under 18 Months.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the toys away from children, stop using them and contact Epoch Everlasting Play for a free replacement or a full refund. The company will provide consumers with a pre-paid shipping label to return the recalled activity desk.', '22205');
INSERT INTO safety_incidents VALUES ('1cd2eb26d4f92f1d92d29498d0672ae4af41d2dd', 'CPSC', '2022-08-25', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Blue''s Clues Foot to Floor Ride-on Toys', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 19 reports of children falling forward while they were riding the toy, resulting in 18 facial injuries.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled ride-on toy away from children and stop using it. Contact the firm for a free kit with instructions to install a new stop bar on the ride-on toy.', '22211');
INSERT INTO safety_incidents VALUES ('153e6bc37635c691904a14eeecc9b21da69f49a8', 'CPSC', '2022-08-25', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'IKEA METALLISK Espresso Makers', 'Burns', 'Explosion', 'Burns', 'The firm has received 16 reports worldwide of the espresso makers bursting, including four reports of burns, scald injuries and hearing damage. No injuries have been reported in the U.S.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled IKEA METALLISK espresso makers with the stainless-steel safety valve. Units bearing date stamps 2040 through 2204 can be returned for a full refund to any Ikea store location or by mail using a pre-paid label. Proof of purchase (receipt) is not required.', '22208');
INSERT INTO safety_incidents VALUES ('4f36ac27f1cedf396a6658dfbdeb3787f587396c', 'CPSC', '2022-08-25', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Paddles sold with stand-up paddleboards', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Agit Global has received 19 reports of the paddle breaking mid-shaft during use, including six reports of leg punctures or laceration injuries.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled paddles and contact Agit Global North America for a free, approximately two-foot long zippered paddle shaft sleeve, intended to be installed over the paddle shaft when the paddle is used.', '22210');
INSERT INTO safety_incidents VALUES ('caa595737bc3e4572af33fd9b5cecceb505f6171', 'CPSC', '2022-08-25', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Polaris Snowmobiles, Model Year 2022 PATRIOT BOOST RMK KHAOS and PATRIOT BOOST PRO RMK', 'Injury', 'Other', 'Not Specified', 'The firm has received 24 reports of the primary (drive) clutch bolt breaking and damaging the clutch assembly.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact a Polaris dealer to schedule a free repair, consisting of an update to the drive clutch and a new drive clutch bolt. Polaris has notified consumers to stop riding the snowmobiles.', '22767');
INSERT INTO safety_incidents VALUES ('d11a362de483c5e5db955a38dee780d9f0d5fd82', 'CPSC', '2022-08-25', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Steel rolling chassis for utility vehicles', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using any utility vehicles with the recalled Navitas steel rolling chassis and contact Navitas Vehicle Systems to schedule a free repair.', '22206');
INSERT INTO safety_incidents VALUES ('8bee8ab07d67fcd997ee01182199f37e111c0189', 'CPSC', '2022-08-25', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Trek Model Year 2022 Speed Concept SLR and MY 2021-2022 Emonda SLR bicycles and MY 2020-2021-2022 aftermarket Bontrager Aeolus RSL VR-C handlebar/stems', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'Trek has received 37 reports of broken carbon handlebars, including one report of injury involving scrapes and bruises.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bikes and aftermarket handlebar/stems and contact their local authorized Trek retailer for a free repair.', '22209');
INSERT INTO safety_incidents VALUES ('4d247cdf2b8d47807595aaf46d32faa33babe49f', 'CPSC', '2022-08-18', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'ASUS ROG Maximus Z690 Hero Motherboards', 'Fire', 'Electrical Fault', 'Burns', 'ASUS Computer International has received 10 reports of the motherboards overheating and melting. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled motherboard and visit https://www.asus.com/us/site/recalls for instruction on how to return the product for a free replacement, including shipping.', '22201');
INSERT INTO safety_incidents VALUES ('0250db2db89b83987fbd989bdd4f3baaffc1f1b1', 'CPSC', '2022-08-18', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Hard Rock Cafe Children''s Hooded Sweatshirts', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled sweatshirts away from the child and remove the drawstring to eliminate the hazard or return the sweatshirt to Hard Rock for a full refund, shipping included.', '22202');
INSERT INTO safety_incidents VALUES ('49977171002996214207621dbe106db5a32dc6e2', 'CPSC', '2022-08-15', 2022, '2022-08', 'USA', 'United States', '', 'Other', '4moms MamaRoo Baby Swing, versions 1.0 through 4.0 and RockaRoo Baby Rockers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', '4moms has received two reports of entanglement incidents involving infants who became caught in the strap under the unoccupied MamaRoo infant swing after they crawled under the seat, including a 10-month-old infant who died from asphyxiation, and a 10-month-old infant who suffered bruising to his neck before being rescued by a caregiver. No incidents involving the RockaRoo have been reported.', 'Fatal', 1, 0, 'Consumers with infants who can crawl should immediately stop using the recalled swings and rockers, place them in an area where crawling infants cannot access and contact 4moms immediately to register for a free strap fastener that will prevent the straps from extending under the swing when not in use.', '22200');
INSERT INTO safety_incidents VALUES ('81dda0ea88693383514e835460293f2c08e40f6b', 'CPSC', '2022-08-11', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Footpads for Onewheel GT Electric Skateboards', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'Future Motion has received 813 reports of the skateboards continuing to operate after the rider has dismounted, including 11 reports of injuries including bruises, friction burns and a twisted ankle.', 'Moderate', 1, 0, 'Consumers should immediately stop using the skateboards with recalled footpads and contact Future Motion to determine whether their footpad is affected. Consumers with affected footpads will receive a free replacement skateboard footpad, including free shipping and installation instructions. Future Motion is contacting all known purchasers directly.', '22766');
INSERT INTO safety_incidents VALUES ('7a737b4e0d8587c810ac7c29b39fe163ac009028', 'CPSC', '2022-08-11', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Residential Elevators', 'Young Children Can Become Entrapped In The Space Between The Exterior Landing (Hoistway) Door And The Interior Elevator Car Door Or Gate If There Is A Hazardous Gap And Suffer Serious Injuries Or Death When The Elevator Is Called To Another Floor.', 'Entrapment', 'Entrapment', 'Residential Elevators, Inc. is aware of one incident involving one of its residential elevators, installed by an independent installer, that resulted in a serious spinal injury to a child.', 'Fatal', 1, 0, 'Consumers should keep unsupervised young children away from the recalled residential elevators and contact Residential Elevators, Inc. for instructions on how to measure for space guards to correct any hazardous gap. Space guards will be provided free of charge and assistance with space guard installation will be provided upon request.', '22199');
INSERT INTO safety_incidents VALUES ('3397b77ace6413558bad7ae6deba71ef9ac18dcd', 'CPSC', '2022-08-04', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'DeWALT 12-inch Sliding Compound Miter Saws', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'DeWALT has received 571 reports of the rear safety guard assembly or components breaking or detaching, including nine reports of laceration injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled miter saws and contact DeWALT for details on how to receive a free repair kit or to take their saw to a DeWALT service center for a free repair. DeWALT is directly contacting all known purchasers.', '22196');
INSERT INTO safety_incidents VALUES ('98b0c3e50283a20c1627b4eb6f29b25141eec526', 'CPSC', '2022-08-04', 2022, '2022-08', 'USA', 'United States', '', 'Other', 'Cordless hedge trimmers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled cordless hedge trimmers and contact Makita U.S.A. Inc. for a free repair. Makita will provide consumers with a merchandise return label to ship the trimmers back to the firm for the free installation of a new blade guard. The firm will return the repaired trimmer with a teal-colored guard on the blade.', '22197');
INSERT INTO safety_incidents VALUES ('398ce78dab0ba346c7ac269060aaadaa94e718ef', 'CPSC', '2022-07-28', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Ceramic Pulley for Switchblade and Drifter kite sailing kites', 'Injury', 'Sharp Edges / Points', 'Not Specified', 'The firm has received 30 reports of the ceramic pulley fraying the bridle line. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Switchblade and Drifter kite sailing kites and contact the place where purchased, an authorized dealer or Adventure Sports for a free replacement kit with installation instructions for the kites. Consumers will receive a replacement kit to make the repair, or can request vendor assistance to replace the pulley. The firm is contacting all known purchasers directly regarding the recall.', '22764');
INSERT INTO safety_incidents VALUES ('08059a5aba702627db84ccab833b41c4321c1da7', 'CPSC', '2022-07-28', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Aesop Post-Poo Drops and Aesop Oil Burner Blends', 'The Recalled Products Contain Low-Viscosity Hydrocarbons Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning. In Addition, The Label On The Products Violates The Federal Hazardous Substances Act (Fhsa) By Omitting The Mandatory Information On The Packaging.', 'Chemical / Toxic Substance', 'Skin Irritation', 'The firm has received three reports of skin irritation/negative skin reaction in the U.S. involving the Oil Burner Blends product with no report of medical treatment.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled products and store them in a safe location out of reach and sight of young children. Contact Aesop for information on how to safely dispose of the recalled products and how to receive a full refund in the form of an Aesop digital gift card in the amount of the price of the recalled product(s). The gift card can be used towards the purchase of any Aesop product at any Aesop store or online at https://www.aesop.com. To obtain the digital gift card, consumers should complete the Refund Request Form at http://aesop.com/us/r/recall-2022 and follow instructions on how to upload a picture showing the batch number and UPC/barcode of the recalled product, and confirm that the recalled product will be disposed in household waste. Consumers who purchased a Home Kit, which includes the recalled product and two other items, will only receive a refund equivalent to the purchase price of the recalled Aesop Post-Poo Drops. Store returns will not be accepted. Consumers must provide proof that the recalled product is in their possession to qualify for a refund.', '22190');
INSERT INTO safety_incidents VALUES ('1753500b19cb19dfdcbcfe262dfcdec4e5839bc2', 'CPSC', '2022-07-28', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Avalanche Transceivers', 'The Recalled Transceivers May Not Switch From Send Mode Into Search Mode. If This Were To Occur, The Device Would Not Be Able To Locate A Skier In An Avalanche, Which Could Result In Severe Bodily Harm Or Death If The Skier Is Buried Under Snow.', 'Other', 'Not Specified', 'Black Diamond has received 26 reports of the search mode on the transceiver not working properly. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled transceivers and perform a safety check to verify if the device can switch into Search Mode by following instructions on this website. If the devices are not working properly, please contact Black Diamond to receive a prepaid shipping label to return the recalled transceivers for a free repair or a replacement device.', '22194');
INSERT INTO safety_incidents VALUES ('400547914fe173a32bdafdb60622b5ed911d35c7', 'CPSC', '2022-07-28', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Evaporator coil drain pans', 'Fire', 'Flammability / Overheating', 'Not Specified', 'DCT has received 26 reports of fire involving evaporator coil drain pans, including three reports of fire since the recall was announced in November 2021. Several of these incidents have resulted in significant fire and smoke damage to residences. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should contact Daikin Comfort Technologies Manufacturing, L.P. (DCT) to determine whether your unit is included in this recall and to register for the free repair by a qualified technician. DCT is contacting all registered consumers where records indicate their gas furnace system is subject to the expanded recall.', '22193');
INSERT INTO safety_incidents VALUES ('5d96df86374a373d1bd6e0da740cc3f1d7dfda50', 'CPSC', '2022-07-28', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Kidoozie™ Play Tents and Playhouses', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled playhouses and play tents away from children, stop using them and contact Epoch Everlasting Play for a full refund or free replacement product.', '22192');
INSERT INTO safety_incidents VALUES ('8d3a630a5c8205d5594666423f3c6351f098213e', 'CPSC', '2022-07-28', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'NUK First Choice 240 mL Glass Baby Bottles', 'The Markings On The Outside Of The Bottles Contain Levels Of Lead That Exceeds The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled glass baby bottles. Contact NUK for information on how to return the recalled baby bottle and receive a full refund. Consumers can register for a kit to return the baby bottles for free at www.recall.nuk-usa.com. Astir Care (Amazon seller) is contacting all known purchasers directly.', '22765');
INSERT INTO safety_incidents VALUES ('d81a5b11128c6f64b16c4fa0b8fd9a734062fe34', 'CPSC', '2022-07-28', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Closed Course Competition Motorcycles', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop riding the recalled closed course competition motorcycles and contact an authorized KTM, Husqvarna or GASGAS Motorcycles dealer to schedule a free repair, which involves replacing the CDI box. KTM is contacting all known purchasers.', '22762');
INSERT INTO safety_incidents VALUES ('abe5aaf758b5cfaa3f6ee6399b8eb964b5fdb9eb', 'CPSC', '2022-07-28', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Underwater Communication Devices', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has reported one small fire with the battery''s PC circuit board during testing. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Powercom, MilCom and RBLi-4 communication devices, remove the battery and contact the firm to receive a free battery pack that has been sealed to prevent water leakage. The firm will provide instructions for properly disposing lithium-ion batteries according federal and state regulations.', '22191');
INSERT INTO safety_incidents VALUES ('7e28487b19b2178638b0275ec61760ce31e5d409', 'CPSC', '2022-07-28', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Arctic Cat Alterra 600 and Tracker 600 All-Terrain Vehicles (ATVs)', 'Electric Shock', 'Electrical Fault', 'Skin Irritation', 'The firm has received five reports of fuses blowing while a vehicle was in use.  No accidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact Textron Specialized Vehicles to arrange for a free repair.  Textron will send consumers instructions along with a replacement 20 Amp fuse, and a new label for the fuse box. Consumers can also bring the vehicle to an authorized repair shop or dealer to have the repair performed free of charge. Textron is contacting all known purchasers.', '22763');
INSERT INTO safety_incidents VALUES ('d81ee7586ad7c016fdb054b8bf111bbd0fabcda0', 'CPSC', '2022-07-21', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Aqualung i330R SCUBA Diving Computers', 'Injury', 'Drowning Risk', 'Drowning', 'The firm has received one report of an incident in which the dive computer failed, displaying incorrect calculation. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Aqualung i330R SCUBA Diving Computers and contact Aqua Lung to arrange for a free repair. Consumers can download a software update through the DiverLog+ application or bring their recalled dive computer to their dealer or local dive center to have the software update installed.', '22187');
INSERT INTO safety_incidents VALUES ('08a7d488141b872a0fa35068b90dfbe3ec58f45c', 'CPSC', '2022-07-21', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Crye Precision LRB Leg Loops', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled LRB Leg Loops and contact Crye Precision to receive a prepaid shipping label to return the recalled leg loops for a full refund. Crye is contacting all known purchasers about the recall.', '22761');
INSERT INTO safety_incidents VALUES ('9d88fdc9f66a5d7b71c0ba9d0874a27e402cbae3', 'CPSC', '2022-07-21', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Monti Kids Toy Box with Bins', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received five reports of the small dowel being exposed after separating from the outer cabinet. No injuries have been reported.', 'Minor', 1, 0, 'Consumer should immediately stop using the recalled Box with Bins and contact Monti Kids for instructions to receive a $35 refund. The firm is contacting all known purchasers directly.', '22759');
INSERT INTO safety_incidents VALUES ('ce6debfe38a6b4bdbe84880ad373159855493a8c', 'CPSC', '2022-07-21', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Baby Mirror Activity Toys', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received one report of an incident in which the dive computer failed, displaying incorrect calculation. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the toy away from children, stop using the recalled Konges Sløjd Baby Mirror Activity Toy and contact Konges Sløjd for a full refund.', '22188');
INSERT INTO safety_incidents VALUES ('675c6c114ba220f259e9fe71c94ac87dd746c535', 'CPSC', '2022-07-21', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Key West Knock Down Hammock Stands', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The Hammock Source has received nine reports of the stands breaking at the base including two reports of scrapes and bruises.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled hammock stands and contact The Hammock Source for instructions on receiving a full refund. The firm is contacting all known purchasers.', '22186');
INSERT INTO safety_incidents VALUES ('b0d71ea2282ecd3cec73ddbe997fd6a1a43dc2a6', 'CPSC', '2022-07-21', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Vichy Laboratoires LiftActiv Peptide-C Anti-Aging Ampoules', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 35 reports of injuries, including one injury involving a cut to a person''s hand requiring stitches.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled product and contact Vichy USA Consumer Care for a full refund. The firm is contacting all known purchasers.', '22760');
INSERT INTO safety_incidents VALUES ('76cb01e0eed63a9ed93b182861d8867c30dd6965', 'CPSC', '2022-07-14', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Tony Hawk Silver Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Sakar for instructions on receiving a refund in the form of a $40 Walmart gift card. Consumers should not return the helmet to Walmart and should contact Sakar for the gift card and to facilitate returns using prepaid postage packaging. Walmart will contact all known purchasers.', '22185');
INSERT INTO safety_incidents VALUES ('336db66d78b47b2fe2efff566bbb841fbf25bc6c', 'CPSC', '2022-07-14', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Outfitter and Big Horn tents', 'Injury', 'Flammability / Overheating', 'Respiratory', 'Westfield has received three reports of the stove jack ring deteriorating due to heat and creating smoke, and one report of smoke inhalation and frostbite related to discontinuing the use of a wood stove while camping.', 'Minor', 1, 0, 'Consumers should immediately stop using a wood stove inside the tents and contact Westfield Outdoor for a free replacement stove jack ring. Consumers can remove the old stove jack ring from the tent and install the replacement ring by following the instructions provided with the replacement ring. Westfield Outdoor is contacting all known purchasers directly.', '22758');
INSERT INTO safety_incidents VALUES ('5619f827abe82c2a21148dca702c5dba11d1b4fd', 'CPSC', '2022-07-07', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'John Deere X380 and X390 Lawn Tractors', 'Injury', 'Other', 'Laceration / Cut', 'The firm has received three reports of the lawn tractor not braking properly. One minor injury resulting in bruises and abrasions has been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled lawn tractors and contact an authorized John Deere dealer for a free repair. John Deere is contacting all known purchasers directly.', '22756');
INSERT INTO safety_incidents VALUES ('2986a94dba629ecfefe84384afd69a080e9726be', 'CPSC', '2022-07-07', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Universal Broadmoore Cayden Gentleman''s 9-drawer chests', 'The Recalled Chests Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Death Or Serious Injuries To Consumers.', 'Entrapment', 'Entrapment', 'Samson International has received one report of a tip-over incident involving a 10-year-old child.', 'Fatal', 1, 0, 'Consumers should immediately stop using recalled chests if they are not properly anchored to the wall and place them in an area that children cannot access. Contact Samson for a full refund or a free tip-over restraint kit. Samson will provide pre-paid shipping labels so that consumers can remove the chest''s drawer slides and return them to Samson for a full refund. Samson will also provide free in-home installation of the tip-over restraint kit upon request. Consumers can also return the item to any Costco Warehouse for a full refund.', '22755');
INSERT INTO safety_incidents VALUES ('1a10c13310b4fa588ee5780d5a25a5d73b623157', 'CPSC', '2022-07-07', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Shake Look Touch books', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Scholastic has received two reports of the pom poms detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the book away from young children and cut the pom poms off the book. Consumers can participate in the recall and receive a $10 gift card by registering online at www.recallrtr.com/slt, submitting a picture of the book and removed pom poms, and affirming that the removed pom poms will be disposed of in the trash. Consumers can use the book after removing and disposing of the pom poms.', '22181');
INSERT INTO safety_incidents VALUES ('6d0f5a48d5d841768ff077a2679d328abeefb30f', 'CPSC', '2022-07-07', 2022, '2022-07', 'USA', 'United States', '', 'Other', 'Fugleman® UT10E and UT10X Utility Terrain Vehicles (UTVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 10 reports of incidents including seven incidents involving fire and three incidents with overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled UTVs and bring the vehicles to an authorized Segway Powersports dealer for a free repair, which includes installation of larger and additional heat shields. The firm has contacted all known purchasers.', '22757');
INSERT INTO safety_incidents VALUES ('c465371f05a070ec9a284c57e354ff2737b2913e', 'CPSC', '2022-06-30', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Children''s Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear away from children and contact Kids Tales for a full refund. Consumers who purchased the pajamas will be asked to destroy the garments by cutting them in half and send the recalling firm a photo of the destroyed garment. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '22178');
INSERT INTO safety_incidents VALUES ('eb153fad12b3cbe442ee231b7bf35ca9af239dbc', 'CPSC', '2022-06-30', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Children''s Pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear away from children and contact Kids Tales for a full refund. Consumers who purchased the pajamas will be asked to destroy the garments by cutting them in half and send the recalling firm a photo of the destroyed garment. Upon receipt of the photo, consumers will be issued a full refund of the purchase price.', '22177');
INSERT INTO safety_incidents VALUES ('5f8810f8ec054eb31c6a6ec9a9ac820d04504ae5', 'CPSC', '2022-06-30', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Residential atmospheric gas-fired boilers', 'The Blocked Vent Temperature Switch (Bvts) Can Malfunction, Which Can Cause The Release Of Gases, Including Carbon Monoxide (Co), Into Consumers'' Homes, Posing A Risk Of Carbon Monoxide Poisoning.', 'Mechanical Failure', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately contact Laars Heating Systems Company to arrange to have a certified technician install repairs at no cost to the consumer. Consumers who continue use of the boiler while awaiting repair should have working carbon monoxide alarms on every level of the home and outside of sleeping areas. The firm is contacting all known purchasers.', '22176');
INSERT INTO safety_incidents VALUES ('4a11a73d0a6867bf61ea01685d39925421faf15c', 'CPSC', '2022-06-30', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Lidocaine 4% Topical Anesthetic Cream', 'The Product Contains Lidocaine Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Is Not Child Resistant, Posing A Risk Of Poisoning To Young Children If They Ingest The Anesthetic Cream.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cream and store it in a location out of sight and reach of children. Contact Mohnark Pharmaceuticals for instructions on how to dispose of the product to receive a full refund. Mohnark Pharmaceuticals is contacting all known purchasers directly.', '22754');
INSERT INTO safety_incidents VALUES ('dcb41e7ad9b808dcc1f2397856259ebc05d53ab6', 'CPSC', '2022-06-30', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'RIO-branded Swinging Hammock Chairs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'ShelterLogic Group has received 24 reports of incidents that resulted in injuries such as bruises, aches and pains, head lacerations, back strain, concussions and abrasions from consumers who fell while using the chair.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled chairs until they have reviewed the new instructions and the pins are properly inserted into the chair''s legs per the instructions. Consumers should contact ShelterLogic Group to receive the new instructions that will help verify proper and safe pin insertion. New instructions can also be found at www.Safety.ShelterLogic.com.', '22175');
INSERT INTO safety_incidents VALUES ('44b46f3e723b5292e87969d25dca5f4c1d082972', 'CPSC', '2022-06-30', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Model Year 2021 and 2022 Kodiak 700 All-Terrain Vehicles (ATVs)', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact Yamaha to receive a trailer towing and hitch weight label. Yamaha is mailing the label with application instructions directly to consumers. Consumer can also contact an authorized Yamaha ATV dealer to schedule free label application. Yamaha is contacting all registered owners directly.', '22753');
INSERT INTO safety_incidents VALUES ('1155bb12bb4768f71724f9861327796305e83e28', 'CPSC', '2022-06-23', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'FLEXIMOUNTS Overhead Garage Storage Racks', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received 18 reports of the U-shaped buckles on the supporting cables failing and the storage racks falling from the garage ceiling. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately unload all items from the racks and contact the firm for a free repair kit. The repair kit includes the instructional video link and written instructions on adding additional support to the storage rack. Loctek is contacting all known purchasers.', '22171');
INSERT INTO safety_incidents VALUES ('da94bf281f85f2e60e9e6ae05beaad25ab6f9180', 'CPSC', '2022-06-23', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Troy-Bilt SpaceSavr Walk-Behind Self-Propelled Lawn Mowers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the mower, store the mower horizontally only and contact the store where purchased or Troy-Bilt to receive a full refund.', '22169');
INSERT INTO safety_incidents VALUES ('a2beaed4622bc2d80028e3049b36ea498f02558f', 'CPSC', '2022-06-23', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Children''s robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children and contact Richie House for a full refund. Consumers who purchased the robes will be asked to destroy the garments by cutting them in half and send the recalling firm a photo of the destroyed garment and of the garment''s side seam label. Upon receipt of the photos, consumers will be issued a full refund. Walmart and Richie House are contacting all known purchasers directly.', '22172');
INSERT INTO safety_incidents VALUES ('e8876df57807a754a901a19a025d62241a918994', 'CPSC', '2022-06-23', 2022, '2022-06', 'USA', 'United States', '', 'Other', '10'' Solar LED Market Umbrellas', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received two reports of the pendant light fixtures detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the umbrellas, remove the solar panel puck containing a lithium-ion battery from the top of the umbrella, store the puck out of the sun and away from combustible material, and not charge the puck with the AC adapter. Consumers can return the umbrellas and solar puck to any Costco Warehouse for a full refund. If unable to return the product, contact Costco for instructions on how to receive a refund. SunVilla and Costco are contacting all known purchasers.', '22752');
INSERT INTO safety_incidents VALUES ('d9b878b1ef73d5f735d26d6504a4153f6a6e0966', 'CPSC', '2022-06-23', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Coda pendant light fixtures', 'Electric Shock', 'Electrical Fault', 'Fracture / Blunt Trauma', 'The firm has received two reports of the pendant light fixtures detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately prevent people from going under the recalled light fixtures and contact Tech Lighting to receive a free repair kit. Consumers will need to schedule installation of the repair kit by a certified electrician, and Tech Lighting will reimburse the consumer for the service. Upon submitting the invoice to Tech Lighting for the installation charges, consumers will receive a reimbursement check.', '22751');
INSERT INTO safety_incidents VALUES ('9582c5598b91acd1056bf13eb4c3d9fa9a2f6356', 'CPSC', '2022-06-23', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Baby Boy Dino Rompers and Baby Boy Camo Rompers Two Pack', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received two reports of snaps detaching from the rompers. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled rompers away from children and return the rompers to any The Children''s Place store for a full refund. The company will send an email notice to all customers who bought the product on the firm''s website with instructions on how to receive a full refund for the recalled products.', '22170');
INSERT INTO safety_incidents VALUES ('c17a84b268e3b80393c5386f3de84e3868f45669', 'CPSC', '2022-06-16', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Kroger Arthritis Pain Acetaminophen, 225 count bottles', 'The Recalled Over-The-Counter Product Contains The Regulated Substance Acetaminophen Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled product in a safe location out of reach and sight of children. Contact Kroger for information on how to properly dispose of the product and receive a full refund.', '22164');
INSERT INTO safety_incidents VALUES ('5594d22f03c9401af6630b58b25b5f1671bcb3bc', 'CPSC', '2022-06-16', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Walgreens Pain Reliever Acetaminophen, 150 count bottles', 'The Recalled Over-The-Counter Products Contain The Regulated Substance Acetaminophen Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach and sight of children. Contact Aurohealth for information on how to return the product at your nearest Walgreens store to receive a full refund.', '22161');
INSERT INTO safety_incidents VALUES ('36de61384153ea059be48d9c6745422ca8f726e8', 'CPSC', '2022-06-16', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Children''s pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear away from children and contact Loulou Lollipop for a full refund. Consumers who purchased the sleepwear will be asked to destroy the garments by cutting them in half and sending the firm a photo of the destroyed product, including the neck label. Upon receipt of the photos, consumers will be issued a full refund or a store gift card. The firm is contacting all known purchasers directly.', '22165');
INSERT INTO safety_incidents VALUES ('ae162ab53fb7bfc3cceb3abb2ff584a8937f2a0d', 'CPSC', '2022-06-16', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Wooden xylophone Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled xylophone and return it to a Primark store for a full refund.', '22167');
INSERT INTO safety_incidents VALUES ('a0f1302ee8639fb339a96d2e956fe3bf67b73276', 'CPSC', '2022-06-16', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Square™ D QO™ Plug-on-Neutral Load Centers, also known as, Load Centers, Breaker Boxes, Electrical Panels', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received one report of an incident of a loose wire. No injuries have been reported.', 'Minor', 1, 0, 'Schneider Electric is directly contacting all known retailers, distributors, homeowners, and any other individuals that purchased or installed the recalled product. All purchasers and installers should immediately contact Schneider Electric to arrange to have the recalled load centers inspected by trained electricians to determine if replacement or repair is required. This inspection and any resulting replacement or repair is free of charge. Consumers can find the catalog number and date code on indoor load centers inside the door of the panel. Consumers should immediately contact Schneider Electric to arrange to have the recalled load center inspected by a trained electrician to determine if repair is required. This inspection and any resulting repair is free of charge. Consumers who continue to use the load centers while awaiting the free repair should have working smoke alarms in their homes. For uninstalled products, consumers should contact Schneider Electric for a free repair or replacement.', '22159');
INSERT INTO safety_incidents VALUES ('975667eabe8ca27568f9184f85f9b06f5d2ced95', 'CPSC', '2022-06-16', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'WarmWave and Hunter Oscillating Ceramic Tower Heaters', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received eight customer reports of fire at the plug or cord and dozens of customer reports of the plug or cord overheating. There have been no reports of injury or death and one report of minor property damage.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled heaters, unplug the unit, and follow the instructions online at (www.homeproductservice.com/recall) on how to properly sever the electrical cord to make the unit unusable, and contact the distributor, Sienhua Group (North America), to receive a prorated refund.', '22168');
INSERT INTO safety_incidents VALUES ('b8ce773aee649961c201c58e88438579065af920', 'CPSC', '2022-06-16', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Kroger Acetaminophen, 100 count bottles', 'The Recalled Over-The-Counter Product Contains The Regulated Substance Acetaminophen Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach and sight of children. Contact Kroger for information on how to properly dispose of the product and receive a full refund.', '22162');
INSERT INTO safety_incidents VALUES ('b0d1806c93a466469a30e7769f96aae0fcc64801', 'CPSC', '2022-06-16', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Kroger Aspirin, 300 count bottles and Ibuprofen, 160 count bottles', 'The Recalled Over-The-Counter Products Contain The Regulated Substances Aspirin And Ibuprofen Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach and sight of children. Contact Kroger for information on how to properly dispose of the product and receive a full refund.', '22160');
INSERT INTO safety_incidents VALUES ('6ad0ca72bf02cb89d8cb7cc6b603ab7a2206870a', 'CPSC', '2022-06-16', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Children''s Desks and Chairs', 'Surface Paint On The Desks And Chairs Contains Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Lead Poisoning Hazard. The Desks And Chairs Also Fail To Comply With The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled children''s desks and chairs and return them to a Times Tienda store for a full refund.', '22166');
INSERT INTO safety_incidents VALUES ('9b293a1dee6791ecc20645c9bfd9c9bf07f8722e', 'CPSC', '2022-06-16', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Nest Swing Egg Chairs', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received 27 reports of the chairs collapsing or tipping over, including 19 reports of injuries, including cuts, scrapes, soreness and one report of broken ribs and a collapsed lung.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled egg chairs and return them to any Marshalls, T.J. Maxx, HomeGoods, or Homesense stores for their choice of either a full refund or a refund in the form of a store gift card. Consumers can also contact TJX for instructions on how to disassemble and dispose of the chair to receive either a full refund or refund in the form of a store gift card.', '22163');
INSERT INTO safety_incidents VALUES ('27cfe4da96e9365958f4c241d81bfcb92198355a', 'CPSC', '2022-06-09', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Brompton Electric Folding Bicycles', 'Injury', 'Chemical / Toxic Substance', 'Fracture / Blunt Trauma', 'The firm has received 10 reports of faulty mudguards causing the bikes to crash, resulting in nine reports of injuries, including head and facial impact, broken bones, shoulder dislocation, bruising, and chipped teeth and two reports of hospitalizations.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact an authorized Brompton dealer for a free repair, which replaces the front mudguard stay and flap and increases the clearance between the mudguard and tire.', '22155');
INSERT INTO safety_incidents VALUES ('e7711e2ec797f564fec3d2e1b86b4f3f1b4de637', 'CPSC', '2022-06-09', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Hisense French Door Refrigerators with Ice Maker', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 139 reports of the refrigerator doors loosening or detaching and five reports of injuries, including foot bruises and lacerations.', 'Moderate', 1, 0, 'Consumers should immediately stop using the refrigerator if the recalled refrigerator''s doors fail to open or close normally until they are repaired. Consumers should contact Hisense USA to determine if their unit is part of the recall and to schedule a free in-home service appointment to have the refrigerator door hinges replaced.', '22151');
INSERT INTO safety_incidents VALUES ('1ed850e6ccf146653a2c985b6b1d53baa6aa5f3b', 'CPSC', '2022-06-09', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Intimidator and Mahindra branded utility vehicles (UTVs)', 'The Throttle Cable Can Freeze At Low Ambient Temperatures, Resulting In A Stuck Throttle Which Can Cause The Brakes To Fail To Stop The Vehicle, Posing A Crash Hazard. Additionally, On Certain Model Year 2022 Intimidator Gc1K Vehicles, The Onboard Software Does Not Prevent Consumers From Exceeding 15 Mph When The Seatbelt Is Disengaged, Posing A Crash Hazard.', 'Other', 'Fracture / Blunt Trauma', 'Intimidator has received 393 reports of throttle cables freezing, including four reports of crashes resulting in bruises. There were no incidents of excess speed when the seatbelt is disengaged.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact an Intimidator or Mahindra authorized dealer to schedule a free repair and to receive a software update/fix for the speed limiter.', '22152');
INSERT INTO safety_incidents VALUES ('2fd52ffe56d3ce3188eaaf596f6c7d1c05b1a0a8', 'CPSC', '2022-06-09', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Jungle Jumparoo Children''s Toys', 'The Toys'' Yellow Poles Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled toys and contact Jungle Jumparoo for information on how to properly dispose of the yellow poles and to receive free replacement poles, including shipping. Jungle Jumparoo is contacting all known purchasers directly.', '22750');
INSERT INTO safety_incidents VALUES ('4389a48aee8be2df86222ed1ef9ac21b2bba018c', 'CPSC', '2022-06-09', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Nautilus Treadmills', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Nautilus has received 21 reports of the treadmills self-starting. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled treadmills and contact Nautilus to receive a free USB flash drive with a software upgrade and installation instructions. Nautilus will automatically ship the USB flash drive and instructions at no cost to customers who purchased the treadmills directly from Nautilus. The instructions will direct consumers to plug the flash drive into the USB port on the treadmill to upload the software upgrade.', '22153');
INSERT INTO safety_incidents VALUES ('257447ff83190f79c4bd6c60b2ce113be94841d8', 'CPSC', '2022-06-09', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Spirit Halloween 48" Black Lights', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received seven reports of bulbs popping, flashing, and catching on fire or smoking, including one mild burn injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled black light fixtures and contact Spirit Halloween for a full refund. Consumers should send a photo of the date code to the firm and then will receive a full refund and instructions on how to destroy and dispose of the product.', '22154');
INSERT INTO safety_incidents VALUES ('be08e8520e6cd95d006590f70dba3baf0d05682c', 'CPSC', '2022-06-09', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Activity Loops', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received three reports of the tubes detaching from the base. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Activity Loops toys, take the toys away from children and return them for a full refund either to the place of purchase or directly to Manhattan Toy. Manhattan Toy will supply a prepaid shipping label for returns directly to the company.', '22156');
INSERT INTO safety_incidents VALUES ('e9bc59d0c891ebedb9435c186434bdbdd515a619', 'CPSC', '2022-06-02', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Wonder & Wise Baby Activity Walkers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Asweets has received 10 reports of the rubber rings detaching from the wheel of the product. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled walkers away from children, stop using them until repaired and contact Asweets for instructions on getting free replacement rear wheels.', '22146');
INSERT INTO safety_incidents VALUES ('d27594c4ebb8c11b8a775932ff3e67292558d9e8', 'CPSC', '2022-06-02', 2022, '2022-06', 'USA', 'United States', '', 'Other', '6" Aflac Plush Promotional Ducks', 'Components Of The Recalled Promotional Ducks Contain Levels Of Certain Phthalates That Exceed The Federal Phthalate Content Standard. A Component Of The Promotional Fishing Duck Also Contains A Level Of Lead That Exceeds The Federal Lead Content Standard. Phthalates And Lead Are Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using and dispose of the recalled plush promotional ducks. Communicorp is contacting Aflac employees and licensed agents who purchased these plush promotional ducks directly.', '22141');
INSERT INTO safety_incidents VALUES ('b774955ebcbbcfae0320b21fd676278e0176562a', 'CPSC', '2022-06-02', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Microwavable bowl holders', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received three reports of incidents of charring from the bowl holders catching fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the microwavable bowl holders and contact Demdaco for a full refund. Consumers can return the bowl holder to the place where it was purchased or request free return shipping by contacting Demdaco directly.', '22144');
INSERT INTO safety_incidents VALUES ('e59ab29a7f3888f5db4bb46beb93b9ef923cbb86', 'CPSC', '2022-06-02', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Frigidaire and Electrolux Side-by-Side, Top Freezer and Multi-door refrigerators', 'Choking', 'Sharp Edges / Points', 'Laceration / Cut', 'Electrolux has received 185 reports of the ice level detectors breaking, including one report of gum lacerations.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Frigidaire and Electrolux refrigerator ice makers, empty the ice bucket and contact Electrolux to schedule a technician to replace the ice maker with one that has a polypropylene ice level detector, free of charge.', '22143');
INSERT INTO safety_incidents VALUES ('ebeeb8c1d054bb7d58814e67f8b2b777f22c68f7', 'CPSC', '2022-06-02', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Backcountry Access Tracker4 Avalanche Transceivers', 'The Toggle Switch Can Separate From The Transceiver, And Prevent The Transceiver From Switching To Search Mode, Making It Difficult To Locate A Skier In An Avalanche, Which Can Result In Severe Bodily Harm Or Death If A Skier Is Buried Under Snow.', 'Other', 'Fracture / Blunt Trauma', 'Elevate Outdoor Collective has received 14 reports of broken toggle switches. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Tracker4 Avalanche Transceiver and contact Backcountry Access to receive a prepaid shipping label to return the recalled transceiver for a free replacement transceiver.', '22147');
INSERT INTO safety_incidents VALUES ('6de665d22f924258abc60697fc9a5d4980628365', 'CPSC', '2022-06-02', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Children''s robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using them and contact Joey Clothing for a full refund. Consumers who purchased the robes from Amazon.com will be contacted through Amazon''s messaging platform. Consumers who purchased the robes directly from Joey Clothing, Nordstrom Rack and Zulily will be contacted via email.', '22145');
INSERT INTO safety_incidents VALUES ('26466c74c74c3c2047c071a619551b774395e0d1', 'CPSC', '2022-06-02', 2022, '2022-06', 'USA', 'United States', '', 'Other', 'Children''s pajama sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajama sets away from children and return the pajama sets to any Target store location for a full refund. Consumers who purchased the pajama sets on Target.com can contact Target to receive a prepaid return label to return the pajama set for a full refund. The firm is contacting known purchasers directly regarding the recall.', '22142');
INSERT INTO safety_incidents VALUES ('f227e150658cc0f9c866646fe8c8fef79c1abb74', 'CPSC', '2022-05-26', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'Wonder & Wise Activity Tables', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Asweets has received five reports of screws on the xylophone becoming loose or detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled activity tables, store them away in a place children cannot access until repaired, and contact Asweets for a free repair kit, including shipping. The repair kit includes a replacement tabletop that includes a block sorting activity in place of the xylophone.', '22138');
INSERT INTO safety_incidents VALUES ('f125fc41493332e551d2a9deb891eae74349ee38', 'CPSC', '2022-05-26', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'Children''s pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear away from children and contact Copper Pearl for a full refund. Consumers who purchased the sleepwear directly from Copper Pearl will be contacted via email and provided prepaid mailers to return the garment(s) for a full refund. Consumers who purchased the sleepwear at retail locations will be asked to destroy the garments by cutting them in half and sending the firm a photo of the destroyed product, including the neck label. Upon receipt of the photos, consumers will be issued a full refund and a 20% off discount code towards another purchase.', '22139');
INSERT INTO safety_incidents VALUES ('d0fe5cc6a88c043f93a5297190a8431d23788c97', 'CPSC', '2022-05-26', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'Children''s pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children and contact Free Birdees for a full refund. Consumers who purchased the sleepwear garments will be asked to destroy the garments by cutting them in half and send the recalling firm a photo of the destroyed garment and of the garment''s neck label. Upon receipt of the photos, consumers will be issued their choice of either a full refund or a store gift card. Free Birdees is contacting all known purchasers directly.', '22749');
INSERT INTO safety_incidents VALUES ('2960c3994925f038381df4de762bbca4d0e7ec7f', 'CPSC', '2022-05-19', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'Hover-1 Superfly Hoverboards', 'Electric Shock', 'Mechanical Failure', 'Fall Injury', 'The firm has received 29 reports of a software issue that caused the hoverboard to provide continued assistance when the rider was not actively controlling the hoverboard. Four minor injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled hoverboards and contact DGL Group for instructions on how to ship affected units to an authorized repair shop free of charge.', '22135');
INSERT INTO safety_incidents VALUES ('4d39742a051311effdc37ada8acd36870546b089', 'CPSC', '2022-05-19', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'Coffee cups', 'Burns', 'Drowning Risk', 'Burns', 'Moderne Glass Company has received six reports of cups cracking after pouring hot water into them. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled coffee cups and contact Moderne Glass Company to receive a full refund. Moderne Glass Company is contacting all known purchasers directly.', '22748');
INSERT INTO safety_incidents VALUES ('643e2b4796b4ed11b05b7f45b25e5a948f15fab6', 'CPSC', '2022-05-12', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'Off-Road Side-by-Side vehicles', 'Fire', 'Explosion', 'Not Specified', 'The firm has received two reports of the fuel tanks being assembled incorrectly. There were no incidents of fuel leakage, and no injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact an authorized Yamaha dealer to schedule a free inspection and repair. Yamaha is contacting all registered owners directly.', '22747');
INSERT INTO safety_incidents VALUES ('64b7ca42e9bba4fc68092ca530a8aa69013e67c4', 'CPSC', '2022-05-05', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'BIBS Baby Bottles', 'Burns', 'Other', 'Burns', 'The firm has received one report of the bumper shrinking and bottle tilting. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled BIBS baby bottles with the bumper and either return the product to BIBS for a full refund or remove and throw out the bumper and use the product without the bumper. If you purchased the bottle online through the BIBS website and wish to return it, contact BIBS Denmark ApS for free shipping.', '22133');
INSERT INTO safety_incidents VALUES ('86c1b88bf9dd2a39c961d8d2267230daf18f6b90', 'CPSC', '2022-05-05', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'Children''s robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children, stop using them and contact NewCosplay for a full refund. Consumers who purchased the robes from Amazon.com will be contacted through Amazon''s messaging platform and provided prepaid mailers to return the products for a full refund. Consumers can also contact NewCosplay to request a postage prepaid mailer to return the products for a full refund.', '22129');
INSERT INTO safety_incidents VALUES ('1859eeacc76ed81d202dc40cded8051a003af702', 'CPSC', '2022-05-05', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'Children''s Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children and contact Linum Home Textiles to receive a pre-paid mailer and instructions on how to return the robe(s) for a full refund. The firm is also contacting consumers who purchased the robes directly from Linum Home Textiles.', '22128');
INSERT INTO safety_incidents VALUES ('183ef2f8b7a8403fe6a79cb9f8d66e75e3bd1d4f', 'CPSC', '2022-05-05', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'Santa Cruz Bicycles 2022 Heckler 9 Electric Bicycles', 'Fire', 'Mechanical Failure', 'Fall Injury', 'Santa Cruz Bicycles has received 10 reports of batteries falling from the frame and two reports of the latch spring causing added wear on the battery housing. No injuries or fires have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact their authorized Santa Cruz Bicycle dealer to arrange for a free repair to replace the latch spring mechanism and install a battery wear plate. Consumers who purchased the bicycle online or no longer reside near their dealer should contact the firm or visit http://santacruzbicycles.com/dealers. Consumers should remove or secure the battery prior to transporting the bicycles. The firm is contacting all known purchasers directly to provide more details about the repair.', '22132');
INSERT INTO safety_incidents VALUES ('8985ae46a724662580d490c414b1d26f2fb127ba', 'CPSC', '2022-05-05', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'Infant French terry jumpsuits, rompers, snap suits, baby dresses and bibs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 29 reports of snaps detaching between the prong ring and the stud or socket piece. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled jumpsuits, rompers, snap suits, baby dresses and bibs and contact Winter Water Factory for instructions on how to receive a full refund or a refund in the form of a store credit. Consumers should destroy the recalled garments by cutting them in half with scissors and then upload a photo of the destroyed garment(s) to the company''s website at www.winterwaterfactory.com/pages/recall. Upon receipt of the photo, consumers will be issued their choice of a full refund of the purchase price or a store credit with an additional 20% of the purchase price.', '22130');
INSERT INTO safety_incidents VALUES ('6ea3f838f60c74ec9d39b2f389736a25148acf51', 'CPSC', '2022-05-05', 2022, '2022-05', 'USA', 'United States', '', 'Other', 'GreenSpeed Magnum and Magnum XL recumbent trikes with quick release front axles and replacement Quick Release Axles', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled trikes and return them to the place of purchase for a free repair. The axles will be sent to GreenSpeed/WizWheelz for repair or replacement. The firm is contacting all known purchasers about the recall.', '22131');
INSERT INTO safety_incidents VALUES ('30cc7ab1d695b4cb2eb81dabfda9b8c5257eaa4d', 'CPSC', '2022-04-28', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'AmazonBasics School Classroom Stack Chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm received 55 consumer reports of the chairs breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and contact Amazon for instructions on how to dispose of the chairs for a full refund. Amazon is contacting all known purchasers directly.', '22743');
INSERT INTO safety_incidents VALUES ('b2309578e79d0d72645984738ea95051449cd92d', 'CPSC', '2022-04-28', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'H for Happy™ Woven Bunny Baskets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled baskets away from children and return them to any Bed Bath & Beyond location for a full refund.', '22126');
INSERT INTO safety_incidents VALUES ('6c6a95a0117e23a111cfe8ed4a9e3642dba1290f', 'CPSC', '2022-04-28', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Best Naturals Organic Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using and store the product in a safe location out of reach and sight of children. Contact Best Nutritionals for information on how to properly dispose the product and receive a full refund. Best Nutritionals is contacting all known purchasers directly.', '22745');
INSERT INTO safety_incidents VALUES ('348cdde89f84b191d961aeaaaf9bd153b2699962', 'CPSC', '2022-04-28', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Electric Start Pressure Washers', 'The Electronic Start/Stop Button On The Pressure Washer Can Malfunction And Self-Start, Posing A Risk Of Carbon Monoxide Poisoning If The Unit Is In A Confined Space.', 'Mechanical Failure', 'Poisoning / Ingestion', 'The firm has received nine reports of the pressure washers self-starting and operating without being connected to a water supply. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pressure washer unless they have removed the rechargeable battery, and contact Generac to arrange to have an authorized dealer replace the start/stop switch on the pressure washer free of charge. The pressure washer can continue to be used with the battery removed but using the pull-start option to start the unit. Generac is contacting known consumers directly to provide more details about the repair.', '22127');
INSERT INTO safety_incidents VALUES ('e887206290246219ca9184bad002592c5b81ada3', 'CPSC', '2022-04-28', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Model Year 2022 RZR Pro R 4 Premium and RZR Pro R 4 Ultimate Recreational Off-Road Vehicles', 'Fire', 'Electrical Fault', 'Not Specified', 'The firm has received one report that a vehicle lost power after start up. No injuries or fires have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair. The dealer will re-route the battery cable, and if needed, replace it free of charge. Polaris has notified consumers to stop riding the vehicles and is contacting registered owners directly to provide more details about the repair.', '22744');
INSERT INTO safety_incidents VALUES ('da4c215202f53bedcefbb9fbad83442e99e70e5e', 'CPSC', '2022-04-28', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Off-road motorcycles', 'The Gear Shift Assembly Can Detach From The Crankcase, Resulting In Unintentional Gear Shifting, Posing A Crash Hazard.', 'Mechanical Failure', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled off-road motorcycles and contact their local Yamaha dealer to schedule a free repair. Yamaha is contacting all registered owners directly.', '22746');
INSERT INTO safety_incidents VALUES ('0a25747f8724e8870225367685406bf45454e359', 'CPSC', '2022-04-21', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Insignia Air Fryers and Air Fryer Ovens', 'Fire', 'Flammability / Overheating', 'Burns', 'Best Buy has received 68 reports from U.S. consumers and 36 reports from Canadian consumers of the air fryer or air fryer ovens catching fire, burning or melting. These include seven reports of minor property damage and two reports of injuries, including an injury to a child''s leg.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled air fryers and air fryer ovens and return the product to Best Buy for a refund in the form of a credit for use at Best Buy stores or Bestbuy.com. Best Buy is contacting all known purchasers directly to arrange returns and providing pre-paid shipping boxes and labels and return instructions. Consumers will receive a credit of $50 or the amount on the purchase receipt if higher. Consumers do not need a purchase receipt to get the $50 credit.', '22125');
INSERT INTO safety_incidents VALUES ('db4c89edf453dd5acdc801d81675ce4d54b8d1fb', 'CPSC', '2022-04-21', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Overhead Garage Storage Racks', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'SafeRacks/Monsterrax has received 55 reports of the racks falling, including one report of an injury where the corners of a ceiling mounted rack fell and bruised and cut a consumer''s face.', 'Moderate', 1, 0, 'Consumers with the recalled Overhead Garage Storage Racks should immediately unload all items from the racks and contact SafeRacks/Monsterrax to receive free replacement bolts. SafeRacks/Monsterrax has contacted all known purchasers of the Overhead Garage Storage Racks to provide free replacement bolts.', '22742');
INSERT INTO safety_incidents VALUES ('b6dd6d8cf330bbd21a568c080cf4a5244052f175', 'CPSC', '2022-04-21', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Nectar® Premier Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should contact Nectar Sleep for a free replacement mattress (including free delivery) or a full refund, to be provided after free removal and disposal of the recalled mattress through Elite Comfort Solutions. Nectar Sleep is contacting all known purchasers directly.', '22740');
INSERT INTO safety_incidents VALUES ('44c30e4dfcf12ae603ba7d6e25c948ee2bcc3f7a', 'CPSC', '2022-04-21', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Monti Kids Wooden Push Toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Monti Kids has received 145 reports of the toy''s rolling cylinder separating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled toy away from children, dispose of the toy by throwing it into the trash, and contact Monti Kids to receive a $40 refund. The firm is contacting all known purchasers directly.', '22741');
INSERT INTO safety_incidents VALUES ('b13f928e31f7b4b0ba812b50cbe38c662b83f146', 'CPSC', '2022-04-21', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'LUXE+WILLOW Heated Blankets', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received three reports of the blankets overheating, including one report of a burn to a consumer''s wrist. One consumer reported seeing flames.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled electric blanket and contact MWA for a full refund or $50 voucher towards the purchase of another LUXE+WILLOW product. Consumers should unplug the electric blanket, cut the electrical cord and submit a photo of the blanket''s cut cord and labeling on the blanket to the firm at support@luxewillow.com as proof of destruction and to receive the refund or $50 voucher. After submitting proof of destruction to the firm, consumers should dispose of the recalled blanket. The firm is contacting all known purchasers directly.', '22123');
INSERT INTO safety_incidents VALUES ('97bfc7ba4dfbdad0da5eb52c43047990112a49c1', 'CPSC', '2022-04-21', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Norwex Ceramic Knives', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 188 reports of incidents, including 158 reports of the handle breaking and 30 reports of damage to the knives during shipping. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ceramic knives and contact Norwex USA for information on how to obtain a free replacement and to request a return kit which includes a pre-paid return shipping label.', '22122');
INSERT INTO safety_incidents VALUES ('de1212c7ab02ee1aa13ab29c1225d0ea70870cd8', 'CPSC', '2022-04-21', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Children''s pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children and contact The Red League to receive a pre-paid mailer and instructions on how to return the garment(s) for a full refund. The firm is also contacting consumers who purchased the pajamas directly from The Red League to provide them a prepaid mailer to return the garment for a full refund.', '22124');
INSERT INTO safety_incidents VALUES ('14b51efc618ee39cae65fbb662a94abe44a4544e', 'CPSC', '2022-04-14', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Shell Diving Inflation Valves with Int''l Nipples for diving dry suits', 'The Internal Part In The Valve Can Malfunction While In Use, Causing Loss Of Inflation And Thermal Protection, Posing A Risk Of Hypothermia To The Consumer.', 'Mechanical Failure', 'Not Specified', 'SI Tech has received three reports of the valve part malfunctioning, resulting in loss of inflation in the dry suit. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the dry suits with the recalled inflation valve and contact Ocean Equipment to receive a notification form and shipping information to return the recalled valve free of charge. The valve part will be replaced by trained technicians who are exclusively authorized to update the valve with a free replacement valve part.', '22115');
INSERT INTO safety_incidents VALUES ('13a2742db9b711097bfe95375b25a6138f091a95', 'CPSC', '2022-04-14', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Crafter''s Square Glue Guns', 'Fire', 'Mechanical Failure', 'Skin Irritation', 'Dollar Tree has received seven reports of electrical malfunctions when using the glue guns, including four reports of fire and one report of skin irritation.', 'Moderate', 1, 0, 'Consumers should immediately unplug and stop using the Crafter''s Square Glue Gun and return it to any Dollar Tree or Family Dollar store for a full refund. Online purchasers will be contacted directly with further instructions.', '22120');
INSERT INTO safety_incidents VALUES ('e417bc7f4fd9e82be5bd1a204aba4016d4681398', 'CPSC', '2022-04-14', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'GE-brand Free-Standing French Door Refrigerators in Fingerprint Resistant Stainless Steel', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received 71 reports of the freezer drawer handle detaching, resulting in 37 reported injuries, including three serious fall injuries.', 'Moderate', 1, 0, 'Consumers should contact GE Appliances to determine if their unit is part of the recall and to schedule a free in-home service call to have the freezer''s handle mounting fasteners replaced and the handle re-installed and for instructions for safe use pending a repair. The firm is contacting all known purchasers directly.', '22117');
INSERT INTO safety_incidents VALUES ('e6120b6bcc1fc4d103f0602bc0220974000da027', 'CPSC', '2022-04-14', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'FAO Schwarz Toy Wood Play Smart Robot Buddy(s) and FAO Schwarz Toy Wood Sensory Boards', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received 20 reports of small parts coming loose or falling off of the toys, including nine reports of parts coming loose or falling off of the Toy Wood Play Smart Robot and 11 reports of parts coming loose or falling off of the Toy Wood Sensory Board. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled toys away from children, stop using them and contact MerchSource to receive a pre-paid label to return the recalled toys and instructions on how to receive a full refund.', '22116');
INSERT INTO safety_incidents VALUES ('cfb004fded94a2fa790c09bdb356e0f32a4ccbb9', 'CPSC', '2022-04-14', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Craftsman 30" Mini and Troy-Bilt TB30 Riding Lawn Mowers', 'The Riding Mowers Can Fail To Come To A Complete Stop And Continue To Move At A Speed Of About One Mile Per Hour When The Clutch/Brake Pedal Is Fully Depressed, Posing A Low Speed Crash Hazard.', 'Other', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled lawn mowers and contact Craftsman or Troy-Bilt for a free inspection and repair. Consumers will be assisted in contacting a local repair shop to have a replacement drive belt installed at no cost to the consumer. Pickup and delivery of the lawn mower will be arranged if necessary at no cost to the consumer.', '22119');
INSERT INTO safety_incidents VALUES ('1070bbd23f89aded996b88acb59c8bc0202c8fa8', 'CPSC', '2022-04-14', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Rae Prenatal Capsules and Rae Immunity Capsules', 'The Products Are Dietary Supplements Containing Iron Which Must Be In Child-Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child-Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach of children and contact Rae Wellness for information on how to dispose of the product and receive a full refund. Consumers can also contact the place of purchase for a full refund.', '22114');
INSERT INTO safety_incidents VALUES ('b4a5af1082103f281934ab937befa029abbe0eaf', 'CPSC', '2022-04-14', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Hempväna Ultra Strength Pain Relief Cream with Lidocaine, Hempväna Ultra Strength Pain Relief Cream Night with Lidocaine, Hempväna Ultra Strength Pain Relief Cream Turmeric with Lidocaine, Hempväna Pain Relieving Hand & Body Lotion with Lidocaine', 'The Products Contain The Substance Lidocaine Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed Or Placed On The Skin Of Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled products and store them in a safe location out of sight and reach of young children. Contact Telebrands for information on how to safely dispose of the recalled products and how to receive a full refund or a free child resistant closure for the jar products. In addition, Telebrands is providing a $15 digital coupon code good toward the purchase of any Hempväna products at www.Hempvana.com.', '22118');
INSERT INTO safety_incidents VALUES ('0a0f0e6c6fac101edf562dd3a628fd39cf6871fb', 'CPSC', '2022-04-07', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Bestar Wall Beds', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'In July 2018, a 79-year-old woman died after a Bestar wall bed fell on her, injuring her spine.Bestar has received reports of 60 additional incidents resulting in bruising and other injuries from the wall beds detaching and hitting consumers.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled wall beds and consult the communication they received from Bestar. Consumers who are uncertain whether their wall bed needs to be reinstalled are entitled to a free inspection.', '22739');
INSERT INTO safety_incidents VALUES ('f9a4dfadaec318f48b14fee959b5839511acbf1d', 'CPSC', '2022-04-07', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'biOrigins Sodium Hydroxide Products', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled product in a safe location out of reach of children and contact Madar Corporation for a full refund and a free warning label. Madar Corporation is contacting all purchasers directly.', '22738');
INSERT INTO safety_incidents VALUES ('2b1e4e5f78bab158b746c86e3ab41390bedb6d14', 'CPSC', '2022-04-07', 2022, '2022-04', 'USA', 'United States', '', 'Other', 'Clikk high chairs', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'Stokke has received six reports of the seat breaking, including two reports of minor bruises.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled white high chairs and contact Stokke for a free replacement. Consumers will receive the free replacement Clikk high chair in white after visiting Stokke''s website to confirm their product is included in the recall and registering the product online.', '22113');
INSERT INTO safety_incidents VALUES ('cc8ab5dc641d810bcdd12299c709f42f45c42984', 'CPSC', '2022-03-31', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Helix Metal Lockable Drug Chests', 'The Locking Mechanism Can Fail Allowing Access To The Contents Inside The Chest, Posing A Risk Of Poisoning.', 'Other', 'Poisoning / Ingestion', 'Maped Helix USA has received two reports of the locking mechanism failing. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chests until repaired and contact Maped Helix USA to be shipped a free consumer-installable repair kit.', '22109');
INSERT INTO safety_incidents VALUES ('a4a93152519d067605b212b9ae0890f0eb81c1ef', 'CPSC', '2022-03-31', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Kid O Hudson® Glow Rattles', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received three reports of the rattle legs breaking off. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled rattles away from children, stop using them, and contact PlayMonster for instructions on receiving a $25 refund. PlayMonster will provide consumers with a prepaid shipping label to return the recalled product.', '22110');
INSERT INTO safety_incidents VALUES ('6c683753747497f5717c4cb654986a5708a828fc', 'CPSC', '2022-03-31', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'SOUNDBOKS (Gen. 3) Bluetooth Speakers with Lithium-Ion Batteries', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled speakers, remove the battery and contact the firm to receive a new battery including shipping. SOUNDBOKS will provide free replacement lithium-ion batteries and a $100 credit toward purchases at SOUNDBOKS web shop, as well as instructions for properly disposing of lithium-ion batteries according to federal and state regulations. SOUNDBOKS has notified all known owners directly to stop using the recalled speakers.', '22737');
INSERT INTO safety_incidents VALUES ('44ae78cc223f1a62c81eb18ab88ccfed92c96789', 'CPSC', '2022-03-31', 2022, '2022-03', 'USA', 'United States', '', 'Other', '2-in-1 Photoelectric Smoke & Fire + Carbon Monoxide Alarms', 'The Alarms Can Fail To Alert Consumers To The Presence Of A Hazardous Level Of Carbon Monoxide, Posing A Risk Of Carbon Monoxide Poisoning Or Death. Carbon Monoxide (Co) Is An Odorless, Colorless, Poisonous Gas.', 'Other', 'Poisoning / Ingestion', 'Universal Security Instruments has received two reports of units that failed to alarm for the presence of carbon monoxide within the specified time requirement. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately contact Universal Security Instruments for a free replacement alarm. Consumers should keep using the recalled alarms until they install replacement alarms.', '22111');
INSERT INTO safety_incidents VALUES ('cfd81043b01ee58a738039f1153bac06112dac9c', 'CPSC', '2022-03-24', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'tonies® Blocks', 'When Two Or More High-Powered Magnets Are Swallowed, Either Intentionally By Younger Children Or Accidentally By Older Children, The Ingested Magnets Can Attract To Each Other, Or To Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Mechanical Failure', 'Poisoning / Ingestion', 'tonies has received one report of the magnet detaching from the product. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should stop using the recalled blocks with magnets immediately, take them away from children, and contact tonies for instructions on returning the recalled blocks for a full refund. Consumers can also go to https://tonies.happyreturns.com/ and choose "Blocks Return" as the reason for return. tonies will then provide the customer with a return label. After the product has been received, tonies will provide the initial form of payment with a full refund and an additional $14.99 tonies.com coupon code. tonies is also contacting all purchasers directly. The recalled products are being remotely deactivated so that they no longer function.', '22736');
INSERT INTO safety_incidents VALUES ('f9c2b7b2c4e7d08304785d21f499e9e6a51962d4', 'CPSC', '2022-03-24', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Commencal Ramones 14-Inch Bicycles', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled bikes away from children, stop using them, and contact the firm for a free repair kit. Commencal Corp. is contacting all purchasers directly by email.', '22735');
INSERT INTO safety_incidents VALUES ('afd6c5043f3f69022b7cb25ba04e078dc34f5445', 'CPSC', '2022-03-24', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'EGL and ACE-branded Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact EGL Motor to make an appointment for a free repair from an authorized repair shop. Reflectors, headlights and a chest protector will be installed on the ATV. EGL will also repair the parking brake, speed capability and spark arrestor.', '22108');
INSERT INTO safety_incidents VALUES ('fe18bcc77e0449a27b9d1c9bbfe2593a9587faa3', 'CPSC', '2022-03-24', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Dimensions Bluetooth Speaker Helmets', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Sakar for instructions on receiving a free replacement helmet. Consumers should not return the helmet to Walmart and should contact Sakar for a free replacement and to facilitate returns using prepaid postage packaging. Walmart will contact all known purchasers.', '22106');
INSERT INTO safety_incidents VALUES ('536466418563f9c2722e1ea16eeae379cabbe172', 'CPSC', '2022-03-24', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Ninebot Children''s Bicycle Helmets', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and return them to Segway for a full refund. Segway is contacting all known purchasers to facilitate returns using prepaid postage.', '22107');
INSERT INTO safety_incidents VALUES ('d5098f9615c4a3551b216188818bdc2727a97072', 'CPSC', '2022-03-17', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'PhysiciansCare brand Aspirin, Extra Strength Non Aspirin, Extra Strength Pain Reliever, Ibuprofen, Medication Station, and Multi-Pack', 'The Recalled Over-The-Counter Products Contain Regulated Substances (Aspirin, Acetaminophen, Or Ibuprofen) Which Must Be In Child Resistant Packaging When Being Used In The Household As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach of children and contact Acme United for information on how to dispose of or return the product and receive a full refund. Acme United is contacting all purchasers directly.', '22733');
INSERT INTO safety_incidents VALUES ('acaf39e52f9f5fc16f1987dd73826dad0a6a0bb3', 'CPSC', '2022-03-17', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'DigitDots 3mm and 5mm Magnetic Balls', 'When Two Or More High-Powered Magnets Are Swallowed, Either Intentionally By Younger Children Or Accidentally By Older Children, The Ingested Magnets Can Attract To Each Other, Or To Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning And Death.', 'Other', 'Poisoning / Ingestion', 'HD Premier is aware of four children who have ingested DigitDots and required surgery to remove the magnets. In addition, CPSC is aware of other reports of children and teenagers ingesting other companies'' high-powered magnets and requiring surgery, including two deaths.', 'Fatal', 1, 0, 'Consumers should stop using the recalled magnets immediately, take them away from children and contact HD Premier to receive a pre-paid label to return the recalled products. Upon receipt of the products, consumers will receive a refund.', '22101');
INSERT INTO safety_incidents VALUES ('f0aeff4b72ba62335e70c8fc589d5ac35f8fbcbb', 'CPSC', '2022-03-17', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'ToolGuards Portable Water Immersion Heaters', 'Fire', 'Electrical Fault', 'Electric Shock', 'The firm has received 19 reports of the recalled water immersion heaters overheating, melting or catching fire and two reports of consumers being shocked.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled portable water immersion heaters and contact FXswede AB for a full refund. Consumers should unplug the water immersion heaters, cut the electrical cord and submit a photo of the water immersion heater and the cut cord, and the Amazon order number if available, to the firm at recall@fxswede.com as proof of destruction and to receive the refund. Consumers should dispose of the recalled water immersion heater and the cut cord after submitting proof of destruction. The firm is contacting all known purchasers directly.', '22734');
INSERT INTO safety_incidents VALUES ('124982c4194e2512cf4c19e68978d1492ba6f39b', 'CPSC', '2022-03-16', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'B. toys Wooden Activity Walker - Walk ''n'' Learn', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Battat has received six reports of the wheels and attachment hardware detaching, including one report of a child putting a detached metal nut in her mouth.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled toddler walkers away from young children and contact Battat for a free repair kit with replacement wheels, attachment hardware and installation instructions. Known purchasers are being contacted directly.', '22103');
INSERT INTO safety_incidents VALUES ('e07577a41d42ca57c5c7ef5aa487858ed978a3c7', 'CPSC', '2022-03-16', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Shop Pro RV & Marine Antifreeze', 'Low Risk', 'Drowning Risk', 'Respiratory', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled antifreeze and contact Prestone for a full refund and instructions on how to properly dispose of the product. Consumers who have already used the mislabeled product in any potable water system, SHOULD NOT DRINK WATER FROM THE SYSTEM and immediately contact Prestone Products for instructions on how to properly flush their water system.', '22104');
INSERT INTO safety_incidents VALUES ('9703947c21a30b83ccf1a11c90245a73286931f9', 'CPSC', '2022-03-16', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Airborne Gummies (63 and 75 count bottles)', 'Injury', 'Explosion', 'Eye Injury', 'Reckitt has received 70 reports of the cap or seal popping off the bottles, including 18 reports of minor injuries and one report of an eye injury requiring medical attention.', 'Moderate', 1, 0, 'Consumers with an unopened bottle(s) should not attempt to open the product and should contact Reckitt to return the unopened bottle(s) to receive a full refund. A postage-paid label will be provided. Bottles that have already been opened are not subject to this recall as they would have released any pressure build up and do not present an injury hazard.', '22099');
INSERT INTO safety_incidents VALUES ('04f206d3a023d8af8d72ea7a506c15c4d05d0411', 'CPSC', '2022-03-16', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Illuminated Mirrors', 'Fire', 'Flammability / Overheating', 'Electric Shock', 'RH has received three reports of the mirror''s electrical switch or wiring catching fire. RH has also received 60 reports of electrical issues including melting, smoking, sparking, shorting and bulbs bursting or breaking. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled mirrors, unplug them and contact RH for their choice of full refund of the purchase price or a refund in the form of a credit if the consumer''s purchase price cannot be determined, or a free replacement mirror. RH will schedule a free pick up of the recalled mirror. RH is contacting all known purchasers directly.', '22102');
INSERT INTO safety_incidents VALUES ('927366599fdcacf34fb3f04894847c6011b17c35', 'CPSC', '2022-03-16', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Sirrus, Sirrus X and Sirrus Sport Bicycles with alloy cranks', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'Specialized Bicycle Components has received 30 reports involving the crank arm disengaging on model year 2021 or 2022 Sirrus X 3.0 and 4.0 bicycles. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled bicycles immediately and contact their nearest authorized Specialized retailer for a free repair. Specialized Bicycle Components is contacting all known purchasers directly.', '22100');
INSERT INTO safety_incidents VALUES ('e9cda34efe48cb4ffd28c349bf2eee9aa12e1a97', 'CPSC', '2022-03-09', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Honda Talon 1000 ROVs', 'Injury', 'Other', 'Skin Irritation', 'Honda has received 16 reports of loose intake funnel band screws entering the engine, resulting in engine damage/failure. Honda has received one report of a loss of control, resulting in a crash with minor injuries to the occupants.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled recreational off-highway vehicles and contact an authorized Honda Powersports dealer to schedule an appointment for a free inspection and repair. Honda is contacting all known purchasers directly.', '22096');
INSERT INTO safety_incidents VALUES ('ef43356327f513f5badad3bd499900e681c4eb96', 'CPSC', '2022-03-09', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Be the Band Music Sets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Crate and Barrel has received six reports of broken or unscrewed maracas. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Be the Band Music Sets and contact Crate and Barrel for instructions on how to receive a refund in the form of a $20 store credit for the maracas. Crate and Barrel is contacting all known purchasers directly.', '22095');
INSERT INTO safety_incidents VALUES ('d490540640b17ff0bf59618f204a933311419ca1', 'CPSC', '2022-03-09', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Danby brand free-standing and slide-in electric and gas ranges', 'Burns', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Minor', 1, 0, 'Consumers should contact Danby Appliances to determine if their unit is part of the recall and to schedule a free in-home service call to inspect the recalled range''s anti-tip bracket and ensure it is securely installed in the floor or wall. Consumers are cautioned not to place any objects on the open oven door until the range''s anti-tip bracket has been inspected and repaired, if necessary. Consumers should not return the recalled ranges to the place of purchase, as retailers are not prepared to take the units back.  Danby is contacting all known purchasers directly.', '22093');
INSERT INTO safety_incidents VALUES ('6e0575a587c60b6c19bcad9ffecd63cfd5d88de9', 'CPSC', '2022-03-09', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'M2R Pro and Warrior Mini Flashlights', 'Burns', 'Flammability / Overheating', 'Burns', 'The firm has received 127 reports of flashlights turning on inadvertently and overheating resulting in 22 reports of burn injuries. Three consumers reported receiving second-degree burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled flashlights and contact Olight for a full refund in the form of a store credit or for a free replacement flashlight. The firm is reaching out to all known purchasers directly.', '22094');
INSERT INTO safety_incidents VALUES ('1c68b47e6b277baa3429eb03ee69215065b514a8', 'CPSC', '2022-03-03', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Ski-Doo Snowmobiles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'BRP has received five reports of fires related to fuel leaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled snowmobiles immediately and contact a Ski-Doo dealer for a free repair. BRP is contacting all known purchasers directly to coordinate the free repair with dealers to change the routing and the exit location of the fuel tank vent. A protective plate will also be installed.', '22732');
INSERT INTO safety_incidents VALUES ('bbccb62f9f9c29271579a239cd52f190f0a4e898', 'CPSC', '2022-03-02', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Bee Happy 12 Days of Craft Advent Calendars', 'Surface Paint On The Brown Bell Found In "Day 10" Of The Advent Calendar Contains Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Risk Of Lead Poisoning. Excessive Levels Of Lead Can Be Toxic Or Cause Other Health Problems To Young Children If The Paint Is Ingested.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled advent calendars away from children and contact ALDI for a full refund.', '22090');
INSERT INTO safety_incidents VALUES ('7a524cc9f4de332ecbfbbb9c5aaddfbca54aed8b', 'CPSC', '2022-03-02', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'Fitbit Ionic smartwatches', 'Burns', 'Flammability / Overheating', 'Burns', 'Fitbit has received at least 115 reports in the United States (and 59 reports internationally) of the battery in the watch overheating with 78 reports of burn injuries in the United States including two reports of third-degree burns and four reports of second-degree burns (and 40 reports of burn injuries internationally).', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Ionic smartwatches and contact Fitbit to receive pre-paid packaging to return the device. Upon receipt of the device, consumers will be issued a refund of $299. Fitbit will also provide participating consumers with a discount code for 40% off select Fitbit devices.', '22089');
INSERT INTO safety_incidents VALUES ('7dfa5f2c1a0550a524e9fa87577bfded26e9d1ab', 'CPSC', '2022-03-02', 2022, '2022-03', 'USA', 'United States', '', 'Other', 'PIRANA descender canyoneering devices', 'Drowning', 'Drowning Risk', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled PIRANA descender devices and contact Petzl for a full refund, including shipping. Consumers will be provided a postage-paid label to return their recalled descender.', '22091');
INSERT INTO safety_incidents VALUES ('34150e7ff6dc76f0fb9d6cfe1221d746df1ed52e', 'CPSC', '2022-02-24', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Mama & Me MINI Children''s Handbags', 'The Metal Zipper Slider, Zipper 0-Ring, D-Ring, Rivet And Stud Of The Children''S Handbags Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled handbags away from children and contact Kelly Wynne for a full refund if purchased at kellywynne.com or contact Nordstrom if purchased at Nordstrom.com. Kelly Wynne and Nordstrom are contacting all known purchasers directly, and will provide pre-paid shipping labels for consumers to return the recalled product for a full refund.', '22731');
INSERT INTO safety_incidents VALUES ('53d111cbd5b2e9eacb835058108134725da29b58', 'CPSC', '2022-02-23', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Wooden Teethers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Bebe au Lait has received six reports of detached beads, including one report of a child placing a bead in their mouth.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled teethers away from children and contact Bebe au Lait for instructions on how to receive a full refund or store credit. Consumers can also fill out a form for a store credit at www.bebeaulait.com/recall.', '22087');
INSERT INTO safety_incidents VALUES ('71cac99f06c551699e809c8f921d6268246ac9d5', 'CPSC', '2022-02-23', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Festive Lights Hanukkah Menorahs', 'Fire', 'Flammability / Overheating', 'Burns', 'TJX has received three reports in the U.S. of the menorahs burning or catching on fire when holding lit candles. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled menorahs and return them to any Marshalls, HomeGoods, or Homesense stores for their choice of either a full refund or a refund in the form of a store gift card.  Consumers can also contact TJX for instructions to submit photographic proof of appropriate disposal to receive either a full refund or refund in the form of a store gift card.', '22086');
INSERT INTO safety_incidents VALUES ('2fd501dad0d84c9d9acf70f215108d991c6245ac', 'CPSC', '2022-02-17', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Hot Air Brushes', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled hot air brushes, destroy them by unplugging the unit and then cutting the cord, and email a photo of the destroyed product to BrushX at replacement@mybrushx.com to receive a free, upgraded replacement product. BrushX is contacting all purchasers directly.', '22725');
INSERT INTO safety_incidents VALUES ('a9161f19a8a17acc7f835f3a9231523b82f82eb1', 'CPSC', '2022-02-17', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Children''s Sleepwear Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear sets away from children and stop using them. H&M will contact all known purchasers directly with instructions on how to return the sleepwear sets for a full refund.', '22728');
INSERT INTO safety_incidents VALUES ('50610bcdddb570f335b38e2aa37f2fb6fbe487fe', 'CPSC', '2022-02-17', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Husqvarna Automower 435X and 535 All-Wheel Drive Robotic Lawnmowers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received five reports of batteries overheating, including two reports of fires. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled lawnmowers and download the free software update that Husqvarna Professional Products is pushing to the recalled units. Consumers with units having more than 1,200 charging cycles will also receive a free replacement battery. Husqvarna Professional Products is contacting all known purchasers directly.', '22727');
INSERT INTO safety_incidents VALUES ('4c8fa46a7ed2fe0b14b6fe891d5efe6b3007d7a8', 'CPSC', '2022-02-17', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Steel drinking cups with handle', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Lovevery has received 70 reports of the handle of the drinking cup becoming partially or completely detached including two incidents where a child had the cup handle in their mouth. No choking injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled drinking cups away from children, stop using them, and contact Lovevery for a free replacement cup. Consumers will receive a free replacement cup after registering on the firm''s website, uploading a photo of their defaced cup with "X Recalled X" written inside of the cup with a permanent marker and affirming to Lovevery that the cup will be recycled according to local guidelines or disposed of in the trash. Lovevery is contacting all known purchasers directly.', '22730');
INSERT INTO safety_incidents VALUES ('c2d92c751f721945886bdd34b9547fccf3d8bc22', 'CPSC', '2022-02-17', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Model Year 2022 MATRYX RMK, INDY, SWITCHBACK, VOYAGEUR, and NORDIC PRO snowmobiles', 'The Throttle Release Switch (Trs) Can Fail To Disengage When The Throttle Lever Is Released And If A Stuck Throttle Condition Occurs When The Trs Fails To Disengage, It Can Lead To Loss Of Vehicle Control, Posing A Crash Hazard. Additionally, On Certain Model Year 2022 Matryx Rmk Snowmobiles, The Throttle Cable Can Be Kinked During Installation, Which Can Lead To Damage Of The Throttle Cable During Operation And Impairment Of The Throttle Function, Posing A Crash Hazard.', 'Chemical / Toxic Substance', 'Skin Irritation', 'Polaris has received four reports of kinked throttle cables and three reports of a stuck throttle. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and if needed, an adjustment of the throttle control assembly and/or a repair to replace the throttle cable (MATRYX RMK only). Polaris has notified consumers to stop riding the snowmobiles. Polaris is contacting all registered owners directly to provide more details about the repair.', '22729');
INSERT INTO safety_incidents VALUES ('6026ff19dba80b7d179efa3c753b0c965bba623f', 'CPSC', '2022-02-17', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Yamaha Golf Cars and Personal Transportation Vehicles (PTV)', 'Injury', 'Other', 'Skin Irritation', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Yamaha vehicles and contact a Yamaha Golf Car dealer to schedule a free repair. Yamaha is contacting all registered owners directly.', '22726');
INSERT INTO safety_incidents VALUES ('3a87dfeef72ee36a2bc0ce1b50c6edec4fe0085c', 'CPSC', '2022-02-17', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Infant Walkers', 'The Infant Walkers Fail To Meet The Federal Safety Standard. They Can Fit Through A Standard Doorway And Are Not Designed To Stop At The Edge Of A Step As Required By The Federal Safety Standard. The Walkers Also Have Leg Openings That Allow The Child To Slip Down Until The Child''S Head Can Become Entrapped At The Neck. Babies Using These Walkers Can Be Seriously Injured Or Killed.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled infant walkers and contact Zeno via e-mail to receive a shipping label to return the infant walker free of charge. Upon receipt of the infant walker, consumers will be issued a full refund of the purchase price. Zeno is notifying all known purchasers directly.', '22724');
INSERT INTO safety_incidents VALUES ('2acbc9ce60430954a5757dc029f4bb104ec11c66', 'CPSC', '2022-02-16', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'American Landmaster EV, L3, L4, L5, L5W and L7 Utility Vehicles (UTVs)', 'Injury', 'Other', 'Skin Irritation', 'American Landmaster has received seven reports of the steering shaft separating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact American Landmaster to receive instructions for conducting an inspection to determine if your vehicle requires repair, or to make an appointment for a no-cost inspection and, if necessary, full repair from an authorized repair shop. American Landmaster is contacting all registered owners directly.', '22081');
INSERT INTO safety_incidents VALUES ('720da376039f1bf513ae53fddaa01e8b92adc3eb', 'CPSC', '2022-02-16', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Anecdote Autumn Glass Candles', 'Fire', 'Sharp Edges / Points', 'Laceration / Cut', 'Anthropologie has received nine reports of the candles flaming up, cracking or breaking apart while in use, resulting in minor property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the candle and return it to an Anthropologie store. If the candle cannot be returned in store, consumers should visit www.anthropologie.com/recall for instructions on how to cut the candle wicks and dispose of the product, provide verification of this to Anthropologie, and receive a full refund. Anthropologie is contacting all known purchasers directly.', '22085');
INSERT INTO safety_incidents VALUES ('3784644c6883de1e1d4c36e2a88b40401bd87b75', 'CPSC', '2022-02-16', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Children''s Sleepwear Garments', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear garments away from children, stop using them and contact the firm for a free replacement garment or a full refund. Esme is contacting all known purchasers and providing prepaid mailers to return the products for a full refund or replacement.', '22080');
INSERT INTO safety_incidents VALUES ('d1affc6323c6c15aa9794c56b78a867b292bc0d0', 'CPSC', '2022-02-16', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Scarves', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled scarves and contact In-Things Corporation to request a prepaid postage mailer to return the scarves for a full refund or a replacement product that meets flammability standards. The refund or replacement will be provided to the consumer once In-Things receives the scarf.', '22084');
INSERT INTO safety_incidents VALUES ('05f838c335c999825fe44e204a05a40438e90402', 'CPSC', '2022-02-16', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Valco Baby Snap Duo Trend Strollers', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Valco Baby has received 207 reports of front wheels cracking or breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled strollers and contact Valco Baby to receive a free replacement front wheel assembly and instructions for replacement. Valco Baby is contacting all known purchasers directly.', '22083');
INSERT INTO safety_incidents VALUES ('56a445a33c8648c85f5011163c6888827425f65f', 'CPSC', '2022-02-16', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Viking 5 Series Freestanding Gas Ranges', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the bake, broil and griddle functions to avoid a risk of gas leak and contact Viking Range to arrange for a free repair by an Authorized Service Provider. Consumers can continue to use only the top surface burners of the range. Surface burners are those covered by the cooking grates on the top surface of the range. The griddle and ovens should not be operated.', '22082');
INSERT INTO safety_incidents VALUES ('e0d7029e82ef46a8a20a626d40f7905fce7b0a07', 'CPSC', '2022-02-10', 2022, '2022-02', 'USA', 'United States', '', 'Other', '2022 Can-Am Outlander ATVs', 'The Atv''S Speedometer Can Display Half Of The Vehicle''S True Speed, Which Can Result In Loss Of Control, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'BRP has received two reports of the vehicles speedometer not displaying the correct speed. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact a Can-Am dealer for a free repair. BRP is contacting all known purchasers directly to coordinate the free repair with dealers to update the engine control module.', '22721');
INSERT INTO safety_incidents VALUES ('ba7a1248bf6f78edcd1e5f606c4bd09271f2194e', 'CPSC', '2022-02-10', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Ski-Doo Snowmobiles', 'The Snowmobile''S Speedometer Can Display Half Of Vehicle''S True Speed, And May Result In Loss Of Control, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'BRP has received four reports of the vehicle speedometer not displaying the correct speed. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact a Ski-Doo dealer for a free repair. BRP is contacting all known purchasers directly to coordinate the free repair with dealers to update the engine control module.', '22720');
INSERT INTO safety_incidents VALUES ('491af75ce14627cdc8ec132c9ff582dad37d170a', 'CPSC', '2022-02-10', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'WORX® Brand 13 Amp 1900 PSI Electric Pressure Washers', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'Positec has received 61 reports of the spray hose and wand separation, including four reports of minor injuries, including cuts and bruises.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pressure washers and contact Positec USA for instructions on returning the spray wand for a free replacement. Once verified, Positec USA will provide the consumer with a prepaid shipping label for return of the wand assembly at which point Positec will provide the consumer with the free replacement. Positec USA is contacting all known purchasers directly.', '22078');
INSERT INTO safety_incidents VALUES ('7e6193554c0694ef1ad304c83e1ca9abc83503ea', 'CPSC', '2022-02-10', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Serta® Perfect Sleeper® Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mattresses and contact Serta to verify whether their mattress is included in the recall.  If their mattress is recalled, consumers will receive a free replacement mattress, including free delivery and disposal of the recalled mattress. Serta is contacting all purchasers directly.', '22722');
INSERT INTO safety_incidents VALUES ('f43ca3e4f8c996856586e13f9ce570eb56d223a3', 'CPSC', '2022-02-10', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Personal Electric Space Heaters', 'Fire', 'Flammability / Overheating', 'Burns', 'Shop LC has received two reports of the electric heaters overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled electric space heaters and return the product to Shop LC.  Shop LC is notifying all known purchasers directly and providing free return labels with pre-paid postage. Upon receipt of the recalled electric heaters, Shop LC will refund consumers through the original method of payment.', '22723');
INSERT INTO safety_incidents VALUES ('f8f0e8d1dd3c3a358b5e2d0c6db4f36f01ecd6b0', 'CPSC', '2022-02-09', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Children''s Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children and stop using them. Consumers who purchased the garments from Amazon.com will be contacted through Amazon''s messaging platform and provided prepaid mailers to return the products for a full refund. Consumers can also contact AllMeInGeld to request a postage prepaid mailer to return the products for a full refund.', '22071');
INSERT INTO safety_incidents VALUES ('bdba2e4a8ee40d959e45d41670754f596dc4b2ba', 'CPSC', '2022-02-09', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Escalade Sports Tennis Tables', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'Escalade Sports has received 78 reports of the tables collapsing, including four reports of minor injuries of scratches and bruises.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled tennis tables and contact Escalade Sports for a free repair kit and installation instructions or a full refund. Escalade Sports requires consumers to cut the net in several places, disassemble the table, and provide pictures to receive a refund. Consumers should not return the recalled tables to Target and should contact Escalade Sports for repair or full refund.', '22076');
INSERT INTO safety_incidents VALUES ('9c2a6b13a3f80763a19370b79fb805120b068f58', 'CPSC', '2022-02-09', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Pittsburgh Automotive Pneumatic Roller Seats', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'Harbor Freight Tools has received 96 reports of the seat weld breaking, including ten reports of minor injuries, including bruises from users falling from the seat.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled seats and return them to the nearest Harbor Freight Tools store for a free replacement or full refund in the form of a gift card. If you are unable to return the seat to one of Harbor Freight Tools'' locations, contact Harbor Freight Tools using the toll-free number or email address below to request a prepaid return shipping label for a replacement or a refund. Harbor Freight Tools is contacting all known purchasers directly.', '22075');
INSERT INTO safety_incidents VALUES ('f0198a7ab3893e1567f8610d1ac547a2997b1a85', 'CPSC', '2022-02-09', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Personal Electric Heaters', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Home Easy has received three reports of the toggle power switch causing a fire. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled heaters and contact Home Easy for a full refund. Consumers should destroy the recalled heaters by unplugging the heater prior to cutting the electrical cord making the product inoperable and then prominently mark on the product "defective" before disposal, following local disposal guidelines. Consumers should take a photo of the cut electrical cord for submission to Home Easy at recall@homeeasy.net. Home Easy is contacting all known purchasers directly.', '22077');
INSERT INTO safety_incidents VALUES ('96edc676356dfaf340308ae6f9dc56de53b18950', 'CPSC', '2022-02-09', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Scorpio Eashook Lanyards with Carabiners', 'Injury', 'Mechanical Failure', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled lanyards and contact Petzl for a full refund, including shipping. Consumers will be provided a postage-paid label to return their recalled lanyard.', '22072');
INSERT INTO safety_incidents VALUES ('f47194b908b83e6549ec47d766698e62fd0c1bb2', 'CPSC', '2022-02-09', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Adam the Apple™ Children''s Stackable Toys', 'Surface Paint On The Wooden Toys Contains Levels Of Lead That Exceed The Federal Lead Paint Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled toys away from children and contact Stack Em'' Up Books to receive a pre-paid shipping label to return the recalled product, regardless of whether they purchased the product or received it as a free giveaway. Consumers that purchased the product at www.stackemupbooks.com or the Philadelphia Gift Show will receive a full refund once they return the product.', '22073');
INSERT INTO safety_incidents VALUES ('7449a252966efb48c5db9a235b3bd866fb303b8c', 'CPSC', '2022-02-09', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Kids Reiny Szn Mid-Cushion Crew Socks', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Stance has received one report of the bells detaching. No injuries and no reports of children putting bells in their mouths have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using and return the recalled socks to a Stance store or contact Stance at info@stance.com to receive instructions for a pre-paid shipping label to return the recalled socks. Upon return of the recalled socks, consumers will receive a refund in the form of a credit of up to $20 to use on their next purchase on Stance.com or at a Stance retail store.  This credit is not transferrable, is not redeemable for cash and is a one-time usage code.', '22074');
INSERT INTO safety_incidents VALUES ('03c6e7afdb2473fb55abf25e005fbb7e38908390', 'CPSC', '2022-02-03', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'River Street Five-Drawer Chests', 'The Recalled Dressers Are Unstable If Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That May Result In Death Or Serious Injuries To Children. The Dressers Do Not Comply With The Performance Requirements Of The U.S. Voluntary Industry Standard (Astm 2057-19).', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled chests and contact Rooms To Go for a free in-home repair by trained technicians, free replacement, or a full refund of the purchase price in the form of a Rooms To Go store credit, including free pick-up of the chest. Rooms To Go is contacting all known purchasers directly.', '22719');
INSERT INTO safety_incidents VALUES ('a3bfd6715df5e081a9b640cb4ec4ce17f1c7917b', 'CPSC', '2022-02-02', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Children''s Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children and stop using them. Consumers who purchased the robes from Amazon will be contacted through Amazon''s messaging platform and provided prepaid mailers to return the robes for a full refund. Consumers can also contact BAOPTEIL to request a postage prepaid mailer to return the robes for a full refund.', '22066');
INSERT INTO safety_incidents VALUES ('02860a622d10770b18bd87f492ae0d52f9f7de52', 'CPSC', '2022-02-02', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'SureClose® READYFIT 180° Hinge-Closer Sets', 'Injury', 'Mechanical Failure', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the hinge-closers and secure access to areas where gates with the hinge-closers are used until the recalled hinge-closers have been replaced. Contact D&D Technologies to receive either a full refund or to schedule hinge-closer replacement at no cost. Consumers will also receive instructions on how to return recalled hinges to D&D Technologies via mail free of charge.', '22069');
INSERT INTO safety_incidents VALUES ('a83404f8d7c7c50aa415c8f9994d520aa0405b4d', 'CPSC', '2022-02-02', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'KOYO Bounca The Squig Limited Edition Plush toys', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled plush toy away from young children and return the toy to any Games Workshop or Warhammer store for a full refund, or destroy the product by cutting off the tail with scissors and provide photographic proof of destruction by emailing the photo to custserv@gwplc.com or uploading photo using the form at https://www.games-workshop.com/recall for a full refund.', '22067');
INSERT INTO safety_incidents VALUES ('d1caa43b81cfece7a5e13a765d74e71073d7ab7e', 'CPSC', '2022-02-02', 2022, '2022-02', 'USA', 'United States', '', 'Other', 'Maxtrade''s Youth Coolster Mountopz All-Terrain Vehicles (ATVs)', 'Injury', 'Other', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact Maxtrade for a free repair from an authorized repair shop. Maxtrade is contacting all known purchasers directly.', '22068');
INSERT INTO safety_incidents VALUES ('5d5101ef28e84cde09147722cc0c1b2606c6e2ca', 'CPSC', '2022-01-28', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Matrix T1 and T3 Series Commercial Treadmills', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Matrix Fitness has received 58 reports of the treadmill''s power cord and socket sparking, smoking, and/or melting, including seven reports of fire; two resulting in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Exercise facilities should ensure that the power cord is completely inserted into the power socket on the treadmills prior to each use, until repaired. Contact Johnson Health Tech North America to schedule a free installation of a power cord bracket. Johnson Health Tech North America is contacting all known purchasers directly.', '22718');
INSERT INTO safety_incidents VALUES ('0213555e3c7158397f69e6f6dbfd86b034bedcec', 'CPSC', '2022-01-26', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Children''s Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children and stop using them. Consumers who purchased the garments from Amazon.com will be contacted through Amazon''s messaging platform and provided prepaid mailers to return the products for a full refund. Consumers can also contact AOSKERA to request a postage prepaid mailer to return the products for a full refund.', '22057');
INSERT INTO safety_incidents VALUES ('65ad936be6110e8e9fe8a3850634f512d0f59b03', 'CPSC', '2022-01-26', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'DEWALT DWCS600, 18-inch corded chain saws', 'Injury', 'Other', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled chain saws and contact DEWALT to receive a pre-paid shipping label to return the product directly to DEWALT in order to receive a free replacement chain saw.', '22059');
INSERT INTO safety_incidents VALUES ('ab2dc5e2feee946b86afa008ac53a53879c2734c', 'CPSC', '2022-01-26', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Evolve Home Energy Storage Systems', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately contact Eguana Technologies to schedule a free repair to the Evolve system. All recalled units connected online will have the batteries state of charge remotely limited, to reduce the risk of overheating until the batteries are replaced. If your unit is not connected online, contact Eguana Technologies to schedule a technician to come to your residence to manually reduce the state of charge, at no cost. Eguana Technologies will arrange for all recalled lithium-ion batteries to be properly replaced and disposed of according to federal and state regulations, and is contacting all known owners directly or through its installers.', '22058');
INSERT INTO safety_incidents VALUES ('907f017a7b3970b1d468f9dca76164be309144d0', 'CPSC', '2022-01-26', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Beach Loungers', 'Injury', 'Mechanical Failure', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled beach loungers and return them to a Family Dollar store for a full refund. Consumers can also email Family Dollar for instructions to make the beach lounger unusable and to then provide Family Dollar a photo. Once confirmed, Family Dollar will provide a refund to the consumer.', '22061');
INSERT INTO safety_incidents VALUES ('648fbf6cb4f3394799cfad4a345ba3c59d4e9b83', 'CPSC', '2022-01-26', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Over-the-counter drugs', 'The Over-The-Counter Drug Products Contain Regulated Substances Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of sight and reach of children, and safely dispose of the recalled product as soon as is practicable. Contact Geri-Care Pharmaceuticals for a full refund or replacement over-the-counter drug product.', '22060');
INSERT INTO safety_incidents VALUES ('9abf4615c4978995440b4f7ba4a9c6a0c9d96315', 'CPSC', '2022-01-19', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Children''s Sleepwear Garments', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled children''s sleepwear garments and take them away from children. Consumers should contact Childrensalon for instruction on returning the recalled sleepwear. Childrensalon will contact all known purchasers and provide prepaid return mailers. Upon returning the garment, Childrensalon, will refund consumers the purchase price.', '22055');
INSERT INTO safety_incidents VALUES ('d66a589cf83808f6f8371bfec7523d3989baf065', 'CPSC', '2022-01-19', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'FRIGG Silicone Pacifiers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Mushie & Co has received eight reports of the silicone nipple detaching from the plastic shield of the pacifier. In addition, the manufacturer has received about 200 reports from outside the U.S. of the silicone nipple detaching from the plastic shield of the pacifier. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pacifiers and contact the firm for a full refund or credit. To obtain a full refund or credit, consumers should cut the silicone nipple from the base of the pacifier and send a photograph of both the detached silicone nipple and the base of the pacifier to Mushie & Co at: mushie.com/pages/recalls. Consumers should then properly dispose of the pacifier by placing both pieces into the garbage.', '22054');
INSERT INTO safety_incidents VALUES ('017c8dfbbcf07c3cd30da7a990288aea68a6926b', 'CPSC', '2022-01-13', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'E-Z-GO Freedom RXV with Rear Facing Seat Personal Transportation Vehicles (PTV)', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the rear facing seat of their recalled vehicle and contact Textron for a free repair. Textron Specialized Vehicles is contacting all purchasers directly to coordinate a free repair program with dealers to inspect and replace the recalled vehicle''s rear seat frame.', '22717');
INSERT INTO safety_incidents VALUES ('716f0a5b31f6a7fd4f8b3b5a097e4a2315da7d23', 'CPSC', '2022-01-12', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Children''s Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled robes away from children and stop using them. Consumers who purchased the garments from Amazon.com will be contacted through Amazon''s messaging platform and provided prepaid mailers to return the products for a refund. Consumers can also contact HulovoX to request a postage prepaid mailer to return the products for a full refund.', '22053');
INSERT INTO safety_incidents VALUES ('8156634984ff1d2f3a14dc5685debc8ce7b70b49', 'CPSC', '2022-01-12', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'EGL and ACE Branded Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact EGL Motor to make an appointment for a no-cost full repair from an authorized repair shop.', '22052');
INSERT INTO safety_incidents VALUES ('a7462de064b2c6d663825aeae30b215fc4e5e4ca', 'CPSC', '2022-01-12', 2022, '2022-01', 'USA', 'United States', '', 'Other', '2021 Model Year Giant and Liv Adult Bicycles', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'Giant Bicycle has received 86 reports of the bicycle''s handlebar becoming loose including three reports of riders falling off the bicycle.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact Giant Bicycle. Consumers will be instructed to schedule an inspection and free repair at the authorized Giant Bicycles retailer where the consumer purchased the bicycle or any other authorized Giant Bicycle retailer.', '22051');
INSERT INTO safety_incidents VALUES ('ad6f77d7b5c5d2a8ed85cf55a48804094a296067', 'CPSC', '2022-01-11', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Bella residential elevators', 'Young Children Can Become Entrapped In The Space Between The Exterior Landing (Hoistway) Door And The Interior Elevator Car Door Or Gate If There Is A Hazardous Gap, And Suffer Serious Injuries Or Death When The Elevator Is Called To Another Floor.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should keep unsupervised young children away from the recalled residential elevators and contact the manufacturers for instructions on how to measure for space guards to correct any hazardous gap. Space guards will be provided free of charge and assistance with space guard installation will be provided on request.', '22045');
INSERT INTO safety_incidents VALUES ('62e4c18443540ec71aa10da37eadec8771953cd3', 'CPSC', '2022-01-11', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Inclinator residential elevators', 'Young Children Can Become Entrapped In The Space Between The Exterior Landing (Hoistway) Door And The Interior Elevator Car Door Or Gate If There Is A Hazardous Gap, And Suffer Serious Injuries Or Death When The Elevator Is Called To Another Floor.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should keep unsupervised young children away from the recalled residential elevators and contact the manufacturers for instructions on how to measure for space guards to correct any hazardous gap. Space guards will be provided free of charge and assistance with space guard installation will be provided on request.', '22046');
INSERT INTO safety_incidents VALUES ('9df5c60cb468fc28b26ad7f7bd5e1dc3940c965b', 'CPSC', '2022-01-11', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Savaria and Garaventa branded residential elevators', 'Young Children Can Become Entrapped In The Space Between The Exterior Landing (Hoistway) Door And The Interior Elevator Car Door Or Gate Due To A Hazardous Gap, And Suffer Serious Injuries Or Death When The Elevator Is Called To Another Floor.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should keep unsupervised young children away from the recalled residential elevators and contact the manufacturers for instructions on how to measure for space guards to correct any hazardous gap. Space guards will be provided free of charge and assistance with space guard installation will be provided on request.', '22047');
INSERT INTO safety_incidents VALUES ('a2414320c161bb1601d94691aa928f0bbbd250ba', 'CPSC', '2022-01-06', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Covered Wood Wagons', 'Paint On The Wood Wagons, The Plastic Handles, And The Red Plastic Cover Contain Levels Of Lead That Exceed The Maximums Allowed. Excessive Levels Of Lead Can Be Toxic Or Cause Other Health Problems To Young Children If The Paint Is Ingested.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled wagons away from children and return them for a full refund. The involved retailers are contacting all known purchasers to arrange returns and providing pre-paid shipping labels and return instructions. Consumers will receive a full refund once the recalled product is returned.', '22715');
INSERT INTO safety_incidents VALUES ('9a2cf4a1dcc412d2e9b29e18e2c752f233c91931', 'CPSC', '2022-01-06', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Outlaw 110 EFI Youth All-Terrain Vehicles (ATVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Polaris has received two reports of fuel leaks. No fire or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free repair, including the installation of a new fuel line. Polaris has notified consumers to stop riding the vehicles. Polaris will be contacting all registered owners directly to provide more details about the repair.', '22716');
INSERT INTO safety_incidents VALUES ('6ecab24624c7c833513049efa8520f19f6e6bc56', 'CPSC', '2022-01-05', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'CRT Motor Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Serious', 1, 0, 'Consumers should stop using the recalled ATVs immediately and contact CRT Motor for instructions on how to receive a full refund.', '22043');
INSERT INTO safety_incidents VALUES ('e27b6c198da5309a708246d5797d384806a554d0', 'CPSC', '2022-01-05', 2022, '2022-01', 'USA', 'United States', '', 'Other', 'Native Creation Small Wool Sweaters', 'Paint On The Zipper Pull Contains Levels Of Lead That Exceed The Maximums Allowed. Excessive Levels Of Lead Can Be Toxic Or Cause Other Health Problems To Young Children If The Paint Is Ingested.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled sweater away from children and contact Native Creation for a full refund.', '22044');
INSERT INTO safety_incidents VALUES ('858304aeb9a787a9bb61848db1f92c35ec5e4a05', 'CPSC', '2021-12-29', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'American Angler Electric Fillet Knives', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Polaris has received 33 reports of broken or cracked steering wheel spokes, including five reports of rollovers and two reports of injuries', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled EFK, unplug the unit, and cut the power cord. Consumers should then contact Scott Fetzer Consumer Brands to receive a free replacement EFK by mail. Consumers will need to provide their mailing address and proof of destruction by sending a photo of the recalled product and cut cord to the firm. The consumer should then throw away the unit in their trash.', '22042');
INSERT INTO safety_incidents VALUES ('ebe1d9c0d7a48f3c3ce184cfae0d366c3b1511b2', 'CPSC', '2021-12-23', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Polaris RZR and GENERAL Recreational Off-Road Vehicles', 'The Steering Wheel Can Separate And Result In A Loss Of Control, Posing A Crash Hazard.', 'Other', 'Fracture / Blunt Trauma', 'Polaris has received 33 reports of broken or cracked steering wheel spokes, including five reports of rollovers and two reports of injuries', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free repair, including the installation of a new steering wheel. Polaris has notified consumers to stop riding the vehicle. Polaris will be contacting all registered owners directly to provide more details about the repair.', '22714');
INSERT INTO safety_incidents VALUES ('a96e5d480d4a4fb5c211b1d86e6bc9dc83d3b7f4', 'CPSC', '2021-12-22', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'The Captain Hang-on Treestands (2021 Batch #2M-0121)', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'GSM Outdoors has received 10 reports of the treestand cables releasing and causing consumers to fall. Two injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled treestands and contact Big Game Treestands to receive either replacement cables or to return the treestand for a full refund. Big Game Treestands is contacting all known consumers directly. To receive replacement cables, the company will set up pick-up of the original cables and delivery of the replacement cables to the consumers address. If a full refund is requested, the consumer will be asked to mail back the entire treestand using a pre-paid label at no cost to the consumer.', '22034');
INSERT INTO safety_incidents VALUES ('64d0d8d4aa0e7ef793910c68aee307196ab0ba0c', 'CPSC', '2021-12-22', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Carex Brand Adult Portable Bed Rails', 'When Attached To An Adult''S Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Rail And The Side Of The Mattress. This Poses A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'Compass has received three reports of entrapment deaths associated with the Bed Support Rail (model P566), between April 2014 and June 2020, involving an 85-year-old man at an assisted living facility in Ohio; an 84-year-old woman at home in California; and an 88-year-old woman at an assisted living facility in Washington. In each case, the bed rail was not securely attached to the bed entrapping the user. No entrapment reports involving the Easy Up 2-in-1 Bed Rail (model P569).', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact Compass Health Brands for a free repair kit for the Bed Support Rail or a refund for the Easy Up 2-in-1 Bed Rail.', '22040');
INSERT INTO safety_incidents VALUES ('0e558b9c2e75d138c3939063f1ab414b9fbb2f82', 'CPSC', '2021-12-22', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Endurance® Hand Bed Rails', 'When Attached To An Adult''S Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Rail And The Side Of The Mattress. This Poses A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'One entrapment death has been reported involving the Endurance Hand Bed Rail (model P1410). The death occurred in December 2012 and involved an 86-year-old man at his home in California.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails. For consumers who own bed rails sold or imported on or after November 1, 2015, Essential Medical Supply, Inc., will provide a refund. The amount of the refund will be pro-rated based on the age of the bed rail. The company is not offering a remedy for older bed rails. Consumers with older bed rails sold between October 2006 and October 2015 should stop use, disassemble and dispose of the bed rails to prevent reuse.', '22039');
INSERT INTO safety_incidents VALUES ('6acf26192ec1324cadaafbd671ed493a7fd2404f', 'CPSC', '2021-12-22', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Angel Line Bunk Beds with angled ladders', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'A 2-year-old boy from Columbus, Ohio died in May 2018 after he was found unresponsive in a gap in the bunk bed ladder.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bunk beds, block children''s access to the bunk beds and contact Angel Line to receive a free repair kit with reinforcement brackets for the ladder. Consumers who paid for the bunk beds to be assembled when purchased will receive reimbursement for help with installing the repair kit if needed.', '22036');
INSERT INTO safety_incidents VALUES ('eadaf35cd51ab5d1afae7c6d8e2b766e5fe9517a', 'CPSC', '2021-12-22', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Pearl River propane hoses used on propane torches and accessories', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Pearl River has received three reports of propane hoses swelling and rupturing. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled propane hoses. To obtain a free replacement hose, send a photograph of the propane hose cut in half so that it is no longer operable to the firm''s e-mail along with a return mailing address to receive a free replacement hose. Once Pearl River receives confirmation of the hose cut in half, consumers can throw away the cut hose.', '22038');
INSERT INTO safety_incidents VALUES ('515e50e8a058a1041270f21f093b67a2c4e229a9', 'CPSC', '2021-12-22', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Royal Sovereign/Royal Centurian portable air conditioners', 'Fire', 'Flammability / Overheating', 'Respiratory', 'Royal Sovereign is aware of 11 reports of the portable air conditioners catching fire or smoking during use resulting in over $1 million in property damage, two injuries and one death due to smoke inhalation.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled portable air conditioners, unplug the unit, follow the instructions online at www.Recall-PAC3012.com for properly severing the electrical cord rendering the unit unusable, and contact Royal Sovereign for a pro-rated refund based on the age of the portable air conditioner. Failure to unplug the unit could result in shock, electrocution, or death.', '22037');
INSERT INTO safety_incidents VALUES ('3a68b6bfd586acc3a414cabbdf9c3fed51698b4e', 'CPSC', '2021-12-16', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Infant Bath Seats', 'Drowning', 'Instability / Fall Risk', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled infant bath seats and contact Karmas Far to receive a pre-paid label to return the products. Upon receipt of the products, consumers will be issued a full refund for the purchase price. Karmas Far is notifying all known purchasers directly.', '22713');
INSERT INTO safety_incidents VALUES ('35e563e83e86fd573b3e2e6e28370ee7c1a2ea44', 'CPSC', '2021-12-16', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Alaura Two-Tone Jar Candles', 'Fire', 'Sharp Edges / Points', 'Laceration / Cut', 'Northern Lights has received 138 reports of the jar candles shattering, cracking or breaking apart, including three reports of laceration injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled candle and return it to any Costco Warehouse for a full refund. Consumers who are not able to return the candle to a Costco Warehouse can contact Northern Lights by email at cr@northernlightscandles.com for instructions on how to cut the candle wicks, provide verification of this to Northern Lights, and then dispose of the candle to receive a full refund. Costco is contacting all known purchasers directly.', '22712');
INSERT INTO safety_incidents VALUES ('c373d6a3d4ed37fc4e73d5cd657d3174794bd201', 'CPSC', '2021-12-15', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Hisun 250cc Utility Vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Hisun Motors Corp. U.S.A. has received five reports of vehicle fires. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact Hisun U.S.A. for a free consumer installable repair kit or arrange to take the utility vehicle to an approved service center for a free repair.', '22032');
INSERT INTO safety_incidents VALUES ('977de07693d329ed046bfb773b845470b6fb22fe', 'CPSC', '2021-12-15', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Harbor Breeze Belleisle Bay and Honeywell Rio Ceiling Fans', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 60 reports of the blades detaching from the fan, including three reports of the blades causing property damage to drywall. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fans and contact Hong Kong China Electric Appliance Manufacture Company ("HKC") to confirm their fan is under the scope of the recall by providing the firm a photo of the fan and date code. The consumers will then be instructed to disconnect the fan, provide a photo of the disconnected fan to HKC and dispose of it in the trash or recycle.  The consumer will then receive a free replacement fan by mail.', '22033');
INSERT INTO safety_incidents VALUES ('7e4fe3734d0b83dad17786ac926298e623477812', 'CPSC', '2021-12-15', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Schwinn Tone Electric Scooters (e-scooters)', 'Injury', 'Instability / Fall Risk', 'Laceration / Cut', 'Pacific Cycle has received nine reports of loosened or cracked handlebars which include one report of an injury where bruising and abrasions occurred, when a consumer fell from the e-scooter while riding after the handlebar broke.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled e-scooters and contact Pacific Cycle for a free repair kit. Consumers will need to provide the serial number of their scooter and a mailing address. The repair kit can be installed by the consumer and includes all required tools and instructions, which are also available in video format. Pacific Cycle estimates it will take consumers between five and ten minutes to install. Alternatively, consumers can ship the e-scooter back to Pacific Cycle for repair, at no cost to the consumer.', '22030');
INSERT INTO safety_incidents VALUES ('5cb18a50b8adaad7a159571a23127cbcc9190fbc', 'CPSC', '2021-12-10', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Letters to Santa Mailbox', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Target has received nine reports of sharp mail slot openings and seven  incidents of lacerations with three requiring medical attention.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mailbox and return it to any Target Store for a full refund in the form of a Target gift card. Consumers can also contact Target to receive a prepaid return label to return the mailbox for a full refund in the form of a Target gift card.', '22029');
INSERT INTO safety_incidents VALUES ('415aa42d9108def95465e43306b55bc41ce76a2c', 'CPSC', '2021-12-08', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Free-Standing and Slide-In Electric and Gas Ranges', 'Burns', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Minor', 1, 0, 'Consumers should contact GE Appliances to determine if their unit is part of the recall and to schedule a free in-home service call to inspect the recalled range''s anti-tip bracket and ensure it is securely installed in the floor or wall. Consumers can continue to use the recalled ranges but are cautioned not to place any objects on the open oven door until the range''s anti-tip bracket has been inspected and repaired, if necessary. Consumers should not return the recalled ranges to the place of purchase, as retailers are not prepared to take the units back.  The firm is contacting all known purchasers directly.', '22028');
INSERT INTO safety_incidents VALUES ('bf23fe6c4d65259f8f4d978fdbe225a98040eee2', 'CPSC', '2021-12-08', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Children''s robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled children''s robes away from children and contact Mark of Fifth Avenue. Consumers can receive a full refund of the purchase price of the garment by cutting the robes in half, taking a photo of the cut garment, and sending an email to mofaproductsafety@gmail.com with the photos. All known purchasers will be contacted.', '22027');
INSERT INTO safety_incidents VALUES ('d7f7465918524c1ccabdc024078d3c137534c221', 'CPSC', '2021-12-06', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Bed Assist Handles and Bed Assist Rail', 'When Attached To An Adult''S Bed, Users Can Become Entrapped Within The Bed Rail Or Between The Rail And The Side Of The Mattress. This Poses A Serious Entrapment Hazard And Risk Of Death By Asphyxiation.', 'Entrapment', 'Choking / Suffocation', 'Drive has received two reports of entrapment deaths associated with two of its Bed Assist Handle bed rails (models 15064 and RTL15073). The deaths occurred in February 2011 and February 2015, and involved a 93-year-old woman at her home in California, and a 92-year-old man at an assisted living facility in Canada.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled bed rails and contact Drive DeVilbiss Healthcare to receive a full refund.', '22025');
INSERT INTO safety_incidents VALUES ('280d84d4a999428226a0ffd2d745b29467ccbb28', 'CPSC', '2021-12-01', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'DEWALT ® Jobsite Pro Wireless Earphones', 'Fire', 'Flammability / Overheating', 'Burns', 'E-filliate has received 61 reports of the earphones overheating during charging or use, including five reports of fire and four reports of minor burn injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the wireless earphones and contact E-filliate to receive a pre-paid shipment label to return the product directly to E-filliate in order to receive a free replacement.', '22023');
INSERT INTO safety_incidents VALUES ('8fec50a0931f9db469b965a81be0cb9f444a7955', 'CPSC', '2021-12-01', 2021, '2021-12', 'USA', 'United States', '', 'Other', 'Projector Flashlights (included as part of a care package)', 'Choking', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'The firm has received two reports of children accessing the button cell batteries from the flashlight, and in one case, a child required surgery to remove a swallowed battery.', 'Serious', 1, 0, 'Consumers should immediately take the recalled projector flashlight away from children, stop using it, and contact Halo for a full refund and a pre-paid shipping label to return the projector flashlight. Upon return, Halo will send the consumer a $5 gift card redeemable at a major national retailer.', '22024');
INSERT INTO safety_incidents VALUES ('229a1fc6ed94c83603f721b37ac9ca58387b2344', 'CPSC', '2021-11-23', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Olympic Dumbbell Handles', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'Impex has received four reports of locking collars that slipped. No injuries were reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled dumbbell handles and contact Impex Fitness to receive a free replacement set of new locking collars. The replacement collars will be mailed out to consumers free of charge. Consumers should dispose of the old collar by discarding it into the trash', '22022');
INSERT INTO safety_incidents VALUES ('8106c8bc50e2a4565d71fbc66c974a1ae3150e81', 'CPSC', '2021-11-18', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'AmazonBasics Memory Foam Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Amazon is contacting all purchasers to arrange for direct shipment of a cover for consumers to place over the mattresses that will bring the mattresses into compliance, free of charge.', '22711');
INSERT INTO safety_incidents VALUES ('0b122c657566b603af55b8654f3b0051efd788b9', 'CPSC', '2021-11-18', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Honda Pioneer and Talon ROVs', 'Injury', 'Other', 'Skin Irritation', 'Honda has received one report of a loss of steering function. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled recreational off-highway vehicles and contact an authorized Honda Powersports dealer to schedule an appointment for a free inspection and repair to install a yoke joint and hardware for the steering shaft assembly. Honda is contacting all known purchasers directly.', '22020');
INSERT INTO safety_incidents VALUES ('1f453deece3780f4c8062cf9c2cdf48071f2df00', 'CPSC', '2021-11-18', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Evaporator coil drain pans installed with residential condensing gas furnaces in an up-flow configuration', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Goodman has received 23 reports of fire involving the evaporator coil drain pans. These incidents have resulted in significant fire and smoke damage to residences. No injuries were reported.', 'Minor', 1, 0, 'Contact Goodman Manufacturing Company to register for the free repair. Visit Goodman''s recall website to use a model verification tool for evaporator coil, furnace, and outdoor condenser. The tool provides step-by-step instructions to determine if your gas furnace system is subject to this recall. Goodman will also assist consumers in gathering information on their units including the drain pan serial number, the furnace model number and brand name, and the model number for the outdoor system.', '22021');
INSERT INTO safety_incidents VALUES ('e40e4c477a3677a87ead7698cc404344377311d7', 'CPSC', '2021-11-12', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Baby Long Sleeve Wiggle Sets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Hanna Andersson has received one reported incident of the snaps detaching. No injuries have been reported. No incidents of children putting snaps in their mouths or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Baby Long Sleeve Wiggle Set and contact Hanna Andersson for a full refund. Hanna Andersson will be providing postage-paid labeling to consumers for the return of the product for a full refund. Hanna Andersson is contacting all known purchasers directly.', '22709');
INSERT INTO safety_incidents VALUES ('068df21383bcd7a411dc72cfa59810b21c7f7a19', 'CPSC', '2021-11-12', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Baby Ruffle Rompers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Hanna Andersson has received three incidents of the snaps detaching or fabric around the snaps ripping. No incidents of children putting snaps in their mouths or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Ruffle Romper and contact Hanna Andersson for a full refund. Hanna Andersson will be providing postage-paid labeling to consumers for the return of the product for a full refund. Hanna Andersson is contacting all known purchasers directly.', '22710');
INSERT INTO safety_incidents VALUES ('2add898f38add53c85336ec66ff97819734bad56', 'CPSC', '2021-11-12', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Lambeth Outdoor Metal Torches', 'Fire', 'Flammability / Overheating', 'Not Specified', 'RH has received seven reports of fuel leaking from the torch canister. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled torches and contact RH for a full refund of the purchase price, or a credit if the consumer''s purchase price cannot be determined. Consumers will receive a prepaid label and packaging to return the torch lid to RH. After RH receives the returned lid, RH will provide a refund or credit to the consumer. RH is contacting all known purchasers directly.', '22707');
INSERT INTO safety_incidents VALUES ('039f10005bc709842060f3c70dbdffdf24b26882', 'CPSC', '2021-11-12', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'VidaXL Steel Pool Ladders', 'Drowning', 'Drowning Risk', 'Drowning', 'The firm has received four reports of falls off the pool ladders. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pool ladders and contact VidaXL for a full refund. VidaXL is contacting all purchasers directly and will instruct consumers to remove two of the ladder''s steps and dispose of the steps and ladder in the trash.', '22708');
INSERT INTO safety_incidents VALUES ('92f94b9110319361e833f0cfbe7071eb655bb0af', 'CPSC', '2021-11-10', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'ABUS MountZ Youth Helmets', 'Injury', 'Other', 'Not Specified', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and return them to ABUS''s Recall Administrator, Sedgwick, free of charge, for a full refund.', '22013');
INSERT INTO safety_incidents VALUES ('44fe80ccea3d76b1145002c62e5014fffcbab456', 'CPSC', '2021-11-10', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Hart 18-Gauge 2" Brad Nailers', 'Injury', 'Mechanical Failure', 'Not Specified', 'None Reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled nailer and return it to any Walmart USA store for a full refund. Consumers may also return items for free by mail via a scheduled pickup from your home. To schedule a free pickup, consumers should call 800-776-5191.', '22017');
INSERT INTO safety_incidents VALUES ('78bfe2537de7c7613f162c5c17da5060b1904d41', 'CPSC', '2021-11-04', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Turbo Racer, Cloud Racer, Captain''s Fort and Fort Highlander Outdoor Playsets', 'The Wooden Parts Used To Reinforce And Create A Decorative Gable Design On The Wooden Roof Pose An Entrapment Hazard To Children. Children Can Become Trapped In The Gap Between The Lower Part Of The Roof Structure And The Bottom Of The Gable Decoration.', 'Entrapment', 'Entrapment', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled playsets and contact Backyard Play Systems for a free repair kit which includes replacement wood parts, hardware and instructions.  If a consumer is unable or does not want to do the repair themselves, Backyard will send a representative to perform the repair for them at no charge.  The firm is contacting all known purchasers directly.', '22706');
INSERT INTO safety_incidents VALUES ('0f92fa1c6e00a8fb87b0562aaebf1255ac5a4bcb', 'CPSC', '2021-11-04', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Kubota RTV-X1100C Model Utility Vehicles', 'Injury', 'Other', 'Skin Irritation', 'Kubota has received one report of a loss of control that resulted in black eyes and minor bruising.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact an Authorized Kubota dealer. If the floormat is warped or degraded, consumers will receive a new floormat installed by the dealer that will be secured by rivets to the floor. If the utility vehicles floormat is not warped or degraded, the dealer will complete a modification to the existing floormat by trimming the mat and then securing it by rivets to the floor. Kubota is contacting all known consumers directly.', '22705');
INSERT INTO safety_incidents VALUES ('4ab0f21139fa12acb166e48648f51fffcf23f703', 'CPSC', '2021-11-03', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Elektron BP-1 Power Handles', 'Fire', 'Electrical Fault', 'Burns', 'Elektron has received one report of the power handle overheating. No fires or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled power handles, disconnect the power cable and remove the batteries; and contact Elektron for instructions on receiving a full refund, including shipping. The firm will provide each consumer with a prepaid shipping label after they have contacted the firm to report the product.', '22015');
INSERT INTO safety_incidents VALUES ('91be0a37e195a27e8786b2b6a79f180ab1d98d49', 'CPSC', '2021-11-03', 2021, '2021-11', 'USA', 'United States', '', 'Other', 'Usines Giant Factories Gas Water Heaters with Emerson control valves', 'Fire', 'Electrical Fault', 'Burns', 'None reported in the United States. Usines Giant Factories has received 20 reports of incidents with the Emerson control valves in Canada, including one report necessitating medical attention due to the release of carbon monoxide.', 'Moderate', 1, 0, 'Consumers should immediately contact Usines Giant Factories, who will arrange to have the Emerson control valve replaced by a certified technician, and to receive a free replacement valve. Consumers who continue to use the water heaters while awaiting repair should have working carbon monoxide alarms outside of sleeping areas and on every level of the home.', '22016');
INSERT INTO safety_incidents VALUES ('2c4596eef2af1101b72ef72e2ca76831d11d9459', 'CPSC', '2021-10-28', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'Arc Collection Furniture', 'Surface Paint On The Furniture Contain Levels Of Lead That Exceed The Federal Lead Paint Ban, Posing A Risk Of Lead Poisoning. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled furniture and contact Design Within Reach for return instructions and a full refund. Design Within Reach is contacting all purchasers directly.', '22704');
INSERT INTO safety_incidents VALUES ('db6eb740744c4f49b6e2b86f03ae3b0c6e2168f3', 'CPSC', '2021-10-27', 2021, '2021-10', 'USA', 'United States', '', 'Other', '56100 Tactec™ Plate Carriers', 'Injury', 'Other', 'Not Specified', 'The firm has received two reports of the cable in the quick release system separating from the handle on the Tactec Plate Carriers. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled plate carriers and contact 5.11 for a free replacement of the cable system.', '22008');
INSERT INTO safety_incidents VALUES ('8031a6dc1787574962c920d4dee5562a5fcb621d', 'CPSC', '2021-10-27', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'Glass cabinet knobs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Liberty Hardware is aware of 29 reports of the knobs breaking during use including three reported laceration injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled glass cabinet knobs, remove them, and contact Liberty Hardware to receive a full refund.', '22010');
INSERT INTO safety_incidents VALUES ('b3c4aa9e45a3af1e619d3106410b5560f5122ab7', 'CPSC', '2021-10-27', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'Nova Series 5-Drawer Chests', 'The Recalled Chests Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Death Or Serious Injuries To Children. The Chests Do Not Comply With The Performance Requirements Of The Voluntary Industry Standard Astm F2057-19.', 'Entrapment', 'Entrapment', 'Magnussen Home has received one report of the chest tipping over, resulting in a minor bruise to a child.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Nova Series 5-Drawer Chest and contact Magnussen Home for a refund. The amount of the refund will be pro-rated based on the age of the chest.', '22011');
INSERT INTO safety_incidents VALUES ('934712ae71a097192ab2be129ce852bedaf26ab9', 'CPSC', '2021-10-27', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'Ottomans', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Meridian Furniture has received six reports of laceration injuries as a result of the sharp edges on the metal band.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ottomans. Contact Meridian Furniture for a prepaid mailing package and shipping label to return the product to Meridian Furniture or provide Meridian with photographic evidence of the disposal or destruction of the product to receive a full refund.', '22012');
INSERT INTO safety_incidents VALUES ('d4264860274af69930629987ed21d55d937bc973', 'CPSC', '2021-10-27', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'myCharge powerbanks', 'Fire', 'Flammability / Overheating', 'Burns', 'myCharge has received 30 reports of the powerbanks overheating, resulting in seven injuries, including burns to the upper body, hands, legs, and/or feet of users, and/or property damage to household flooring, walls and furniture.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled powerbanks and contact myCharge for instructions on returning the battery to obtain a refund in the form of an electronic voucher for the full purchase price plus a 25% bonus for redemption on www.mycharge.com.', '22009');
INSERT INTO safety_incidents VALUES ('539f64ddee630e4412badcead527c46a2f8271cb', 'CPSC', '2021-10-22', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'Better Homes and Gardens Essential Oil Infused Aromatherapy Room Spray with Gemstones', 'Tests Conducted By The Centers For Disease Control And Prevention (Cdc) Determined That A Bottle Of The Room Spray Contained The Rare And Dangerous Bacteria Burkholderia Pseudomallei Which Causes Melioidosis, A Condition That Is Difficult To Diagnose And Can Be Fatal.', 'Microbiological Contamination', 'Not Specified', 'CDC has been investigating a cluster of four cases of melioidosis in the U.S., including two deaths. Cases were reported in Kansas, Minnesota, Texas and Georgia, including a child fatality.', 'Fatal', 1, 0, 'Consistent with CDC recommendations, consumers should immediately stop using the recalled room spray, double bag the bottle in clean, clear zip-top resealable bags, place it in a small cardboard box and return it to any Walmart store for a full refund. Do not open the bottle. Do not attempt to throw away or dispose of the bottle. Customers will also receive a $20 Walmart Gift Card upon return.', '22007');
INSERT INTO safety_incidents VALUES ('f6a339af5f7e379cf1742e80c0b266e72232c1a8', 'CPSC', '2021-10-21', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'Husqvarna and GASGAS Off-Road closed course competition motorcycles', 'Falls', 'Instability / Fall Risk', 'Skin Irritation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop riding the recalled closed course competition motorcycles and contact an authorized Husqvarna or GASGAS Motorcycles dealer to schedule a free repair, which involves inspecting the retaining "R" clips for correct mounting. Husqvarna and GASGAS Motorcycles are contacting all known purchasers directly.', '22702');
INSERT INTO safety_incidents VALUES ('73fe019ed82aae86b66312636f864c73be993f5f', 'CPSC', '2021-10-21', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'Lightform projectors', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Lightform has received 16 reports of overheating. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled projectors and contact the firm for a free software update for the projectors. Lightform is contacting all known purchasers directly.', '22703');
INSERT INTO safety_incidents VALUES ('203048d457f3a4420cadf4de3e2ce555ab11ad4f', 'CPSC', '2021-10-13', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'Specialized Tarmac SL7 Bicycles and Framesets', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The company has received two reports of the bicycle''s steerer tube breaking after harsh frontal impact. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact Specialized Bicycle Components for a free inspection and repair.', '22006');
INSERT INTO safety_incidents VALUES ('1e19d0220f812c559895cd1c0b8e12a8613eb2cb', 'CPSC', '2021-10-07', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'Zoom 360 Ultralight jogging strollers', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'There have been 25 incidents of restricted front wheel movement reported, including 12 incidents where the wheel fork bearing wore through the housing and detached, with one fall resulting in bruises when the user fell onto the stroller.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled strollers and contact the firm for a free repair kit to replace the front wheel fork bearing. Joovy is contacting all known purchasers directly.', '22701');
INSERT INTO safety_incidents VALUES ('f31e4bd55e5ed48fc5bacabac3ee3a5e4ea56385', 'CPSC', '2021-10-06', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'ElliptiGO Arc bicycles', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'ElliptiGO has received 12 reports of broken frames and 11 reports of cracked frames. Six minor injuries resulting from falls have been reported, including lacerations, abrasions, road rash and a broken helmet.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ElliptiGO Arc bicycles and contact ElliptiGO Inc. for a replacement bike, credit or refund. The amount of credit or refund will be prorated based on the age of the bike.', '22003');
INSERT INTO safety_incidents VALUES ('b5f3ec181cc8f3b64863d00d932aae439d883cba', 'CPSC', '2021-10-06', 2021, '2021-10', 'USA', 'United States', '', 'Other', 'White Wood Stools', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'Hobby Lobby has received seven reports of the stool breaking while in use, including six incidents resulting in minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled stools and return them to the nearest Hobby Lobby store for a full refund.', '22004');
INSERT INTO safety_incidents VALUES ('921f766bed04eb3b5feaf76437135b1a46fde0f3', 'CPSC', '2021-09-29', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'SONOMA Goods For Life Branded Ultimate Oversized Antigravity Chairs', 'Falls', 'Mechanical Failure', 'Fall Injury', 'Kohl''s has received 18 reports of the chairs breaking or collapsing, including two reports of minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and return them to the nearest Kohl''s store. Consumers with a receipt will receive a full refund and consumers without a receipt will receive a store credit.', '21201');
INSERT INTO safety_incidents VALUES ('a83d27d29f5741785d357c55fdccd09ad71c26b9', 'CPSC', '2021-09-29', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Luyuan Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Other', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact Luyuan for a free repair from an authorized repair shop.', '21204');
INSERT INTO safety_incidents VALUES ('9008b4e57a6f836a321a08d40599c0221f303a15', 'CPSC', '2021-09-29', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Martha Stewart Collection Oil & Vinegar Cruets', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Macy''s has received six reports of the glass cruets breaking, resulting in three lacerations, two of which required stitches.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled product and return it to a Macy''s store or contact Macy''s to return the product with free shipping for a full refund.', '21202');
INSERT INTO safety_incidents VALUES ('7cf03589003b73b8f61fb70f55bffc9e601489e8', 'CPSC', '2021-09-29', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Venom Youth All-Terrain Vehicles (ATVs)', 'Injury', 'Other', 'Not Specified', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact Venom Motorsports to arrange the return of the recalled ATVs for a full refund.', '21203');
INSERT INTO safety_incidents VALUES ('92da002868ebfbbf89a1a39a7b6d4f4c431fcb12', 'CPSC', '2021-09-23', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Model Year 2011-2021 Phoenix 200 ATV', 'The Throttle Speed Control Stop Can Break And Become Stuck, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'The firm has received 18 reports of throttle stop breaking or sticking, including one report of a crash which resulted in a minor injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact Polaris to receive a free replacement throttle speed control bracket. Polaris is notifying dealers and contacting registered owners directly.', '21784');
INSERT INTO safety_incidents VALUES ('4ed57e97a4aa8818404ed53c1ab71e0020779afd', 'CPSC', '2021-09-23', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Boppy Original Newborn Loungers, Boppy Preferred Newborn Loungers and Pottery Barn Kids Boppy Newborn Loungers', 'Infants Can Suffocate If They Roll, Move, Or Are Placed On The Lounger In A Position That Obstructs Breathing, Or Roll Off The Lounger Onto An External Surface, Such As An Adult Pillow Or Soft Bedding That Obstructs Breathing.', 'Other', 'Choking / Suffocation', 'There have been eight reports of infant deaths associated with the Boppy Company Newborn Lounger and this hazard.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled loungers and contact The Boppy Company for a refund.', '21198');
INSERT INTO safety_incidents VALUES ('65febcfa459489a3e6b9c38f477fc8996535845e', 'CPSC', '2021-09-22', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Oceanic Adult Dry Top Snorkels', 'Drowning', 'Drowning Risk', 'Drowning', 'Oceanic has received 13 reports of the snorkels leaking. One injury, involving minor cuts to a consumer who tripped after a snorkel leaked, has been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled snorkels and follow the instructions online at www.oceanicsnorkel.com to destroy the product and register for a free replacement snorkel, shipping included.', '21199');
INSERT INTO safety_incidents VALUES ('7b09333a9e2f0a3035b75bf684542602826d4296', 'CPSC', '2021-09-16', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Bauer Forced Air Propane Portable Heaters', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 13 reports of propane gas leaking, including one report of a fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled propane portable heaters and inspect the heaters with a soapy water leak test per these instructions (PDF) from Harbor Freight to determine that the fitting at the back of the unit is not leaking. Harbor Freight is contacting all known purchasers directly with updated instructions for use and detailed instructions on how to inspect and tighten the fittings on the heaters if necessary, using the wrench supplied with the product. If leaks persist, after self-inspection and appropriate tightening as needed, contact Harbor Freight Tools for more information.', '21782');
INSERT INTO safety_incidents VALUES ('150dec384de2c6b77eb8ecd8e76dc9d0c83918b5', 'CPSC', '2021-09-16', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'E-Z-GO PTVs and Tracker Off-Road Vehicles', 'The Parking Brake Catch Bracket Can Wear Out And Cause The Parking Brake To Fail, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'Textron Specialized Vehicles has received 19 reports of worn parking brake latch brackets. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles. Textron Specialized Vehicles is contacting all purchasers directly to coordinate a free repair. Consumers may contact Textron per the information listed below.', '21783');
INSERT INTO safety_incidents VALUES ('4095daf65592a210f50c5adfe6c991e3de60cb41', 'CPSC', '2021-09-15', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Gas One propane adapter hoses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Gas One has received five reports of adapter hoses swelling. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the adapter hose and contact Gas One to obtain a free replacement hose.', '21197');
INSERT INTO safety_incidents VALUES ('25181cb24396f8e54b6fe128c1bf0ca8df4ded1d', 'CPSC', '2021-09-09', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Ballz QR Skewers', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Burley has received 21 reports of the skewer failing. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Ballz QR Skewers and contact Burley to receive instructions on how to dispose of the skewer and to receive a free replacement skewer.', '21779');
INSERT INTO safety_incidents VALUES ('46a38590b6e37edceada118d473f6a14ffe29d65', 'CPSC', '2021-09-09', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Janod Children''s Shaving Kits', 'The Brown Trim Of The Shaving Kit Bags Contains Levels Of A Regulated Phthalate That Exceed The Prohibition Of Specific Phthalates. Banned Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled children''s shaving kit and return it to the place of purchase for a full refund.', '21194');
INSERT INTO safety_incidents VALUES ('882b022718c33863c1b3b897efc4a9aa77446537', 'CPSC', '2021-09-09', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Teak shower benches', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'Consumers have reported 81 incidents of the shower benches collapsing, breaking during use, or falling apart, including four reports of people being injured in falls. The four injuries included a fractured tailbone, persistent head and body aches and bruising.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled shower benches and return them to Costco for a full refund. Costco is contacting all purchasers directly.', '21780');
INSERT INTO safety_incidents VALUES ('a939c6ffa2c68f4b0f62ef8eadbb637bccca9dea', 'CPSC', '2021-09-09', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'VITUS 14 and VITUS 16 Kids Bikes', 'Injury', 'Other', 'Not Specified', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled bikes away from children and stop using them. Wiggle Ltd. is contacting all purchasers directly and is providing a free replacement wheel with footbrake.', '21781');
INSERT INTO safety_incidents VALUES ('7b42065f161e6a8781d4240474b587228a651d96', 'CPSC', '2021-09-02', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'StepUp Sidekick Learning Towers', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'Step2 has received 20 reports of the storage trays or steps coming loose from the tower, including one child sustaining minor bruises after falling from the tower.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled StepUp Sidekick Learning Tower and contact Step2 for a full refund or a credit on Step2.com of equivalent value or an Amazon gift card, if purchased via Amazon.com.', '21778');
INSERT INTO safety_incidents VALUES ('66cc5046eb064c5a7b047c4e33d34955c6b26755', 'CPSC', '2021-09-01', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'Top Paw® Double Diner Dog Bowls', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'PetSmart has received three reports of cuts and scratches to consumers'' hands as a result of handling the unfinished edge on the recalled dog bowls.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled dog bowls and return them to any PetSmart store for a full refund.', '21192');
INSERT INTO safety_incidents VALUES ('77418d1c2af21e65aa1a77d534cc6f7a059b2dd9', 'CPSC', '2021-09-01', 2021, '2021-09', 'USA', 'United States', '', 'Other', 'TurboSke Kids Toddler Bike Helmets', 'Injury', 'Other', 'Not Specified', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled kids bike helmets and return them free of charge to SKE Outdoors for a full refund or free replacement helmet.', '21193');
INSERT INTO safety_incidents VALUES ('def05685b5deb5712e233cd0774af473b3e3454b', 'CPSC', '2021-08-26', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Cutie Spoovel children''s eating utensils', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Ryan and Rose have received three reports of the Cutie Spoovel handle breaking when a child bit down on it. No injuries or reports of choking have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled utensils away from children, dispose of them, and contact Ryan and Rose to receive a full refund or a $20 shop credit. Ryan and Rose is directly notifying all known purchasers of the product recall.', '21777');
INSERT INTO safety_incidents VALUES ('45d5120898c9c5167173d8f9c56d211a51bbdd17', 'CPSC', '2021-08-25', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Hovertrax 2.0 Self-Balancing Scooters/Hoverboards with GLW Battery Packs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'There have been more than 20 reports of Hovertrax 2.0 Self-Balancing Hoverboards containing GLW battery packs overheating, including some reports of smoke or fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled self-balancing scooters/hoverboards and contact Razor for instructions on how to obtain a prepaid shipping carton to send the GLW battery pack back to Razor, and to receive a free replacement battery pack.', '21189');
INSERT INTO safety_incidents VALUES ('fc4f4f4df2786e9f78b41a12b2ddc55ca475e4bd', 'CPSC', '2021-08-25', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Ocean and Safari animal wooden tray puzzles', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received six reports of puzzle pieces breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled puzzles away from children and contact Wee Gallery for a refund in the form of a $35 gift certificate for the purchase of any Wee Gallery product.', '21188');
INSERT INTO safety_incidents VALUES ('42fdfcfeefa6a4dcb9023e9bb47cc19457c8eeb3', 'CPSC', '2021-08-19', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Infant Bath Seats', 'Drowning', 'Instability / Fall Risk', 'Drowning', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled infant bath seats and contact Frieyss for instructions on returning the bath seats with free shipping to receive a full refund. Frieyss is contacting all known purchasers directly.', '21775');
INSERT INTO safety_incidents VALUES ('fed72b345fd8837226fecd145a7a88466a893eaa', 'CPSC', '2021-08-19', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'John Deere compact utility tractors', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'John Deere has received one report of a wheel falling off. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled tractors and contact an authorized John Deere dealer for a free inspection and repair of the wheel mounting bolts. John Deere is contacting all known purchasers directly.', '21776');
INSERT INTO safety_incidents VALUES ('d51d282c85fc5c186c824188e8ed8738e7ca859a', 'CPSC', '2021-08-18', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Teether Rings with Decorative Fabric and Plush Attachments', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Hallmark has received four reports of the wooden teether rings breaking, including one report of a child placing broken wooden parts in their mouth and one report of a pinched lip.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled teethers away from children and contact Hallmark to receive a $25 gift card towards any product at Hallmark Gold Crown Stores or online at www.hallmark.com.', '21181');
INSERT INTO safety_incidents VALUES ('2d9632d6ef293e3f3c3eac5a9a1ee5b844ac802d', 'CPSC', '2021-08-18', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'B-Air VP-33 Blower Fans', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Intertex has received five reports of the capacitor overheating in the blower fans and causing fire-related property damage totaling about $75,000. No injuries have been reported.', 'Minor', 1, 0, 'Purchasers should immediately stop using the recalled blower fans and contact the firm for a free repair kit including an S-3 capacitor and installation instructions.', '21182');
INSERT INTO safety_incidents VALUES ('be92bea1452f918cd3e1c73da05f8b884f1a9058', 'CPSC', '2021-08-18', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Mountain Bicycles', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received nine reports of broken bottom brackets. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact Marin Bikes for instructions on receiving a free replacement bottom bracket and scheduling a free repair.', '21183');
INSERT INTO safety_incidents VALUES ('13bc2895638e3c8989f5f92beb7d3ef5a93fe11b', 'CPSC', '2021-08-18', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Tucker & Tate children''s socks', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Customers should immediately stop using the recalled children''s socks and contact Nordstrom to receive a full refund.', '21187');
INSERT INTO safety_incidents VALUES ('8e121497a4cf96357f310b58ee3f16ea428abe84', 'CPSC', '2021-08-18', 2021, '2021-08', 'USA', 'United States', '', 'Other', '8-Pack Scent Stamper Pens', 'The Purple Scent Stamper Pen Has Elevated Levels Of Benzyl Alcohol, Posing A Risk Of Skin Irritation.', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Stamper Pens and return them to a Primark store for a full refund.', '21185');
INSERT INTO safety_incidents VALUES ('541623f9bb40679df2e570362bb62c5f64767357', 'CPSC', '2021-08-18', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Ravin® white arrow nocks', 'Injury', 'Other', 'Not Specified', 'The firm has received 51 reports of finger injuries while nocking or re-nocking the white nocks, including 21 serious injuries, and 28 new finger injuries reported since the original recall announcement. The firm has also received reports of other injuries resulting from maintenance and other issues.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled white arrow nocks and contact Ravin Crossbows for free replacement orange nocks and up to a $1 merchandise credit for each recalled nock that is returned. Follow the manufacturer''s instructions and maintenance guidelines for continued safe operation of the crossbows and nocks.', '21186');
INSERT INTO safety_incidents VALUES ('6919ab6e0bd1d4d0c0d527f3c97b0902ff09fc39', 'CPSC', '2021-08-18', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Swivel Counter Stools', 'Injury', 'Mechanical Failure', 'Fall Injury', 'TJX has received 20 reports of stools breaking in which consumers fell, including 17 reports of minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled counter stools and return them to any HomeGoods or Homesense store for their choice of either a full refund or store gift card.', '21184');
INSERT INTO safety_incidents VALUES ('95e2545cbc10190a56780f4a446ad78e8c1ecdc4', 'CPSC', '2021-08-17', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Zen Magnets and Neoballs Magnets', 'When Two Or More High-Powered Magnets Are Swallowed, Either Accidentally Or Intentionally, The Ingested Magnets Can Attract To Each Other, Or To Another Metal Object, And Become Lodged In The Digestive System. This Can Result In Perforations, Twisting And/Or Blockage Of The Intestines, Infection, Blood Poisoning, And Death.', 'Other', 'Poisoning / Ingestion', 'Zen Magnets LLC is aware of two children who ingested Zen Magnets and required surgery to remove the magnets and parts of their intestines and bowels. In addition, CPSC is aware of other reports of children and teenagers ingesting high-powered magnets and requiring surgery. A 19-month-girl died after ingesting similar high-powered magnets.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled magnets and contact Zen Magnets LLC for a refund.', '21179');
INSERT INTO safety_incidents VALUES ('89c1d5adf7540dcc2a3032a346446ccfb3312af2', 'CPSC', '2021-08-12', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Pacapet Fluffy Pink Area Rugs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None Reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled rugs and contact Pacapet for instructions to return the recalled rugs with free shipping in exchange for a full refund. Amazon, on behalf of Pacapet, is contacting all known purchasers directly.', '21772');
INSERT INTO safety_incidents VALUES ('d1bdd67105c01dbb266ea825fe8619de55cc4d33', 'CPSC', '2021-08-12', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Rossignol 2018 and 2019 Model Year All Track DH Bicycles', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact Rossignol for information on receiving a free replacement front triangle of the bicycle frame. Rossignol is contacting all known purchasers directly to arrange for free replacement parts and installation.', '21773');
INSERT INTO safety_incidents VALUES ('2854f41de52a5e59c0ec0cf8d7c90f858cb20a0e', 'CPSC', '2021-08-12', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'YOH Super Soft Purple Rugs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None Reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled rugs and contact Suellen Roosevein for instructions on how to receive a full refund, including shipping. Amazon, on behalf of Suellen Roosevein, is contacting all known purchasers directly.', '21774');
INSERT INTO safety_incidents VALUES ('d1fedde244b7bbc9ebf4cc994340665dd9934897', 'CPSC', '2021-08-12', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Andecor Girls Soft Tye Dye Area Rugs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None Reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled rugs and contact And Beyond for instructions on how to receive a full refund, including shipping. Amazon, on behalf of And Beyond, is contacting all known purchasers directly.', '21771');
INSERT INTO safety_incidents VALUES ('34f3015fd2682fd5bdf71b87d28640e7edb4cbc0', 'CPSC', '2021-08-11', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Delayed Egress Locks', 'The Lockset Can Fail To Open, Posing An Entrapment Hazard And Inability To Vacate A Location In An Emergency.', 'Entrapment', 'Entrapment', 'The firm has received reports of 56 incidents with the recalled locks. No injuries have been reported.', 'Minor', 1, 0, 'Facilities using the recalled locks should contact the firm for instructions on receiving a free repair of the firmware by a technician.', '21177');
INSERT INTO safety_incidents VALUES ('0e88c8778eb02803f8a742c11b37b61ea84372af', 'CPSC', '2021-08-04', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'LG Chem "RESU10H" Lithium-Ion Residential Energy Storage System Batteries', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received five reports of the lithium storage batteries smoking and catching on fire, resulting in property damage and one injury.', 'Minor', 1, 0, 'Consumers with recalled batteries should immediately contact LG Energy Solution Michigan to schedule a free replacement. LG Energy Solution Michigan will arrange for modifications to recalled batteries that are connected online to reduce the risk of overheating until they can be replaced with new batteries. LG Energy Solution Michigan, its distributors, and its installers also are attempting to contact owners directly.', '21175');
INSERT INTO safety_incidents VALUES ('5ba626d95282ae63d7cfda6aef0a6f9764967ec0', 'CPSC', '2021-08-04', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'True Living Sling Loungers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received three reports of the sling loungers collapsing, resulting in amputations or lacerations to fingers from the metal folding joints.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled sling loungers, cut the fabric of the chair rendering it unusable, and contact Dollar General to return the recalled loungers for a full refund of the purchase price.', '21176');
INSERT INTO safety_incidents VALUES ('36c9e8786bc0f4423a25859724f8d1412633a196', 'CPSC', '2021-08-04', 2021, '2021-08', 'USA', 'United States', '', 'Other', 'Dehumidifiers', 'Fire', 'Flammability / Overheating', 'Burns', 'New Widetech is aware of 107 incidents of the recalled dehumidifiers overheating and/or catching fire, resulting in about $17 million in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the dehumidifiers immediately and contact New Widetech for a refund. The amount of the refund will be pro-rated based on the age of the dehumidifier.', '21174');
INSERT INTO safety_incidents VALUES ('a4fe20b2854ce5d271f1ec0b31111c8553e39530', 'CPSC', '2021-07-29', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Children''s Sleepwear Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear sets away from children and stop using them. SHEIN will contact all known purchasers. Upon returning the garment, SHEIN will refund consumers the purchase price and provide a $10.00 gift card.', '21769');
INSERT INTO safety_incidents VALUES ('89e0921b524a2b333f10568d795a4455dc233100', 'CPSC', '2021-07-29', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Generac® and DR® 6500 Watt and 8000 Watt portable generators', 'An Unlocked Handle Can Pinch Consumers'' Fingers Against The Generator Frame When The Generator Is Moved, Posing Finger Amputation And Crushing Hazards.', 'Entrapment', 'Entrapment', 'Generac has received eight reports of injuries, seven resulting in finger amputations and one in finger crushing.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled portable generators, unless the locking pin has been inserted to secure the handle in place before and after moving the generator, and contact Generac for a free repair kit.', '21173');
INSERT INTO safety_incidents VALUES ('89b41f4909d03acd6b0121d4fc2147180c27a60d', 'CPSC', '2021-07-29', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Specialized 1st Generation Turbo Levo and Kenevo electric mountain bike battery packs', 'Fire', 'Electrical Fault', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled electric mountain bikes and contact Specialized Bicycle for a free repair. Specialized is contacting purchasers directly about the recall. Consumers should not charge the recalled battery pack or expose it to wet conditions until it has been repaired by an authorized Specialized retailer.', '21770');
INSERT INTO safety_incidents VALUES ('6de1ca2ab5ae8f3545e5c8aefc972ff62d8532b7', 'CPSC', '2021-07-28', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Birkenstock Kids'' Mogami Sandals Sizes 24-28', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled sandals away from children and return the sandals to the place of purchase for a full refund.', '21172');
INSERT INTO safety_incidents VALUES ('2dabb7ac224becd5ecc7c8716c2fc3eb780e28be', 'CPSC', '2021-07-28', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Children''s Pajamas', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled pajamas away from children and stop using them. Amazon and/or Tkala Fashion will contact all known purchasers with information on how to receive a refund. If you do not receive communication from either Amazon or Tkala Fashion, contact Tkala Fashion.', '21171');
INSERT INTO safety_incidents VALUES ('ea98f00f55c7048481be810da13e579362b6781c', 'CPSC', '2021-07-27', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Removable Foam Facial Interfaces for Oculus Quest 2 Virtual Reality Headsets', 'Burns', 'Other', 'Skin Irritation', 'The firm has received approximately 5,716 reports of incidents of skin irritation and approximately 45 reports of consumers that required medical attention.', 'Moderate', 1, 0, 'Consumers who experience a skin irritation or reaction should immediately stop using the recalled foam facial interface, and all consumers should contact Facebook Technologies to receive a free silicone cover. Facebook Technologies is contacting all Quest 2 users directly.', '21768');
INSERT INTO safety_incidents VALUES ('6eb58190035c17ed647883b0d88191d7fc76f33a', 'CPSC', '2021-07-22', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Barrington 5-Drawer Chests', 'The Recalled Chests Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Death Or Serious Injuries To Children. The Chests Do Not Comply With The Performance Requirements Of The Voluntary Industry Standard Astm F2057-14.', 'Entrapment', 'Entrapment', 'Bel Furniture has received one report of the chest tipping over and injuring a child.', 'Fatal', 1, 0, 'Consumers should immediately stop using the 5-Drawer Chests and contact Bel Furniture for a full refund with free pick-up of the dresser or consumers can return the drawer slides for free and dispose of the dresser, or for a free installation of tip-over restraints by Bel Furniture. Bel Furniture is contacting all purchasers directly.', '21764');
INSERT INTO safety_incidents VALUES ('8544908bf797f9ffdab37eb2f5c9b087cb7b5c77', 'CPSC', '2021-07-22', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Model Years 2020 and 2021 Can-AM Defender HD10 side-by-side vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'BRP has received three reports of incidents involving fires. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using track kits on the recalled vehicles in snow conditions and contact a Can-Am dealer for a free repair. BRP is contacting all known purchasers directly.', '21767');
INSERT INTO safety_incidents VALUES ('b6a5d0c0d8ec043bd465737a35f70e6996864eff', 'CPSC', '2021-07-22', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Model Year 2021 GENERAL 1000, GENERAL 4 1000, GENERAL XP 1000 and GENERAL XP 4 1000 ROVs', 'The Weld Between The Brake Pedal Pivot Bracket And The Eps Mounting Bracket Can Separate, Which Can Result In A Loss Of Brake Function, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and if needed, a free repair. Polaris is notifying dealers and contacting registered owners directly.', '21765');
INSERT INTO safety_incidents VALUES ('32987ac03f671e69915858963141f126bfe2258b', 'CPSC', '2021-07-22', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Model Year 2021 RZR Pro XP and RZR Pro XP 4 Recreational Off-Road Vehicles (ROVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair. Polaris is notifying dealers and contacting registered owners directly.', '21766');
INSERT INTO safety_incidents VALUES ('1dac9b5254e276b69692583198bfbd6c3a3bcd6d', 'CPSC', '2021-07-21', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Caldwell E-Max® Pro BT Earmuffs with rechargeable lithium battery packs', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately remove the recalled lithium-battery pack from the earmuffs and contact American Outdoor Brands for disposal instructions in accordance with local laws and to receive free replacement alkaline batteries; including shipping.', '21167');
INSERT INTO safety_incidents VALUES ('fff6f79d3c74a614938372de2f79ab17324bf948', 'CPSC', '2021-07-21', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'One Stop Gardens 15,000 and 30,000 BTU Tank Top Propane Heaters', 'Burns', 'Other', 'Burns', 'The firm has received reports of nine incidents of flame redirection to the rear of the heater and/or the tip switch safety feature melting. Three of these incidents resulted in minor burn injuries when the consumers attempted to turn off the unit.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled tank top propane heaters and return them to their local Harbor Freight Tools store for a full refund of the purchase price, plus applicable tax, in the form of a Harbor Freight Tools gift card. Harbor Freight Tools is contacting all known purchasers directly.', '21168');
INSERT INTO safety_incidents VALUES ('0a9ff9b2ce147cff545044dbfd715dbf64db17ac', 'CPSC', '2021-07-21', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Rechargeable handheld fans', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Rite Aid has received two consumer reports of the rechargeable handheld fans overheating and emitting smoke. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled rechargeable handheld fans and contact Rite Aid for a full refund.', '21169');
INSERT INTO safety_incidents VALUES ('ae644fa1ccf6da6f8b844ae8b30ebf79f6aa0adf', 'CPSC', '2021-07-15', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Arroyo and Hideaway Wood Burning Fire Pits', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Real Flame has received one report of a fire involving minor property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Arroyo or Hideaway Wood Burning Fire Pits and contact Real Flame to arrange for removal of the fire pit in exchange for a full refund. Real Flame is contacting all known purchasers directly.', '21763');
INSERT INTO safety_incidents VALUES ('2efc3608d03e43b80023cfa3df215629c70d807a', 'CPSC', '2021-07-14', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Ozone 500® Girls'' and Boys'' Elevate 24-Inch Bicycles', 'Injury', 'Entrapment', 'Electric Shock', 'Academy has received one report of a person injuring their hand under the seat when the rear shock spring compressed.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and bring them to any Academy Sports + Outdoors store for a free repair or a full refund. Consumers can also contact Academy Sports + Outdoors for a replacement shock and repair instructions or to receive a pre-paid shipping label to return the bicycle for a full refund.', '21163');
INSERT INTO safety_incidents VALUES ('aa27f3c1c8c054cc7b5e5ba06abeb9c5199ae379', 'CPSC', '2021-07-14', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Disney Baby Winnie the Pooh Rattle Sets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Walgreens has received 8 reports of the feet on the Winnie the Pooh rattle detaching. No Injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled rattle away from young children and contact Walgreens for a full refund.', '21164');
INSERT INTO safety_incidents VALUES ('445657343faa286166d5fa2c1373891e1a9799c0', 'CPSC', '2021-07-08', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Creekside Kids Five-Drawer Chests', 'The Recalled Chests Are Unstable If They Are Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Death Or Serious Injuries To Children. The Chests Do Not Comply With The Performance Requirements Of The Voluntary Industry Standard Astm F2057-19.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled chests and contact Rooms To Go for a free repair, replacement, or a full refund of the purchase price in the form of a Rooms To Go store credit, including free pick-up of the chest. Rooms To Go is contacting all known purchasers directly.', '21761');
INSERT INTO safety_incidents VALUES ('fa8acac30fefad00fcc7fd0b90679cd2085f0d31', 'CPSC', '2021-07-08', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'ECHO EGi-2300 Watt Generators', 'Fire', 'Flammability / Overheating', 'Burns', 'Echo has received four reports of the generator overheating or catching fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled generators and contact ECHO for instructions on how to obtain a free repair. ECHO is contacting all known purchasers directly.', '21760');
INSERT INTO safety_incidents VALUES ('1808858609f2938155cef432709904637a35c322', 'CPSC', '2021-07-08', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'SOWTECH Espresso Machines with Glass Carafes', 'Burns', 'Other', 'Burns', 'The firm has received 48 reports of the glass carafe breaking, resulting in five burn injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled espresso machines and contact LoHi Tech to receive a free replacement metal carafe. LoHi Tech is contacting all purchasers directly.', '21762');
INSERT INTO safety_incidents VALUES ('b0482de5d6d1255161a34cfa91241127324517ab', 'CPSC', '2021-07-07', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Children''s Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled garments and contact One Twenty Clothing Company US LLC for instructions on returning the garments with free shipping to receive a full refund.', '21160');
INSERT INTO safety_incidents VALUES ('e96bb847da51a0dbee6b9fc6b168f2a1b86c4603', 'CPSC', '2021-07-01', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'Deep Frame Mirrors', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Rejuvenation has received 18 reports of the glass mirror detaching and falling out of the frame, causing the glass to break. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled mirrors and contact Rejuvenation for a full refund or a free replacement. Rejuvenation is contacting all known purchasers directly.', '21758');
INSERT INTO safety_incidents VALUES ('5984af01d903caf80a3f2b769ecebe52310eef0d', 'CPSC', '2021-07-01', 2021, '2021-07', 'USA', 'United States', '', 'Other', 'The Best Damn Liquids branded liquid nicotine', 'Liquid Nicotine Must Be In Special Packaging As Required By The Child Nicotine Poisoning Prevention Act (Cnppa). The Packaging Of The Products Is Not Child-Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed Or Touched By Young Children. Liquid Nicotine Is Toxic If Ingested Or Absorbed Through The Skin Or Eyes.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled products, store them out of the reach of children and contact TBD Liquids for a full refund in the form of a gift card or free replacement. TBD Liquids is contacting all known purchasers directly.', '21759');
INSERT INTO safety_incidents VALUES ('12b24918aefa9c93caae3b900ce21ce247d6f62a', 'CPSC', '2021-06-30', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Children''s Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled garments and contact Auranso Official for instructions on returning the garments with free shipping to receive a full refund.', '21156');
INSERT INTO safety_incidents VALUES ('533e255c00dd0f29f3ca11e95a853529c2dfb136', 'CPSC', '2021-06-30', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Children''s Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled garments and contact Booph for instructions on returning the garments with free shipping to receive a full refund.', '21157');
INSERT INTO safety_incidents VALUES ('ef75908ffe1b517a23581f75c241d5d6bbe42903', 'CPSC', '2021-06-30', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Children''s Robes', 'Fire', 'Flammability / Overheating', 'Burns', 'The children''s robes fail to meet the federal flammability standards for children''s sleepwear, posing a risk of burn injuries to children.', 'Minor', 0, 0, 'Consumers should immediately stop using the recalled garments and contact SIORO for instructions on returning the garments with free shipping to receive a full refund.', '21159');
INSERT INTO safety_incidents VALUES ('0dd04df17d79408e1f36dfd69f5e3dd708cd4cf9', 'CPSC', '2021-06-30', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'UPPAbaby adapters included with Rumbleseats', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 135 reports of detachments, including 77 incidents resulting in bumps, scrapes and two reports of broken noses.', 'Moderate', 1, 0, 'Consumers who own a RumbleSeat accessory, manufactured between September 2014 and July 2019, will be provided with replacement RumbleSeat adapters. Consumers should immediately stop using the recalled adapters and contact UPPAbaby to receive free replacement adapters. Consumers should go to www.uppababy.com to confirm their RumbleSeat accessory adapters are included in the recall. If the adapter does not have a yellow tab, immediately stop using the recalled RumbleSeat accessory with the adapters and fill out the form on the UPPAbaby website in order to receive a free replacement adapter set.', '21158');
INSERT INTO safety_incidents VALUES ('5aaa8339bd822120c01d61f63ad5d5c2137a4f6d', 'CPSC', '2021-06-24', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Brushed Gold Tea Kettles', 'Burns', 'Drowning Risk', 'Burns', 'Gramr has received 122 reports of the kettles expelling hot water and/or steam, including 18 reports of minor burn injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the kettles and contact Gramr for a credit towards the purchase of another product or a refund. Gramr is contacting all known purchasers directly.', '21756');
INSERT INTO safety_incidents VALUES ('980c3d779a1be4c10840eb3774f6038b9cb1f2db', 'CPSC', '2021-06-24', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Girls'' Nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled children''s nightgowns and contact La Paloma for a full refund. La Paloma is contacting all known purchasers directly.', '21757');
INSERT INTO safety_incidents VALUES ('5709e9068924dc2e30388dd722311dcd698554a8', 'CPSC', '2021-06-24', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Wintergreen Essential Oil, Birch Essential Oil, Headache Relief Essential Oil Blend, Headache Relief Roll-On Essential Oil Blend, and Deep Muscle Essential Oil Blend', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled essential oils, store the products in a safe location out of reach of children, and contact Plant Guru for a full refund for the roll-on products and a free child-resistant replacement cap for the bottles. All known purchasers are being contacted directly.', '21755');
INSERT INTO safety_incidents VALUES ('408329d156aeb45f99f9d588c24c037e29f57f1b', 'CPSC', '2021-06-16', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Cove Appliance 24-inch built-in dishwashers', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received five reports of burning smells, flames and smoking inside the dishwashers. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled dishwashers, unplug them from their power source, and contact Cove Appliance to schedule a free repair. Cove Appliance will install a second thermal protection device and replace the dishwasher''s heating element.', '21151');
INSERT INTO safety_incidents VALUES ('bbf15265d3097ae456e6861fec994a9c8765f174', 'CPSC', '2021-06-10', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Children''s Barhee Fishing Hero Toy Games', 'The Metal Rollers On The Bottom Of The Flying Dinosaur Figures Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled toys away from children and contact Blue Star Trading for a full refund. Blue Star Trading is contacting all purchasers directly.', '21754');
INSERT INTO safety_incidents VALUES ('7e15b825811312161e657bd839851f1b68da75f8', 'CPSC', '2021-06-10', 2021, '2021-06', 'USA', 'United States', '', 'Other', '2021 Can-Am Outlander and Renegade ATVs', 'The Steering Knuckle Can Detach From The Lower Arm, Resulting In A Loss Of Control Of The Vehicle, Posing A Crash Hazard.', 'Mechanical Failure', 'Skin Irritation', 'BRP has received one incident of a detached steering knuckle resulting in the rider losing control and crashing. No injuries were reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Can-Am dealer for a free repair. BRP is contacting all known purchasers directly.', '21753');
INSERT INTO safety_incidents VALUES ('95a198ab68d0c7e0a6d7df62587ac3883128a390', 'CPSC', '2021-06-09', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'CamelBak Podium and Peak Fitness water bottles', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'CamelBak has received 14 reports of the silicone valve coming loose in the cap and detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled caps sold with the water bottles and contact CamelBak for a free replacement cap.', '21149');
INSERT INTO safety_incidents VALUES ('84df98f9f36aa058e93c9b241155d3e638bf065b', 'CPSC', '2021-06-09', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Klein Tools Non-Contact Voltage Tester Model NCVT-1', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'Klein Tools has received two reports of incidents of the voltage tester not working properly, including one shock injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled non-contact voltage testers and contact Klein Tools for instructions on receiving a free replacement tool.', '21150');
INSERT INTO safety_incidents VALUES ('389d642b657433e2c0fc5a09f5572698540b890e', 'CPSC', '2021-06-03', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Fisher-Price 4-in-1 Rock ''n Glide Soothers and 2-in-1 Soothe ''n Play Gliders', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'There have been reports of four infant deaths in the 4-in-1 Rock ''n Glide Soother. The infants were reportedly placed on their backs unrestrained in the product and later found on their stomachs. These incidents occurred between April 2019 and February 2020. The fatalities were a 4-month old from Missouri, a 2-month old from Nevada, a 2-month old from Michigan and an 11-week old from Colorado. There have been no fatalities in the 2-in-1 Soothe ''n Play Gliders.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled products and contact Fisher-Price for a refund.', '21147');
INSERT INTO safety_incidents VALUES ('e47fa22d4368a5db86da6d2e054cb59de5faf8db', 'CPSC', '2021-06-03', 2021, '2021-06', 'USA', 'United States', '', 'Other', 'Kalorik Pro 1500F Electric Steakhouse Grills', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'The firm has received reports that five consumers received electric shocks from the recalled grills, including three in the United States and two in Canada.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Electric Steakhouse Grills and contact Kalorik for a free repair kit to replace the electroplated control knobs. Kalorik is contacting all purchasers directly.', '21752');
INSERT INTO safety_incidents VALUES ('3ae3f7be77f2ed839bdec95f3e8deb7b63a779b8', 'CPSC', '2021-05-27', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Umbrosa umbrellas equipped with the Umbrosa Evolution Arm/Holder', 'Injury', 'Other', 'Not Specified', 'Umbrosa has received five reports of the umbrellas breaking at the elbow. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled umbrellas and contact Umbrosa to receive a free replacement arm/holder. Umbrosa is contacting all known purchasers directly.', '21751');
INSERT INTO safety_incidents VALUES ('7d4f8d5214c8e5fb193bd09128db9ff1d746884f', 'CPSC', '2021-05-27', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Williams Advanced Materials & Chemicals Recalls Three Chemical Products Due to Failure to Meet Child-Resistant Packaging Requirement and Violation of FHSA Labeling Requirement (Recall Alert)', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach of children and contact Williams Advanced Materials & Chemicals for a free replacement child-resistant cap and label. Williams Advanced Materials & Chemicals is contacting all purchasers directly.', '21750');
INSERT INTO safety_incidents VALUES ('837eb6dee219eea731d276852e575db0982db5c7', 'CPSC', '2021-05-26', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'METROUS1, METROUS2 and METROUS4 Compact City Strollers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received 15 consumer reports of the button on the buckle that releases the harness breaking and detaching when pressed by the user, making it difficult to release the buckle. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled strollers and contact Ergobaby for instructions and a full free replacement restraint harness with buckle.', '21139');
INSERT INTO safety_incidents VALUES ('5a36472d2a745c7e7be47381bdaf8e84690c6bbb', 'CPSC', '2021-05-26', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Joy/JM-branded My Little Steamer® and My Little Steamer® Go Mini', 'Burns', 'Drowning Risk', 'Burns', 'HSN has received 227 reports of hot water spraying or leaking from the steamers, including 106 reports of burn injuries. These reports include eight reports of second-degree burns and six reports of third-degree burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled clothing steamers and contact HSN for information about how to receive a full refund for units purchased from January 2018 to December 2020, a partial refund for units purchased from January 2015 to December 2017, or a voucher for units purchased before January 2015.', '21138');
INSERT INTO safety_incidents VALUES ('706ee66f57380624cb11c9a6fcf82d3397ba12c5', 'CPSC', '2021-05-26', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Arizona Jean Co. "Lilac Smoke" Girls Midweight Puffer Jackets', 'The Puffer Jackets Have A Drawstring Located Inside The Lining Of The Bottom Area Of The Garment. The Drawstring Can Become Entangled Or Caught On Playground Slides, Handrails, School Bus Doors Or Other Moving Objects, Posing An Entanglement Hazard To Children.', 'Other', 'Not Specified', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled jacket away from children, cut and remove the drawstring to eliminate the hazard, or contact JCPenney for instructions on how to return the jacket and obtain a full refund of the original purchase price, shipping included.', '21140');
INSERT INTO safety_incidents VALUES ('87f91b4329a5b9832c92946bb35b79b921e4d21e', 'CPSC', '2021-05-26', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Room Essentials Shower Stools', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Target has received 12 reports of consumers falling off the recalled shower stools, including four reports of bruises, bumps and scratches, and one report of an arm sprain.', 'Moderate', 1, 0, 'Consumers should stop using the recalled shower stools immediately and return the shower stools to any Target store or contact Target for a full refund.', '21141');
INSERT INTO safety_incidents VALUES ('0f17b7550512e56c617ffea597256985e61760f5', 'CPSC', '2021-05-26', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Bontrager Satellite City Bicycle Pedals', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'Trek has received 132 reports of the recalled pedals loosening, locking up or falling off, including seven reports of riders falling and experiencing injuries, including scrapes, bruises and road rash.', 'Moderate', 1, 0, 'Consumers should immediately stop using bicycles equipped with the recalled pedals and contact their local authorized Trek retailer for instructions on receiving free installation of replacement pedals.', '21142');
INSERT INTO safety_incidents VALUES ('61c158c3ae5cae4753ca32dcf9e6b8e0493c90e5', 'CPSC', '2021-05-20', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'John Deere XUV590 and XUV590 S4 Gator™ utility vehicles', 'Injury', 'Mechanical Failure', 'Skin Irritation', 'Deere & Company has received four reports of speedometers malfunctioning. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact an authorized John Deere dealer for a free software update. John Deere is contacting all known purchasers directly.', '21748');
INSERT INTO safety_incidents VALUES ('bb42f2d7e7dba7821bf29b2c9af78c85e3269fe8', 'CPSC', '2021-05-20', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Pro Supply Outlet (PSO) Sodium and Potassium Hydroxide', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach of children and contact Pro Supply Outlet for a free replacement child-resistant cap and label to put on the product. Pro Supply Outlet is contacting all purchasers directly.', '21749');
INSERT INTO safety_incidents VALUES ('ef52c308f23598bf099f48960b6c293e77bbfaf8', 'CPSC', '2021-05-19', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Cheyenne Products Mainstay folding metal padded chairs and barstools', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 41 reports of incidents of the weld connecting the legs to the bottom of the chair breaking, resulting in 19 injuries, including four reports of fractures and one report of a torn ligament.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled folding chairs and barstools and contact Cheyenne for a full refund.', '21137');
INSERT INTO safety_incidents VALUES ('fe7f576cd79153e033a0a5d89c0d281a8cf91bf5', 'CPSC', '2021-05-19', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'IKEA Recalls Bowls, Plates, and Mugs Due to Burn Hazard', 'Burns', 'Mechanical Failure', 'Burns', 'IKEA is aware of 123 reports of breakage worldwide, including four reports of injuries, two of which required medical attention. Most of the injuries were burns due to hot contents leaking out. This includes one incident, without injury, in the United States.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bowls, plates, and mugs and return them to any IKEA store for a full refund.', '21136');
INSERT INTO safety_incidents VALUES ('44c278ee34d72c6e89d7c114b3a57fbfd8ae33c9', 'CPSC', '2021-05-13', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Sodium Hydroxide Flakes, Pure Lye, Caustic Soda Drain Cleaner and Sodium Hydroxide Flake (Caustic Soda Flake)', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of sight and reach of children. Contact Alliance Chemical for a free replacement child resistant packaging and label to put on the product. Alliance Chemical is contacting all known purchasers directly.', '21743');
INSERT INTO safety_incidents VALUES ('61155bf1034ab3a30f3787e1925389b34dc2a0bb', 'CPSC', '2021-05-13', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Model Year 2021-2022 Ski-Doo snowmobiles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'BRP has received 10 reports of overheating mufflers, including three incidents that resulted in fires. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using their recalled vehicles immediately and contact a Ski-Doo dealer for a free repair. BRP is contacting all known purchasers directly.', '21746');
INSERT INTO safety_incidents VALUES ('f7016ad993c8d027cc9e7b7f1aad59147212391a', 'CPSC', '2021-05-13', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Backyard Discovery Big Brutus, Little Brutus and Mini Brutus metal A-frame swing sets', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'Leisure Time Products has received three reports of the swing hanger attachment failing, which resulted in one side of the swing falling. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled swing sets and contact Leisure Time Products for a free repair kit. Leisure Time Products is contacting all purchasers directly.', '21747');
INSERT INTO safety_incidents VALUES ('6cfdd62a7d613cbd53940db94b071e0e01b0b810', 'CPSC', '2021-05-13', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Model Year 2021 RZR PRO XP and RZR PRO XP 4 (ROVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of a leak in the oil supply line. No fires, injuries, or property damage have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair. Polaris notified all dealers and contacted registered owners directly.', '21744');
INSERT INTO safety_incidents VALUES ('499e8dd0ad1e5e8ee1acb29bd5fb2b86ca425f1e', 'CPSC', '2021-05-13', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'The Lye Guy Sodium Hydroxide and Potassium Hydroxide', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of sight and reach of children. Contact The Lye Guy for free replacement child resistant packaging and a new label. All known purchasers are being contacted directly by the firm.', '21745');
INSERT INTO safety_incidents VALUES ('bb905575ca2a25705ae2d9dd5910d64c2ed62a12', 'CPSC', '2021-05-12', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'YTL, Longli and TIYA Log Splitters with Briggs & Stratton® 250cc engines', 'Injury', 'Flammability / Overheating', 'Fracture / Blunt Trauma', 'The company is aware of two incidents, which resulted in broken wrists.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled log splitters and contact an authorized Briggs & Stratton dealer for a free inspection and repair.', '21133');
INSERT INTO safety_incidents VALUES ('f8520356482cefdd34f1ecdc5a011bdc0e408cc1', 'CPSC', '2021-05-12', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Wild Republic Slap Watches', 'Choking', 'Small Parts / Choking Hazard', 'Poisoning / Ingestion', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately take the slap watches away from children, stop using them and contact Wild Republic for a full refund.', '21134');
INSERT INTO safety_incidents VALUES ('5db4c9fcba14e96c141c0c74c864ee1ee47618ba', 'CPSC', '2021-05-06', 2021, '2021-05', 'USA', 'United States', '', 'Other', '2021 CFORCE 800XC All-Terrain Vehicles (ATVs)', 'The Electronic Power Steering (Eps) Can Malfunction And Cause The Rider To Lose Control Of The Vehicle, Posing A Crash Hazard.', 'Mechanical Failure', 'Skin Irritation', 'CFMOTO has received three reports of the EPS failing and loss of vehicle control. Two injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ATVs and contact a CFMOTO dealer to schedule a free repair. CFMOTO is contacting all registered owners and dealers directly.', '21742');
INSERT INTO safety_incidents VALUES ('790fb125db0375b72c9245dfb383e968a1b0b872', 'CPSC', '2021-05-06', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Kidde TruSense Smoke Alarms and Combination Smoke/Carbon Monoxide Alarms', 'Fire', 'Flammability / Overheating', 'Not Specified', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately contact Kidde for a free replacement alarm. Consumers should keep using the recalled alarms until they install replacement alarms.', '21130');
INSERT INTO safety_incidents VALUES ('fe82468b2cb29c3df3ea648ac1d5ea04be0df3af', 'CPSC', '2021-05-05', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Inclined sleeper accessory included with Kolcraft Cuddle ''n Care 2-in-1 Bassinet & Incline Sleepers and Preferred Position 2-in-1 Bassinet & Incline Sleepers', 'Infant Fatalities Have Been Reported With Other Manufacturers'' Inclined Sleep Products, After The Infants Rolled From Their Back To Their Stomach Or Side, Or Under Other Circumstances.', 'Other', 'Not Specified', 'No incidents or injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled inclined sleeper accessory and contact Kolcraft for a $35 voucher to be used on www.Kolcraft.com or a $20 refund. The voucher can be used until February 20, 2022. Kolcraft is contacting all registered owners and known purchasers directly via a postcard by mail. Consumers can continue to use the bassinet without the inclined sleeper accessory.', '21125');
INSERT INTO safety_incidents VALUES ('022e18513723583b7746d77ac36b398590a4376a', 'CPSC', '2021-05-05', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Tread', 'Injury', 'Mechanical Failure', 'Laceration / Cut', 'The firm is aware of 18 reports of the touchscreen loosening and six reports of the touchscreen detaching and falling. No injuries have been reported in the U.S. There have been reports of minor injuries such as abrasions, minor cuts, and bruises in Canada and the United Kingdom.', 'Minor', 1, 0, 'The touchscreen on the treadmill can detach and fall, posing a risk of injury to consumers.', '21129');
INSERT INTO safety_incidents VALUES ('866de8c91dbfcd063f9ca0be2327a7c5543f5481', 'CPSC', '2021-05-05', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Tread+', 'Injury', 'Sharp Edges / Points', 'Fracture / Blunt Trauma', 'A 6-year-old child recently died after being pulled under the rear of the treadmill. In addition, Peloton has received 72 reports of adult users, children, pets and/or objects being pulled under the rear of the treadmill, including 29 reports of injuries to children such as second- and third-degree abrasions, broken bones, and lacerations.', 'Fatal', 1, 0, 'Adult users, children, pets and objects can be pulled underneath the rear of the treadmill, posing a risk of injury or death.', '21128');
INSERT INTO safety_incidents VALUES ('58478de0c2997fdd41c8400e1fea4e65445804d7', 'CPSC', '2021-05-05', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'WAYNE WaterBUG GLOW Multi-Use Submersible Water Removal Pumps', 'Fire', 'Electrical Fault', 'Electric Shock', 'The firm has received 28 reports of the circuit board malfunctioning, including two reports of minor burn injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pumps and contact Scott Fetzer Consumer Brands for a free replacement WaterBUG AUTO or standard WaterBUG pump.', '21124');
INSERT INTO safety_incidents VALUES ('f80022a49921b63b3011fcdf89ed844663157da6', 'CPSC', '2021-05-05', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Pickens Flip Up Towel Grab Bars', 'Injury', 'Mechanical Failure', 'Fall Injury', 'Signature Hardware has received 13 reports of the towel bar and grab bar detaching or partially detaching from each other, including two reports that consumers fell.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled product and contact Signature Hardware for a full refund or a free replacement grab bar.', '21126');
INSERT INTO safety_incidents VALUES ('8275ed1168629f09a62b391810a15ddec9d21d42', 'CPSC', '2021-05-05', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Infant Sleep Bags', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled infant sleep bags and contact TJX for instructions on how to participate in the recall and receive their choice of either a full refund or a store gift card.', '21123');
INSERT INTO safety_incidents VALUES ('8ca817840cf17e272392340438c6ce3a9ea4ee1e', 'CPSC', '2021-05-05', 2021, '2021-05', 'USA', 'United States', '', 'Other', 'Outdoor wooden folding chairs', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'TJX has received 18 reports of the recalled chairs breaking or collapsing, including 15 reports of falls that resulted in minor injuries, including back and neck injuries and lacerations.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and contact TJX for instructions on how to participate in the recall and receive a full refund. Alternatively, consumers can return the recalled chairs to any T.J. Maxx, Marshalls, or HomeGoods store for a full refund.', '21127');
INSERT INTO safety_incidents VALUES ('85f96195decee71970ec8623bb625b6d44af23ee', 'CPSC', '2021-04-29', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Modernist Pantry Kitchen Alchemy Sodium Hydroxide', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of sight and reach of children. Contact Modernist Pantry for a free replacement child resistant packaging and label. All known purchasers are being contacted directly.', '21740');
INSERT INTO safety_incidents VALUES ('aae6aa28890966a86074a7d346803e2718bd192c', 'CPSC', '2021-04-29', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'CRF450R Off-Road Motorcycles', 'Injury', 'Other', 'Skin Irritation', 'The firm has received two reports of the off-road motorcycle''s drive chain breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled off-road motorcycles and contact an authorized Honda Powersports dealer to schedule an appointment for a free repair. Honda is contacting all known purchasers directly.', '21741');
INSERT INTO safety_incidents VALUES ('551c58985745a3cd4068313b773c7f4d7e92bd55', 'CPSC', '2021-04-28', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'StaRite and Mastertemp pool heaters', 'Fire', 'Flammability / Overheating', 'Not Specified', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled heaters and contact Pentair Water Pool and Spa for a free repair.', '21119');
INSERT INTO safety_incidents VALUES ('82d406b7d12dad3fd4ade9a6363f11d556babce4', 'CPSC', '2021-04-28', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Sauder and Aliesha-May Counter-height bar stools (two-piece sets)', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The company has received three reports of the stool being unstable, including two falls. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bar stools and contact Sauder Woodworking to receive a full refund for each two-piece stool set. Sauder Woodworking is contacting all known purchasers directly.', '21117');
INSERT INTO safety_incidents VALUES ('74a3f4ae497f25c6bc996cc07a2b980b6f0201b1', 'CPSC', '2021-04-28', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'LifeSeasons Blood Nourish-R Iron Supplement', 'The Product Is A Dietary Supplement Containing Iron, Which Must Be In Child Resistant Packaging, As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Poisoning Risk If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Contact LifeSeasons for instructions on how to return the product for a full refund, or a refund in the form of a merchandise credit for the amount equal to the purchase price.', '21118');
INSERT INTO safety_incidents VALUES ('1d9fa580c21fdc0191e8f8a3fc575a043c09d435', 'CPSC', '2021-04-22', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'BRUTE FORCE® 750 All-Terrain Vehicles (ATVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Kawasaki dealer to schedule a free repair to replace the fuel pump retainer plate bolts. Kawasaki is contacting all known purchasers directly.', '21738');
INSERT INTO safety_incidents VALUES ('7a71aa56528cc934de81e96647d67d4d7cb8120d', 'CPSC', '2021-04-22', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'TERYX® off-highway vehicles (ROVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Kawasaki dealer to schedule a free repair to replace the fuel pump retainer plate bolts. Kawasaki is contacting all known purchasers directly.', '21739');
INSERT INTO safety_incidents VALUES ('a3dbe5689463ca7a72068ff14235044588e6bca0', 'CPSC', '2021-04-22', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Welmate Lidocaine Numbing Cream', 'The Packaging Is Not Child Resistant As Required By The Poison Prevention Packaging Act. The Pain Relieving Cream Contains Lidocaine, Posing A Risk Of Poisoning To Young Children If They Put It On Their Skin Or Ingest It.', 'Other', 'Poisoning / Ingestion', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cream, store it in a safe location out of reach of children and contact YYBA for instructions on how to dispose of the product to receive a full refund. YYBA is directly notifying all known consumers who purchased the recalled product on eBay, Walmart and wellspringmeds.com. Amazon is directly notifying all customers who purchased the recalled product on Amazon.com.', '21737');
INSERT INTO safety_incidents VALUES ('f60080c8355c478775d5ac0e90bf39978c5297a2', 'CPSC', '2021-04-21', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Swix branded Focus Down Jackets Jr.', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled jacket away from children and remove the drawstrings to eliminate the hazard, or return the jacket to BRAV USA for a full refund, shipping included.', '21114');
INSERT INTO safety_incidents VALUES ('30bc4917b13b7f262fd6906ae5c49023ee36fe29', 'CPSC', '2021-04-21', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Brompton Electric Folding Bicycles', 'Injury', 'Mechanical Failure', 'Fall Injury', 'The firm has received one report of a software issue that caused a bicycle to provide continued assistance when the rider had stopped pedalling. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled bicycles immediately and contact the nearest authorized Brompton Electric dealer for a free software upgrade to Version 1-2-10-2.', '21116');
INSERT INTO safety_incidents VALUES ('662ddd0bfe4efbb9385244e61cd2249c2fb45d8b', 'CPSC', '2021-04-21', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Coffee Bean Roasters', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received reports of 20 incidents of the coffee bean roasters overheating causing the plastic to melt, coffee beans to burn, and/or flames and smoke to emanate from the roaster. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled coffee bean roasters and contact Metal Ware for a full refund or a refund in the form of a store credit. Metal Ware will provide consumers with free return shipping for the roasters. Upon Metal Ware''s receipt of the returned roaster, the consumer can choose between receiving a full refund of $85 or a refund in the form of a store credit in the amount of $100 for use at www.nesco.com.', '21115');
INSERT INTO safety_incidents VALUES ('7fec825cd7e63c44312a78c8347a17682aec1fc4', 'CPSC', '2021-04-14', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Charging Cases Sold with Audio-Technica Wireless Headphones, Model ATH-CK3TW', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received four reports of incidents of the charging cases overheating, all outside of the United States. These incidents resulted in damage to the charging cases and to the surfaces on which charging occurred. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the charging cases and contact Audio-Technica for instructions on returning the charging cases for a free replacement charging case. Audio-Technica will provide consumers with a prepaid return shipping label and will send consumers a replacement charging case upon receipt of the returned case.', '21110');
INSERT INTO safety_incidents VALUES ('bd76ec26ed1b26255422f32da297ba7fd1bd1f7f', 'CPSC', '2021-04-14', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'B. toys Firefly Frank Infant Teethers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Battat has received 14 reports of the wings detaching or pieces of the wing breaking off, including one report of a child choking on a broken piece of the wing.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled teethers away from young children and return them to any Target store for a full refund, or contact Battat to return by mail for a full refund.', '21109');
INSERT INTO safety_incidents VALUES ('293c1b69d31ae45463203a39c65bd6281b38587e', 'CPSC', '2021-04-14', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Clip Clop Infant Activity Rattles', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled rattles away from children, stop using them and contact Playgro for a free replacement, including shipping.', '21112');
INSERT INTO safety_incidents VALUES ('94fa3cd1895ad5870a61c9dfc1577d00fb2257ed', 'CPSC', '2021-04-14', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Cat & Jack Baby Heart Ears Rompers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received 40 reports of the hearts peeling or detaching, including one report of a child choking', 'Moderate', 1, 0, 'Consumers should immediately take the recalled rompers away from children and return them to any Target Store for a full refund. Consumers who purchased the romper on Target.com can contact Target to receive a prepaid return label to return the romper.', '21111');
INSERT INTO safety_incidents VALUES ('0be0fad4608ef7d28bb15665e6a56de8bc91639b', 'CPSC', '2021-04-12', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'PIEPS DSP Pro, DSP Pro Ice, and DSP Sport Avalanche Transceivers', 'The Transceiver Can Switch Modes Unexpectedly When Not Locked Or Installed In The Harness. When This Occurs, It Will Prevent The Transceiver From Transmitting A Signal And Can Make It Difficult To Locate A Skier In An Avalanche, Which Can Result In Severe Bodily Harm Or Death.', 'Other', 'Fracture / Blunt Trauma', 'Black Diamond has received 65 reports of the transceiver modes switching unexpectedly while in use. One death and one instance of a skier getting caught in an avalanche who suffered a broken arm and minor injuries were both reported in British Columbia.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled avalanche transceivers and contact Black Diamond for a free replacement hardcase carrying system and user guide to be used with the recalled transceivers.', '21108');
INSERT INTO safety_incidents VALUES ('4440ccf411a048b69b7f781e386d31adc227daf5', 'CPSC', '2021-04-08', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'GEO Wintergreen Organic Essential Oil and GEO Alleviate Organic Essential Oil Blend', 'These Products Contain The Substance Methyl Salicylate, Which Must Be In Child Resistant Packaging, As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled essential oils and dispose of the products. Geo Essential is automatically refunding consumers the full purchase price through the distribution channel through which the products were purchased. GEO is contacting all known purchasers directly.', '21736');
INSERT INTO safety_incidents VALUES ('3901134b94a3d72f67b3955aecf6f85db768427a', 'CPSC', '2021-04-08', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Ellipsis Jetpack mobile hotspots', 'Fire', 'Flammability / Overheating', 'Burns', 'Verizon has received 15 reports of devices overheating, including six reports of fire damage to bedding or flooring and two reports of minor burn injuries.', 'Minor', 1, 0, 'Consumers can reduce the risk of hazard by powering the unit off, unplugging it from its power source and store in a place away from children, on top a hard surface with adequate ventilation around the unit and away from combustibles until it can be properly returned to Verizon. If consumers must use the product for internet access, then they should take the following steps: Turn the recalled hotspot "on" and plug it in to allow the hotspot to receive two over-the-air automatic software updates that: (a) enable the device''s identifying number to be viewed on its scrolling screen and (b) prevent the device from charging while the device is plugged in and powered on. After the software update is applied, users should: (a) Leave the device powered on while it is plugged in. (b) When not in use, the device should be turned off, unplugged from its power source, and securely stored. Consumers should use the contact information below to receive a replacement hotspot free of charge and a return envelope to return the Ellipsis to Verizon for safe disposal. Schools that provided the recalled Ellipsis Jetpack to students have been contacted by Verizon with instructions on receiving replacement hotspots free of charge and mailing packages to return the recalled Ellipsis Jetpacks to Verizon for safe disposal. Parents whose children received the recalled Ellipsis Jetpack from their schools should contact their school for instructions on how to receive a free replacement device and return their recalled Ellipsis Jetpacks.', '21106');
INSERT INTO safety_incidents VALUES ('04808852b5f44528cefa341ccc4446c23dc7875a', 'CPSC', '2021-04-07', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Epicure Prep Bowls (Set of Four)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received six reports of the prep bowls breaking or shattering in the United States and 35 reports in Canada, including one report of a minor cut on the finger.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled prep bowls and contact Epicure for a free replacement product.', '21103');
INSERT INTO safety_incidents VALUES ('9bf72b3f3799c1a2156cb339a57854b8a51c4f27', 'CPSC', '2021-04-07', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'EC8 Power Cables', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Goal Zero has received four reports of the cable connected to the vehicle battery overheating, melting, or catching on fire, some of which resulted in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cables and contact Goal Zero for a free replacement.', '21104');
INSERT INTO safety_incidents VALUES ('bf58b5ae44cce9d63968ef062d46a82dacf101a6', 'CPSC', '2021-04-07', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Greenworks and Powerworks pressure washer spray guns', 'Injury', 'Explosion', 'Fracture / Blunt Trauma', 'Hongkong Sun Rise has received 15 reports of the pressure washer spray gun connector breaking, allowing the hose and/or parts of the connector to become dislodged when under pressure during use. This resulted in 13 reports of injuries, including 7 of which required medical treatment for post-concussion, broken bones and/or injuries to the eyes and mouth.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled spray guns and contact Hongkong Sun Rise Trading for a free replacement of the spray gun handle.', '21105');
INSERT INTO safety_incidents VALUES ('7d96707d340c65305f99b57103a448d6dce1705a', 'CPSC', '2021-04-07', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Animal, Heathered Plush and Luxe Sherpa Children''s Bath Wraps', 'Fire', 'Flammability / Overheating', 'Burns', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled bath wraps and contact RH for a full refund of the purchase price, or credit of $35 for the Animal Bath Wrap, $32 for the Heathered Bath Wrap or $39 for the Sherpa Bath Wrap, if the consumer''s purchase price cannot be determined. RH is contacting all known purchasers directly.', '21102');
INSERT INTO safety_incidents VALUES ('f754a8220a1a0e7e0c3d9fa4562e497689491564', 'CPSC', '2021-04-01', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'doTERRA Deep Blue, PastTense and Deep Blue Touch Essential Oils', 'The Products Contain The Substance Methyl Salicylate, Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Applied To The Skin Or Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately store the products in a safe location out of reach of children and contact doTERRA for a free replacement product of similar value. doTERRA is contacting all known purchasers directly.', '21734');
INSERT INTO safety_incidents VALUES ('06b0a9235e33394d8df454ffe2598d5ca89ca48c', 'CPSC', '2021-04-01', 2021, '2021-04', 'USA', 'United States', '', 'Other', 'Foldable Infant Bath Seats', 'Drowning', 'Instability / Fall Risk', 'Drowning', 'No incidents or injuries reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled infant bath seats and contact BATTOP for instructions on returning the bath seats with free shipping to receive a full refund. Amazon, on behalf of BATTOP, is contacting all known purchasers directly.', '21735');
INSERT INTO safety_incidents VALUES ('e0fa5f3737a109729b623165d585bf0b43e5146b', 'CPSC', '2021-03-25', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'PureLine 1.5 HP Pool Pump Motors', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 26 reports of motors burning, smoking, or melting. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pool pump motors and contact Inyo Pool Products for a free replacement. After replacement, consumers should cut one of the wires connecting to the capacitor and dispose of the recalled pump motors in accordance with local requirements. Consumers are asked to send a photo of the cut wires to Inyo Pool Products at recall@inyopools.com. Inyo Pool Products is contacting all known purchasers directly.', '21731');
INSERT INTO safety_incidents VALUES ('2324c462709e2fcb8d30be3ef7651d2489f59e40', 'CPSC', '2021-03-25', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'KTM, Husqvarna and GASGAS closed course competition motorcycles', 'The Drive Chain Can Break, Posing A Crash Hazard And/Or Property Damage.', 'Other', 'Skin Irritation', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop riding the recalled closed course competition motorcycles and contact an authorized KTM, Husqvarna or GASGAS Motorcycles dealer to schedule a free repair, which involves replacing the drive chain. KTM, Husqvarna and GASGAS Motorcycles are contacting all purchasers directly.', '21733');
INSERT INTO safety_incidents VALUES ('65b15fb25637c3326b6ec1521bcaf5c3880ef51e', 'CPSC', '2021-03-25', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Model Year 2020-2021 RANGER 1000 and RANGER CREW 1000, Model Year 2020 ProXD 2000G and 4000G, Model Year 2020-2021 Ariens/Gravely JSV3200, JSV3400, and JSV6400, Model Year 2020 Bobcat UV34 4x4 GAS and UV34 XL GAS, and Model Year 2021 Bobcat UV34 4x4 GAS', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received three reports of drive belt failure resulting in a damaged fuel line, including two reports of fire, neither of which involved property damage other than to the vehicle. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris, Ariens, or Bobcat dealer to schedule a free inspection and repair, if needed. Polaris, Ariens, and Bobcat are notifying all dealers and contacting registered owners directly.', '21732');
INSERT INTO safety_incidents VALUES ('6bc1af9c1120e33483e6565b8aff6472baa61842', 'CPSC', '2021-03-24', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Beal Birdie Belay Devices', 'Injury', 'Mechanical Failure', 'Not Specified', 'The firm has received three reports of the user being unable to lower the climber because the hand lever became detached from the device. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Beal Birdie Belay Devices and contact Liberty Mountain for a free replacement.', '21101');
INSERT INTO safety_incidents VALUES ('02f91d5435248100beccc5c37cac4be9b5650d26', 'CPSC', '2021-03-24', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Hog 100-pound Propane Cylinders', 'Fire', 'Flammability / Overheating', 'Not Specified', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled propane cylinders and contact Flame King for a full refund or free replacement.', '21100');
INSERT INTO safety_incidents VALUES ('e23fc5349a46d7642066a5e2f210a81e28b4af5e', 'CPSC', '2021-03-18', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'YTL Log Splitters with Briggs & Stratton 250cc engines', 'Injury', 'Flammability / Overheating', 'Fracture / Blunt Trauma', 'The company is aware of two incidents, which resulted in broken wrists.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled log splitters and contact an authorized Briggs & Stratton dealer for a free inspection and repair. Briggs & Stratton is contacting all purchasers directly.', '21730');
INSERT INTO safety_incidents VALUES ('458a325e9e67d8326aceffee40ff31b667d130b7', 'CPSC', '2021-03-18', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Evrysdi™ (risdiplam)', 'The Bottles Containing The Prescription Drug Can Leak Due To A Fit Issue Between The Press-In Bottle Adapter And Bottleneck. If The Bottle Is Leaking, There Is A Risk Of Drug Exposure By Contact With Skin Or Eyes. Prescription Drugs Must Be In Child Resistant Packaging That Prevents Children From Gaining Access To The Contents As Required By The Poison Prevention Packaging Act (Pppa).', 'Other', 'Poisoning / Ingestion', 'Genentech has received 26 reports of leaking bottles. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately store Evrysdi in a safe location out of reach and sight of children. Consumers should inspect the bottle for any leaking. If it is leaking, contact Genentech for a free replacement. Consumers can continue to use as directed, as the leakage is not anticipated to impact the safety or efficacy of administered medicine. If Evrysdi gets on your skin, wash the area with soap and water. If Evrysdi gets in your eyes, rinse your eyes with water. Genentech is contacting all known purchasers directly.', '21729');
INSERT INTO safety_incidents VALUES ('c354be90ae3ee38098e2a57aa6e7d9ef13b75f4c', 'CPSC', '2021-03-18', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'illu-Mist Battery-Powered Garden Sprayers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received four reports of batteries overheating, including one report of a battery melting and catching fire resulting in less than $100 in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled battery-powered sprayers, remove the battery tray, and look for a brown battery. If the battery is brown, consumers should remove the battery and tray and dispose of them in accordance with local laws for disposal of lithium-ion batteries, and contact HD Hudson for a free replacement battery and tray. Always follow proper battery use and storage procedures as listed in the instructions.', '21098');
INSERT INTO safety_incidents VALUES ('5190ea5fa6a3de5a2a7ae5375f9129656a4ece12', 'CPSC', '2021-03-18', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Shepherd Boy Plush toys with wire staff', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 12 reports of the shepherd''s staff fabric unwrapping and exposing the metal wire with one report of a sharp edge. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately discard the toy''s wire staff and contact The Shepherd''s Treasure for a full refund of the value of the Shepherd Boy Plush Toy in the form of a gift certificate. Consumers can continue to use the plush toy without the shepherd''s staff. The Shepherd''s Treasure is contacting all purchasers directly.', '21728');
INSERT INTO safety_incidents VALUES ('de8c69344e4cc843970d67e0be53d0c4d91a2ca5', 'CPSC', '2021-03-17', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'HR Platform Frames', 'Injury', 'Mechanical Failure', 'Entrapment', 'The firm has received 100 reports of the HR platform frame collapsing. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled HR Platform Frames and contact Global Home Imports to receive a free repair kit with metal clips to strengthen the frame. Global Home Imports will ship a kit directly to consumers free of charge.', '21096');
INSERT INTO safety_incidents VALUES ('b0af0e48a5f345359210ad70558194a916b5852d', 'CPSC', '2021-03-17', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'HOFISH 10-Inch Hybrid Certi-PUR Certified Foam and Pocket Spring Mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mattresses and contact HOFISH to receive a free fitted cover to put on the mattress to bring it into compliance with the federal standard.', '21097');
INSERT INTO safety_incidents VALUES ('8ae4489e1591893fe3b19d9f39cfe17af5c2db0a', 'CPSC', '2021-03-11', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'KTM SX-E 5 and Husqvarna EE-5 Motorcycles', 'Water Can Get Into The Battery Causing A Short Circuit, Posing A Crash Hazard.', 'Electrical Fault', 'Skin Irritation', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop riding the recalled motorcycles and contact an authorized KTM or Husqvarna Motorcycles dealer, respective of their motorcycle brand, to schedule a free repair. KTM and Husqvarna Motorcycles are contacting all known purchasers directly.', '21727');
INSERT INTO safety_incidents VALUES ('343ab4aec56c9bcf8fcc7c4665a7537603bc930a', 'CPSC', '2021-03-11', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Revive Three Wick Soy Candles', 'Fire', 'Flammability / Overheating', 'Burns', 'Melaleuca has received 17 reports of high flames, including 14 reports of the wax catching fire. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles, carefully cut all three wicks as short as possible to prevent the candles from being used and discard the product. Melaleuca has contacted all known purchasers directly about the recall and refund.', '21726');
INSERT INTO safety_incidents VALUES ('dd504167b08c172c9af6c41ccaec3782c461ee01', 'CPSC', '2021-03-10', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Hillsdale Furniture Jennings Counter and Bar Stools', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm received reports of 21 stool seats either that broke off their bases or had loose welding. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Jennings counter and bar stools and contact Hillsdale Furniture for a free repair kit.', '21093');
INSERT INTO safety_incidents VALUES ('503fa8664dc56d133e905eeee6fea30f4735a5e3', 'CPSC', '2021-03-10', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Lifetime Products 6-foot Seminar Tables', 'Injury', 'Mechanical Failure', 'Not Specified', 'Lifetime Products has received one report from a consumer who identified 11 tables with the brace arms not properly locking into place. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled seminar tables and contact Lifetime Products for a free repair bracket.', '21092');
INSERT INTO safety_incidents VALUES ('81b7d21ad4f5083328f554ef99dd1debbd57a91b', 'CPSC', '2021-03-04', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Cabina Bunk Beds', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Casa Kids has received nine reports from consumers that some of the screws that hold their bed''s foundation to the bed''s guardrails were spinning loose. In one incident, the foundation on one lower bed dislodged from one of its two bed rails. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using their recalled Cabina Bunk Beds until they have inspected their beds to determine whether the screws that hold the bed''s foundation to the guardrails are tightly in place. Casa Kids is contacting all purchasers directly with detailed instructions on how to inspect and repair their bunk beds. Casa Kids will immediately send a new set of screws to any consumers who alert Casa Kids that their bed''s guardrails are not tightly in place.', '21725');
INSERT INTO safety_incidents VALUES ('0e0835b18c22befd7a46ced834039ce43648bc75', 'CPSC', '2021-03-04', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Model Year 2020-2021 RANGER 1000, RANGER CREW 1000, RANGER XP 1000, and RANGER CREW XP 1000 and Model Year 2020 ProXD 2000G, ProXD 2000G H, ProXD 4000G, and ProXD 4000G H', 'The Throttle Pedal Can Return To The Idle Position More Slowly Than Anticipated Once The Pedal Is Released Or Stick In The Depressed Position, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'The firm has received 52 reports of throttle pedals returning to the idle position slowly or sticking, including six reports of vehicle crashes resulting in minor property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free repair. Polaris is notifying all dealers and contacting registered owners directly.', '21724');
INSERT INTO safety_incidents VALUES ('f56465ebc6db9054f01987579251a7cddc251ed9', 'CPSC', '2021-03-03', 2021, '2021-03', 'USA', 'United States', '', 'Other', 'Model Year 2017-2020 Masi Evoluzione and Gran Corsa bicycles', 'Falls', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received five reports of the bicycle forks breaking, including three reports of minor injuries including bumps, bruises and scrapes.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact their local Haro Bicycles dealer for a free inspection, and repair or replacement of the fork and compression plug.', '21090');
INSERT INTO safety_incidents VALUES ('72b1623df8ba05481feba0b4ad25cb5c7a7bd99f', 'CPSC', '2021-02-25', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Imatinib Mesylate Tablets 100 mg, Imatinib Mesylate Tablets 400 mg, Pregabalin Capsules 50 mg, Pregabalin Capsules 75 mg, Pregabalin Capsules 100 mg, Pregabalin Capsules 150 mg, Sevelamer Carbonate Tablets 800 mg, Tadalafil Tablets 5 mg and Tadalafil Tablets 20 mg', 'The Products Are Prescription Medications That Were Labeled And Distributed By Dr. Reddy''S For Institutional Use Only. The Prescription Medications Were Distributed By Third Party Wholesalers To Retail Pharmacies And Could Have Been Dispensed To Consumers. The Packaging Of The Products Is Not Child Resistant And Can Pose A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately store the recalled medications in a safe location out of reach of children and contact Dr. Reddy''s for a full refund.', '21089');
INSERT INTO safety_incidents VALUES ('8a85365a5d136f007d9c4718ae4877c097fdd730', 'CPSC', '2021-02-25', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'StyleWell Wood Windsor Dining Chair Sets', 'Falls', 'Mechanical Failure', 'Fall Injury', 'Home Depot has received 17 reports of the chair''s back detaching from the chair base. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and inspect the chairs for missing screw holes and wood screws on the underside of the chair seat base. Home Depot is contacting all purchasers directly to provide inspection instructions.', '21722');
INSERT INTO safety_incidents VALUES ('c0c1aab0fcf845d1c55fb8bee57bdb29b7f31736', 'CPSC', '2021-02-25', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'deSensua Wintergreen, Birch and Pain Soother Essential Oils', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact MTIG Productions for a full refund. All known purchasers are being contacted directly.', '21723');
INSERT INTO safety_incidents VALUES ('34ab7aad88cd1228d94eb23f3065ca822bf8a3c3', 'CPSC', '2021-02-24', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Northern Tool & Equipment Powerhorse 13000ES Portable Generators', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'NTE has received one report of an incorrect wiring connection. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled generators and contact Northern Tool & Equipment to schedule a free repair by an authorized dealer.', '21086');
INSERT INTO safety_incidents VALUES ('d7c79b0a02b0739fc0f11b59076b38a42bb49bc4', 'CPSC', '2021-02-24', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Potter Electric Addressable Pull Stations Single/Dual Action', 'Fire', 'Flammability / Overheating', 'Not Specified', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately contact Potter Electric or their fire alarm system dealers/installers for a free replacement. All known Potter Electric distributors and dealers/installers have been notified directly by the firm.', '21085');
INSERT INTO safety_incidents VALUES ('ae1e28beee61b82aa1cb0d841ca02917bf0df273', 'CPSC', '2021-02-24', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Bee Free Children''s Helmets', 'Injury', 'Other', 'Not Specified', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers with children between the ages of 2 and 4 should immediately stop using the recalled helmets and contact SmartPool for a full refund.', '21088');
INSERT INTO safety_incidents VALUES ('b67d7bb8e20c967bef39457b740548c903c1121c', 'CPSC', '2021-02-24', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Margo Taper Candle Holders', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of the candle holder catching fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candle holders and return them to any Urban Outfitters store for a full refund. Customers can also contact Urban Outfitters to receive a prepaid return label to return the candle holders by mail. Urban Outfitters is contacting online purchasers by email.', '21087');
INSERT INTO safety_incidents VALUES ('f1fad65fabf1a1315969f8b7033e42ceece5c359', 'CPSC', '2021-02-17', 2021, '2021-02', 'USA', 'United States', '', 'Other', '10-in-1 Incredible Inventions Science Kits', 'Low Risk', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled science kit, take the included red and blue magnet away from children, and contact Anker Play Products to receive a full refund.', '21083');
INSERT INTO safety_incidents VALUES ('bf367d5f6ba92b0b70f127c4ef04dd82853b7942', 'CPSC', '2021-02-17', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'J Hunt Home and J Hunt and Co. Accent Tables with Charging Receptacles', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'No incidents or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the charging receptacles and ports and contact Jimco Lamp for a full refund or free replacement accent table.', '21081');
INSERT INTO safety_incidents VALUES ('298100031e975aa2007b0c66f30fc56583a42b62', 'CPSC', '2021-02-17', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Presto Indoor Electric Smoker', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'The firm has received reports of five smokers tripping circuit breakers and outlets. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Presto Indoor Electric Smokers and contact the firm to receive return instructions, or return the product to the store where it was purchased for a refund.', '21079');
INSERT INTO safety_incidents VALUES ('e38b26fb79abac72b0003b97dde02b3311bf765f', 'CPSC', '2021-02-17', 2021, '2021-02', 'USA', 'United States', '', 'Other', '5-Pack Nose Piercings and Body Bars', 'The Nose Piercings And Body Bars Have Elevated Levels Of Nickel, Posing A Risk Of Skin Irritation.', 'Other', 'Skin Irritation', 'No incidents or injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled piercing products and return them to a Primark store for a full refund.', '21082');
INSERT INTO safety_incidents VALUES ('c8c5eb7ce685e89722e031bc33306db3ce0795dc', 'CPSC', '2021-02-17', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Toro Power Max Snowthrowers', 'The Auger Can Fail To Disengage When The Control Lever Is Released, Posing An Amputation Hazard.', 'Other', 'Not Specified', 'The firm has received five reports of incidents related to auger failing to disengage when the control lever is released. No injuries have been reported.', 'Serious', 1, 0, 'Consumers should immediately stop using the recalled Toro Power Max Snowthrower and contact a Toro authorized dealer for a free repair.', '21080');
INSERT INTO safety_incidents VALUES ('ff242a09e5498ccfa384eda2e4fe8c46c4244f0b', 'CPSC', '2021-02-12', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'NZXT H1 computer cases', 'Fire', 'Flammability / Overheating', 'Not Specified', 'NZXT has received 11 reports of circuit boards overheating or catching fire worldwide, six of which occurred in the U.S. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled computer cases and contact NZXT for a free repair kit.', '21078');
INSERT INTO safety_incidents VALUES ('9f9d2a529b17859d3e871e2da1670167d4187904', 'CPSC', '2021-02-11', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Strap Safety Brackets', 'Injury', 'Mechanical Failure', 'Not Specified', 'The firm has received three reports of improperly welded strap safety brackets breaking when a large amount of weight was suddenly dropped on the Strap Safeties. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled brackets and contact Rep Fitness for free replacement brackets. Rep Fitness is directly contacting all known purchasers of the recalled brackets.', '21721');
INSERT INTO safety_incidents VALUES ('4530a3cc97db36e641d75a80ef43914f8063236f', 'CPSC', '2021-02-11', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Model Year 2021 Wolverine RMAX4 1000 Recreational Off-Highway Vehicles (ROVs)', 'Injury', 'Other', 'Electric Shock', 'Yamaha has received one report of the rear shock absorber breaking loose. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ROVs and contact an authorized Yamaha dealer to schedule a free repair. Yamaha is contacting all registered owners directly.', '21720');
INSERT INTO safety_incidents VALUES ('38d5558c668eb5e2e3378ef7ee1ce874056132ba', 'CPSC', '2021-02-10', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Muscle Rack Heavy Duty Steel Shelving Units', 'Injury', 'Other', 'Fracture / Blunt Trauma', 'Edsal has received seven reports of shelves bending or breaking due to heavy items placed on shelves, including one injury to a consumer who suffered a broken toe after items fell when the shelving unit broke.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled shelving units and contact Edsal Manufacturing to receive a full refund.', '21076');
INSERT INTO safety_incidents VALUES ('a169b37583cf4435da1e6f49fbdb8a9be39e5ed4', 'CPSC', '2021-02-10', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Bowflex SelectTech™ 2080 Barbells with Curl Bar', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'Nautilus has received one report of a weight plate falling off the end of a barbell, causing property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled barbells and contact Nautilus to receive a free kit with replacement straight and curl bars. Nautilus will ship a kit to customers who purchased the barbells directly from Nautilus.', '21075');
INSERT INTO safety_incidents VALUES ('01053c21209d9d01815f0e72935133e1fa139c4b', 'CPSC', '2021-02-03', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'DeWALT® cordless kerosene forced-air heaters', 'Fire', 'Flammability / Overheating', 'Poisoning / Ingestion', 'Enerco has received one report of a heater starting unexpectedly when it was moved while in standby without being turned off. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled heaters and contact Enerco for a free replacement corded heater.', '21074');
INSERT INTO safety_incidents VALUES ('d0a8ab62c5b58d82b5281275b1292560230f31b1', 'CPSC', '2021-02-03', 2021, '2021-02', 'USA', 'United States', '', 'Other', 'Victory Innovations and Protexus Electrostatic Sprayers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Victory Innovations has received 37 reports of the lithium-ion battery pack in the electrostatic sprayers overheating, catching on fire or exploding, some of which resulted in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled sprayers, remove the battery pack and dispose it in accordance with local laws for disposal of lithium-ion batteries, and contact Victory Innovations for a free replacement battery pack, including shipping.', '21073');
INSERT INTO safety_incidents VALUES ('41f4cc3ede6a85cbb1ead7e8f0f821dbf43318fe', 'CPSC', '2021-01-27', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Junction Tall Chests and Low Dressers', 'The Recalled Chests And Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Death Or Injuries To Children.', 'Entrapment', 'Entrapment', 'CB2 has received 10 reports of incidents, including five reports of the Tall Chest and five reports of the Low Dresser tipping forward when the tip-over kit was not in use. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled chests and/or dressers if they are not properly anchored to a wall and place them in an area that children cannot access. Contact CB2 for instructions on how to receive full store credit or a full refund.', '21071');
INSERT INTO safety_incidents VALUES ('eadb5d896efc663705f88ee287a6f2a3b30422dc', 'CPSC', '2021-01-19', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Rapala® Rechargeable Fillet Knives (Item No. RRFN)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Rapala USA has received reports of 12 batteries overheating and catching fire, in some cases causing damage to surrounding areas. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled rechargeable fillet knife, remove the battery and look for a white ETL label on the battery. If the battery does not have a white ETL label, consumers should contact Rapala USA for a free replacement battery and for pre-paid return of the old battery to Rapala for proper disposal.', '21070');
INSERT INTO safety_incidents VALUES ('213c86a0caca57d46c7cedf1eb8ec778c6103371', 'CPSC', '2021-01-14', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Scalpa Numb Maximum Strength Topical Anesthetic Cream', 'The Product Contains The Substance Lidocaine Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning To Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Scalpa Numb, store the cream in a safe location out of reach of children and contact Scalpa for a full refund or store credit. Scalpa is directly notifying all known purchasers about the recall.', '21719');
INSERT INTO safety_incidents VALUES ('188cabfadcbffc7aadaacbf4810d372c43ee8cff', 'CPSC', '2021-01-13', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Belkin "Portable Wireless Charger + Stand Special Edition"', 'Fire', 'Mechanical Failure', 'Electric Shock', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled portable wireless chargers. Contact Belkin for instructions on safe disposal, and for a full refund or credit towards the purchase of another product.', '21066');
INSERT INTO safety_incidents VALUES ('cfa026ba664ba6d1b822ee09060a566febc20e9b', 'CPSC', '2021-01-13', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Janod Toy Confetti Trumpets', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled toy away from children, stop using the Confetti Trumpet or the trumpet in the Confetti Music Live Set, dispose of the trumpet and contact Juratoys US for a refund.', '21067');
INSERT INTO safety_incidents VALUES ('c05dad3358081736eaa995e0519a35ee60f5f44e', 'CPSC', '2021-01-13', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Sea to Summit Alpha and Sigma camping pots', 'Burns', 'Mechanical Failure', 'Burns', 'Sea to Summit has received 10 reports of the latch disengaging or becoming damaged due to excessive heat exposure. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Alpha and Sigma pots with a black Nylon latch and contact Sea to Summit for a free latch repair kit.', '21068');
INSERT INTO safety_incidents VALUES ('fe2d4124e75dfb3ccca1af3f89fe4edc6a73066a', 'CPSC', '2021-01-07', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Frontier model rotary tillers', 'Some Pto Drivelines Were Assembled Without A Specified Safety Sign. The Safety Sign Explains The Associated Hazards And That An Operator Or Bystander Can Become Entangled If There Is Contact With The Driveline.', 'Other', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled rotary tillers and contact an authorized John Deere dealer for a free inspection and repair. John Deere is contacting all known purchasers directly.', '21717');
INSERT INTO safety_incidents VALUES ('9bebfcf6d5f7641fe2f2d203028f99536d8559a3', 'CPSC', '2021-01-07', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Chests, cabinets and dressers', 'The Recalled Chests, Cabinets And Dressers Are Unstable And Can Tip Over If Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Death Or Injuries To Children. The Chests Do Not Comply With The Performance Requirements Of The U.S. Voluntary Industry Standard (Astm F2057-19).', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using any recalled chest, cabinet or dresser that is not properly anchored to the wall and keep it away from children. Contact Noble House Home Furnishings for instructions to receive a full refund. The firm is contacting all known purchasers directly.', '21718');
INSERT INTO safety_incidents VALUES ('953ea6ae199310a146630c120928f68d9cc78783', 'CPSC', '2021-01-06', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Ozone 500® Density Bicycles', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact Academy Sports + Outdoors for a free repair or free replacement hardware.', '21063');
INSERT INTO safety_incidents VALUES ('78531e278fdeac71a3ba2715d13b316a572a10d3', 'CPSC', '2021-01-06', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Massage Guns', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Massimo has received three reports of fires with the recalled massage guns that resulted in over $15,000 in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled massage guns and contact Massimo for a full refund.', '21064');
INSERT INTO safety_incidents VALUES ('c9ab1d352a1dc3a4cc0d797e9ad4e4fb0a6c87fa', 'CPSC', '2021-01-06', 2021, '2021-01', 'USA', 'United States', '', 'Other', 'Rust-Oleum Professional Bright Galvanizing Compound Spray', 'Injury', 'Explosion', 'Not Specified', 'The firm has received six reports of the container bottom detaching, including one reported injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled aerosol paint and contact Rust-Oleum for a full refund. Rust-Oleum will give consumers information on how to safely dispose of the product.', '21060');
INSERT INTO safety_incidents VALUES ('005bc617f4c0b8f9acb8eaf4f8435ff8afee45b5', 'CPSC', '2020-12-31', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'SMART Connect Mini Devices', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has one report of a voltage regulator failure resulting in battery cell failure in a device at an Anticimex facility. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled devices and should not unplug their installed devices until they are contacted by Anticimex to schedule a removal appointment and provide further instructions. The replacement and installation of the new device will be free of charge. Anticimex is directly contacting all known purchasers.', '21716');
INSERT INTO safety_incidents VALUES ('2c2935ad280322ab4091d5c9233ffd19c192154e', 'CPSC', '2020-12-30', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Cloud Island infant rompers', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 16 reports of the snaps breaking, detaching, or missing from the rompers including one report of scratches and one report of a child being pinched.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled infant rompers away from children and return them to any Target Store for a full refund. Consumers that purchased the rompers on Target.com can contact Target to receive a prepaid return label to return the rompers.', '21061');
INSERT INTO safety_incidents VALUES ('86d6e44406222854a07be3fed63c6e93b48aaae4', 'CPSC', '2020-12-30', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Cat & Jack Infant-Toddler One-Piece Rashguard Swimsuits', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 27 reports of the snaps breaking or detaching, including one report of a laceration.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled one-piece Rashguard swimsuits away from children and return them to any Target Store for a full refund. Consumers that purchased the one-piece Rashguard swimsuit on Target.com can contact Target to receive a prepaid return label to return the swimsuit.', '21062');
INSERT INTO safety_incidents VALUES ('cfa33285086529a40677ec1511bdececc3662bc1', 'CPSC', '2020-12-23', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Excedrin Migraine Caplets, Excedrin Migraine Geltabs, Excedrin Extra Strength Caplets, Excedrin PM Headache Caplets, and Excedrin Tension Headache Caplets', 'Some Of The Bottles Containing The Over-The-Counter Drug Can Have A Hole In The Bottom. If There Is A Hole, Children Could Access And Swallow The Contents, Posing A Risk Of Poisoning. These Products Contain The Substances Aspirin And Acetaminophen Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa).', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the recalled Excedrin bottles out of sight and reach of children and inspect the bottom of the bottle to determine if there is a hole. If there is a hole in the bottle, contact GSK Consumer Relations for information on how to receive a prepaid shipping label for return to receive a full refund. Bottles without a hole can be retained and used as directed.', '21057');
INSERT INTO safety_incidents VALUES ('48ae5151127fc70f17816d0e34a152eebfe9b9f7', 'CPSC', '2020-12-23', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Hampton Bay 54-inch Mara Indoor/Outdoor Ceiling Fans', 'Injury', 'Mechanical Failure', 'Not Specified', 'The firm has received 47 reports of the blade detaching from the fan, including two reports of the fan blade hitting a consumer and four reports of the blade causing property damage.', 'Moderate', 1, 0, 'Consumers should immediately stop using the ceiling fans and inspect the ceiling fans using the instructions at www.kingoffans.com/MaraRecall.htm or by visiting the QR code listed in the recall press release. If consumers observe blade movement or uneven gaps between the blades and fan body or movement of the clip during inspection, consumers should immediately contact King of Fans for a free replacement ceiling fan.', '21059');
INSERT INTO safety_incidents VALUES ('7cc55088ad2f24974d70fcbbedb3c4b8bf61f5f1', 'CPSC', '2020-12-23', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Swirled Taper and Sofia Taper Candle Holders', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received 11 reports of the candle holders catching fire including 1 report of property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candle holders and return them to any Urban Outfitters store for a full refund. Customers can also contact Urban Outfitters to receive a prepaid return label to return the candle holders by mail. Urban Outfitters is contacting online purchasers by email; in-store purchasers should contact Urban Outfitters.', '21058');
INSERT INTO safety_incidents VALUES ('f9bd97cf4b77bbb7b62f8de3c278afb67d336881', 'CPSC', '2020-12-22', 2020, '2020-12', 'USA', 'United States', '', 'Other', '2021 Can-Am Outlander and Renegade All-Terrain Vehicles (ATVs)', 'A Rear Wheel Can Separate From The Vehicle And Cause A Loss Of Control, Posing A Crash Hazard To Consumers.', 'Instability / Fall Risk', 'Skin Irritation', 'BRP received two reports of the rear wheel coming loose and falling off the all-terrain vehicles. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a BRP Can-Am ATV dealer for a free repair. BRP is contacting all known purchasers directly.', '21715');
INSERT INTO safety_incidents VALUES ('6b26cb2ef122abab15a9260be41d7bc0425456bd', 'CPSC', '2020-12-17', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Otis and CemcoLift Private Residence Elevators', 'Children Can Become Entrapped In The Space Between The Exterior Landing (Hoistway) Door And The Interior Elevator Car Door Or Gate, And Suffer Serious Injuries Or Death When The Elevator Is Called To Another Floor.', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'Otis is aware of at least four incidents involving an Otis or CemcoLift private residence elevator that resulted in a crushed spine and abdomen, fractured hip, broken arm and feet, and bruising to the face and chest.', 'Fatal', 1, 0, 'Consumers should disable or block children''s access to any Otis or CemcoLift private residence elevator and contact Otis to schedule a free inspection and the installation of space guard(s), if necessary.', '21056');
INSERT INTO safety_incidents VALUES ('9f0225a5d51d5e64d23782bca9df46b5ae87a3f5', 'CPSC', '2020-12-16', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Can-Am® Off-Road screw jacks', 'Injury', 'Mechanical Failure', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Customers should immediately stop using the recalled products and contact a BRP Can-Am Off-Road dealer to receive a full refund.', '21054');
INSERT INTO safety_incidents VALUES ('1d739f1d91520a11bdbbd29b3a477b99411988b8', 'CPSC', '2020-12-16', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Camp Chef portable stoves', 'Fire', 'Sharp Edges / Points', 'Not Specified', 'Camp Chef has received 26 reports of gas leaking from regulators. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Camp Chef Stoves and contact Camp Chef to obtain a free gas regulator replacement kit.', '21053');
INSERT INTO safety_incidents VALUES ('21eb939156d72298680719b58965026b9d057c9e', 'CPSC', '2020-12-16', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Cannondale Canvas NEO Bicycles', 'Falls', 'Mechanical Failure', 'Laceration / Cut', 'Cycling Sports Group has received eight reports of the fender detaching and contacting the bicycle wheel, two of which resulted in injuries involving bruising and abrasions.', 'Moderate', 1, 0, 'Consumers should immediately stop riding the bicycle until the front fender is removed, and contact their local authorized Cannondale dealer or Cycling Sports Group to arrange for a free repair.', '21051');
INSERT INTO safety_incidents VALUES ('4f06296f9d2b6a5d5e6bfea4aecd6afd209bf3cf', 'CPSC', '2020-12-16', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Inclined sleeper accessory included with the Graco Pack ''n Play Day2Dream Playard with Bedside Sleeper, Graco Pack ''n Play Nuzzle Nest Playard, Graco Pack ''n Play Everest Playard and Graco Pack ''n Play Rock ''n Grow Playard', 'Infant Fatalities Have Been Reported With Other Manufacturers'' Inclined Sleep Products, After Infants Rolled From Their Back To Their Stomach Or Side While Unrestrained, Or Under Other Circumstances.', 'Other', 'Not Specified', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled inclined sleeper accessory and contact Graco for a refund for the accessory. Consumers can continue to use the playard portion of the product and other accessories included with the playard.', '21052');
INSERT INTO safety_incidents VALUES ('d5528c31e08c06325931171a6b2f3f08bdb64998', 'CPSC', '2020-12-16', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'LG Chem "RESU 10H" Lithium-Ion Residential Energy Storage System', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received five reports of fires resulting in minor property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers with recalled batteries should immediately contact LG Energy Solution Michigan to schedule a free replacement. LG Energy Solution Michigan, its distributors and its installers also are attempting to contact all owners directly to arrange for modifications to the recalled batteries to reduce the risk of overheating until they can be replaced with new batteries.', '21055');
INSERT INTO safety_incidents VALUES ('b9d9bc6356f14081ef957656d6045b599432cfeb', 'CPSC', '2020-12-10', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Homfa HPB-087 and HPB-106 Cabinets', 'The Recalled Cabinets Are Unstable If Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That Can Result In Death Or Serious Injuries To Children. The Cabinets Do Not Comply With The Performance Requirements Of The U.S. Voluntary Industry Standard (Astm F2057-19).', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using any recalled cabinet that is not properly anchored to the wall and keep it away from children. Homfa will provide pre-paid shipping labels, so that consumers can remove the cabinet''s drawer slides and return them to the firm for a full refund. Consumers should then discard the rest of the dresser. The firm is contacting all known purchasers directly.', '21714');
INSERT INTO safety_incidents VALUES ('576ad2e2c9602356629033003dfb8ff69f04e34b', 'CPSC', '2020-12-10', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Scentsy Luminary Jack Warmer and Scentsy Bless This Home Warmer', 'Fire', 'Electrical Fault', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled warmers and contact Scentsy for a full refund. Scentsy will issue refunds for all Luminary Jack Warmers and affected Bless This Home Warmers after consumers email Scentsy a photo of the warmer with the wires cut, rendering the warmers unusable. Consumers with a Bless This Home Warmer should contact Scentsy for further instructions to determine if their Bless This Home Warmers are affected. Scentsy is contacting purchasers directly.', '21712');
INSERT INTO safety_incidents VALUES ('ab76ab08bb86852e1f4d6d4be1e57358e3500bd0', 'CPSC', '2020-12-10', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Crua Tri, Crua Loj, and Crua Cottage tents in the Mór Series', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the tents below near any flame or other source of ignition. The firm will send the purchasers a new free label stating that the tent is not fire retardant (FR). Once consumers receive the new label, they should remove the incorrect original label, replace it with the new label, and keep the tents away from any flame or other source of ignition. Thermo Tents is contacting all known purchasers.', '21713');
INSERT INTO safety_incidents VALUES ('c7e8e5065fbf30b434260427a2874d3c51a631b6', 'CPSC', '2020-12-09', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'CRAFTSMAN® CMECSP610 10-inch corded chain saws with extension poles', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'CRAFTSMAN has received one report of the recalled chain saw starting without operation of the switch causing a laceration injury to a consumer.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled chain saws and contact CRAFTSMAN for a free repair kit.', '21047');
INSERT INTO safety_incidents VALUES ('bd1a2add4179e628bb0835bc5381ba00cdfd9c65', 'CPSC', '2020-12-09', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Dash® X FM child bicycle seats', 'The Reclining Plate That Holds The Child Bicycle Seat In Place Can Detach, Making The Child Seat Unstable And Can Cause The Rider Of The Bicycle To Lose Control, Posing A Crash Hazard.', 'Mechanical Failure', 'Skin Irritation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Dash X FM child bicycle seats and contact Burley to receive instructions on how to identify and dispose of the recalled child seat and how to receive a free replacement child seat. Consumers will be provided with a replacement Dash Bicycle Seat (Dash X FM, Dash FM, or Dash RM).', '21045');
INSERT INTO safety_incidents VALUES ('0f2effb0a04d61e8a97a8374df948c92fe68a5cb', 'CPSC', '2020-12-09', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Fiskars 16 foot Extendable Pole Saw/Pruners', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Fiskars received two reports of the poles separating and falling. Two laceration injuries requiring stitches have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled pole saw/pruners and contact Fiskars Brands to receive instructions on how to destroy and dispose of the product in exchange for a full refund.', '21044');
INSERT INTO safety_incidents VALUES ('1b76d2068d0d1d563e6308711a94d83ba7aa7ecf', 'CPSC', '2020-12-09', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Yeti 25A Fast Charge Power Supplies', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Goal Zero has received three reports of the power supplies overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Yeti 25A Fast Charge power supply and contact Goal Zero for a free repair. If the product is in use, unplug it and wait for it to cool down before touching.', '21050');
INSERT INTO safety_incidents VALUES ('c14ea1d0806aefe75cfcf4afe0668a78c6083d52', 'CPSC', '2020-12-09', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Su-VGun and GrillGun propane torch guns', 'Fire', 'Flammability / Overheating', 'Not Specified', 'GrillBlazer has received 260 reports of propane leaking from the recalled torch guns, including three incidents that resulted in fires. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Su-VGun and GrillGun propane torch guns and contact GrillBlazer for instructions, and how to receive a free repair, if required.', '21049');
INSERT INTO safety_incidents VALUES ('c7618706b43a8a64028f1aa9d41e97a129fd420d', 'CPSC', '2020-12-09', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'allen + roth 62-inch Electric Fireplaces', 'Fire', 'Flammability / Overheating', 'Respiratory', 'The firm has received 28 reports of overheating, fire, or smoke. Several of these incidents reportedly caused smoke damage to the surrounding area and in one instance smoke inhalation.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled electric fireplaces and contact L G Sourcing to receive a free repair kit and to schedule a free in-home repair.', '21046');
INSERT INTO safety_incidents VALUES ('d91b8071a75a91b250abbb16cecf5d2befaeeb0a', 'CPSC', '2020-12-09', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Delta UV EA-4H-10 ultra-violet generators installed in swimming pools and swim spas', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 92 reports of incidents involving overheating, melting or burning of the generators and the area around the generators. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately unplug and discontinue use of the generator and contact Neptune Benson for a free inspection and repair or replacement.', '21042');
INSERT INTO safety_incidents VALUES ('4d0c5de5005296920d52f759a97e4c3c49edf5f8', 'CPSC', '2020-12-09', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Children''s flashlights', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received four reports of the flashlight overheating, including one minor burn.', 'Minor', 1, 0, 'Consumers should immediately take the flashlight away from children, stop using it, remove the batteries and dispose of the flashlight; and contact Spirit Halloween for a full refund.', '21043');
INSERT INTO safety_incidents VALUES ('5b31047707e2b6a86012df98ecbae93fdb69a76f', 'CPSC', '2020-12-09', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Western Chief toddler light-up rain boots', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received 115 reports of the boot handles and rivets detaching and 2 reports of children placing the rivets in their mouths. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled boots, take the boots away from children, and return them to any Target Store for a full refund.', '21048');
INSERT INTO safety_incidents VALUES ('663c177112ba54846a38bf2f64bc7dcb5ff3b01c', 'CPSC', '2020-12-03', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Honda Pioneer 700 & 1000 Recreational Off-Highway Vehicles (ROVs) with Electric Power Steering (EPS)', 'Injury', 'Other', 'Skin Irritation', 'The firm has received 8 reports of the ROVs having either play in the steering or losing control of steering. No injuries or accidents have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ROVs and contact an authorized Honda Powersports dealer to schedule an appointment for a free inspection and repair, if necessary. Honda is contacting all known purchasers directly.', '21711');
INSERT INTO safety_incidents VALUES ('e3d604af767212ca1de358052a280c8ca3255fba', 'CPSC', '2020-12-02', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Sure Scents 2-1 Peaceful Stream/Moonlit Waves Candles', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received two reports that flame height reached above the glass, causing the glass to break. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Sure Scents 2-1 Peaceful Stream/Moonlit Waves candles and contact Dollar Tree for a full refund.', '21039');
INSERT INTO safety_incidents VALUES ('24180dcb5bcb1bfb5421e101d03f334716a64338', 'CPSC', '2020-12-02', 2020, '2020-12', 'USA', 'United States', '', 'Other', 'Huffy Torex 24V ride-on toy UTVs', 'Injury', 'Other', 'Not Specified', 'Huffy has received 36 reports of incidents. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled toy UTV and contact Huffy for a free replacement controller.', '21040');
INSERT INTO safety_incidents VALUES ('2fb5b4fbd44a20295f174a3a99696dc091f0bde8', 'CPSC', '2020-11-25', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Baby Spoons and Forks, Feeding Spoons and Placemat Feeding sets 4PCs', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled baby spoons and forks, feeding spoons and placemat sets and contact Herobility to return the products for a full refund or a Herobility gift card with free shipping on a future order. Herobility is notifying all consumers who purchased the recalled products through its website directly.', '21033');
INSERT INTO safety_incidents VALUES ('182b00c0e3ce89863aa4b1fc4e23e83855913587', 'CPSC', '2020-11-25', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Powerfix Steel Shelving Units', 'Falls', 'Entrapment', 'Entrapment', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled shelving units if they do not have mounting hardware attaching them to the wall and contact Lidl for free mounting hardware or return the shelving unit to Lidl for a full refund.', '21038');
INSERT INTO safety_incidents VALUES ('4e653f545ce1a11115082b3bded548abb057a3a0', 'CPSC', '2020-11-25', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Wine Barrel Chandeliers', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'RH has received 14 reports of hanging hardware components breaking, including 11 reports of the chandelier falling. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should prevent people from going into the immediate area underneath the chandelier. Contact RH to schedule a free in-home repair or replacement depending on chandelier hardware type. The firm is notifying all known purchasers directly.', '21034');
INSERT INTO safety_incidents VALUES ('0118d859a4940ceaa68330f773616736e4be75f8', 'CPSC', '2020-11-25', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Model Year 2020 Aluminum Santa Cruz and Juliana Bicycles', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Santa Cruz has received four reports of the recalled aluminum frame bicycle pieces bending or buckling. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles with aluminum frames and contact the firm to arrange for a free inspection. Consumers with affected frames can choose either a free replacement aluminum frame or a refund voucher for the value of the recalled frame.', '21036');
INSERT INTO safety_incidents VALUES ('d3f84748e3a73f828f6786e3922fe5dd1ef1a19f', 'CPSC', '2020-11-25', 2020, '2020-11', 'USA', 'United States', '', 'Other', '3-in-1 Qi wireless chargers, power banks and travel wall chargers', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received four reports of incidents, including two that resulted in fires. One consumer reported that a fire caused $6,000 worth of property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the chargers and contact Towsleys to receive a credit for a free replacement charger and instructions on disposing of the recalled products.', '21037');
INSERT INTO safety_incidents VALUES ('7bd9e06ce5972db636bd2c5938c5c8b97b92ab45', 'CPSC', '2020-11-24', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Bicycle Helmets', 'Injury', 'Other', 'Not Specified', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact Any Volume for a full refund. Any Volume is contacting all known purchasers directly.', '21710');
INSERT INTO safety_incidents VALUES ('53b77a4d8fa89ffd8af0ef9c737cff5861a07683', 'CPSC', '2020-11-24', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Crock-Pot® 6-Quart Express Crock Multi-Cookers', 'Burns', 'Explosion', 'Burns', 'Sunbeam Products has received 119 reports of lid detachment, resulting in 99 burn injuries ranging in severity from first-degree to third-degree burns.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Crock-Pot in pressure cooker mode, but may continue to use for slow cooking and sautéing. Consumers should contact Crock-Pot immediately to obtain a free replacement lid. Consumers who continue using the multi-cooker in pressure cooker mode while waiting for the replacement lid should be certain the lid is securely turned to the fully locked position by aligning the arrow on the lid with the lock symbol on the base.', '21035');
INSERT INTO safety_incidents VALUES ('8e0bdbd34b99701cf66fc6b0d8a2e38d9708b626', 'CPSC', '2020-11-19', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Model Years 2020-2021 RZR PRO XP, PRO XP4 and Model Year 2021 RZR Turbo S, Turbo S4, XP Turbo and XP 4 Turbo ROV', 'Injury', 'Other', 'Not Specified', 'Polaris has received 136 reports of clutch failure, including 8 reports of debris and clutch component ejection that damaged nearby parts of the vehicle. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair. Polaris is notifying all dealers and contacting registered owners directly.', '21709');
INSERT INTO safety_incidents VALUES ('bed4e1ab8d3834ee03c133b6f478f9382751d011', 'CPSC', '2020-11-12', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Electric Throw Heated Blankets', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 26 reports of overheating including one consumer describing a minor burn injury and another an unspecified injury.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled blankets and contact InvoSpa for instructions on how to receive a full refund. All purchasers will be contacted by InvoSpa.', '21708');
INSERT INTO safety_incidents VALUES ('c575d8c5aa0cebb05ee12dbc39f49c625e726162', 'CPSC', '2020-11-12', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Zinus metal bunk beds', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received 13 reports of the bunk bed welds coming apart including three reports of multiple welds simultaneously failing. Of the 13 reports received, three resulted in bumps and bruises after the consumer fell to the floor from the upper bunk when the welds failed.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled upper bunk and contact the firm for instructions on receiving a free repair kit with reinforcement brackets or a full refund. Zinus is contacting all purchasers directly.', '21707');
INSERT INTO safety_incidents VALUES ('7321fbe35d837c405428867f987bbe10782daa3d', 'CPSC', '2020-11-10', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Arena Swim Snorkels Pro II and Swim Snorkels II', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received one report of a small piece of the swim snorkel being inhaled.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled snorkels and contact the firm for a free replacement tube or mouthpiece.', '21026');
INSERT INTO safety_incidents VALUES ('462da7aa9813100db531b3a2ab93a5b6eb8eb493', 'CPSC', '2020-11-10', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Crafty Bubbles Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate, Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Poisoning Risk If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Bolek''s Craft Supplys for a full refund.', '21029');
INSERT INTO safety_incidents VALUES ('ef4104e9191c164932475035fea43b8e2aa02438', 'CPSC', '2020-11-10', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Oakmont LP fire pit tables', 'Fire', 'Flammability / Overheating', 'Burns', 'Sunjoy has received 17 reports of the fire pit tables hose installed incorrectly with 12 of those fire pit tables igniting, resulting in 4 reports of minor property damage. The firm has received one report of a consumer who was burned on their hand.', 'Minor', 1, 0, 'Consumers should immediately stop using the fire pit tables and contact Sunjoy to receive a free replacement burner kit and installation instructions.', '21027');
INSERT INTO safety_incidents VALUES ('f0401e5313e5df68213a7c45736fd0e3491651c3', 'CPSC', '2020-11-10', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'SONOMA Goods For Life branded three-wick candles', 'Fire', 'Flammability / Overheating', 'Burns', 'Kohl''s has received 29 reports involving high flames and/or breaking glass containers with the three-wick candles, including five incidents resulting in minor burn injuries and six incidents involving minor property damage including burn marks on furniture, carpet, and/or countertops.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles and return them to the nearest Kohl''s store. Consumers with a receipt will receive a full refund and consumers without a receipt will receive a store credit.', '21024');
INSERT INTO safety_incidents VALUES ('d20448f354163aac17b0e8d039c90b1302dcb553', 'CPSC', '2020-11-10', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Salsa Cutthroat Bicycles and Forks', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Salsa Cycles has received seven reports of cracked forks. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles, contact Salsa Cycles, and bring the recalled Salsa Cutthroat bicycles, framesets, and aftermarket forks to a Salsa authorized retailer for inspection and free installation of a replacement fork.', '21025');
INSERT INTO safety_incidents VALUES ('7d85837a024d7d5ce6e96471ad2a09e03a23daf9', 'CPSC', '2020-11-10', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Ring Video Doorbells (2nd Generation)', 'Fire', 'Flammability / Overheating', 'Burns', 'Ring has received 85 incident reports of incorrect doorbell screws installed with 23 of those doorbells igniting, resulting in minor property damage. The firm has received eight reports of minor burns.', 'Minor', 1, 0, 'Consumers should immediately stop installing the recalled video doorbells and contact Ring for revised installation instructions or download them here. Consumers can check if their video doorbell is part of this recall through Ring''s website or app.', '21028');
INSERT INTO safety_incidents VALUES ('b2d416a3a525e78d54e601cf8d88bdb8e9f78f1b', 'CPSC', '2020-11-04', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Climbing treestands', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'The firm has received five reports of the treestand''s cable separating, resulting in two injuries involving fractures.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled climbing treestands and contact the firm for instructions on receiving a refund in the form of a gift card.', '21022');
INSERT INTO safety_incidents VALUES ('ccc07d28404c656c62ec202d602454e2d78354a0', 'CPSC', '2020-11-04', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Rogue Home Timers', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received seven reports of the battery overheating and two of the reports resulted in the battery burning and melting the battery compartment. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Rogue Home Timers and contact Coulter Ventures for instructions on how to receive a full refund.', '21018');
INSERT INTO safety_incidents VALUES ('51f8baf79e074c0dd8b70ad655e7249f5e6cb938', 'CPSC', '2020-11-04', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Cat & Jack "Himani" and "Jaren" Toddler Boots', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'The firm has received five reports of the elastic laces breaking and one report of both the elastic laces and toggle breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled boots away from children and return them to any Target Store for a full refund. If consumers purchased the boots on Target.com, they may contact Target to receive a prepaid return label to return the boots.', '21021');
INSERT INTO safety_incidents VALUES ('90c994295dc77b7ed72442f5da65c4788bf8ad85', 'CPSC', '2020-11-04', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Drawer Chests', 'The Recalled Drawer Chests Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That May Result In Death Or Injuries To Children. The Chests Do Not Comply With The Performance Requirements Of The U.S. Voluntary Industry Standard (Astm F2057-19).', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled chests and contact Walker Edison for instructions to dispose of the product and obtain a full refund or free replacement. Walker Edison will provide packaging and pre-paid shipping labels so that consumers can remove the chest''s drawer slides and return them to the firm for a full refund or free replacement chest.', '21019');
INSERT INTO safety_incidents VALUES ('ee9d31f28cd91d0eb7bd3cb369e9922eb176fb87', 'CPSC', '2020-11-04', 2020, '2020-11', 'USA', 'United States', '', 'Other', 'Rambler® 20 oz Travel Mugs with Stronghold Lids', 'Burns', 'Other', 'Burns', 'The firm has received two reports of the magnetic slider on the Rambler 20 oz Travel Mug with Stronghold Lid being ejected after being sealed with hot liquid. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the Rambler 20 oz Travel Mug with Stronghold Lid and visit yeti.com for instructions on returning the lid or at a YETI store for a full refund.', '21020');
INSERT INTO safety_incidents VALUES ('80bec09eb0d756cf1aa4f343396359ef50e1bc93', 'CPSC', '2020-10-29', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Heavy Duty Oven Liners', 'If The Oven Liner Is Not Cut Or Configured For The Exact Specifications Of The Oven And It Is Placed Over Any Vents Or Other Openings In The Oven, Carbon Monoxide Can Build Up, Posing A Risk Of Carbon Monoxide Poisoning To Consumers.', 'Other', 'Poisoning / Ingestion', 'The firm has received one report of a consumer''s carbon monoxide alarm going off when using their oven with the recalled oven liner. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled oven liners. The company has notified all known purchasers. Consumers who have not received their refund should contact Gorilla Commerce.', '21705');
INSERT INTO safety_incidents VALUES ('34d353710cf51b485dd3a0e6d9f4a7d6b2ebacae', 'CPSC', '2020-10-29', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Mueller Austria Onion Chopper Pro', 'The Product''S Locking Tab Can Detach From The Rest Of The Unit During Use, Causing Hands And Fingers To Slide Into The Blades.', 'Sharp Edges / Points', 'Laceration / Cut', 'Mueller Austria has received 266 incidents of the tab breaking, resulting in 137 laceration injuries to the hands and fingers.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled onion choppers and contact Mueller Austria for a free replacement model with a newly-designed locking tab.', '21017');
INSERT INTO safety_incidents VALUES ('635ff5a92557edbdfc2ee8c35e8f8a87254da5d6', 'CPSC', '2020-10-29', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Nash Convertible Cribs', 'Injury', 'Mechanical Failure', 'Not Specified', 'Serena & Lily has received 5 reports of the leg partially detaching from the headboard/footboard. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled cribs and contact Serena & Lily for a repair, replacement or refund. Consumers can choose a replacement headboard and footboard to repair the crib, plus a coupon for $250 good for one year from date of issue; replace the Nash Convertible Crib; exchange for another Serena & Lily crib of equivalent value; or a full refund. Serena & Lily is contacting all purchasers of recalled cribs directly.', '21706');
INSERT INTO safety_incidents VALUES ('747103ab48c41fe9a8c9a19fa3b56c86d41faf78', 'CPSC', '2020-10-28', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Ron Jon Surf Shop Sippy Cup', 'The Plastic Characters On The Recalled Sippy Cup Contain Levels Of Lead That Exceed The Federal Lead Content Ban And Contain Levels Of A Regulated Phthalate That Exceed The Prohibition Of Specific Phthalates. Lead And Banned Phthalates Are Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled Sippy Cup away from children and contact Porter World Trade for instructions on how to return the product for a full refund.', '21015');
INSERT INTO safety_incidents VALUES ('a8adf3337fc16b3a56566c565995952efb9fa29b', 'CPSC', '2020-10-28', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Surgeloc Surge Protection Devices', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of an arcing incident that caused smoke damage to the wall in a commercial location. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled surge protection devices and contact Schneider Electric for instructions on receiving a free equivalent replacement surge protector.', '21013');
INSERT INTO safety_incidents VALUES ('2140077767cf5a14ee39db1b24707205ab621282', 'CPSC', '2020-10-22', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Wintergreen essential oil, and Pain Ease, Sports Pro, True Blue, Relieve Me oil blends', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act. The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Wintergreen essential oil and oil blends, store the product in a safe location out of reach of children and contact Rocky Mountain Oils for a free replacement lid. Rocky Mountain Oils is contacting all purchasers directly.', '21704');
INSERT INTO safety_incidents VALUES ('de0ab3b1619232502ce4e622e1e8f50178541d7e', 'CPSC', '2020-10-21', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'SALT™ Lounge Chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 19 reports of chairs breaking, including four reports of minor injuries from falls.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled lounge chairs and return them to any Bed Bath & Beyond location for a full refund of the purchase price, or a merchandise credit if the consumer''s purchase price cannot be determined.', '21012');
INSERT INTO safety_incidents VALUES ('42c74631dd363567e2881a87a2236e9b15e2c86d', 'CPSC', '2020-10-21', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Trace bookcases', 'Injury', 'Mechanical Failure', 'Not Specified', 'CB2 has received 11 reports of the bookcase collapsing when loaded. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bookcases and contact CB2 for instructions on how to receive a free replacement bookcase or a full refund.', '21011');
INSERT INTO safety_incidents VALUES ('b728715640fbcbd2afe968dbba2484e502398fb1', 'CPSC', '2020-10-21', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Danish Tall Bookcases', 'Injury', 'Mechanical Failure', 'Not Specified', 'Crate and Barrel has received five reports of the bookcase''s leg breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bookcase and contact Crate and Barrel to receive a full refund.', '21009');
INSERT INTO safety_incidents VALUES ('64bf821cd8b76d42ba85f963d7267b432bf23ef7', 'CPSC', '2020-10-21', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'MorfBoard Skate & Scoot Combo scooters with "Y" handlebars', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'The company has received 18 reports of the "Y" handlebars breaking with one injury when a child fell resulting in a bloody nose.', 'Moderate', 1, 0, 'Consumers should immediately take these recalled scooters with the "Y" handlebars away from children and contact Jakks Pacific to receive a free replacement "T" handlebar.', '21010');
INSERT INTO safety_incidents VALUES ('60dea2c3d9e0f9e30841ccf0d519320dda3696ba', 'CPSC', '2020-10-15', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'PR70P Clip-In Pedals fitted on Peloton bikes (sold between July 2013 and May 2016)', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 120 consumer reports of pedal breakages, including 16 reports of leg injuries. Five of the injuries required medical care, such as stitches to the lower leg.', 'Moderate', 1, 0, 'Consumers should immediately stop using bikes fitted with PR70P Clip-In pedals. Peloton is notifying all affected consumers directly on how to receive free replacement pedals, along with instructions for self-installation.', '21702');
INSERT INTO safety_incidents VALUES ('8f9a5964fc8b521032718054f56faaeee6736874', 'CPSC', '2020-10-15', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Homerygardens™ 4-Outlet, 6-Foot Long Indoor and Outdoor Extension Cord Splitters', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled extension cords and contact Sales BSD Inc. to return the product for a full refund. Shipping and handling will be at no cost to consumers. The firm is contacting all known purchasers directly.', '21703');
INSERT INTO safety_incidents VALUES ('402e7fad4bccfb3ffa8d910daeea7f40a85588dc', 'CPSC', '2020-10-09', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Great Falls outdoor ceiling fans', 'Injury', 'Sharp Edges / Points', 'Fracture / Blunt Trauma', 'Westinghouse Lighting has received 62 reports of the fan blades cracking or breaking, including one report of an impact injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ceiling fans and contact Westinghouse Lighting for instructions on receiving a free replacement blade kit.', '21701');
INSERT INTO safety_incidents VALUES ('771e339bdb84d7307ae7e90832c878cf2a13c5a5', 'CPSC', '2020-10-07', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Bordo and Bordo XL dining tables', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'CB2 has received four reports of the tables collapsing including three reports of injuries involving a laceration and a swollen leg/ankle.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled tables and contact CB2 for instructions on how to receive a full refund.', '21004');
INSERT INTO safety_incidents VALUES ('0cf2eca6a670cbdbdb652d75700e729a93da2e4a', 'CPSC', '2020-10-07', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Trianium cell phone battery pack cases', 'Burns', 'Flammability / Overheating', 'Burns', 'Endliss has received 96 reports of batteries overheating due to thermal runaway, including 10 reports of burn injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled phone cases, dispose of them in accordance with local laws on battery disposal, and contact Endliss for a free replacement power pack.', '21003');
INSERT INTO safety_incidents VALUES ('18a39c5c495225d4655ecec3893c819ce373288a', 'CPSC', '2020-10-07', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Kingsbury 70 inch ceiling fans', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'HKC-US has received 76 reports of the light globe falling, including four laceration injuries.', 'Moderate', 1, 0, 'Consumers should immediately contact HKC to request a new owner''s manual and light kit label to help ensure correct installation of the light globe.', '21005');
INSERT INTO safety_incidents VALUES ('f5c23eda6db94480e2af6c7dbc2e810d44eb7c6e', 'CPSC', '2020-10-07', 2020, '2020-10', 'USA', 'United States', '', 'Other', 'Antifreeze products', 'The Antifreeze Products Contain The Substance Ethylene Glycol Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act. The Products'' Caps Were Not Rotated Enough During Manufacturing To Engage The Child Resistant Mechanism, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately inspect the product and twist the cap to ensure the child resistant mechanism is engaged.', '21002');
INSERT INTO safety_incidents VALUES ('92b00a5f529979057abc37ea42e2c9b866c78b90', 'CPSC', '2020-09-30', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Low-Stretch Kernmantle Ropes', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ropes and inspect the rope for a deep cut or tape connecting two ends of rope together, and if either is found, contact Petzl America for instructions on receiving a free replacement rope.', '20194');
INSERT INTO safety_incidents VALUES ('c291076467d019ee5a663e04fabada0458a7ee14', 'CPSC', '2020-09-30', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'STIHL BF-KM Mini-Cultivator attachments', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'STIHL Inc. has received 12 reports of incidents, including six reports of lacerations to consumers.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mini-cultivator attachment and take it to an authorized STIHL servicing dealer for a free inspection and free proper assembly.', '20193');
INSERT INTO safety_incidents VALUES ('b647004c43a960c4689abea0b317d587f3726950', 'CPSC', '2020-09-24', 2020, '2020-09', 'USA', 'United States', '', 'Other', '2020 and 2021 ZFORCE 950 Sport Recreational Off-Highway Vehicles (ROVs)', 'The Throttle Gas Pedal Can Fail To Return Quickly To The Idle Position Which Can Create A Crash Hazard If The Vehicle Does Not Slow Down As Quickly As Expected By The Driver When The Gas Pedal Is Released. The Throttle Gas Pedal Can Fail To Return Quickly To The Idle Position Which Can Create A Crash Hazard If The Vehicle Does Not Slow Down As Quickly As Expected By The Driver When The Gas Pedal Is Released.', 'Mechanical Failure', 'Skin Irritation', 'CFMOTO has received two reports of the throttle pedal assembly malfunctioning. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ROVs and contact a CFMOTO dealer to schedule a free repair. CFMOTO is contacting all registered owners and dealers directly.', '20781');
INSERT INTO safety_incidents VALUES ('d9df2c7ce2e32ec0b54b3d89fbb3c788128db3d6', 'CPSC', '2020-09-24', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Vthrive Bioactive Women''s One-Daily Multi vitamins', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Contact The Vitamin Shoppe for instructions on how to dispose of the product and receive a full refund or merchandise credit. The Vitamin Shoppe is notifying all known purchasers directly.', '20782');
INSERT INTO safety_incidents VALUES ('05a4d01e636adfb7b6ec26c4623ae18d43527e27', 'CPSC', '2020-09-23', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Caravan Sports Armed/Padded Arm Bagged Chairs', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received reports of six incidents where the seat fabric separated from the chair frame. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Caravan Sports Armed/Padded Arm Bagged chairs and contact Caravan Global for instructions on how to receive a full refund.', '20189');
INSERT INTO safety_incidents VALUES ('e24d197e72e9db3ea74487b25223ff036e8e96d0', 'CPSC', '2020-09-23', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Kobalt Brand 40-volt Lithium Ion Cordless Electric Chainsaws', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Hongkong Sun Rise Trading has received 48 reports of the switch contacts welding causing the chainsaw to remain in the "on" position. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chainsaws and contact Hongkong Sun Rise Trading for a free repair.', '20191');
INSERT INTO safety_incidents VALUES ('edfd2df12ee55223c6ce385d190dc15dec0e8abd', 'CPSC', '2020-09-23', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Kobalt brand 40-volt Lithium Ion 8-inch Cordless Electric Pole Saws', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Hongkong Sun Rise Trading has received 65 reports of the saws continuing to run. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pole saws and contact Hongkong Sun Rise Trading for a free repair.', '20192');
INSERT INTO safety_incidents VALUES ('af8c7a6207a44d21c9735bbe172f7aa5e46cf592', 'CPSC', '2020-09-23', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Electric bicycles', 'Electric Shock', 'Mechanical Failure', 'Fall Injury', 'Pedego has received five reports of the bike''s electrical cable malfunctioning, causing the bike to unexpectedly accelerate. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact a local Pedego dealer to arrange for a free repair.', '20188');
INSERT INTO safety_incidents VALUES ('ffbc8efc1d9a9489cc737185c21eb6b208b5f5c8', 'CPSC', '2020-09-23', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Sirrus, Sirrus X and Sirrus Sport Bicycles with alloy cranks', 'Injury', 'Instability / Fall Risk', 'Skin Irritation', 'The firm has received 56 reports of crank arm disengaging, including seven reports of injuries. One injury involved a torn bicep tendon and the other six were minor injuries, such as road rash.', 'Minor', 1, 0, 'Consumers should stop using the recalled bicycles immediately and contact their nearest authorized Specialized retailer for a free repair.', '20190');
INSERT INTO safety_incidents VALUES ('04369053319385005eec1fd997510c241680cabd', 'CPSC', '2020-09-16', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Monoprice Category 6 Ethernet Bulk CMR Communications Cables', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled cables and contact Monoprice to schedule a free installation visit to inspect and replace the cable at no charge.', '20184');
INSERT INTO safety_incidents VALUES ('7957d701c7603b8db8b80ed0e98bdf61718798de', 'CPSC', '2020-09-16', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Dual Fuel Portable Generators', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received 26 reports of fuel leaking from the fuel valve. No fires, injuries, or property damage have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled generators and contact MWE Investments to arrange for a free repair.', '20185');
INSERT INTO safety_incidents VALUES ('6ba3d3891554d6efe2e2e26611ec40b89ae6d5fe', 'CPSC', '2020-09-16', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Industrial Three-Panel Mirrors', 'Injury', 'Mechanical Failure', 'Fall Injury', 'RH has received 6 reports of mirror panels detaching or becoming loose. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled mirrors and contact RH to receive a full refund of the purchase price, or a credit if the consumer''s purchase price cannot be determined.', '20183');
INSERT INTO safety_incidents VALUES ('680dc7298198f6218f6d9b55776c0847e39b875a', 'CPSC', '2020-09-11', 2020, '2020-09', 'USA', 'United States', '', 'Other', '31 Medique Over-the-Counter drugs from the product lines Medi-First, Medi-First Plus, Medique, Dover, Otis Clapp, and Ecolab', 'The Over-The-Counter Products Contain Regulated Substances Which Must Be In Child Resistant Packaging When Being Used In The Household As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach of children and contact Medique for information on how to dispose of the product and receive a full refund. All known purchasers are being notified directly.', '20780');
INSERT INTO safety_incidents VALUES ('b3075f58b3dea034a2e31d05ce81d72e5f89cfed', 'CPSC', '2020-09-10', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Organic Aromas Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Organic Aromas for store credit of the original purchase price or a replacement with any other essential oil of choice in the same size as the original purchase. Organic Aromas is contacting all known purchasers directly.', '20778');
INSERT INTO safety_incidents VALUES ('8d36da01d0042b548fcbcece4e17070783d9d413', 'CPSC', '2020-09-10', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Traction elevators', 'The Elevator Cab Can Rise Unexpectedly To The Top Of The Elevator Shaft And Abruptly Stop, Posing An Impact Hazard To Any Occupants In The Elevator Cab.', 'Other', 'Fracture / Blunt Trauma', 'The firm has confirmed eight reports of a failure in the motor gearbox assembly. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled elevators and contact Residential Elevators to schedule a free repair. All affected elevators must be repaired, including elevators that have been inspected as part of the firm''s March 29, 2018 recall. Some elevators may have already received the new CPSC approved remedy for this recall. Residential Elevators is able to determine whether a residential elevator is included in this recall by the consumer''s street address. Residential Elevators is contacting all known purchasers with affected elevators to schedule a free repair.', '20779');
INSERT INTO safety_incidents VALUES ('2ea80d633184f17f8adc6de5c03bef292c3f4ea3', 'CPSC', '2020-09-09', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Front Racks with Bamboo Trays', 'Falls', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'Cycling Sports Group has received reports of two incidents of the tray detaching and contacting the bicycle wheel, one resulting in a fall involving minor cuts and bruises, and the other involving both bruising and a concussion.', 'Minor', 1, 0, 'Consumers should immediately stop riding the bicycle until the front rack is removed, and contact their local authorized Cannondale dealer or Cycling Sports Group to arrange for a free repair.', '20179');
INSERT INTO safety_incidents VALUES ('b5862c82c032604fef113a652486211f8ee7f7d7', 'CPSC', '2020-09-09', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Patio 2-Burner Propane Gas Grills with Side Shelves', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Royal Gourmet has received six reports of incidents involving grill catching on fire. No injuries have been reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled grill and contact Royal Gourmet for a free accessory repair kit.', '20178');
INSERT INTO safety_incidents VALUES ('12561ca70fdef510c1c6e7b02508f24ef8a17e25', 'CPSC', '2020-09-09', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'WHILL Personal Electric Vehicles, Model Ci', 'Injury', 'Mechanical Failure', 'Skin Irritation', 'There have been 15 reports of device malfunctions. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled personal mobility vehicle and contact WHILL for a free replacement control pad.', '20177');
INSERT INTO safety_incidents VALUES ('ecb0ddcab0944d030bbc723d1f5187c640582167', 'CPSC', '2020-09-03', 2020, '2020-09', 'USA', 'United States', '', 'Other', '2020 ZFORCE 950 Sport Recreational Off-Highway Vehicles (ROVs)', 'Fire', 'Flammability / Overheating', 'Not Specified', 'CFMOTO has received two reports of the fuel injector connection not fully secure and locked in place, causing a fuel leak. One of the incidents resulted in a vehicle engine fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ROVs and contact a CFMOTO dealer to schedule a free repair. CFMOTO is contacting all registered owners and dealers directly.', '20776');
INSERT INTO safety_incidents VALUES ('ff08f24da2a36d7ae39f30350b54377e4a3b67c8', 'CPSC', '2020-09-03', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Domyos Swiss balls', 'Injury', 'Mechanical Failure', 'Fracture / Blunt Trauma', 'Decathlon USA has received 26 reports of the balls unexpectedly bursting, resulting in six injuries worldwide, including bruises, scratches, and fractures. No incidents or injuries have been reported in the U.S.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled swiss balls and contact Decathlon for a refund in the form of a store credit for the amount equal to the purchase price. Decathlon is contacting all known purchasers directly.', '20777');
INSERT INTO safety_incidents VALUES ('b72c147e9a23216f7c770e3c4ec9cfbba60cd08a', 'CPSC', '2020-09-03', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'SODA SENSE® CO2 canisters', 'Injury', 'Other', 'Not Specified', 'Soda Sense has received 18 reports of the canister''s top valve ejecting, resulting in minor property damage, such as damage to the home soda machine if the canister was in the machine when the valve broke, or when the valve in the canister broke, damage to surrounding property like glasses, plates or other fragile items if knocked into by the machine, the valve or the canister. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled canisters and contact SODA SENSE to receive a free replacement canister, including shipping. SODA SENSE is contacting all known purchasers directly.', '20775');
INSERT INTO safety_incidents VALUES ('19011439c949e239dffce38a31b3400f6f851c6a', 'CPSC', '2020-09-03', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Hi-Lift Storage Hoist Classic and Pro models sold with green polypropylene straps', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'StoreYourBoard has received six reports of straps breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled straps and contact StoreYourBoard.com for instructions on proper disposal of the green straps and how to receive free black replacement straps. StoreYourBoard.com is contacting all known purchasers directly.', '20774');
INSERT INTO safety_incidents VALUES ('a046c9bd6908c80efa45b20b25ad2fc357370380', 'CPSC', '2020-09-02', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'LEDU Black Fluorescent Computer Task Lamps Model L283MB', 'Burns', 'Flammability / Overheating', 'Burns', 'Advantus has received one report of smoke emerging from the lampscase housing. No injuries reported.', 'Minor', 1, 0, 'Consumers should immediately unplug and stop using the recalled lamp and contact Advantus to arrange for a full refund.', '20175');
INSERT INTO safety_incidents VALUES ('b3f0b79132fb0830086753956b872cb6cbf7d700', 'CPSC', '2020-09-02', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'Swivel rocker and glider chairs', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Hanamint has received 26 incidents of the chair''s post separating from the base, including one injury involving a small scrape.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled swivel rockers and gliders and contact Hanamint for a free repair.', '20176');
INSERT INTO safety_incidents VALUES ('e7c5ea431e652d83d69e0e150d7e2c2fd1bb21d2', 'CPSC', '2020-09-02', 2020, '2020-09', 'USA', 'United States', '', 'Other', 'IMMI SubZero 4-point and IMMI Click6 6-point UTV harnesses', 'Injury', 'Other', 'Skin Irritation', 'IMMI reports that seven Harnesses lacked stitching at one of multiple attachment points. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled SubZero and Click6 harnesses until inspected by an authorized dealer. Consumers with affected harnesses missing stitching will receive a free replacement harness.', '20174');
INSERT INTO safety_incidents VALUES ('c3ad765e7da7b3279b813c7baef79867619af9dd', 'CPSC', '2020-08-27', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Calmer Solutions Wintergreen Gautheria Procumdens 100% Pure Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Amazon will be contacting all known purchasers with instructions on how to receive a full refund.', '20772');
INSERT INTO safety_incidents VALUES ('8f7854daecad674906af0a183e2210f605da6112', 'CPSC', '2020-08-27', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Birch Sweet Essential Oil 100% Pure', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Amazon will be contacting all known purchasers with instructions on how to receive a full refund.', '20773');
INSERT INTO safety_incidents VALUES ('1943840de2ab395c767021f72bfc7c034844c7e5', 'CPSC', '2020-08-27', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Morpher flat-folding bicycle helmets', 'Injury', 'Other', 'Not Specified', 'None reported.', 'Minor', 1, 0, 'Morpher is no longer in business and is unable to conduct the recall. Consumers should immediately stop using the recalled helmets and dispose of them to prevent further usage. Amazon and Morpher are contacting all known purchasers directly.', '20771');
INSERT INTO safety_incidents VALUES ('c835c8a19a7b8f4b191905f68ab465ad470ea71a', 'CPSC', '2020-08-26', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Standoff and Wide Dock Ladders', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'One reported incident, including a laceration injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled dock ladders and contact CMP Group to return the ladders for a full refund or a free replacement ladder.', '20172');
INSERT INTO safety_incidents VALUES ('20ab4e6fe2d873c7588f20b7173071ad63860a4a', 'CPSC', '2020-08-26', 2020, '2020-08', 'USA', 'United States', '', 'Other', '6" Plush Aflac Promotional Doctor Duck', 'The Buttons On The Lab Coat Worn By The Doctor Duck Contain Levels Of Lead That Exceed The Federal Lead Content Standard. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately dispose of the recalled plush Doctor Duck. Communicorp is contacting Aflac employees and licensed agents who purchased the Doctor Duck directly.', '20173');
INSERT INTO safety_incidents VALUES ('1ffcca745ace31341056d82c1b85e73a44041df7', 'CPSC', '2020-08-21', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Children''s helmets', 'Injury', 'Other', 'Not Specified', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and contact woom bikes USA for instructions on how to receive a full refund. woom bikes USA is contacting all purchasers directly.', '20770');
INSERT INTO safety_incidents VALUES ('7804b77ae43f85d3cbedfa23dbdb9aab113caea0', 'CPSC', '2020-08-19', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Super Soaker XP 20 and Super Soaker XP 30', 'The Decorative Sticker On The Water Tank Of The Water Blaster Toys Contain Levels Of Lead In The Ink That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled toy away from children and contact Hasbro Inc. for instructions on how to return the product and receive a full refund. Consumers will be asked to unscrew the tank from the blaster and return the tank to the manufacturer using a postage prepaid label, for a full refund.', '20168');
INSERT INTO safety_incidents VALUES ('573d28af50b364528c149de71d0f630d397d26ca', 'CPSC', '2020-08-19', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'CFMK Surface Mount Brackets', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'The firm has received 24 reports of CPANL LEDs coming loose or falling from the CFMK Bracket, resulting in one injury.', 'Minor', 1, 0, 'Consumers should immediately stop using CPANL LEDs surface mounted with a CFMK Bracket and contact Lithonia Lighting for a free CFMK Bracket repair kit. Consumers should prevent people from going into the immediate area under the fixtures until the brackets are repaired.', '20167');
INSERT INTO safety_incidents VALUES ('47e1919a7abea8b3d4704f066defa460f4ca29bd', 'CPSC', '2020-08-19', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Three-Wick Halloween Candles', 'Fire', 'Flammability / Overheating', 'Burns', 'Pier 1 has received seven reports involving high flames with the three-wick Halloween candles, including one incident resulting in a minor burn injury and one report of minor property damage.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled candles and carefully cut all three wicks as short as possible to prevent other consumers from being able to use the candle. Consumers should then discard the product in their household trash.', '20169');
INSERT INTO safety_incidents VALUES ('e68d5fc9b0ed1f9f95ad16bed34ab087c7de3a78', 'CPSC', '2020-08-19', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Bastian Teak medicine cabinets', 'Injury', 'Mechanical Failure', 'Fall Injury', 'Signature Hardware has received seven reports of the mirrors detaching and falling, including one report that an installer was injured when two mirrors fell and struck his back and three reports of minor property damage. Signature Hardware also has received seven reports that a mirror was loose or detached when the consumer received the medicine cabinet.', 'Moderate', 1, 0, 'Consumers should immediately contact Signature Hardware to schedule a free in-home repair.', '20166');
INSERT INTO safety_incidents VALUES ('81ed63d9073c1bb3d53a1dfa45a82631e4af5f73', 'CPSC', '2020-08-12', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Sweet Protection brand Ripper Jr., Ripper MIPS Jr., and Ripper MIPS bicycle helmets', 'Injury', 'Other', 'Not Specified', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled helmets and return to the store where sold or contact Active Brands/Sweet Protection for a full refund.', '20165');
INSERT INTO safety_incidents VALUES ('a35a28d6bcb321824716e2cbd971e0c551fb778d', 'CPSC', '2020-08-12', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Lawn dart sets', 'Lawn Darts Are Banned In The U.S. Due To Serious Risks Of Skull Punctures And Other Serious Injuries, Particularly To Children.', 'Sharp Edges / Points', 'Not Specified', 'None reported.', 'Serious', 1, 0, 'Crown Darts UK is unable to conduct the recall. Consumers should immediately stop using the recalled lawn dart sets and destroy and dispose of them to prevent further usage.', '20163');
INSERT INTO safety_incidents VALUES ('ac459474f87f120f7a90d3c77f2bad130ffdd96e', 'CPSC', '2020-08-12', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'B-Air, BlueDri, BlueDri Pro and Soleaire Blowers', 'Fire', 'Electrical Fault', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the convenience outlets on the side of the recalled blowers and contact Intertex for a free repair. Consumers with recalled units will receive a free cordset adapter with an integrated circuit breaker.', '20162');
INSERT INTO safety_incidents VALUES ('f9249d2255f40dcf8a91ccfc89ac7bc643147202', 'CPSC', '2020-08-12', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Thule Sleek strollers', 'Injury', 'Mechanical Failure', 'Not Specified', 'Thule has received one report of the stroller''s handlebar detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled strollers and contact Thule Group to arrange for the return of the product and to receive a free replacement Sleek stroller frame.', '20164');
INSERT INTO safety_incidents VALUES ('24664aff00208593cb825cd853f550fd9cd80cd5', 'CPSC', '2020-08-11', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Essential Home Belmont 2.0 four-drawer chests', 'The Recalled Chests Are Unstable And Can Tip Over If Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Death Or Injuries To Children.', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled chests if they are not properly anchored to a wall and place them in an area that children cannot access. For chests purchased on or after February 11, 2019, contact Transform to receive a free anchoring kit and upon request, a one-time, free in-home installation of the wall anchor kit. For chests purchased before February 11, 2019, contact Transform to receive a free anchoring kit.', '20161');
INSERT INTO safety_incidents VALUES ('18ae93a5636ae2f1eb590863e69f2ea5d0b030db', 'CPSC', '2020-08-06', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'REVIVE Wintergreen and Birch Essential Oils and REVIVE Sore No More, Ache Away and Breeze Essential Oil Blends', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the products in a safe location out of reach of children and contact REVIVE for a free child-resistant replacement cap. REVIVE is directly notifying all known purchasers about the recall.', '20769');
INSERT INTO safety_incidents VALUES ('dbb3864c5a4947189abc26d66bb3ce2b2a171fa3', 'CPSC', '2020-08-05', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'Moravian Star lights', 'Fire', 'Electrical Fault', 'Electric Shock', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the light and contact Hercules for a free repair kit.', '20158');
INSERT INTO safety_incidents VALUES ('60200c6abb9cd4b321bba21d928bd5df2d4f827e', 'CPSC', '2020-08-05', 2020, '2020-08', 'USA', 'United States', '', 'Other', 'X-14® Mildew Stain Remover', 'Falls', 'Explosion', 'Skin Irritation', 'None.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled X-14 Mildew Stain Remover and contact WD-40 Company for instructions on how to dispose of the product or return it to receive a full refund.', '20160');
INSERT INTO safety_incidents VALUES ('7dcc1a7de243d3f8fc3db7298bd2798d2a35b8fe', 'CPSC', '2020-07-30', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Bio Source Naturals Wintergreen and Birch Sweet Essential Oils', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Are Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the products in a safe location out of reach of children and contact Bio Source Naturals for a full refund. Bio Source Naturals is directly notifying all known purchasers about the recall.', '20767');
INSERT INTO safety_incidents VALUES ('5c8fb5a4950f72ea600e98775d7a147079384c70', 'CPSC', '2020-07-30', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Valor H5 gas fireplace', 'Fire', 'Sharp Edges / Points', 'Laceration / Cut', 'Miles Industries has received one report of delayed ignition in the United States. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled fireplaces and contact their Valor fireplace retailer or contractor to schedule a free repair. Miles Industries is contacting all known purchasers directly.', '20768');
INSERT INTO safety_incidents VALUES ('fcf5607237b0b286df4b627fd9b8005cb7920ff1', 'CPSC', '2020-07-28', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Prestige Solo & Prestige Excellence condensing gas boilers', 'Flue Gas Can Escape From The Gas Boilers If The Vent Adapter Is Not Securely Reattached To The Boiler After Maintenance Or Repair, Posing A Carbon Monoxide Poisoning Hazard To Consumers.', 'Other', 'Poisoning / Ingestion', 'The firm has received one report of a death from carbon monoxide poisoning associated with the recalled boilers in 2016 following a repair where the adapter was not reattached. The firm has also received two other reports of vent tube adapter separation from the recalled boilers.', 'Fatal', 1, 0, 'Consumers with recalled boilers should immediately contact Triangle Tube to schedule a free repair. Consumers who continue using the boilers while awaiting repair should have working carbon monoxide alarms on each level of their homes and outside sleeping areas. Consumers who do not have a carbon monoxide alarm can contact Triangle Tube to have one shipped to them free of charge.', '20157');
INSERT INTO safety_incidents VALUES ('d3e5615f77f06be526feb44a80ed49933bd4cff7', 'CPSC', '2020-07-23', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Nature''s Oil Wintergreen and Birch Essential Oils', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Are Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the products in a safe location out of reach of children and contact Bulk Apothecary for a full refund. All known purchasers are being notified directly by Bulk Apothecary about the recall and will receive a full refund.', '20766');
INSERT INTO safety_incidents VALUES ('9f04250a84682e7d14c0e332bcffbc5496b62299', 'CPSC', '2020-07-23', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Model Year 2020 Ranger XP 1000 and Ranger CREW XP 1000 Off-Road Vehicles, Model Years 2019 - 2020 PRO XD 4000D UTVs, Model Year 2019 PRO XD 2000D UTVs, and Model Year 2020 Bobcat UV34 and UV34XL UTVs', 'An Improperly Manufactured Clutch Component Can Cause The Engine Braking Feature To Fail, Resulting In Unexpected Vehicle Motion, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'The firm has received 14 reports of unexpected motion or drive clutch locking, including one report of a crash resulting in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair, if needed. Polaris is notifying dealers and contacting registered owners directly.', '20765');
INSERT INTO safety_incidents VALUES ('b90ad057a5ca9cf4890c034c170da2f04956bdac', 'CPSC', '2020-07-23', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Home Accents Holiday artificial Christmas trees', 'Burns', 'Flammability / Overheating', 'Burns', 'The firm has received 509 reports of incidents of overheating involving the foot-pedal controller, including one report of a burn.', 'Moderate', 1, 0, 'Consumers should immediately stop using the foot-pedal controller, dispose of it and contact Willis Electric for free replacement foot pedal controller.', '20153');
INSERT INTO safety_incidents VALUES ('7ac3307816e08dea428f228b8804f52d8197ed51', 'CPSC', '2020-07-22', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'BioMed Balance Wintergreen and Birch Tar Essential Oils', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Are Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact BioMed Balance for a full refund.', '20154');
INSERT INTO safety_incidents VALUES ('5537d069df34807709a067ad5a4a37770fd6d8b0', 'CPSC', '2020-07-22', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Greenpan SimmerLite Dutch Ovens with Lid', 'Burns', 'Other', 'Burns', 'The firm has received four consumer reports of incidents, including three reports of the lid exploding while the product was inside the oven, resulting in one report of property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled Dutch Ovens immediately and contact Cookware Company for a full refund or a free replacement glass lid.', '20151');
INSERT INTO safety_incidents VALUES ('5844aa49feaeebf2e05bcb73797389dab415144f', 'CPSC', '2020-07-22', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Mattress on the Go folding mattresses', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled mattresses and contact DownEast to receive a free fitted liner to cover the mattress and bring it into compliance with the federal standard.', '20155');
INSERT INTO safety_incidents VALUES ('dce5db28945dd60590244c3e83c0a565b1f09327', 'CPSC', '2020-07-22', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Manhattan Ball', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Manhattan Toy has received six reports of the plastic tubes detaching from the center ball. Two of the six reports included a silicone teether being separated from the toy. The firm also reported one incident of a child mouthing the silicone teether after it came off.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled toy away from children and contact Manhattan Toy or return it to any Target Store for a full refund.', '20152');
INSERT INTO safety_incidents VALUES ('3e5040dd19089dfa59a7aff8f1700191fa3388a8', 'CPSC', '2020-07-16', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Model Year 2015-2020 AXYS Trail Performance and Crossover snowmobiles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Polaris has received 13 reports of improperly secured fuel hoses. No fires or injuries have been reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled snowmobiles and contact a Polaris dealer to schedule a free inspection and, if needed, a free repair. Polaris is notifying dealers and contacting registered owners directly.', '20764');
INSERT INTO safety_incidents VALUES ('a9fb5fa6a4118d01b32bd54d4bbb0d46398ec8b2', 'CPSC', '2020-07-16', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Rocky Mountain non-electric alloy frame Instinct, Instinct BC and Pipeline bicycles', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received 12 reports of front triangles cracking. There have been no reports of injuries.', 'Moderate', 1, 0, 'Consumers should stop using the recalled bicycles immediately and contact Rocky Mountain for information on how to receive a free replacement front triangle.', '20150');
INSERT INTO safety_incidents VALUES ('10686563cea7a6a6adb8503862d6c8011a7caab2', 'CPSC', '2020-07-15', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Parke Twin and Full Beds', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Crate and Barrel has received nine reports of incidents of the headboard separating from the frame, including two foot injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled beds and contact Crate and Barrel for a free replacement.', '20149');
INSERT INTO safety_incidents VALUES ('57355aeef2306904c8772406c31d9793aacb930a', 'CPSC', '2020-07-15', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Simplers Botanicals Organic Wintergreen (Gaultheria Fragrantissiam) Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Contact Nutraceutical Corporation for instructions on how to dispose of the product and receive a full refund.', '20148');
INSERT INTO safety_incidents VALUES ('84b3f4475c8809031b45df8454f68198c606129c', 'CPSC', '2020-07-09', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Wintergreen 100% Pure Essential Oil, Sweet Birch 100% Pure Essential Oil, Super Soother Pure Essential Oil Blend, and Breathe Deep Pure Essential Oil Blend', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Are Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. All known purchasers are being notified directly by Ananda Apothecary about the recall and will receive a full refund for the sample size (0.5 mL) or be sent a free replacement child-resistant closure for the all other sizes.', '20759');
INSERT INTO safety_incidents VALUES ('c16c20c652349adb6f1e2ec6d76267a35aece0dc', 'CPSC', '2020-07-09', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'All Field and Prism RGBA light fixtures', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'Cooper Lighting Solutions has received three reports of lenses falling from All Field fixtures at indoor facilities in the U.S. No injuries have been reported.', 'Minor', 1, 0, 'Customers should immediately stop using the recalled light fixtures and contact Cooper Lighting Solutions for a free repair. Cooper Lighting is contacting all known purchasers to schedule repairs.', '20763');
INSERT INTO safety_incidents VALUES ('d413d70ea9de13f877005f16e59b16334f19845b', 'CPSC', '2020-07-09', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'DaVinci Bailey bassinets', 'Falls', 'Entrapment', 'Entrapment', 'DaVinci has received 13 reports of the mattress support becoming disengaged. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bassinets and contact DaVinci for a free repair kit that will reinforce the mattress support. In the meantime, parents are urged to find an alternate, safe sleeping environment for the child, such as a crib that meets current safety standards. DaVinci is contacting all known purchasers directly.', '20762');
INSERT INTO safety_incidents VALUES ('95bbb363e63fc42d5a10b76a7026af60f1b909c1', 'CPSC', '2020-07-09', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Miracle Botanicals Wintergreen and Birch Essential Oils', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the products in a safe location out of reach of children. Contact Miracle Botanicals for a free child-resistant replacement cap. Miracle Botanicals is directly notifying all known purchasers who purchased the products on MiracleBotanicals.com and Etsy.com. For products purchased on Amazon.com, all known purchasers are being notified directly by Amazon.', '20760');
INSERT INTO safety_incidents VALUES ('7bf658663b64413a07a4fa33270a0bacef093927', 'CPSC', '2020-07-09', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Riveted Mesh Floor Lamps', 'Fire', 'Flammability / Overheating', 'Not Specified', 'RH has received 11 reports of the lamp''s foot switch overheating, including one report of the foot switch catching fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using and unplug the recalled lamp immediately and contact RH for a full refund of the purchase price. RH is contacting all known purchasers directly.', '20761');
INSERT INTO safety_incidents VALUES ('7fc839fe24ce25351651a1a31447252f1780d9b4', 'CPSC', '2020-07-08', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'GloryBee Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact GloryBee for a free child-resistant replacement cap or store credit.', '20145');
INSERT INTO safety_incidents VALUES ('77ebc73319b3aca9c483d60582246c082c729378', 'CPSC', '2020-07-08', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Silvercrest Bread Makers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'There has been one incident of the bread maker becoming energized. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately unplug and stop using the bread maker and return it to their nearest Lidl store for a full refund.', '20146');
INSERT INTO safety_incidents VALUES ('a9a1f3dc4fb15faf7a341d5a04b1519683416883', 'CPSC', '2020-07-08', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Pranarom Wintergreen Essential Oils', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately dispose of the product and contact Pranarom for a free replacement product.', '20147');
INSERT INTO safety_incidents VALUES ('2114a6de6965ba3093d366af333e0186389389cb', 'CPSC', '2020-07-02', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Belecoo 535-S Baby Strollers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled baby stroller and contact A Better You! for instructions on how to receive a full refund including taxes and original shipping cost. The firm is contacting all known purchasers directly.', '20755');
INSERT INTO safety_incidents VALUES ('0b0ebd1b6ee76b538d5369b7d41e94db7332cd4f', 'CPSC', '2020-07-02', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Cottage Town Bedroom Furniture Collection', 'The Base Coat Paint Used On Pieces Within The Furniture Collection Contains Levels Of Lead That Exceed The Federal Lead Paint Standard. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled furniture and contact Rooms To Go for free replacement and free pickup of the furniture. Rooms To Go is contacting all known purchasers directly. Consumers will not be responsible for shipping costs.', '20754');
INSERT INTO safety_incidents VALUES ('90a550fc000aba88a11bdd129c4dece5b376abf0', 'CPSC', '2020-07-02', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Edens Garden 100% Pure Wintergreen and Birch Essential Oil', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Are Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product out of reach of children in a safe location and contact Edens Garden for a free replacement child resistant cap. Edens Garden is contacting all known purchasers directly about the recall.', '20756');
INSERT INTO safety_incidents VALUES ('40e6feda49aa992cd2287e46e2fdc32af1e7aa65', 'CPSC', '2020-07-02', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Model Year 2018-2020 Polaris Phoenix 200 ATVs', 'The Throttle Lever Stop Can Fail Due To Damage During Shipping, Posing A Crash Hazard.', 'Other', 'Skin Irritation', 'The firm received five consumer reports; four of them pertain to the throttle stop breaking, and one report of the throttle stop sticking. No injuries reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and, if needed, a free repair. Polaris is notifying dealers and contacting registered owners directly.', '20757');
INSERT INTO safety_incidents VALUES ('924ce4dc745ca2327e30a1492b50b085b48073f2', 'CPSC', '2020-07-02', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Model Year 2019 - 2020 Ranger XP 1000 & Model Year 2020 General XP 1000 Utility Vehicles (UTVs)', 'The Throttle Can Fail To Return To The Idle Position After The Engine Stalls And Is Restarted In Gear Without Switching The Key To The Off Position Due To A Software Problem, Causing The Vehicle To Accelerate Suddenly, Posing A Crash Hazard To The User.', 'Other', 'Skin Irritation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair. Polaris is notifying dealers and contacting registered owners directly.', '20758');
INSERT INTO safety_incidents VALUES ('0f0576ecdc02967b9dfc8fc90d0f21472862b51b', 'CPSC', '2020-07-01', 2020, '2020-07', 'USA', 'United States', '', 'Other', 'Cub Scout activity pins', 'The Pin''S Face And Shaft Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled pin away from children and return the pin to any Boy Scouts of America retail store or contact Boy Scout of America''s National Distribution Center for a full refund, including shipping, or for a merchandise credit.', '20144');
INSERT INTO safety_incidents VALUES ('d1c9e1c8b706a4c2aa427a9bf2d551f3551eec9b', 'CPSC', '2020-06-25', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Baby Strollers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled baby strollers and contact Costway for instructions on how to receive a full refund including taxes and original shipping cost. Costway is contacting all purchasers directly.', '20753');
INSERT INTO safety_incidents VALUES ('5375a9438d2cdb54e47a6ab4c79b043932eedc70', 'CPSC', '2020-06-24', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Modavari Forrest Live Edge Benches', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The Furniture Connexion has received 12 reports of tipping or instability, including two injuries. Injuries include a head injury and toe injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled product and contact Furniture Connexion Inc for a free a repair kit. The Furniture Connexion Inc is contacting all purchasers directly.', '20142');
INSERT INTO safety_incidents VALUES ('6963576e1b0621ac015222d9924a6135853ce226', 'CPSC', '2020-06-18', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Lochinvar condensing residential boilers', 'The Boiler''S Flue Grommet Can Deteriorate And Dislodge During Use And Allow The Boiler To Emit Carbon Monoxide, Posing A Risk Of Carbon Monoxide Poisoning.', 'Other', 'Poisoning / Ingestion', 'The firm has received 7 reports of boiler''s flue grommets deteriorating, including one report of two nonfatal injuries involving carbon monoxide poisoning, and two reports of carbon monoxide emission not involving an injury.', 'Fatal', 1, 0, 'Consumers with the recalled boilers should immediately contact the installer or a qualified technician to schedule a free repair. Consumers who continue use of the boilers while awaiting repair should have working carbon monoxide alarms outside of sleeping areas and on every level of the home.', '20141');
INSERT INTO safety_incidents VALUES ('fa12241b47b4dbd008db86feaf9413b4899c884b', 'CPSC', '2020-06-18', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Brighton, Travis and Bevelle dressers', 'The Recalled Dressers Are Unstable If The Mirror Is Not Installed, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Death Or Injuries To Children. The Dressers Do Not Comply With One Of The Performance Requirements Of The U.S. Voluntary Industry Standard (Astm 2057-17). The Tip-Over Restraint Kits Do Not Comply With The Performance Requirements Of The U.S. Voluntary Industry Standard (F3096-14).', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should always keep children away from dresser until repair is completed. Contact Modus for a free compliant replacement tip-over restraint kit and to request a one-time, free in-home installation of the kit. Modus Furniture is contacting all known purchasers directly.', '20752');
INSERT INTO safety_incidents VALUES ('040871f1f6c289f0fbcd9b2cca33c3ed1b1feb66', 'CPSC', '2020-06-18', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Recreational off-highway vehicles (ROVs)', 'Injury', 'Other', 'Skin Irritation', 'The firm has received three reports of the ROVs moving while in the park position. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ROVs and contact an authorized Honda Powersports dealer to schedule an appointment for a free inspection and repair. Honda is contacting all known purchasers directly.', '20751');
INSERT INTO safety_incidents VALUES ('87fae3b398bc4bdf5be68d196a2d0c6c4922e572', 'CPSC', '2020-06-17', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Edwards Mechanical Heat Detectors', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Minor', 1, 0, 'Consumers who use the product in life-safety applications permitted by code (for example, in elevator shafts, or in lieu of smoke detectors, manual pull stations, or sprinklers in particular settings), or in residential attics or residential garages, should immediately contact a fire or security alarm professional for free replacement and installation of the heat detector.', '20140');
INSERT INTO safety_incidents VALUES ('375fc5b952143dda1e4bfd6daedf8624c8485d16', 'CPSC', '2020-06-17', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'HON Office Chairs', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'HON has received reports of 11 chair backs breaking including two reports of minor injuries.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled chairs and contact HON for a free replacement back including installation instructions.', '20137');
INSERT INTO safety_incidents VALUES ('64466f30da78f4d862770990aa92bd5a46ba9bb0', 'CPSC', '2020-06-17', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Charging Cable for Relay Screenless Communication Devices', 'Burns', 'Flammability / Overheating', 'Burns', 'Republic has received two reports of incidents of the charging cable overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled charging cables and contact Republic Wireless for a free replacement charging cable. Republic Wireless is contacting consumers of affected products who have active accounts to provide free replacement cables. Customers who purchased a Relay device but do not currently have an active account can contact Republic Wireless to determine if they have an affected product and to obtain a free replacement.', '20139');
INSERT INTO safety_incidents VALUES ('a56657ad536ec9b149686b5273e85efb2509db8b', 'CPSC', '2020-06-17', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Rainbow SRX Vacuums', 'Fire', 'Flammability / Overheating', 'Burns', 'There have been two reports of the SRX vacuum catching fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately unplug and stop using their affected SRX vacuum and contact an authorized Rainbow distributor for a free repair.', '20138');
INSERT INTO safety_incidents VALUES ('38d797efe263bdba5bd333d1143c58a4d81c5c6f', 'CPSC', '2020-06-11', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Miniware Teething Spoons', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Bonnsu has received one report of an infant who bit through the silicone teething spoon, resulting in a piece separating inside the infant''s mouth.', 'Moderate', 1, 0, 'Consumers should stop using the recalled teething spoons immediately and contact Bonnsu for a free replacement product.', '20135');
INSERT INTO safety_incidents VALUES ('a2959a150a6e524e219c4bd33d5f0d15ab73a174', 'CPSC', '2020-06-11', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Davina Wintergreen Essential Oil and Davina Kneads Relief Sore Muscle Blend', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Contact Davina Wellness for a free replacement child-resistant cap. All known purchasers are being notified directly about the recall by Davina Wellness or by the online retailer where the product was purchased.', '20750');
INSERT INTO safety_incidents VALUES ('983d507eb677e5a102e9e9f5126a6a42019006a8', 'CPSC', '2020-06-10', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Field & Stream safety ropes', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'The firm has received one report of the safety rope failing when used during freezing weather, resulting in a concussion and knee injury.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ropes and return them to any DICK''s Sporting Goods or Field & Stream store if purchased at those stores or at Sportsman''s Warehouse store if purchased there. Consumers with a receipt will receive a full refund and consumers without a receipt will receive a store credit of the purchase price.', '20133');
INSERT INTO safety_incidents VALUES ('5e8e4245a970b149a2ba3135f22aa60fc481a288', 'CPSC', '2020-06-10', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Umbrella strollers', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled strollers and contact Island Wear for instructions on how to receive a full refund.', '20132');
INSERT INTO safety_incidents VALUES ('7969ff6cd488f32de53e93ba1bc7dbee5cf34f02', 'CPSC', '2020-06-10', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Indiglow LED T8 Lamps', 'Injury', 'Flammability / Overheating', 'Fall Injury', 'Ushio America has received reports of five incidents involving the lamp tubes overheating and falling to the ground. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using Ushio America T8 Indiglow LED lamps and contact the firm for a full refund or a free replacement lamp. Ushio America is contacting all known purchasers directly.', '20134');
INSERT INTO safety_incidents VALUES ('c4a2a0220dd0563ee14cd3ac18ac201428c461bd', 'CPSC', '2020-06-04', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Simply Earth Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Simply Earth for a free child-resistant replacement cap. The firm is directly notifying all known purchasers about the recall.', '20748');
INSERT INTO safety_incidents VALUES ('2929630ec20a97408e04402530bbf8d192e10851', 'CPSC', '2020-06-04', 2020, '2020-06', 'USA', 'United States', '', 'Other', 'Emori Wintergreen 100% Pure Essential Therapeutic Grade Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Contact Tim Trading for instructions on how to dispose of the product and receive a full refund or replacement with a similar product. All known purchasers are being notified directly about the recall by Tim Trading or Amazon.', '20749');
INSERT INTO safety_incidents VALUES ('691cb3517262214191e303bfabf076c8898e8ccf', 'CPSC', '2020-05-27', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Wide Fit Kitten Heel Court Pumps', 'The Leather Insock In The Shoes Has Elevated Levels Of Chromium Vi, Posing A Risk Of Skin Irritation.', 'Other', 'Skin Irritation', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled shoes and return the shoes to a Primark store for a full refund of the purchase price.', '20127');
INSERT INTO safety_incidents VALUES ('13d66d55d2590dc6e8841f02747681327e517a87', 'CPSC', '2020-05-27', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Sanvall Rapid Alivio Pain Relieving Roll-On', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the pain relieving roll-on in a safe location out of reach of children and contact Sanvall Enterprises for a full refund.', '20126');
INSERT INTO safety_incidents VALUES ('f09b89f0d227189d6bd983bfab2f3d1f9c68baef', 'CPSC', '2020-05-21', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Nelson and Lauki Dressers and Cabinets', 'The Recalled Dressers And Cabinets Are Unstable And Can Tip Over If Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Death Or Injuries To Children. The Chests Do Not Comply With The Performance Requirements Of The U.S. Voluntary Industry Standard (Astm F2057-19).', 'Entrapment', 'Entrapment', 'Herman Miller has received one report of a tip-over with no injuries or property damage. No other incidents have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using this or any recalled chest or cabinet if not properly anchored to the wall, place it in an area that children cannot access and contact Herman Miller to receive a full refund with free pick-up of the chest. Herman Miller is contacting all known purchasers directly.', '20747');
INSERT INTO safety_incidents VALUES ('771d921d62dcd9b3d160bad44160b34a3d5cb687', 'CPSC', '2020-05-21', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Viva Doria Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Contact Viva Doria for instructions on how to dispose the product and receive a full refund. All known purchasers are being notified directly about the recall by Viva Doria or by the online retailer where the product was purchased.', '20746');
INSERT INTO safety_incidents VALUES ('c9bce351859daad27971c8ef298adc1b6213e585', 'CPSC', '2020-05-20', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Bunz Kidz Children''s Sleepwear Sets', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately take the recalled sleepwear sets away from children and contact Stargate Apparel for a full refund.', '20125');
INSERT INTO safety_incidents VALUES ('7dc38cb7a57a3a4b3f5539630ba61886c10d5a57', 'CPSC', '2020-05-14', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Aromatics International Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Aromatics International for a free replacement child-resistant cap. Aromatics International is notifying all known purchasers directly.', '20742');
INSERT INTO safety_incidents VALUES ('84eaf89547865540c749ff8faac1cc0057d9abf0', 'CPSC', '2020-05-14', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Swurfer Kiwi Baby and Toddler Swings', 'Falls', 'Mechanical Failure', 'Fall Injury', 'The firm has received six reports of the rope end detaching. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled swings and contact the firm to receive instructions to repair the swings.', '20121');
INSERT INTO safety_incidents VALUES ('ff31813bc8c3de1cea7f191a0b45cd3356cb1394', 'CPSC', '2020-05-14', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Garia Golf & Courtesy battery-powered electric vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm is aware of five incidents of overheating and fire damage to the vehicles. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop charging these recalled golf and courtesy vehicles and contact Garia or a Garia dealer to schedule a free repair. Garia is contacting all known customers by direct mail and e-mail.', '20122');
INSERT INTO safety_incidents VALUES ('305a7bee760248db5507d7fbad8f74a9a5593e26', 'CPSC', '2020-05-14', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Attachment Kits for John Deere 60-inch Brooms', 'Injury', 'Other', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using their John Deere 60-inch Broom and contact an authorized John Deere dealer for a free copy of the Operator''s Manual. John Deere is contacting all known purchasers of the recalled Attachment Kits. If an Attachment Kit did include an Operator''s Manual, consumers can continue to use their Broom.', '20744');
INSERT INTO safety_incidents VALUES ('d6fed7f38318946d5ca5cfa4bd90207118d49cc8', 'CPSC', '2020-05-14', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Organic Pure Oil Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Organic Pure Oil for a full refund. Organic Pure Oil and Amazon are notifying all known purchasers directly.', '20745');
INSERT INTO safety_incidents VALUES ('1d5b168876d07a430ec1b57f18a63cf3fe29a4f0', 'CPSC', '2020-05-14', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Hampton Bay, Patriot Lighting and Paradise light kits with Sterno Home LED power supplies', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'The firm has received one report of the light''s power supply plug blade detaching in an AC outlet. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled path lights and contact Sterno Home to receive a free replacement LED power supply and installation instructions.', '20123');
INSERT INTO safety_incidents VALUES ('7fbaddeba969527a8653a07062a4bb9e66839468', 'CPSC', '2020-05-14', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Jade Bloom Wintergreen and Birch Sweet Essential Oils', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Contact Jade Bloom for instructions on how to dispose of the products and receive a full refund or a store credit. The firm is directly notifying all known purchasers.', '20743');
INSERT INTO safety_incidents VALUES ('191a4fa475323ae38fe3f75eaeea3ec2d0098d1a', 'CPSC', '2020-05-13', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Hodedah HI4DR 4-drawer chests', 'The Recalled Chest Is Unstable If It Is Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That May Result In Death Or Serious Injuries To Children. The Chests Do Not Comply With The Performance Requirements Of The U.S. Voluntary Industry Standard (Astm 2057-19).', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using any recalled chest that is not properly anchored to the wall and place it in an area that children cannot access. Hodedah will provide free anti-tip anchoring kits or packaging and pre-paid shipping labels so that consumers can remove the chest''s drawer slides and return them to the firm for a full refund and discard the rest of the dresser.', '20120');
INSERT INTO safety_incidents VALUES ('f7de929cb337af4725b00adb895359c433a9368d', 'CPSC', '2020-05-07', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Poppin'' Cobs 10 Pack Microwave Popcorn', 'Fire', 'Flammability / Overheating', 'Burns', 'Poppin'' Cobs has received five reports of the popcorn brown paper bags catching on fire in the microwave. No injuries or property damage have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Poppin'' Cobs 10 Pack Microwave Popcorn and contact the firm to receive free replacement bags. Consumers can order the replacement bags online at https://www.poppincobs.com/products/replacement-bags', '20118');
INSERT INTO safety_incidents VALUES ('47c1bbbf2ab0d182dcb692f71bfb765d3a6c82a2', 'CPSC', '2020-05-07', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Noah Reverse Fleece Hoodies', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled reverse fleece hoodies and contact Noah Clothing for a full refund plus a $20 gift card upon sending Noah a photo of the garment cut in half. Noah Clothing is directly contacting all known purchasers.', '20119');
INSERT INTO safety_incidents VALUES ('d4b3fadb8521ef70b53295bf908dddd3116af381', 'CPSC', '2020-05-07', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Mag Cube magnetic ball sets', 'Injury', 'Other', 'Poisoning / Ingestion', 'None reported with these recalled magnet sets. CPSC staff has received numerous incident reports of ingestions involving other small, high-powered magnets, including many that required surgery.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled magnetic balls and take them away from children. If you purchased the recalled magnetic balls for someone else, notify the recipient immediately. Consumers should contact Sobeauty Inc. for instructions on returning your product and receiving a full refund including taxes and the original shipping cost.', '20741');
INSERT INTO safety_incidents VALUES ('7a80eb447f4a4c8cb568619a75ce62b5e9bb3d95', 'CPSC', '2020-05-06', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Prepac 4-drawer chests', 'The Recalled Chests Are Unstable And Can Tip Over If Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Death Or Injuries To Children.', 'Entrapment', 'Entrapment', 'None reported', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled chests if not properly anchored to the wall and place them in an area that children cannot access. Contact Prepac to receive a free tipover restraint kit and consumers can request a one-time, free in-home installation of the wall anchor strap.', '20117');
INSERT INTO safety_incidents VALUES ('9ad7775bf98e0cf59bf086924ebf45f8a2fa082c', 'CPSC', '2020-05-01', 2020, '2020-05', 'USA', 'United States', '', 'Other', 'Power adapters sold with Epson scanners', 'Fire', 'Flammability / Overheating', 'Burns', 'Epson is aware of 15 incidents worldwide of the adapter melting or catching fire, resulting in property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled adapters and contact Epson to receive a free replacement adapter.', '20116');
INSERT INTO safety_incidents VALUES ('82d7ba2c9d313c0a1077189cbc1c1c1f4fd14991', 'CPSC', '2020-04-30', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Flash Receivers', 'The Back-Up Battery Can Fail To Fully Charge Resulting In The Receiver Not Working As Intended And Failing To Flash To Alert Hearing-Impaired Persons To An Emergency.', 'Other', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately contact Bellman & Symfon to receive a free repair. Consumers can continue to use their Flash Receivers until they receive the free repair, but the firm advises in the meantime to unplug and re-plug their units to keep them properly powered.', '20114');
INSERT INTO safety_incidents VALUES ('0f3f30f6e8449bf550eba1e24d997f926ee2a468', 'CPSC', '2020-04-30', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Essential Trading Post Wintergreen and Birch Essential Oils', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Are Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Essential Trading Post for a full refund. The firm is directly notifying all known purchasers about the recall.', '20740');
INSERT INTO safety_incidents VALUES ('65e6afa218ee4b14e6525d9dcf92c66fb95d441b', 'CPSC', '2020-04-30', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Rechargeable battery packs', 'Burns', 'Electrical Fault', 'Burns', 'Modular Robotics has received four reports of the rechargeable battery packs smoking and overheating. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the rechargeable battery packs, contact Modular Robotics for a free replacement battery pack. Safely dispose of the defective product by following local laws for disposal of the batteries.', '20115');
INSERT INTO safety_incidents VALUES ('854a041c8581acf144bd64d583e155828af27b6e', 'CPSC', '2020-04-30', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Children''s Neck Pillows', 'Paint On The Zippers And Zipper Pulls Contains Levels Of Lead That Exceed The Federal Lead Paint Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately take the recalled children''s neck pillows away from children and contact Ximi Vogue for a full refund.', '20113');
INSERT INTO safety_incidents VALUES ('8960dba3996f8860752333bc598ed76b95bb3a5f', 'CPSC', '2020-04-23', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'BioFinest Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Contact BioFinest for instructions on how to dispose of the product and receive a full refund. Biofinest is contacting all known purchasers directly.', '20739');
INSERT INTO safety_incidents VALUES ('7fe610ba240468cae9895597457a8eff5707d98f', 'CPSC', '2020-04-23', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Leviton 50 ampere, non-NEMA electrical connectors, plugs, receptacles and inlets', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'Leviton has received four reports of mismarked devices, including one report of a consumer who received an electrical shock, and three reports of minor property damage to equiptment with which the devices were being used.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled devices, disconnect power to them and contact Leviton to arrange for a free replacement device.', '20112');
INSERT INTO safety_incidents VALUES ('5bf283b0bb87543aca330c8a4b72ca7a0b5e7c50', 'CPSC', '2020-04-23', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'LUS Hair Dryers & Diffusers', 'Electric Shock', 'Electrical Fault', 'Electric Shock', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using and unplug the hair dryers. LUS is contacting all known purchasers of the hair dryers and providing a choice of either a full refund of the purchase price or a $175 store credit.', '20738');
INSERT INTO safety_incidents VALUES ('d1b3e3e994bca4167d5db65084fc3cb4009800cd', 'CPSC', '2020-04-23', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Dr. Mercola Wintergreen Essential Oil', 'The Products Contain The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should store the product in a safe location out of reach of children and contact Natural Health Partners for a free replacement child resistant cap or a full refund. Natural Health Partners is contacting all known purchasers directly about the recall.', '20736');
INSERT INTO safety_incidents VALUES ('9434368005836144c465df688b8e38c764a1d9b4', 'CPSC', '2020-04-23', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Eiji Essentials Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Naturo Sciences for a refund. The firm is directly notifying all known purchasers about the recall.', '20737');
INSERT INTO safety_incidents VALUES ('4615da4d0b212e1fefab44d5125b0124d3b8cd14', 'CPSC', '2020-04-16', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Dr. Adorable Sweet Birch Essential Oils', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Dr. Adorable for a full refund. Dr. Adorable is contacting all known purchasers directly.', '20731');
INSERT INTO safety_incidents VALUES ('962fcffce2521074c9754d0382e04b80caf02d71', 'CPSC', '2020-04-16', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Troy-Bilt and Craftsman 25cc 2-Cycle trimmers and Remington 25cc 2-Cycle polesaw', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled trimmers and polesaws and contact MTD Southwest for instructions on obtaining a free replacement trimmer or polesaw.', '20110');
INSERT INTO safety_incidents VALUES ('813f6e9bd2f90769c0fb8c257c30793c1f91971d', 'CPSC', '2020-04-16', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Model Year 2018 - 2020 Ranger XP 1000 & CREW XP 1000 Off-Road Vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Polaris has received four reports of clutch belts breaking which resulted in fuel line damage and fires. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair. Polaris is notifying dealers and contacting affected registered owners directly.', '20733');
INSERT INTO safety_incidents VALUES ('ba7f3d1269026a83ac968e47fa74bb78bd638691', 'CPSC', '2020-04-16', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Model Year 2019 - 2020 Ranger XP 1000 & CREW XP 1000 Off-Road Vehicles', 'Fire', 'Flammability / Overheating', 'Not Specified', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair. Polaris is notifying dealers and contacting affected registered owners directly.', '20734');
INSERT INTO safety_incidents VALUES ('de0d3f5944df5a0142f4c2be7bbd43d57182d9ae', 'CPSC', '2020-04-16', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Model Year 2019 Polaris PRO XD and model year 2020 Ranger Utility vehicles (UTVs)', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair. Polaris is notifying dealers and contacting registered owners directly.', '20735');
INSERT INTO safety_incidents VALUES ('d7c4c61b193c734196876868bc3cb9f743a2b028', 'CPSC', '2020-04-16', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Vitamin Shoppe Energy Formula Multivitamins (90 Tablets)', 'The Product Is A Dietary Supplement Containing Iron Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Poisoning Risk If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children. Contact The Vitamin Shoppe for instructions on how to dispose of the product and receive a refund or merchandise credit. All known purchasers are being notified directly by the firm about the recall.', '20732');
INSERT INTO safety_incidents VALUES ('46a667fd89fee97df2596b2141a86728ea7f0d1c', 'CPSC', '2020-04-16', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Wyndmere Birch Sweet Essential Oil and Aches and Pains Synergistic Blend', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Wyndmere Naturals for a full refund or a free child resistant replacement cap.', '20111');
INSERT INTO safety_incidents VALUES ('a58c73e13fd886d399aba75050ec26e6b6c8e197', 'CPSC', '2020-04-09', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Yeti SnowMX conversion kits', 'The Brakes On The Snow Bike Can Fail After The Conversion Kit Has Been Installed, Posing A Crash Hazard To The User.', 'Other', 'Skin Irritation', 'Camso has received 12 incidents of the brakes failing. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using snow bikes with the recalled conversion kits and contact an authorized Yeti SnowMX dealer to make an appointment for a free repair.', '20108');
INSERT INTO safety_incidents VALUES ('9b2c778dff349e69725c43caf379e6b3884b8052', 'CPSC', '2020-04-09', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Commercial-Grade Tamper Resistant Duplex Receptacles', 'Burns', 'Flammability / Overheating', 'Burns', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled receptacles and contact the firm for a free replacement, a full refund or a refund in the form of a credit.', '20109');
INSERT INTO safety_incidents VALUES ('337c713bf060db9da5e0cd4c55decc265f76b8f5', 'CPSC', '2020-04-08', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Lenox 2.5 Quart Tea Kettles', 'Burns', 'Drowning Risk', 'Burns', 'Continuum has received 14 reports of tea kettles expelling hot water through the top, including four reports of burn injuries, some of them severe.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled tea kettles and contact Continuum for a full refund if proof of purchase is available. If not, consumers will be entitled to a refund of $29.99.', '20107');
INSERT INTO safety_incidents VALUES ('741c4e1b3c94b4a524450870ec345bdfa90f5a48', 'CPSC', '2020-04-06', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Blythe dressers', 'The Recalled Dressers Are Unstable If Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That May Result In Death Or Serious Injuries To Children. The Dressers Do Not Comply With The Performance Requirements Of The U.S. Voluntary Industry Standard (Astm 2057-17).', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled dressers if not properly anchored to the wall and place it into an area that children cannot access. Consumers should contact Joybird for a free in-home repair to the dresser''s legs or a free one-time in-home installation of a tip-over restraint kit by a technician plus a $50 gift card to be used on Joybird''s website, or free pick-up of the dresser for a full refund. Joybird is contacting all known purchasers directly.', '20106');
INSERT INTO safety_incidents VALUES ('076c9411fafaea4d13e8e95c125dac7454b5b1f7', 'CPSC', '2020-04-02', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Musical Lili Llama', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Manhattan Toy has received seven reports of loose screws falling off the toy, including two reports of children putting the screws in their mouths.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled toy away from children and contact Manhattan Toy for a free repair kit.', '20102');
INSERT INTO safety_incidents VALUES ('2be13ced962de3892d19cbb4e43820ad632c8de9', 'CPSC', '2020-04-02', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'Wireless Power Reclining Furniture', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm is aware of 6 incidents of batteries overheating and causing fires to the chairs and floor coverings. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the "Wireless Power" reclining furniture and contact Southern Motion for a free in-home repair, including a credit for the cost of the "Wireless Power" lithium-ion battery option.', '20103');
INSERT INTO safety_incidents VALUES ('0d9e1e2e3e67fca33a9e9822c43936176009e8f0', 'CPSC', '2020-04-02', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'ASSO and ASSOS Sonoma wall fan heaters', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Stelpro has received five reports of overheating. There are no reports of injuries.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled heaters and contact Stelpro for information on receiving a free replacement wall fan heater.', '20105');
INSERT INTO safety_incidents VALUES ('4dbbf7da41eb536f2a6f01d9fadef26ada6f7dfc', 'CPSC', '2020-04-02', 2020, '2020-04', 'USA', 'United States', '', 'Other', 'VP Harrier and Giant Pinner DH bicycle pedals', 'Injury', 'Instability / Fall Risk', 'Fracture / Blunt Trauma', 'VP Components has received 79 reports of broken spindles and one report of a rider injured in a fall, after the spindle of a Giant Pinner DH model pedal separated from the body of the pedal.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled bicycle pedals contact the bike shop or online retailer where the pedals were originally purchased to arrange for free replacement pedals.', '20104');
INSERT INTO safety_incidents VALUES ('d799d62527bd26d2e203d2596cc73bcb3ce08b15', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Perfect Descent™ Auto Belays climbing devices', 'Injury', 'Mechanical Failure', 'Fall Injury', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled belay devices and contact C3 Manufacturing to receive a free repair. The firm contacted all known purchasers directly on October 21, 2019.', '20097');
INSERT INTO safety_incidents VALUES ('5192095d3d9ed0b0a194f616efe207e932e4945a', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Children''s Tool Kits', 'The Tool Belt, Hammer And Suspenders (Model H3044) Contain Excessive Levels Of Lead, Violating The Federal Lead Content Standard. In Addition, The Toy Goggles And Hardhats Do Not Meet Toy Safety Requirements.', 'Chemical / Toxic Substance', 'Not Specified', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using these recalled Children''s Tool Kits and keep them away from children. Consumers should contact Grizzly Industrial for instructions on returning the recalled tool kits to receive a full refund including return shipping. Grizzly is contacting all known purchasers directly to notify them of this recall.', '20098');
INSERT INTO safety_incidents VALUES ('14b31ba47ffccfa7faaa03b689ce9de663f79538', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Miles Glass Pitchers with Wood Lid', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Crate and Barrel has received five reports of the handle breaking off the glass pitcher while in use. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using the recalled pitchers immediately and contact Crate and Barrel for a full refund and disposal instructions.', '20099');
INSERT INTO safety_incidents VALUES ('07075af274948dd6bd5161ecddec3ecbfab7bdd7', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Grower''s Edge Vaporizers', 'Fire', 'Flammability / Overheating', 'Electric Shock', 'Hawthorne received 11 reports of overheating or fire, 9 for the Deluxe and 2 for the commercial model. Hawthorne has received one report of property damage as a result of vaporizer use, apart from damage to the vaporizer itself. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled vaporizers and return them to the place of purchase for a full refund in the form of store credit.', '20095');
INSERT INTO safety_incidents VALUES ('55d1dd066311b0a768287308d034c6692d673f98', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Kawasaki MULE PRO off-highway utility vehicles', 'Injury', 'Other', 'Skin Irritation', 'The firm has received 453 reports of incidents of steering problems. No injuries have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact a Kawasaki dealer to schedule a free repair. Kawasaki is contacting all known purchasers directly.', '20726');
INSERT INTO safety_incidents VALUES ('09fc28a11324cdc35d147b49cd35bdf90c554a8b', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Kawasaki MULE PRO off-highway utility vehicles', 'Fire', 'Flammability / Overheating', 'Respiratory', 'Kawasaki has received 165 reports of oil leakage and 84 reports of vehicles catching on fire, resulting in three injuries, including one report of a burn to the user''s foot, one report of a burn to the user''s arm, hand and buttocks and one incident of smoke inhalation. Kawasaki is aware of more than $131,000 in property damage claims, excluding the cost of damage to vehicles.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact a Kawasaki dealer to schedule a free repair. Kawasaki is contacting all known purchasers directly.', '20727');
INSERT INTO safety_incidents VALUES ('22e02c288c8877a21a79b7112c40499d6e2e426e', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Kids & Koalas baby walkers', 'The Baby Walkers Fail To Meet The Federal Safety Standard. Specifically, They Can Fit Through A Standard Doorway And Are Not Designed To Stop At The Edge Of A Step As Required By The Federal Safety Standard And They Have Leg Openings That Allow The Child To Slip Down Until The Child''S Head Can Become Entrapped At The Neck. Babies Using These Walkers Can Be Seriously Injured Or Killed.', 'Entrapment', 'Entrapment', 'None.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled baby walkers, dismantle them, and throw them away.', '20730');
INSERT INTO safety_incidents VALUES ('0a9f8c7386773cb4cc4eefd39b0e6422c1d1d0f9', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Lilly of New York children''s winter boots', 'The Boots'' Sole Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately take the recalled winter boots away from children and contact Lilly of New York for a full refund or to receive a free replacement product of similar value. Zulily is contacting all known purchasers directly.', '20729');
INSERT INTO safety_incidents VALUES ('f10ca597d271cb43eb03e18385c6a687b8c6cb0e', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Plant Therapy Wintergreen, Organic Wintergreen, Muscle Aid Synergy Blend, Tingly Mint Synergy Blend, and Vein Aid Synergy Blend Oils', 'The Products Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Products Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Plant Therapy for a free replacement child-resistant cap. All known purchasers are being notified directly by the firm about the recall.', '20723');
INSERT INTO safety_incidents VALUES ('a880a5f3bc7dede4ff7f907b146ee6bc8ecd4c51', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Thule Sleek Car Seat Adapters', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Thule has received three reports of the plastic brackets on the car seat adapters cracking or breaking while in use. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled Sleek Car Seat Adapter and contact Thule Group to arrange for the return of the product for a full refund or to receive a free replacement product of a Thule Sleek Bassinet which works on the Thule Sleek Stroller.', '20096');
INSERT INTO safety_incidents VALUES ('8f51dfe91eb6ee1cffc4bc85fdcb27a35a7ea99b', 'CPSC', '2020-03-19', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Woom model 4, 5, 6 bicycles', 'Injury', 'Mechanical Failure', 'Fall Injury', 'The firm has received two reports of the fork becoming loose or detaching in the U.S. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled bicycles and contact the firm for a free repair kit for the front fork. The firm is contacting all known purchasers and providing a free repair kit including installation instructions.', '20728');
INSERT INTO safety_incidents VALUES ('b36bba2245bfd335aafae1e73f0910c516de237a', 'CPSC', '2020-03-18', 2020, '2020-03', 'USA', 'United States', '', 'Other', '100% Sodium Hydroxide Drain Cleaner', 'Chemical', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately store the recalled product in a safe location out of reach of children and contact Belle Chemical for a free replacement label to put on the product.', '20094');
INSERT INTO safety_incidents VALUES ('be5b05389f0fd7d5d7162eae5daea39b68a10ac6', 'CPSC', '2020-03-18', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Sodium Hydroxide, Lye/Caustic Soda and Potassium Hydroxide, Caustic Potash Ash', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach of children and contact Belle Chemical for a free replacement child-resistant packaging and label to put on the product.', '20093');
INSERT INTO safety_incidents VALUES ('0bd9524a1d8b1a5312d93246a041d8dcddf7e372', 'CPSC', '2020-03-18', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Soap Supply Co. Lye, Soap Makers Lye, California Soap Supply, Combo Pure Solutions, Red Crown High Test Lye, and Boyer Potassium Hydroxide Flakes', 'Chemical', 'Chemical / Toxic Substance', 'Skin Irritation', 'CPSC has received two reports of chemical burn injuries with the California Soap Supply product. One involved a child who received chemical burns to their mouth after gaining access to the product.', 'Minor', 1, 0, 'Consumers should immediately store the recalled products in a safe location out of reach of children and contact Boyer for a free replacement child-resistant cap.', '20092');
INSERT INTO safety_incidents VALUES ('f198d43ec46fb6e10af74d0743933f91e19cd56d', 'CPSC', '2020-03-18', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Earthsonnets Wintergreen (Gualtheria procumbens) Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Earth Sonnets for a free replacement child resistant cap. All known purchasers are being notified directly by the firm about the recall.', '20725');
INSERT INTO safety_incidents VALUES ('10044c6237fc11d045e2e1677829acb18328655c', 'CPSC', '2020-03-18', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Earthroma''s Wintergreen Essential Oil', 'The Product Contains The Substance Methyl Salicylate Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the product in a safe location out of reach of children and contact Earthroma for a free replacement child resistant cap. All known purchasers are being notified directly by the firm about the recall.', '20722');
INSERT INTO safety_incidents VALUES ('0a15d42e175f6e6c5e054fe415b323ab33dbff8c', 'CPSC', '2020-03-18', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Sandimmune® (cyclosporine capsules, USP) 100 mg soft gelatin capsules and Neoral® (cyclosporine capsules, USP) MODIFIED 100 mg soft gelatin capsules prescription drug blister packages', 'The Prescription Drug Packaging Is Not Child Resistant As Required By The Poison Prevention Packaging Act (Pppa), Posing A Risk Of Poisoning If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately secure the product out of the sight and reach of children and contact the firm to request a free child-resistant pouch in which to store the blister package medications. Consumers can continue to use the medication as directed. The child-resistant pouches should be used to store these medications until new child-resistant blister packaging is available.', '20091');
INSERT INTO safety_incidents VALUES ('415af2b212e6f3c2090d781e13cbe40694bfd8bf', 'CPSC', '2020-03-18', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'NumbSkin pain relief cream with lidocaine', 'The Packaging Is Not Child Resistant As Required By The Poison Prevention Packaging Act. The Pain Relieving Cream Contains Lidocaine, Posing A Risk Of Poisoning To Young Children If They Put It On Their Skin Or Ingest It.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately store the pain relief cream in a safe location out of reach of children and contact SeeNext Venture for instructions on how to dispose or return it and to receive a free replacement similar product with a child-resistant cap. Amazon is contacting all known purchasers directly.', '20724');
INSERT INTO safety_incidents VALUES ('a3c9aa76ea934f4549de896e704e32d322ce7e0b', 'CPSC', '2020-03-17', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Honda EB2200i, EU2200i, EU2200i Companion and EU2200i Camo Portable Generators', 'Fire', 'Electrical Fault', 'Burns', 'Honda has received 13 reports of the generator''s inverter assembly short-circuiting while in use, including 10 reports of fire. No injuries or property damage reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled generators and contact a local authorized Honda Power Equipment service dealer to schedule a free repair. Honda is contacting all known purchasers directly. Consumers who took part in the previous recall for these generators should also take part in this recall.', '20090');
INSERT INTO safety_incidents VALUES ('478f62a9378441561ad72d1758f09021c8a40d1c', 'CPSC', '2020-03-12', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Finch three-drawer dressers', 'The Recalled Dressers Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Death Or Injuries To Children.', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using any recalled dressers that are not properly anchored to the wall and place them in an area that children cannot access. Contact Homestar to receive a free tip-over restraint kit and a one-time free in-home installation of the kit. Homestar is contacting all known purchasers directly.', '20721');
INSERT INTO safety_incidents VALUES ('13cd4149562bc01a929294fb139897205062ccfc', 'CPSC', '2020-03-12', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Kichler 52-inch LED Indoor Ceiling fans', 'Injury', 'Mechanical Failure', 'Fall Injury', 'Kichler has received about 62 reports of the fan blade iron breaking or detaching. Kichler has received one report of property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled ceiling fans and contact Kichler for instructions on receiving a free replacement ceiling fan.', '20088');
INSERT INTO safety_incidents VALUES ('635e1cff74c432dde58f953aafecdab70371f855', 'CPSC', '2020-03-12', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Line 6 Relay G10 Digital Wireless Guitar Systems and USB Charging Cables', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Yamaha is aware of four incidents worldwide of the battery cover separating forcefully from the transmitter, including one report of minor property damage. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled products and contact Yamaha to receive a free repair for the G10 Family of Products, and a full refund for the G10T USB charging cable.', '20089');
INSERT INTO safety_incidents VALUES ('fd0240d94d249df99381309b4053228b63900464', 'CPSC', '2020-03-05', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'ECHO and Shindaiwa Backpack Blowers and replacement straps', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'The firm has received 62 reports of incidents, including one minor injury, when pieces of blower were expelled from the machine, hitting a consumer in the neck.', 'Minor', 1, 0, 'Consumers should immediately stop using the backpack blowers and return them to an authorized ECHO or Shindaiwa dealer for a free repair. To locate the nearest authorized dealer, go to the ECHO Store Locator at www.echo-usa.com or the Shindaiwa Dealer Locator at www.shindaiwa-usa.com.', '20086');
INSERT INTO safety_incidents VALUES ('69337f2969dcb7c45bef6d893ffa7fcdd8375ae0', 'CPSC', '2020-03-05', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Children''s pajamas and robes', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled garments, take them away from children and contact Joules USA for a full refund.', '20087');
INSERT INTO safety_incidents VALUES ('9792f5ad8c2242de7994444235a12bdf52e8ba8f', 'CPSC', '2020-03-05', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'Camino Floor Lamps', 'Fire', 'Flammability / Overheating', 'Not Specified', 'RH has received six reports of the lamp''s foot switch overheating or catching fire, including five reports of minor property damage to flooring. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should stop using and unplug the recalled lamp immediately and contact RH for a full refund of the purchase price. RH is contacting all known purchasers directly.', '20720');
INSERT INTO safety_incidents VALUES ('e552de63846e3945e4ca01ac544fe36893aad6b6', 'CPSC', '2020-03-04', 2020, '2020-03', 'USA', 'United States', '', 'Other', 'KULLEN 3-drawer chest', 'The Recalled Chest Is Unstable If It Is Not Anchored To The Wall, Posing Tip-Over And Entrapment Hazards That May Result In Death Or Serious Injuries To Children. Additionally, Kullen 3-Drawer Chests Imported After August 12, 2019 Do Not Comply With The Performance Requirements Of The Updated Version Of The U.S. Consensus Standard (Astm 2057-19).', 'Entrapment', 'Entrapment', 'IKEA has received six reports of tip-over incidents involving KULLEN 3-drawer chests that were not anchored to the wall, including one report involving a minor cut and one report involving minor cuts and bruises.', 'Fatal', 1, 0, 'Consumers should immediately stop using the KULLEN 3-drawer chest if not properly anchored to the wall and place it into an area that children cannot access. Consumers should contact IKEA for either a full refund or a free wall-attachment (anchor) kit. For refund: IKEA will accept in-store returns or arrange for free pick up of the chests for a full refund. For wall-attachment (anchor) kit: Consumers can order a free wall-attachment (anchor) kit. Consumers can install the anchor themselves or IKEA will provide a one-time, free in-home installation service, upon request.', '20085');
INSERT INTO safety_incidents VALUES ('bfbec93a6b79e89364427e84dadf731827d1bb46', 'CPSC', '2020-02-27', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Just Blanks children''s nightgowns', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled nightgowns away from children and contact Ishtex Textile Products for a full refund.', '20082');
INSERT INTO safety_incidents VALUES ('0e8ec3862ee87bc4f4da058b342a72e3e04ccbb2', 'CPSC', '2020-02-27', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Lennox Ductless Single-Zone and Multi-Zone heat pumps', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received two reports, both in Canada, of overheating. One report included a small hole in the heat pump motor due to melting and one report of the fan blade and motor catching fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately contact their installing servicer, dealer, or contractor to arrange for a free replacement of the outdoor unit. While awaiting replacement, consumers should monitor the recalled heat pumps while they are being operated and keep foliage and other flammable items at least 24 inches away from the recalled units. Lennox is contacting all known independent dealers about the recall directly. The dealers will contact individual consumers to arrange for recalled outdoor units to be removed and replacement units to be installed.', '20083');
INSERT INTO safety_incidents VALUES ('6e7811967b8253485b95caad49211b00659b30a6', 'CPSC', '2020-02-27', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Little Helper''s™ children''s grocery shopping carts', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'Step2 has received 22 reports of cart baskets breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately take away the recalled shopping carts from children and contact Step2® for a free replacement shopping cart or a refund in the form of a $40 credit towards the purchase price of another Step2 product on www.Step2.com.', '20081');
INSERT INTO safety_incidents VALUES ('b1af48ede10246518cea91c715eb0363d03b79a6', 'CPSC', '2020-02-27', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Bayside Furnishings Lawler-9-PC-Dining Sets', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'Whalen has received reports of approximately 178 chairs breaking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the dining chairs and contact Whalen for instructions to receive a full refund. Whalen is contacting all known purchasers directly.', '20719');
INSERT INTO safety_incidents VALUES ('5bd50d67bf6e01327071639dc3d04a81c7bd17b7', 'CPSC', '2020-02-26', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Home Decorators Collection Print Block 4-Drawer Whitewash Chest', 'The Recalled Chest Is Unstable If It Is Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Death Or Injuries To Children. The Chest Does Not Comply With The Performance Requirements Of The U.S. Voluntary Industry Standard (Astm 2057-17).', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled chest unless properly anchored to the wall, and place it in an area that children cannot access. Contact Home Depot for a full refund with free chest pick-up.', '20079');
INSERT INTO safety_incidents VALUES ('8a9534835322d2075d474c39feccb384effb0f43', 'CPSC', '2020-02-26', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Aura and Silas 3-Drawer Chests', 'The Recalled Chests Are Unstable If They Are Not Anchored To The Wall, Posing Serious Tip-Over And Entrapment Hazards That Can Result In Death Or Injuries To Children.', 'Entrapment', 'Entrapment', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using any recalled chest that is not properly anchored to the wall and place it in an area that children cannot access. Safavieh will provide packaging and pre-paid shipping labels so that consumers can remove the chest''s drawer slides and return them to the firm for a full refund.', '20078');
INSERT INTO safety_incidents VALUES ('78d6cc5494694f3d9a3e2fa28a5f4d2d51328315', 'CPSC', '2020-02-20', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Browning Leather Pistol Holsters', 'Fire', 'Flammability / Overheating', 'Not Specified', 'Browning has received one report where the holster design changed the position of the safety switch on the firearm. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled holsters and contact Browning for a free replacement.', '20076');
INSERT INTO safety_incidents VALUES ('ebb1361803d56d9d5fafc9c512aea5a97a23051d', 'CPSC', '2020-02-20', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Inclined sleeper accessory included with Kolcraft Cuddle ''n Care 2-in-1 Bassinet & Incline Sleepers and Preferred Position 2-in-1 Bassinet & Incline Sleepers', 'Infant Fatalities Have Been Reported With Other Manufacturers'' Inclined Sleep Products, After The Infants Rolled From Their Back To Their Stomach Or Side, Or Under Other Circumstances.', 'Other', 'Not Specified', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled inclined sleeper accessory and contact Kolcraft for a $35 voucher to be used on www.Kolcraft.com or a $20 refund. The voucher can be used until February 20, 2022. Kolcraft is contacting all registered owners and known purchasers directly via a postcard by mail. Consumers can continue to use the bassinet without the inclined sleeper accessory.', '20075');
INSERT INTO safety_incidents VALUES ('c26182db74cda379095100adda1de8ec7aa9340a', 'CPSC', '2020-02-19', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Contigo Kids Cleanable Water Bottles', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'Contigo has received a total of 427 reports of the spout detaching including 27 spouts found in children''s mouths.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled water bottles and the replacement lids provided in the previous recall, take them away from children, and contact Contigo for a free water bottle. Consumers who received replacement lids in the previous recall should contact Contigo for the new water bottle.', '20074');
INSERT INTO safety_incidents VALUES ('45f4d879e61f079f6a3e9eb9415716c55c9ba963', 'CPSC', '2020-02-13', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Harbor Breeze Santa Ana ceiling fan', 'Injury', 'Sharp Edges / Points', 'Not Specified', 'The firm has received 210 reports of the fan blade breaking or ejecting from the fan, including 10 reports of a fan blade hitting consumers.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled ceiling fan and contact the firm for a free set of replacement blade holders.', '20072');
INSERT INTO safety_incidents VALUES ('1839263c1bab0f6a7d1a63dbab5ef937d87eef33', 'CPSC', '2020-02-13', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Gas-powered E-Z-GO, Cushman and Tracker brand off-road vehicles', 'Fire', 'Electrical Fault', 'Burns', 'Textron Specialized Vehicles has received 13 reports of melted and/or burned wires and electrical components and loss of vehicle function in some cases, including one report of fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled off-road vehicles and contact Textron Specialized Vehicles for a free repair. Textron Specialized Vehicles is contacting all known purchasers directly.', '20073');
INSERT INTO safety_incidents VALUES ('d84c8a4e263a5de5bec4a8698e3b12b34f809a18', 'CPSC', '2020-02-13', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Yamaha Golf Cars', 'Injury', 'Mechanical Failure', 'Skin Irritation', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled Yamaha Golf Cars and contact a Yamaha Golf car dealer to schedule a free repair. Yamaha is contacting all registered owners directly.', '20718');
INSERT INTO safety_incidents VALUES ('ebbe7ff473034d0a4788d49010a6d2f0b7a04f30', 'CPSC', '2020-02-06', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Leaf blowers', 'The Blades Inside The Leaf Blower Can Break Off And Discharge From The Unit, Posing A Projectile Hazard To The User Or Bystanders.', 'Sharp Edges / Points', 'Not Specified', 'The firm has received eight reports of the blades breaking and discharging from the blowers. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled leaf blowers and contact the firm for instructions to receive a full refund.', '20070');
INSERT INTO safety_incidents VALUES ('ce7fa9932b5c6c414a65d693b510f64580586b98', 'CPSC', '2020-02-06', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Go Forward 4-in-1 Evolved Ergonomic, Flip Front2back and Up Close Newborn infant carriers', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled infant carriers and contact Infantino for instructions on how to receive a free replacement carrier.', '20071');
INSERT INTO safety_incidents VALUES ('1c8ee60a96540429e9ceafc4e75a98ab6e348994', 'CPSC', '2020-02-06', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Sophie la Giraffe Bead Maze', 'Choking', 'Small Parts / Choking Hazard', 'Choking / Suffocation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled Sophie la Giraffe Bead Maze toy and check the bottom of the toy for the recalled batch numbers. If the toy matches the recalled batch numbers, consumers should destroy the triangle piece and contact Juratoys to receive a free replacement triangle piece.', '20066');
INSERT INTO safety_incidents VALUES ('342db523e5deb0f96f55bfd758f3f50edc05b8ae', 'CPSC', '2020-02-06', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'CHMACH-SR Senior Catchers helmets', 'Injury', 'Other', 'Not Specified', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled catcher''s helmets and contact Rawlings to receive a free replacement back plate for head sizes 7.5 and below or a full refund for head sizes above 7.5.', '20067');
INSERT INTO safety_incidents VALUES ('71f776b848bf0611d72ce6d9e5a4cef52ac2f78f', 'CPSC', '2020-02-06', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Patmos Chaise Lounge Chairs', 'The Paint Used On The Chair''S Metal Frame Contains Levels Of Lead That Exceed The Federal Lead Paint Standard. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Effects.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should stop using the recalled chairs immediately and contact Rooms To Go for a replacement. Rooms To Go is contacting all known purchasers directly.', '20717');
INSERT INTO safety_incidents VALUES ('e437afb03bddec54d40a434eb4500975f8a45394', 'CPSC', '2020-02-06', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Sump Pumps sold under Utilitech, Do It and Star Water Systems brands', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received six reports of the recalled sump pumps smoking. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately unplug the recalled sump pumps and contact Star Water Systems for instructions to disable their pump and to obtain a full refund.', '20069');
INSERT INTO safety_incidents VALUES ('9166077da66eecee57fd289b4ebd9bb60f655ae2', 'CPSC', '2020-02-06', 2020, '2020-02', 'USA', 'United States', '', 'Other', 'Sun Essential Oils, Wintergreen', 'The Product Contains The Substance Methyl Salicylate, Which Must Be In Child Resistant Packaging As Required By The Poison Prevention Packaging Act (Pppa). The Packaging Of The Product Is Not Child Resistant, Posing A Poisoning Risk If The Contents Are Swallowed By Young Children.', 'Other', 'Poisoning / Ingestion', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately store the product in a safe location out of the reach of children and contact Sun Organic for a free replacement child-resistant cap.', '20068');
INSERT INTO safety_incidents VALUES ('ef6e74d9f66746922eb71c499abfc2ac48fa7b4c', 'CPSC', '2020-01-30', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Model Year 2017-2018 Bobcat 3650 Utility Vehicles (UTVs)', 'The Rear Brake Line Can Become Punctured Causing The Brakes To Fail, Posing A Collision And Crash Hazard.', 'Sharp Edges / Points', 'Skin Irritation', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Bobcat dealer to schedule a free inspection and repair. Bobcat is notifying dealers and contacting affected registered owners directly.', '20715');
INSERT INTO safety_incidents VALUES ('f2545aee452ecc3fb3f6a67bfea5ec146c5bfd75', 'CPSC', '2020-01-30', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Children''s Lounge Pants', 'Fire', 'Flammability / Overheating', 'Burns', 'None reported.', 'Minor', 1, 0, 'Consumers should immediately take the recalled lounge pants away from children and contact K-Apparel for a full refund. K-Apparel is contacting all known purchasers.', '20716');
INSERT INTO safety_incidents VALUES ('66286e1b5c8cbcef509b3ef89dbd31cb0af854bc', 'CPSC', '2020-01-30', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Desk Chairs', 'Injury', 'Instability / Fall Risk', 'Fall Injury', 'Pier 1 has received 29 reports of chair legs breaking, resulting in one minor back injury.', 'Minor', 1, 0, 'Consumers should stop using the recalled desk chairs immediately and contact Pier 1® to receive a free repair kit, including shipping.', '20064');
INSERT INTO safety_incidents VALUES ('368c5bdb694175b4dff67c629aa081410bb72d55', 'CPSC', '2020-01-30', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Model Year 2017-2018 Brutus Utility Vehicles (UTVs)', 'The Rear Brake Line Can Become Punctured Causing The Brakes To Fail, Posing A Collision And Crash Hazard.', 'Sharp Edges / Points', 'Skin Irritation', 'Polaris has received one report where the rear brake line ruptured while in use. No collisions, crashes, injuries or deaths have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled vehicles and contact a Polaris dealer to schedule a free inspection and repair. Polaris is notifying dealers and contacting affected registered owners directly.', '20713');
INSERT INTO safety_incidents VALUES ('c8308d1a5c0ca87dbe6f02f260a39130a6609e97', 'CPSC', '2020-01-30', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Model Year 2019 Polaris PRO XD Utility Vehicles (UTVs)', 'The Rear Brake Line Can Become Punctured Causing The Rear Brakes To Fail, Posing A Collision And Crash Hazard To The Rider.', 'Sharp Edges / Points', 'Skin Irritation', 'Polaris has received eight reports of rear brake failures. No collisions, crashes, injuries or deaths have been reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the recalled utility vehicles and contact a Polaris dealer to schedule a free inspection and repair. Polaris is notifying dealers and contacting affected registered owners directly.', '20714');
INSERT INTO safety_incidents VALUES ('acd65148542c4dbe652eb06f70adb0f9af0c3b12', 'CPSC', '2020-01-29', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Beautyrest Beginnings Incline Sleeper with Adjustable Feeding Position for Newborns; Disney Baby Minnie Mouse Incline Sleeper with Adjustable Feeding Position for Newborns; Delta Children Deluxe 3-in-1 Activity Rocker, Feeder and Sleeper; Simmons Kids Beautyrest Deluxe 3-in-1 Activity Rocker, Feeder, and Sleeper; 3-in-1 Activity Rocker, Feeder and Incline Sleeper and others.', 'Infant Fatalities Have Been Reported With Other Manufacturers'' Inclined Sleep Products, After The Infants Rolled From Their Back To Their Stomach Or Side, Or Under Other Circumstances.', 'Other', 'Not Specified', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the inclined sleeper and contact Delta for a cash refund or voucher.', '20061');
INSERT INTO safety_incidents VALUES ('7fdf5dae43da9f5bffcefa3da1e77515f5e9fc48', 'CPSC', '2020-01-29', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Pillo Portable Napper', 'Infant Fatalities Have Been Reported With Other Manufacturers'' Inclined Sleep Products, After The Infants Rolled From Their Back To Their Stomach Or Side, Or Under Other Circumstances.', 'Other', 'Not Specified', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the product and contact Evenflo for a cash refund or voucher.', '20060');
INSERT INTO safety_incidents VALUES ('e7f4baebb29af379b63b99755a84759ac9df607e', 'CPSC', '2020-01-29', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Graco Little Lounger Rocking Seat', 'Infant Fatalities Have Been Reported With Other Manufacturers'' Inclined Sleep Products, After Infants Rolled From Their Back To Their Stomach Or Side, Or Under Other Circumstances.', 'Other', 'Not Specified', 'None reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the product and contact Graco for a cash refund or a voucher.', '20062');
INSERT INTO safety_incidents VALUES ('3438d2ca549a87ca2c289449ab5af10e514a4f24', 'CPSC', '2020-01-29', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'SwaddleMe By Your Bed Sleeper inclined sleeper', 'Infant Fatalities Have Been Reported With Other Manufacturers'' Inclined Sleep Products, After The Infants Rolled From Their Back To Their Stomach Or Side, Or Under Other Circumstances.', 'Other', 'Not Specified', 'No injuries reported.', 'Fatal', 1, 0, 'Consumers should immediately stop using the inclined sleeper and contact Summer Infant for a cash refund or voucher.', '20059');
INSERT INTO safety_incidents VALUES ('802b20bfbac70a23634ee90fc1244c827441e271', 'CPSC', '2020-01-23', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Spare 10,000 mAh Power Banks', 'Fire', 'Flammability / Overheating', 'Burns', 'The firm has received one report of fire. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately unplug and stop using the recalled power banks and dispose of the recalled power banks by following local laws for disposal of lithium-ion batteries.', '20058');
INSERT INTO safety_incidents VALUES ('ac25c3fa6e5802603f6d08167cc7304d70e9552e', 'CPSC', '2020-01-23', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'STIHL RE 90 Pressure Washers', 'Injury', 'Explosion', 'Not Specified', 'STIHL has received seven reports of the nozzle detaching from the spray wand during use. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled pressure washers and contact STIHL or an authorized STIHL servicing dealer to receive a free replacement spray wand.', '20057');
INSERT INTO safety_incidents VALUES ('e093666fbc05bd89df563a10309776aa9c652757', 'CPSC', '2020-01-23', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Stand2Learn Stools', 'Falls', 'Instability / Fall Risk', 'Fall Injury', 'VARIDESK has received seven reports of the stool''s foot support bars breaking off. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the stools and contact VARIDESK for a full refund.', '20054');
INSERT INTO safety_incidents VALUES ('002bd7c5656a07772eab83533b542c2b7221ca10', 'CPSC', '2020-01-16', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Tango Mini Strollers', 'Falls', 'Mechanical Failure', 'Fall Injury', 'None reported.', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled strollers and contact Baby Trend for a replacement or full refund.', '20052');
INSERT INTO safety_incidents VALUES ('910391488cf3c33f8b950331e6dcdbb5ce3ef931', 'CPSC', '2020-01-14', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Thompson''s® WaterSeal® Waterproofing Wood Protector and Masonry Protector in Aerosol Cans', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The Thompson''s Company received approximately 18 reports of leaking cans from retailers. No injuries, fires, or property damage were reported.', 'Minor', 1, 0, 'Consumers should immediately stop using Thompson''s WaterSeal Waterproofing Wood Protector and Masonry Protector in aerosol cans, discard the products in accordance with local requirements and contact The Thompson''s Company for a full refund.', '20056');
INSERT INTO safety_incidents VALUES ('4b6393c8d500fc40bed35fa9e35275b9643fae13', 'CPSC', '2020-01-09', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Holiday Travel Mugs', 'Fire', 'Flammability / Overheating', 'Not Specified', 'The firm has received one report of sparks when a consumer used the mug in a microwave. No injuries have been reported.', 'Minor', 1, 0, 'Consumers should immediately stop using the recalled mugs and return them to place of purchase for a full refund or contact Boston Warehouse Trading Corp.', '20050');
INSERT INTO safety_incidents VALUES ('f19f0846bcaae06e44b24036ba501b707e85a526', 'CPSC', '2020-01-09', 2020, '2020-01', 'USA', 'United States', '', 'Other', '33.5 oz. Milk Bottles', 'Injury', 'Sharp Edges / Points', 'Laceration / Cut', 'None Reported', 'Moderate', 1, 0, 'Foodservice establishments and customers should immediately stop using the recalled milk bottles and contact the firm to receive a refund in the form of a credit voucher or a free replacement bottle', '20051');
INSERT INTO safety_incidents VALUES ('3287bb2b6bb4514b23a12603d7d16bc6fc1f9389', 'CPSC', '2020-01-09', 2020, '2020-01', 'USA', 'United States', '', 'Other', 'Little Bambino 4 in 1 canopy children''s tricycles', 'Paint On The Canopy''S Frame Contains Levels Of Lead That Exceed The Federal Lead Paint Ban And Tricycle Components Contain Levels Of Lead That Exceed The Federal Lead Content Ban. Lead Is Toxic If Ingested By Young Children And Can Cause Adverse Health Issues.', 'Chemical / Toxic Substance', 'Poisoning / Ingestion', 'None reported', 'Moderate', 1, 0, 'Consumers should immediately stop using the recalled tricycles, take them away from children and contact Thesaurus Global Marketing for a full refund, including the cost of shipping. Amazon is contacting all known purchasers directly.', '20712');
