INSERT INTO safety_incidents VALUES ('dba78b9fc3e913e6422766d901613e699f570614', 'OPSS', '2025-12-11', 2025, '2025-12', 'United Kingdom', 'United Kingdom', '', 'Other', 'Product Safety Alert: Baby Sleep Pillows (PSA8)', 'Choking', 'Flammability / Overheating', 'Choking / Suffocation', 'This is a Product Safety Alert from the Office for Product Safety and Standards (OPSS) for a product commonly known as a ''Baby Sleep Pillow.'' Baby Sleep Pillows can pose a risk of suffocation, overheating and death to babies. This Alert is for consumers (particularly parents and caregivers to babies), childcare and educational establishments, local authority trading standards and businesses to warn of the potential harm that baby sleep pillows can pose.', 'Fatal', 0, 0, '', 'product-safety-alert-baby-sleep-pillows-psa8');
