-- Safety Dashboard — Full Normalised Dataset
-- Generated : 2026-04-26T18:14:32Z
-- Records   : 8044
-- Sources   : ACCC, CPSC, EU Safety Gate, Health Canada, OPSS

DROP TABLE IF EXISTS safety_incidents;

CREATE TABLE safety_incidents (
    id TEXT PRIMARY KEY, source VARCHAR(50), date DATE, year INTEGER, month VARCHAR(7),
    region VARCHAR(50), notifying_country VARCHAR(100), country_of_origin VARCHAR(100),
    product_category VARCHAR(100), product_desc TEXT, risk_type VARCHAR(100),
    hazard_type VARCHAR(100), injury_type VARCHAR(100), injury_description TEXT,
    severity VARCHAR(20), injury_flag SMALLINT, injury_count INTEGER,
    corrective_action TEXT, reference VARCHAR(100)
);

CREATE INDEX idx_date ON safety_incidents (date);
CREATE INDEX idx_year ON safety_incidents (year);
CREATE INDEX idx_region ON safety_incidents (region);
CREATE INDEX idx_source ON safety_incidents (source);
CREATE INDEX idx_product_category ON safety_incidents (product_category);
CREATE INDEX idx_hazard_type ON safety_incidents (hazard_type);
CREATE INDEX idx_injury_type ON safety_incidents (injury_type);
CREATE INDEX idx_severity ON safety_incidents (severity);
CREATE INDEX idx_country_origin ON safety_incidents (country_of_origin);
CREATE INDEX idx_injury_flag ON safety_incidents (injury_flag);

